/* ============================================================
   Procedure: [dbo].[USP_GetBillingDisplay]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[USP_GetBillingDisplay]
(
    @AgentName NVARCHAR(100),
    @FromDate DATETIME,
    @ToDate DATETIME,
    @TokenStart INT,
    @TokenEnd INT,
    @UserID BIGINT,
    -- Pagination
    @PageNumber INT,
    @PageSize INT
)
AS
BEGIN
    --SET NOCOUNT ON;

    --DECLARE
    --    @AgentName NVARCHAR(100) = N'',
    --    @FromDate DATETIME = N'2025-03-25',
    --    @ToDate DATETIME = N'2026-03-25',
    --    @TokenStart INT = 0,
    --    @TokenEnd INT = 3000,
    --    @UserID BIGINT = 34594,
    --    -- Pagination
    --    @PageNumber INT = 1,
    --    @PageSize INT = 10


    

    SET @PageSize = 10;

    DECLARE @ParentID BIGINT = dbo.ufn_GetUserParentId(@UserID);

    ----------------------------------------
    -- Pagination Calculation
    ----------------------------------------
    DECLARE @StartRow INT = (@PageNumber - 1) * @PageSize;

    ----------------------------------------
    -- Main Query With Filters
    ----------------------------------------
    ;WITH Result AS
    (
        SELECT
            ROW_NUMBER() OVER (ORDER BY tu.CreatedOn DESC) AS RowNum,
            ag.AgentID,
            ag.Name AS AgentName,
            FORMAT(tu.CreatedOn, 'yyyy-MM-dd HH:mm:ss ttt') AS [DateTime],
            tu.TotalTokens AS TokenUsed,
            icd.Debits AS Amount,
            icd.Remarks AS Remarks,
            ud.User_Login
        FROM tbl_ai_TokenUsages AS tu WITH (NOLOCK)
        INNER JOIN IntCredit_Details AS icd WITH (NOLOCK) ON tu.IntCreditId = icd.Credit_ID
        LEFT JOIN tbl_ai_Agents AS ag WITH (NOLOCK)  ON json_value(tu.detailJson, '$.assistant_id') = ag.assistantId
        LEFT JOIN User_Detail AS ud WITH (NOLOCK) ON ag.CreatedBy = ud.User_ID
        WHERE
            icd.User_Id = @ParentID
            AND (ag.Name LIKE '%' + ISNULL(@AgentName, '') + '%')
            AND 1 = ( case 
                when isnull(@FromDate, '')  = '' and isnull(@ToDate, '')  = '' then 1 
                when CAST(tu.CreatedOn AS DATE) >= CAST(@FromDate AS DATE) AND CAST(tu.CreatedOn AS DATE) <= CAST(@ToDate AS DATE) then 1
                else 0 end)
             --Optional filters (currently commented out):
             AND 1 = (case 
                when isnull(@TokenStart, 0) = 0 AND isnull(@TokenEnd, 0) = 0 then 1 
                when tu.TotalTokens between @TokenStart and @TokenEnd    then 1
                else 0 end  )
             
    ),
    Total AS
    (
        SELECT COUNT(*) AS TotalCount
        FROM Result
    )

    ----------------------------------------
    -- Final Output (Paginated Data + Total Count)
    ----------------------------------------
    SELECT
        R.*,
        T.TotalCount
    FROM Result R
    CROSS JOIN Total T
    WHERE R.RowNum > @StartRow 
      AND R.RowNum <= T.TotalCount -- Use (@StartRow + @PageSize) for strict pagination
    ORDER BY R.RowNum;
END



GO

