CREATE   PROC USP_GETBLACKLISTNO -- 'SMS','9015479794' 
         @SERVICE VARCHAR(10),
         @MOBILENO VARCHAR(10)
        AS
          
         DECLARE @Blacklist VARCHAR(50)
          
         IF (@SERVICE='SMS')
        BEGIN
        set @Blacklist=(SELECT 'E' FROM BLACKLISTEDNO WHERE BLACKMOBILENO=@MOBILENO)
        END
       ELSE IF (@SERVICE='VOICEAD')
        BEGIN
       -- SET @Blacklist=(SELECT  'E' FROM [CRM\R2].[voicead].[DBO].[userdetail] WHERE USER_LOGIN = @MOBILENO)
        set @Blacklist=(SELECT 'E' FROM BLACKLISTEDNO WHERE BLACKMOBILENO=@MOBILENO)
        END 
        
        select isnull(@Blacklist,'')


