/* ============================================================
   Procedure: [dbo].[Usp_GetBotCampaign_ByID]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[Usp_GetBotCampaign_ByID]
(
  @BotID bigint
)
AS
BEGIN
    SET NOCOUNT ON;
	--declare
	--@BotID bigint=504
    BEGIN TRY
 
        SELECT
            v.id AS BotId,
            ISNULL(v.campaign_name, '') AS CampaignName,
            ISNULL(v.parentid, 0) AS ParentId,
            ISNULL(v.created_by, 0) AS CreatedBy,
            ISNULL(v.isactive, 0) AS IsActive,
            ISNULL(v.eventid, 0) AS EventId,
            -- existing/time columns (if present)
            ISNULL(v.timebeforeunit, 0) AS TimeBeforeEvent,
            ISNULL(v.timeunit, '') AS TimeUnit,
 
            -- values previously returned (fallback to JSON if column absent)

            -- required fields extracted from JSON stored in campaign_settings
            TRY_CAST(JSON_VALUE(v.campaign_settings, '$.botId') AS INT)         AS VoiceBotTypeId,
            ISNULL(JSON_VALUE(v.campaign_settings, '$.fromNumber'), '')                 AS FromNumber
            --TRY_CAST(JSON_VALUE(v.campaign_settings, '$.reminderValue') AS INT)         AS ReminderValue,
            --ISNULL(JSON_VALUE(v.campaign_settings, '$.reminderUnit'), '')             AS ReminderUnit,
            --TRY_CAST(JSON_VALUE(v.campaign_settings, '$.executionLimit') AS INT)       AS ExecutionLimit
 
        FROM dbo.voice_bot_campaigns v WITH (NOLOCK)
        WHERE v.id = @BotID;
 
    END TRY
    BEGIN CATCH
        -- bubble up/log error
        EXEC usp_InsertErrorInfo;
    END CATCH
END



GO

