/* ============================================================
   Procedure: [dbo].[usp_GetCallerContext]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE usp_GetCallerContext-- '7840002738',34594
    @CallerId varchar(50),@parentid bigint
AS
BEGIN
declare @entity varchar(20),@entityid bigint,@callerdetails nvarchar(max),@is_converted bit=0,@followupdata nvarchar(max)='',@calldata nvarchar(max)=''
,@opentickets nvarchar(max)='',@recentactivities nvarchar(max),@additionaldetails nvarchar(max)=''
if exists (select 1 from UserLeads(nolock) where parentid=@parentid  and @callerid in (isnull(nullif(mobileno,'0'),''),isnull(nullif(mobileno1,'0'),''),
isnull(nullif(mobileno2,'0'),'')))
begin
select top 1 @entity='lead',@entityid=id from UserLeads(nolock) where parentid=@parentid  and @callerid in (isnull(nullif(mobileno,'0'),''),isnull(nullif(mobileno1,'0'),''),
isnull(nullif(mobileno2,'0'),'')) order by id desc
select @is_converted=case when exists(select 1 from LeadInteractionHistory l(nolock) join FollowUp_Status f(nolock) on l.FollowUpStatus=f.id and f.isconvert=1) then 1 else 0 end

select @followupdata=(select top 5 l.CreatedOn,u.user_login as FollowupBy , f.FollowupStatus,d.User_Login as AssignedTo,l.FollowupDate as NextFollowupdate,l.Remarks 
from LeadInteractionHistory l(nolock) join FollowUp_Status f(nolock) on l.FollowUpStatus=f.id 
join user_detail u on u.user_id=f.createdby left join user_detail d on d.user_id=l.AssignedTo 
order by l.id desc
FOR JSON PATH, INCLUDE_NULL_VALUES, WITHOUT_ARRAY_WRAPPER) 

select @recentactivities=(select top 5 eventdate,u.User_Login as EventBy,a.EventName,t.eventdescription   
from tbl_LeadEventHistory(nolock) t join User_Detail u on t.userid=u.user_id
join ActivityMaster(nolock) a on a.id=t.EventID order by t.historyid desc FOR JSON PATH, INCLUDE_NULL_VALUES, WITHOUT_ARRAY_WRAPPER)

end
else if exists (select 1 from Userenquiry(nolock) where parentid=@parentid  and @callerid in (isnull(nullif(mobileno,'0'),''),isnull(nullif(mobileno1,'0'),''),
isnull(nullif(mobileno2,'0'),'')))
begin

select top 1 @entity='enquiry',@entityid=EnquiryID from Userenquiry(nolock) where parentid=@parentid  and @callerid in (isnull(nullif(mobileno,'0'),''),isnull(nullif(mobileno1,'0'),''),
isnull(nullif(mobileno2,'0'),'')) order by EnquiryID desc

select @recentactivities=(select top 5 eventdate,u.User_Login as EventBy,a.EventName,t.eventdescription   
from tbl_LeadEventHistory(nolock) t join User_Detail u on t.userid=u.user_id
join ActivityMaster(nolock) a on a.id=t.EventID order by t.historyid desc FOR JSON PATH, INCLUDE_NULL_VALUES, WITHOUT_ARRAY_WRAPPER)


end
else if exists (select 1 from UserLeads(nolock) where parentid=@parentid  and @callerid in (isnull(nullif(mobileno,'0'),''),isnull(nullif(mobileno1,'0'),''),
isnull(nullif(mobileno2,'0'),'')))
begin
select top 1 @entity='user',@entityid=user_id from User_detail(nolock) where parentid=@parentid  and @callerid =str(mobile) order by user_id desc
end
else
begin
select @entity='Unknown',@entityid=0
end



if isnull(@entity,'')<>''
begin
--drop table if exists #caller_details
--create table #caller_details(fieldnameexposed varchar(250),fieldnameactual varchar(250),fieldtype varchar(50),fieldvalue nvarchar(max))

--insert into #caller_details
exec usp_replaceentityplaceholders_allfields_insert @entityid,@entity

select @callerdetails=entitydetails from entity_details_transition(nolock) where entity=@entity and entityid=@entityid
end

select @calldata=(select top 10 c.direction as Calldirection,callstarttime,callendtime,customercalldisposition,agentcalldisposition, u.User_Login as AgentLastAttempted,o.outcomename as CallOutcome,remarks as Callremarks  
from calllog(nolock) c left join user_detail u (nolock) on u.user_id=c.agentuserid
left join calloutcomes (nolock) o on o.id=c.outcomeid
where Customernumber=@callerid and c.parentid=@parentid order by c.id desc for json path, include_null_values, without_array_wrapper) 


select case when @entity='Enquiry' then 'Raw Enquiry' when @entity='lead' and @is_converted=1 then 'Customer' when @entity='lead' then 'lead' when
@entity='User' then 'Team Member' else @entity end as Caller_Profile,@callerdetails as Caller_Details,@calldata as Recent_Calls,@recentactivities 
as Recent_Activities,@followupdata as Recent_FollowUps,@opentickets as Recent_Tickets,@additionaldetails as Additional_Details


END



GO

/* ============================================================
   Procedure: [dbo].[usp_getcallersidentity]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_getcallersidentity]
@userid bigint,@mobile nvarchar(20)
as
begin
declare @parentid bigint,@usermobile nvarchar(20),@id bigint,@caller nvarchar(20)
select @parentid=parentid,@usermobile=str(mobile) from user_detail(nolock) where user_id=@userid
if ((select top 1 parentid from Cloud_User_Phone(nolock) where phoneno in (@mobile,'0'+cast(@mobile as nvarchar)) order by userphid desc)=@parentid)
begin
select top 1 @caller=k.callerid from kit19calls(nolock) k
join Kit19CallsDialled d on k.uniqueid=d.puniqueid where k.dnid in (@mobile,'0'+cast(@mobile as nvarchar)) and k.context='inbound'
and left(replace(d.callerid,'local/',''),len(@usermobile))=@usermobile and datediff(mi,d.call_start_time,getdate())<=5
order by d.id desc
if @caller is not null
begin
select top 1 @id=id from UserLeads(nolock) where ParentID=@parentid and (mobileno=@caller or mobileno1=@caller or mobileno1=@caller)order by ID desc
if @id is not null
select @id as id,'Lead' as CallerType,* from userleads(nolock) where ID=@id 
else
begin
select top 1 @id=enquiryid from Userenquiry(nolock) where ParentID=@parentid and (mobileno=@caller or mobileno1=@caller or mobileno1=@caller) order by enquiryid desc
if @id is not null
select @id as id,'Enquiry' as CallerType,* from userenquiry(nolock) where enquiryID=@id
end
end
end
end





GO

/* ============================================================
   Procedure: [dbo].[usp_getcallersmobile]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_getcallersmobile] --33819,'1204259308'      
@userid bigint,@mobile nvarchar(20)      
as      
begin      
declare @parentid bigint,@usermobile nvarchar(20),@id bigint,@caller nvarchar(20)      
select @parentid=parentid,@usermobile=str(mobile) from user_detail(nolock) where user_id=@userid   
drop table if exists #whocalled  
create table #whocalled(callerno nvarchar(20),calltime datetime)  
if ((select top 1 parentid from Cloud_User_Phone(nolock) where phoneno =case when substring(@mobile,1,1)='0' then substring(@mobile,2,len(@mobile)-1) else @mobile end order by userphid desc)=@parentid)      
begin      
insert into #whocalled(callerno,calltime)  
select top 1 k.callerid,k.call_start_time from kit19calls(nolock) k      
join Kit19CallsDialled d on k.uniqueid=d.puniqueid where k.dnid in (case when substring(@mobile,1,1)='0' then substring(@mobile,2,len(@mobile)-1) else @mobile end,'0'+cast(@mobile as nvarchar)) and k.context='inbound'      
and d.kc_agentuserid=@userid  
order by d.id desc      
  
insert into #whocalled(callerno,calltime)  
select top 1 customernumber,callstarttime from CallLog(nolock) where gatewayid in (2,7) and agentuserid=@userid order by id desc  
  
select top 1 @caller=callerno from #whocalled order by calltime desc  
end 
select @caller callerno
     
end      
  
  
  


GO

/* ============================================================
   Procedure: [dbo].[usp_getcallersmobile_pelcrm]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_getcallersmobile_pelcrm] --40856,'918035714639'
@userid bigint,@mobile nvarchar(20)          
as          
begin          
declare @parentid bigint,@usermobile nvarchar(20),@id bigint,@caller nvarchar(20),@uniqueid nvarchar(50) ,@direction varchar(20)  ,@call_id bigint              
select @parentid=parentid,@usermobile=str(mobile) from user_detail(nolock) where user_id=@userid 
drop table if exists #whocalled      
create table #whocalled(callerno nvarchar(20),calltime datetime,uniqueid nvarchar(50),direction varchar(20) ,call_id bigint)     
if ((select top 1 parentid from Cloud_User_Phone(nolock) where phoneno =case when substring(@mobile,1,1)='0' then substring(@mobile,2,len(@mobile)-1) else @mobile end order by userphid desc)=@parentid)          
begin          
insert into #whocalled(callerno,calltime,uniqueid,direction)      
select top 1 k.callerid,k.call_start_time,k.uniqueid,case when context like 'inbound%' then 'in' else 'out' end from kit19calls(nolock) k          
join Kit19CallsDialled d on k.uniqueid=d.puniqueid where k.dnid in (case when substring(@mobile,1,1)='0' then substring(@mobile,2,len(@mobile)-1) else @mobile end,'0'+cast(@mobile as nvarchar)) and k.context='inbound'          
and d.kc_agentuserid=@userid      
order by d.id desc          
      
insert into #whocalled(callerno,calltime,call_id,direction)      
select top 1 customernumber,callstarttime,id,case when direction='incoming' then 'in' else 'out' end from CallLog(nolock) where gatewayid in (2,7) and agentuserid=@userid order by id desc      
      
select top 1 @caller=callerno,@uniqueid=uniqueid,@direction=direction,@call_id=call_id from #whocalled order by calltime desc      
end     
select @caller callerno  ,@uniqueid uniqueid, @direction direction,@call_id call_id  
         
end          
      


	  --select top 10 * from calllog(nolock) where agentuserid=40856 order by 1 desc


