/* ============================================================
   Procedure: [dbo].[usp_getCallLogSummary]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


--select top 10 * from calllog(nolock) where gatewayid=7 and appid is not null

--exec MySMS.dbo.usp_getCallLogSummary @userid=46410,@rsection=N'calls'
--Exec usp_getCallLogSummary 39698  
CREATE   PROC [dbo].[usp_getCallLogSummary]  
(  
 @userid bigint,  
 @rsection nvarchar(50)='Calls'  
)  
AS  
BEGIN  
 -- declare @userid bigint=17534,@rsection nvarchar(50)='Calls'  
 -- declare @userid bigint=40533,@rsection nvarchar(50)='Calls'  
 -- declare @userid bigint=32222,@rsection nvarchar(50)='Calls'  
 -- declare @userid bigint=46410,@rsection nvarchar(50)='Calls'  
   
 declare @isadmin int,@parentid bigint,@UserLoginWithName nvarchar(200)     
 declare @tbluser table (User_ID bigint,Name varchar(100), Image varchar(100))     
 insert into @tbluser     
 exec Use_GetUserDetails @UserId     
 select @isadmin=isnull(isadmin,0),@parentid=parentid,@UserLoginWithName = isnull(user_login+' ( '+isnull(fname,'')+' '+ISNULL(lname,'')+' )' ,'') from user_detail(nolock) where user_id=@userid     
  
 select @rsection Section, Parentid,  
 sum(case when Direction like 'in%' and cast(callstarttime as date)=cast(getdate() as date) then 1 else 0 end) IncomingCallsToday,  
 sum(case when Direction like 'out%' and appid is not null and cast(callstarttime as date)=cast(getdate() as date) then 1 else 0 end) AutomatedOutgoingCallsToday,  
 sum(case when Direction like 'out%' and gatewayid!=0 and appid is null and cast(callstarttime as date)=cast(getdate() as date) then 1 else 0 end) ClickCallsToday,  
 sum(case when Direction like 'in%' and datediff(dd,cast(callstarttime as date),cast(getdate() as date)) between 0 and 6 then 1 else 0 end) IncomingCallsLast7days,  
 sum(case when Direction like 'out%' and appid is not null and datediff(dd,cast(callstarttime as date),cast(getdate() as date)) between 0 and 6 then 1 else 0 end)  
 AutomatedOutgoingCallsLast7days,  
 sum(case when Direction like 'out%' and gatewayid!=0 and appid is null and datediff(dd,cast(callstarttime as date),cast(getdate() as date)) between 0 and 6 then 1 else 0 end) ClickCallsLast7days,  
 sum(case when Direction like 'in%' and month(callstarttime)=month(getdate()) and year(callstarttime)=year(getdate()) then 1 else 0 end) IncomingCallsThisMonth,  
 sum(case when Direction like 'out%' and appid is not null and month(callstarttime)=month(getdate()) and year(callstarttime)=year(getdate()) then 1 else 0 end) AutomatedOutgoingCallsThisMonth,  
 sum(case when Direction like 'out%' and gatewayid!=0 and appid is null and month(callstarttime)=month(getdate()) and year(callstarttime)=year(getdate()) then 1 else 0 end) ClickCallsThisMonth  
 from calllog(nolock) k     
 --where parentid=@parentid and callstarttime>dateadd(dd,-30,getdate())     
 where parentid=@parentid and callstarttime>dateadd(dd,-30,getdate())     
   --and dbo.lastagentattended(k.uniqueid)= case when @isadmin=1 then dbo.lastagentattended(k.uniqueid) else @UserLoginWithName end     
   --  and dbo.lastagentidattended(k.uniqueid) in (iif(@isadmin=1,dbo.lastagentidattended(k.uniqueid),(select User_ID from @tbluser))) 
    and 
    1 = case when @isadmin=1 then 1 
        --when dbo.lastagentidattended(k.uniqueid) in  (select User_ID from @tbluser) 
		WHEN isnull(k.agentuserid, 0) IN ( select USER_ID  from @tbluser)  

         then 1 else 0 end

 group by parentid     
  
 select @rsection Section,* from     
 (     
  select t.parentid,   
    sum(case when cast(t.callstarttime as date)=cast(getdate() as date) then 1 else 0 end) as  SIMCallsToday,  
    sum(case when datediff(dd,cast(t.callstarttime as date),cast(getdate() as date)) between 0 and 7 then 1 else 0 end) as SIMCallsLast7Days,  
    sum(case when month(t.callstarttime)=month(getdate()) and year(t.callstarttime)=year(getdate()) then 1 else 0 end) as SIMCallsThisMonth  
  from [dbo].[CallLog] t join user_detail(nolock) u on u.user_id=t.agentuserid     
  where t.parentid=@parentid and t.callstarttime>dateadd(dd,-30,getdate()) and t.gatewayid=0    
    --and t.agentuserid=case when @isadmin=1 then t.agentuserid else @userid end     
   -- and t.agentuserid in (iif(@isadmin=1, t.agentuserid, (select User_ID from @tbluser)))     
     and 1 = case when @isadmin=1 then 1
	          when t.agentuserid in (select User_ID from @tbluser)
			     then 1
		      else 0  		 
            end      
   group by t.parentid     
 ) a     
  
 select @rsection Section,* from     
 (     
  select k.parentid,  
    count(distinct (case when cast(k.callstarttime as date)=cast(getdate() as date) then k.uniqueid end)) as CallsMissedToday,  
    count(distinct (case when datediff(dd,cast(k.callstarttime as date),cast(getdate() as date)) between 0 and 7 then k.uniqueid end)) as CallsMissedLast7Days,  
    count(distinct (case when month(k.callstarttime)=month(getdate()) and year(k.callstarttime)=year(getdate()) then k.uniqueid end)) as CallsMissedThisMonth  
  from CallLog(nolock) k   
  where k.parentid=@parentid and k.callstarttime>dateadd(dd,-30,getdate()) and (isnull(k.agentcalldisposition,'')!='ANSWERED' /*or k.customercalldisposition != 'ANSWERED'*/) and k.Direction like 'In%'  
  
    --and dbo.lastagentidattended(k.uniqueid) in (iif(@isadmin=1,dbo.lastagentidattended(k.uniqueid),(select User_ID from @tbluser)))    
    and 1 = case when @isadmin=1 then 1
	          when dbo.lastagentidattended(k.uniqueid) in (select User_ID from @tbluser)
			     then 1
		      else 0
			end
       group by k.parentid     
    ) a     
  
 select @rsection Section, CL.agentuserid,   
   Executive=isnull(UD.User_Login+' ('+isnull(UD.FName,'')+' '+ISNULL(UD.LName,'')+')',''), [Image]=isnull(UD.Image,''),   
   MissedCallCount=Sum(case when CL.direction='Incoming' and isnull(CL.agentcalldisposition,'')!='ANSWERED' then 1 else 0 end),  
   InComingCalls=Sum(case when CL.direction='Incoming' then 1 else 0 end),  
   OutgoingCalls=Sum(case when CL.direction='Outgoing' and CL.appid is null then 1 else 0 end)  
 from calllog(nolock) CL inner join User_Detail(nolock) UD  
 On CL.agentuserid=UD.User_ID  
 where CL.parentid=@parentid and CL.agentuserid is not null and  
    --CL.agentuserid in (iif(@isadmin=1, CL.agentuserid, (select User_ID from @tbluser)))  
   1 = case when @isadmin=1 then 1
        when CL.agentuserid in (select User_ID from @tbluser)
		     then 1
		else 0 
		end
   
   and cast(CL.callstarttime as date)=cast(getdate() as date)  
 group by CL.agentuserid, isnull(UD.User_Login+' ('+isnull(UD.FName,'')+' '+ISNULL(UD.LName,'')+')',''), isnull(UD.Image,'')  
  
END  



GO

/* ============================================================
   Procedure: [dbo].[usp_getCallLogSummary_agents]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

--Exec usp_getCallLogSummary 39698  
CREATE   PROC usp_getCallLogSummary_agents  
(  
 @userid bigint,  
 @rsection nvarchar(50)='Calls'  
)  
AS  
BEGIN  
 -- declare @userid bigint=17534,@rsection nvarchar(50)='Calls'  
 -- declare @userid bigint=40533,@rsection nvarchar(50)='Calls'  
 -- declare @userid bigint=32222,@rsection nvarchar(50)='Calls'  
   
 declare @isadmin int,@parentid bigint,@UserLoginWithName nvarchar(200)     
 declare @tbluser table (User_ID bigint,Name varchar(100), Image varchar(100))     
 insert into @tbluser     
 exec Use_GetUserDetails @UserId     
 select @isadmin=isnull(isadmin,0),@parentid=parentid,@UserLoginWithName = isnull(user_login+' ( '+isnull(fname,'')+' '+ISNULL(lname,'')+' )' ,'') from user_detail(nolock) where user_id=@userid     
  
 select @rsection Section, Parentid,  
 sum(case when Direction like 'in%' and cast(callstarttime as date)=cast(getdate() as date) then 1 else 0 end) IncomingCallsToday,  
 sum(case when Direction like 'out%' and appid is not null and cast(callstarttime as date)=cast(getdate() as date) then 1 else 0 end) AutomatedOutgoingCallsToday,  
 sum(case when Direction like 'out%' and gatewayid!=0 and appid is null and cast(callstarttime as date)=cast(getdate() as date) then 1 else 0 end) ClickCallsToday,  
 sum(case when Direction like 'in%' and datediff(dd,cast(callstarttime as date),cast(getdate() as date)) between 0 and 7 then 1 else 0 end) IncomingCallsLast7days,  
 sum(case when Direction like 'out%' and appid is not null and datediff(dd,cast(callstarttime as date),cast(getdate() as date)) between 0 and 7 then 1 else 0 end) AutomatedOutgoingCallsLast7days,  
 sum(case when Direction like 'out%' and gatewayid!=0 and appid is null and datediff(dd,cast(callstarttime as date),cast(getdate() as date)) between 0 and 7 then 1 else 0 end) ClickCallsLast7days,  
 sum(case when Direction like 'in%' and month(callstarttime)=month(getdate()) and year(callstarttime)=year(getdate()) then 1 else 0 end) IncomingCallsThisMonth,  
 sum(case when Direction like 'out%' and appid is not null and month(callstarttime)=month(getdate()) and year(callstarttime)=year(getdate()) then 1 else 0 end) AutomatedOutgoingCallsThisMonth,  
 sum(case when Direction like 'out%' and gatewayid!=0 and appid is null and month(callstarttime)=month(getdate()) and year(callstarttime)=year(getdate()) then 1 else 0 end) ClickCallsThisMonth  
 from calllog(nolock) k     
 where parentid=@parentid and callstarttime>dateadd(dd,-30,getdate())     
   --and dbo.lastagentattended(k.uniqueid)= case when @isadmin=1 then dbo.lastagentattended(k.uniqueid) else @UserLoginWithName end     
   and dbo.lastagentidattended(k.uniqueid) in 
   (iif(@isadmin=1,dbo.lastagentidattended(k.uniqueid),(select User_ID from @tbluser)))    
 group by parentid     
  
 select @rsection Section,* from     
 (     
  select t.parentid,   
    sum(case when cast(t.callstarttime as date)=cast(getdate() as date) then 1 else 0 end) as  SIMCallsToday,  
    sum(case when datediff(dd,cast(t.callstarttime as date),cast(getdate() as date)) between 0 and 7 then 1 else 0 end) as SIMCallsLast7Days,  
    sum(case when month(t.callstarttime)=month(getdate()) and year(t.callstarttime)=year(getdate()) then 1 else 0 end) as SIMCallsThisMonth  
  from [dbo].[CallLog] t join user_detail(nolock) u on u.user_id=t.agentuserid     
  where t.parentid=@parentid and t.callstarttime>dateadd(dd,-30,getdate()) and t.gatewayid=0    
    --and t.agentuserid=case when @isadmin=1 then t.agentuserid else @userid end     
    and t.agentuserid in (iif(@isadmin=1, t.agentuserid, (select User_ID from @tbluser)))     
  group by t.parentid     
 ) a     
  
 select @rsection Section,* from     
 (     
  select k.parentid,  
    count(distinct (case when cast(k.callstarttime as date)=cast(getdate() as date) then k.uniqueid end)) as CallsMissedToday,  
    count(distinct (case when datediff(dd,cast(k.callstarttime as date),cast(getdate() as date)) between 0 and 7 then k.uniqueid end)) as CallsMissedLast7Days,  
    count(distinct (case when month(k.callstarttime)=month(getdate()) and year(k.callstarttime)=year(getdate()) then k.uniqueid end)) as CallsMissedThisMonth  
  from CallLog(nolock) k   
  where k.parentid=@parentid and k.callstarttime>dateadd(dd,-30,getdate()) and (isnull(k.agentcalldisposition,'')!='ANSWERED' /*or k.customercalldisposition != 'ANSWERED'*/) and k.Direction like 'In%'  
   and dbo.lastagentidattended(k.uniqueid) in (iif(@isadmin=1,dbo.lastagentidattended(k.uniqueid),(select User_ID from @tbluser)))    
  group by k.parentid     
 ) a     
  
 select @rsection Section, 
   Executive=isnull(UD.Agentname,''), 
   MissedCallCount=Sum(case when CL.direction='Incoming' and isnull(CL.agentcalldisposition,'')!='ANSWERED' then 1 else 0 end),  
   InComingCalls=Sum(case when CL.direction='Incoming' then 1 else 0 end),  
   OutgoingCalls=Sum(case when CL.direction='Outgoing' and CL.appid is null then 1 else 0 end)  
 from calllog(nolock) CL inner join calling_agents(nolock) UD  
 On CL.calling_agentid=UD.id  
 where CL.parentid=@parentid and CL.calling_agentid is not null and  
   UD.kit19userid in (iif(@isadmin=1, UD.kit19userid, (select User_ID from @tbluser)))  
   and cast(CL.callstarttime as date)=cast(getdate() as date)  
 group by CL.agentuserid, isnull(UD.Agentname,'')
  
END  


GO

/* ============================================================
   Procedure: [dbo].[usp_getcallstatus]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON



--exec [usp_getcallstatus] 'Read_this_text:Text: Again a whole new text to be read ;Id:2;Agent:Amy;LanguageCode:en-GB;Metadata:{SampleRate:8000}'
CREATE   PROCEDURE [dbo].[usp_getcallstatus] (@uniqueid nvarchar(4000))  
as  
begin  
DECLARE @decoded  nvarchar(4000)
SET @decoded = @uniqueid
    SET @decoded = REPLACE(@decoded, '%253a', ':')
    SET @decoded = REPLACE(@decoded, '%3a', ':')
    SET @decoded = REPLACE(@decoded, '%253b', ';')
    SET @decoded = REPLACE(@decoded, '%3b', ';')
    SET @decoded = REPLACE(@decoded, '%257b', '{')
    SET @decoded = REPLACE(@decoded, '%7b', '{')
    SET @decoded = REPLACE(@decoded, '%257d', '}')
    SET @decoded = REPLACE(@decoded, '%7d', '}')
    SET @decoded = REPLACE(@decoded, '%2b', ' ')  -- + becomes space
    SET @decoded = REPLACE(@decoded, '+', ' ')    -- just in case

select @uniqueid=@decoded
--DECLARE @input VARCHAR(MAX) = 'key1:value1;key2:value2;key3:{subkey1:subvalue1|subkey2:subvalue2|subkey3:subvalue3}';

--declare @uniqueid nvarchar(4000)='Read_this_text:Text:Read this text;Agent:Amy;LanguageCode:en-GB;Metadata:{SampleRate:8000}'
DECLARE @input nVARCHAR(MAX) 
if @uniqueid like 'Read_this_text:%'
begin
select @input=replace(@uniqueid,'Read_this_text:','')
print concat('before trim: ',@input)
select @input='"{'+REPLACE(
         REPLACE(
           REPLACE(
             REPLACE(
               REPLACE(replace(replace(@input,'Text: ','Text:'),' ;Id:',';Id'), ';', '","'), 
             ':', '":"'), 
           '|', '","'), 
         '{', '{"'), 
       '}', '"}')+'}"'
print concat('after trim: ',@input)
end

Select case when 
@uniqueid='abcd' then '985.23' when
@uniqueid='1234' then '04/02/2025 14:30' when
@uniqueid like 'Read_this_text:%' then @input when
exists (select 1 from kit19callsdialled(nolock) where puniqueid=@uniqueid and dialstatus='ANSWER') then 'Answered' else 'Missed' end as CallStatus  
end


GO

