/* ============================================================
   Procedure: [dbo].[Usp_GetCampaignCountFroGraph]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON





	CREATE   PROCEDURE dbo.Usp_GetCampaignCountFroGraph --233,335      
(      
@EnqNo bigint,      
@kit19UserID bigint      
      
)       
      
as      
      
Begin      
      
  Declare @DateCurrentTo date = null      
  Declare @Status nvarchar(50) = 'Red'      
      
   CREATE TABLE #TempLinked                                        
    (                                        
      Result VARCHAR(200)                                        
    )               
                          
     INSERT INTO #TempLinked                                        
     EXEC GetStatusofLinkedServer 'CRM'                                        
     IF NOT EXISTS(                                        
        SELECT 'x'                                        
        FROM   #TempLinked                                        
    )                             
    begin         
      
    select @DateCurrentTo = convert(date,CreatedDate) From CRM.CRMDB.dbo.AccountSetup where EnqNo = @EnqNo and UserBy = @kit19UserID       
 and Stage = 'Customer Accepted Setup Request'        
       
 --for temp      
        
 ----Declare @DateCurrentTo date = null      
  ----  set @DateCurrentTo = '2016-01-01 21:08:03.167'      
   ----Declare @Status nvarchar(50) = 'Red'      
      
    declare  @EventBasedCount int = 0;    
   declare @ScheduledBasedCount int = 0      
    
   select  @EventBasedCount = Count(ID)  from UserCampaignMaster where ParentID = @kit19UserID and IsEventBased = 1 and CONVERT(date,CreatedOn) >= convert(date,@DateCurrentTo)      
   --and id in (select CampaignID from UserCampaignHistory where  IsEventBased = 1 and isnull(ReasonIfNotRun,'') = '')      
         
   select @ScheduledBasedCount = Count(ID) from UserCampaignMaster where ParentID = @kit19UserID and IsScheduled = 1  and CONVERT(date,CreatedOn) >= convert(date,@DateCurrentTo)      
    --and id in (select CampaignID from UserCampaignHistory where  IsScheduled = 1 and isnull(ReasonIfNotRun,'') = '')      
         
      
    
    
   select @EventBasedCount as EventBasedCount  , @ScheduledBasedCount as ScheduledBasedCount    
      
      
      
   end      
      
  drop table  #TempLinked      
      
      
End      
      
      



GO

/* ============================================================
   Procedure: [dbo].[usp_getcampaigndetails]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_getcampaigndetails]      
@campaignid bigint,      
@fromdate date=null,      
@todate date=null      
as      
begin    
declare @parentid bigint  
declare @medium nvarchar(50)  
select @medium= medium,@parentid=parentid from usercampaignmaster(nolock) where id=@campaignid    
if @medium='SMS'      
begin      
select Mobile,Message,SenderID,MessageStatus,MessageInsertDate from      
(      
(select BatchID,Mobile,Message,SenderID,MessageStatus,MessageInsertDate from MessageDeliveryStatus(nolock)      
where MessageInsertDate between isnull(@fromdate,dateadd(d,-30,getdate())) and isnull(@todate,getdate())  
and u_id=@parentid  
      
union       
select BatchID,Mobile,Message,SenderID,MessageStatus,MessageInsertDate from ThirtyDaysHistory(nolock)      
where MessageInsertDate between isnull(@fromdate,dateadd(d,-30,getdate())) and isnull(@todate,getdate())   
and u_id=@parentid  
  
) a      
join      
(select batchid from usercampaignexecutionhistory(nolock) u where CampaignID=@campaignid and u.ExecutionTime between       
 isnull(@fromdate,dateadd(d,-30,getdate())) and isnull(@todate,dateadd(d,1,getdate()))      
) u on u.batchid=a.batchid      
)      
end      
if @medium='Mail'      
begin      
select guid,email_id,sentdatetime,replyto,status,a.BatchID from      
(      
(select GUID,email_id,sentdatetime,replyto,status,batchid from clientemails(nolock)      
where sentdatetime between isnull(@fromdate,dateadd(d,-30,getdate())) and isnull(@todate,getdate())  
and dbo.ufn_getuserparentid(userid)=@parentid  
  
      
union       
select GUID,email_id,sentdatetime,replyto,status,batchid from ThirtyDaysClientEmails--(nolock)      
where sentdatetime between isnull(@fromdate,dateadd(d,-30,getdate())) and isnull(@todate,getdate())    
and dbo.ufn_getuserparentid(userid)=@parentid  
  
) a       
join      
(select batchid from usercampaignexecutionhistory(nolock) u where CampaignID=@campaignid and u.ExecutionTime between       
 isnull(@fromdate,dateadd(d,-30,getdate())) and isnull(@todate,dateadd(d,1,getdate()))      
) u on u.batchid=a.batchid      
)      
end      
if @medium='Voice'      
begin      
select mobile,voiceinsertdate,voicestatus,StatusDescription,IVRName from      
(select mobile,batchid,voiceinsertdate,voicestatus,StatusDescription,appname as IVRName from       
Voice_DeliveryStatus(nolock) v    
join      
Cloud_app_master c (nolock) on c.AppId=v.appid where v.voiceInsertDate       
between isnull(@fromdate,dateadd(d,-30,getdate())) and isnull(@todate,dateadd(d,1,getdate()))   and v.parentid=@parentid   
) a       
join      
(select batchid from usercampaignexecutionhistory(nolock) u where CampaignID=@campaignid and u.ExecutionTime between       
 isnull(@fromdate,dateadd(d,-30,getdate())) and isnull(@todate,dateadd(d,1,getdate()))      
) u on u.batchid=a.batchid      
      
end      
if @medium='Whatsapp'      
begin      
/*select Template,error,errordescription,isprocessed,scheduledon,entityname,entityid,mobile,      
wa_message_id from      
(select json_value(requestjson,'$.whatsapp.template.name') Template,isnull(errorid,'') Error,errordescription,      
isprocessed,scheduledon,entityname,entityid,wa_message_id,replace(json_value(requestjson,'$.whatsapp.to'),'+','') mobile,batchid from       
mysmsconversations.dbo.tbl_ims_schedule_message(nolock) i where i.CreatedDate      
between isnull(@fromdate,dateadd(d,-30,getdate())) and isnull(@todate,dateadd(d,1,getdate())) and isnull(batchid,0)<>0    
and dbo.ufn_getuserparentid(i.createdby)=@parentid  
union      
select json_value(requestjson,'$.whatsapp.template.name') Template,isnull(errorid,'') Error,errordescription,      
isprocessed,scheduledon,entityname,entityid,wa_message_id,replace(json_value(requestjson,'$.whatsapp.to'),'+','') mobile,batchid from       
mysmsconversations.dbo.tbl_ims_schedule_message_archived(nolock) i where i.CreatedDate      
between isnull(@fromdate,dateadd(d,-30,getdate())) and isnull(@todate,dateadd(d,1,getdate()))  and isnull(batchid,0)<>0       
and dbo.ufn_getuserparentid(i.createdby)=@parentid  
) a       
join      
(select batchid from usercampaignexecutionhistory(nolock) u where CampaignID=@campaignid and u.ExecutionTime between       
 isnull(@fromdate,dateadd(d,-30,getdate())) and isnull(@todate,dateadd(d,1,getdate()))      
) u on u.batchid=a.batchid   */   
 DECLARE @sqlquery NVARCHAR(MAX);

SELECT @sqlquery = concat('
    SELECT 
        Template,
        Error,
        errordescription,
        isprocessed,
        scheduledon,
        entityname,
        entityid,
        mobile,
        wa_message_id
    FROM
    (
        SELECT 
            JSON_VALUE(requestjson, ''$.whatsapp.template.name'') AS Template,
            ISNULL(errorid, '''') AS Error,
            errordescription,
            isprocessed,
            scheduledon,
            entityname,
            entityid,
            wa_message_id,
            REPLACE(JSON_VALUE(requestjson, ''$.whatsapp.to''), ''+'', '''') AS mobile,
            batchid
        FROM 
            tbl_ims_schedule_message WITH (NOLOCK) i
        WHERE 
            i.CreatedDate BETWEEN ISNULL(',@fromdate,' DATEADD(d, -30, GETDATE())) AND ISNULL(',@todate,' DATEADD(d, 1, GETDATE()))
            AND ISNULL(batchid, 0) <> 0
            AND dbo.ufn_getuserparentid(i.createdby) =', @parentid, '

        UNION

        SELECT 
            JSON_VALUE(requestjson, ''$.whatsapp.template.name'') AS Template,
            ISNULL(errorid, '''') AS Error,
            errordescription,
            isprocessed,
            scheduledon,
            entityname,
            entityid,
            wa_message_id,
            REPLACE(JSON_VALUE(requestjson, ''$.whatsapp.to''), ''+'', '''') AS mobile,
            batchid
        FROM 
            tbl_ims_schedule_message_archived WITH (NOLOCK) i
        WHERE 
            i.CreatedDate BETWEEN ISNULL(',@fromdate,' DATEADD(d, -30, GETDATE())) AND ISNULL(',@todate,' DATEADD(d, 1, GETDATE()))
            AND ISNULL(batchid, 0) <> 0
            AND dbo.ufn_getuserparentid(i.createdby) =', @parentid,'
    ) a
    JOIN 
    (
        SELECT 
            batchid
        FROM 
            usercampaignexecutionhistory WITH (NOLOCK) u
        WHERE 
            CampaignID =', @campaignid,'
            AND u.ExecutionTime BETWEEN ISNULL(',@fromdate,' DATEADD(d, -30, GETDATE())) AND ISNULL(',@todate,' DATEADD(d, 1, GETDATE()))
    ) u ON u.batchid = a.batchid;
');

EXEC usp_clr_ExecuteRemoteQuery @sqlquery;
     
end      

end


GO

/* ============================================================
   Procedure: [dbo].[usp_getcampaigndetails_Pagination]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_getcampaigndetails_Pagination] --9668, '08-31-2023','09-01-2023' , 0, 10      
 @campaignid bigint,      
 @fromdate date=null,      
 @todate date=null,
 @OffsetValue INT = 0,  
 @PagingSize INT = 10
as      
begin    
  declare @parentid bigint  
  declare @medium nvarchar(50)  
  declare @Count int = 0 ;    
  drop table if exists #tempcmgnhistory    
  
  select batchid into #tempcmgnhistory  from usercampaignexecutionhistory(nolock) u where CampaignID=@campaignid and u.ExecutionTime between       
 isnull(@fromdate,dateadd(d,-30,getdate())) and isnull(@todate,dateadd(d,1,getdate()))         

select @medium= medium,@parentid=parentid from usercampaignmaster(nolock) where id=@campaignid    
if @medium='SMS'      
begin

select @Count = COUNT(1) from
(
select Mobile,Message,SenderID,MessageStatus,MessageInsertDate from      
(      
(select BatchID,Mobile,Message,SenderID,MessageStatus,MessageInsertDate from MessageDeliveryStatus(nolock)      
where MessageInsertDate between isnull(@fromdate,dateadd(d,-30,getdate())) and isnull(@todate,getdate())  
and u_id=@parentid  
      
union       
select BatchID,Mobile,Message,SenderID,MessageStatus,MessageInsertDate from ThirtyDaysHistory(nolock)      
where MessageInsertDate between isnull(@fromdate,dateadd(d,-30,getdate())) and isnull(@todate,getdate())   
and u_id=@parentid  
  
) a      
join      
(      
  select batchid from #tempcmgnhistory as u 
) u on u.batchid=a.batchid      
)) as tbl 

