/* ============================================================
   Procedure: [dbo].[usp_GetCampaignExecutionDetails]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_GetCampaignExecutionDetails]
	@camid bigint = NULL,
    @UserId bigint = NULL, 
    @FromDate DATETIME = NULL, 
    @ToDate DATETIME = NULL
AS
BEGIN
    SET NOCOUNT ON;

    -- Temporary table to store intermediate results (if needed)
    CREATE TABLE #TempResults (
        CampaignName NVARCHAR(255),
        BatchID INT,
        ExecutionDate DATETIME,
        ReplyTo NVARCHAR(255),
        Status NVARCHAR(50),
        Message NVARCHAR(MAX)
    );

    -- Main Query to Fetch Data
    INSERT INTO #TempResults (CampaignName, BatchID, ExecutionDate, ReplyTo, Status, Message)
    SELECT 
        UCM.CampaignName,                    
        UCEH.BatchID,                        
        UCEH.ExecutionTime,                  
        CE.ReplyTo,                          
        CE.Status,                           
        CE.Message                           
    FROM 
        UserCampaignExecutionHistory UCEH
    INNER JOIN 
        UserCampaignMaster UCM ON UCEH.CampaignID = UCM.ID
    INNER JOIN 
        BatchEmail_Infos BEI ON UCEH.BatchID = BEI.BatchID
    INNER JOIN 
        ClientEmails CE ON BEI.BatchID = CE.BatchID
    WHERE 
        --(@UserId IS NULL OR UCEH.UserID = @UserId) 
		(@camid IS NULL OR UCEH.CampaignID = @camid)
        and (@FromDate IS NULL OR UCEH.ExecutionTime >= @FromDate) 
        AND (@ToDate IS NULL OR UCEH.ExecutionTime <= @ToDate);   

    -- Return Results
    SELECT * 
    FROM #TempResults;

    -- Cleanup
    DROP TABLE #TempResults;
END;



GO

/* ============================================================
   Procedure: [dbo].[usp_GetCampaignExecutionHistory]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[usp_GetCampaignExecutionHistory]
	@ParentID BIGINT,
	@CampaignID BIGINT
AS
BEGIN
	SELECT ucm.ID                         AS CampaignID,
	       ucm.CampaignName,
	       uceh.ExecutionTime,
	       uceh.NoOfRecipients,
	       isnull(nullif(uceh.Response,''),0) as Response,
	       uceh.BatchID
	FROM   UserCampaignExecutionHistory   AS uceh
	       INNER JOIN UserCampaignMaster  AS ucm
	            ON  uceh.CampaignID = ucm.ID
	WHERE  uceh.ParentID = @ParentID
	       AND uceh.CampaignID = @CampaignID order by uceh.ExecutionTime desc
END



GO

/* ============================================================
   Procedure: [dbo].[usp_GetCampaignExecutionModeDetails]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_GetCampaignExecutionModeDetails]
    @camid BIGINT = NULL,
    @UserId BIGINT = NULL, 
    @FromDate DATETIME = NULL, 
    @ToDate DATETIME = NULL,
    @Mode NVARCHAR(50), -- Mode to specify the type (e.g., 'voice', 'sms', 'email')
    @OffsetValue INT = 0, -- For pagination
    @PagingSize INT = 20 -- For pagination
AS
BEGIN
    SET NOCOUNT ON;

    DECLARE @StartPoint INT = @OffsetValue + 1;
    DECLARE @EndPoint INT = @PagingSize + @OffsetValue;

    -- Temporary table to store intermediate results with row numbers
    CREATE TABLE #TempResults (
        RowNumber INT,
        CampaignName NVARCHAR(255),
        BatchID INT,
        ExecutionDate DATETIME,
        ReplyTo NVARCHAR(255),
        Status NVARCHAR(50),
        Message NVARCHAR(MAX)
    );

    -- Temporary table to store total row count
    CREATE TABLE #TotalRows (
        TotalRows INT
    );

    -- Main Query to Fetch Data Based on Mode
    IF @Mode = 'voice'
    BEGIN
        INSERT INTO #TempResults (RowNumber, CampaignName, BatchID, ExecutionDate, ReplyTo, Status)
        SELECT 
            ROW_NUMBER() OVER (ORDER BY UCEH.ExecutionTime DESC) AS RowNumber,
            UCM.CampaignName,                    
            UCEH.BatchID,                        
            UCEH.ExecutionTime,                  
            CE.Mobile,                          
            CE.voiceStatus
        FROM 
            UserCampaignExecutionHistory UCEH
        INNER JOIN 
            UserCampaignMaster UCM ON UCEH.CampaignID = UCM.ID
        INNER JOIN 
            batchvoiceinfo BEI ON UCEH.BatchID = BEI.BatchID
        INNER JOIN 
            voice_deliverystatus CE ON BEI.BatchID = CE.BatchID
        WHERE 
            (@camid IS NULL OR UCEH.CampaignID = @camid) 
            AND UCM.Medium = 'voice'
            AND (@FromDate IS NULL OR UCEH.ExecutionTime >= @FromDate) 
            AND (@ToDate IS NULL OR UCEH.ExecutionTime <= @ToDate);

        INSERT INTO #TotalRows (TotalRows)
        SELECT COUNT(*)
        FROM 
            UserCampaignExecutionHistory UCEH
        INNER JOIN 
            UserCampaignMaster UCM ON UCEH.CampaignID = UCM.ID
        INNER JOIN 
            batchvoiceinfo BEI ON UCEH.BatchID = BEI.BatchID
        INNER JOIN 
            voice_deliverystatus CE ON BEI.BatchID = CE.BatchID
        WHERE 
            (@camid IS NULL OR UCEH.CampaignID = @camid) 
            AND UCM.Medium = 'voice'
            AND (@FromDate IS NULL OR UCEH.ExecutionTime >= @FromDate) 
            AND (@ToDate IS NULL OR UCEH.ExecutionTime <= @ToDate);
    END
    ELSE IF @Mode = 'sms'
    BEGIN
        INSERT INTO #TempResults (RowNumber, CampaignName, BatchID, ExecutionDate, ReplyTo, Status, Message)
        SELECT 
            ROW_NUMBER() OVER (ORDER BY UCEH.ExecutionTime DESC) AS RowNumber,
            UCM.CampaignName,                    
            UCEH.BatchID,                        
            UCEH.ExecutionTime,                  
            CE.Mobile,                          
            CE.MessageStatus,                           
            CE.Message
        FROM 
            UserCampaignExecutionHistory UCEH
        INNER JOIN 
            UserCampaignMaster UCM ON UCEH.CampaignID = UCM.ID
        INNER JOIN 
            batchinfo BEI ON UCEH.BatchID = BEI.BatchID
        INNER JOIN 
            messagedeliverystatus CE ON BEI.BatchID = CE.BatchID
        WHERE 
            (@camid IS NULL OR UCEH.CampaignID = @camid)
            AND (@FromDate IS NULL OR UCEH.ExecutionTime >= @FromDate) 
            AND (@ToDate IS NULL OR UCEH.ExecutionTime <= @ToDate);

        INSERT INTO #TotalRows (TotalRows)
        SELECT COUNT(*)
        FROM 
            UserCampaignExecutionHistory UCEH
        INNER JOIN 
            UserCampaignMaster UCM ON UCEH.CampaignID = UCM.ID
        INNER JOIN 
            batchinfo BEI ON UCEH.BatchID = BEI.BatchID
        INNER JOIN 
            messagedeliverystatus CE ON BEI.BatchID = CE.BatchID
        WHERE 
            (@camid IS NULL OR UCEH.CampaignID = @camid)
            AND (@FromDate IS NULL OR UCEH.ExecutionTime >= @FromDate) 
            AND (@ToDate IS NULL OR UCEH.ExecutionTime <= @ToDate);
    END
    ELSE IF @Mode = 'mail'
    BEGIN
        INSERT INTO #TempResults (RowNumber, CampaignName, BatchID, ExecutionDate, ReplyTo, Status, Message)
        SELECT 
            ROW_NUMBER() OVER (ORDER BY UCEH.ExecutionTime DESC) AS RowNumber,
            UCM.CampaignName,                    
            UCEH.BatchID,                        
            UCEH.ExecutionTime,                  
            CE.ReplyTo,                          
            CE.Status,                           
            CE.Message
        FROM 
            UserCampaignExecutionHistory UCEH
        INNER JOIN 
            UserCampaignMaster UCM ON UCEH.CampaignID = UCM.ID
        INNER JOIN 
            BatchEmail_Infos BEI ON UCEH.BatchID = BEI.BatchID
        INNER JOIN 
            ClientEmails CE ON BEI.BatchID = CE.BatchID
        WHERE 
            (@camid IS NULL OR UCEH.CampaignID = @camid)
            AND (@FromDate IS NULL OR UCEH.ExecutionTime >= @FromDate) 
            AND (@ToDate IS NULL OR UCEH.ExecutionTime <= @ToDate);

        INSERT INTO #TotalRows (TotalRows)
        SELECT COUNT(*)
        FROM 
            UserCampaignExecutionHistory UCEH
        INNER JOIN 
            UserCampaignMaster UCM ON UCEH.CampaignID = UCM.ID
        INNER JOIN 
            BatchEmail_Infos BEI ON UCEH.BatchID = BEI.BatchID
        INNER JOIN 
            ClientEmails CE ON BEI.BatchID = CE.BatchID
        WHERE 
            (@camid IS NULL OR UCEH.CampaignID = @camid)
            AND (@FromDate IS NULL OR UCEH.ExecutionTime >= @FromDate) 
            AND (@ToDate IS NULL OR UCEH.ExecutionTime <= @ToDate);
    END
    ELSE
    BEGIN
        -- Handle invalid mode
        RAISERROR('Invalid mode specified. Use ''voice'', ''sms'', or ''email''.', 16, 1);
        RETURN;
    END

    -- Return Paginated Results
    SELECT 
        RowNumber, CampaignName, BatchID, ExecutionDate, ReplyTo, Status, Message
    FROM 
        #TempResults
    WHERE 
        RowNumber BETWEEN @StartPoint AND @EndPoint;

    -- Return Total Rows
    SELECT TotalRows FROM #TotalRows;

    -- Cleanup
    DROP TABLE #TempResults;
    DROP TABLE #TotalRows;
END;



GO

/* ============================================================
   Procedure: [dbo].[usp_GetCampaignExecutionModeDetails1]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_GetCampaignExecutionModeDetails1]--------------------------------running sp
    @Mode NVARCHAR(10),
    @camid INT = NULL,
    @FromDate DATETIME = NULL,
    @ToDate DATETIME = NULL,
    @StartPoint INT,
    @EndPoint INT
AS
BEGIN
    -- Logic for 'voice' mode
    IF @Mode = 'voice'
    BEGIN
        -- Directly select data for 'voice' mode with total row count
        ;WITH VoiceResults AS (
            SELECT 
                ROW_NUMBER() OVER (ORDER BY UCEH.ExecutionTime DESC) AS RowNumber,
                UCM.CampaignName,
                UCEH.BatchID,
                UCEH.ExecutionTime,
                COALESCE(NULLIF(CE.Mobile, ''), 'N/A') AS ReplyTo,
                CE.voiceStatus AS Status
            FROM 
                UserCampaignExecutionHistory UCEH (NOLOCK)
            INNER JOIN 
                UserCampaignMaster UCM (NOLOCK) ON UCEH.CampaignID = UCM.ID
            INNER JOIN 
                batchvoiceinfo BEI (NOLOCK) ON UCEH.BatchID = BEI.BatchID
            INNER JOIN 
                voice_deliverystatus CE (NOLOCK) ON BEI.BatchID = CE.BatchID
            WHERE 
               1 = (CASE WHEN ISNULL(@camid, 0) = 0 THEN 1 
                         WHEN UCEH.CampaignID = @camid THEN 1 
                         ELSE 0 END) 
            AND UCM.Medium = 'mail'
            AND 1 = (CASE WHEN @FromDate IS NULL OR @ToDate IS NULL THEN 1 
                          WHEN CAST(UCEH.ExecutionTime AS DATE) BETWEEN CAST(@FromDate AS DATE) AND CAST(@ToDate AS DATE) THEN 1 
                          ELSE 0 END)
        )
        SELECT 
            RowNumber,
            CampaignName,
            BatchID,
            ExecutionTime AS ExecutionDate,
            ReplyTo,
            Status,
            (SELECT COUNT(*) FROM VoiceResults) AS TotalRows
        FROM VoiceResults
        WHERE RowNumber BETWEEN @StartPoint AND @EndPoint;
    END
 
    -- Logic for 'sms' mode
     IF @Mode = 'sms'
    BEGIN
        -- Directly select data for 'sms' mode with total row count
        ;WITH SmsResults AS (
            SELECT 
                ROW_NUMBER() OVER (ORDER BY UCEH.ExecutionTime DESC) AS RowNumber,
                UCM.CampaignName,
                UCEH.BatchID,
                UCEH.ExecutionTime,
                COALESCE(NULLIF(CE.Mobile, ''), 'N/A') AS ReplyTo,
                CE.MessageStatus AS Status
            FROM 
                UserCampaignExecutionHistory UCEH (NOLOCK)
            INNER JOIN 
                UserCampaignMaster UCM (NOLOCK) ON UCEH.CampaignID = UCM.ID
            INNER JOIN 
                batchinfo BEI (NOLOCK) ON UCEH.BatchID = BEI.BatchID
            INNER JOIN 
                messagedeliverystatus CE (NOLOCK) ON BEI.BatchID = CE.BatchID
            WHERE 
                1 = (CASE WHEN ISNULL(@camid, 0) = 0 THEN 1 
                          WHEN UCEH.CampaignID = @camid THEN 1 
                          ELSE 0 END) 
            AND UCM.Medium = 'mail'
            AND 1 = (CASE WHEN @FromDate IS NULL OR @ToDate IS NULL THEN 1 
                          WHEN CAST(UCEH.ExecutionTime AS DATE) BETWEEN CAST(@FromDate AS DATE) AND CAST(@ToDate AS DATE) THEN 1 
                          ELSE 0 END)
        )
        SELECT 
            RowNumber,
            CampaignName,
            BatchID,
            ExecutionTime AS ExecutionDate,
            ReplyTo,
            Status,
            (SELECT COUNT(*) FROM SmsResults) AS TotalRows
        FROM SmsResults
        WHERE RowNumber BETWEEN @StartPoint AND @EndPoint;
    END
 
    -- Logic for 'mail' mode
     IF @Mode = 'mail'
    BEGIN
        -- Directly select data for 'mail' mode with total row count
        ;WITH MailResults AS (
            SELECT 
                ROW_NUMBER() OVER (ORDER BY UCEH.ExecutionTime DESC) AS RowNumber,
                UCM.CampaignName,
                UCEH.BatchID,
                UCEH.ExecutionTime,
                COALESCE(NULLIF(CE.ReplyTo, ''), 'N/A') AS ReplyTo,
                CE.Status
                --CE.Message
            FROM 
                UserCampaignExecutionHistory UCEH (NOLOCK)
            INNER JOIN 
                UserCampaignMaster UCM (NOLOCK) ON UCEH.CampaignID = UCM.ID
            INNER JOIN 
                BatchEmail_Infos BEI (NOLOCK) ON UCEH.BatchID = BEI.BatchID
            INNER JOIN 
                ClientEmails CE (NOLOCK) ON BEI.BatchID = CE.BatchID
            WHERE 
               1 = (CASE WHEN ISNULL(@camid, 0) = 0 THEN 1 
                         WHEN UCEH.CampaignID = @camid THEN 1 
                         ELSE 0 END) 
            AND UCM.Medium = 'mail'
            AND 1 = (CASE WHEN @FromDate IS NULL OR @ToDate IS NULL THEN 1 
                          WHEN CAST(UCEH.ExecutionTime AS DATE) BETWEEN CAST(@FromDate AS DATE) AND CAST(@ToDate AS DATE) THEN 1 
                          ELSE 0 END)
        )
        SELECT 
            RowNumber,
            CampaignName,
            BatchID,
            ExecutionTime AS ExecutionDate,
            ReplyTo,
            Status,
            (SELECT COUNT(*) FROM MailResults) AS TotalRows
        FROM MailResults
        WHERE RowNumber BETWEEN @StartPoint AND @EndPoint;
    END
	 IF @Mode = 'whatsapp'
    BEGIN
 
        ;WITH WhatsappResults AS (
            SELECT 
                ROW_NUMBER() OVER (ORDER BY UCEH.ExecutionTime DESC) AS RowNumber,
                UCM.CampaignName,
                UCEH.BatchID,
                UCEH.ExecutionTime,
            COALESCE(NULLIF(JSON_VALUE(CE.requestjson, '$.whatsapp.to'), ''), 'N/A') AS ReplyTo,
            COALESCE(NULLIF(JSON_VALUE(CE.responsejson, '$.statusDesc'), ''), 'N/A') AS Status
                --CE.Message
            FROM 
                UserCampaignExecutionHistory UCEH (NOLOCK)
            INNER JOIN 
                UserCampaignMaster UCM (NOLOCK) ON UCEH.CampaignID = UCM.ID
            INNER JOIN 
                wbatchinfo BEI (NOLOCK) ON UCEH.BatchID = BEI.BatchID
            INNER JOIN 
                [10.0.0.135].mysmsConversations.dbo.tbl_ims_schedule_message CE (NOLOCK) ON BEI.BatchID = CE.BatchID
            WHERE 
               1 = (CASE WHEN ISNULL(@camid, 0) = 0 THEN 1 
                         WHEN UCEH.CampaignID = @camid THEN 1 
                         ELSE 0 END) 
            AND UCM.Medium = 'whatsapp'
            AND 1 = (CASE WHEN @FromDate IS NULL OR @ToDate IS NULL THEN 1 
                          WHEN CAST(UCEH.ExecutionTime AS DATE) BETWEEN CAST(@FromDate AS DATE) AND CAST(@ToDate AS DATE) THEN 1 
                          ELSE 0 END)
