/* ============================================================
   Procedure: [dbo].[usp_GetCampaignForCRM]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[usp_GetCampaignForCRM]
AS
BEGIN
	SELECT cm.CampaignName + '#' + ISNULL(
	           (
	               SELECT TOP 1 URLName
	               FROM   CampaignShortURL csu
	               WHERE  csu.CampaignName = cm.CampaignName
	                      AND Track_Unsubscribe = 1
	               ORDER BY
	                      csu.CreatedDate DESC
	           ),
	           ''
	       ) + '#' + ISNULL(
	           (
	               SELECT TOP 1 URLName
	               FROM   CampaignShortURL csu
	               WHERE  csu.CampaignName = cm.CampaignName
	                      AND Track_Unsubscribe = 0
	               ORDER BY
	                      csu.CreatedDate DESC
	           ),
	           ''
	       )               AS ID,
	       cm.CampaignName + ' (' + cm.[Message] + ')' AS CampaignName
	FROM   CampaignMaster     cm
	WHERE  SenderID IS NOT NULL
	UNION
	SELECT cm.CampaignName + '#' + ISNULL(
	           (
	               SELECT TOP 1 URLName
	               FROM   CampaignShortURL csu
	               WHERE  csu.CampaignName = cm.CampaignName
	                      AND Track_Unsubscribe = 1
	               ORDER BY
	                      csu.CreatedDate DESC
	           ),
	           ''
	       ) + '#' + ISNULL(
	           (
	               SELECT TOP 1 URLName
	               FROM   CampaignShortURL csu
	               WHERE  csu.CampaignName = cm.CampaignName
	                      AND Track_Unsubscribe = 0
	               ORDER BY
	                      csu.CreatedDate DESC
	           ),
	           ''
	       )               AS ID,
	       cm.CampaignName + ' (' + CASE 
	                                     WHEN ISNULL(cm.MailContent, '') <> '' THEN 
	                                          ISNULL(cm.MailContent, '')
	                                     ELSE ISNULL(cm.MailSubject, '')
	                                END + ')  '
	FROM   CampaignMaster     cm
	WHERE  SenderID IS NULL
END



GO

