CREATE   PROC [dbo].[Usp_GetCampaignIDByName] --'abcd1',335
(@CampaignName NVARCHAR(100), @UserID INT)
AS 
BEGIN
	SELECT ISNULL(CampaignID, 0) AS CampaignID
	FROM   UserCampaignSettings
	WHERE  NAME           = @CampaignName
	       AND UserID     = @UserID
END



GO

/* ============================================================
   Procedure: [dbo].[Usp_GetCampaignIDWise_EexecutionStatus]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

 CREATE   PROCEDURE dbo.Usp_GetCampaignIDWise_EexecutionStatus  --47  
--'27/10/2017','27/10/2017','',1,1            
(  
  
 @CampaignID_PRM Bigint  
  
 )    
  
AS    
  BEGIN    
      --declare @FromDate varchar(50)='27/10/2017',            
      --@Todate varchar(50)='28/10/2017',            
      --@UserLogin varchar(100)='',            
      --@SMS Bit =1,            
      --@Mail Bit=1        
      SELECT *    
      INTO   #temp    
      FROM   usercampaignmaster ucm    
      WHERE  ucm.ID = @CampaignID_PRM  
        
       --CONVERT(VARCHAR, CONVERT(DATETIME, UCM.nextexecutedatetime, 121),    
       --      112    
       --      ) BETWEEN    
       --      CONVERT(VARCHAR, CONVERT(DATETIME, @FromDate, 103), 112) AND    
       --             CONVERT(VARCHAR, CONVERT(DATETIME, @ToDate, 103), 112)    
    
      SELECT uch.*    
      INTO   #temp2    
      FROM   usercampaignhistory uch    
             JOIN #temp t    
               ON t.id = uch.campaignid   
                 
                  
      DECLARE @User_ID INT    
    
      --select CONVERT(varchar, CONVERT(datetime, @FromDate, 103), 112),CONVERT(varchar,dateadd(d,1,CONVERT(datetime,@ToDate, 103)), 112)      
      --select * from UserCampaignMaster ucm where CONVERT(varchar, CONVERT(datetime, UCM.NextExecuteDateTime, 121), 112) between CONVERT(varchar, CONVERT(datetime, @FromDate, 103), 112)  and  CONVERT(varchar,dateadd(d,1,CONVERT(datetime,@ToDate, 103)), 112)      
      -- --Declare @FromDate varchar(50) = '14/10/2017',@ToDate varchar(50) = '25/10/2017'            
      -- --Declare @SMS Bit = 1 , @Mail bit = 1             
      -- --Declare @UserLogin varchar(100) =  'sms19'        
      -- select top 1 CONVERT(varchar, CONVERT(datetime, UCM.NextExecuteDateTime, 121), 112) from UserCampaignMaster ucm         
       
    
      --IF( @UserLogin <> '' )    
      --  BEGIN    
      --      SELECT @User_ID = user_id    
      --      FROM   user_detail    
      --      WHERE  user_login = @UserLogin    
    
      --      SELECT UCM.id,    
      --             CASE    
      --               WHEN UCH.issms = 1 THEN 'SMS'    
      --               ELSE 'Mail'    
      --             END                               AS Type,    
      --             (SELECT user_login    
      --              FROM   user_detail    
      --              WHERE  user_id = @User_ID)       AS UserLogin,    
      --             UCM.campaignname,    
      --             UCM.nextexecutedatetime,    
      --             (SELECT tbl1.createdon    
      --              FROM   (SELECT campaignid,    
      --                             createdon    
      --                      FROM   #temp2 UCH2 (nolock)    
      --                      WHERE  UCH2.id =    
      --                             (SELECT Min(uch3.id)    
      --                              FROM   #temp2 (nolock)uch3    
      --                              WHERE  uch3.campaignid = uch2.campaignid))    
      --                     AS    
      --                     tbl1    
      --              WHERE  tbl1.campaignid = UCM.id) AS FirstExecutionDateTime,    
      --             (SELECT tbl1.createdon    
      --              FROM   (SELECT campaignid,    
      --                             createdon    
      --                      FROM   #temp2 UCH2 (nolock)    
      --                      WHERE  UCH2.id =    
      --                             (SELECT Max(uch3.id)    
      --                              FROM   #temp2 (nolock) uch3    
      --                              WHERE  uch3.campaignid = uch2.campaignid))    
      --                     AS    
      --                     tbl1    
      --              WHERE  tbl1.campaignid = UCM.id) AS LastExecutionDateTime,    
      --             ( CASE    
      --                 WHEN UCM.nextexecutedatetime < Getdate()    
      --                      AND (SELECT TOP 1 UCH1.id    
      --                           FROM   #temp2 UCH1 (nolock)    
      --                           WHERE  UCH1.campaignid = UCM.id) IS NULL THEN    
      --                 'Execution Not Attempted'    
      --                 WHEN UCM.nextexecutedatetime > Getdate() THEN    
      --                 'Yet To Be Executed'    
      --                 WHEN UCH.step3 = 1 THEN 'Executed at '    
      --                                   + Isnull(Cast(step3datetime AS    
      --                                         NVARCHAR    
      --                                         ),    
      --                                         '')    
      --                 WHEN step2 = 1 THEN 'Step2 Executed at '    
      --                                     + Isnull(Cast(step2datetime AS    
      --                                     NVARCHAR    
      --                                     ),    
      --                                     '')    
      --                 WHEN step1 = 1 THEN 'Step1 Executed  at '    
      --                                     + Isnull(Cast(step1datetime AS    
      --                                     NVARCHAR    
      --                                     ),    
      --                                     '')    
      --                 WHEN UCH.step1 = 0 THEN 'Execution Started at '    
      --                                         + Cast(UCH.createdon AS VARCHAR)    
      --               END )                           AS Status    
      --      FROM   #temp UCM(nolock)    
      --             LEFT OUTER JOIN #temp2 UCH(nolock)    
      --                          ON UCM.id = UCH.campaignid    
      --      WHERE  CONVERT(VARCHAR, CONVERT(DATETIME, UCM.nextexecutedatetime,    
      --                              121    
      --                              ),    
      --             112    
      --             ) BETWEEN    
      --                    CONVERT(VARCHAR, CONVERT(DATETIME, @FromDate, 103),    
      --                    112)    
      --                    AND    
      --                    CONVERT(VARCHAR, Dateadd(d, 1, CONVERT(DATETIME,    
      --                                                   @ToDate    
      --                                                   ,    
      --                                                   103)    
      --                                     ),    
      --                    112)    
      --             AND ( UCM.parentid = @User_ID )    
      --             AND ( ( UCH.issms = CASE    
      --                                   WHEN @SMS = 1 THEN @SMS    
      --                                   ELSE NULL    
      --                                 END )    
      --                    OR ( UCH.ismail = CASE    
      --                                        WHEN @Mail = 1 THEN @Mail    
      --                                        ELSE NULL    
      --                                      END ) )    
      --             AND ( UCH.id IS NULL    
      --                    OR uch.id = (SELECT Max(id)    
      --                                 FROM   #temp2 uch1 (nolock)    
      --                                 WHERE    
      --                 uch1.campaignid = uch.campaignid) )    
      --      GROUP  BY UCM.id,    
      --                UCM.createdby,    
      --                UCM.campaignname,    
      --                nextexecutedatetime,    
      --                uch.issms,    
      --                uch.createdon,    
      --                uch.campaignid,    
      --                uch.id,    
      --                UCH.step1,    
      --                UCH.step1datetime,    
      --                UCH.step2,    
      --                UCH.step2datetime,    
      --                UCH.step3,    
      --                UCH.step3datetime    
      --  END    
      --ELSE    
        BEGIN    
            --declare @CountID bigint =0          
            --  SELECT @CountID = Count(UCH.ID)FROM #temp2 UCH JOIN #temp UCM ON UCH.CampaignID=UCM.ID          
            SELECT UCM.id,    
                   CASE    
                     WHEN UCH.issms = 1 THEN 'SMS'    
                     ELSE 'Mail'    
                   END                               AS Type,    
                   (SELECT user_login    
                    FROM   user_detail    
                    WHERE  user_id = UCM.createdby)  AS UserLogin,    
                   UCM.campaignname,    
                   UCM.nextexecutedatetime,    
                   (SELECT tbl1.createdon    
                    FROM   (SELECT campaignid,    
                                   createdon    
                            FROM   #temp2 UCH2 (nolock)    
                    WHERE  UCH2.id =    
                                   (SELECT Min(uch3.id)    
                                    FROM   #temp2 uch3 (nolock)    
                                    WHERE  uch3.campaignid = uch2.campaignid))    
                           AS    
                           tbl1    
                    WHERE  tbl1.campaignid = UCM.id) AS FirstExecutionDateTime,    
                   (SELECT tbl1.createdon    
                    FROM   (SELECT campaignid,    
                                   createdon    
                            FROM   #temp2 UCH2 (nolock)    
                            WHERE  UCH2.id =    
                                   (SELECT Max(uch3.id)    
                                    FROM   #temp2 uch3 (nolock)    
                                    WHERE  uch3.campaignid = uch2.campaignid))    
                           AS    
                           tbl1    
                    WHERE  tbl1.campaignid = UCM.id) AS LastExecutionDateTime,    
                   ( CASE    
                       WHEN UCM.nextexecutedatetime < Getdate()    
                            AND (SELECT TOP 1 UCH1.id    
                                 FROM   #temp2 UCH1 (nolock)    
                                 WHERE  UCH1.campaignid = UCM.id) IS NULL THEN    
                       'Execution Not Attempted'    
                       WHEN UCM.nextexecutedatetime > Getdate() THEN    
                       'Yet To Be Executed'    
                       WHEN UCH.step3 = 1 THEN 'Executed at '    
                                               + Isnull(Cast(step3datetime AS    
                                               NVARCHAR    
                                               ),    
                                               '')    
                       WHEN step2 = 1 THEN 'Step2 Executed at '    
                                           + Isnull(Cast(step2datetime AS    
                                           NVARCHAR    
                                           ),    
                                           '')    
                       WHEN step1 = 1 THEN 'Step1 Executed  at '    
                                           + Isnull(Cast(step1datetime AS    
                                           NVARCHAR    
                                           ),    
                                           '')    
                       WHEN UCH.step1 = 0 THEN 'Execution Started at '    
                                               + Cast(UCH.createdon AS VARCHAR)    
                     END )                           AS Status    
            FROM   #temp UCM(nolock)    
                   LEFT OUTER JOIN #temp2 UCH(nolock)    
                                ON UCM.id = UCH.campaignid    
            WHERE    
            --CONVERT(VARCHAR, CONVERT(DATETIME, UCM.nextexecutedatetime,    
            --                        121    
            --                        ),    
            --       112    
            --       ) BETWEEN    
            --              CONVERT(VARCHAR, CONVERT(DATETIME, @FromDate, 103),    
            --              112)    
            --              AND    
            --              CONVERT(VARCHAR, Dateadd(d, 1, CONVERT(DATETIME,    
            --                                             @ToDate    
            --                                             ,    
            -- 103)    
            --                               ),    
            --              112)    
            --       AND ( 1 = 1 )    
            --       AND ( ( UCH.issms = CASE    
            --                             WHEN @SMS = 1 THEN @SMS    
            --                             ELSE NULL    
            --                           END )    
            --              OR ( UCH.ismail = CASE    
            --                                  WHEN @Mail = 1 THEN @Mail    
            --                                  ELSE NULL    
            --                                END ) )   
              
                 UCM.ID = @CampaignID_PRM  
               
                   AND ( UCH.id IS NULL    
                          OR uch.id = (SELECT Max(id)    
                                       FROM   #temp2 uch1    
                                       WHERE    
                       uch1.campaignid = uch.campaignid) )    
            GROUP  BY UCM.id,    
                      UCM.createdby,    
                      UCM.campaignname,    
                      nextexecutedatetime,    
                      uch.issms,    
                      uch.createdon,    
                      uch.campaignid,    
                      uch.id,    
                      UCH.step1,    
                      UCH.step1datetime,    
                      UCH.step2,    
                      UCH.step2datetime,    
                      UCH.step3,    
                      UCH.step3datetime    
            ORDER  BY nextexecutedatetime    
        END    
    
      DROP TABLE #temp    
    
      DROP TABLE #temp2    
  END 


GO

/* ============================================================
   Procedure: [dbo].[Usp_GetCampaignList]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROC [dbo].[Usp_GetCampaignList]
AS 
BEGIN
	SELECT ID,
	       CampaignName
	FROM   CampaignMaster
	ORDER BY
	       ID DESC
END



GO

/* ============================================================
   Procedure: [dbo].[Usp_GetCampaignMaster]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.Usp_GetCampaignMaster --'','M'  
 @Search VARCHAR(100),  
 @IsSMS CHAR(1)  
AS  
BEGIN  
 IF @IsSMS = 'S'  
 BEGIN  
     SELECT A.ID,  
            A.CampaignName,  
            CASE   
                 WHEN ISNULL(A.InclusionsNumber, '') <> '' THEN '<p><b>Including Number:</b>' + A.InclusionsNumber +  
                      '</p>'  
                 ELSE ''  
            END + CASE   
                       WHEN A.IsSequential = 1 THEN '<p><b>Sequential Campaign</b></p>'   
                            + CASE   
                                   WHEN ISNULL(A.SequentialCampaign, '')   
                                        <> '' THEN '<p><b>Sequential Campaign:</b>'   
                                        + A.SequentialCampaign   
                                        +  
                                        '</p>'  
                                   ELSE ''  
                              END + CASE   
                                         WHEN ISNULL(A.ResponseList, '') <>  
                                              '' THEN '<p><b> Response:</b>'   
                                              + A.ResponseList +  
                                              '</p>'  
                                         ELSE ''  
                                    END + CASE   
                                               WHEN ISNULL(A.[Time], '') <>  
                                                    '' THEN '<p><b> Time:</b>' + CAST(A.[Time] AS VARCHAR(50))   
                                                    +  
                                                    '</p>'  
                                               ELSE ''  
                                          END  
                       ELSE ''  
                  END + CASE   
                             WHEN ISNULL(A.Applicabilty, '') <> '' THEN '<p><b>Applicabilty:</b>' + A.Applicabilty   
                                  +  
                                  '</p>'  
                             ELSE ''  
                        END   
            + CASE   
                   WHEN ISNULL(A.ExclusionsNumber, '') <> '' THEN '<p><b>Excluding Number:</b>' + A.ExclusionsNumber   
                        +  
                        '</p>'  
                   ELSE ''  
              END   
            + CASE   
                   WHEN ISNULL(A.Exclusions, '') <> '' THEN '<p><b>Exclusions:</b>' + A.Exclusions +  
                        '</p>'  
                   ELSE ''  
              END   
            + CASE   
                   WHEN ISNULL(A.SenderID, '') <> '' THEN '<p><b>SenderID:</b>' + A.SenderID +  
                        '</p>'  
                   ELSE ''  
              END   
            + CASE   
                   WHEN ISNULL(A.[Message], '') <> '' THEN '<p><b>Message:</b>' + A.[Message] +  
                        '</p>'  
                   ELSE ''  
              END + CASE   
                         WHEN ISNULL(A.IsUnicode, '') <> '' THEN '<p><b> Tags:</b>' + CASE   
                                                                                           WHEN A.IsUnicode = 1 THEN   
                                                                                                'Yes'  
                                                                                           ELSE 'No'  
                                                                                      END +  
                              '</p>'  
                         ELSE ''  
                    END   
            + CASE   
                   WHEN ISNULL(A.Accounts, '') <> '' THEN '<p><b> Accounts:</b>' + A.Accounts +  
                        '</p>'  
                   ELSE ''  
              END + CASE   
                         WHEN ISNULL(A.TrackResponse, '') <> '' THEN '<p><b> TrackResponse:</b>' + REPLACE(REPLACE(A.TrackResponse, 'C', 'Call'), 'M', 'Microsite')   
                              +  
                              '</p>'  
                         ELSE ''  
                    END + CASE   
                               WHEN ISNULL(A.UnsubscribePage, '') <> '' THEN '<p><b> Unsubscribe:</b>' + REPLACE(REPLACE(A.UnsubscribePage, 'C', 'Call'), 'M', 'Microsite')   
                                    +  
                                    '</p>'  
                               ELSE ''  
                          END + CASE   
                                     WHEN ISNULL(A.Tags, '') <> '' THEN '<p><b> Tags:</b>' + A.Tags +  
                                          '</p>'  
                                     ELSE ''  
                                END + CASE   
                                           WHEN ISNULL(A.ExpiryDate, '')   
                                                <> '' THEN '<p><b> Expiry Date:</b>'   
                                                +  
                                                CAST(A.ExpiryDate AS VARCHAR(50))   
                                                +  
                                                '</p>'  
                                           ELSE ''  
                                      END + CASE   
                                                 WHEN ISNULL(A.ScheduleTime, '')   
                                                      <> '' THEN '<p><b> Schedule Date:</b>'   
                                                      +  
                                                      CAST(A.ScheduleTime AS VARCHAR(50))   
                                                      +  
                                                      '</p>'  
                                                 ELSE ''  
                                            END AS SearchCriteria,  
            A.IsExecuted,
            A.isrunning,  
            A.NoOfRecipients  
     FROM   (  
                SELECT cm.ID,  
                       cm.CampaignName,  
                       cm.InclusionsNumber,  
                       cm.SequentialCampaign,  
                       (  
                           SELECT STUFF(  
                                      (  
                                          SELECT N', ' + ss.SearchName  
                                          FROM   SearchDetails AS ss  
                                                 INNER JOIN dbo.fn_Split(cm.Applicabilty, '#') AS fs  
                                                      ON  ss.ID = fs.[value]   
                                                          FOR XML   
                                                          PATH(''),  
                                                 TYPE  
                                      )   
                                      .value('text()[1]', 'nvarchar(max)'),  
                                      1,  
                                      2,  
                                      N''  
                                  )  
                       )               AS Applicabilty,  
                       cm.ExclusionsNumber,  
                       (  
                           SELECT STUFF(  
                                      (  
                                          SELECT N', ' + ss.SearchName  
                                          FROM   SavedSearch AS ss  
                                                 INNER JOIN dbo.fn_Split(cm.Exclusions, '#') AS fs  
                                                      ON  ss.ID = fs.[value]   
                                                          FOR XML   
                                                          PATH(''),  
                                                 TYPE  
                                      )   
                                      .value('text()[1]', 'nvarchar(max)'),  
                                      1,  
                                      2,  
                                      N''  
                                  )  
                       )               AS Exclusions,  
                       cm.SenderID,  
                       cm.[Message],  
                       cm.MailReplyTo,  
         cm.MailSubject,  
                       cm.MailContent,  
                       (  
                           SELECT ud.FName + ' ' + ud.LName + ' ( ' + uf.Name   
                                  + ' )'  
                           FROM   User_Detail AS ud  
                                  INNER JOIN User_Filter AS uf  
                                       ON  uf.Code = ud.userfilter  
                           WHERE  ud.[User_ID] = cm.Accounts  
                       )               AS Accounts,  
                       cm.IsSequential,  
                       CASE   
                            WHEN cm.ResponseList = 'immed' THEN 'Immediate'  
                            ELSE 'after'  
                       END             AS ResponseList,  
                       cm.[Time],  
                       (  
                           SELECT STUFF(  
                                      (  
                                          SELECT N', ' + fs.[Value]  
                                          FROM   dbo.fn_Split(cm.TrackResponse, '#') AS fs   
                                                 FOR XML   
                                                 PATH(''),  
                                                 TYPE  
                                      )   
                                      .value('text()[1]', 'nvarchar(max)'),  
                                      1,  
                                      2,  
                                      N''  
                                  )  
                       )               AS TrackResponse,  
                       cm.ResponseShortURL,  
                       (  
                           SELECT STUFF(  
                                      (  
                                          SELECT N', ' + fs.[Value]  
                                          FROM   dbo.fn_Split(cm.UnsubscribePage, '#') AS fs   
                                                 FOR XML   
                                                 PATH(''),  
                                                 TYPE  
                                      )   
                                      .value('text()[1]', 'nvarchar(max)'),  
                                      1,  
                                      2,  
                                      N''  
                                  )  
                       )               AS UnsubscribePage,  
                       cm.UnsubscribeMicrositeURL,  
                       cm.Tags,  
                       cm.ScheduleTime,  
                       cm.IsUnicode,  
                       CASE   
                            WHEN cm.IsExecuted = 1 THEN 1  
                            ELSE 0  
                       END             AS IsExecuted,  
                       cm.NoOfRecipients,  
                       cm.ExpiryDate,  
                       cm.CreatedOn ,
                       cm.isrunning
                        
                FROM   CampaignMaster  AS cm  
                       LEFT JOIN CreditAgent AS ca  
                            ON  ca.Id = cm.Createdby  
                WHERE  cm.IsActive = 1  
                       AND cm.SenderID IS NOT NULL  
                       AND (  
                               ISNULL(@Search, '') = ''  
                               OR cm.CampaignName LIKE '%' + @Search + '%'  
                               OR cm.[Message] LIKE '%' + @Search + '%'  
                           )  
            ) A  
     ORDER BY  
            A.CreatedOn DESC  
 END  
 ELSE  
 BEGIN  
     SELECT A.ID,  
            A.CampaignName,  
            CASE   
                 WHEN ISNULL(A.Applicabilty, '') <> '' THEN '<p><b>Applicabilty:</b>' + CAST(A.Applicabilty AS VARCHAR(5000))   
                      +  
                      '</p>'  
                 ELSE ''  
            END   
            + CASE   
                   WHEN ISNULL(A.ExclusionsNumber, '') <> '' THEN '<p><b>Excluding Number:</b>' + CAST(A.ExclusionsNumber AS VARCHAR(5000))   
                        +  
                        '</p>'  
        ELSE ''  
              END   
            + CASE   
                   WHEN ISNULL(A.Exclusions, '') <> '' THEN '<p><b>Exclusions:</b>' + CAST(A.Exclusions AS VARCHAR(5000))   
                        +  
                        '</p>'  
                   ELSE ''  
              END + CASE   
                         WHEN A.IsSequential = 1 THEN '<p><b>Sequential Campaign</b></p>'   
                              + CASE   
                                     WHEN ISNULL(A.SequentialCampaign, '')   
                                          <> '' THEN '<p><b>Sequential Campaign:</b>'   
                                          + A.SequentialCampaign   
                                          +  
                                          '</p>'  
                                     ELSE ''  
                                END + CASE   
                                           WHEN ISNULL(A.ResponseList, '') <>  
                                                '' THEN '<p><b> Response:</b>'   
                                                +  
                                                CAST(A.ResponseList AS VARCHAR(500)) +  
                                                '</p>'  
                                           ELSE ''  
                                      END + CASE   
                                                 WHEN ISNULL(A.[Time], '') <>  
                                                      '' THEN '<p><b> Time:</b>' + CAST(A.[Time] AS VARCHAR(50))   
                                                      +  
                                                      '</p>'  
                                                 ELSE ''  
                                            END  
                         ELSE ''  
                    END  
            + CASE   
                   WHEN ISNULL(A.MailReplyTo, '') <> '' THEN '<p><b>Reply To:</b>' + A.MailReplyTo +  
                        '</p>'  
                   ELSE ''  
              END   
            + CASE   
                   WHEN ISNULL(A.MailSubject, '') <> '' THEN '<p><b> Subject:</b>' + A.MailSubject +  
                        '</p>'  
                   ELSE ''  
              END + CASE   
                         WHEN ISNULL(A.MailContent, '') <> '' THEN '<p><b> Content:</b>' + A.MailContent +  
                              '</p>'  
                         ELSE ''  
                    END   
              
            + CASE   
                   WHEN ISNULL(A.Accounts, '') <> '' THEN '<p><b> Accounts:</b>' +  
                        CAST(A.Accounts AS VARCHAR(500)) +  
                        '</p>'  
                   ELSE ''  
              END + CASE   
                         WHEN ISNULL(A.TrackResponse, '') <> '' THEN '<p><b> TrackResponse:</b>' + REPLACE(REPLACE(A.TrackResponse, 'C', 'Call'), 'M', 'Microsite')   
                              +  
                              '</p>'  
                         ELSE ''  
                    END + CASE   
                               WHEN ISNULL(A.UnsubscribePage, '') <> '' THEN '<p><b> Unsubscribe:</b>' + REPLACE(REPLACE(A.UnsubscribePage, 'C', 'Call'), 'M', 'Microsite')   
                                    +  
                                    '</p>'  
                               ELSE ''  
                          END + CASE   
                                     WHEN ISNULL(A.Tags, '') <> '' THEN '<p><b> Tags:</b>' + A.Tags +  
                                          '</p>'  
                                     ELSE ''  
                                END + CASE   
                                           WHEN ISNULL(A.ExpiryDate, '')   
                                                <> '' THEN '<p><b> Expiry Date:</b>'   
                                                +  
                                                CAST(A.ExpiryDate AS VARCHAR(50))   
                                                +  
                                                '</p>'  
                                           ELSE ''  
                                      END + CASE   
                                                 WHEN ISNULL(A.ScheduleTime, '')   
                                                      <> '' THEN '<p><b> Schedule Date:</b>'   
                                                      +  
                                                      CAST(A.ScheduleTime AS VARCHAR(50))   
                                                      +  
                                                      '</p>'  
                                                 ELSE ''  
                                            END AS SearchCriteria,  
            A.IsExecuted,
            A.isrunning,   
            A.NoOfRecipients,  
            A.UserName,  
            A.UserPassword  
     FROM   (  
                SELECT cm.ID,  
                       ''              AS UserName,  
                       ''              AS UserPassword,  
                       cm.CampaignName,  
                       cm.SequentialCampaign,  
                       (  
                           SELECT STUFF(  
                                      (  
                                          SELECT N', ' + ss.SearchName  
                                          FROM   SavedSearch AS ss  
                                                 INNER JOIN dbo.fn_Split(cm.Applicabilty, '#') AS fs  
                                                      ON  ss.ID = fs.[value]   
                                                          FOR XML   
                                                          PATH(''),  
                                                 TYPE  
                                      )   
                                      .value('text()[1]', 'nvarchar(max)'),  
                                      1,  
                                      2,  
                                      N''  
                                  )  
                       )               AS Applicabilty,  
                       cm.ExclusionsNumber,  
                       (  
                           SELECT STUFF(  
                                      (  
                                          SELECT N', ' + ss.SearchName  
                                          FROM   SavedSearch AS ss  
                                                 INNER JOIN dbo.fn_Split(cm.Exclusions, '#') AS fs  
                                                      ON  ss.ID = fs.[value]   
                                                          FOR XML   
                                                          PATH(''),  
                                                 TYPE  
                                      )   
                                      .value('text()[1]', 'nvarchar(max)'),  
                                      1,  
                                      2,  
                                      N''  
                                  )  
                       )               AS Exclusions,  
                       cm.SenderID,  
                       cm.[Message],  
                       cm.MailReplyTo,  
                       cm.MailSubject,  
                       CAST(  
                           cm.MailContent COLLATE Latin1_General_CI_AI  
                           AS NVARCHAR(15)  
                       )               AS MailContent,  
                       (  
                           SELECT ud.Firstname + ' ' + ud.Middlename + ' ' +  
                                  ud.Lastname   
                                  + ' ( ' + ud.EmailId   
                                  + ' )'  
                           FROM   PelConnectDB.dbo.Users AS ud  
                           WHERE  CAST(ud.Username COLLATE Latin1_General_CI_AI AS NVARCHAR(MAX)) = cm.Accounts  
                       )               AS Accounts,  
                       cm.IsSequential,  
                       CASE   
                            WHEN cm.ResponseList = 'immed' THEN 'Immediate'  
                            ELSE 'after'  
                       END             AS ResponseList,  
                       cm.[Time],  
                       (  
                           SELECT STUFF(  
                                      (  
                                          SELECT N', ' + ss.SearchName  
                                          FROM   SavedSearch AS ss  
                                                 INNER JOIN dbo.fn_Split(cm.Exclusions, '#') AS fs  
                                                      ON  ss.ID = fs.[value]   
                                                          FOR XML   
                                                          PATH(''),  
                                                 TYPE  
                                      )   
                                      .value('text()[1]', 'nvarchar(max)'),  
                                      1,  
                                      2,  
                                      N''  
                                  )  
                       )               AS TrackResponse,  
                       cm.ResponseShortURL,  
                       cm.UnsubscribePage,  
                       cm.UnsubscribeMicrositeURL,  
                       cm.Tags,  
                       cm.ScheduleTime,  
                       CASE   
                            WHEN cm.IsExecuted = 1 THEN 1  
                            ELSE 0  
                       END             AS IsExecuted,  
                       cm.NoOfRecipients,  
                       cm.ExpiryDate,  
                       cm.CreatedOn,
                       cm.isrunning  
                FROM   CampaignMaster  AS cm  
                       LEFT JOIN CreditAgent AS ca  
                            ON  ca.Id = cm.Createdby  
                WHERE  cm.IsActive = 1  
                       AND cm.MailSubject IS NOT NULL  
                       AND (  
                               ISNULL(@Search, '') = ''  
                               OR cm.CampaignName LIKE '%' + @Search + '%'  
                               OR cm.MailSubject LIKE '%' + @Search + '%'  
                           )  
            ) A  
     ORDER BY  
            A.CreatedOn DESC  
 END  
END 


GO

