   Procedure: [dbo].[Usp_GetCampaignMasterAddCampaign]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.Usp_GetCampaignMasterAddCampaign --'','S'
	@Search VARCHAR(100),
	@IsSMS CHAR(1)
AS
BEGIN
	IF @IsSMS = 'S'
	BEGIN
	    SELECT cm.ID,
	           cm.CampaignName,
	           cm.Applicabilty,
	           cm.ExclusionsNumber,
	           cm.Exclusions,
	           cm.InclusionsNumber,
	           cm.IsDuplicates,
	           cm.SenderID,
	           cm.[Message],
	           cm.MailReplyTo,
	           cm.MailSubject,
	           cm.MailContent,
	           cm.Accounts,
	           cm.IsSequential,
	           cm.SequentialCampaign,
	           cm.ResponseList,
	           cm.[Time],
	           cm.TrackResponse,
	           cm.ResponseShortURL,
	           cm.UnsubscribePage,
	           cm.UnsubscribeMicrositeURL,
	           cm.Tags,
	           cm.ScheduleTime,
	           cm.IsActive,
	           cm.IsUnicode,
	           (
	               SELECT TOP 1 csu.URLName
	               FROM   CampaignShortURL AS csu
	               WHERE  csu.CampaignName = cm.CampaignName
	                      AND csu.Track_Unsubscribe = 1
	           )                      AS ResponseMicro,
	           (
	               SELECT TOP 1 csu.URLName
	               FROM   CampaignShortURL AS csu
	               WHERE  csu.CampaignName = cm.CampaignName
	                      AND csu.Track_Unsubscribe = 0
	           )                      AS UnsubscribeMicro,
	           STUFF(
	               (
	                   SELECT ',  ' + sd.SearchName + '(' + CASE 
	                                                             WHEN sd.IsKit19 
	                                                                  = 1 THEN 
	                                                                  'Kit19'
	                                                             ELSE CASE 
	                                                                       WHEN 
	                                                                            sd.IsKitever 
	                                                                            =
	                                                                            1 THEN 
	                                                                            'Kitever'
	                                                                       ELSE CASE 
	                                                                                 WHEN 
	                                                                                      sd.IsCRMDB 
	                                                                                      =
	                                                                                      1 THEN 
	                                                                                      'CRM'
	                                                                                 ELSE CASE 
	                                                                                           WHEN 
	                                                                                                sd.IsList 
	                                                                                                =
	                                                                                                1 THEN 
	                                                                                                'List'
	                                                                                           ELSE 
	                                                                                                ''
	                                                                                      END
	                                                                            END
	                                                                  END
	                                                        END + ')'
	                   FROM   SearchDetails AS sd
	                          INNER JOIN dbo.fn_Split(cm.Applicabilty, '#') AS 
	                               fs
	                               ON  sd.ID = fs.[value] 
	                                   FOR XML PATH('')
	               ),
	               1,
	               1,
	               ''
	           )                      AS ApplicabilityName,
	           STUFF(
	               (
	                   SELECT ',  ' + sd.SearchName + '(' + CASE 
	                                                             WHEN sd.IsKit19 
	                                                                  = 1 THEN 
	                                                                  'Kit19'
	                                                             ELSE CASE 
	                                                                       WHEN 
	                                                                            sd.IsKitever 
	                                                                            =
	                                                                            1 THEN 
	                                                                            'Kitever'
	                                                                       ELSE CASE 
	                                                                                 WHEN 
	                                                                                      sd.IsCRMDB 
	                                                                                      =
	                                                                                      1 THEN 
	                                                                                      'CRM'
	                                                                                 ELSE CASE 
	                                                                                           WHEN 
	                                                                                                sd.IsList 
	                                                                                                =
	                                                                                                1 THEN 
	                                                                                                'List'
	                                                                                           ELSE 
	                                                                                                ''
	                                                                                      END
	                                                                            END
	                                                                  END
	                                                        END + ')'
	                   FROM   SearchDetails AS sd
	                          INNER JOIN dbo.fn_Split(cm.Exclusions, '#') AS fs
	                               ON  sd.ID = fs.[value] 
	                                   FOR XML PATH('')
	               ),
	               1,
	               1,
	               ''
	           )                      AS ExclusionsName,
	           STUFF(
	               (
	                   SELECT ',  ' + REPLACE(cpd.PageName, 'www.kit19.com/', '') 
	                          + ' ( ' + csu.ShortUrl +
	                          ' )'
	                   FROM   ClientPageDetail AS cpd
	                          INNER JOIN ClientSiteUrl csu
	                               ON  csu.ClientPageiD = cpd.Id
	                          INNER JOIN dbo.fn_Split(cm.ResponseShortURL, '#') AS 
	                               fs
	                               ON  csu.Id = fs.[value] 
	                                   FOR XML PATH('')
	               ),
	               1,
	               1,
	               ''
	           )                      AS ResponseShortURLName,
	           STUFF(
	               (
	                   SELECT ',  ' + REPLACE(cpd.PageName, 'www.kit19.com/', '') 
	                          + ' ( ' + csu.ShortUrl +
	                          ' )'
	                   FROM   ClientPageDetail AS cpd
	                          INNER JOIN ClientSiteUrl csu
	                               ON  csu.ClientPageiD = cpd.Id
	                          INNER JOIN dbo.fn_Split(cm.UnsubscribeMicrositeURL, '#') AS 
	                               fs
	                               ON  csu.Id = fs.[value] 
	                                   FOR XML PATH('')
	               ),
	               1,
	               1,
	               ''
	           )                      AS UnsubscribeMicrositeURLName,
	           cm.ExpiryDate
	    FROM   CampaignMaster         AS cm
	           LEFT JOIN CreditAgent  AS ca
	                ON  ca.Id = cm.Createdby
	    WHERE  cm.IsActive = 1
	           AND cm.SenderID IS NOT NULL
	           AND (
	                   ISNULL(@Search, '') = ''
	                   OR cm.CampaignName LIKE '%' + @Search + '%'
	                   OR cm.[Message] LIKE '%' + @Search + '%'
	               )
	END
	ELSE
	BEGIN
	    SELECT cm.ID,
	           cm.CampaignName,
	           cm.Applicabilty,
	           cm.ExclusionsNumber,
	           cm.Exclusions,
	           cm.InclusionsNumber,
	           cm.IsDuplicates,
	           cm.SenderID,
	           cm.[Message],
	           cm.MailReplyTo,
	           cm.MailSubject,
	           cm.MailContent,
	           cm.Accounts,
	           cm.IsSequential,
	           cm.SequentialCampaign,
	           cm.ResponseList,
	           cm.[Time],
	           cm.TrackResponse,
	           cm.ResponseShortURL,
	           cm.UnsubscribePage,
	           cm.UnsubscribeMicrositeURL,
	           cm.Tags,
	           cm.ScheduleTime,
	           cm.IsActive,
	           cm.IsUnicode,
	           (
	               SELECT TOP 1 csu.URLName
	               FROM   CampaignShortURL AS csu
	               WHERE  csu.CampaignName = cm.CampaignName
	                      AND csu.Track_Unsubscribe = 1
	           )                      AS ResponseMicro,
	           (
	               SELECT TOP 1 csu.URLName
	               FROM   CampaignShortURL AS csu
	               WHERE  csu.CampaignName = cm.CampaignName
	                      AND csu.Track_Unsubscribe = 0
	           )                      AS UnsubscribeMicro,
	           STUFF(
	               (
	                   SELECT ',  ' + sd.SearchName + '(' + CASE 
	                                                             WHEN sd.IsKit19 
	                                                                  = 1 THEN 
	                                                                  'Kit19'
	                                                             ELSE CASE 
	                                                                       WHEN 
	                                                                            sd.IsKitever 
	                                                                            =
	                                                                            1 THEN 
	                                                                            'Kitever'
	                                                                       ELSE CASE 
	                                                                                 WHEN 
	                                                                                      sd.IsCRMDB 
	                                                                                      =
	                                                                                      1 THEN 
	                                                                                      'CRM'
	                                                                                 ELSE CASE 
	                                                                                           WHEN 
	                                                                                                sd.IsList 
	                                                                                                =
	                                                                                                1 THEN 
	                                                                                                'List'
	                                                                                           ELSE 
	                                                                                                ''
	                                                                                      END
	                                                                            END
	                                                                  END
	                                                        END + ')'
	                   FROM   SearchDetails AS sd
	                          INNER JOIN dbo.fn_Split(cm.Applicabilty, '#') AS 
	                               fs
	                               ON  sd.ID = fs.[value] 
	                                   FOR XML PATH('')
	               ),
	               1,
	               1,
	               ''
	           )                      AS ApplicabilityName,
	           STUFF(
	               (
	                   SELECT ',  ' + sd.SearchName + '(' + CASE 
	                                                             WHEN sd.IsKit19 
	                                                                  = 1 THEN 
	                                                                  'Kit19'
	                                                             ELSE CASE 
	                                                                       WHEN 
	                                                                            sd.IsKitever 
	                                                                            =
	                                                                            1 THEN 
	                                                                            'Kitever'
	                                                                       ELSE CASE 
	                                                                                 WHEN 
	                                                                                      sd.IsCRMDB 
	                                                                                      =
	                                                                                      1 THEN 
	                                                                                      'CRM'
	                                                                                 ELSE CASE 
	                                                                                           WHEN 
	                                                                                                sd.IsList 
	                                                                                                =
	                                                                                                1 THEN 
	                                                                                                'List'
	                                                                                           ELSE 
	                                                                                                ''
	                                                                                      END
	                                                                            END
	                                                                  END
	                                                        END + ')'
	                   FROM   SearchDetails AS sd
	                          INNER JOIN dbo.fn_Split(cm.Exclusions, '#') AS fs
	                               ON  sd.ID = fs.[value] 
	                                   FOR XML PATH('')
	               ),
	               1,
	               1,
	               ''
	           )                      AS ExclusionsName,
	           STUFF(
	               (
	                   SELECT ',  ' + REPLACE(cpd.PageName, 'www.kit19.com/', '') 
	                          + ' ( ' + csu.ShortUrl +
	                          ' )'
	                   FROM   ClientPageDetail AS cpd
	                          INNER JOIN ClientSiteUrl csu
	                               ON  csu.ClientPageiD = cpd.Id
	                          INNER JOIN dbo.fn_Split(cm.ResponseShortURL, '#') AS 
	                               fs
	                               ON  csu.Id = fs.[value] 
	                                   FOR XML PATH('')
	               ),
	               1,
	               1,
	               ''
	           )                      AS ResponseShortURLName,
	           STUFF(
	               (
	                   SELECT ',  ' + REPLACE(cpd.PageName, 'www.kit19.com/', '') 
	                          + ' ( ' + csu.ShortUrl +
	                          ' )'
	                   FROM   ClientPageDetail AS cpd
	                          INNER JOIN ClientSiteUrl csu
	                               ON  csu.ClientPageiD = cpd.Id
	                          INNER JOIN dbo.fn_Split(cm.UnsubscribeMicrositeURL, '#') AS 
	                               fs
	                               ON  csu.Id = fs.[value] 
	                                   FOR XML PATH('')
	               ),
	               1,
	               1,
	               ''
	           )                      AS UnsubscribeMicrositeURLName,
	           cm.ExpiryDate
	    FROM   CampaignMaster         AS cm
	           LEFT JOIN CreditAgent  AS ca
	                ON  ca.Id = cm.Createdby
	    WHERE  cm.IsActive = 1
	           AND cm.MailSubject IS NOT NULL
	           AND (
	                   ISNULL(@Search, '') = ''
	                   OR cm.CampaignName LIKE '%' + @Search + '%'
	                   OR cm.MailSubject LIKE '%' + @Search + '%'
	               )
	END
END 


