/* ============================================================
   Procedure: [dbo].[Usp_GetCampaignNameForEmailReport]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON



CREATE   PROCEDURE dbo.Usp_GetCampaignNameForEmailReport  --'CRM Mails','2021-01-01','2021-08-01',335   
 (  
   @CampaignType nvarchar(50) = null,  
   @DateFrom date = null ,  
   @DateTo date = null ,  
   @ParentID bigint  
 )  
as  
Begin  
  
select cast(isnull(scheduleddate,batchinserttime) as date) batchinserttime,               
coalesce(t.cname,c.campaignname,case when mail_source in ('emails','csv') then               
cast(isnull(scheduleddate,batchinserttime) as nvarchar(50))+'_'+cast(b.batchid as nvarchar)              
else 'CRM_'+mail_source end)              
 as campaignname,              
 case when t.id is not null then 'Triggered Campaign'              
 when c.id is not null and isnull(c.IsScheduled,0)=1 then 'Scheduled Campaign'               
 when c.id is not null and isnull(c.IsScheduled,0)=0 then 'Event Based Campaign'               
 when mail_source in ('emails','csv') then 'Bulk Mail Campaign'              
 else 'CRM Mails' end              
 as campaigntype    
into #batcht        
from               
MySMS.dbo.BatchEmail_Infos(nolock) b               
join MySMS.dbo.user_detail(nolock) u on u.User_ID=b.UserID              
left join MySMS.dbo.usercampaignmaster(nolock) c on c.ParentID=u.parentid and b.mail_source like 'campaign%'             
and cast(c.ID as nvarchar)=replace(b.mail_source,              
'Campaign :','')              
left join MySMS.dbo.triggeredcampaigns(nolock) t on c.eventid=t.eventid and t.mailcampaignid=c.id            
where u.ParentID=@ParentID              
and cast(isnull(scheduleddate,batchinserttime) as date) between @DateFrom and @DateTo       
      
select * into #batch from #batcht  
  where campaigntype =  case when (@CampaignType is null or @CampaignType = '') then campaigntype  
                             else @CampaignType      
                        end     
select distinct campaignname from #batch where campaignname is not null  
  
drop table #batcht  
drop table #batch  
  
End  




GO

/* ============================================================
   Procedure: [dbo].[Usp_GetCampaignRecipients]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

--select * from user_detail(nolock) where user_login like 'printdome%'  
CREATE   PROC [dbo].[Usp_GetCampaignRecipients] -- 44296
(@ParentID BIGINT)        
  AS        
BEGIN  
 SELECT CM.CampaignName,  
        tbl.CampaignID,  
        tbl.NoOfRecipients  
 FROM   (  
            SELECT CampaignID AS CampaignID,  
                   SUM([NoOfRecipients]) AS NoOfRecipients  
            FROM   UserCampaignExecutionHistory  (nolock)
            GROUP BY  
                   CampaignID  
        ) AS tbl  
        INNER JOIN UserCampaignMaster CM  (nolock)
             ON  tbl.CampaignID = CM.ID  
 WHERE  ParentID = @ParentID  
END   


GO

