	     @SearchID
	
	----------------Kitever Users END 
	
	----------------Kitever Leads
	CREATE TABLE #TempKiteverLeads
	(
		MicrositeName     VARCHAR(200) NULL,
		FirstName         VARCHAR(200) NULL,
		LastName          VARCHAR(200) NULL,
		Email             VARCHAR(200) NULL,
		Mobileno          VARCHAR(20) NULL,
		ADDRESS           NVARCHAR(200) NULL,
		City              NVARCHAR(200) NULL,
		Zip               NVARCHAR(20) NULL,
		Remarks           NVARCHAR(500) NULL,
		Source            TINYINT NULL
	) 
	
	INSERT INTO #TempKiteverLeads
	EXEC Usp_Get_Kitever_ClientLeadDetails
	     @SearchID
	
	----------------Kitever Users END 
	
	----------------CRM InternalUser
	CREATE TABLE #TempCRMInternalUser
	(
		USER_ID        INT,
		User_Login     VARCHAR(25),
		FName          VARCHAR(50) NULL,
		LName          VARCHAR(50) NULL,
		Email          VARCHAR(50) NULL,
		Mobileno       VARCHAR(20) NULL,
		ADDRESS        VARCHAR(200) NULL,
		RoleName       VARCHAR(200) NULL
	)
	
	INSERT INTO #TempCRMInternalUser
	EXEC usp_GetCRMInternalUsers
	     @SearchID
	
	----------------CRM InternalUser END 
	
	
	----------------CRM Preenquiry
	CREATE TABLE #TempCRMPreenquiry
	(
		EnqNo             VARCHAR(150) NULL,
		EnqDate           VARCHAR(150) NULL,
		NAME              VARCHAR(150) NULL,
		Mobileno          VARCHAR(150) NULL,
		R_Address         VARCHAR(150) NULL,
		O_Address         VARCHAR(150) NULL,
		Executive         VARCHAR(150) NULL,
		ServiceName       VARCHAR(150) NULL,
		STATUS            VARCHAR(150) NULL,
		VisitStatus       VARCHAR(150) NULL,
		MeetingStatus     VARCHAR(150) NULL,
		Mobileno2         VARCHAR(150) NULL,
		Mobileno3         VARCHAR(150) NULL,
		EMail             VARCHAR(150) NULL,
		Email2            VARCHAR(150) NULL,
		Email3            VARCHAR(150) NULL,
		company_name      VARCHAR(150) NULL
	)
	
	INSERT INTO #TempCRMPreenquiry
	EXEC usp_GetPreEnquiryExecute
	     @SearchID
	
	----------------CRM Preenquiry END 
	
	----------------CRM Unsubscribe
	CREATE TABLE #TempCRMUnsubscribe
	(
		Mobileno VARCHAR(15)
	)
	
	INSERT INTO #TempCRMUnsubscribe
	EXEC usp_GetMobileNumberUnsubscribed
	     @SearchID
	
	----------------CRM Unsubscribe END 
	SELECT Mobileno
	FROM   #TempKit19Users
	UNION
	SELECT Mobileno
	FROM   #TempKit19Leads
	UNION
	SELECT Mobileno
	FROM   #TempKiteverUsers
	UNION
	SELECT Mobileno
	FROM   #TempKiteverLeads
	UNION
	SELECT Mobileno
	FROM   #TempCRMInternalUser
	UNION
	SELECT Mobileno
	FROM   #TempCRMPreenquiry
	UNION
	SELECT Mobileno
	FROM   #TempCRMUnsubscribe
	
	DROP TABLE #TempKit19Users 
	DROP TABLE #TempKit19Leads
	DROP TABLE #TempKiteverUsers
	DROP TABLE #TempKiteverLeads
	DROP TABLE #TempCRMInternalUser
	DROP TABLE #TempCRMPreenquiry
	DROP TABLE #TempCRMUnsubscribe
END



