/* ============================================================
   Procedure: [dbo].[Usp_GetCampaignStatus]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.Usp_GetCampaignStatus --233,335    
(    
@EnqNo bigint,    
@kit19UserID bigint    
    
)     
    
as    
    
Begin    
    
  Declare @DateCurrentTo date = null    
  Declare @Status nvarchar(50) = 'Red'    
    
   CREATE TABLE #TempLinked                                      
    (                                      
      Result VARCHAR(200)                                      
    )             
                        
     INSERT INTO #TempLinked                                      
     EXEC GetStatusofLinkedServer 'CRM'                                      
     IF NOT EXISTS(                                      
        SELECT 'x'                                      
        FROM   #TempLinked                                      
    )                           
    begin       
    
    select @DateCurrentTo = convert(date,CreatedDate) From CRM.CRMDB.dbo.AccountSetup where EnqNo = @EnqNo and UserBy = @kit19UserID     
 and Stage = 'Customer Accepted Setup Request'      
     
  
    --Declare @DateCurrentTo date = null    
   --set @DateCurrentTo = '2016-01-01 21:08:03.167'    
   --Declare @Status nvarchar(50) = 'Red'    
    
   if(exists(    
   select ID from UserCampaignMaster where ParentID = @kit19UserID and IsEventBased = 1 and (EventsName='ENQADD') and CONVERT(date,CreatedOn) >= convert(date,@DateCurrentTo)    
   and id in (select CampaignID from UserCampaignHistory where  IsEventBased = 1 and isnull(ReasonIfNotRun,'') = '')))    
       
   Begin    
    
   if(exists(    
   select ID from UserCampaignMaster where ParentID = @kit19UserID and IsEventBased = 1 and (EventsName='FOLADD') and CONVERT(date,CreatedOn) >= convert(date,@DateCurrentTo)    
   and id in (select CampaignID from UserCampaignHistory where  IsEventBased = 1 and isnull(ReasonIfNotRun,'') = '')))    
       
   Begin    
      
    if(exists(    
   select ID from UserCampaignMaster where ParentID = @kit19UserID and IsEventBased = 1 and (EventsName='LEDADD') and CONVERT(date,CreatedOn) >= convert(date,@DateCurrentTo)    
   and id in (select CampaignID from UserCampaignHistory where  IsEventBased = 1 and isnull(ReasonIfNotRun,'') = '')))    
         
    Begin    
    
    if(exists(    
   select ID from UserCampaignMaster where ParentID = @kit19UserID and IsScheduled = 1  and CONVERT(date,CreatedOn) >= convert(date,@DateCurrentTo)    
   and id in (select CampaignID from UserCampaignHistory where  IsScheduled = 1 and isnull(ReasonIfNotRun,'') = '')))    
       
      Begin    
       select @Status = 'Green'    
   End    
    
    End    
    
   End    
    
   End    
    
  select @Status as status       
         
    
    
   end    
    
  drop table  #TempLinked    
    
    
End    
    



GO

/* ============================================================
   Procedure: [dbo].[Usp_getCategary]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC Usp_getCategary
( @filter int
)
AS
Begin 
Declare @categary INT
Set @categary = 0;
if(@filter <= 4)
Begin
set @categary = 4
end 
if(@filter>4 and @filter<=5)
Begin
set @categary=3
End
if(@filter>5 and @filter < 8)
Begin
Set @categary=2
end
if(@filter >= 8)
Begin
Set @categary=1
End
select @categary
End 



GO

