SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[usp_getCityName] --'Delhi'
	@StateName VARCHAR(50) = NULL
AS
BEGIN
	IF (ISNULL(@StateName, '') = '')
	BEGIN
	    SELECT mc.City_Name
	    FROM   M_City AS mc
	END
	ELSE
	BEGIN
	    SELECT mc.City_Name
	    FROM   M_City              AS mc
	           INNER JOIN M_State  AS ms
	                ON  ms.State_ID = mc.State_ID
	    WHERE  ms.State_Name = @StateName
	END
END



