/* ============================================================
   Procedure: [dbo].[Usp_GetClientLeadDetails]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC Usp_GetClientLeadDetails --25           
(
    @SearchID BIGINT,
    @SearchText VARCHAR(50) = NULL,
    @PageSize INT = 0
)      
AS                   
BEGIN
	BEGIN TRY
		SELECT DISTINCT fgun3.MicrositeName,
		       fgun3.FirstName,
		       fgun3.LastName,
		       fgun3.Email,
		       fgun3.Mobile,
		       fgun3.[ADDRESS],
		       fgun3.City,
		       fgun3.Zip,
		       fgun3.Remarks,
		       fgun3.Source,
		       fgun3.dateCreated
		FROM   SearchDetails AS sd
		       OUTER APPLY funcToGetLeadMicrosite_Datewise(sd.MicrositeName, sd.FromDate, sd.ToDate) AS 
		fgun3
		WHERE  sd.ID = @SearchID
		       AND fgun3.MicrositeName IS NOT NULL
		       AND (
		               ISNULL(@SearchText, '') = ''
		               OR fgun3.FirstName LIKE '%' + @Searchtext + '%'
		               OR fgun3.LastName LIKE '%' + @Searchtext + '%'
		               OR fgun3.Email LIKE '%' + @Searchtext + '%'
		               OR fgun3.Mobile LIKE '%' + @Searchtext + '%'
		               OR fgun3.[ADDRESS] LIKE '%' + @Searchtext + '%'
		           )
	END TRY
	BEGIN CATCH
		SELECT ERROR_NUMBER()     AS ErrorNumber,
		       ERROR_SEVERITY()   AS ErrorSeverity,
		       ERROR_STATE()      AS ErrorState,
		       ERROR_PROCEDURE()  AS ErrorProcedure,
		       ERROR_LINE()       AS ErrorLine,
		       ERROR_MESSAGE()    AS ErrorMessage
	END CATCH
END 


GO

