/* ============================================================
   Procedure: [dbo].[Usp_GetClientList]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


  
CREATE   PROCEDURE Usp_GetClientList  --0,50,''          
(        
  @OffsetValue INT = 0        
 ,@PagingSize INT = 50        
 ,@searchtext VARCHAR(50)=''        
          
)          
AS            
BEGIN        
       
  if(RTRIM(ltrim(@searchtext)) = '')      
   Begin      
        SELECT  count(1) over() as TotalRow,   User_login,Name,USER_ID,[PName],  FORMAT(LastLogin1,'dd-MMM-yyyy hh:mm:s tt') As Current_login,  
  FORMAT(LastLogin2 ,'dd-MMM-yyyy hh:mm:s tt') As Last_login   
        FROM (  
  SELECT ud1.User_Login, ISNULL(ud1.FName,'') +' '+ IsNull (ud1.LName,'') AS [Name], ud1.ID As User_ID ,ud1.ParentID, ud2.User_Login +' ('+   
  ISNULL(ud2.FName,'') +' '+ IsNull (ud2.LName,'')+')' AS [PName],  
  ud1.LastLogin1 , ud1.LastLogin2   
  FROM user_detail ud1 WITH(NOLOCK)        
  Inner Join User_Detail ud2 WITH (NOLOCK) on ud1.ParentID=ud2.user_id  
        ) dt        
       WHERE User_Login LIKE '%'+@searchtext+'%' Or Name LIKE '%'+@searchtext+'%' ORDER BY LastLogin1 desc,Name ASC         
        OFFSET @OffsetValue  Rows FETCH NEXT @PagingSize ROWS ONLY         
      
  END      
    ELSE      
   BEGIN      
          
        SELECT  count(1) over() as TotalRow,   User_login,Name,USER_ID,[PName],  FORMAT(LastLogin1,'dd-MMM-yyyy hh:mm:s tt') As Current_login,  
  FORMAT(LastLogin2 ,'dd-MMM-yyyy hh:mm:s tt') As Last_login   
        FROM (  
  SELECT ud1.User_Login, ISNULL(ud1.FName,'') +' '+ IsNull (ud1.LName,'') AS [Name], ud1.ID As User_ID ,ud1.ParentID, ud2.User_Login +' ('+   
  ISNULL(ud2.FName,'') +' '+ IsNull (ud2.LName,'')+')' AS [PName],  
  ud1.LastLogin1 , ud1.LastLogin2   
  FROM user_detail ud1 WITH(NOLOCK)        
  Inner Join User_Detail ud2 WITH (NOLOCK) on ud1.ParentID=ud2.user_id  
        ) dt            
      WHERE User_Login = @searchtext       
     ORDER BY LastLogin1 desc,Name ASC         
     OFFSET @OffsetValue  Rows FETCH NEXT @PagingSize ROWS ONLY         
           
   End      
      
      
END


GO

