/* ============================================================
   Procedure: [dbo].[Usp_GetCloudGroupUsersByGroupID]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[Usp_GetCloudGroupUsersByGroupID] --26
(
  @GroupID bigint
)
as
Begin
 
  SELECT
       CUG.id
      ,CUG.GroupId
      ,CUG.userid
      ,(select user_login from User_Detail(nolock) where User_ID = CUG.userid) as user_login
	  ,CUG.parentid
      ,CUG.Role
      ,CUG.Assign
      ,CUG.Active
      ,isnull(CUG.SequenceGRP,0) as SequenceGRP 
  FROM [Cloud_user_Group](nolock) as CUG 
  inner join dbo.User_Detail ud        
on ud.User_id = cug.userid  and ud.Status = 1               
  where CUG.GroupId = @GroupID order by ISNULL(SequenceGRP,0)  asc
 
end


