(  
  @GroupID bigint  
)  
as  
Begin  
  
  SELECT  
       CUG.id  
      ,CUG.GroupId  
      ,CUG.userid 
	  ,cug.calling_agentid
	  ,ca.Agentname
      ,(select user_login from User_Detail(nolock) where User_ID = CUG.userid) as user_login
	  ,ca.mobile
	  ,ca.email
      ,CUG.parentid  
      ,CUG.Role  
      ,CUG.Assign  
      ,CUG.Active  
      ,isnull(CUG.SequenceGRP,0) as SequenceGRP   
  FROM [Cloud_user_Group] as CUG (nolock)
  join Calling_Agents ca (nolock) on cug.calling_agentid=ca.id
  where CUG.GroupId = @GroupID order by ISNULL(SequenceGRP,0)  asc  
  
end


