/* ============================================================
   Procedure: [dbo].[usp_GetcommissionSlabs]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON



 CREATE   PROC [dbo].[usp_GetcommissionSlabs]    
@referid int,@isactive int=null    
as        
begin    
if exists(select 1 from referrer_details where id=@referid and isadmin=1)    
begin    
if @isactive is null    
begin    
select id,slabname,ServiceReferred,CommissionAmount,CommissionPercent,IsAmount,isnull(minimumorderamount,0) as minimumorderamount,[userGroup],[Description],ValidFrom,DateCreated,ValidTill,status from Referrer_Payout_Rates order by datecreated desc,status 
desc    
end    
else    
begin    
select id,slabname,ServiceReferred,CommissionAmount,CommissionPercent,IsAmount,isnull(minimumorderamount,0) as minimumorderamount,[userGroup],[Description],ValidFrom,DateCreated,ValidTill,status from Referrer_Payout_Rates where status=@isactive order by datecreated desc,status desc    
end    
end    
else    
begin    
select id,slabname,ServiceReferred,CommissionAmount,CommissionPercent,IsAmount,isnull(minimumorderamount,0) as minimumorderamount,[userGroup],[Description],ValidFrom,DateCreated,ValidTill,status from Referrer_Payout_Rates where status=1 and getdate() between validfrom and validtill order by datecreated desc,status desc    
end    
end    






GO

