/* ============================================================
   Procedure: [dbo].[usp_GetConsentByParentId]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[usp_GetConsentByParentId] --34594
    @UserID bigINT
AS
BEGIN
    SET NOCOUNT ON;

    BEGIN TRY
	declare @ParentId BIGINT;
	 select @ParentId = ParentID FROM User_Detail (NOLOCK) WHERE User_ID = @UserID;
        -- Check if consent exists for the given ParentId
        IF EXISTS (SELECT 1 FROM dbo.Consent WHERE ParentId = @ParentId)
        BEGIN
            -- Return only the message if the consent exists
            SELECT 'Consent exists' AS Message;
        END
        ELSE
        BEGIN
            -- Return a message if no consent record is found
            SELECT 'No consent find' AS Message;
        END
    END TRY
    BEGIN CATCH
        -- Return error message on failure
        SELECT ERROR_MESSAGE() AS ErrorMessage;
    END CATCH
END;



GO

