  where User_Detail.User_Login=@UserNameOrEmailID  and Reseller_Detail.Domain=@url and User_Detail.status=1        
  --and         
  --Reseller_Detail.Reseller_ID in(        
  --  select MIN(Reseller_ID) from reseller_detail where  Reseller_Detail.Domain=@url        
  --)                     
end        
end        
        
else        
 Begin        
             
          
declare @type2 varchar(2)                          
set @type2=( select top 1  User_Detail.type                          
  from User_Detail join Reseller_Detail on User_Detail.M_ID=Reseller_Detail.Reseller_ID                           
  where User_Detail.EMail=@UserNameOrEmailID  and Reseller_Detail.Domain=@url         
