  --)        
  )        
          
if @type2='0' or @type2='2'                          
 begin                          
  select User_Detail.CountryCode ,User_Detail.User_ID,User_Detail.EMail                       
  from User_Detail join Reseller_Detail on User_Detail.M_ID=Reseller_Detail.Reseller_ID                           
  where User_Detail.EMail=@UserNameOrEmailID  and Reseller_Detail.Domain=@url  and User_Detail.status=1        
          
  --and         
  --Reseller_Detail.Reseller_ID in(        
  --  select MIN(Reseller_ID) from reseller_detail where  Reseller_Detail.Domain=@url        
  --)        
                           
 end                                 
else                      
begin                      
select User_Detail.CountryCode ,User_Detail.User_ID,User_Detail.EMail                       
  from User_Detail join Reseller_Detail on User_Detail.User_ID=Reseller_Detail.User_ID                          
