      ,[IncludeList]
      ,[ExcludeSearch]
      ,[ExcludeGroup]
      ,[ExcludeList]
      ,[IncludeMobile]
      ,[ExcludeMobile]
      ,[IncludeMail]
      ,[Excludemail]
      ,[IsBillApplicability]
      ,[MinBillAmount]
      ,[MaxBillAmount]
      
     -- ,[StartDate]
