/* ============================================================
   Procedure: [dbo].[usp_GetCRMInternalUsers]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

        
        
CREATE   PROCEDURE dbo.usp_GetCRMInternalUsers
	@SearchID VARCHAR(MAX),
	@SearchText VARCHAR(50) = NULL,
	@PageSize INT = 0
AS
BEGIN
	BEGIN TRY
		SELECT A.[USER_ID],
		       A.User_Login,
		       A.FName,
		       A.LName,
		       A.Email,
		       A.Mobile,
		       A.[ADDRESS],
		       A.RoleName
		FROM   (
		           SELECT [USER_ID],
		                  User_Login,
		                  FName,
		                  LName,
		                  Email,
		                  Mobile,
		                  [ADDRESS],
		                  RoleName
		           FROM   [dbo].[funcToGetCRMDetails_InsertUsers_Users](@SearchID) 
		           UNION         
		           SELECT [USER_ID],
		                  User_Login,
		                  FName,
		                  LName,
		                  Email,
		                  Mobile,
		                  [ADDRESS],
		                  RoleName
		           FROM   [dbo].[funcToGetCRMDetails_InsertUsers_Role](@SearchID)
		       ) A
		WHERE  A.[USER_ID] IS NOT NULL
		       AND (
		               ISNULL(@SearchText, '') = ''
		               OR A.User_Login LIKE '%' + @SearchText + '%'
		               OR A.FName LIKE '%' + @SearchText + '%'
		               OR A.LName LIKE '%' + @SearchText + '%'
		               OR A.Email LIKE '%' + @SearchText + '%'
		               OR A.Mobile LIKE '%' + @SearchText + '%'
		               OR A.[ADDRESS] LIKE '%' + @SearchText + '%'
		               OR A.RoleName LIKE '%' + @SearchText + '%'
		           )
	END TRY
	BEGIN CATCH
		SELECT ERROR_NUMBER()     AS ErrorNumber,
		       ERROR_SEVERITY()   AS ErrorSeverity,
		       ERROR_STATE()      AS ErrorState,
		       ERROR_PROCEDURE()  AS ErrorProcedure,
		       ERROR_LINE()       AS ErrorLine,
		       ERROR_MESSAGE()    AS ErrorMessage
	END CATCH
END 


GO

/* ============================================================
   Procedure: [dbo].[Usp_getCrmKeyFromAcres99]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.Usp_getCrmKeyFromAcres99          
 as                                  
  Begin                 
                
  select a.id,a.Acres_UserName,a.Acres_PWD,a.Kit19ParentId,case when LastAPIHit<dateadd(dd,-30,getdate()) then  dateadd(dd,-30,getdate())        
  else LastAPIHit end LastAPIHit,case when LastDateFetched<dateadd(dd,-30,getdate()) then  dateadd(dd,-30,getdate())        
  else LastDateFetched end as LastDateFetched, isnull(u.EMail,'')          as Email        
     from Acres99_Mapping a (nolock)        
  join user_detail(nolock) u on u.User_ID=a.Kit19ParentID and u.status=1        
  join Price_UserSubscriptionDetails(nolock) p on p.UserID=u.User_ID and u.user_id=u.parentid and p.IsNewPlan=1 and p.PlanEndDate>getdate()        
  where a.status = 1 and                                
   (ISNULL(LastAPIHit,'') = '' or (DATEDIFF(minute,ISNULL(LastAPIHit,''),getdate()))>=10)          
   and isnull(a.ExpiredOn,dateadd(mi,5,getdate()))>getdate()        
  --  and a.ID = 2    
  order by ID desc                  
              
  End        
        
        
  --update Acres99_Mapping set expiredon=getdate() where id=4


GO

/* ============================================================
   Procedure: [dbo].[Usp_getCrmKeyFromExporter]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.Usp_getCrmKeyFromExporter                                  
  as                                  
  Begin                      
                                    
  select m.id,ExporterKey,ExporterEmailID,m.ParentId,LastAPIHit,LastDateFetched ,                  
 isnull(u.EMail,'') as Email,                
 (select top 1 isnull(EMail,'')  from User_Detail where User_ID = 335 ) as EmailMain,                
 isnull(u.User_Login,'') as UserLogin                    
 from tbl_ExporterMapping m (nolock) join user_detail (nolock) u on m.ParentId=u.User_ID              
 join Price_UserSubscriptionDetails p (nolock) on p.userid=u.User_ID and  u.user_id=u.ParentID  and isnewplan=1 and planenddate>getdate()            
 and u.status=1                             
 where m.status = 1 and isnull(m.ExporterEmailID,'') != '' and              
   (ISNULL(LastAPIHit,'') = '' or (DATEDIFF(minute,ISNULL(LastAPIHit,''),getdate()))>=15)        
           
   and m.createdon >= convert(datetime, '2022-03-26 23:00:01')        
     order by m.id desc                           
                                 
  End 


GO

