/* ============================================================
   Procedure: [dbo].[usp_getcrmmails]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE usp_getcrmmails
as
begin
CREATE TABLE #TempLinked                                                                
   (                                                                
        Result VARCHAR(200)                                                                
   )                                  
                               
  begin try                            
                            
                            
                            
    INSERT INTO #TempLinked                                                                
    EXEC GetStatusofLinkedServer 'CRM'                                                                
    IF NOT EXISTS(                                                                
       SELECT 'x'                                                                
       FROM   #TempLinked                                                                
   )                                                     
 begin       
declare @c int,@tr int,@batchid bigint=0,@tname nvarchar(200),@q nvarchar(max),@statusid bigint=0
select @c=count(distinct mail_batchid) from crm.crmdb.dbo.finalmailsend where isprocessed=0
while @c>0
begin
set @statusid=0
select @batchid=min(mail_batchid)  from crm.crmdb.dbo.finalmailsend where isprocessed=0 and mail_batchid>@batchid
if isnull(@batchid,0) <>0
begin
select @tr=count(1) from crm.crmdb.dbo.finalmailsend where mail_batchid=@batchid
select top 1 @tname=t_name  from crm.crmdb.dbo.finalmailsend where mail_batchid=@batchid

insert into CRM_SMS_Mail_Sent(medium,batchid,tname,cstatus,tcount)
select 'Mail',@batchid,@tname,0,@tr
select @statusid=SCOPE_IDENTITY()

select @q= 'insert into '+@tname+'(mailroute,IsMonitor,Mail_Attechement,Mail_BatchID,Mail_FromEmail,Mail_InsertedDate,Mail_ParentID,Mail_Priority,Mail_ScheduleDate,Mail_ScheduledTime,                
Mail_Subject,Mail_TempleteBody,Mail_TempleteName,Mail_ToEmail,Mail_UserID,Messages,TemplateID,count,source,mailsource)                
select mailroute,IsMonitor,Mail_Attechement,Mail_BatchID,Mail_FromEmail,Mail_InsertedDate,Mail_ParentID,Mail_Priority,null,null,                
Mail_Subject,Mail_TempleteBody,Mail_TempleteName,Mail_ToEmail,Mail_UserID,Messages,TemplateID,count,source,mailsource from 
crm.crmdb.dbo.finalmailsend where isprocessed=0 and mail_batchid='+cast(@batchid as nvarchar)+
'; update crm.crmdb.dbo.finalmailsend set isprocessed=1 where mail_batchid='+cast(@batchid as nvarchar)
print @q
exec sp_executesql @q

update CRM_SMS_Mail_Sent set cstatus=1 where id=@statusid

end
set @c=@c-1
end
end                              
                              
  end try                            
  begin catch                            
       exec Usp_inserterrorinfo                              
  end catch                 
                            
                            
   drop table #TempLinked      
end



GO

/* ============================================================
   Procedure: [dbo].[usp_getcrmmails_new]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

  
CREATE   PROCEDURE usp_getcrmmails_new  
as  
begin  
CREATE TABLE #TempLinked                                                                  
   (                                                                  
        Result VARCHAR(200)                                                                  
   )                                    
                                 
  begin try                              
                              
                              
                              
    INSERT INTO #TempLinked                                                                  
    EXEC GetStatusofLinkedServer 'CRM'                                                                  
    IF NOT EXISTS(                                                                  
       SELECT 'x'                                                                  
       FROM   #TempLinked                                                                  
   )                                                       
 begin         
declare @c int,@tr int,@batchid bigint=0,@tname nvarchar(200),@q nvarchar(max),@statusid bigint=0,@fms_id bigint=0  
select @c=count(distinct mail_batchid) from crm.crmdb.dbo.finalmailsend where isprocessed=0  
while @c>0  
begin  
set @statusid=0  
select @batchid=min(mail_batchid)  from crm.crmdb.dbo.finalmailsend where isprocessed=0 and mail_batchid>@batchid  
if isnull(@batchid,0) <>0  
begin  
select @tr=count(1),@fms_id=min(fms_id) from crm.crmdb.dbo.finalmailsend where mail_batchid=@batchid  
select top 1 @tname=t_name  from crm.crmdb.dbo.finalmailsend where mail_batchid=@batchid  
  
insert into CRM_SMS_Mail_Sent(medium,batchid,tname,cstatus,tcount)  
select 'Mail',@batchid,@tname,0,@tr  
select @statusid=SCOPE_IDENTITY()  
  
select @q= '
while exists (select 1 from crm.crmdb.dbo.finalmailsend where isprocessed=0 and mail_batchid='+cast(@batchid as nvarchar)+')
begin

insert into '+@tname+'(mailroute,IsMonitor,Mail_Attechement,Mail_BatchID,Mail_FromEmail,Mail_InsertedDate,Mail_ParentID,Mail_Priority,Mail_ScheduleDate,Mail_ScheduledTime,                  
Mail_Subject,Mail_TempleteBody,Mail_TempleteName,Mail_ToEmail,Mail_UserID,Messages,TemplateID,count,source,mailsource)                  
select top 5000 mailroute,IsMonitor,Mail_Attechement,Mail_BatchID,Mail_FromEmail,Mail_InsertedDate,Mail_ParentID,Mail_Priority,null,null,                  
Mail_Subject,Mail_TempleteBody,Mail_TempleteName,Mail_ToEmail,Mail_UserID,Messages,TemplateID,count,source,mailsource from   
crm.crmdb.dbo.finalmailsend where isprocessed=0 and mail_batchid='+cast(@batchid as nvarchar)+  
' and fms_id > '+cast(@fms_id as nvarchar) +' order by fms_id ;
update crm.crmdb.dbo.finalmailsend set isprocessed=1 where fms_id > '+cast(@fms_id as nvarchar) +' and mail_batchid='+cast(@batchid as nvarchar) +
';
select @fms_id=@fms_id + '+5000+' 
end
'  
print @q  
exec sp_executesql @q  
  
update CRM_SMS_Mail_Sent set cstatus=1 where id=@statusid  
  
end  
set @c=@c-1  
end  
end                                
                                
  end try                              
  begin catch                              
       exec Usp_inserterrorinfo                                
  end catch                   
                              
                              
   drop table #TempLinked        
end  


GO

