/* ============================================================
   Procedure: [dbo].[usp_GetCustomButtonDetails]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[usp_GetCustomButtonDetails]
    @BatchID INT,
	@ModuleCode nvarchar(Max)
AS
BEGIN
    SET NOCOUNT ON;

   

    -- Conditional query based on ModuleCode
    IF @Modulecode = 'PAG10031' --OR @Modulecode = 'PAG10002'
    BEGIN
        SELECT 
            wr.WebhookID,
            cb.ButtonName,
            wr.WebhookEntryID,
            wr.ErrorDetails AS Status, -- Alias ErrorDetails as Status
            wr.CreatedDate,
            wr.ProcessedDate
        FROM 
            tbl_cb_webhook_restbl wr
        INNER JOIN 
            tbl_CB_CustomButtons cb ON wr.WebhookID = cb.WebhookID
        WHERE 
            wr.WebhookID = @BatchID
            AND cb.ModuleCode = @Modulecode
        ORDER BY 
            wr.WebhookEntryID;
    END
    ELSE if @Modulecode = 'PAG10002'
    BEGIN
       SELECT 
            wr.WebhookID,
            cb.ButtonName,
            wr.WebhookEntryID,
            wr.ErrorDetails AS Status, -- Alias ErrorDetails as Status
            wr.CreatedDate,
            wr.ProcessedDate
        FROM 
            tbl_cb_webhook_restbl wr
        INNER JOIN 
            tbl_CB_CustomButtons cb ON wr.WebhookID = cb.WebhookID
        WHERE 
            wr.WebhookID = @BatchID
            AND cb.ModuleCode = @Modulecode
        ORDER BY 
            wr.WebhookEntryID;
    END
	
	ELSE
    BEGIN
        -- If the ModuleCode is not 'PAG10031' or 'PAG10002', handle accordingly or raise an error
        SELECT 'No matching records for the provided ModuleCode' AS Message;
    END


    SET NOCOUNT OFF;
END;



GO

