Last login in last 7 days
Leads added:
Manual
Automatic
Enquiries added:
Manual
Automatic
Follow ups added:
Manual
Automatic
Tasks operations: ( added, edited) 
Appointment operations:
Physical appointment operations:
Telephony:
Incoming calls
Click2call
Web form:
Visits/ form filled
Landing pages:
Visits/ form filled
Pipeline activities:
Invoice created
Quotation created
WhatsApp:
Broadcasts
Triggered campaigns
Chatbot sessions
SMS, Mail, Voice:
Promotions
Triggered campaigns
Ett:
Logged in users
Location:
Signed in users
Ticket:
Created
Active users
Team chat:
Sessions*/
CREATE   PROCEDURE [dbo].[usp_getcustomerusage]
@userid bigint=null
as
begin
drop table if exists #temp
drop table if exists #users
drop table if exists #leads
drop table if exists #Enquiries
drop table if exists #followups
drop table if exists #triggeredcampaigns
drop table if exists #Appointments
drop table if exists #calls
drop table if exists #chatbotSessions
drop table if exists #emails
drop table if exists #ett
drop table if exists #invoices
drop table if exists #LandingPageEntries
drop table if exists #LocationUsers
drop table if exists #PhysicalAppointments
drop table if exists #pipeline
drop table if exists #quotes
drop table if exists #sms
drop table if exists #tasks
drop table if exists #voices
drop table if exists #WebFormEntries
drop table if exists #WebPageVisits
drop table if exists #whatsappBroadcasted
DECLARE @sqlquery NVARCHAR(MAX);


select distinct u.user_id,u.user_login,u.CompnayName as Company,case --when a.am_name is not null then  AM_Name 
when l.user_id is null then 'Unlinked' else 'Unassigned' end
as AccountManager
,PlanStartDate as SubscriptionStart,planEnddate as SubscriptionExpiry
into #temp
from Price_UserSubscriptionDetails p (nolock)
 join user_detail u (nolock)
 on p.UserID=u.user_id
and p.IsNewPlan=1
left join LinkedAccount l on l.User_ID=u.User_ID and l.Verified=1
--left join CRM.CRMDB.[dbo].[Assign_accountmanager_Latest] a on l.RefrenceNo=a.[Refrence_No]
where u.user_id=u.ParentID and u.user_id=case when @userid is not null then @userid else u.user_id end
and PlanEndDate>=case when @userid is not null then cast(getdate() as date) else PlanEndDate end

Print concat(CAST(GETDATE() as Datetime2 (3) ),': #temp done')

select parentid,sum(case when status=1 then 1 else 0 end) ActiveUsers,
sum(case when status=0 then 1 else 0 end) InactiveUsers,
sum(case when lastlogin1>=dateadd(d,-7,getdate()) or t.userid is not null then 1 else 0 end) ActiveLast7Days
into #users
from user_detail(nolock) u 
left join 
(select  userid,max(createddate) CreatedDate from [tbl_mob_DeviceSyncHistory](nolock) where createddate>=dateadd(d,-7,getdate()) and IsActive=1 group by userid  )t on u.user_id=t.userid
group by parentid


  Print concat(CAST(GETDATE() as Datetime2 (3) ),': #users done')

select parentid,sum(case when enquirysource in (12,13,14,15,22,23,28,29) then 1 else 0 end) ManualLeads,
sum(case when enquirysource not in (12,13,14,15,22,23,28,29) then 1 else 0 end) AutomaticLeads,
sum(case when enquirysource in (12,13,14,15,22,23,28,29) and CreatedOn>=dateadd(d,-7,getdate()) then 1 else 0 end) ManualLeads7Days,
sum(case when enquirysource not in (12,13,14,15,22,23,28,29)  and CreatedOn>=dateadd(d,-7,getdate()) then 1 else 0 end) AutomaticLeads7Days
into #leads
from userleads(nolock)  group by parentid

  Print concat(CAST(GETDATE() as Datetime2 (3) ),': #leads done')

select parentid,sum(case when enquirysource in (12,13,14,15,22,23,28,29) then 1 else 0 end) ManualEnquiries,
sum(case when enquirysource not in (12,13,14,15,22,23,28,29) then 1 else 0 end) AutomaticEnquiries,
sum(case when enquirysource in (12,13,14,15,22,23,28,29) and CreatedDate>=dateadd(d,-7,getdate()) then 1 else 0 end) ManualEnquiries7Days,
sum(case when enquirysource not in (12,13,14,15,22,23,28,29)  and CreatedDate>=dateadd(d,-7,getdate()) then 1 else 0 end) AutomaticEnquiries7Days
into #Enquiries
from userenquiry(nolock)  group by parentid

  Print concat(CAST(GETDATE() as Datetime2 (3) ),': #enquiries done')

select parentid,count(1) FollowupsAdded,sum(case when CreatedOn>=dateadd(d,-7,getdate()) then 1 else 0 end) Followups7Days
into #followups
from leadinteractionhistory(nolock) group by parentid

  Print concat(CAST(GETDATE() as Datetime2 (3) ),': #followups done')

/* select parentid,count(1) As ActiveTriggeredCampaigns 
into #triggeredcampaigns
from triggeredcampaigns(nolock) t where isactive=1 and
(exists (select 1 from usercampaignmaster(nolock) where id in (t.smscampaignid,t.mailcampaignid,t.voicecampaignid,t.whatsappcampaignid) and isactive=1)
or exists(select 1 from mysmsconversations.dbo.tbl_WA_SequenceMaster(nolock) where sequenceid=t.sequenceid and isactive=1))
group by parentid     */

DROP TABLE IF EXISTS #temp3;
    CREATE TABLE #temp3 ([Name] varchar(200), UserId BIGINT, ParentId BIGINT, sequencetype nvarchar(20), s_eventid int, IsActive bit,IsDeleted bit,CreatedBy bigint,CreatedOn datetime );

DECLARE @query NVARCHAR(MAX);
SET @query = '
        SELECT Name , UserId , ParentId , sequencetype , s_eventid , IsActive ,IsDeleted ,CreatedBy ,CreatedOn
        FROM tbl_WA_SequenceMaster (NOLOCK) ';

    -- Execute the query using your CLR procedure
    INSERT INTO #temp3(Name , UserId , ParentId , sequencetype , s_eventid , IsActive ,IsDeleted ,CreatedBy ,CreatedOn)
    EXEC usp_clr_FillRemoteData @query;


select parentid,count(1) As ActiveTriggeredCampaigns 
into #triggeredcampaigns
from triggeredcampaigns(nolock) t where isactive=1 and
(exists (select 1 from usercampaignmaster(nolock) where id in (t.smscampaignid,t.mailcampaignid,t.voicecampaignid,t.whatsappcampaignid) and isactive=1)
--or exists(select 1 from mysmsconversations.dbo.tbl_WA_SequenceMaster(nolock) where sequenceid=t.sequenceid and isactive=1))
OR EXISTS ( SELECT 1 FROM #temp3 temp WHERE temp.sequenceid = t.sequenceid AND ISNULL(temp.isactive, 0) = 1))
group by parentid 



  Print concat(CAST(GETDATE() as Datetime2 (3) ),': #triggeredcampaigns done')

select dbo.ufn_getuserparentid(createdby) Parentid,
sum(case when istask=1 then 1 else 0 end) TasksAdded,sum(case when istask=1  and CreatedOn>=dateadd(d,-7,getdate()) then 1 else 0 end) 
TasksAdded7Days
into #tasks
from tbl_tsk_TaskHistory(nolock)  group by dbo.ufn_getuserparentid(createdby)

  Print concat(CAST(GETDATE() as Datetime2 (3) ),': #tasks done')

select dbo.ufn_getuserparentid(createdby) Parentid,
sum(case when istask=0 then 1 else 0 end) AppointmentsAdded,sum(case when istask=0  and CreatedOn>=dateadd(d,-7,getdate()) then 1 else 0 end) 
AppointmentsAdded7Days
into #Appointments
from tbl_tsk_TaskHistory(nolock)  group by dbo.ufn_getuserparentid(createdby)

  Print concat(CAST(GETDATE() as Datetime2 (3) ),': #appointments done')

select Parentid,
count(1) PhysicalAppointmentsAdded,sum(case when Createddate>=dateadd(d,-7,getdate()) then 1 else 0 end) 
PhysicalAppointments7Days
into #PhysicalAppointments
from TBL_ET_PhysicalAppointment(nolock)  group by Parentid

  Print concat(CAST(GETDATE() as Datetime2 (3) ),': #physical_appointment done')

select parentid,sum(case when direction='incoming' then 1 else 0 end) as IncomingCalls,
sum(case when direction<>'incoming' then 1 else 0 end) as OutgoingCalls,
sum(case when direction='incoming' and callcreatedon>=dateadd(d,-7,getdate()) then 1 else 0 end) as IncomingCalls7Days,
sum(case when direction<>'incoming'  and callcreatedon>=dateadd(d,-7,getdate()) then 1 else 0 end) as OutgoingCalls7Days
into #calls
from CallLog(nolock) group by Parentid

  Print concat(CAST(GETDATE() as Datetime2 (3) ),': #calllog done')

select dbo.ufn_getuserparentid(createdby) Parentid,count(1) PipelineAdded,sum(case when createddate>=dateadd(d,-7,getdate()) then 1 else 0 end)
PipelineAdded7Days
into #pipeline
from LeadPipelineMapping(nolock) group by dbo.ufn_getuserparentid(createdby)

  Print concat(CAST(GETDATE() as Datetime2 (3) ),': #pipeline done')

select parentid,sum(case when type= 'LandingPage' then 1 else 0 end) as LandingPageVisits
,sum(case when type<> 'LandingPage' then 1 else 0 end) as WebformVisits
,sum(case when type= 'LandingPage' and visitdate>=dateadd(d,-7,getdate()) then 1 else 0 end) as LandingPage7DaysVisits,
sum(case when type= 'LandingPage' and visitdate>=dateadd(d,-7,getdate())then 1 else 0 end) as Webform7DaysVisits
into #WebPageVisits
from VisitPageDetails(nolock) group by parentid

  Print concat(CAST(GETDATE() as Datetime2 (3) ),': #webpagevisits done')

select w.parentid,count(1) as WebFormEntries,
sum(case when t.EntryDate >=dateadd(d,-7,getdate())then 1 else 0 end) as Webform7DaysEntries
into #WebFormEntries
 from WebEntryTbl(nolock) t join WebFormTbl (nolock) w on w.FormId=t.formid
  group by parentid

    Print concat(CAST(GETDATE() as Datetime2 (3) ),': #webformentries done')

	/*
  select dbo.ufn_getuserparentid(w.CreatedBy) Parentid,count(1) as LandingPageEntries,
sum(case when t.DateCreated >=dateadd(d,-7,getdate())then 1 else 0 end) as LandingPage7DaysEntries
into #LandingPageEntries
 from ClientLeadDetails(nolock) t join ClientPageDetail (nolock) w on t.cname=right(w.pagename,len(t.cname))
  group by dbo.ufn_getuserparentid(w.CreatedBy)

    Print concat(CAST(GETDATE() as Datetime2 (3) ),': #landingpagenetries done')
*/
select parentid,count(1) InvoicesCreated,sum(case when created_at >=dateadd(d,-7,getdate())then 1 else 0 end) as Invoices7Days
into #invoices
from MySMSInvoicing.dbo.invoices(nolock)   group by parentid

  Print concat(CAST(GETDATE() as Datetime2 (3) ),': #invoices done')

select parentid,count(1) quotesCreated,sum(case when created_at >=dateadd(d,-7,getdate())then 1 else 0 end) as quotes7Days
into #quotes
from MySMSInvoicing.dbo.quotes(nolock)   group by parentid

  Print concat(CAST(GETDATE() as Datetime2 (3) ),': #quotes done')

/* select parentid,sum(totalbroadcasted) totalbroadcasted,sum(totaltriggered) TotalTriggered,sum(Broadcasted7Days) Broadcasted7Days,
sum(Triggered7Days) Triggered7Days
into #whatsappBroadcasted
from
(select dbo.ufn_GetUserParentId(createdby) Parentid,sum(case when isnull(broadcastid,0)>0 then 1 else 0 end) as TotalBroadcasted
,sum(case when isnull(batchid,0)>0 then 1 else 0 end) as TotalTriggered,
sum(case when isnull(broadcastid,0)>0 and createddate>=dateadd(d,-7,getdate())then 1 else 0 end) as Broadcasted7Days
,sum(case when isnull(batchid,0)>0 then 1 else 0 end) as Triggered7Days
from mysmsconversations.dbo.tbl_ims_schedule_message(nolock) group by dbo.ufn_GetUserParentId(createdby)
union
select dbo.ufn_GetUserParentId(createdby),sum(case when isnull(broadcastid,0)>0 then 1 else 0 end) as TotalBroadcasted
,sum(case when isnull(batchid,0)>0 then 1 else 0 end) as TotalTriggered,
sum(case when isnull(broadcastid,0)>0 and createddate>=dateadd(d,-7,getdate())then 1 else 0 end) as Broadcasted7Days
,sum(case when isnull(batchid,0)>0 then 1 else 0 end) as Triggered7Days
from mysmsconversations.dbo.tbl_ims_schedule_message(nolock) group by dbo.ufn_GetUserParentId(createdby)
) a group by Parentid      */




DROP TABLE IF EXISTS #temp1;
    CREATE TABLE #temp1 (broadcastid bigint, batchid BIGINT, createddate datetime);


SET @query = '
        SELECT broadcastid, batchid,createddate
        FROM tbl_ims_schedule_message (NOLOCK) ';

    -- Execute the query using your CLR procedure
    INSERT INTO #temp1(broadcastid, batchid,createddate)
    EXEC usp_clr_FillRemoteData @query;

DROP TABLE IF EXISTS #temp4;
    CREATE TABLE #temp4 (parentid bigint ,chatbotFlowSessionId bigint,createdOn datetime);


SET @query = '
        SELECT parentid, chatbotFlowSessionId,createdOn
        FROM tbl_ims_ChabotSessionAction (NOLOCK) ';

    -- Execute the query using your CLR procedure
    INSERT INTO #temp4(parentid, chatbotFlowSessionId,createdOn)
    EXEC usp_clr_FillRemoteData @query;

	DROP TABLE IF EXISTS #whatsappBroadcasted;
    CREATE TABLE #whatsappBroadcasted (parentid bigint ,totalbroadcasted int,TotalTriggered int,Broadcasted7Days int,Triggered7Days int);


set @query = 'select parentid,sum(totalbroadcasted) totalbroadcasted,sum(totaltriggered) TotalTriggered,sum(Broadcasted7Days) Broadcasted7Days,
sum(Triggered7Days) Triggered7Days
from
(select mysms.dbo.ufn_GetUserParentId(createdby) Parentid,sum(case when isnull(broadcastid,0)>0 then 1 else 0 end) as TotalBroadcasted
,sum(case when isnull(batchid,0)>0 then 1 else 0 end) as TotalTriggered,
sum(case when isnull(broadcastid,0)>0 and createddate>=dateadd(d,-7,getdate())then 1 else 0 end) as Broadcasted7Days
,sum(case when isnull(batchid,0)>0 then 1 else 0 end) as Triggered7Days
from tbl_ims_schedule_message(nolock) group by mysms.dbo.ufn_GetUserParentId(createdby)
union
select mysms.dbo.ufn_GetUserParentId(createdby),sum(case when isnull(broadcastid,0)>0 then 1 else 0 end) as TotalBroadcasted
,sum(case when isnull(batchid,0)>0 then 1 else 0 end) as TotalTriggered,
sum(case when isnull(broadcastid,0)>0 and createddate>=dateadd(d,-7,getdate())then 1 else 0 end) as Broadcasted7Days
,sum(case when isnull(batchid,0)>0 then 1 else 0 end) as Triggered7Days
from tbl_ims_schedule_message(nolock) group by mysms.dbo.ufn_GetUserParentId(createdby)
) a group by Parentid'    

    INSERT INTO #whatsappBroadcasted(parentid,totalbroadcasted,TotalTriggered,Broadcasted7Days,Triggered7Days)
    EXEC usp_clr_FillRemoteData @query;


  Print concat(CAST(GETDATE() as Datetime2 (3) ),': #whatsappbroadcast done')

select parentid,count(distinct chatbotFlowSessionId) ChatBotSessions,sum(case when createdon>=dateadd(d,-7,getdate())then 1 else 0 end)
ChatbotSessions7Days
into #chatbotSessions from
(select distinct parentid,chatbotFlowSessionId,cast(createdOn as date) createdon from #temp4
group by parentid,chatbotFlowSessionId,cast(createdOn as date)) a
group by parentid 




  Print concat(CAST(GETDATE() as Datetime2 (3) ),': #chatbot done')
/*
select dbo.ufn_GetUserParentId(userid) Parentid,
--sum(totalrecords) TotalSMS,sum(case when BatchInsertTime>=dateadd(d,-7,getdate()) then totalrecords else 0 end) SMS7Days,
sum(case when sms_source like 'Campaign%' or sms_source like 'Automation%' then TotalRecords else 0 end) as TriggeredSMS,
sum(case when sms_source like 'Mass%' then TotalRecords else 0 end) as CRMSMS,
sum(case when sms_source like 'Bulk%' or sms_source like 'API%' then TotalRecords else 0 end) as PromotionSMS,
sum(case when (sms_source like 'Campaign%' or sms_source like 'Automation%') and BatchInsertTime>=dateadd(d,-7,getdate()) then TotalRecords else 0 end) as Triggered7DaysSMS,
sum(case when sms_source like 'Mass%' and BatchInsertTime>=dateadd(d,-7,getdate())  then TotalRecords else 0 end) as CRM7DaysSMS,
sum(case when (sms_source like 'Bulk%' or sms_source like 'API%') and BatchInsertTime>=dateadd(d,-7,getdate())  then TotalRecords else 0 end) as Promotion7DaysSMS
--into #sms
from batchinfo(nolock) where batchinserttime>dateadd(yy,-1,getdate()) group by dbo.ufn_GetUserParentId(userid)

  Print concat(CAST(GETDATE() as Datetime2 (3) ),': #sms done')
*/
select dbo.ufn_GetUserParentId(userid) Parentid,sum(case when mail_source like 'Campaign%' or mail_source like 'Automation%' then TotalRecords else 0 end) as Triggeredemail,
sum(case when mail_source like 'Enquiry%' or mail_source like 'lead%' then TotalRecords else 0 end) as CRMemail,
sum(case when mail_source like 'csv%' or mail_source like 'group%'  or mail_source like 'emails%' then TotalRecords else 0 end) as Promotionemail,
sum(case when (mail_source like 'Campaign%' or mail_source like 'Automation%') and BatchInsertTime>=dateadd(d,-7,getdate()) then TotalRecords else 0 end) as Triggered7Daysemail,
sum(case when (mail_source like 'Enquiry%' or mail_source like 'lead%') and BatchInsertTime>=dateadd(d,-7,getdate())  then TotalRecords else 0 end) as CRM7Daysemail,
sum(case when (mail_source like 'csv%' or mail_source like 'group%'  or mail_source like 'emails%' or mail_source like 'API%') and BatchInsertTime>=dateadd(d,-7,getdate())  then TotalRecords else 0 end) as Promotion7Daysemail
into #emails
from batchemail_infos(nolock)  where batchinserttime>dateadd(yy,-1,getdate()) group by dbo.ufn_GetUserParentId(userid)

  Print concat(CAST(GETDATE() as Datetime2 (3) ),': #email done')

select dbo.ufn_GetUserParentId(userid) Parentid,sum(case when voice_source like 'Campaign%' or voice_source like 'Automation%' then TotalRecords else 0 end) as Triggeredvoice,
sum(case when voice_source like 'Enquiry%' or voice_source like 'lead%' then TotalRecords else 0 end) as CRMvoice,
sum(case when voice_source like 'bulk%' or voice_source is null then TotalRecords else 0 end) as Promotionvoice,
sum(case when (voice_source like 'Campaign%' or voice_source like 'Automation%') and BatchInsertTime>=dateadd(d,-7,getdate()) then TotalRecords else 0 end) as Triggered7Daysvoice,
sum(case when (voice_source like 'Enquiry%' or voice_source like 'lead%') and BatchInsertTime>=dateadd(d,-7,getdate())  then TotalRecords else 0 end) as CRM7Daysvoice,
sum(case when (voice_source like 'bulk%' or voice_source is null) and BatchInsertTime>=dateadd(d,-7,getdate()) then TotalRecords else 0 end) as Promotion7Daysvoice
into #voices
from BatchVoiceInfo(nolock)  where batchinserttime>dateadd(yy,-1,getdate()) group by dbo.ufn_GetUserParentId(userid)

  Print concat(CAST(GETDATE() as Datetime2 (3) ),': #voice done')

select dbo.ufn_GetUserParentId(user_id) Parentid,count(distinct user_id) as EttUsers,
(select count(distinct user_id) from MysmsTimeTrack.dbo.timetrackingloginstatus where dbo.ufn_GetUserParentId(user_id)=
dbo.ufn_GetUserParentId(t.user_id) and createdon >=dateadd(d,-7,getdate())) as ETTUsers7Days 
into #ett
from MysmsTimeTrack.dbo.timetrackingloginstatus t (nolock) group by dbo.ufn_GetUserParentId(user_id)

  Print concat(CAST(GETDATE() as Datetime2 (3) ),': #ett done')

select parentid,count(distinct userid) LocationUsers,
count(distinct case when createddate >=dateadd(d,-7,getdate()) then userid else 0 end) Location7DaysUsers
into #LocationUsers 
from
(select distinct parentid,userid,cast(createddate as date) createddate from  TBL_ET_Attendance(nolock) group by parentid,userid,cast(createddate as date)) 
a group by parentid

  Print concat(CAST(GETDATE() as Datetime2 (3) ),': #locationusers done')
/**/

select t.User_ID,t.User_Login,t.Company,t.AccountManager,t.SubscriptionStart,t.SubscriptionExpiry,isnull(u.ActiveUsers,0) ActiveUsers,
isnull(u.InactiveUsers,0) InactiveUsers,isnull(u.ActiveLast7Days,0) ActiveLast7Days,
ISNULL(l.AutomaticLeads, 0) AutomaticLeads, ISNULL(l.ManualLeads, 0) ManualLeads, ISNULL(l.AutomaticLeads7Days, 0) AutomaticLeads7Days, ISNULL(l.ManualLeads7Days, 0) ManualLeads7Days,
ISNULL(e.AutomaticEnquiries, 0) AutomaticEnquiries, ISNULL(e.ManualEnquiries, 0) ManualEnquiries, ISNULL(e.AutomaticEnquiries7Days, 0) AutomaticEnquiries7Days, ISNULL(e.ManualEnquiries7Days, 0) ManualEnquiries7Days,
ISNULL(f.FollowupsAdded, 0) FollowupsAdded, ISNULL(f.Followups7Days, 0) Followups7Days,isnull(tr.ActiveTriggeredCampaigns,0) ActiveTriggeredCampaigns,
ISNULL(pl.PipelineAdded, 0) PipelineAdded, ISNULL(pl.PipelineAdded7Days, 0) PipelineAdded7Days,
ISNULL(ts.TasksAdded, 0) TasksAdded, ISNULL(ts.TasksAdded7Days, 0) TasksAdded7Days, ISNULL(a.AppointmentsAdded, 0) AppointmentsAdded, ISNULL(a.AppointmentsAdded7Days, 0) AppointmentsAdded7Days, ISNULL(p.PhysicalAppointmentsAdded, 0) PhysicalAppointmentsAdded, ISNULL(p.PhysicalAppointments7Days, 0) PhysicalAppointments7Days,
ISNULL(c.IncomingCalls, 0) IncomingCalls, ISNULL(c.OutgoingCalls, 0) OutgoingCalls, ISNULL(c.IncomingCalls7Days, 0) IncomingCalls7Days, ISNULL(c.OutgoingCalls7Days, 0) OutgoingCalls7Days,
ISNULL(w.LandingPageVisits, 0) LandingPageVisits, ISNULL(w.WebformVisits, 0) WebformVisits, ISNULL(w.LandingPage7DaysVisits, 0) LandingPage7DaysVisits, ISNULL(w.Webform7DaysVisits, 0) Webform7DaysVisits,
ISNULL(we.WebFormEntries, 0) WebFormEntries, ISNULL(we.Webform7DaysEntries, 0) Webform7DaysEntries,
--isnull(lp.LandingPageEntries,0) LandingPageEntries,isnull(lp.LandingPage7DaysEntries,0) LandingPage7DaysEntries,
ISNULL(q.quotesCreated, 0) quotesCreated, ISNULL(q.quotes7Days, 0) quotes7Days, ISNULL(i.InvoicesCreated, 0) InvoicesCreated, ISNULL(i.Invoices7Days, 0) Invoices7Days,
ISNULL(wb.totalbroadcasted, 0) totalbroadcasted, ISNULL(wb.Broadcasted7Days, 0) Broadcasted7Days, ISNULL(wb.TotalTriggered, 0) TotalTriggered, ISNULL(wb.Triggered7Days, 0) Triggered7Days,
ISNULL(cs.ChatBotSessions, 0) ChatBotSessions, ISNULL(cs.ChatbotSessions7Days, 0) ChatbotSessions7Days,
--isnull(s.CRMSMS,0) CRMSMS,isnull(s.CRM7DaysSMS,0) CRM7DaysSMS,isnull(s.TriggeredSMS,0)TriggeredSMS,isnull(s.Triggered7DaysSMS,0) Triggered7DaysSMS,isnull(s.PromotionSMS,0) PromotionSMS,isnull(s.Promotion7DaysSMS,0) Promotion7DaysSMS,
ISNULL(m.CRMemail, 0) CRMemail, ISNULL(m.CRM7Daysemail, 0) CRM7Daysemail, ISNULL(m.Triggeredemail, 0) Triggeredemail, ISNULL(m.Triggeredemail, 0) Triggeredemail, ISNULL(m.Promotionemail, 0) Promotionemail, ISNULL(m.Promotion7Daysemail, 0) Promotion7Daysemail,
ISNULL(v.CRMvoice, 0) CRMvoice, ISNULL(v.CRM7Daysvoice, 0) CRM7Daysvoice, ISNULL(v.Triggeredvoice, 0) Triggeredvoice, ISNULL(v.Triggeredvoice, 0) Triggeredvoice, ISNULL(v.Promotionvoice, 0) Promotionvoice, ISNULL(v.Promotion7Daysvoice, 0) Promotion7Daysvoice,
ISNULL(et.EttUsers, 0) EttUsers, ISNULL(et.ETTUsers7Days, 0) ETTUsers7Days, ISNULL(lc.LocationUsers, 0) LocationUsers, ISNULL(lc.Location7DaysUsers, 0) Location7DaysUsers
from 
#temp t
left join #users u on u.parentid=t.user_id
left join #leads l on l.parentid=t.user_id
left join #enquiries e on e.parentid=t.user_id
left join #followups f on f.parentid=t.user_id
left join #triggeredcampaigns tr on tr.parentid=t.User_ID
left join #tasks ts on ts.parentid=t.user_id
left join #appointments a on a.parentid=t.user_id
left join #PhysicalAppointments p on p.parentid=t.user_id
left join #calls c on c.parentid=t.user_id
left join #WebPageVisits w on w.parentid=t.user_id
left join #WebFormEntries we on we.parentid=t.user_id
--left join #LandingPageEntries lp on lp.parentid=t.user_id
left join #pipeline pl on pl.parentid=t.user_id
left join #invoices i on i.parentid=t.user_id
left join #quotes q on q.parentid=t.user_id
left join #whatsappBroadcasted wb on wb.parentid=t.user_id
left join #chatbotSessions cs on cs.parentid=t.user_id
--left join #sms s on s.parentid=t.user_id
left join #emails m on m.parentid=t.user_id
left join #voices v on v.parentid=t.user_id
left join #ett et on et.parentid=t.user_id
left join #LocationUsers lc on lc.parentid=t.user_id

order by SubscriptionExpiry desc
drop table if exists #temp
drop table if exists #users
drop table if exists #leads
drop table if exists #Enquiries
drop table if exists #followups
