/* ============================================================
   Procedure: [dbo].[usp_getcustomfielderrorlog]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.usp_getcustomfielderrorlog @userid BIGINT
	,@mode VARCHAR(10)
	,@fromdt DATETIME = NULL
	,@todate DATETIME = NULL
	,@fieldname NVARCHAR(max) = NULL
	,@formname NVARCHAR(max) = NULL
	,@errormsg NVARCHAR(max) = NULL
AS
BEGIN
	DECLARE @parentid BIGINT

	SELECT @parentid = parentid
	FROM User_Detail
	WHERE User_ID = @userid

	IF @mode = 'Data'
	BEGIN
		SELECT wf.FormId
			,wf.FormName
			,String_agg(cf.fieldname, ',') AS fieldname
			,String_agg(ErrorMessage, ',') AS ErrorMessage
			,err.EntryDate
			,err.fieldvaluejson
			,err.EntryId
			,err.Active
			,ue.EnquiryID
			,ue.PersonName
		FROM Errorlogcustomfield err
		JOIN WebFormTbl wf ON err.formid = wf.FormId
		JOIN customfields cf ON err.fieldid = cf.Field_Id
		LEFT JOIN WebEntryTbl wet ON wet.EntryId = err.EntryId
		LEFT JOIN UserEnquiry ue ON ue.enquiryid = wet.enqueryid
		WHERE wf.ParentId = @parentid
			AND err.fieldvaluejson IS NOT NULL
			AND wf.isEnquiry = 1
		GROUP BY wf.FormId
			,wf.FormName
			,err.EntryDate
			,err.fieldvaluejson
			,err.EntryId
			,err.Active
			,ue.EnquiryID
			,ue.PersonName
		ORDER BY EntryDate DESC
	END
	ELSE IF @mode = 'Filter'
	BEGIN
		SELECT wf.formid
			,wf.FormName
			,String_agg(cf.fieldname, ',') AS fieldname
			,String_agg(ErrorMessage, ',') AS ErrorMessage
			,err.EntryDate
			,err.fieldvaluejson
			,err.EntryId
			,err.Active
			,ue.EnquiryID
			,ue.PersonName
			,wf.isEnquiry
		FROM Errorlogcustomfield err
		JOIN WebFormTbl wf ON err.formid = wf.FormId
		JOIN customfields cf ON err.fieldid = cf.Field_Id
		LEFT JOIN WebEntryTbl wet ON wet.EntryId = err.EntryId
		LEFT JOIN UserEnquiry ue ON ue.enquiryid = wet.enqueryid
		WHERE wf.ParentId = @parentid
			AND (
				@fieldname IS NULL
				OR cf.fieldname LIKE '%' + @fieldname + '%'
				)
			AND (
				@formname IS NULL
				OR wf.FormName LIKE '%' + @formname + '%'
				)
			AND (
				@fromdt IS NULL
				OR err.EntryDate > @fromdt
				)
			AND (
				@todate IS NULL
				OR err.EntryDate < @todate
				)
			AND (
				@errormsg IS NULL
				OR err.ErrorMessage LIKE '%' + @errormsg + '%'
				)
			AND err.fieldvaluejson IS NOT NULL
			AND wf.isEnquiry = 1
		GROUP BY wf.FormId
			,wf.FormName
			,err.EntryDate
			,err.fieldvaluejson
			,err.EntryId
			,err.Active
			,ue.EnquiryID
			,ue.PersonName
			,wf.isEnquiry
		ORDER BY EntryDate DESC
	END

	EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @userid
		,@Activity_type = 'View_webfrmentry'
		,@ActionType = 'S'
		,@RowJson = ''
		,@Table_name = 'Errorlogcustomfield'
END
	--exec usp_getcustomfielderrorlog 34594,'Data'



GO

