/* ============================================================
   Procedure: [dbo].[Usp_getCustomFieldValue]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

--exec Usp_getCustomFieldValue @enquiryid=9564624,@parentid=43966,@mode=N'Select',@type=N'Lead'
--go

CREATE   PROCEDURE [dbo].[Usp_getCustomFieldValue]           
@enquiryid Bigint,          
@customfieldid Bigint=0,        
@parentid Bigint=0,        
@mode varchar(10),      
@type varchar(10),      
@fieldId bigint =0,      
@value varchar(5000)=''      
AS           
BEGIN   

--declare 
--	@enquiryid Bigint = 9564624,          
--	@customfieldid Bigint=0,        
--	@parentid Bigint=43966,        
--	@mode varchar(10) = N'Select',      
--	@type varchar(10) = N'Lead',      
--	@fieldId bigint =0,      
--	@value varchar(5000)=''   
 

 IF @mode='Save'          
 BEGIN          
 IF @type='Enquiry'      
 BEGIN      
  IF EXISTS (Select 1 FROM customfieldEnquiryvalue WHERE EnquiryID=@enquiryid and fieldID=@fieldId)       
  BEGIN      
   UPDATE customfieldEnquiryvalue       
   SET fieldvalue=@value       
   WHERE EnquiryID=@enquiryid and fieldID=@fieldId      
  END      
  Else       
  BEGIN      
   INSERT INTO customfieldEnquiryvalue (EnquiryID,fieldID,fieldvalue)       
   VALUES(@enquiryid,@fieldId,@value)      
  END      
 END      
 ELSE IF @type='Lead'      
 BEGIN      
  IF EXISTS (Select 1 FROM customfieldLeadvalue WHERE LeadID=@enquiryid and fieldID=@fieldId)       
  BEGIN      
   UPDATE customfieldLeadvalue      
   SET fieldvalue=@value       
   WHERE LeadID=@enquiryid and fieldID=@fieldId      
  END      
  Else       
  BEGIN      
   INSERT INTO customfieldLeadvalue (LeadID,fieldID,fieldvalue)       
   VALUES(@enquiryid,@fieldId,@value)      
  END          
 END       
 END          
          
 ELSE IF @mode='Select'          
 BEGIN 
	drop table if exists #tpCF  

	select * into #tpCF from customfields(nolock)   
	where ParentID = @parentID and isActive = 1  

	 IF @type='Enquiry'      
		 BEGIN      
	  Select cf.field_ID, cf.fieldname,    
	  (CASE cf.datatype                    
				 WHEN 'd'                    
			   THEN 'Date'                    
			   WHEN 'f'                    
			   THEN 'Numeric'                    
			   WHEN 'v'                    
			   THEN 'Text'                    
			   WHEN 'r'                    
			   THEN 'Radio'                    
			   WHEN 'm'                    
			   THEN 'Multiline'                    
			   WHEN 's'                    
			   THEN 'Select'                    
			   WHEN 'c'                    
			   THEN 'Checkbox'                        
			   WHEN 'l'                    
			   THEN 'List'                
			  END) AS FieldType, cf.datatype, cf.isMandatory,cfev.EnquiryID,cfev.fieldvalue,cf.choices,
			  [cf].[ParentFieldId],  
			   (  
				select STRING_AGG(p.field_ID, ',') from #tpCF p where p.ParentFieldId = cf.field_ID  
			   ) as [ChildFieldId],
			   (  
					select fieldvalue from customfieldEnquiryvalue(nolock) p 
						where p.fieldID = cf.ParentFieldId  and p.EnquiryID = @enquiryid
			   ) as [ParentFieldValue]
		From customfieldEnquiryvalue cfev          
			right Join customfields cf on cf.field_ID=cfev.fieldID and cfev.EnquiryID=@enquiryid         
		WHERE ParentID=@parentid and cf.datatype<>'e' and cf.isActive=1       
	 END      
	 ELSE IF @type='Lead'      
	 BEGIN      
	  Select cf.field_ID, cf.fieldname,    
	   (CASE datatype                    
				 WHEN 'd'                    
			   THEN 'Date'                    
			   WHEN 'f'                    
			   THEN 'Numeric'                    
			   WHEN 'v'                    
			   THEN 'Text'                    
			   WHEN 'r'                    
			   THEN 'Radio'                    
			   WHEN 'm'                    
			   THEN 'Multiline'                    
			   WHEN 's'                    
			   THEN 'Select'                    
			   WHEN 'c'                    
			   THEN 'Checkbox'                        
			   WHEN 'l'                    
			   THEN 'List'                
			  END) AS FieldType,    
	  cf.datatype, cf.isMandatory,cfev.EnquiryID,cfev.fieldvalue,cf.choices,
			  [cf].[ParentFieldId],  
			   (  
				select STRING_AGG(p.field_ID, ',') from #tpCF p where p.ParentFieldId = cf.field_ID  
			   ) as [ChildFieldId],
			   (  
					select fieldvalue from customfieldLeadvalue(nolock) p 
						where p.fieldID = cf.ParentFieldId  and p.LeadID = @enquiryid
			   ) as [ParentFieldValue]
			From customfieldLeadvalue cfev          
	  right Join customfields cf on cf.field_ID=cfev.fieldID          
	  and cfev.LeadID=@enquiryid         
	  WHERE ParentID=@parentid and cf.datatype<>'e' and  cf.isActive=1    
	 END      
      
 END          
END  


GO

