/* ============================================================
   Procedure: [dbo].[usp_getdashboardmetrics]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

  
-- exec usp_getdashboardmetrics 26023,26023    
CREATE   PROCEDURE usp_getdashboardmetrics  
@pid bigint,@uid bigint    
as    
begin    
  
 -- declare @pid bigint=26023,@uid bigint=26023  
 declare @FollowUpsToday int=0, @FollowUpsOverdue int=0, @NewLeadsAssigned int=0, @NewEnquiries int=0, @TicketsAwaitingResolution int=0  
  
select SUM(case when cast(getdate() as date)=cast(u.FollowupDate as date) then 1 else 0 end) FollowUpsToday    
,SUM(case when ((cast(getdate() as date)>cast(u.FollowupDate as date)) and (isnull(FollowUpStatus,0)) <> 5) then 1 else 0 end) FollowUpsOverdue    
,SUM(case when createdby<>AssignedTo and cast(getdate() as date)=cast(u.ModifiedOn as date) and AssignedTo=@uid then 1 else 0 end) NewLeadsAssigned,  
 Parentid,@uid Userid   
 into #ul    
 from userleads(nolock) u where ParentID=@pid and AssignedTo= case when @pid=@uid then AssignedTo else @uid end    
 group by u.ParentID    
     
select COUNT(1) NewEnquiries,Parentid,@uid Userid into #ue from userenquiry(nolock) e where parentid=@pid and createdby= case when @pid=@uid then createdby else @uid end and CAST(CreatedDate as DATE)=cast(getdate() as date)    
group by e.ParentID    
    
select @FollowUpsOverdue=isnull(l.FollowUpsOverdue,0),@FollowUpsToday=isnull(l.FollowUpsToday,0), @NewLeadsAssigned=isnull(l.NewLeadsAssigned,0),@NewEnquiries=isnull(e.NewEnquiries,0), @TicketsAwaitingResolution=0   
from #ul l full join #ue e on l.ParentID=e.ParentID    
  
select @FollowUpsOverdue as FollowUpsOverdue, @FollowUpsToday as FollowUpsToday, @NewLeadsAssigned as NewLeadsAssigned, @NewEnquiries as NewEnquiries, @TicketsAwaitingResolution as TicketsAwaitingResolution  
  
end  


GO

