/* ============================================================
   Procedure: [dbo].[usp_GetDashboardReportMapping]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC usp_GetDashboardReportMapping
(
	@DashboardId bigint
)
As
Begin
	SELECT	DRM.DRMapId, DRM.DashboardId, DRM.ReportId, DRM.SequenceNo, DRM.RangeCode, DRM.IsActive, DR.ReportName, DR.ReportType,
			DR.JasperReportID, DTR.RangeId, DTR.RangeName, DTR.StartDays, DTR.EndDays
	FROM	tbl_DashboardReportMapping AS DRM WITH (nolock) INNER JOIN tbl_DashboardReports AS DR WITH (nolock) 
	ON		DRM.ReportId = DR.ReportId INNER JOIN tbl_DateRange AS DTR WITH (nolock) 
	ON		DRM.RangeCode = DTR.RangeCode
	WHERE   DRM.DashboardId=@DashboardId
End



GO

/* ============================================================
   Procedure: [dbo].[usp_getdashboardstats]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_getdashboardstats]           
as          
begin          
Select Service,LastExecution,TodayCount,DetailedCount from          
(          
select 'MailExtraction' as Service,max(createdon) as LastExecution,sum(case when createdon>cast(getdate() as date)   then 1 else 0 end)  as TodayCount,0 as DetailedCount from usermails(nolock) --where createdon>cast(getdate() as date)          
union          
select 'MailParsing' as Service,max(Createddate) as LastExecution,sum(case when enquirysource='Mail' and createddate>cast(getdate() as date)   then 1 else 0 end) as TodayCount,0 as DetailedCount from ParsedEnquiries(nolock) -- where createddate>cast(getdate() as date)          
union         
select 'Enquiries' as Service,max(Createddate) as LastExecution,sum(case when createddate>cast(getdate() as date)   then 1 else 0 end) as TodayCount,count(1) as DetailedCount     
from userenquiry(nolock) -- where createddate>cast(getdate() as date)           
union    
select 'Leads' as Service,max(Createdon) as LastExecution,sum(case when CreatedOn>cast(getdate() as date)   then 1 else 0 end) as TodayCount,count(1) as DetailedCount     
from userleads(nolock) -- where createddate>cast(getdate() as date)           
union    
select 'FollowUps' as Service,max(l.Createdon) as LastExecution,sum(case when l.CreatedOn>cast(getdate() as date)   then 1 else 0 end) as TodayCount,count(1) as DetailedCount     
from LeadInteractionHistory(nolock) l join userleads u on u.ParentID=l.ParentID and u.LeadNo=l.LeadNo and u.CreatedOn<>l.CreatedOn-- where createddate>cast(getdate() as date)           
union    
select 'Tasks' as Service,max(l.Createdon) as LastExecution,sum(case when l.CreatedOn>cast(getdate() as date)   then 1 else 0 end) as TodayCount,count(1) as DetailedCount     
from tbl_tsk_Taskhistory l(nolock) where istask=1-- where createddate>cast(getdate() as date)           
union    
select 'Appointments' as Service,max(l.Createdon) as LastExecution,sum(case when l.CreatedOn>cast(getdate() as date)   then 1 else 0 end) as TodayCount,count(1) as DetailedCount     
from tbl_tsk_Taskhistory l(nolock) where istask=0-- where createddate>cast(getdate() as date)           
union    
select 'Indiamart' as Service, max(cast(datereceived as datetime)) as LastExecution,sum(case when cast(datereceived as datetime)>cast(getdate() as date) then 1 else 0 end) as TodayCount,      
Count(1) as DetailedCount from IndiamartLeads(nolock) -- where cast(datereceived as datetime)>cast(getdate() as date)          
union       
select 'TradeIndia' as Service, max(cast(datereceived as datetime)) as LastExecution,sum(case when cast(datereceived as datetime)>cast(getdate() as date) then 1 else 0 end) as TodayCount,      
Count(1) as DetailedCount from Tradeindiadata(nolock)  --where cast(datereceived as datetime)>cast(getdate() as date)          
union    
select 'Magic Bricks' as Service, max(CreatedOn) as LastExecution,sum(case when CreatedOn>cast(getdate() as date) then 1 else 0 end) as TodayCount,      
Count(1) as DetailedCount from MagicBrickLeads(nolock) -- where cast(datereceived as datetime)>cast(getdate() as date)          
union          
--select  'SMSEventCampaign' as Service,campaignexecuteddatetime as Lastexecution,count(uc.id) as TodayCount,sum(isnull(Step3Recipients,0)) as DetailedCount from           
--usercampaignexecution(nolock) u join usercampaignhistory(nolock) uc on u.isSMS=uc.IsSMS and u.isevent=uc.IsEventBased and uc.CampaignID<>0 and uc.Step3Recipients>0           
--and cast(campaignexecuteddatetime as date)=cast(uc.CreatedOn as date)          
--where uc.IsEventBased=1 and uc.isSMS=1 group by CampaignExecutedDatetime      
select  'SMSEventCampaign' as Service,max(uc.Step3DateTime) as Lastexecution,sum (case when cast(uc.CreatedOn as date)=cast(getdate() as date) then 1 else 0 end) as TodayCount,sum(isnull(Step3Recipients,0)) as DetailedCount from           
usercampaignhistory(nolock) uc  where uc.IsEventBased=1 and uc.CampaignID<>0 and uc.Step3Recipients>0           
and month(uc.CreatedOn)=month(getdate()) and year(uc.CreatedOn)=year(getdate())
and uc.IsSMS=1 --group by cast(uc.CreatedOn as date)          

union          
select  'SMSScheduledCampaign' as Service,campaignexecuteddatetime as Lastexecution,count(uc.id) as TodayCount,sum(isnull(Step3Recipients,0)) as DetailedCount from           
usercampaignexecution(nolock) u left join usercampaignhistory(nolock) uc on u.isSMS=uc.IsSMS and u.isevent=uc.IsEventBased and uc.CampaignID<>0 and uc.Step3Recipients>0           
and cast(campaignexecuteddatetime as date)=cast(uc.CreatedOn as date)          
where uc.IsEventBased=0 and uc.isSMS=1 group by CampaignExecutedDatetime          
union    
select  'MailEventCampaign' as Service,max(uc.Step3DateTime) as Lastexecution,sum (case when cast(uc.CreatedOn as date)=cast(getdate() as date) then 1 else 0 end) as TodayCount,sum(isnull(Step3Recipients,0)) as DetailedCount from           
usercampaignhistory(nolock) uc  where uc.IsEventBased=1 and uc.CampaignID<>0 and uc.Step3Recipients>0           
and month(uc.CreatedOn)=month(getdate()) and year(uc.CreatedOn)=year(getdate())
and uc.Ismail=1 --group by cast(uc.CreatedOn as date)         

--select  'MailEventCampaign' as Service,campaignexecuteddatetime as Lastexecution,count(uc.id) as TodayCount,sum(isnull(Step3Recipients,0)) as DetailedCount from           
--usercampaignexecution(nolock) u left join usercampaignhistory(nolock) uc on u.issms=uc.Issms and u.isevent=uc.IsEventBased and uc.CampaignID<>0 and uc.Step3Recipients>0           
--and cast(campaignexecuteddatetime as date)=cast(uc.CreatedOn as date)          
--where u.IsEvent=1 and u.isSMS=0 group by CampaignExecutedDatetime          
union          
select  'MailScheduledCampaign' as Service,campaignexecuteddatetime as Lastexecution,count(uc.id) as TodayCount,sum(isnull(Step3Recipients,0)) as DetailedCount from           
usercampaignexecution(nolock) u left join usercampaignhistory(nolock) uc on u.isSMS=uc.IsSMS and u.isevent=uc.IsEventBased and uc.CampaignID<>0 and uc.Step3Recipients>0           
and cast(campaignexecuteddatetime as date)=cast(uc.CreatedOn as date)          
where  u.IsEvent=0 and u.isSMS=0 group by CampaignExecutedDatetime          
union          
select  'VoiceEventCampaign' as Service,campaignexecuteddatetime as Lastexecution,count(uc.id) as TodayCount,sum(isnull(Step3Recipients,0)) as DetailedCount from           
usercampaignexecution(nolock) u left join usercampaignhistory(nolock) uc on u.isSMS=uc.IsSMS and u.isevent=uc.IsEventBased and uc.CampaignID<>0 and uc.Step3Recipients>0           
and cast(campaignexecuteddatetime as date)=cast(uc.CreatedOn as date)          
where  u.IsEvent=1 and u.isSMS=2 group by CampaignExecutedDatetime          
union          
select  'VoiceScheduledCampaign' as Service,campaignexecuteddatetime as Lastexecution,count(uc.id) as TodayCount,sum(isnull(Step3Recipients,0)) as DetailedCount from           
usercampaignexecution(nolock) u left join usercampaignhistory(nolock) uc on u.isSMS=uc.IsSMS and u.isevent=uc.IsEventBased and uc.CampaignID<>0 and uc.Step3Recipients>0           
and cast(campaignexecuteddatetime as date)=cast(uc.CreatedOn as date)          
where  u.IsEvent=0 and u.isSMS=2 group by CampaignExecutedDatetime          
union          
select 'VoiceBroadcast',max(lastaccesstime) as LastExecution,sum(case when LastAccessTime>cast(getdate() as date) and processed=2  then 1 else 0 end) as TodayCount,      
0 as DetailedCount from Kit19Cloudvoicefinaltbl --where LastAccessTime>cast(getdate() as date) and processed=2          
union          
select 'InboundCalls',max(call_start_time) as LastExecution,sum(case when call_start_time>cast(getdate() as date)  then 1 else 0 end)  as TodayCount,0 as DetailedCount from Kit19Calls where context in ('inbound','inbound1','incoming')          
union          
select 'ClickCalls',max(call_start_time) as LastExecution,sum(case when call_start_time>cast(getdate() as date)  then 1 else 0 end)  as TodayCount,0 as DetailedCount from Kit19Calls where context='DialerCalls'          
union          
select 'SFTPVoiceUpload',max(lastaccesstime) as LastExecution,sum(case when lastaccesstime>cast(getdate() as date) and fileuploaded='Y'  then 1 else 0 end)  as TodayCount,0 as DetailedCount from Cloud_PlayFile           
union          
select 'FacebookLeads',max(CreatedOn) as LastExecution,sum(case when CreatedOn>cast(getdate() as date) then 1 else 0 end)  as TodayCount,          
sum(case when CreatedOn>cast(getdate() as date) and isproccesed=1  then 1 else 0 end) as DetailedCount from tbl_fb_FacebookLeadJson           
union          
select 'Justdial' as Service, max(cast(datereceived as datetime)) as LastExecution,sum(case when datereceived>cast(getdate() as date) then 1 else 0 end) as TodayCount,Count(1) as DetailedCount from JustdialLeads(nolock)            
union          
select 'DialPadCalls' as Service, max(cast(CreateOn as datetime)) as LastExecution,sum(case when CreateOn>cast(getdate() as date) then 1 else 0 end) as TodayCount          
,sum(case when CreateOn>cast(getdate() as date) and CallStartDateTime is not null then 1 else 0 end) as DetailedCount from tbl_DailPaidCallDetails(nolock)       
union      
select 'Location' as Service, max(cast(Createddate as datetime)) as LastExecution,sum(case when Createddate>cast(getdate() as date) then 1 else 0 end) as TodayCount          
,0 as DetailedCount from realtimelocation(nolock)       
) A          
End 


GO

/* ============================================================
   Procedure: [dbo].[usp_getdashboardstatssingleuser]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_getdashboardstatssingleuser] -- 29453 
@parentid bigint    
as      
begin      
--declare @parentid bigint=335

Select Service,LastExecution,TodayCount,DetailedCount,Description from      
(     
--declare @parentid bigint=335 
Select 'Subscription' as Service,PlanstartDate as LastExecution,0 as TodayCount,0 as DetailedCount,'Subscription ending on '+cast(PlanEndDate as nvarchar) as Description from Price_UserSubscriptionDetails where isnewplan=1 and USERID=@parentid
union all
Select 'ActiveUsers' as Service,max(lastlogin1) as LastExecution,sum(case when lastlogin1 >cast(getdate() as date) then 1 else 0 end) as TodayStatus
,sum(case when isnull(lastlogin1,lastlogin2) is not null then 1 else 0 end) as DetailedCount,'Total users with active status are '+cast(sum(case when status=1 then 1 else 0 end) as nvarchar)  Description
from user_detail(nolock) where parentid=@parentid
union all 
select 'MailForwarding' as Service,max(CreatedOn) as Lastexecution,sum(case when isstep7=1 then 1 else 0 end) as TodayStatus,0 as DetailedCount,
case when sum(case when isstep7=1 then 1 else 0 end)> 0 then 
'User has '+cast(sum(case when isstep7=1 then 1 else 0 end) as nvarchar)+ ' mails forwarded' 
else 
'User has no mails forwarded yet' end as Description from usermailbox(nolock) where parentid=@parentid
union all
select 'MailExtraction' as Service,max(createdon) as LastExecution,sum(case when createdon>cast(getdate() as date)   then 1 else 0 end)  as TodayCount,count(1) as DetailedCount, 
case when count(1) >0 then 'User has ' +cast(count(1) as nvarchar)+ ' mails forwarded to kit19 as yet'  else 'User has no mails forwarded yet' end as Description from usermails(nolock) 
where UserID=@parentid
union all      
select 'MailParsing' as Service,max(Createddate) as LastExecution,sum(case when createddate>cast(getdate() as date)   then 1 else 0 end) as TodayCount,count(1) as DetailedCount,
case when count(1) >0 then 'User has ' +cast(count(1) as nvarchar)+ ' mails parsed and entered as enquiry in kit19 as yet' 
else case when exists(select 1 from UserMailsFilters u join UserMailsParsing p on u.id=p.FilterID and u.ParentID=@parentid) then 'User has Filter and parsing setting but no mails
are received at kit19 yet' else 'User has no mails filters and parsing and hence no mail is received or parsed yet' end end as Description
from ParsedEnquiries(nolock) 
where enquirysource='Mail' and Parentid=@parentid 
union all     
select 'Enquiries' as Service,max(Createddate) as LastExecution,sum(case when createddate>cast(getdate() as date)   then 1 else 0 end) as TodayCount,count(1) as DetailedCount, 
case when max(Createddate)>cast(getdate() as date) then 'User has entered enquiry(s) today.' 
when max(Createddate) is not null then 'User has not created any enquiry since '+cast(datediff(d,max(createddate),getdate()) as nvarchar)+ ' days.'
else 'User has entered no enquiry yet' end as Description
from userenquiry(nolock) where ParentID=@parentid
union all
select 'Leads' as Service,max(Createdon) as LastExecution,sum(case when CreatedOn>cast(getdate() as date)   then 1 else 0 end) as TodayCount,count(1) as DetailedCount, 
case when max(Createdon)>cast(getdate() as date)
 then 'User has entered lead(s) today.' 
when max(Createdon) is not null then 'User has not created any lead since '+cast(datediff(d,max(createdon),getdate()) as nvarchar)+ ' days.'
else 'User has entered no lead yet' end as Description
from userleads(nolock) where parentid=@parentid
union all
select 'FollowUps' as Service,max(l.Createdon) as LastExecution,sum(case when l.CreatedOn>cast(getdate() as date)   then 1 else 0 end) as TodayCount,count(1) as DetailedCount,
case when max(l.Createdon)>cast(getdate() as date)
 then 'User has entered followup(s) today.' 
when max(l.Createdon) is not null then 'User has not created any followups since '+cast(datediff(d,max(l.createdon),getdate()) as nvarchar)+ ' days.'
else 'User has entered no followup yet' end as Description
from LeadInteractionHistory(nolock) l join userleads u on u.ParentID=l.ParentID and u.LeadNo=l.LeadNo and u.CreatedOn<>l.CreatedOn and l.ParentID=@parentid
union all
select 'Tasks' as Service,dbo.fn_Max_date(max(l.Createdon),isnull(max(l.CompletedOn),max(l.Createdon))) as LastExecution,sum(case when l.CreatedOn>cast(getdate() as date)   then 1 else 0 end) as TodayCount,count(1) as DetailedCount,
case when dbo.fn_Max_date(max(l.Createdon),isnull(max(l.CompletedOn),max(l.Createdon)))>cast(getdate() as date)
 then 'User has updated task(s) today.' 
when dbo.fn_Max_date(max(l.Createdon),isnull(max(l.CompletedOn),max(l.Createdon))) is not null then 'User has not updated any task since '+
cast(datediff(d,dbo.fn_Max_date(max(l.Createdon),isnull(max(l.CompletedOn),max(l.Createdon))),getdate()) as nvarchar)+ ' days.'
else 'User has created no task yet' end as Description
from tbl_tsk_Taskhistory l(nolock) 
join user_detail u on u.User_ID=l.CreatedBy
where istask=1 and u.ParentID=@parentid-- where createddate>cast(getdate() as date)       
union all
select 'Appointments' as Service,dbo.fn_Max_date(max(l.Createdon),isnull(max(l.CompletedOn),max(l.Createdon))) as LastExecution,sum(case when l.CreatedOn>cast(getdate() as date)   then 1 else 0 end) as TodayCount,count(1) as DetailedCount,
case when dbo.fn_Max_date(max(l.Createdon),isnull(max(l.CompletedOn),max(l.Createdon)))>cast(getdate() as date)
 then 'User has updated appointment(s) today.' 
when dbo.fn_Max_date(max(l.Createdon),isnull(max(l.CompletedOn),max(l.Createdon))) is not null then 'User has not updated any appointment since '
+cast(datediff(d,dbo.fn_Max_date(max(l.Createdon),isnull(max(l.CompletedOn),max(l.Createdon))),getdate()) as nvarchar)+ ' days.'
else 'User has created no appointment yet' end as Description
from tbl_tsk_Taskhistory l(nolock) 
join user_detail u on u.User_ID=l.CreatedBy
where istask=0 and u.ParentID=@parentid
union all
select 'Indiamart' as Service, max(cast(datereceived as datetime)) as LastExecution,sum(case when cast(datereceived as datetime)>cast(getdate() as date) then 1 else 0 end) as TodayCount,  
count(1) as DetailedCount, 
case when max(m.id) is null then 'User has not integrated Indiamart yet' 
when max(m.id) is not null and (max(cast(m.status as int))=0 or max(m.ExpiredOn) is not null) 
then 'User has integrated Indiamart but his key is either inactive or expired'
when  max(cast(datereceived as datetime)) is null then 'User has integrated Indiamart but there is no insiamart lead yet'
when max(cast(datereceived as datetime)) is not null and count(1)>0 and datediff(d,max(cast(datereceived as datetime)),getdate())>3  then
'User has integrated Indiamart and captured ' +cast(count(1) as nvarchar)+ ' leads but is inactive since '+cast(datediff(d,max(cast(datereceived as datetime)),getdate()) as nvarchar)+' days'
else 'User has captured '+cast(count(1) as nvarchar)+ ' indiamart leads till date'   end as Description
 from IndiamartLeads(nolock) i right join IndiamartMapping m on m.IndiamartId=i.INDIAMARTKEY where m.Kit19ParentId=@parentid
union all   
select 'TradeIndia' as Service, max(cast(datereceived as datetime)) as LastExecution,sum(case when cast(datereceived as datetime)>cast(getdate() as date) then 1 else 0 end) as TodayCount,  
count(1) as DetailedCount,
case when max(m.id) is null then 'User has not integrated TradeIndia yet' 
when max(m.id) is not null and (max(cast(m.status as int))=0 or max(m.ExpiredOn) is not null) 
then 'User has integrated TradeIndia but his key is either inactive or expired'
when  max(cast(datereceived as datetime)) is null then 'User has integrated TradeIndia but there is no insiamart lead yet'
when max(cast(datereceived as datetime)) is not null and count(1)>0 and datediff(d,max(cast(datereceived as datetime)),getdate())>3  then
'User has integrated TradeIndia and captured ' +cast(count(1) as nvarchar)+ ' leads but is inactive since '+cast(datediff(d,max(cast(datereceived as datetime)),getdate()) as nvarchar)+' days'
else 'User has captured '+cast(count(1) as nvarchar)+ ' TradeIndia leads till date'   end as Description
from Tradeindiadata(nolock) t join TradeIndia_Mapping m on t.TradeIndiaKey=m.TradeIndia_Key and Kit19ParentID=@parentid --where cast(datereceived as datetime)>cast(getdate() as date)      
union all      
select  'SMSEventCampaign' as Service,
max(Step3DateTime) as Lastexecution,
count(uc.id) as TodayCount,
sum(isnull(Step3Recipients,0)) as DetailedCount,
case when max(Step3DateTime) is null then 'User does not have any active and running SMS Event Campaign'
when cast(max(Step3DateTime) as date)= cast(getdate() as date) then 'User has active SMS Event campaigns'
else 'User has SMS event campaigns that have either expired or not started yet. The last campaign ran '+cast(datediff(d,max(Step3DateTime),getdate()) as nvarchar)+  ' days back' end as Description
from       
user_detail ud (nolock)
left join usercampaignhistory(nolock) uc on uc.CampaignID<>0 and uc.Step3Recipients>0 and ud.user_id=uc.parentid and uc.IsEventBased=1 and uc.isSMS=1     
where ud.User_ID=@parentid 
group by ud.User_ID
union all 
select  'SMSScheduledCampaign' as Service,
max(Step3DateTime) as Lastexecution,
count(uc.id) as TodayCount,
sum(isnull(Step3Recipients,0)) as DetailedCount,
case when max(Step3DateTime) is null then 'User does not have any active and running SMS Scheduled Campaign'
when cast(max(Step3DateTime) as date)= cast(getdate() as date) then 'User has active SMS Scheduled campaigns'
else 'User has SMS Scheduled campaigns that have either expired or not started yet. The last campaign ran '+cast(datediff(d,max(Step3DateTime),getdate()) as nvarchar)+  ' days back' end as Description
from       
user_detail ud (nolock)
left join usercampaignhistory(nolock) uc on uc.CampaignID<>0 and uc.Step3Recipients>0 and ud.user_id=uc.parentid and uc.IsEventBased=0 and uc.isSMS=1     
where ud.User_ID=@parentid 
group by ud.User_ID
union all      
select  'MailEventCampaign' as Service,
max(Step3DateTime) as Lastexecution,
count(uc.id) as TodayCount,
sum(isnull(Step3Recipients,0)) as DetailedCount,
case when max(Step3DateTime) is null then 'User does not have any active and running Mail Event Campaign'
when cast(max(Step3DateTime) as date)= cast(getdate() as date) then 'User has active Mail Event campaigns'
else 'User has Mail event campaigns that have either expired or not started yet. The last campaign ran '+cast(datediff(d,max(Step3DateTime),getdate()) as nvarchar)+  ' days back' end as Description
from       
user_detail ud (nolock)
left join usercampaignhistory(nolock) uc on uc.CampaignID<>0 and uc.Step3Recipients>0 and ud.user_id=uc.parentid and uc.IsEventBased=1 and uc.isSMS=0     
where ud.User_ID=@parentid 
group by ud.User_ID
union all 
select  'MailScheduledCampaign' as Service,
max(Step3DateTime) as Lastexecution,
count(uc.id) as TodayCount,
sum(isnull(Step3Recipients,0)) as DetailedCount,
case when max(Step3DateTime) is null then 'User does not have any active and running Mail Scheduled Campaign'
when cast(max(Step3DateTime) as date)= cast(getdate() as date) then 'User has active Mail Scheduled campaigns'
else 'User has Mail Scheduled campaigns that have either expired or not started yet. The last campaign ran '+cast(datediff(d,max(Step3DateTime),getdate()) as nvarchar)+  ' days back' end as Description
from       
user_detail ud (nolock)
left join usercampaignhistory(nolock) uc on uc.CampaignID<>0 and uc.Step3Recipients>0 and ud.user_id=uc.parentid and uc.IsEventBased=0 and uc.isSMS=0     
where ud.User_ID=@parentid 
group by ud.User_ID
union all      
select  'VoiceEventCampaign' as Service,
max(Step3DateTime) as Lastexecution,
count(uc.id) as TodayCount,
sum(isnull(Step3Recipients,0)) as DetailedCount,
case when max(Step3DateTime) is null then 'User does not have any active and running Voice Event Campaign'
when cast(max(Step3DateTime) as date)= cast(getdate() as date) then 'User has active Voice Event campaigns'
else 'User has Voice event campaigns that have either expired or not started yet. The last campaign ran '+cast(datediff(d,max(Step3DateTime),getdate()) as nvarchar)+  ' days back' end as Description
from       
user_detail ud (nolock)
left join usercampaignhistory(nolock) uc on uc.CampaignID<>0 and uc.Step3Recipients>0 and ud.user_id=uc.parentid and uc.IsEventBased=1 and uc.isSMS=2     
where ud.User_ID=@parentid
group by ud.User_ID
union all 
select  'VoiceScheduledCampaign' as Service,
max(Step3DateTime) as Lastexecution,
count(uc.id) as TodayCount,
sum(isnull(Step3Recipients,0)) as DetailedCount,
case when max(Step3DateTime) is null then 'User does not have any active and running Voice Scheduled Campaign'
when cast(max(Step3DateTime) as date)= cast(getdate() as date) then 'User has active Voice Scheduled campaigns'
else 'User has Voice Scheduled campaigns that have either expired or not started yet. The last campaign ran '+cast(datediff(d,max(Step3DateTime),getdate()) as nvarchar)+  ' days back' end as Description
from       
user_detail ud (nolock)
left join usercampaignhistory(nolock) uc on uc.CampaignID<>0 and uc.Step3Recipients>0 and ud.user_id=uc.parentid and uc.IsEventBased=0 and uc.isSMS=2     
where ud.User_ID=@parentid
group by ud.User_ID
union all      
select 'VoiceBroadcast',max(lastaccesstime) as LastExecution,sum(case when LastAccessTime>cast(getdate() as date) and processed=2  then 1 else 0 end) as TodayCount,  
count(1) as DetailedCount,'' as Description
 from Kit19Cloudvoicefinaltbl k(nolock) join BatchVoiceInfo b (nolock) on b.BatchID=k.batchid where b.parentid=@parentid      
union all      
select 'InboundCalls',max(call_start_time) as LastExecution,sum(case when call_start_time>cast(getdate() as date)  then 1 else 0 end)  as TodayCount,count(1) as DetailedCount,'' as Description from 
Kit19Calls k (nolock) left join cloud_user_phone(nolock) cu on 
cu.PhoneNo = isnull(k.clientid,(select case when k.context like 'outbound%' then k.callerid else k.dnid end))  where isnull(k.clientid,cu.Parentid)=@parentid
and context in ('inbound','inbound1','incoming')      
union all      
select 'ClickCalls',max(call_start_time) as LastExecution,sum(case when call_start_time>cast(getdate() as date)  then 1 else 0 end)  as TodayCount,count(1) as DetailedCount,'' as Description from 
Kit19Calls k (nolock) left join cloud_user_phone(nolock) cu on 
cu.PhoneNo = isnull(k.clientid,(select case when k.context like 'outbound%' then k.callerid else k.dnid end))  where isnull(k.clientid,cu.Parentid)=@parentid
and context='DialerCalls'      
union all      
select 'SFTPVoiceUpload',max(lastaccesstime) as LastExecution,sum(case when lastaccesstime>cast(getdate() as date) and fileuploaded='Y'  then 1 else 0 end)  as TodayCount,
count(1) as DetailedCount,'' as Description 
from Cloud_PlayFile (nolock) where  clientid=@parentid   
union all      
select 'FacebookLeads',max(f.CreatedOn) as LastExecution,sum(case when f.CreatedOn>cast(getdate() as date) then 1 else 0 end)  as TodayCount,      
count(1) as DetailedCount,'' as Description from tbl_fb_FacebookLeadJson f join tbl_fb_WebhookJsonData w  on w.FbLeadgen_Id=f.LeadgenId
join tbl_fb_FacebookPages p on p.FbPageId=w.FbPageId     where w.fbAd_id<>0 and 
p.parentid=@parentid
union all      
select 'Justdial' as Service, max(cast(j.datereceived as datetime)) as LastExecution,sum(case when j.datereceived>cast(getdate() as date) then 1 else 0 end) as TodayCount,
count(1) as DetailedCount ,'' as Description
from JustdialLeads(nolock) j join JDMapping m on j.jdparentid=m.JDParentId and Kit19ParentId=@parentid      
union all      
select 'DialPadCalls' as Service, max(cast(CreateOn as datetime)) as LastExecution,sum(case when CreateOn>cast(getdate() as date) then 1 else 0 end) as TodayCount      
,count(1) as DetailedCount,'' as Description from tbl_DailPaidCallDetails(nolock) t join user_detail u (nolock) on u.User_ID=t.UserId 
where u.ParentID=@parentid
union all  
select 'Location' as Service, max(cast(t.Createddate as datetime)) as LastExecution,sum(case when t.Createddate>cast(getdate() as date) then 1 else 0 end) as TodayCount      
,count(1) as DetailedCount,'' as Description from realtimelocation(nolock)   t join user_detail u (nolock) on u.User_ID=t.UserId 
where u.ParentID=@parentid
) A      
End   
  
  
  --select * from user_Detail where user_login like 'rsgroup764634'


