/* ============================================================
   Procedure: [dbo].[usp_getdashboardstatssingleuserdatewise_sectionwise]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


--exec usp_getdashboardstatssingleuserdatewise 32222, 7
CREATE   PROCEDURE [dbo].[usp_getdashboardstatssingleuserdatewise_sectionwise] --29453,10,0   
@parentid bigint ,@days int=null,@section int=null     
as        
begin        
set @days=coalesce(@days,1)
set @section=coalesce(@section,0)
declare @sectionDesc nvarchar(100)
select @sectionDesc=
case 
when @section=0 then 'All'
when @section=1 then 'Subscription & Credit usage'
--when @section=2 then 'Credit usage'
when @section=3 then 'Prospects Created'
when @section=4 then 'Integrations'
when @section=5 then 'Lead Management'
when @section=6 then 'Campaigns'
when @section=7 then 'Calls'
when @section=8 then 'Support Tickets'
end
create table #temp(Service nvarchar(100),LastExecution nvarchar(100),TotalCount nvarchar(10),DetailedCount nvarchar(10),Description nvarchar(200))
      
if @section=0 or @section=1
begin
insert into #temp(Service,LastExecution,TotalCount,DetailedCount,Description) 
Select Service,LastExecution,cast(TodayCount as nvarchar) as TotalCount,cast(isnull(DetailedCount,0) as nvarchar) DetailedCount,Description from 
(   
--declare @parentid int=335,@days int=10
Select 'Subscription' as Service,PlanstartDate as LastExecution,'0' as TodayCount,cast(PlanEndDate as nvarchar) as DetailedCount,'' as Description 
from Price_UserSubscriptionDetails where isnewplan=1 and USERID=@parentid  
union all  
Select 'TotalUsers' as Service,max(lastlogin1) as LastExecution,sum(case when lastlogin1 >cast(getdate() as date) then 1 else 0 end) as TodayStatus  
,cast(count(1) as nvarchar) as DetailedCount,''  Description  
from user_detail(nolock) where parentid=@parentid 
union all
Select 'ActiveUsers' as Service,max(lastlogin1) as LastExecution,sum(case when lastlogin1 >cast(getdate() as date) then 1 else 0 end) as TodayStatus  
,cast(sum(case when isnull(lastlogin1,lastlogin2) is not null then 1 else 0 end) as nvarchar) as DetailedCount,''  Description  
from user_detail(nolock) where parentid=@parentid and status=1 and datediff(d,lastlogin1,getdate())<=case when @days is null then datediff(d,lastlogin1,getdate()) else @days end  
union all
Select 'SMS' Service,max(date) LastExecution,0 as TodayCount,cast(sum(Totalconsumption) as nvarchar) DetailedCount,'' Description  from DailyConsumption(nolock)d join User_Detail(nolock) u on d.User_id=u.User_ID
where u.parentid=@parentid and datediff(d,d.date,getdate())<=case when @days is null then datediff(d,d.Date,getdate()) else @days end  
union all
Select 'Mail' Service,max(date) LastExecution,0 as TodayCount,cast(sum(TotalMailConsumption) as nvarchar) DetailedCount,'' Description  from DailyMailConsumption(nolock)d join User_Detail(nolock) u on d.User_id=u.User_ID
where u.parentid=@parentid and datediff(d,d.date,getdate())<=case when @days is null then datediff(d,d.Date,getdate()) else @days end  
union all
Select 'Money' Service,max(date) LastExecution,0 as TodayCount,cast(sum(TotalMoneyConsumption) as nvarchar) DetailedCount,'' Description  from DailyMoneyConsumption(nolock)d join User_Detail(nolock) u on d.User_id=u.User_ID
where u.parentid=@parentid and datediff(d,d.date,getdate())<=case when @days is null then datediff(d,d.Date,getdate()) else @days end  
) A
end
if @section=0 or @section=3
begin
insert into #temp(Service,LastExecution,TotalCount,DetailedCount,Description) 
Select Service,LastExecution,cast(TodayCount as nvarchar) as TotalCount,cast(isnull(DetailedCount,0) as nvarchar) DetailedCount,Description from 
(  
select 'Landing Page Visits' Service,max(Visitdate) LastExecution,sum(case when visitdate>cast(getdate() as date) then 1 else 0 end) as TodayCount,count(1) DetailedCount,'' Description 
from VisitPageDetails(nolock) 
where parentid=@parentid and Type='LandingPage' and datediff(d,visitdate,getdate())<=case when @days is null then datediff(d,VisitDate,getdate()) else @days end  
union all
select 'Web Form Visits' Service,max(Visitdate) LastExecution,sum(case when visitdate>cast(getdate() as date) then 1 else 0 end) as TodayCount,count(1) DetailedCount,
'' Description from VisitPageDetails(nolock) 
where parentid=@parentid and Type='Webform' and datediff(d,visitdate,getdate())<=case when @days is null then datediff(d,VisitDate,getdate()) else @days end  
union all
select 'Landing Page Enquiries' Service,max(c.datecreated) LastExecution,sum(case when c.datecreated>cast(getdate() as date) then 1 else 0 end) as TodayCount,
count(1) DetailedCount,'' Description from ClientLeadDetails c(nolock) join ClientPageDetail m(nolock) on right(m.pagename,len(m.pagename)-charindex('/',m.pagename,1))=c.cname
where m.user_id=@parentid and datediff(d,c.datecreated,getdate())<=case when @days is null then datediff(d,c.datecreated,getdate()) else @days end
union all
select 'Web form Enquiries' Service,max(c.entrydate) LastExecution,sum(case when c.entrydate>cast(getdate() as date) then 1 else 0 end) as TodayCount,
count(1) DetailedCount,'' Description from WebEntryTbl c(nolock) join WebFormTbl w(nolock) on w.FormId=c.FormId where w.ParentId=@parentid 
and datediff(d,c.EntryDate,getdate())<=case when @days is null then datediff(d,c.EntryDate,getdate()) else @days end
union all
select 'SMS Link Tracking' Service,max(c.VisitDate) LastExecution,sum(case when c.VisitDate>cast(getdate() as date) then 1 else 0 end) as TodayCount,
count(1) DetailedCount,'' Description from Link_smsTrack c(nolock) where c.ParentId=@parentid 
and datediff(d,visitdate,getdate())<=case when @days is null then datediff(d,VisitDate,getdate()) else @days end  
union all
select 'Mail Link Tracking' Service,max(c.visiteddate) LastExecution,sum(case when c.visiteddate>cast(getdate() as date) then 1 else 0 end) as TodayCount,
count(1) DetailedCount,'' Description from url_tracktbl c(nolock) where c.ParentId=@parentid 
and datediff(d,visiteddate,getdate())<=case when @days is null then datediff(d,VisitedDate,getdate()) else @days end  
) A
end
if @section=0 or @section=4
begin
insert into #temp(Service,LastExecution,TotalCount,DetailedCount,Description) 
Select Service,LastExecution,cast(TodayCount as nvarchar) as TotalCount,cast(isnull(DetailedCount,0) as nvarchar) DetailedCount,Description from 
(
select 'MailParsing' as Service,max(Createddate) as LastExecution,sum(case when createddate>cast(getdate() as date)   then 1 else 0 end) as TodayCount,count(1) as DetailedCount,'' as Description  
from ParsedEnquiries(nolock)   
where enquirysource='Mail' and Parentid=@parentid  and datediff(d,Createddate,getdate())<=case when @days is null then datediff(d,Createddate,getdate()) else @days end  
union all       
select 'Indiamart' as Service, max(cast(datereceived as datetime)) as LastExecution,sum(case when cast(datereceived as datetime)>cast(getdate() as date) then 1 else 0 end) as TodayCount,    
count(1) as DetailedCount,''as Description  
 from IndiamartLeads(nolock) i right join IndiamartMapping m on m.IndiamartId=i.INDIAMARTKEY where m.Kit19ParentId=@parentid  
 and datediff(d,cast(datereceived as datetime),getdate())<=case when @days is null then datediff(d,cast(datereceived as datetime),getdate()) else @days end  
union all     
select 'TradeIndia' as Service, max(cast(datereceived as datetime)) as LastExecution,sum(case when cast(datereceived as datetime)>cast(getdate() as date) then 1 else 0 end) as TodayCount,    
count(1) as DetailedCount,  '' as Description  
from Tradeindiadata(nolock) t join TradeIndia_Mapping m on t.TradeIndiaKey=m.TradeIndia_Key and Kit19ParentID=@parentid --where cast(datereceived as datetime)>cast(getdate() as date)        
and datediff(d,cast(datereceived as datetime),getdate())<=case when @days is null then datediff(d,cast(datereceived as datetime),getdate()) else @days end  
union all        
select 'FacebookLeads',max(f.CreatedOn) as LastExecution,sum(case when f.CreatedOn>cast(getdate() as date) then 1 else 0 end)  as TodayCount,        
count(1) as DetailedCount,'' as Description 
from tbl_fb_FacebookLeadJson f join tbl_fb_WebhookJsonData w  on w.FbLeadgen_Id=f.LeadgenId  
join tbl_fb_FacebookPages p on p.FbPageId=w.FbPageId     where w.fbAd_id<>'0' and   
p.parentid=@parentid  
and datediff(d,cast(f.CreatedOn as datetime),getdate())<=case when @days is null then datediff(d,cast(f.CreatedOn as datetime),getdate()) else @days end  
union all        
select 'Justdial' as Service, max(cast(j.datereceived as datetime)) as LastExecution,sum(case when cast(j.datereceived as datetime)>cast(getdate() as date) then 1 else 0 end) as TodayCount,  
count(1) as DetailedCount ,'' as Description  
from JustdialLeads(nolock) j join JDMapping m on j.jdparentid=m.JDParentId and Kit19ParentId=@parentid        
and datediff(d,cast(j.DateReceived as datetime),getdate())<=case when @days is null then datediff(d,cast(j.DateReceived as datetime),getdate()) else @days end  
union all        
select 'tawk.to Chat'  as Service,max(Createddate) as LastExecution,sum(case when createddate>cast(getdate() as date)   then 1 else 0 end) as TodayCount,count(1) as DetailedCount,'' as Description  
from ParsedEnquiries(nolock)   
where enquirysource like '%Tawk%' and Parentid=@parentid  and datediff(d,Createddate,getdate())<=case when @days is null then datediff(d,Createddate,getdate()) else @days end  
) A
end
if @section=0 or @section=5
begin
insert into #temp(Service,LastExecution,TotalCount,DetailedCount,Description) 
Select Service,LastExecution,cast(TodayCount as nvarchar) as TotalCount,cast(isnull(DetailedCount,0) as nvarchar) DetailedCount,Description from 
(
select 'Enquiries' as Service,max(Createddate) as LastExecution,sum(case when createddate>cast(getdate() as date)   then 1 else 0 end) as TodayCount,count(1) as DetailedCount,'' as Description  
from userenquiry(nolock) where ParentID=@parentid and datediff(d,Createddate,getdate())<=case when @days is null then datediff(d,Createddate,getdate()) else @days end  
union all  
select 'Leads' as Service,max(Createdon) as LastExecution,sum(case when CreatedOn>cast(getdate() as date)   then 1 else 0 end) as TodayCount,count(1) as DetailedCount,'' as Description  
from userleads(nolock) where parentid=@parentid and datediff(d,CreatedOn,getdate())<=case when @days is null then datediff(d,Createdon,getdate()) else @days end  
union all  
select 'FollowUps' as Service,max(l.Createdon) as LastExecution,sum(case when l.CreatedOn>cast(getdate() as date)   then 1 else 0 end) as TodayCount,count(1) as DetailedCount,'' as Description  
from LeadInteractionHistory(nolock) l join userleads u on u.ParentID=l.ParentID and u.LeadNo=l.LeadNo and u.CreatedOn<>l.CreatedOn and l.ParentID=@parentid  
and datediff(d,l.Createdon,getdate())<=case when @days is null then datediff(d,l.Createdon,getdate()) else @days end  
union all  
select 'Conversions' as Service,max(l.Createdon) as LastExecution,sum(case when l.CreatedOn>cast(getdate() as date)   then 1 else 0 end) as TodayCount,count(1) as DetailedCount,'' as Description  
from LeadInteractionHistory(nolock) l join userleads u on u.ParentID=l.ParentID and u.LeadNo=l.LeadNo and u.CreatedOn<>l.CreatedOn and l.ParentID=@parentid  
and l.FollowUpStatus=5
and datediff(d,l.Createdon,getdate())<=case when @days is null then datediff(d,l.Createdon,getdate()) else @days end  
union all  
select 'Tasks' as Service,dbo.fn_Max_date(max(l.Createdon),isnull(max(l.CompletedOn),max(l.Createdon))) as LastExecution,sum(case when l.CreatedOn>cast(getdate() as date)   then 1 else 0 end) as TodayCount,count(1) as DetailedCount,  
'' as Description  
from tbl_tsk_Taskhistory l(nolock)   
join user_detail u on u.User_ID=l.CreatedBy  
where istask=1 and u.ParentID=@parentid and datediff(d,l.Createdon,getdate())<=case when @days is null then datediff(d,l.Createdon,getdate()) else @days end  
union all  
select 'Appointments' as Service,dbo.fn_Max_date(max(l.Createdon),isnull(max(l.CompletedOn),max(l.Createdon))) as LastExecution,sum(case when l.CreatedOn>cast(getdate() as date)   then 1 else 0 end) as TodayCount,count(1) as DetailedCount,  
'' as Description  
from tbl_tsk_Taskhistory l(nolock)   
