and (uc.id is null or datediff(mi,cast(Step3DateTime as datetime),getdate())<=case when @mins is null then datediff(mi,cast(Step3DateTime as datetime),getdate()) else @mins end)    
where ud.User_ID=@parentid     
group by ud.User_ID    
union all          
select  'VoiceEventCampaign' as Service,    
max(Step3DateTime) as Lastexecution,    
count(uc.id) as TodayCount,    
sum(isnull(Step3Recipients,0)) as DetailedCount,    
'' as Description  from           
user_detail ud (nolock)    
left join usercampaignhistory(nolock) uc on uc.CampaignID<>0 and uc.Step3Recipients>0 and ud.user_id=uc.parentid and uc.IsEventBased=1 and uc.isSMS=2         
and (uc.id is null or datediff(mi,cast(Step3DateTime as datetime),getdate())<=case when @mins is null then datediff(mi,cast(Step3DateTime as datetime),getdate()) else @mins end)    
where ud.User_ID=@parentid     
group by ud.User_ID    
union all     
select  'VoiceScheduledCampaign' as Service,    
max(Step3DateTime) as Lastexecution,    
count(uc.id) as TodayCount,    
sum(isnull(Step3Recipients,0)) as DetailedCount,    
'' as Description  from           
user_detail ud (nolock)    
left join usercampaignhistory(nolock) uc on uc.CampaignID<>0 and uc.Step3Recipients>0 and ud.user_id=uc.parentid and uc.IsEventBased=0 and uc.isSMS=2         
and (uc.id is null or datediff(mi,cast(Step3DateTime as datetime),getdate())<=case when @mins is null then datediff(mi,cast(Step3DateTime as datetime),getdate()) else @mins end)    
where ud.User_ID=@parentid    
group by ud.User_ID    
) A  
end  
  
if @section=0 or @section=7  
begin  
insert into #temp(Service,LastExecution,TotalCount,DetailedCount,Description)   
Select Service,LastExecution,cast(TodayCount as nvarchar) as TotalCount,cast(isnull(DetailedCount,0) as nvarchar) DetailedCount,Description from   
(  
select 'VoiceBroadcast' as Service,max(lastaccesstime) as LastExecution,sum(case when LastAccessTime>cast(getdate() as date) and processed=2  then 1 else 0 end) as TodayCount,      
count(1) as DetailedCount,'' as Description    
 from Kit19Cloudvoicefinaltbl k(nolock) join BatchVoiceInfo b (nolock) on b.BatchID=k.batchid where b.parentid=@parentid          
 and datediff(mi,cast(lastaccesstime as datetime),getdate())<=case when @mins is null then datediff(mi,cast(lastaccesstime as datetime),getdate()) else @mins end    
union all          
select 'InboundCalls',max(call_start_time) as LastExecution,sum(case when call_start_time>cast(getdate() as date)  then 1 else 0 end)  as TodayCount,count(1) as DetailedCount,'' as Description from     
Kit19Calls k (nolock) left join cloud_user_phone(nolock) cu on     
cu.PhoneNo = isnull(k.clientid,(select case when k.context like 'outbound%' then k.callerid else k.dnid end))  where isnull(k.clientid,cu.Parentid)=@parentid    
and context in ('inbound','inbound1','incoming')          
and datediff(mi,cast(call_start_time as datetime),getdate())<=case when @mins is null then datediff(mi,cast(call_start_time as datetime),getdate()) else @mins end    
union all          
select 'ClickCalls',max(call_start_time) as LastExecution,sum(case when call_start_time>cast(getdate() as date)  then 1 else 0 end)  as TodayCount,count(1) as DetailedCount,'' as Description from     
Kit19Calls k (nolock) left join cloud_user_phone(nolock) cu on     
cu.PhoneNo = isnull(k.clientid,(select case when k.context like 'outbound%' then k.callerid else k.dnid end))  where isnull(k.clientid,cu.Parentid)=@parentid    
and context='DialerCalls'          
and datediff(mi,cast(call_start_time as datetime),getdate())<=case when @mins is null then datediff(mi,cast(call_start_time as datetime),getdate()) else @mins end    
union all          
select 'DialPadCalls' as Service, max(cast(CreateOn as datetime)) as LastExecution,sum(case when cast(CreateOn as datetime)>cast(getdate() as date) then 1 else 0 end) as TodayCount          
,count(1) as DetailedCount,'' as Description from tbl_DailPaidCallDetails(nolock) t join user_detail u (nolock) on u.User_ID=t.UserId     
where u.ParentID=@parentid    
and datediff(mi,cast(CreateOn as datetime),getdate())<=case when @mins is null then datediff(mi,cast(CreateOn as datetime),getdate()) else @mins end    
)A  
end  
if @section=0 or @section=8  
begin  
insert into #temp(Service,LastExecution,TotalCount,DetailedCount,Description)   
Select Service,LastExecution,cast(TodayCount as nvarchar) as TotalCount,cast(isnull(DetailedCount,0) as nvarchar) DetailedCount,Description from   
(  
Select 'Tickets Added' as Service,max(date_created) as LastExecution,sum(case when date_created>cast(getdate() as date) then 1 else 0 end) as TodayCount,  
count(1) as DetailedCount,'' as Description from Serv_TicketMaster (nolock) where parentid=@parentid and   
datediff(mi,cast(date_created as datetime),getdate())<=case when @mins is null then datediff(mi,cast(date_created as datetime),getdate()) else @mins end    
union all  
Select 'Tickets Updated' as Service,max(submitteddate) as LastExecution,sum(case when submitteddate>cast(getdate() as date) then 1 else 0 end) as TodayCount,  
count(distinct h.ticketid) as DetailedCount,'' as Description from Serv_TicketHistory h (nolock)   
join serv_ticketmaster m (nolock) on m.ticketid=h.ticketid  
where h.parentid=@parentid and m.update_by is not null and  
datediff(mi,cast(submitteddate as datetime),getdate())<=case when @mins is null then datediff(mi,cast(submitteddate as datetime),getdate()) else @mins end    
union all  
Select 'Tickets Resolved' as Service,max(submitteddate) as LastExecution,sum(case when submitteddate>cast(getdate() as date) then 1 else 0 end) as TodayCount,  
count(distinct h.ticketid) as DetailedCount,'' as Description from Serv_TicketHistory h (nolock)   
join serv_ticketmaster m (nolock) on m.ticketid=h.ticketid  
where h.parentid=@parentid and m.update_by is not null and h.status=1 and  
datediff(mi,cast(submitteddate as datetime),getdate())<=case when @mins is null then datediff(mi,cast(submitteddate as datetime),getdate()) else @mins end    
)A  
end  
 Select @sectionDesc as Section,Service,LastExecution,cast(TotalCount as nvarchar) as TotalCount,cast(DetailedCount as nvarchar) DetailedCount,Description from   
#temp  
end 


