and (uc.id is null or datediff(d,cast(Step3DateTime as datetime),getdate())<=case when @days is null then datediff(d,cast(Step3DateTime as datetime),getdate()) else @days end)  
where ud.User_ID=@parentid   
group by ud.User_ID  
union all   
select  'MailScheduledCampaign' as Service,  
max(Step3DateTime) as Lastexecution,  
count(uc.id) as TodayCount,  
sum(isnull(Step3Recipients,0)) as DetailedCount,  
case when max(Step3DateTime) is null then 'User does not have any active and running Mail Scheduled Campaign'  
when cast(max(Step3DateTime) as date)= cast(getdate() as date) then 'User has active Mail Scheduled campaigns'  
else 'User has Mail Scheduled campaigns that have either expired or not started yet. The last campaign ran '+cast(datediff(d,max(Step3DateTime),getdate()) as nvarchar)+  ' days back' end as Description  
from         
user_detail ud (nolock)  
left join usercampaignhistory(nolock) uc on uc.CampaignID<>0 and uc.Step3Recipients>0 and ud.user_id=uc.parentid and uc.IsEventBased=0 and uc.isSMS=0       
and (uc.id is null or datediff(d,cast(Step3DateTime as datetime),getdate())<=case when @days is null then datediff(d,cast(Step3DateTime as datetime),getdate()) else @days end)  
where ud.User_ID=@parentid   
group by ud.User_ID  
union all        
select  'VoiceEventCampaign' as Service,  
max(Step3DateTime) as Lastexecution,  
count(uc.id) as TodayCount,  
sum(isnull(Step3Recipients,0)) as DetailedCount,  
case when max(Step3DateTime) is null then 'User does not have any active and running Voice Event Campaign'  
when cast(max(Step3DateTime) as date)= cast(getdate() as date) then 'User has active Voice Event campaigns'  
else 'User has Voice event campaigns that have either expired or not started yet. The last campaign ran '+cast(datediff(d,max(Step3DateTime),getdate()) as nvarchar)+  ' days back' end as Description  
from         
user_detail ud (nolock)  
left join usercampaignhistory(nolock) uc on uc.CampaignID<>0 and uc.Step3Recipients>0 and ud.user_id=uc.parentid and uc.IsEventBased=1 and uc.isSMS=2       
and (uc.id is null or datediff(d,cast(Step3DateTime as datetime),getdate())<=case when @days is null then datediff(d,cast(Step3DateTime as datetime),getdate()) else @days end)  
where ud.User_ID=@parentid   
group by ud.User_ID  
union all   
select  'VoiceScheduledCampaign' as Service,  
max(Step3DateTime) as Lastexecution,  
count(uc.id) as TodayCount,  
sum(isnull(Step3Recipients,0)) as DetailedCount,  
case when max(Step3DateTime) is null then 'User does not have any active and running Voice Scheduled Campaign'  
