/* ============================================================
   Procedure: [dbo].[usp_GetDataListUserMails]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

  
CREATE   PROCEDURE [dbo].[usp_GetDataListUserMails]  
 @ParentID BIGINT,  
 @FilterName VARCHAR(500),  
 @IsValid BIT,  
 @IsInvalid BIT  
AS  
BEGIN  
 SELECT    
        dbo.[fn_getusertimefromindiantime](@ParentID,uere.CreatedDate)       AS CreatedOn,
        
        
        uere.PersonName,  
        uere.CompanyName,  
        uere.MobileNo,  
        uere.MobileNo1,  
        uere.MobileNo2,  
        uere.EmailID,  
        uere.EmailID1,  
        uere.EmailID2,  
        uere.City,  
        uere.[State],  
        uere.Country,  
        uere.CountryCode,  
        uere.PinCode,  
        uere.ResidentialAddress,  
        uere.OfficeAddress,  
        uere.InitialRemarks,  
        uere.FilterName  
 
 FROM   UserEnquiryRawEntries  AS uere  
 WHERE  uere.ParentID = @ParentID  
        AND uere.FilterName = @FilterName  
        AND uere.IsValid = @IsValid  
        AND uere.IsInValid = @IsInvalid  
 ORDER BY  
        uere.CreatedDate DESC  
END  



GO

