 inner join PipelineStages pis on lpm.PipeLineStage = pis.ID   
 inner join UserLeads(nolock) ul on lpm.LeadID = ul.Id  
where lpm.ID = ' + cast(@DealID as nvarchar(20))  
  
  /*
  '-- lpm.PipelineID > 0 and lpm.CreatedBy = ' + cast(@CreatedBy as varchar(20)) +'  
  --  and ((lpm.LeadID = case when ' + cast(@LeadId as varchar(20)) +' = 0 then lpm.LeadID else ' + cast(@LeadId as varchar(20)) +' end)  
  --or (lpm.PipelineID = case when ' + cast(@PipelineId as varchar(20)) +' = 0 then lpm.PipelineID else ' + cast(@PipelineId as varchar(20)) +' end)  
  --or (lpm.PipeLineStage = case when ' + cast(@PipelineStage as varchar(20)) +' = 0 then lpm.PipeLineStage else  ' + cast(@PipelineStage as varchar(20)) +' end))  
) t   
--Where  ''a''=''a'' ' + @FullText + ' ' + @FilterText + '  
)tt  
--Where  ''a''=''a'' ' + @SearchText + '  order by tt.ID desc   
  --OFFSET ' + cast(@OffsetValue as varchar(20)) + ' Rows FETCH NEXT ' + cast(@PagingSize as varchar(20)) + ' ROWS ONLY'   
  */

    print @Query1  
  
  exec (@Query1)  
  
--select count(*) over() as TotalRecords, * from (  
