-- inner join User_Detail UD1 on lpm.CreatedBy = UD1.User_ID   
-- inner join User_Detail UD2 on lpm.DealOwner = UD2.User_ID   
-- inner join Pipeline_Master pim on lpm.PipelineID = pim.ID  
-- inner join PipelineStages pis on lpm.PipeLineStage = pis.ID   
-- inner join UserLeads(nolock) ul on lpm.LeadID = ul.Id  
--where lpm.PipelineID > 0 and lpm.CreatedBy = @CreatedBy  
-- and ((lpm.LeadID = case when @LeadId = 0 then lpm.LeadID else @LeadId end)  
--  or (lpm.PipelineID = case when @PipelineId = 0 then lpm.PipelineID else @PipelineId end)  
--  or (lpm.PipeLineStage = case when @PipelineStage = 0 then lpm.PipeLineStage else @PipelineStage end))  
