/* ============================================================
   Procedure: [dbo].[Usp_GetDealHistory]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.Usp_GetDealHistory --132188
(
  @LeadID bigint
)
as
Begin

    SELECT
         LPM.PipelineID
        ,PM.Name as PipelineName
	    ,LPM.PipeLineStage
		,PS.Name as StageName
        ,LPM.Probability
        ,LPM.Amount
        ,LPM.Remarks
        ,LPM.CreatedDate
        ,LPM.CreatedBy
        ,(select isnull(User_Login,'') from User_Detail(nolock) where User_ID = LPM.CreatedBy) as CreatedByName
		,( case when LPM.DeletedOn is null then cast('' as nvarchar)
		        else  cast(LPM.DeletedOn as nvarchar)
		        end
		 ) as DeletedOn 

     FROM LeadPipelineMapping(nolock) as LPM 
	 join Pipeline_Master(nolock) as PM on LPM.PipelineID = PM.ID
     join PipelineStages(nolock) as PS on LPM.PipeLineStage = PS.ID 

	 where LPM.LeadID = @LeadID order by CreatedDate desc

 End




GO

/* ============================================================
   Procedure: [dbo].[Usp_GetDealPipelineProgress]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[Usp_GetDealPipelineProgress] --4254245 --1668438
 (  
  @LeadId bigint  
)  
as  
begin  
  
 --declare   
 -- @LeadId bigint = 1668438  
  
 declare @ParentId bigint = 0;  
  
 select @ParentId = ParentID from UserLeads(nolock) where ID = @LeadId  
  
 select s.*, l.*, ud.User_Login from (  
  select P.ID as PineLineId, p.Name as PinelineName, S.ID as StageId, S.Name as StageName, S.Sequence as StageSequence,s.Probability, s.CreatedBy 
   from Pipeline_Master(nolock) P inner join PipelineStages(nolock) S on S.PipelineID = P.ID   
  where P.IsDeleted = 0 and S.IsDeleted = 0 and P.ParentID = @ParentId and P.ID IN (  
   select PipelineID from LeadPipelineMapping_latest(nolock) l where l.IsDeleted = 0 and l.LeadID = @LeadId)  
   --order by s.[Sequence] asc  
 ) s left join (  
 select l.LeadID, l.CreatedDate, PipeLineStage, CreatedBy from LeadPipelineMapping_latest(nolock) l where l.IsDeleted = 0 and l.LeadID = @LeadId   
 ) l on l.PipeLineStage = s.StageId  
 left join User_Detail(nolock) ud on s.CreatedBy = ud.User_ID   
  order by PineLineId , StageSequence asc

end  


GO

/* ============================================================
   Procedure: [dbo].[Usp_getDeals_ByStageWise]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.Usp_getDeals_ByStageWise  --3,30         
(          
 @pipelineID bigint,          
 @StageID bigint          
)          
as          
Begin          
          
   Declare @MaxAmount numeric(18,2) = 0            
   Declare @TotalAmount Numeric(18,2) = 0          
   Declare @TotalCount int = 0     
        
   select @MaxAmount = max(isnull(Amount,0)) from LeadPipelineMapping where PipelineID = @pipelineID and  PipeLineStage = @StageID  and Isdeleted = 0        
          
   select @TotalAmount = sum(isnull(Amount,0)) from LeadPipelineMapping where PipelineID = @pipelineID and  PipeLineStage = @StageID  and Isdeleted = 0        
        
   select @TotalCount = isnull(count(1),0) from LeadPipelineMapping where PipelineID = @pipelineID 
   and  PipeLineStage = @StageID and Isdeleted = 0           
           
          
  select           
       [ID]          
      ,[LeadID]         
   ,isnull((select top 1 Personname from userleads where id = LeadID),'') as LeadName            
     -- ,[PipelineID]          
     -- ,[PipeLineStage]          
      ,(select isnull(Name,'')  from PipelineStages where ID = PipeLineStage and  PipelineID = @PipeLineID ) as StageName          
   ,[Probability]          
      ,[Amount]          
   ,@MaxAmount as MaxAmount           
   ,@TotalAmount as TotalAmount    
   ,@TotalCount as TotalDeal           
   ,[Remarks]          
      ,[CreatedDate]          
      ,[CreatedBy]          
      ,[EstimatedClosureDate]    
   , ( case when  datediff(DAY,getdate(),EstimatedClosureDate) > 0    
                  then cast(datediff(DAY,getdate(),EstimatedClosureDate) as nvarchar(100)) +' '+ 'days'    
      else 'expired'    
    end                   
     ) as ExpiryIn    
            
      ,[DealOwner]          
   ,(select isnull(user_login,'') from User_Detail where user_id = DealOwner ) as Owner          
          
  ,@StageID as StageID  
  
       from LeadPipelineMapping where PipelineID = @pipelineID and  PipeLineStage = @StageID  and Isdeleted = 0          
              
                
End 


GO

/* ============================================================
   Procedure: [dbo].[Usp_getDeals_ByStageWise_WithPriviledge]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.Usp_getDeals_ByStageWise_WithPriviledge  --3,30             
(              
 @pipelineID bigint,              
 @StageID bigint,  
 @UserID bigint              
)              
as              
Begin              
              
   Declare @MaxAmount numeric(18,2) = 0                
   Declare @TotalAmount Numeric(18,2) = 0              
   Declare @TotalCount int = 0    
   Declare @IsAdmin bit = 0  
     
    select top 1  @IsAdmin = isnull(Isadmin,0) from User_Detail(nolock) where User_ID = @UserID       
       
    
    
    
         
   select @MaxAmount = max(isnull(Amount,0)) from LeadPipelineMapping   
   where PipelineID = @pipelineID and  PipeLineStage = @StageID  and Isdeleted = 0  
         and CreatedBy = case when @IsAdmin = 1  
                        then CreatedBy  
          else @UserID  
       end          
               
              
   select @TotalAmount = sum(isnull(Amount,0)) from LeadPipelineMapping  
    where PipelineID = @pipelineID and  PipeLineStage = @StageID  and Isdeleted = 0            
        and CreatedBy = case when @IsAdmin = 1  
                        then CreatedBy  
          else @UserID  
       end          
   
     
            
   select @TotalCount = isnull(count(1),0) from LeadPipelineMapping where PipelineID = @pipelineID     
   and  PipeLineStage = @StageID and Isdeleted = 0               
         and CreatedBy = case when @IsAdmin = 1  
                        then CreatedBy  
          else @UserID  
       end          
  
                  
              
  select               
       [ID]              
      ,[LeadID]             
   ,isnull((select top 1 Personname from userleads where id = LeadID),'') as LeadName                
     -- ,[PipelineID]              
     -- ,[PipeLineStage]              
      ,(select isnull(Name,'')  from PipelineStages where ID = PipeLineStage and  PipelineID = @PipeLineID ) as StageName              
   ,[Probability]              
      ,[Amount]              
   ,@MaxAmount as MaxAmount               
   ,@TotalAmount as TotalAmount        
   ,@TotalCount as TotalDeal               
   ,[Remarks]              
      ,[CreatedDate]              
      ,[CreatedBy]              
      ,[EstimatedClosureDate]        
   , ( case when  datediff(DAY,getdate(),EstimatedClosureDate) > 0        
                  then cast(datediff(DAY,getdate(),EstimatedClosureDate) as nvarchar(100)) +' '+ 'days'        
      else 'expired'        
    end                       
     ) as ExpiryIn        
                
      ,[DealOwner]              
   ,(select isnull(user_login,'') from User_Detail where user_id = DealOwner ) as Owner              
              
  ,@StageID as StageID      
      
    from LeadPipelineMapping with(nolock) where PipelineID = @pipelineID and  PipeLineStage = @StageID  and Isdeleted = 0              
       and CreatedBy = case when @IsAdmin = 1  
                        then CreatedBy  
          else @UserID  
    end          
                  
                    
End 


