   declare @DateIntervalQuery nvarchar(max) = '' 
   declare @AmountRangeQuery nvarchar(max) = ''
   declare @ExpiryStatusQuery nvarchar(max) = ''


   if(rtrim(ltrim(@DealOwner)) = '')
     Begin
	    set @DealOwnerQuery = N' and (1 = 1) ' 
	 End
    else
	 Begin
	   set @DealOwnerQuery = N' and (lpm.DealOwner in ( select CAST(ISNULL(value, lpm.DealOwner) as bigint) from fn_Split('''+@DealOwner+''','','')))'
	 End

    if(rtrim(ltrim(@FromDate)) <> '' and rtrim(ltrim(@ToDate)) <> '' )
     Begin
	    set @DateIntervalQuery = N' and ( cast(lpm.CreatedDate as date) between cast('''+@FromDate+''' as date) and cast('''+ @ToDate +''' as date))'
	 End
    else
	 Begin
	   set @DateIntervalQuery = N' and (1 = 1) '
	 End
	 	 
    if(rtrim(ltrim(@AmountFrom)) <> '' and rtrim(ltrim(@AmountTo)) <> '' )
     Begin
	    set @AmountRangeQuery = N' and ( lpm.Amount  >= cast('''+@AmountFrom+''' as numeric(18,2)) and lpm.Amount  <=  cast('''+ @AmountTo +''' as numeric(18,2)))'
	 End
    else
	 Begin
	   set @AmountRangeQuery = N' and (1 = 1) '
	 End

	 if(isnull(@ExpiryInStatus,0) = 1)
	   Begin
	      set  @ExpiryStatusQuery =  N' and ( datediff(DAY,getdate(),lpm.EstimatedClosureDate) <= 0  )' 
	   end
     else
	   Begin 
	     set  @ExpiryStatusQuery =  N' and (1 = 1)' 
	   End




   declare @MaxQuery nvarchar(max) =  N'select @MaxAmount = max(isnull(Amount,0)) from LeadPipelineMapping(nolock) lpm   
     where PipelineID = '+ cast(@pipelineID as nvarchar) + ' and  PipeLineStage = '+ cast( @StageID as nvarchar)  + ' and Isdeleted = 0  
         and CreatedBy = case when '+ cast( @IsAdmin as nvarchar) + ' = 1  
                        then CreatedBy  
          else '+ cast(@UserID as nvarchar) + ' 
       end ' + @DealOwnerQuery + @DateIntervalQuery + @AmountRangeQuery + @ExpiryStatusQuery
	   
  print @MaxQuery
