   Declare @TotalAmount Numeric(18,2) = 0                          
   Declare @TotalCount int = 0                
           
   select @StageID = ISNULL(StageID,0) from #tblStages where RowNum = @RowIndex         
           
                         
   --select @MaxAmount = max(isnull(Amount,0)) from LeadPipelineMapping               
   --where PipelineID = @pipelineID and  PipeLineStage = @StageID  and Isdeleted = 0              
   --      and CreatedBy = case when @IsAdmin = 1              
   --                     then CreatedBy              
   --       else @UserID              
   --    end                      
   DECLARE @retvalMax numeric(18,2)               
   DECLARE @ParmDefinitionMax nvarchar(500) =  '';                         
   SET @ParmDefinitionMax = N'@MaxAmount numeric(18,2) OUTPUT';            
               
   DECLARE @retvalTotalAmount numeric(18,2)               
   DECLARE @ParmDefinitionTotalAmount nvarchar(500) =  '';                         
   SET @ParmDefinitionTotalAmount = N'@TotalAmount numeric(18,2) OUTPUT';            
               
               
   DECLARE @retvalTotalCount numeric(18,2)               
   DECLARE @ParmDefinitionTotalCount nvarchar(500) =  '';                         
   SET @ParmDefinitionTotalCount = N'@TotalCount numeric(18,2) OUTPUT';            
               
            
            
            
   declare @DealOwnerQuery nvarchar(max) = ''            
   declare @DateIntervalQuery nvarchar(max) = ''             
   declare @AmountRangeQuery nvarchar(max) = ''            
   declare @ExpiryStatusQuery nvarchar(max) = ''            
            
            
   if(rtrim(ltrim(@DealOwner)) = '')            
     Begin            
     set @DealOwnerQuery = N' and (1 = 1) '             
  End            
    else            
  Begin            
    set @DealOwnerQuery = N' and (lpm.DealOwner in ( select CAST(isnull(ISNULL(value, lpm.DealOwner),0) as bigint) from fn_Split('''+@DealOwner+''','','')))'            
  End            
            
    if(rtrim(ltrim(@FromDate)) <> '' and rtrim(ltrim(@ToDate)) <> '' )            
     Begin            
     set @DateIntervalQuery = N' and ( cast(lpm.CreatedDate as date) between cast('''+@FromDate+''' as date) and cast('''+ @ToDate +''' as date))'            
  End            
    else            
  Begin            
    set @DateIntervalQuery = N' and (1 = 1) '            
  End            
                
    if(rtrim(ltrim(@AmountFrom)) <> '' and rtrim(ltrim(@AmountTo)) <> '' )            
     Begin            
     set @AmountRangeQuery = N' and ( lpm.Amount  >= cast('''+@AmountFrom+''' as numeric(18,2)) and lpm.Amount  <=  cast('''+ @AmountTo +''' as numeric(18,2)))'            
  End            
    else            
  Begin            
    set @AmountRangeQuery = N' and (1 = 1) '            
  End            
            
  if(isnull(@ExpiryInStatus,0) = 1)            
    Begin            
       set  @ExpiryStatusQuery =  N' and ( datediff(DAY,getdate(),lpm.EstimatedClosureDate) <= 0  )'             
    end            
     else            
    Begin             
      set  @ExpiryStatusQuery =  N' and (1 = 1)'             
    End            
            
            
            
            
   declare @MaxQuery nvarchar(max) =  N'select @MaxAmount = max(isnull(Amount,0)) from LeadPipelineMapping_latest_PipelineGrouping(nolock) lpm   join #LeadAsPerAssigned as leadAsgn on lpm.LeadID = leadAsgn.AssignedLeadID                
     where PipelineID = '+ cast(@pipelineID as nvarchar) + ' and PipeLineStage = '+ cast( @StageID as nvarchar) + ' and isnull(LostID, 0) = (case when '+ cast(@LostID as nvarchar) + ' > 0 then '+ cast(@LostID as nvarchar) + ' else isnull(LostID, 0) end) and Isdeleted = '+ cast(@Isdeleted as nvarchar)
	 + '              
         and DealOwner ' +  case when cast(@IsAdmin as nvarchar)  = '1'              
                        then N' = DealOwner '              
      When  @UserIdTeamLst  != '' then N' in ('+ @UserIdTeamLst + ')'          
         else N' = ' + cast(@UserID as nvarchar)              
             end   
	 +  @DealOwnerQuery + @DateIntervalQuery + @AmountRangeQuery + @ExpiryStatusQuery            
                
  print @MaxQuery            
  exec sp_executesql @MaxQuery,@ParmDefinitionMax,@MaxAmount=@retvalMax OUTPUT;            
              
    set  @MaxAmount = isnull(@retvalMax,0)            
                           
   --select @TotalAmount = sum(isnull(Amount,0)) from LeadPipelineMapping              
   -- where PipelineID = @pipelineID and  PipeLineStage = @StageID  and Isdeleted = 0                        
   --     and CreatedBy = case when @IsAdmin = 1              
   --                     then CreatedBy              
   --   else @UserID              
   --    end                      
               
   declare @TotalAmountQuery nvarchar(max) =  N'select @TotalAmount = sum(isnull(Amount,0)) from LeadPipelineMapping_latest_PipelineGrouping(nolock) lpm               
      join #LeadAsPerAssigned as leadAsgn on lpm.LeadID = leadAsgn.AssignedLeadID   
	 where PipelineID = '+ cast(@pipelineID as nvarchar) + ' and  PipeLineStage = '+ cast( @StageID as nvarchar)  + ' and isnull(LostID, 0) = (case when '+ cast(@LostID as nvarchar) + ' > 0 then '+ cast(@LostID as nvarchar) + ' else isnull(LostID, 0) end) and  Isdeleted = '+ cast(@Isdeleted as nvarchar)+'              
         and DealOwner ' +  case when cast(@IsAdmin as nvarchar)  = '1'              
                        then N' = DealOwner '              
      When  @UserIdTeamLst  != '' then N' in ('+ @UserIdTeamLst + ')'          
         else N' = ' + cast(@UserID as nvarchar)              
             end   
	   + @DealOwnerQuery + @DateIntervalQuery + @AmountRangeQuery + @ExpiryStatusQuery            
                
  print @TotalAmountQuery            
  exec sp_executesql @TotalAmountQuery,@ParmDefinitionTotalAmount,@TotalAmount=@retvalTotalAmount OUTPUT;            
              
   set  @TotalAmount = isnull(@retvalTotalAmount,0)            
                        
   --select @TotalCount = isnull(count(1),0) from LeadPipelineMapping where PipelineID = @pipelineID                 
   --and  PipeLineStage = @StageID and Isdeleted = 0                           
   --      and CreatedBy = case when @IsAdmin = 1              
   --                     then CreatedBy              
   --       else @UserID              
   --    end                      
              
  declare @TotalCountQuery nvarchar(max) =  N'select @TotalCount = isnull(count(1),0) from LeadPipelineMapping_latest_PipelineGrouping(nolock) lpm               
      join #LeadAsPerAssigned as leadAsgn on lpm.LeadID = leadAsgn.AssignedLeadID   

	 where PipelineID = '+ cast(@pipelineID as nvarchar) + ' and  PipeLineStage = '+ cast( @StageID as nvarchar)  + ' and isnull(LostID, 0) = (case when '+ cast(@LostID as nvarchar) + ' > 0 then '+ cast(@LostID as nvarchar) + ' else isnull(LostID, 0) end) and Isdeleted = '+ cast(@Isdeleted as nvarchar)+'              
         and DealOwner' +  case when cast(@IsAdmin as nvarchar)  = '1'              
                        then N' = DealOwner '              
      When  @UserIdTeamLst  != '' then N' in ('+ @UserIdTeamLst + ')'          
         else N' = ' + cast(@UserID as nvarchar)              
             end   
	   + @DealOwnerQuery + @DateIntervalQuery + @AmountRangeQuery + @ExpiryStatusQuery            
                
  print @TotalCountQuery            
  exec sp_executesql @TotalCountQuery,@ParmDefinitionTotalCount,@TotalCount=@retvalTotalCount OUTPUT;            
              
   set  @TotalCount = isnull(@retvalTotalCount,0)            
                                             
   Declare @FinalQuery  nvarchar(max) = N'select                           
       [ID]                          
      ,[LeadID]                         
   ,isnull((select top 1 Personname from userleads with(nolock) where id = LeadID),'''') as LeadName                            
     -- ,[PipelineID]                          
     -- ,[PipeLineStage]                          
      ,(select isnull(Name,'''')  from PipelineStages with(nolock) where ID = PipeLineStage and  PipelineID = '+ cast(@pipelineID as nvarchar) + ' ) as StageName                          
   ,[Probability]                          
      ,[Amount]                          
   ,'+ cast(isnull(@MaxAmount,0) as nvarchar)+' as MaxAmount                           
   ,'+ cast(isnull(@TotalAmount,0) as nvarchar)+' as TotalAmount                    
   ,'+cast(isnull(@TotalCount,0) as nvarchar)+' as TotalDeal                           
   ,[Remarks]                          
      ,[CreatedDate]                          
      ,[CreatedBy]                          
      ,[EstimatedClosureDate]                    
   , ( case when  datediff(DAY,getdate(),EstimatedClosureDate) > 0                    
                  then cast(datediff(DAY,getdate(),EstimatedClosureDate) as nvarchar(100)) +''''+ ''days''                    
      else ''expired''                    
    end                                   
     ) as ExpiryIn                    
                            
      ,[DealOwner]                          
   ,(select isnull(user_login,'''') from User_Detail with(nolock) where user_id = DealOwner ) as Owner                          
                          
  , '+ cast(isnull(@StageID,0) as nvarchar) +' as StageID                  
                  
    from LeadPipelineMapping_latest_PipelineGrouping(nolock) lpm  join #LeadAsPerAssigned as leadAsgn on lpm.LeadID = leadAsgn.AssignedLeadID    where PipelineID = '+ cast(@pipelineID as nvarchar) + ' and  PipeLineStage = '+ cast( @StageID as nvarchar)  + ' and isnull(LostID, 0) = (case when '+ cast(@LostID as nvarchar) + ' > 0 then '+ cast(@LostID as nvarchar) + ' else isnull(LostID, 0) end) and Isdeleted = '+ cast(@Isdeleted as nvarchar)+'              
         and DealOwner ' +  case when cast(@IsAdmin as nvarchar)  = '1'              
                        then N' = DealOwner '              
      When  @UserIdTeamLst  != '' then N' in ('+ @UserIdTeamLst + ')'          
         else N' = ' + cast(@UserID as nvarchar)              
             end   
	   + @DealOwnerQuery + @DateIntervalQuery + @AmountRangeQuery + @ExpiryStatusQuery         
            
   print @FinalQuery            
    exec sp_executesql @FinalQuery               
                
    end -- end while loop             
                  
    drop table if exists #tblStages                     
	drop table if exists #LeadAsPerAssigned

End 





