/* ============================================================
   Procedure: [dbo].[Usp_getDeals_ByStageWise_WithPriviledgeWithCollectiveStage_New_Export]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[Usp_getDeals_ByStageWise_WithPriviledgeWithCollectiveStage_New_Export]  --357,'2549,2581',31871,'','','','','',0,0                         
(                          
 @pipelineID bigint,                          
 @StageIDCollections nvarchar(max),              
 @LostID bigint,            
 @UserID bigint,            
 @DealOwner nvarchar(max),            
 @FromDate nvarchar(100),            
 @ToDate nvarchar(100),            
 @AmountFrom nvarchar(100),            
 @AmountTo nvarchar(100),            
 @ExpiryInStatus bit,      
 @IsDeleted bit,
  @EstimatedClosureFrom nvarchar(100) = null,            
 @EstimatedClosureTo nvarchar(100) = null                                
)                          
as                          
Begin                          
           
 if(@IsDeleted = null)      
    begin       
      set @IsDeleted = 0        
    End      
 -- Declare @pipelineID bigint = 358,                          
 --@StageIDCollections nvarchar(max) = N'3561,2552,2563,2562,3797,2558,2561,2557,2556,2564,2555,2554,3862,2571,2572',              
 --@LostID bigint = 0,            
 --@UserID bigint = 39042,            
 --@DealOwner nvarchar(max) = N'',            
 --@FromDate nvarchar(100) = N'03/15/2023 00:00:00',            
 --@ToDate nvarchar(100) = N'03/22/2023 00:00:00',            
 --@AmountFrom nvarchar(100) = N'0',            
 --@AmountTo nvarchar(100) = N'9999999',            
 --@ExpiryInStatus bit = 0,
 --@IsDeleted bit = 0                 
      
 --@pipelineID=15, @StageIDCollections=N'102,103,104,105,106',@UserID=32222,@DealOwner=N'', @FromDate=N'03/02/2022',@ToDate=N'03/09/2022',@AmountFrom=N'0',@AmountTo=N'9999999',@ExpiryInStatus=0        
        
    drop table if exists #tblStages         
        
    Declare @StageCount int = 0;         
    Declare @RowIndex int = 0;         
 select ROW_NUMBER() over(order by [value] asc) as RowNum, [value] as StageID into #tblStages from (        
    select cast(isnull(value,0) as bigint) as value from fn_Split(@StageIDCollections,',')) as tbl        
         
    select @StageCount = isnull(count(1),0) from #tblStages            
 --select * from #tblStages        
         
 DECLARE @ParentId BIGINT = 0;        
 SELECT @ParentId = ParentID FROM User_Detail(nolock) WHERE User_ID = @UserId;                          
 Declare @IsAdmin bit = 0              
        
 declare @tbluser table (User_ID bigint,Name varchar(100), Image varchar(100))        
 select @IsAdmin = IsAdmin from User_Detail(nolock) where User_ID = @UserId        
 if(@IsAdmin = 1)        
 begin        
  set @UserId = 0;        
  insert into @tbluser        
  exec Use_GetUserDetails @ParentId        
 end        
 else        
 Begin        
  insert into @tbluser        
  exec Use_GetUserDetails @UserId        
 End        
           
 Declare @TeamCode varchar(10) = ''        
 Declare @ScopeCode varchar(10) = ''         
 Declare @UserIdTeamLst varchar(Max) = ''         
 Declare @UserLoginTeamLst varchar(Max) = ''         
        
 --select @TeamCode = TeamCode, @ScopeCode = ScopeCode, @UserIdTeamLst = UserIdTeamLst, @UserLoginTeamLst = UserLoginTeamLst from dbo.ufn_GetUserRoleScope(@UserId)         
        
 select @UserIdTeamLst=isnull(STRING_AGG(User_ID,','),'') From @tbluser        
        
  while(isnull(@StageCount,0) > 0 )        
  begin        
        
   set @StageCount = @StageCount - 1;        
   set  @RowIndex = @RowIndex + 1         
        
        
   Declare @StageID bigint = 0                        
   Declare @MaxAmount numeric(18,2) = 0                            
   Declare @TotalAmount Numeric(18,2) = 0                          
   Declare @TotalCount int = 0                
           
   select @StageID = ISNULL(StageID,0) from #tblStages where RowNum = @RowIndex         
           
                         
   --select @MaxAmount = max(isnull(Amount,0)) from LeadPipelineMapping               
   --where PipelineID = @pipelineID and  PipeLineStage = @StageID  and Isdeleted = 0              
   --      and CreatedBy = case when @IsAdmin = 1              
   --                     then CreatedBy              
   --       else @UserID              
   --    end                      
   DECLARE @retvalMax numeric(18,2)               
   DECLARE @ParmDefinitionMax nvarchar(500) =  '';                         
   SET @ParmDefinitionMax = N'@MaxAmount numeric(18,2) OUTPUT';            
               
   DECLARE @retvalTotalAmount numeric(18,2)               
   DECLARE @ParmDefinitionTotalAmount nvarchar(500) =  '';                         
   SET @ParmDefinitionTotalAmount = N'@TotalAmount numeric(18,2) OUTPUT';            
               
               
   DECLARE @retvalTotalCount numeric(18,2)               
   DECLARE @ParmDefinitionTotalCount nvarchar(500) =  '';                         
   SET @ParmDefinitionTotalCount = N'@TotalCount numeric(18,2) OUTPUT';            
               
            
            
            
   declare @DealOwnerQuery nvarchar(max) = ''            
   declare @DateIntervalQuery nvarchar(max) = ''             
   declare @AmountRangeQuery nvarchar(max) = ''            
   declare @ExpiryStatusQuery nvarchar(max) = ''            
   declare @EstimatedClosureDateStatusQuery nvarchar(max) = ''            
            
            
   if(rtrim(ltrim(@DealOwner)) = '')            
     Begin            
     set @DealOwnerQuery = N' and (1 = 1) '             
  End            
    else            
  Begin            
    set @DealOwnerQuery = N' and (DealOwner in ( select CAST(ISNULL(value, DealOwner) as bigint) from fn_Split('''+@DealOwner+''','','')))'            
  End  
  
  if(rtrim(ltrim(@FromDate)) <> '' and rtrim(ltrim(@ToDate)) <> '' )            
     Begin            
     set @DateIntervalQuery = N' and ( cast(CreatedDate as date) between cast('''+@FromDate+''' as date) and cast('''+ @ToDate +''' as date))'            
  End            
    else            
  Begin            
    set @DateIntervalQuery = N' and (1 = 1) '            
  End 
            
    if(rtrim(ltrim(@EstimatedClosureFrom)) <> '' and rtrim(ltrim(@EstimatedClosureTo)) <> '' )            
     Begin            
     set @EstimatedClosureDateStatusQuery = N' and ( cast(EstimatedClosureDate as date) between cast('''+@EstimatedClosureFrom+''' as date) and cast('''+ @EstimatedClosureTo +''' as date))'            
  End            
    else            
  Begin            
    set @EstimatedClosureDateStatusQuery = N' and (1 = 1) '            
  End            
                
    if(rtrim(ltrim(@AmountFrom)) <> '' and rtrim(ltrim(@AmountTo)) <> '' )            
     Begin            
     set @AmountRangeQuery = N' and ( Amount  >= cast('''+@AmountFrom+''' as numeric(18,2)) and Amount  <=  cast('''+ @AmountTo +''' as numeric(18,2)))'            
  End            
    else            
  Begin            
    set @AmountRangeQuery = N' and (1 = 1) '            
  End            
            
  if(isnull(@ExpiryInStatus,0) = 1)            
    Begin            
       set  @ExpiryStatusQuery =  N' and ( datediff(DAY,getdate(),EstimatedClosureDate) <= 0  )'             
    end            
     else            
    Begin             
      set  @ExpiryStatusQuery =  N' and (1 = 1)'             
    End            
            
            
            

   declare @MaxQuery nvarchar(max) =  N'select @MaxAmount = max(isnull(Amount,0)) from LeadPipelineMapping_latest(nolock) lpm               
     where PipelineID = '+ cast(@pipelineID as nvarchar) + ' and PipeLineStage = '+ cast( @StageID as nvarchar) + ' and isnull(LostID, 0) = (case when '+ cast(@LostID as nvarchar) + ' > 0 then '+ cast(@LostID as nvarchar) + ' else isnull(LostID, 0) end) and Isdeleted = '+ cast(@Isdeleted as nvarchar)
	 + '              
         and DealOwner ' +  case when cast(@IsAdmin as nvarchar)  = '1'              
                        then N' = DealOwner '              
      When  @UserIdTeamLst  != '' then N' in ('+ @UserIdTeamLst + ')'          
         else N' = ' + cast(@UserID as nvarchar)              
             end
	 + @DealOwnerQuery + @DateIntervalQuery + @AmountRangeQuery + @ExpiryStatusQuery            
                
  print @MaxQuery            
  exec sp_executesql @MaxQuery,@ParmDefinitionMax,@MaxAmount=@retvalMax OUTPUT;            
              
    set  @MaxAmount = isnull(@retvalMax,0)            
                           
   --select @TotalAmount = sum(isnull(Amount,0)) from LeadPipelineMapping              
   -- where PipelineID = @pipelineID and  PipeLineStage = @StageID  and Isdeleted = 0                        
   --     and CreatedBy = case when @IsAdmin = 1              
   --                     then CreatedBy              
   --   else @UserID              
   --    end                      
               
   declare @TotalAmountQuery nvarchar(max) =  N'select @TotalAmount = sum(isnull(Amount,0)) from LeadPipelineMapping_latest(nolock) lpm               
     where PipelineID = '+ cast(@pipelineID as nvarchar) + ' and  PipeLineStage = '+ cast( @StageID as nvarchar)  + ' and isnull(LostID, 0) = (case when '+ cast(@LostID as nvarchar) + ' > 0 then '+ cast(@LostID as nvarchar) + ' else isnull(LostID, 0) end) and  Isdeleted = '+ cast(@Isdeleted as nvarchar)+'              
         and DealOwner ' +  case when cast(@IsAdmin as nvarchar)  = '1'              
                        then N' = DealOwner '              
      When  @UserIdTeamLst  != '' then N' in ('+ @UserIdTeamLst + ')'          
         else N' = ' + cast(@UserID as nvarchar)              
             end + @DealOwnerQuery + @DateIntervalQuery + @AmountRangeQuery + @ExpiryStatusQuery            
                
  print @TotalAmountQuery            
  exec sp_executesql @TotalAmountQuery,@ParmDefinitionTotalAmount,@TotalAmount=@retvalTotalAmount OUTPUT;            
              
   set  @TotalAmount = isnull(@retvalTotalAmount,0)            
                        
   --select @TotalCount = isnull(count(1),0) from LeadPipelineMapping where PipelineID = @pipelineID                 
   --and  PipeLineStage = @StageID and Isdeleted = 0                           
   --      and CreatedBy = case when @IsAdmin = 1              
   --                     then CreatedBy              
   --       else @UserID              
   --    end                      
              
  declare @TotalCountQuery nvarchar(max) =  N'select @TotalCount = isnull(count(1),0) from LeadPipelineMapping_latest(nolock) lpm               
     where lpm.PipelineID = '+ cast(@pipelineID as nvarchar) + ' and  lpm.PipeLineStage = '+ cast( @StageID as nvarchar)  + ' and isnull(lpm.LostID, 0) = (case when '+ cast(@LostID as nvarchar) + ' > 0 then '+ cast(@LostID as nvarchar) + ' else isnull(lpm.LostID, 0) end) and Isdeleted = '+ cast(@Isdeleted as nvarchar)+'              
         and lpm.DealOwner ' +  case when cast(@IsAdmin as nvarchar)  = '1'              
                        then N' = DealOwner '              
      When  @UserIdTeamLst  != '' then N' in ('+ @UserIdTeamLst + ')'          
         else N' = ' + cast(@UserID as nvarchar)              
             end + @DealOwnerQuery + @DateIntervalQuery + @AmountRangeQuery + @ExpiryStatusQuery            
                
  print @TotalCountQuery            
  exec sp_executesql @TotalCountQuery,@ParmDefinitionTotalCount,@TotalCount=@retvalTotalCount OUTPUT;            
              
   set  @TotalCount = isnull(@retvalTotalCount,0)            
                                             
   Declare @FinalQuery  nvarchar(max) = N'select                           
       ID                          
      ,LeadID                         
   ,isnull((select top 1 Personname from userleads with(nolock) where id = LeadID),'''') as LeadName 
   ,isnull((select top 1 LeadNo from userleads with(nolock) where id = LeadID),'''') as LeadNo 
     -- ,[PipelineID]                          
     -- ,[PipeLineStage]                          
      ,(select isnull(Name,'''')  from PipelineStages with(nolock) where ID = PipeLineStage and  PipelineID = '+ cast(@pipelineID as nvarchar) + ' ) as StageName                          
   ,Probability                          
      ,Amount                          
   ,'+ cast(isnull(@MaxAmount,0) as nvarchar)+' as MaxAmount                           
   ,'+ cast(isnull(@TotalAmount,0) as nvarchar)+' as TotalAmount                    
   ,'+cast(isnull(@TotalCount,0) as nvarchar)+' as TotalDeal                           
   ,Remarks                          
      ,CreatedDate                          
      --,[CreatedBy]                            
      ,(dbo.udf_mk_GetTaskCreatorName(CreatedBy)) AS [CreatedBy]                          
      ,EstimatedClosureDate                    
   , ( case when  datediff(DAY,getdate(),EstimatedClosureDate) > 0                    
                  then cast(datediff(DAY,getdate(),EstimatedClosureDate) as nvarchar(100)) +''''+ ''days''                    
      else ''expired''                    
    end                                   
     ) as ExpiryIn                    
                            
      --,[DealOwner]                                                   
      ,(dbo.udf_mk_GetTaskCreatorName(DealOwner)) AS DealOwner                            
   ,(select isnull(user_login,'''') from User_Detail with(nolock) where user_id = DealOwner ) as Owner                          
                          
  , '+ cast(isnull(@StageID,0) as nvarchar) +' as StageID, Reason as LostReason,LostRemark as LostRemark                
                  
    from LeadPipelineMapping_latest(nolock) 


	where PipelineID = '+ cast(@pipelineID as nvarchar) + ' and  PipeLineStage = '+ cast( @StageID as nvarchar)  + ' and isnull(LostID, 0) = (case when '+ cast(@LostID as nvarchar) + ' > 0 then '+ cast(@LostID as nvarchar) + ' else isnull(LostID, 0) end) and Isdeleted = '+ cast(@Isdeleted as nvarchar)+'              
         and DealOwner ' +  case when cast(@IsAdmin as nvarchar)  = '1'              
                        then N' = DealOwner '              
      When  @UserIdTeamLst  != '' then N' in ('+ @UserIdTeamLst + ')'          
         else N' = ' + cast(@UserID as nvarchar)              
             end + @DealOwnerQuery + @DateIntervalQuery + @AmountRangeQuery + @ExpiryStatusQuery + @EstimatedClosureDateStatusQuery        
            
   print @FinalQuery            
    exec sp_executesql @FinalQuery               
                
    end -- end while loop             
                  
    drop table if exists #tblStages                     
End 



