   --    end                      
               
   declare @TotalAmountQuery nvarchar(max) = @QueryTotality + ' ; ' +  N'select @TotalAmount = sum(isnull(Amount,0)) from LeadPipelineMapping_latest_PipelineGrouping(nolock) lpm join #userleadsBySegment as uls               
     on lpm.LeadID = uls.ID  join #LeadAsPerAssigned as leadAsgn on lpm.LeadID = leadAsgn.AssignedLeadID             
     where PipelineID = '+ cast(@pipelineID as nvarchar) + ' and  PipeLineStage = '+ cast( @StageID as nvarchar)  + ' and isnull(LostID, 0) = (case when '+ cast(@LostID as nvarchar) + ' > 0 then '+ cast(@LostID as nvarchar) + ' else isnull(LostID, 0) end) and  Isdeleted = '+ cast(@Isdeleted as nvarchar)+'              
         and DealOwner ' +  case when cast(@IsAdmin as nvarchar)  = '1'              
                        then N' = DealOwner '              
      When  @UserIdTeamLst  != '' then N' in ('+ @UserIdTeamLst + ')'          
         else N' = ' + cast(@UserID as nvarchar)              
             end   
	   + @DealOwnerQuery + @DateIntervalQuery + @AmountRangeQuery + @ExpiryStatusQuery            
                
  print @TotalAmountQuery            
  exec sp_executesql @TotalAmountQuery,@ParmDefinitionTotalAmount,@TotalAmount=@retvalTotalAmount OUTPUT;            
              
   set  @TotalAmount = isnull(@retvalTotalAmount,0)            
                        
   --select @TotalCount = isnull(count(1),0) from LeadPipelineMapping where PipelineID = @pipelineID                 
   --and  PipeLineStage = @StageID and Isdeleted = 0                           
   --      and CreatedBy = case when @IsAdmin = 1              
   --                     then CreatedBy              
   --       else @UserID              
   --    end                      
              
  declare @TotalCountQuery nvarchar(max) = @QueryTotality + ' ; ' +  N'select @TotalCount = isnull(count(1),0) from LeadPipelineMapping_latest_PipelineGrouping(nolock) lpm join #userleadsBySegment as uls               
     on lpm.LeadID = uls.ID  join #LeadAsPerAssigned as leadAsgn on lpm.LeadID = leadAsgn.AssignedLeadID             
     where PipelineID = '+ cast(@pipelineID as nvarchar) + ' and  PipeLineStage = '+ cast( @StageID as nvarchar)  + ' and isnull(LostID, 0) = (case when '+ cast(@LostID as nvarchar) + ' > 0 then '+ cast(@LostID as nvarchar) + ' else isnull(LostID, 0) end) and Isdeleted = '+ cast(@Isdeleted as nvarchar)+'              
         and DealOwner' +  case when cast(@IsAdmin as nvarchar)  = '1'              
                        then N' = DealOwner '              
      When  @UserIdTeamLst  != '' then N' in ('+ @UserIdTeamLst + ')'          
         else N' = ' + cast(@UserID as nvarchar)              
             end   
	   + @DealOwnerQuery + @DateIntervalQuery + @AmountRangeQuery + @ExpiryStatusQuery            
                
  print @TotalCountQuery            
  exec sp_executesql @TotalCountQuery,@ParmDefinitionTotalCount,@TotalCount=@retvalTotalCount OUTPUT;            
              
   set  @TotalCount = isnull(@retvalTotalCount,0)            
                                             
   Declare @FinalQuery  nvarchar(max) = @QueryTotality + ' ; ' + N'select                           
       lpm.[ID]                          
      ,[LeadID]                         
   ,isnull((select top 1 Personname from userleads as ul1 with(nolock) where ul1.id = LeadID),'''') as LeadName                            
     -- ,[PipelineID]                          
     -- ,[PipeLineStage]                          
      ,(select isnull(Name,'''')  from PipelineStages as ps1 with(nolock) where ps1.ID = PipeLineStage and  PipelineID = '+ cast(@pipelineID as nvarchar) + ' ) as StageName                          
   ,[Probability]                          
      ,[Amount]                          
   ,'+ cast(isnull(@MaxAmount,0) as nvarchar)+' as MaxAmount                           
   ,'+ cast(isnull(@TotalAmount,0) as nvarchar)+' as TotalAmount                    
   ,'+cast(isnull(@TotalCount,0) as nvarchar)+' as TotalDeal                           
   ,[Remarks]                          
      ,[CreatedDate]                          
      ,[CreatedBy]                          
      ,[EstimatedClosureDate]                    
   , ( case when  datediff(DAY,getdate(),EstimatedClosureDate) > 0                    
                  then cast(datediff(DAY,getdate(),EstimatedClosureDate) as nvarchar(100)) +''''+ ''days''                    
      else ''expired''                    
    end                                   
     ) as ExpiryIn                    
                            
      ,[DealOwner]                          
   ,(select isnull(user_login,'''') from User_Detail with(nolock) where user_id = DealOwner ) as Owner                          
                          
  , '+ cast(isnull(@StageID,0) as nvarchar) +' as StageID                  
                  
    from LeadPipelineMapping_latest_PipelineGrouping(nolock) lpm join #userleadsBySegment as uls               
     on lpm.LeadID = uls.ID join #LeadAsPerAssigned as leadAsgn on lpm.LeadID = leadAsgn.AssignedLeadID   where PipelineID = '+ cast(@pipelineID as nvarchar) + ' and  PipeLineStage = '+ cast( @StageID as nvarchar)  + ' and isnull(LostID, 0) = (case when '+ cast(@LostID as nvarchar) + ' > 0 then '+ cast(@LostID as nvarchar) + ' else isnull(LostID, 0) end) and Isdeleted = '+ cast(@Isdeleted as nvarchar)+'              
         and DealOwner ' +  case when cast(@IsAdmin as nvarchar)  = '1'              
                        then N' = DealOwner '              
      When  @UserIdTeamLst  != '' then N' in ('+ @UserIdTeamLst + ')'          
         else N' = ' + cast(@UserID as nvarchar)              
             end   
	   + @DealOwnerQuery + @DateIntervalQuery + @AmountRangeQuery + @ExpiryStatusQuery         
            
   print @FinalQuery            
    exec sp_executesql @FinalQuery               
                
    end -- end while loop             
                  
    drop table if exists #tblStages
	drop table if exists  #userleadsBySegment 
	drop table if exists #LeadAsPerAssigned


End 





