SET QUOTED_IDENTIFIER ON

  
CREATE   PROCEDURE [dbo].[usp_GetDeliveryReport]  
 @BatchID BIGINT,  
 @CampaignID BIGINT  
AS  
BEGIN  
 DECLARE @UserID BIGINT  
 SELECT TOP 1 @UserID = ucm.AccountUsed  
 FROM   UserCampaignMaster AS ucm  
        INNER JOIN UserCampaignExecutionHistory AS uceh  
             ON  uceh.ID = ucm.ID  
 WHERE  ucm.ID = @CampaignID  
   
 SELECT *  
 FROM   MySMS.dbo.ThirtyDaysHistory AS tdh  
 WHERE  tdh.BatchID = @BatchID  
        AND tdh.U_ID = @UserID  
END    
 



