/* ============================================================
   Procedure: [dbo].[USP_GetDetailedReport]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[USP_GetDetailedReport]
    @UserID NVARCHAR(50),
	@FromDate Datetime,
	@Todate Datetime,
	@PageNumber int,
	@PageSize int
AS
BEGIN
    
	DECLARE @PreviousFromDate DATETIME = DATEADD(DAY, -DATEDIFF(DAY, @FromDate, @Todate) - 1, @FromDate);
	DECLARE @PreviousToDate DATETIME = DATEADD(DAY, -DATEDIFF(DAY, @FromDate, @Todate) - 1, @Todate);

	DECLARE @Offset INT = (@PageNumber - 1) * @PageSize; -- Calculate offset
	DECLARE @Fetch INT = @PageSize; -- Number of rows to fetch

	declare @ParentId bigint
	
	select @ParentId = ParentId from User_Detail(nolock) where User_Id = @UserID

	drop table if exists #tempUsers  
	create table #tempUsers(User_ID bigint, Name nvarchar(255), Image nvarchar(255))  
	insert into #tempUsers(User_ID, Name, Image)  
	exec Use_GetUserDetails @UserID = @UserID  

	-- select * from #tempUsers

	select 
		COUNT(*) OVER () AS TotalRecords,
		ted.Mode as Mode,
		--CONCAT(FORMAT(Cast(@FromDate as date), 'dd-MMM-yyyy'),' to ', FORMAT(Cast(@Todate as date), 'dd-MMM-yyyy')) as Period,
		FORMAT(ted.CreatedDate, 'dd-MMM-yyyy HH:mm') as Period,
		tem.PageURL as [PageName],
		CONCAT(ud.ParentID, ' (', pud.User_Login, ')') AS [ParentLogin],
		CONCAT(ud.User_ID, ' (', ud.User_Login, ')') AS [UserLogin],
		--ted.Mode as Mode,
		--CONCAT(
		--		FLOOR(SUM(ted.SpendTime) / 3600), ' h ',
		--		FLOOR(CAST(SUM(ted.SpendTime) AS INT) % 3600 / 60), ' m ',
		--		CAST(SUM(ted.SpendTime) AS INT) % 60, ' s'
		--	) AS [ActiveTime]
		CONCAT(
				FLOOR((ted.SpendTime) / 3600), ' h ',
				FLOOR(CAST((ted.SpendTime) AS INT) % 3600 / 60), ' m ',
				CAST((ted.SpendTime) AS INT) % 60, ' s'
			) AS [ActiveTime]
	from tbl_user_engagement_track_master(nolock) tem 
	inner join tbl_user_engagement_track_details ted on  ted.UserEngMasterId = tem.EngagementID
	left join #tempUsers tu on tem.UserID = tu.User_ID
	left join User_Detail ud on tem.UserID = ud.User_ID
	LEFT JOIN User_Detail pud ON ud.ParentID = pud.User_ID
	where tem.UserID = @UserID and FORMAT(ted.CreatedDate, 'yyyy-MM-dd HH:mm') between FORMAT(@FromDate , 'yyyy-MM-dd HH:mm') and FORMAT(@Todate , 'yyyy-MM-dd HH:mm')
	--where 
 --   (
 --       (@UserID = @ParentId AND tu.User_ID = tem.UserID)
 --       OR
 --       (@UserID <> @ParentId AND tem.UserID = @UserID)
 --   )
 --   AND FORMAT(ted.CreatedDate, 'yyyy-MM-dd') BETWEEN CAST(@FromDate AS DATE) AND CAST(@Todate AS DATE)
	GROUP BY 
		CONCAT(ud.ParentID, ' (', pud.User_Login, ')'),
        CONCAT(ud.User_ID, ' (', ud.User_Login, ')'),
		tem.PageURL,
		ted.Mode,
		ted.SpendTime,
		ted.CreatedDate
    ORDER BY 
        FORMAT(ted.CreatedDate, 'dd-MMM-yyyy') DESC
	OFFSET @Offset ROWS FETCH NEXT @Fetch ROWS ONLY;
END



GO

