CREATE   PROCEDURE [dbo].[USP_GetDetailsPageFilter]
	--@UserID NVARCHAR(50),
    @PageUrl NVARCHAR(50),
	@FromDate Datetime,
	@Todate Datetime
AS
BEGIN

		--declare @ParentId bigint
	
		--select @ParentId = ParentId from User_Detail(nolock) where User_Id = @UserID

		--drop table if exists #tempUsers  
		--create table #tempUsers(User_ID bigint, Name nvarchar(255), Image nvarchar(255))  
		--insert into #tempUsers(User_ID, Name, Image)  
		--exec Use_GetUserDetails @UserID = @UserID  

    select 

		COUNT(DISTINCT tem.UserID) as [TotalVisitors],
		COUNT(tem.PageURL) as [TotalVisits],
		CONCAT( FLOOR(SUM(ted.SpendTime) / 3600), ' h ',
				   FLOOR(CAST(SUM(ted.SpendTime) AS INT) % 3600 / 60), ' m ',
				   CAST(SUM(ted.SpendTime) AS INT) % 60, ' s') AS TotalActiveTime,

		CONCAT(
			   FLOOR((CAST(SUM(ted.SpendTime) AS INT) / NULLIF(COUNT( tem.PageURL), 0)) / 3600), ' h ',
			   FLOOR((CAST(SUM(ted.SpendTime) AS INT) / NULLIF(COUNT( tem.PageURL), 0)) % 3600 / 60), ' m ',
			   FLOOR((CAST(SUM(ted.SpendTime) AS INT) / NULLIF(COUNT( tem.PageURL), 0)) % 60), ' s') AS [AvgTimeforVisit],

		CONCAT(
			   FLOOR((CAST(SUM(ted.SpendTime) AS INT) / NULLIF(COUNT(DISTINCT tem.UserID), 0)) / 3600), ' h ',
			   FLOOR((CAST(SUM(ted.SpendTime) AS INT) / NULLIF(COUNT(DISTINCT tem.UserID), 0)) % 3600 / 60), ' m ',
			   FLOOR((CAST(SUM(ted.SpendTime) AS INT) / NULLIF(COUNT(DISTINCT tem.UserID), 0)) % 60), ' s') AS [AvgTimeforPerPage]
	    
	from tbl_user_engagement_track_master(nolock) tem 
	inner join tbl_user_engagement_track_details ted on  ted.UserEngMasterId = tem.EngagementID
	--left join #tempUsers tu on tem.UserID = tu.User_ID
	left join User_Detail ud on tem.UserID = ud.User_ID
	--where 
 --   (
 --       (@UserID = @ParentId AND tu.User_ID = tem.UserID)
 --       OR
 --       (@UserID <> @ParentId AND tem.UserID = @UserID)
 --   )
	--AND tem.PageURL LIKE '%' + @PageUrl + '%'
	--AND FORMAT(ted.CreatedDate, 'yyyy-MM-dd HH:mm') between FORMAT(@FromDate , 'yyyy-MM-dd HH:mm') and FORMAT(@Todate , 'yyyy-MM-dd HH:mm') 
	 where tem.PageURL LIKE '%' + @PageUrl + '%' and FORMAT(ted.CreatedDate, 'yyyy-MM-dd HH:mm') between FORMAT(@FromDate , 'yyyy-MM-dd HH:mm') and FORMAT(@Todate , 'yyyy-MM-dd HH:mm')
   
END



