CREATE   PROCEDURE [dbo].[usp_GetDiscountFromCoupon_withInt] --'lap',17626,30,1,0 --'abctrnsTes1',17626,19,0,0   --'TESTA',335,43,1,0       
 @couponcode NVARCHAR(50),        
 @user_id BIGINT,        
 @planid INT,        
 @IsSMS BIT,        
 @IsMail BIT,
 @IsINTSMS BIT        
AS        
BEGIN        
DECLARE @quantity INT = (        
             SELECT quantity        
             FROM   planmaster        
             WHERE  @planid = id        
         )     
 DECLARE @UUserFilter     NVARCHAR(20) = (        
