             FROM   user_detail        
             WHERE  USER_ID = @user_id        
         )     
 Declare @VarMinVolume Bigint  = 0       
 Declare @VarMaxVolume Bigint  = 0    
 Declare @VarMinMailVolume Bigint  = 0    
 Declare @VarMaxMailVolume Bigint  = 0        
 Declare @VarValidRange nvarchar(50) = 'InvalidRange'        
        
select @VarMinVolume = ISNULL(MinVolume,0),@VarMaxVolume = ISNULL(MaxVolume,0)    
,@VarMinMailVolume = ISNULL(MinMailVolume,0),@VarMaxMailVolume = ISNULL(MaxMailVolume,0)  
   from M_Coupon where  couponcode = @couponcode          
 -- select @VarMinVolume,@VarMaxVolume,@VarMinMailVolume,@VarMaxMailVolume    
 --IF EXISTS(   
 if @issms=1 and @IsMail=0 and @IsINTSMS = 0  
 begin       
      if((@VarMinVolume>=0 and @VarMaxVolume>0) and (@VarMinMailVolume=0 and @VarMaxMailVolume=0))    
       Begin    
        SELECT @VarValidRange = 'ValidRange'        
        FROM   m_coupon m        
        WHERE  m.couponcode = @couponcode        
               AND m.[STATUS] = 1        
               AND ISNULL(NULLIF(m.[ROUTE], 'All'), @uuserfilter) = @uuserfilter        
               AND GETDATE() BETWEEN ValidFrom  AND ValidTo  
               AND @quantity BETWEEN (MinVolume) AND (MaxVolume)     
       End    
 end   
 if @issms=1 and @IsMail=0 and @IsINTSMS = 1  
 begin       
      if((@VarMinVolume>=0 and @VarMaxVolume>0) and (@VarMinMailVolume=0 and @VarMaxMailVolume=0))    
       Begin    
        SELECT @VarValidRange = 'ValidRange'        
        FROM   m_coupon m        
        WHERE  m.couponcode = @couponcode        
               AND m.[STATUS] = 1        
               AND ISNULL(NULLIF(m.[ROUTE], 'All'), @uuserfilter) = @uuserfilter        
               AND GETDATE() BETWEEN ValidFrom  AND ValidTo  
               AND @quantity BETWEEN (MinVolume) AND (MaxVolume) 
               AND @quantity BETWEEN  MinIntVolume and  MaxIntVolume  
       End    
 end 
   
   if @issms=1 and @IsMail=1 and @IsINTSMS = 0  
 begin   
if((@VarMinVolume>=0 and @VarMaxVolume>0) and (@VarMinMailVolume >=0 and @VarMaxMailVolume > 0))    
       Begin    
       SELECT @VarValidRange = 'ValidRange'        
        FROM   m_coupon m        
        WHERE  m.couponcode = @couponcode        
               AND m.[STATUS] = 1        
               AND ISNULL(NULLIF(m.[ROUTE], 'All'), @uuserfilter) = @uuserfilter        
               AND GETDATE() BETWEEN ValidFrom AND ValidTo   
               AND @quantity BETWEEN (MinVolume) AND (MaxVolume)  
               AND  @quantity BETWEEN (MinMailVolume) AND (MaxMailVolume)  
        End   
  end   
  if @issms=1 and @IsMail=1 and @IsINTSMS = 1  
 begin   
if((@VarMinVolume>=0 and @VarMaxVolume>0) and (@VarMinMailVolume >=0 and @VarMaxMailVolume > 0))    
       Begin    
       SELECT @VarValidRange = 'ValidRange'        
        FROM   m_coupon m        
        WHERE  m.couponcode = @couponcode        
               AND m.[STATUS] = 1        
               AND ISNULL(NULLIF(m.[ROUTE], 'All'), @uuserfilter) = @uuserfilter        
               AND GETDATE() BETWEEN ValidFrom AND ValidTo   
               AND @quantity BETWEEN (MinVolume) AND (MaxVolume)  
               AND  @quantity BETWEEN (MinMailVolume) AND (MaxMailVolume) 
               AND @quantity BETWEEN  MinIntVolume and  MaxIntVolume  
        End   
  end   
  if @IsSMS=0 and @IsMail=1 and @IsINTSMS = 0  
  begin  
if((@VarMinVolume=0 and @VarMaxVolume=0) and (@VarMinMailVolume >=0 and @VarMaxMailVolume > 0))    
       Begin   
        SELECT @VarValidRange = 'ValidRange'        
        FROM   m_coupon m        
        WHERE  m.couponcode = @couponcode    
               AND m.[STATUS] = 1        
               AND ISNULL(NULLIF(m.[ROUTE], 'All'), @uuserfilter) = @uuserfilter        
               AND GETDATE() BETWEEN ValidFrom AND ValidTo   
               --AND @quantity BETWEEN (MinVolume) AND (MaxVolume)  
               AND  @quantity BETWEEN (MinMailVolume) AND (MaxMailVolume)  
        End  
          
end    
if @IsSMS=0 and @IsMail=1 and @IsINTSMS = 1  
  begin  
if((@VarMinVolume=0 and @VarMaxVolume=0) and (@VarMinMailVolume >=0 and @VarMaxMailVolume > 0))    
       Begin   
        SELECT @VarValidRange = 'ValidRange'        
        FROM   m_coupon m        
        WHERE  m.couponcode = @couponcode    
               AND m.[STATUS] = 1        
               AND ISNULL(NULLIF(m.[ROUTE], 'All'), @uuserfilter) = @uuserfilter        
               AND GETDATE() BETWEEN ValidFrom AND ValidTo   
                AND  @quantity BETWEEN (MinMailVolume) AND (MaxMailVolume)
                AND @quantity BETWEEN  MinIntVolume and  MaxIntVolume 
        End  
          
end   
if @IsSMS=0 and @IsMail=0 and @IsINTSMS = 1  
  begin  
if((@VarMinVolume=0 and @VarMaxVolume=0) and (@VarMinMailVolume >=0 and @VarMaxMailVolume > 0))    
       Begin   
        SELECT @VarValidRange = 'ValidRange'        
        FROM   m_coupon m        
        WHERE  m.couponcode = @couponcode    
               AND m.[STATUS] = 1        
               AND ISNULL(NULLIF(m.[ROUTE], 'All'), @uuserfilter) = @uuserfilter        
               AND GETDATE() BETWEEN ValidFrom AND ValidTo   
                AND @quantity BETWEEN  MinIntVolume and  MaxIntVolume 
        End  
          
end   
   -- )        
       
   --select @VarValidRange     
        
 if(@VarValidRange = 'ValidRange')    
 BEGIN        
        
     SELECT VALUE INTO #temp        
        
     FROM   dbo.fn_split(        
        
                (        
        
                    SELECT savedsearch        
        
                    FROM   m_coupon        
        
                    WHERE  CouponCode = @couponcode        
        
                ),        
        
                '#'        
        
            )   
     DECLARE @s BIGINT              
      SELECT @s = MIN(VALUE)        
       FROM   #temp            
      CREATE TABLE #TempTable2        
         (        
          UserID         BIGINT,        
          User_Login     VARCHAR(250),        
          FName          VARCHAR(250),        
          LName          VARCHAR(250),        
          EMail          VARCHAR(500),       
          Mobile         VARCHAR(50),        
          Country        VARCHAR(50),        
          [State]        VARCHAR(50),        
          City           VARCHAR(50),        
          userfilter     VARCHAR(250)        
         )    
     WHILE @s IS NOT NULL        
        
     BEGIN        
        
         SELECT @s = MIN(VALUE)   
         FROM   #temp        
         INSERT INTO #TempTable2        
           (        
             UserID,        
             User_Login,        
             FName,        
             LName,        
             EMail,        
             Mobile,        
             Country,        
             [State],        
             City,        
             userfilter        
           )        
        
         EXEC usp_GetExecutedKit19UsersForCoupon @s,@user_id    
           
         DELETE FROM   #temp        
         WHERE  VALUE = @s        
        
     END    
  
     IF EXISTS ( SELECT 'x'  FROM   #TempTable2 AS tt        
        
            WHERE  tt.UserID = @user_id        
        )        
        
     BEGIN        
         SELECT TOP 1 1 Result,--'Coupon Applied Successfully',        
        
                mc.Discount ,mc.IsAmount       
        
         FROM   M_Coupon  AS mc        
        
         WHERE  mc.CouponCode = @couponcode        
        
         ORDER BY  mc.DateCreated DESC        
        
                 
        
      DROP TABLE #TempTable2        
        
         GOTO endofsp        
        
     END        
        
     ELSE        
        
     BEGIN        
        
         SELECT 0 Result,     --Coupon invalid   
        
                0 discount      
        
                 
        
      DROP TABLE #TempTable2        
        
         GOTO endofsp        
        
     END        
        
 END            
 ELSE        
        
 BEGIN        
        
     SELECT 0 Result, --Coupon invalid       
        
            0 discount      
     GOTO endofsp        
        
 END    
 endofsp:        
        
END   
  
  
--select * from m_coupon where ID=154  


