/* ============================================================
   Procedure: [dbo].[usp_GetDiscountFromCouponCode]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_GetDiscountFromCouponCode] --'abcCoupon',335,2,0,1
	@couponcode NVARCHAR(50),
	@user_id BIGINT,
	@planid INT,
	@IsSMS BIT,
	@IsMail BIT
AS
BEGIN
	DECLARE @quantity        INT = (
	            SELECT quantity
	            FROM   planmaster
	            WHERE  @planid = id
	        )    
	
	
	
	DECLARE @UUserFilter     NVARCHAR(20) = (
	            SELECT userfilter
	            FROM   user_detail
	            WHERE  USER_ID = @user_id
	        )    
	
	
	
	IF EXISTS(
	       SELECT 1
	       FROM   m_coupon m
	       WHERE  m.couponcode = @couponcode
	              AND m.[STATUS] = 1
	              AND ISNULL(NULLIF(m.[ROUTE], 'All'), @uuserfilter) = @uuserfilter
	              AND GETDATE() BETWEEN 
	                  
	                  ValidFrom AND ValidTo
	              AND @quantity BETWEEN (MinVolume) AND (MaxVolume)
	              AND m.IsSMS = @IsSMS
	              AND m.IsMail = @IsMail
	   )
	BEGIN
	    SELECT VALUE INTO #temp
	    FROM   dbo.fn_split(
	               (
	                   SELECT savedsearch
	                   FROM   m_coupon
	                   WHERE  CouponCode = @couponcode
	               ),
	               '#'
	           )    
	    
	    
	    
	    DECLARE @s BIGINT      
	    
	    SELECT @s = MIN(VALUE)
	    FROM   #temp    
	    
	    
	    
	    WHILE @s IS NOT NULL
	    BEGIN
	        --select @s
	        
	        --select dbo.fn_UserMatchesSearch(@user_id,@s)     
	        
	        IF (@IsSMS = 1)
	        BEGIN
	            IF (
	                   SELECT dbo.fn_UserMatchesSearch(@user_id, @s)
	               ) = 1
	            BEGIN
	                SELECT 'Coupon applied successfully' Result,
	                       discount
	                FROM   M_Coupon
	                WHERE  @Couponcode = Couponcode 
	                
	                
	                
	                GOTO endofsp
	            END
	            ELSE
	            BEGIN
	                DELETE 
	                FROM   #temp
	                WHERE  VALUE = @s    
	                
	                
	                
	                SELECT @s = MIN(VALUE)
	                FROM   #temp
	            END
	        END
	        ELSE
	        BEGIN
	            IF (
	                   SELECT dbo.fn_UserMatchesSearchForMail(@user_id, @s)
	               ) = 1
	            BEGIN
	                SELECT 'Coupon applied successfully' Result,
	                       discount
	                FROM   M_Coupon
	                WHERE  @Couponcode = Couponcode 
	                
	                
	                
	                GOTO endofsp
	            END
	            ELSE
	            BEGIN
	                DELETE 
	                FROM   #temp
	                WHERE  VALUE = @s    
	                
	                
	                
	                SELECT @s = MIN(VALUE)
	                FROM   #temp
	            END
	        END
	    END     
	    
	    SELECT 'Coupon invalid' Result,
	           0 discount 
	    
	    
	    
	    GOTO endofsp
	END
	ELSE
	BEGIN
	    --SELECT @couponcode,
	    
	    --       @UUserFilter,
	    
