/* ============================================================
   Procedure: [dbo].[usp_GetDiscountFromCouponCode1]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC [dbo].[usp_GetDiscountFromCouponCode1] --'newcoupon',17626,9 
@couponcode NVARCHAR(50),    
@user_id BIGINT,    
@planid INT    

AS    
BEGIN  
 DECLARE @quantity        INT = (  
             SELECT quantity  
             FROM   planmaster  
             WHERE  @planid = id  
         )
         select @quantity  
   
 DECLARE @UUserFilter     NVARCHAR(20) = (  
             SELECT userfilter  
             FROM   user_detail  
             WHERE  USER_ID = @user_id  
         )  
         select @uuserfilter
   
 IF EXISTS(  
        SELECT 1  
        FROM   m_coupon  
        WHERE  couponcode     = @couponcode  
               AND STATUS      = 1  
               AND ISNULL(NULLIF(ROUTE, ''), @uuserfilter) = @uuserfilter  
               AND GETDATE() BETWEEN   
                   ValidFrom AND ValidTo  
               AND @quantity BETWEEN (MinVolume) AND (MaxVolume)  
    )  
 BEGIN  
     select 'coupon eligible'
     SELECT VALUE INTO #temp  
     FROM   dbo.fn_split(  
                (  
                    SELECT savedsearch  
                    FROM   m_coupon  
                    WHERE  CouponCode = @couponcode  
                ),  
                '#'  
            )  
       
     DECLARE @s BIGINT    
     SELECT @s = MIN(VALUE)  
     FROM   #temp  
     select @s
       
     WHILE @s IS NOT NULL  
     BEGIN  
         --select @s  
         select dbo.fn_UserMatchesSearch(@user_id,@s)   
         IF (  
                SELECT dbo.fn_UserMatchesSearch(@user_id, @s)  
            ) = 1  
         BEGIN  
             SELECT 'Coupon applied successfully' Result,  
                    discount  
             FROM   M_Coupon  
             WHERE  @Couponcode = Couponcode  
               
             GOTO endofsp  
         END  
         ELSE  
         BEGIN  
             DELETE   
             FROM   #temp  
             WHERE  VALUE = @s  
               
             SELECT @s = MIN(VALUE)  
             FROM   #temp  
         END  
     END   
     SELECT 'Coupon invalid' Result,  
            0 discount  
       
     GOTO endofsp  
 END  
 ELSE  
 BEGIN  
     --SELECT @couponcode,  
     --       @UUserFilter,  
     --       @quantity,  
     --       STATUS,  
     --       ROUTE,  
     --       ValidFrom,  
     --       ValidTo,  
     --       (MinVolume),  
     --       (MaxVolume)  
     --FROM   M_Coupon  
     --WHERE  CouponCode = @couponcode  
     select 'coupon ineligible'  
     SELECT 'Coupon invalid' Result,  
            0 discount  
       
     GOTO endofsp  
 END   
 endofsp:  
END


GO

