   Procedure: [dbo].[usp_GetDiscountFromCouponCodeNew]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_GetDiscountFromCouponCodeNew] --'TESTA',335,43,1,0

	@couponcode NVARCHAR(50),

	@user_id BIGINT,

	@planid INT,

	@IsSMS BIT,

	@IsMail BIT

AS

BEGIN

	DECLARE @quantity        INT = (

	            SELECT quantity

	            FROM   planmaster

	            WHERE  @planid = id

	        )    

	

	

	

	

	

	

	

	DECLARE @UUserFilter     NVARCHAR(20) = (

	            SELECT userfilter

	            FROM   user_detail

	            WHERE  USER_ID = @user_id

	        )    

	

	

	

	

	

	

	

	IF EXISTS(

	       SELECT 1

	       FROM   m_coupon m

	       WHERE  m.couponcode = @couponcode

	              AND m.[STATUS] = 1

	              AND ISNULL(NULLIF(m.[ROUTE], 'All'), @uuserfilter) = @uuserfilter

	              AND GETDATE() BETWEEN 

	                  

	                  

	                  

	                  ValidFrom AND ValidTo

	              AND @quantity BETWEEN (MinVolume) AND (MaxVolume)

	              AND m.IsSMS = @IsSMS

	              AND m.IsMail = @IsMail

	   )

	BEGIN

	    SELECT VALUE INTO #temp

	    FROM   dbo.fn_split(

	               (

	                   SELECT savedsearch

	                   FROM   m_coupon

	                   WHERE  CouponCode = @couponcode

	               ),

	               '#'

	           )    

	    

	    

	    

	    

	    

	    

	    

	    DECLARE @s BIGINT      

	    

	    

	    

	    SELECT @s = MIN(VALUE)

	    FROM   #temp    

	    

	    

	    

	    

	    

	    

	        CREATE TABLE #TempTable2

	        (

	        	UserID         BIGINT,

	        	User_Login     VARCHAR(250),

	        	FName          VARCHAR(250),

	        	LName          VARCHAR(250),

	        	EMail          VARCHAR(500),

	        	Mobile         VARCHAR(50),

	        	Country        VARCHAR(50),

	        	[State]        VARCHAR(50),

	        	City           VARCHAR(50),

	        	userfilter     VARCHAR(250)

	        )

	    

	    WHILE @s IS NOT NULL

	    BEGIN

	        SELECT @s = MIN(VALUE)

	        FROM   #temp

	        

	        DELETE 

	        FROM   #temp

	        WHERE  VALUE = @s

	        

	        

	        INSERT INTO #TempTable2

	          (

	            UserID,

	            User_Login,

	            FName,

	            LName,

	            EMail,

	            Mobile,

	            Country,

	            [State],

	            City,

	            userfilter

	          )

	        EXEC usp_GetExecutedKit19UsersForCoupon @s,@user_id

	    END     

	    

	    IF EXISTS (

	           SELECT 'x'

	           FROM   #TempTable2 AS tt

	           WHERE  tt.UserID = @user_id

	       )

	    BEGIN

	        SELECT TOP          1 'Coupon Applied Successfully',

	               mc.Discount

	        FROM   M_Coupon  AS mc

	        WHERE  mc.CouponCode = @couponcode

	        ORDER BY

	               mc.DateCreated DESC

	        

	    	DROP TABLE #TempTable2

	        GOTO endofsp

	    END

	    ELSE

	    BEGIN

	        SELECT 'Coupon invalid' Result,

	               0 discount

	        

	    	DROP TABLE #TempTable2

	        GOTO endofsp

	    END

	END

	ELSE

	BEGIN

	    SELECT 'Coupon invalid' Result,

	           0 discount 

	    

	    

	    

	    

	    

	    

	    

	    GOTO endofsp

	END 

	

	

	

	endofsp:

END



