               AND  @quantity BETWEEN (MinMailVolume) AND (MaxMailVolume)
        End 
  end 
  if @IsSMS=0 and @IsMail=1
  begin
if((@VarMinVolume=0 and @VarMaxVolume=0) and (@VarMinMailVolume >=0 and @VarMaxMailVolume > 0))  
       Begin 
        SELECT @VarValidRange = 'ValidRange'      
        FROM   m_coupon m      
        WHERE  m.couponcode = @couponcode  
               AND m.[STATUS] = 1      
               AND ISNULL(NULLIF(m.[ROUTE], 'All'), @uuserfilter) = @uuserfilter      
               AND GETDATE() BETWEEN ValidFrom AND ValidTo 
               --AND @quantity BETWEEN (MinVolume) AND (MaxVolume)
               AND  @quantity BETWEEN (MinMailVolume) AND (MaxMailVolume)
        End
        
end  
   -- )      
     
   --select @VarValidRange   
      
 if(@VarValidRange = 'ValidRange')  
 BEGIN      
      
     SELECT VALUE INTO #temp      
      
     FROM   dbo.fn_split(      
      
                (      
      
                    SELECT savedsearch      
      
