   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.Usp_GetDispositionOfCalls
As
Begin
   select distinct dialstatus from Kit19CallsDialled(nolock) where  isnull(dialstatus,'') <> ''
     order by dialstatus asc
end



GO

/* ============================================================
   Procedure: [dbo].[usp_GetDistinctParentIds]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_GetDistinctParentIds]        
AS        
BEGIN        
    SET NOCOUNT ON;        
        
    BEGIN TRY        
        SELECT DISTINCT u.parentid        
        FROM userreport as u  WITH(NOLOCK) join       
   user_detail as d  WITH(NOLOCK) on u.user_id=d.user_id join Price_UserSubscriptionDetails as pu  WITH(NOLOCK) on pu.UserID=d.User_ID where Reportdate=CAST(DATEADD(d, -1, GETDATE()) AS DATE) and       
   d.Status=1 and pu.IsNewPlan=1 and pu.PlanEndDate >= cast(GETDATE() as date)  
   and d.m_id in (10043,10001) order by u.parentid desc;        
    END TRY        
    BEGIN CATCH        
   exec usp_InsertErrorInfo         
    END CATCH;        
END; 


GO

/* ============================================================
   Procedure: [dbo].[Usp_GetDLTTemplateBySenderName]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[Usp_GetDLTTemplateBySenderName]  --'DMCARE',40671  --'TXTSMS',335                        
(                        
  @SenderName nvarchar(100),                        
  @UserID bigint                        
)                        
as                        
Begin                        
                        
      Declare @Parentid bigint = 0;          
          
      select @Parentid = ISNULL(parentId,User_ID) from User_Detail(nolock) where User_ID = @UserID           
      --select @Parentid = ISNULL(User_ID,User_ID) from User_Detail(nolock) where User_ID = @UserID     
          
    
    
   --Select DLT.IsUnicode, TSM.DLT_TemplateID as DLT_TemplateID, TSM.DLT_TemplateID + '-' + SUBSTRING(DLT.TemplateText,1,50)  as TemplateText   , SUBSTRING(DLT.TemplateText,1,50)  as TemplateTextTooltip , DLT.TemplateText as TemplateTextDetail   from  DLT_TemplateSenderMapping(nolock) TSM                     
   --Join DLT_Template(nolock) DLT                      
   --on TSM.DLT_TemplateID = DLT.DLT_TemplateID                       
   --where TSM.CreatedBy = @UserID                        
   --and TSM.SenderID in                         
   --   (                         
   --    Select SID.Sender_ID from SenderID_Detail(nolock) SID                        
   --    where User_ID = @UserID and Sender_Name = @SenderName                          
   --   )               
                 
   Select 
    --DLT.IsUnicode,
   dbo.fn_IsUnicode(DLT.MailContent) as IsUnicode,
   TSM.DLT_TemplateID as DLT_TemplateID,        
           isnull(nullif(DLT.Name,''),dlt.DLT_TemplateID) as TemplateName,                     
    TSM.DLT_TemplateID + '-' + SUBSTRING(DLT.MailContent,1,50)  as TemplateText             
     , SUBSTRING(DLT.MailContent,1,50)  as TemplateTextTooltip , DLT.MailContent as TemplateTextDetail             
  ,isnull(DLT.Name,'') as Name  from  DLT_TemplateSenderMapping(nolock) TSM                        
   Join UserMailTemplate(nolock) DLT                      
   on TSM.DLT_TemplateID = DLT.DLT_TemplateID    
    and  
 (  
   (DLT.ParentID  = @Parentid)                    
       or  
   ( DLT.CreatedBy = @UserID)    
    )  
   where (TSM.CreatedBy = @UserID or (TSM.CreatedBy = @Parentid))                       
   and TSM.SenderID in                         
      (                         
       Select SID.Sender_ID from SenderID_Detail(nolock) SID                        
       where(    
        (User_ID = @UserID)    
         or (User_ID = @Parentid)    
   )        
    and Sender_Name = @SenderName                          
      )              
              
                          
end 


GO

/* ============================================================
   Procedure: [dbo].[Usp_GetDLTTemplateBySenderName_new]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

     
 -- Usp_GetDLTTemplateBySenderName_new 'KITAPP',34594    
    
CREATE   PROCEDURE [dbo].[Usp_GetDLTTemplateBySenderName_new] --'ANYAPV',49370,1,0     --'DMCARE',40671  --'TXTSMS',335                              
(                              
  @SenderName nvarchar(100),                              
  @UserID bigint,    
  @isenquiry bit,    
  @isleads bit     
)                              
as                              
Begin                              
  
  --     declare  @SenderName nvarchar(100) = 'ANYAPV',
		--@UserID bigint  = 49370,    
		--@isenquiry bit = 1,    
		--@isleads bit = 0     
  


      Declare @Parentid bigint = 0;                
                
      select @Parentid = ISNULL(parentId,User_ID) from User_Detail(nolock) where User_ID = @UserID                 
                          
                       
   Select DLT.IsUnicode, TSM.DLT_TemplateID as DLT_TemplateID,              
           isnull(nullif(DLT.Name,''),dlt.DLT_TemplateID) as TemplateName,                           
    TSM.DLT_TemplateID + '-' + SUBSTRING(DLT.MailContent,1,50)  as TemplateText                   
     , SUBSTRING(DLT.MailContent,1,50)  as TemplateTextTooltip , DLT.MailContent as TemplateTextDetail                   
  ,isnull(DLT.Name,'') as Name,DLT.IsEnquiry,dlt.IsLeads  from  DLT_TemplateSenderMapping(nolock) TSM                              
   Join UserMailTemplate(nolock) DLT                            
   on TSM.DLT_TemplateID = DLT.DLT_TemplateID          
  join  SenderID_Detail(nolock) SID on tsm.SenderID = sid.Sender_ID
   where 
       dlt.ParentID = @Parentid
	   	  and sid.Sender_Name = @SenderName                                 

  and 
  1= case 
  when Dlt.IsEnquiry=1 and @isenquiry=1 then 1
  when Dlt.IsLeads=1 and @isleads=1 then 1
 else 0 end

end 
       --select * from UserMailTemplate with(nolock) where ParentID = 49370



