CREATE   PROCEDURE [dbo].[Usp_GetDLTTemplateBySenderNameWithChanges] --'XSKODA',39680  --'TXTSMS',335                  
(                  
  @SenderName nvarchar(100) = null,
  @UserID bigint                  
)                  
as                  
Begin        

	--declare 
	--@SenderName nvarchar(100) = null,
	--@UserID bigint  = 32222
                  
   Declare @Parentid bigint = 0;    
    
   select @Parentid = ISNULL(parentId,User_ID) from User_Detail(nolock) where User_ID = @UserID     
           
   Select   distinct   
            --DLT.IsUnicode,  
            TSM.DLT_TemplateID as DLT_TemplateID,  
            ( case when  isnull(DLT.Name,'') <> '' then DLT.Name  
        else       
            TSM.DLT_TemplateID + '-' + SUBSTRING(DLT.MailContent,1,50)  
     end )    
      as TemplateText      
     
      
      --, SUBSTRING(DLT.MailContent,1,50)  as TemplateTextTooltip , DLT.MailContent as TemplateTextDetail       
     -- ,isnull(DLT.Name,'') as Name    
    
  from  DLT_TemplateSenderMapping(nolock) TSM                  
   Join UserMailTemplate(nolock) DLT                
   on TSM.DLT_TemplateID = DLT.DLT_TemplateID                 
   where (TSM.CreatedBy = @UserID or (TSM.CreatedBy = @Parentid))                 
   and TSM.SenderID in                   
      (                   
       Select SID.Sender_ID from SenderID_Detail(nolock) SID                  
       where ((User_ID = @UserID) or (User_ID = @Parentid) ) and Sender_Name = @SenderName                    
      )        
        
                    
end  


