/* ============================================================
   Procedure: [dbo].[usp_getdlttemplateid]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE usp_getdlttemplateid
(@user_id bigint,@m nvarchar(2000))
as
begin
declare @dltid nvarchar(50),@c int,@n nvarchar(max),@tid bigint=0,@dm nvarchar(max),@q nvarchar(max),@parentid bigint
--@m nvarchar(2000)='Dear Client, % is the OTP for submission the request for your Folio Account Statement. Valid for % minutes.',
select @parentid=parentid from user_detail(nolock) where user_id=@user_id
select top 1 @dltid=DLT_TemplateID from UserMailTemplate(nolock) where 
activestatus=1 and DLT_TemplateID is not null and ParentID=@parentid
and @m = MailContent --or @m like 
if @dltid is null
begin
select @c= count(1) from UserMailTemplate(nolock) where 
activestatus=1 and DLT_TemplateID is not null and ParentID=@parentid
drop table if exists ##dlt
create table ##dlt(dltid nvarchar(50))
while @c>0 and @dltid is null
begin
select @tid=min(id) from UserMailTemplate(nolock) where 
activestatus=1 and DLT_TemplateID is not null and ParentID=@parentid and id>@tid
select @dm=mailcontent from UserMailTemplate(nolock) where id=@tid
select @n=coalesce(@n+'+ ''%''+','')+''''+rtrim(value)+'''' from dbo.fn_split(@dm,'%')
print @n
select @q='insert into ##dlt(dltid) select case when '''+@m+''' like '+@n+ ' then DLT_TemplateID end from UserMailTemplate(nolock) where id='+cast(@tid as nvarchar)
print @q
exec (@q)
select top 1 @dltid=dltid from ##dlt 
set @c=@c-1
set @n=null
truncate table ##dlt
end
end 
select isnull(@dltid,0) as DLT_TemplateID
end



GO

