SET QUOTED_IDENTIFIER ON

/***********************      
***********************/      
CREATE   PROC Usp_GetdndRefundRecord --'','','01/11/2010','20/11/2010'      
( @Userid varchar(20),      
@senderid varchar(20),      
@FDATE varchar(20),      
@TDATE varchar(20)      
)      
AS      
Begin      
Declare @query varchar(MAX)      
Declare @where varchar(MAX)      
Set @query=''      
Set @where=''      
if(@userid='')      
Begin      
Set @where=@where+ ' and 1=1 '      
End      
else      
Begin      
Set @where=@where+ ' and userID='+Convert(varchar,@UserID,10)      
End      
if(@senderid='')      
Begin      
Set @where=@where+ ' and 1=1 '      
End      
else      
Begin      
Set @where=@where+ ' and senderid='''+@senderid+''''      
End      
if(@FDATE='' or @TDATE='')      
Begin      
Set @where=@where+' and 1=1 '      
End      
else      
Begin      
Set @where =@where +' and convert(nvarchar,date,112) between convert(nvarchar,convert(datetime,'''+@FDATE+''',103),112) and convert(nvarchar,convert(datetime ,'''+@TDATE +''',103),112)'              
End      
SET @query='select d.ID,d.USERID,d.Senderid,d.Total,d.DND,convert(varchar,d.date,103) as DATE,d.Message,d.Priority,case(d.Priority) when ''1'' then ''Priority'' else ''Normal'' end as PriorityType,case(isnull(d.IsRefund,0)) when ''0'' then ''NotRefund'' else ''Refunded'' End
  
    
 as IsRefund,d.action,d.IsUnicode,d.batchid from dndrefund d,User_detail u where u.User_id=d.USERID and u.FilterMode=1 and d.action=0 and d.dnd > 0 '+@where+'       
 order by Date'        
           
print(@Query)              
exec(@query)        
End 


GO

