   Procedure: [dbo].[usp_GetDomainInfoByUserId]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE usp_GetDomainInfoByUserId      
(              
    @UserId bigint             
)              
as              
begin              
              
    --declare @UserId bigint = 34594 --48167 --52237   
      
    drop table if exists #tDomain  
              
    DECLARE @ParentId bigint  = 0, @domainName nvarchar(255), @domainType nvarchar(255) = '', @backgroundImage nvarchar(255),   
    @companyLogo nvarchar(255), @slogan nvarchar(255),             
    @faviconIcon nvarchar(255), @hyperlinkOnLogo nvarchar(512), @termUrl nvarchar(255), @policyUrl nvarchar(512),            
    @domain nvarchar(255), @resellerId bigint = 0 , @CompanyName varchar(300), @Applogo nvarchar(300), @M_ID bigint = 0
  
    select @ParentId = ParentID, @M_ID = M_ID from User_Detail(nolock) where User_ID = @UserId  
  
    print concat('@ParentId => ', @ParentId)
  
    select d.Reseller_ID, d.ParentID, d.Domain, d.domainType into #tDomain from (              
        select r.Reseller_ID, u.ParentID, r.Domain, 'partner' as 'domainType' from reseller_detail(nolock) r              
        inner join User_Detail(nolock) u on r.User_ID = u.User_ID -- or r.Reseller_ID = u.M_ID         
        where (r.Reseller_ID = @M_ID OR r.User_ID = @UserId) and r.Partner_Type in (2,3)          
        --where r.User_ID = @ParentId  and r.Partner_Type in (2,3)          
    union              
        select 0 as [Reseller_ID], s.ParentID, s.[value] as [Domain], 'client' as [domainType]              
        from MYSMSInvoicing.dbo.settings(nolock) s               
        where s.[key]  = 'CustomiseDomain' and parentid = @ParentId         
    ) d              
  
  

         
 SELECT @ParentId = ParentID, @domainType = domainType, @resellerId = Reseller_ID from #tDomain              
          
 DECLARE @loginPage nvarchar(255) = '~/AppLogin.aspx', @WebsiteSettingJSON nvarchar(max) = N'{"Theme":"Theme 1"}'              
               
   /*            
   {    "USERID": "62600",    "DomainName": "www.partner.newpartner.co.in",    "LogoUrl": "Google Form Mapping.jpg",    "HyperlinkLogo": "www.partner.newpartner.co.in",    "favicon": "10043/Favicon Image.png",    "Theme": "Theme 1",    "Background_ImageUr
l": "10043/download.jpg",    "TermUrl": "www.partner.newpartner.co.in",    "PolicyUrl": "www.partner.newpartner.co.in"  }            
   */            
  
 IF(EXISTS(SELECT 1 from tbl_pt_CustomizationMetadata(NOLOCK) WHERE userid = @ParentId) and @domainType = 'partner')              
 BEGIN              
  SELECT   
    @loginPage = ( case JSON_VALUE(jsondata, '$.Theme')              
         when 'theme 1' then '~/AppLogin1.aspx'              
         when 'theme 2' then '~/AppLogin2.aspx'              
         when 'theme 3' then '~/AppLogin3.aspx'              
         else '~/AppLogin.aspx' end),            
      @backgroundImage  = JSON_VALUE(jsondata, '$.Background_ImageUrl'),            
      @companyLogo  = JSON_VALUE(jsondata, '$.LogoUrl'),            
      @hyperlinkOnLogo  = JSON_VALUE(jsondata, '$.HyperlinkLogo'),      
      @domainName = JSON_VALUE(jsondata, '$.DomainName'),   
      @faviconIcon  = JSON_VALUE(jsondata, '$.favicon'),            
      @policyUrl  = JSON_VALUE(jsondata, '$.PolicyUrl'),            
      @termUrl  = JSON_VALUE(jsondata, '$.TermUrl'),        
      @Applogo = JSON_VALUE(jsonMobileData, '$.MobileAppLogo')        
  from tbl_pt_CustomizationMetadata(nolock) where userid = @ParentId             
            
 END             
             
        
print @domainType         
        
 if(@domainType = 'client')            
 begin            
     select @companyLogo =  [value] from MYSMSInvoicing.dbo.settings(nolock) s where s.ParentId = @ParentId and [key] = 'SiteLogo'            
     select @backgroundImage = [value] from MYSMSInvoicing.dbo.settings(nolock) s where s.ParentId = @ParentId and [key] = 'BackGroundLogo'            
     select @faviconIcon= [value] from MYSMSInvoicing.dbo.settings(nolock) s where s.ParentId = @ParentId and [key] = 'Fav'            
     select @loginPage  = '~/ClientLogin.aspx', @hyperlinkOnLogo  = '', @slogan  = '', @policyUrl  = '', @termUrl = ''  
 end            
            
 --Testing Element            
 --select @loginPage = '~/AppLogin3.aspx'            
            
               
 SELECT             
     @ParentId as [ParentId],             
     @loginPage as [LoginPage],            
     @hyperlinkOnLogo as [hyperlinkOnLogo],            
     isnull(@slogan,'') as [slogan],            
     isnull(@domainName,'') as [domainName],            
     @policyUrl as [policyUrl],            
     @termUrl as [termUrl],            
     @backgroundImage as [backgroundImage],            
     @companyLogo as [companyLogo],            
     @faviconIcon as [faviconIcon],            
     @domainType as [domainType],            
     @resellerId as [ResellerId],          
     @CompanyName as [CompanyName] ,        
     @Applogo as [AppLogo]        
              
 --SELECT ParentID, Domain, domainType, '~/AppLogin3.aspx' as [LoginPage] FROM #tDomain              
              
END 


GO

