CREATE   PROC [dbo].[Usp_GetDuplicateEntryStatus]
(@PersonName NVARCHAR(100), @CompanyName NVARCHAR(100)) 
AS
BEGIN
	IF (
	       EXISTS(
	           SELECT 'x'
	           FROM   UserEnquiry
	           WHERE  PersonName          = @PersonName
	                  AND CompanyName     = @CompanyName
	       )
	   )
	BEGIN
	    SELECT 'Exist'
	END
	ELSE
	BEGIN
	    SELECT 'Not Exist'
	END
END



