CREATE   PROC usp_GetDynamicMailTemplateData
(
	@MailTemplateId bigint
)
As
Begin

	-- Declare @MailTemplateId bigint=16905

	select  UCM.TemplateID, UMT.Name as TemplateName, UCM.MailReplyTo, UMT.MailSubject, UMT.MailContent, UCM.FromMailId
	from UserCampaignMaster(nolock) UCM inner join [UserMailTemplate](nolock) UMT
	on	UCM.TemplateID=UMT.ID
	where UMT.ID=@MailTemplateId
	
End


GO

/* ============================================================
   Procedure: [dbo].[usp_getearlywarningaccounts]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC [dbo].[usp_getearlywarningaccounts]
as
begin
DECLARE @xml NVARCHAR(MAX)
DECLARE @body NVARCHAR(MAX)

update e set FinalStatus=1,ReactivatedOn=lastlogin1 from earlywarningaccounts e join user_detail u on e.user_id=u.user_id where lastlogin1>datecaptured
and e.id=(select max(id) from EarlyWarningAccounts where user_id=e.User_id)


declare @total int= (select COUNT(distinct user_id) from EarlyWarningAccounts)
declare @totalRetrieved int= (select count(1) from
(select distinct user_id from EarlyWarningAccounts group by user_id having max(FinalStatus)=1 ) A)
select A.Date,A.PossibleChurnReported,A.CasesRetrieved into #temp 
from 
(select cast(month(datecaptured) as nvarchar)+'-'+cast(year(datecaptured) as nvarchar) as Date,count(distinct user_id) PossibleChurnReported,sum(case when finalstatus=1 then 1 else 0 end) CasesRetrieved
from EarlyWarningAccounts where cast(month(datecaptured) as nvarchar)+'-'+cast(year(datecaptured) as nvarchar)<>cast(month(getdate()) as nvarchar)+'-'+cast(year(getdate()) as nvarchar)
group by month(datecaptured),year(datecaptured)
union all
select cast(cast(Datecaptured as date) as nvarchar) Date,count(1) PossibleChurnReported,sum(case when finalstatus=1 then 1 else 0 end) CasesRetrieved from EarlyWarningAccounts 
where month(datecaptured)=month(getdate()) and year(datecaptured)=year(getdate())
group by cast(Datecaptured as date) 
union all
select 'TotalTillDate ' ,@total PossibleChurnReported,@totalRetrieved CasesRetrieved 
 ) A 
--select * from #temp
--drop table #temp

SET @xml =CAST(( SELECT Date AS 'td','',PossibleChurnReported AS 'td','', 
CasesRetrieved AS 'td' from #temp FOR XML PATH('tr'), ELEMENTS ) AS NVARCHAR(MAX))


SET @body ='<html><H1>Possible Churn Cases Report as on '+cast(cast(getdate() as date) as nvarchar)+'</H1><body><table border = 2><tr><th>Date</th><th>PossibleChurnReported</th><th>CasesRetrieved</th></tr>' 
SET @body = @body + @xml +'</table></body></html>'
declare @subject nvarchar(100) = 'Possible Churn Cases Report as on '+cast(cast(getdate() as date) as nvarchar)
select @body
EXEC msdb.dbo.sp_send_dbmail
@profile_name='Alerts', 
@recipients='csshukla@pelsoftlabs.in', 
@blind_copy_recipients='karuna@pelsoftlabs.in;possiblechurn@pelsoftlabs.in;surjeet.kaur@pelsoftlabs.in;animesh.shukla@pelsoftlabs.in',
@subject=@subject,
@body = @body,
@body_format ='HTML'


insert into EarlyWarningAccounts(DateCaptured,User_id,User_login,ReferenceNo,LinkedStatus,LastLogin,FinalStatus,ReactivatedOn)
select getdate() DateCaptured,u.user_Id,u.user_login,isnull(l.refrenceno,0) RefrenceNo,case when l.verified=1 then 1 else 0 end as LinkedStatus,u.Lastlogin1,0 Finalstatus,Null LoggedInOn --into 15DaysInactiveAccounts
from user_detail u left join
(select user_id,refrenceno,verified from crm.crmdb.dbo.linkedaccount) l on l.user_id=u.user_id
where datediff(d,u.lastlogin1,getdate()) between 15 and 20 and m_id=10043
and u.user_id not in (select distinct user_id from credit_details(nolock) where debits>0 and datediff(d,datecreated,getdate())<=20)
and u.user_id=parentid and u.user_id not in (select user_id from EarlyWarningAccounts where cast(datecaptured as date)=cast(getdate() as date))

select * into #temp2 from EarlyWarningAccounts where cast(datecaptured as date)=cast(getdate() as date)
declare @count int=(select count(1) from #temp2)
SET @xml =CAST(( SELECT cast(DateCaptured as date) AS 'td','',User_id AS 'td','',User_login AS 'td','',ReferenceNo AS 'td','',LinkedStatus AS 'td','',LastLogin AS 'td' from #temp2 FOR XML PATH('tr'), ELEMENTS ) AS NVARCHAR(MAX))


SET @body ='<html><H1>Possible Churn Cases as on '+cast(cast(getdate() as date) as nvarchar)+ '. Total cases: ' + cast(@count as nvarchar)+
'</H1><body><table border = 2><tr><th>Date</th><th>User_id</th><th>User_login</th><th>ReferenceNo</th><th>LinkedStatus</th><th>LastLogin</th></tr>' 
SET @body = @body + @xml +'</table></body></html>'
set @subject = 'Possible Churn Cases as on '+cast(cast(getdate() as date) as nvarchar)+ '. Total cases: ' + cast(@count as nvarchar)
select @body
EXEC msdb.dbo.sp_send_dbmail
@profile_name='Alerts', 
@recipients='csshukla@pelsoftlabs.in', 
@blind_copy_recipients='karuna@pelsoftlabs.in;possiblechurn@pelsoftlabs.in;surjeet.kaur@pelsoftlabs.in;animesh.shukla@pelsoftlabs.in',
@subject=@subject,
@body = @body,
@body_format ='HTML'

drop table #temp
drop table #temp2

end




GO

/* ============================================================
   Procedure: [dbo].[Usp_GetEmailIDByLeadID]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.Usp_GetEmailIDByLeadID --260 ,4  
(  
  
  @LeadID bigint,    
  @WhichEmail int  
  
)   
as  
Begin  
  
    if(@WhichEmail = 1)  
 Begin  
     select isnull(EmailID,'') from userleads where  ID = @LeadID      
 End  
 else if(@WhichEmail = 2)  
 Begin  
   select isnull(EmailID1,'') from userleads where  ID = @LeadID      
 End  
 else if(@WhichEmail = 3)  
 Begin  
   select isnull(EmailID2,'') from userleads where  ID = @LeadID      
 End
 else if(@WhichEmail = 4)  
 Begin  
   select isnull(EmailID,'') as EmailID,isnull(EmailID1,'') as EmailID1 , isnull(EmailID2,'') as EmailID2 from userleads where  ID = @LeadID      
 End
   
  
End


GO

