/* ============================================================
   Procedure: [dbo].[usp_GetEmailLinkDetails]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC dbo.usp_GetEmailLinkDetails  
as   
Begin  
   
   
 select [ID],  
      --, (select User_Login   from user_detail where USER_ID = UserID ) as 'User'    
      UserID  
      ,[ParentID]  
      ,[EmailID]  
      ,[ForwadingEmail] as VirtualMail  
      ,case when  IsVerified = 1  
               then 'Yes'  
               else  
                    'No'  
       end  as Forwarded  
      ,[IsFiltered]  
      ,[LastExtracted]  
      ,[LastFiltered]  
      ,[CreatedOn]  
      ,[CreatedBy]  
      ,[isLatest]  
      , case when IsStep7 = 1  
                  then 'Step7'  
                  else  
                       case when IsStep6 = 1  
                             then 'Step6'  
                             else   
                                  case when IsStep5 = 1  
                                       then 'Step5'  
                                       else   
                                            case when IsStep4 = 1  
                                                  then 'Step4'  
                                                  else   
                                                      case when IsStep3 = 1  
                                                           then 'Step3'  
                                                           else  
                                                              case when IsStep2 = 1  
                                                                    then 'Step2'  
                                                                    else  
                                                                       case when IsStep1 = 1  
                                                                           then 'Step1'  
                                                                           else  
                                                                               'No Step Executed Yet'  
                                                                       end   
                                                              end   
                                                      end  
                                            end    
                                                
                                  end  
                       end  
                         
        end   
        as LastExecutedStep      
           
  from UserMailbox order by ID desc  
  
end





GO

