/* ============================================================
   Procedure: [dbo].[USP_GetEmailsRecord]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


-- THIS STORED PROCEDURE IS NOT FOUND IN PROJECT. IT MAY BE USED IN WINDOWS SERVICE FOR SENDING EMAILS..                         
CREATE   PROC [dbo].[USP_GetEmailsRecord]-- 1,''     
(@TOPCOUNT INT = 100, @SMTPSERVER VARCHAR(50) = '')                                           
AS                                            
BEGIN
	--EXEC USP_INSERTTOP_BUTTOMFIVEINQUEUE          
	DECLARE @RESTCOUNTAFTERDIRECT INT                                       
	DECLARE @RESTCOUNTAFTERPRIORITY INT                                    
	
	DECLARE @TEMPTABLE TABLE 
	        (
	            MAIL_GUID NVARCHAR(50),
	            MAIL_ID BIGINT,
	            MAIL_BATCHID BIGINT,
	            MAIL_FROMEMAIL VARCHAR(500),
	            MAIL_TOEMAIL VARCHAR(500),
	            REPLYTO NVARCHAR(100),
	            MAIL_SUBJECT VARCHAR(1000),
	            MAIL_TEMPLETEBODY TEXT,
	            MAIL_ATTECHEMENT VARCHAR(1000),
	            MAIL_TEMPLETENAME VARCHAR(1000),
	            MAIL_INSERTEDDATE DATETIME,
	            MAIL_USERID INT,
	            MAIL_SCHEDULEDATE DATETIME
	        )
	
	INSERT INTO @TEMPTABLE
	SELECT TOP(@TOPCOUNT) ER.MAIL_GUID,
	       ER.MAIL_ID,
	       ER.MAIL_BATCHID,
	       ER.MAIL_FROMEMAIL,
	       ER.MAIL_TOEMAIL,
	       ER.REPLYTO,
	       (
	           SELECT TOP 1 [Email_Subject]
	           FROM   BatchEmail_Infos
	           WHERE  BatchID = MAIL_BATCHID
	       )MAIL_SUBJECT,
	       ISNULL(MAIL_TEMPLETEBODY, MESSAGES)MAIL_TEMPLETEBODY,
	       ER.MAIL_ATTECHEMENT,
	       ER.MAIL_TEMPLETENAME,
	       ER.MAIL_INSERTEDDATE,
	       ER.MAIL_USERID,
	       ER.MAIL_SCHEDULEDATE
	FROM   MAIL_EMAILSREPORT ER(NOLOCK)
	WHERE  ISNULL(ER.MAIL_PRIORITY, 0) = 2
	       AND (
	               ER.MAIL_SCHEDULEDATE = ''
	               OR CONVERT(DATETIME, ER.MAIL_SCHEDULEDATE, 104) <= GETDATE()
	               OR ER.MAIL_SCHEDULEDATE IS NULL
	           )        
	
	SET @RESTCOUNTAFTERDIRECT = @@ROWCOUNT                                        
	
	IF (@RESTCOUNTAFTERDIRECT < @TOPCOUNT)
	BEGIN
	    INSERT INTO @TEMPTABLE
	    SELECT TOP(@TOPCOUNT -@RESTCOUNTAFTERDIRECT) ER.MAIL_GUID,
	           ER.MAIL_ID,
	           ER.MAIL_BATCHID,
	           ER.MAIL_FROMEMAIL,
	           ER.MAIL_TOEMAIL,
	           ER.REPLYTO,
	           (
	               SELECT TOP 1 [Email_Subject]
	               FROM   [BatchEmail_Infos]
	               WHERE  BatchID = MAIL_BATCHID
	           )MAIL_SUBJECT,
	           ISNULL(MAIL_TEMPLETEBODY, MESSAGES)MAIL_TEMPLETEBODY,
	           ER.MAIL_ATTECHEMENT,
	           ER.MAIL_TEMPLETENAME,
	           ER.MAIL_INSERTEDDATE,
	           ER.MAIL_USERID,
	           ER.MAIL_SCHEDULEDATE
	    FROM   MAIL_EMAILSREPORT ER(NOLOCK)
	    WHERE  ISNULL(ER.MAIL_PRIORITY, 0) = 1
	           AND (
	                   ER.MAIL_SCHEDULEDATE = ''
	                   OR CONVERT(DATETIME, ER.MAIL_SCHEDULEDATE, 104) <=
	                      GETDATE()
	                   OR ER.MAIL_SCHEDULEDATE IS NULL
	               )                  
	    
	    SET @RESTCOUNTAFTERPRIORITY = @@ROWCOUNT                                     
	    
	    IF (
	           (@RESTCOUNTAFTERDIRECT + @RESTCOUNTAFTERPRIORITY) < @TOPCOUNT
	       )
	    BEGIN
	        SET @TOPCOUNT = @TOPCOUNT -(@RESTCOUNTAFTERDIRECT + @RESTCOUNTAFTERPRIORITY)                
	        INSERT INTO @TEMPTABLE
	        SELECT TOP(@TOPCOUNT) ER.MAIL_GUID,
	               ER.MAIL_ID,
	               ER.MAIL_BATCHID,
	               ER.MAIL_FROMEMAIL,
	               ER.MAIL_TOEMAIL,
	               ER.REPLYTO,
	               (
	                   SELECT TOP 1 [Email_Subject]
	                   FROM   [BatchEmail_Infos]
	                   WHERE  BatchID = MAIL_BATCHID
	               )MAIL_SUBJECT,
	               ISNULL(MAIL_TEMPLETEBODY, MESSAGES)MAIL_TEMPLETEBODY,
	               ER.MAIL_ATTECHEMENT,
	               ER.MAIL_TEMPLETENAME,
	               ER.MAIL_INSERTEDDATE,
	               ER.MAIL_USERID,
	               ER.MAIL_SCHEDULEDATE
	        FROM   MAIL_EMAILSREPORT ER(NOLOCK)
	        WHERE  ISNULL(ER.MAIL_PRIORITY, 0) = 0
	               AND (
	                       ER.MAIL_SCHEDULEDATE = ''
	                       OR CONVERT(DATETIME, ER.MAIL_SCHEDULEDATE, 104) <=
	                          GETDATE()
	                       OR ER.MAIL_SCHEDULEDATE IS NULL
	                   )
	    END
	END 
	--DELETE FROM MAIL_EMAILSREPORT BY MAIL_ID                      
	DELETE MAIL_EMAILSREPORT
	FROM   MAIL_EMAILSREPORT ER
	       JOIN @TEMPTABLE TT
	            ON  ER.MAIL_ID = TT.MAIL_ID 
	
	--GET RECORDS FROM TEMPTABLE                                            
	SELECT Mail_GUID,
	       MAIL_ID,
	       ISNULL(MAIL_BATCHID, 0) AS MAIL_BATCHID,
	       MAIL_FROMEMAIL,
	       MAIL_TOEMAIL,
	       ReplyTo,
	       MAIL_SUBJECT,
	       MAIL_TEMPLETEBODY,
	       MAIL_ATTECHEMENT,
	       MAIL_TEMPLETENAME,
	       MAIL_INSERTEDDATE,
	       MAIL_USERID,
	       ISNULL(MAIL_SCHEDULEDATE, GETDATE()) AS MAIL_SCHEDULEDATE
	FROM   @TEMPTABLE
END 



GO

