   Procedure: [dbo].[USP_GetEmailsRecord_Api]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON



/* This procedure is used in SendEmailApi_CRM Window service to send the emails to various recipient that is 
stroed in the Mail_EmailsApi table and  which priority is equal to 0(Zero). This procedure also insert the details in 
 mail_current_emailsreportsent table when emails is sent from the Mail_EamilsApi Table.  */
 
CREATE   PROC [dbo].[USP_GetEmailsRecord_Api]
AS
BEGIN                          
select Mail_ID,Mail_FromEmail, Mail_ToEmail, Mail_Attechement,Mail_TempleteName,Messages,
   Mail_InsertedDate,'1'  as Mail_delivered,'0' as Mail_Invalid ,Mail_UserID, GETDATE()
    as Mail_DeliveredDate,Mail_Subject,Mail_ScheduleDate, Mail_BatchID  into #temp from
     Mail_EmailsApi where Mail_IsSent=0
     
     select  Mail_FromEmail,Mail_ToEmail,Mail_Subject,Messages,Mail_Attechement from #temp
insert into mail_current_emailsreportsent select Mail_ID,Mail_FromEmail, Mail_ToEmail, Mail_Attechement,Mail_TempleteName,
   Mail_InsertedDate,Mail_delivered,Mail_Invalid ,Mail_UserID,Mail_DeliveredDate,Mail_Subject,Mail_ScheduleDate, Mail_BatchID from  #temp
   
update Mail_EmailsApi set Mail_IsSent=1 where mail_id in(select mail_id from #temp)
drop table #temp
END



