/* ============================================================
   Procedure: [dbo].[USP_GETEMAILSRECORD_FORFILTERATION_NEW]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[USP_GETEMAILSRECORD_FORFILTERATION_NEW] -- 5
	@TOPCOUNT INT = 500
AS
BEGIN
	DECLARE @TOTAL NVARCHAR(200)                                
	
	DECLARE @MAIL_BATCHID NVARCHAR(200)          
	
	SELECT TOP 1 @MAIL_BATCHID = BATCHID
	FROM   BATCHEMAIL_INFOS(NOLOCK)
	WHERE  IsProcess = 0
	ORDER BY
	       ID
	
	
	
	IF NOT EXISTS(
	       SELECT 'X'
	       FROM   EmailsFilter(NOLOCK)
	       WHERE  Mail_BatchID = @MAIL_BATCHID
	   )
	BEGIN
	    PRINT 1                           
	    
	    UPDATE [BATCHEMAIL_INFOS]
	    SET    IsProcess     = 1
	    WHERE  BATCHID       = @MAIL_BATCHID
	END
	
	
	
	DECLARE @TEMPTABLE TABLE 
	        
	        (
	            Mail_GUID NVARCHAR(50),
	            MAIL_ID INT,
	            MAIL_FROMEMAIL VARCHAR(500),
	            MAIL_TOEMAIL VARCHAR(500),
	            MAIL_SUBJECT VARCHAR(1000),
	            MAIL_TEMPLETEBODY TEXT,
	            MAIL_ATTECHEMENT VARCHAR(1000),
	            MAIL_TEMPLETENAME VARCHAR(1000),
	            [MESSAGES] TEXT,
	            MAIL_INSERTEDDATE DATETIME,
	            MAIL_USERID INT,
	            ReplyTo VARCHAR(100),
	            Mail_BatchID BIGINT,
	            Mail_Priority INT,
	            Mail_ScheduleDate DATETIME
	        ) 
	
	--INSERT INTO TEMPTABLE
	
	--DECLARE @MAIL_GUID nvarchar(50) ,@MAIL_SUBJECT NVARCHAR(250),@MAIL_TEMPLETEBODY NVARCHAR(max)  
	
	
	
	DECLARE @MAIL_GUID             NVARCHAR(50),
	        @MAIL_SUBJECT          NVARCHAR(250),
	        @Message               NVARCHAR(MAX),
	        @MAIL_TEMPLETEBODY     NVARCHAR(MAX) 
	
	
	
	--SELECT @MAIL_SUBJECT=[TemplateSubject],@MAIL_TEMPLETEBODY=[Template_Content] FROM [Kitever].[dbo].[Template_Mail_Detail] WHERE [TemplateMailId]=(SELECT TemplateID FROM dbo.BatchEmail_Infos WHERE BatchID=@MAIL_BATCHID)  
	
	
	
	SELECT @MAIL_SUBJECT = Email_Subject,
	       @Message     = [Message]
	FROM   [dbo].BatchEmail_Infos
	WHERE  BatchID      = @MAIL_BATCHID 
	
	
	
	--SELECT top 1 @MAIL_GUID=GUID from ClientEmails(nolock) where BatchID=@MAIL_BATCHID  
	
	
	
	INSERT INTO @TEMPTABLE
	SELECT TOP(@TOPCOUNT) CE.GUID     MAIL_GUID,
	       MAIL_ID,
	       MAIL_FROMEMAIL,
	       MAIL_TOEMAIL,
	       @MAIL_SUBJECT              MAIL_SUBJECT,
	       @MAIL_TEMPLETEBODY         MAIL_TEMPLETEBODY,
	       MAIL_ATTECHEMENT,
	       MAIL_TEMPLETENAME,
	       [MESSAGES],
	       MAIL_INSERTEDDATE,
	       MAIL_USERID,
	       EF.ReplyTo,
	       Mail_BatchID,
	       Mail_Priority,
	       Mail_ScheduleDate
	FROM   EmailsFilter EF(NOLOCK)
	       INNER JOIN dbo.ClientEmails CE(NOLOCK)
	            ON  EF.Mail_BatchID = CE.BatchID
	            AND EF.Mail_ToEmail = CE.Email_Id
	            AND ISNULL(EF.IsMonitor, 0) = 1 
	
	--WHERE  Mail_BatchID = @MAIL_BATCHID  
	
	
	
	
	
	--DELETE FROM EmailsFilter BY MAIL_ID                                          
	
	DELETE EmailsFilter
	FROM   EmailsFilter ER
	       JOIN @TEMPTABLE TT
	            ON  ER.MAIL_ID = TT.MAIL_ID 
	
	--GET RECORDS FROM TEMPTABLE                                          
	
	SELECT Mail_GUID,
	       MAIL_ID,
	       MAIL_FROMEMAIL,
	       MAIL_TOEMAIL,
	       MAIL_SUBJECT,
	       MAIL_TEMPLETENAME,
	       [MESSAGES],
	       MAIL_INSERTEDDATE,
	       MAIL_USERID,
	       ReplyTo,
	       Mail_BatchID,
	       Mail_Priority,
	       Mail_ScheduleDate,
	       MAIL_ATTECHEMENT,
	       MAIL_TEMPLETEBODY
	FROM   @TEMPTABLE
END 


GO

