         )                                                               
  
drop table if exists #insertedid                                 
create table #insertedid(mail_id bigint,mail_guid nvarchar(100))                              
RETRY:                                                                         
BEGIN TRY                                                                      
--BEGIN TRAN                                 
INSERT INTO @TEMPTABLE(MAIL_GUID,                                                              
        Mail_ID,                           
        MAIL_FROMEMAIL,                                                              
        MAIL_TOEMAIL,                                                              
        MAIL_SUBJECT,                           
        MAIL_TEMPLETEBODY,                                                          
        MAIL_ATTECHEMENT,                                                              
        MAIL_TEMPLETENAME,                      
        [MESSAGES],                                   
        MAIL_INSERTEDDATE,                                                              
        MAIL_USERID,                                                   
        ReplyTo,                                                              
        Mail_BatchID,                                                           
        Mail_Priority,                                                              
        Mail_ScheduleDate,smtpserver) output inserted.mail_id,inserted.mail_guid into #insertedid                           
select MAIL_GUID,                                                              
        Mail_ID,                           
        MAIL_FROMEMAIL,                                                              
        MAIL_TOEMAIL,                                                              
        MAIL_SUBJECT,                           
        MAIL_TEMPLETEBODY,                                                          
        MAIL_ATTECHEMENT,                                                              
        MAIL_TEMPLETENAME,                      
        [MESSAGES],                                   
        MAIL_INSERTEDDATE,                                                              
        MAIL_USERID,                                                   
        ReplyTo,                                                              
        Mail_BatchID,                                                           
        Mail_Priority,                                                              
        Mail_ScheduleDate,smtpserver                                                             
        from   
 (SELECT TOP(@TOPCOUNT) MAIL_GUID,                                                              
 MAIL_ID,                                                              
        MAIL_FROMEMAIL,                                                              
        MAIL_TOEMAIL,                                                              
        EF.MAIL_SUBJECT,                                                    
        MAIL_TEMPLETEBODY,                                                          
        MAIL_ATTECHEMENT,                                                              
        MAIL_TEMPLETENAME,                                                            
        EF.[MESSAGES],                                   
        MAIL_INSERTEDDATE,                                                              
        MAIL_USERID,                                                   
        EF.ReplyTo,                                                              
   Mail_BatchID,                                                           
Mail_Priority,                                                              
        Mail_ScheduleDate,    
  '' as smtpserver                                
  FROM   EmailsFilter EF  (nolock)       
  join BatchEmail_Infos(nolock) b on b.BatchID=ef.Mail_BatchID                           
  left JOIN dbo.CustomerEmail CE   (nolock)                                         
  ON  EF.Mail_ToEmail = CE.Email    
  where    
        EF.MAIL_USERID <> 34594 and
          
  --dbo.fn_isemailunsubscribed(EF.mail_userid,EF.Mail_ToEmail)=0  
  --and  
  1=case when @mod is null then 1 when ef.mail_id%6=@mod then 1 else 0 end    
 and EF.Mail_Priority=@Mail_Priority    
  order by case  when b.UserID=335 then 100  
  when b.totalrecords<10  then -2   
  --when b.UserID=17977 then -1  
   when  ce.id is not null then 0  
 else cast(b.TotalProcessed/cast(b.TotalRecords as float) as numeric(18,4))*100  end asc     
 --else isnull(b.scheduleddate,b.batchinserttime) end asc    
 ) A                
  
  
drop table if exists #mail_ids  
create table #mail_ids(id bigint,batchid bigint,mail_guid nvarchar(100))  
insert into Unsubscribedmails(mail_id,batchid,datesent,mail_guid,email_id) output inserted.mail_id as id,inserted.batchid as batchid,  
inserted.mail_guid as mail_guid into #mail_ids  
select mail_id,mail_batchid,mail_inserteddate,mail_guid,Mail_ToEmail from @TEMPTABLE ef where   
  dbo.fn_isemailunsubscribed(EF.mail_userid,EF.Mail_ToEmail)=1  
update c set status='Unsubscribed' from  clientemails c join #mail_ids m on cast(c.guid as nvarchar(100))=m.mail_guid and c.BatchID=m.batchid  
     
DELETE ER                                                              
FROM   EmailsFilter ER                                                   
        JOIN #insertedid TT ON  ER.MAIL_GUID = TT.MAIL_GUID    
                          
  
                              
--COMMIT                                                                      
END TRY                                                                      
BEGIN CATCH                                                                                                                          
--IF @@TRANCOUNT>0                                                                      
--ROLLBACK                                                                      
EXECUTE USP_INSERTERRORINFO;                              
IF ERROR_NUMBER() = 1205 -- Deadlock Error Number                                
BEGIN                                
WAITFOR DELAY '00:00:00.05' -- Wait for 5 ms                                
GOTO RETRY -- Go to Label RETRY                                
END                                                                           
END CATCH                                 
          
;with cte as (select ROW_NUMBER() over (PARTITION by mail_guid order by (select 0)) RN,Mail_GUID,          
 MAIL_ID,                                                        
        MAIL_FROMEMAIL,                                                        
        MAIL_TOEMAIL,                                                        
        MAIL_SUBJECT,                                                        
        MAIL_TEMPLETENAME,          
        messages,                                                    
        --cast ([MESSAGES] as nvarchar(max)) [MESSAGES],                               
        MAIL_INSERTEDDATE,                                                        
        MAIL_USERID,                                                        
        ReplyTo,                                                        
        Mail_BatchID,                                                  
        Mail_Priority,                                                        
        Mail_ScheduleDate,                                          
         MAIL_ATTECHEMENT,                                                        
        MAIL_TEMPLETEBODY,    
  '' as smtpserver          
       FROM   @TEMPTABLE t)          
 select * into #t from cte where RN=1          
           
 select Mail_GUID,          
 MAIL_ID,                                                        
        MAIL_FROMEMAIL,                                                        
        MAIL_TOEMAIL,                         
        MAIL_SUBJECT,                                                        
        MAIL_TEMPLETENAME,          
        [messages],                                                    
        --cast ([MESSAGES] as nvarchar(max)) [MESSAGES],                               
        MAIL_INSERTEDDATE,                                                        
        MAIL_USERID,                                                        
        ReplyTo,                                                        
        Mail_BatchID,                                                  
        Mail_Priority,                                                        
        Mail_ScheduleDate,                                          
        MAIL_ATTECHEMENT,                                                        
        MAIL_TEMPLETEBODY,smtpserver from #t    
  
  
  
update b set totalprocessed = isnull(totalprocessed,0) + isnull(Coun,0) from   
(select * from BatchEmail_Infos(nolock) where batchid in (select mail_batchid from @TEMPTABLE)) b                            
 join   
 (select mail_batchid,count(mail_batchid)coun from @TEMPTABLE group by mail_batchid)   
 tt on tt.Mail_BatchID=b.BatchID                             
  
   
 update b set isprocess=1,BatchProcessTime=GETDATE() from   
 (select * from BatchEmail_Infos(nolock) where batchid in (select mail_batchid from @TEMPTABLE)) b                            
 where not exists(select 1 from emailsfilter(nolock) where mail_batchid=b.BatchID)  
 and totalprocessed>=totalrecords  
   
 insert into emailcountracking(batchid,tablename,mailcount,createdon)  
 select batchid,'Unsubscribedmails',count(1),getdate() from #mail_ids group by batchid  
    
drop table if exists #t     
drop table if exists #mail_ids  
end  
end try    
begin catch    
exec usp_inserterrorinfo    
end catch    
    
END 


