  SELECT TOP (@TOPCOUNT) ER.MAIL_GUID,ER.MAIL_ID,ER.MAIL_BATCHID,ER.MAIL_FROMEMAIL,ER.MAIL_TOEMAIL,ER.REPLYTO,Case when c.Mail_Subject IS not null and c.mail_subject<>'' then c.Mail_Subject when isnull(c.templateid,0)<>0 then umt.mailsubject else ER.MAIL_SUBJECT end as MAIL_SUBJECT,                        
  case when c.messages IS not null and c.messages<>'' then c.Messages when isnull(c.templateid,0)<>0 then umt.MailContent else ISNULL(MAIL_TEMPLETEBODY,ER.MESSAGES) end as MAIL_TEMPLETEBODY,  
  ER.MAIL_ATTECHEMENT,ER.MAIL_TEMPLETENAME,      
  ER.MAIL_INSERTEDDATE,ER.MAIL_USERID,ER.MAIL_SCHEDULEDATE                         
  FROM MAIL_EMAILSREPORT2 ER(NOLOCK) left join campaignmessages c on er.mail_batchid=c.batchid  
  left join usermailtemplate umt on c.templateid=umt.id 
 WHERE ISNULL(ER.MAIL_PRIORITY,0)=2                      
 -- AND (ER.MAIL_SCHEDULEDATE='' OR CONVERT(DATETIME ,ER.MAIL_SCHEDULEDATE,104)<=GETDATE() OR ER.MAIL_SCHEDULEDATE IS NULL)                      
                      
  SET @RESTCOUNTAFTERDIRECT =@@ROWCOUNT                                                      
                  
  IF (@RESTCOUNTAFTERDIRECT< @TOPCOUNT)                                                      
  BEGIN                                         
    INSERT INTO @TEMPTABLE                                 
    SELECT TOP (@TOPCOUNT-@RESTCOUNTAFTERDIRECT) ER.MAIL_GUID,ER.MAIL_ID,ER.MAIL_BATCHID,ER.MAIL_FROMEMAIL,ER.MAIL_TOEMAIL,ER.REPLYTO,                      
    Case when c.Mail_Subject IS not null and c.mail_subject<>'' then c.Mail_Subject when isnull(c.templateid,0)<>0 then umt.mailsubject else ER.MAIL_SUBJECT end as MAIL_SUBJECT,                        
  case when c.messages IS not null and c.messages<>'' then c.Messages when isnull(c.templateid,0)<>0 then umt.MailContent else ISNULL(MAIL_TEMPLETEBODY,ER.MESSAGES) end as MAIL_TEMPLETEBODY,  
  ER.MAIL_ATTECHEMENT,ER.MAIL_TEMPLETENAME,      
  ER.MAIL_INSERTEDDATE,ER.MAIL_USERID,ER.MAIL_SCHEDULEDATE                         
  FROM MAIL_EMAILSREPORT2 ER(NOLOCK) left join campaignmessages c on er.mail_batchid=c.batchid  
  left join usermailtemplate umt on c.templateid=umt.id 
WHERE ISNULL(ER.MAIL_PRIORITY,0)=1                      
--    AND (ER.MAIL_SCHEDULEDATE='' OR CONVERT(DATETIME ,ER.MAIL_SCHEDULEDATE,104)<=GETDATE() OR ER.MAIL_SCHEDULEDATE IS NULL)                                
                    
    SET @RESTCOUNTAFTERPRIORITY =@@ROWCOUNT                                                   
                 
    IF ((@RESTCOUNTAFTERDIRECT +@RESTCOUNTAFTERPRIORITY)< @TOPCOUNT)                                                     
  BEGIN                                                  
    SET @TOPCOUNT = @TOPCOUNT-(@RESTCOUNTAFTERDIRECT +@RESTCOUNTAFTERPRIORITY)                              
    INSERT INTO @TEMPTABLE  SELECT TOP (@TOPCOUNT) ER.MAIL_GUID,ER.MAIL_ID,ER.MAIL_BATCHID,ER.MAIL_FROMEMAIL,ER.MAIL_TOEMAIL,                
    ER.REPLYTO,Case when c.Mail_Subject IS not null and c.mail_subject<>'' then c.Mail_Subject when isnull(c.templateid,0)<>0 then umt.mailsubject else ER.MAIL_SUBJECT end as MAIL_SUBJECT,                        
  case when c.messages IS not null and c.messages<>'' then c.Messages when isnull(c.templateid,0)<>0 then umt.MailContent else ISNULL(MAIL_TEMPLETEBODY,ER.MESSAGES) end as MAIL_TEMPLETEBODY,  
  ER.MAIL_ATTECHEMENT,ER.MAIL_TEMPLETENAME,      
  ER.MAIL_INSERTEDDATE,ER.MAIL_USERID,ER.MAIL_SCHEDULEDATE                         
  FROM MAIL_EMAILSREPORT2 ER(NOLOCK) left join campaignmessages c on er.mail_batchid=c.batchid  
  left join usermailtemplate umt on c.templateid=umt.id 
 WHERE ISNULL(ER.MAIL_PRIORITY,0)=0                       
 --   AND (ER.MAIL_SCHEDULEDATE='' OR CONVERT(DATETIME,ER.MAIL_SCHEDULEDATE,104)<=GETDATE() OR ER.MAIL_SCHEDULEDATE IS NULL)                                
  END                      
   END                 
   --DELETE FROM MAIL_EMAILSREPORT BY MAIL_ID                                    
   DELETE MAIL_EMAILSREPORT2 FROM MAIL_EMAILSREPORT2 ER JOIN @TEMPTABLE TT ON ER.MAIL_ID=TT.MAIL_ID                                       
                      
   --GET RECORDS FROM TEMPTABLE                                                          
   SELECT Mail_GUID,MAIL_ID, ISNULL(MAIL_BATCHID,0) AS MAIL_BATCHID, MAIL_FROMEMAIL,MAIL_TOEMAIL,ReplyTo ,MAIL_SUBJECT,MAIL_TEMPLETEBODY, MAIL_ATTECHEMENT,MAIL_TEMPLETENAME,MAIL_INSERTEDDATE,MAIL_USERID,        
   ISNULL(MAIL_SCHEDULEDATE,GETDATE()) AS MAIL_SCHEDULEDATE FROM @TEMPTABLE                          
END 


GO

/* ============================================================
   Procedure: [dbo].[Usp_getEmailsRecords]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.Usp_getEmailsRecords --2, '',1         
(        
  @TOPCOUNT INT=50,                                                                  
  @SMTPSERVER VARCHAR(50)='',                                   
  @div int         
)        
as          
Begin          
           
     select top 2 EF.Mail_UserID, EF.Mail_ID,
	  (select value from dbo.fn_split(EF.MAIL_FROMEMAIL,'@') where position=1)  as MAIL_FROMName
	 , EF.Mail_FromEmail , EF.Mail_ToEmail, EF.ReplyTo, EF.Mail_Subject, BMInfo.Message, EF.Mail_BatchID        
       ,EF.Mail_Priority, BMInfo.ispersonalized, BMInfo.IsProcess  from EmailsFilter as EF with(nolock)        
               
   join BatchEmail_Infos as BMInfo with(nolock)        
      on EF.Mail_BatchID = BMInfo.BatchID        
      order by  EF.Mail_ID desc             
        
End          


GO

/* ============================================================
   Procedure: [dbo].[Usp_getEmailsRecords_KarixAPI]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.Usp_getEmailsRecords_KarixAPI --2,'',9                   
(                    
  @TOPCOUNT INT= 50,                                                                              
  @SMTPSERVER VARCHAR(50)='',                                               
  @div int                     
)                    
as                      
Begin            
          
          
      set @TOPCOUNT = 5          
      /*                   
       select top 3 EF.Mail_UserID, EF.Mail_ID, EF.Mail_FromEmail , EF.Mail_ToEmail, EF.ReplyTo, EF.Mail_Subject, BMInfo.Message, EF.Mail_BatchID                    
          ,EF.Mail_Priority, BMInfo.ispersonalized, BMInfo.IsProcess from EmailsFilter as EF with(nolock)                    
          join BatchEmail_Infos as BMInfo with(nolock)                    
          on EF.Mail_BatchID = BMInfo.BatchID                    
          order by  EF.Mail_ID desc                         
      */              
              
    DECLARE @RESTCOUNTAFTERDIRECT INT                                                                                 
    DECLARE @RESTCOUNTAFTERPRIORITY  INT                                                                              
                                                  
    DECLARE @TEMPTABLE TABLE                                                                                      
    (                                                       
    MAIL_GUID NVARCHAR(50),                                                    
    MAIL_ID BIGINT,                                                                                      
    MAIL_BATCHID BIGINT,                                                                 
    MAIL_FROMName nvarchar(500),            
    MAIL_FROMEMAIL NVARCHAR(500),                                                                                      
    MAIL_TOEMAIL NVARCHAR(500),                                                        
    REPLYTO NVARCHAR(500),                                                                                   
    MAIL_SUBJECT NVARCHAR(1000),                                                                                    
    [Message] nvarchar(max),              
    --Mail_Priority int ,              
    IsPersonalized int ,              
    --MAIL_TEMPLETEBODY NTEXT,                                                                                      
    --MAIL_ATTECHEMENT VARCHAR(1000),                                                                                      
    --MAIL_TEMPLETENAME VARCHAR(1000),                                                                                      
    MAIL_INSERTEDDATE NVARCHAR(50),                                                                                      
    MAIL_USERID BIGINT,                                                                    
    MAIL_SCHEDULEDATE NVARCHAR(50)                      
    --smtpserver nvarchar(20)                                                                     
    )                     
              
  RETRY0:                    
  begin try                    
  begin transaction                                                                       
  INSERT INTO @TEMPTABLE                                                             
  select * from                       
     (              
    SELECT TOP (@TOPCOUNT) ER.Mail_GUID ,ER.MAIL_ID,ER.MAIL_BATCHID,            
            
      (select value from dbo.fn_split(ER.MAIL_FROMEMAIL,'@') where position=1)  as MAIL_FROMName            
              
     ,ER.MAIL_FROMEMAIL,ER.MAIL_TOEMAIL,ER.REPLYTO,          
  Case          
      when c.Mail_Subject IS not null and c.mail_subject<>'' and BMInfo.IsPersonalized = 0          
       then c.Mail_Subject           
      when isnull(c.templateid,0)<>0 and BMInfo.IsPersonalized = 0  then umt.mailsubject         
   else                      
        ER.MAIL_SUBJECT           
     end          
  as MAIL_SUBJECT,                           
      case          
      when c.messages IS not null and c.messages<>'' and BMInfo.IsPersonalized = 0                  
           then c.Messages           
   when isnull(c.templateid,0)<>0 and BMInfo.IsPersonalized = 0  and umt.MailContent is not null and umt.MailContent <> ''            
     then umt.MailContent                   
         when BMInfo.IsPersonalized = 1          
then ER.MESSAGES          
   else          
      ER.MESSAGES          
     --ISNULL(MAIL_TEMPLETEBODY,ER.MESSAGES)           
     end           
     as [Message],              
              
    BMInfo.IsPersonalized,              
       ER.MAIL_INSERTEDDATE,ER.MAIL_USERID,ER.MAIL_SCHEDULEDATE                                                     
    FROM                       
      -- MAIL_EMAILSREPORT2 ER with (nolock)                       
    EmailsFilter as ER with(nolock)                    
     join BatchEmail_Infos as BMInfo with(nolock)                    
     on ER.Mail_BatchID = BMInfo.BatchID  and ER.Mail_UserID = BMInfo.UserID      
        
 left join [mysms].dbo.campaignmessages c with (nolock) on er.mail_batchid=c.batchid                      
    left join [mysms].dbo.usermailtemplate umt with (nolock) on c.templateid=umt.id                             
 WHERE  ER.Mail_UserID = 34594       
       and                
 --ISNULL(ER.MAIL_PRIORITY,0)=2  and              
    isnull(ER.IsProcess, 0) = 0         
     -- and  (ER.MAIL_BATCHID % 10) = @div      
       
     --and BMInfo.IsPersonalized = 1                          
     order by ER.MAIL_BATCHID , ER.Mail_ID asc              
  --order by case when mail_batchid=119524978 then -1 when mail_userid<>335 then 0 else mail_id               
     -- end                                               
 ) A                    
               
 /*              
               
  SET @RESTCOUNTAFTERDIRECT =@@ROWCOUNT                                                                                  
  IF (@RESTCOUNTAFTERDIRECT< @TOPCOUNT)                                                                                  
  BEGIN                                                                     
    INSERT INTO @TEMPTABLE                                                             
 Select * from                       
  (              
  SELECT TOP (@TOPCOUNT-@RESTCOUNTAFTERDIRECT) ER.MAIL_ID,ER.MAIL_BATCHID,            
   (select value from dbo.fn_split(ER.MAIL_FROMEMAIL,'@') where position=1)  as MAIL_FROMName            
   ,            
  ER.MAIL_FROMEMAIL,ER.MAIL_TOEMAIL,ER.REPLYTO              
  ,Case when c.Mail_Subject IS not null and c.mail_subject<>'' then c.Mail_Subject              
   when isnull(c.templateid,0)<>0 then umt.mailsubject else                      
         ER.MAIL_SUBJECT end as MAIL_SUBJECT,                                                    
        case when c.messages IS not null and c.messages<>''                   
         then c.Messages when isnull(c.templateid,0)<>0 then umt.MailContent                   
        else ISNULL(MAIL_TEMPLETEBODY,ER.MESSAGES) end as [Message],              
         BMInfo.IsPersonalized,              
         ER.MAIL_INSERTEDDATE,ER.MAIL_USERID,ER.MAIL_SCHEDULEDATE                                                     
    FROM                       
      -- MAIL_EMAILSREPORT2 ER with (nolock)                       
    EmailsFilter as ER with(nolock)                    
     join BatchEmail_Infos as BMInfo with(nolock)                    
     on ER.Mail_BatchID = BMInfo.BatchID                    
 left join [mysms].dbo.campaignmessages c with (nolock) on er.mail_batchid=c.batchid                              
    left join [mysms].dbo.usermailtemplate umt with (nolock) on c.templateid=umt.id                             
 WHERE ISNULL(ER.MAIL_PRIORITY,0)=1 and isnull(ER.IsProcess, 0) = 0  and  (ER.MAIL_BATCHID % 10) = @div                            
     order by ER.MAIL_BATCHID asc              
   ) A                    
 end          
                    
SET @RESTCOUNTAFTERPRIORITY =@@ROWCOUNT                                                                               
IF ((@RESTCOUNTAFTERDIRECT +@RESTCOUNTAFTERPRIORITY)< @TOPCOUNT)                    
BEGIN                                                                     
    INSERT INTO @TEMPTABLE                                                             
 Select * from                       
 (               
   SELECT TOP (@TOPCOUNT-@RESTCOUNTAFTERDIRECT) ER.MAIL_ID,ER.MAIL_BATCHID,            
    (select value from dbo.fn_split(ER.MAIL_FROMEMAIL,'@') where position=1)  as MAIL_FROMName,            
   ER.MAIL_FROMEMAIL,ER.MAIL_TOEMAIL              
      ,ER.REPLYTO              
  ,Case when c.Mail_Subject IS not null and c.mail_subject<>'' then c.Mail_Subject              
   when isnull(c.templateid,0)<>0 then umt.mailsubject else                      
         ER.MAIL_SUBJECT end as MAIL_SUBJECT,                                                    
        case when c.messages IS not null and c.messages<>''                   
         then c.Messages when isnull(c.templateid,0)<>0 then umt.MailContent                   
        else ISNULL(MAIL_TEMPLETEBODY,ER.MESSAGES) end as [Message],              
         BMInfo.IsPersonalized,              
         ER.MAIL_INSERTEDDATE,ER.MAIL_USERID,ER.MAIL_SCHEDULEDATE                                                     
    FROM                       
      -- MAIL_EMAILSREPORT2 ER with (nolock)                       
    EmailsFilter as ER with(nolock)                    
     join BatchEmail_Infos as BMInfo with(nolock)                    
     on ER.Mail_BatchID = BMInfo.BatchID                    
 left join [mysms].dbo.campaignmessages c with (nolock) on er.mail_batchid=c.batchid                              
    left join [mysms].dbo.usermailtemplate umt with (nolock) on c.templateid=umt.id                             
 WHERE ISNULL(ER.MAIL_PRIORITY,0)= 0  and isnull(ER.IsProcess, 0) = 0 and  (ER.MAIL_BATCHID % 10) = @div                            
     order by ER.MAIL_BATCHID asc              
 ) A                    
end                    
  */              
              
    update EF set EF.IsProcess = 2 from EmailsFilter as EF with (nolock)              
       JOIN @TEMPTABLE TT ON EF.MAIL_ID=TT.MAIL_ID  where EF.Mail_UserID = 34594                 
             
                                                                            
                    
commit                    
end try                    
BEGIN CATCH                                                           
IF @@TRANCOUNT>0                                                          
ROLLBACK                                                                                                         
EXECUTE USP_INSERTERRORINFO;                                                                                 
IF ERROR_NUMBER() = 1205 -- Deadlock Error Number                                                                      
BEGIN                                                                                            
WAITFOR DELAY '00:00:00.05' -- Wait for 5 ms                                                                                     
GOTO RETRY0 -- Go to Label RETRY                                                                                            
END                                                                                                                         
END CATCH               
              
   SELECT *                    
   FROM @TEMPTABLE t  order by t.MAIL_BATCHID asc              
              
              
End 


GO

/* ============================================================
   Procedure: [dbo].[Usp_getEmailsRecords_KarixAPI_WithBatchIDAndGUICombined]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[Usp_getEmailsRecords_KarixAPI_WithBatchIDAndGUICombined] --2,'',9                     
(                      
  @TOPCOUNT INT= 50,                                                                                
  @SMTPSERVER VARCHAR(50)='',                                                 
  @div int                       
)                      
as                        
Begin              
            
      set @TOPCOUNT = 5            
      /*                     
       select top 3 EF.Mail_UserID, EF.Mail_ID, EF.Mail_FromEmail , EF.Mail_ToEmail, EF.ReplyTo, EF.Mail_Subject, BMInfo.Message, EF.Mail_BatchID                      
          ,EF.Mail_Priority, BMInfo.ispersonalized, BMInfo.IsProcess from EmailsFilter as EF with(nolock)                      
          join BatchEmail_Infos as BMInfo with(nolock)                      
          on EF.Mail_BatchID = BMInfo.BatchID                      
          order by  EF.Mail_ID desc                           
      */                
                
    DECLARE @RESTCOUNTAFTERDIRECT INT                                                                                   
    DECLARE @RESTCOUNTAFTERPRIORITY  INT                                                                                
                                                    
    DECLARE @TEMPTABLE TABLE                                                                                        
    (                                                         
    MAIL_GUID NVARCHAR(50),                                                      
    MAIL_ID BIGINT,                                                                                        
    --MAIL_BATCHID BIGINT,  
    MAIL_BATCHID nvarchar(500),  
    MAIL_FROMName nvarchar(500),              
    MAIL_FROMEMAIL NVARCHAR(500),                                                                                        
    MAIL_TOEMAIL NVARCHAR(500),                                                          
    REPLYTO NVARCHAR(500),                                                                                     
    MAIL_SUBJECT NVARCHAR(1000),                                                                                      
    [Message] nvarchar(max),                
    --Mail_Priority int ,                
    IsPersonalized int ,                
    --MAIL_TEMPLETEBODY NTEXT,                                                                                        
    --MAIL_ATTECHEMENT VARCHAR(1000),                                                                                        
    --MAIL_TEMPLETENAME VARCHAR(1000),                                                                                        
    MAIL_INSERTEDDATE NVARCHAR(50),                                                                                        
    MAIL_USERID BIGINT,                                                                      
    MAIL_SCHEDULEDATE NVARCHAR(50),                        
    --smtpserver nvarchar(20)                                                                       
    MAIL_BATCHIDOnly BIGINT
	)                       
                
  RETRY0:                      
  begin try                      
  begin transaction     
    
  drop table if exists #insertedid                                   
  create table #insertedid(mail_id bigint,mail_guid nvarchar(100))  
      
  INSERT INTO @TEMPTABLE  
   --output inserted.mail_id,inserted.mail_guid into #insertedid    
  select * from                         
    (                
    SELECT TOP (@TOPCOUNT) ER.Mail_GUID ,ER.MAIL_ID,  
   case when BMInfo.IsPersonalized = 1  
              then  cast(ER.Mail_GUID as nvarchar) + '~' + cast (isnull(ER.MAIL_BATCHID,0) as nvarchar)   
    else cast (ER.MAIL_BATCHID as nvarchar)   
             end   
            as MAIL_BATCHID,              
             
      (select value from dbo.fn_split(ER.MAIL_FROMEMAIL,'@') where position=1)  as MAIL_FROMName              
                
     ,ER.MAIL_FROMEMAIL,ER.MAIL_TOEMAIL,ER.REPLYTO,            
  Case            
      when c.Mail_Subject IS not null and c.mail_subject<>'' and BMInfo.IsPersonalized = 0            
       then c.Mail_Subject             
      when isnull(c.templateid,0)<>0 and BMInfo.IsPersonalized = 0  then umt.mailsubject           
   else                        
        ER.MAIL_SUBJECT             
     end            
  as MAIL_SUBJECT,                             
      case            
      when c.messages IS not null and c.messages<>'' and BMInfo.IsPersonalized = 0                    
           then c.Messages             
   when isnull(c.templateid,0)<>0 and BMInfo.IsPersonalized = 0  and umt.MailContent is not null and umt.MailContent <> ''              
     then umt.MailContent                     
         when BMInfo.IsPersonalized = 1            
then ER.MESSAGES            
   else            
      ER.MESSAGES            
     --ISNULL(MAIL_TEMPLETEBODY,ER.MESSAGES)             
     end             
     as [Message],                
                
    BMInfo.IsPersonalized,                
       ER.MAIL_INSERTEDDATE,ER.MAIL_USERID,ER.MAIL_SCHEDULEDATE ,ER.MAIL_BATCHID as MAIL_BATCHIDOnly                                                       
    FROM                         
      -- MAIL_EMAILSREPORT2 ER with (nolock)                         
    EmailsFilter as ER with(nolock)                      
     join BatchEmail_Infos as BMInfo with(nolock)                      
     on ER.Mail_BatchID = BMInfo.BatchID  and ER.Mail_UserID = BMInfo.UserID        
          
   left join [mysms].dbo.campaignmessages c with (nolock) on er.mail_batchid=c.batchid                        
    left join [mysms].dbo.usermailtemplate umt with (nolock) on c.templateid=umt.id                               
   WHERE  ER.Mail_UserID = 34594         
     and                  
    --ISNULL(ER.MAIL_PRIORITY,0)=2  and                
     isnull(ER.IsProcess, 0) = 0           
     -- and  (ER.MAIL_BATCHID % 10) = @div        
         
     --and BMInfo.IsPersonalized = 1                            
   --  order by ER.MAIL_BATCHID , ER.Mail_ID asc     
    order by case  when BMInfo.UserID=335 then 100  
     when BMInfo.totalrecords<10  then -2   
     --when b.UserID=17977 then -1  
     -- when  ce.id is not null then 0  
     else cast(BMInfo.TotalProcessed/cast(BMInfo.TotalRecords as float) as numeric(18,4))*100  end asc 

     --order by case when mail_batchid=119524978 then -1 when mail_userid<>335 then 0 else mail_id                 
     -- end                                                 
 ) A                      
        
     
   drop table if exists #mail_ids    
create table #mail_ids(id bigint,batchid bigint,mail_guid nvarchar(100))    
insert into Unsubscribedmails(mail_id,batchid,datesent,mail_guid,email_id) output inserted.mail_id as id,inserted.batchid as batchid,    
inserted.mail_guid as mail_guid into #mail_ids    
select mail_id,
                mail_batchidOnly  
    
  ,mail_inserteddate,mail_guid,Mail_ToEmail from @TEMPTABLE ef where     
  dbo.fn_isemailunsubscribed(EF.mail_userid,EF.Mail_ToEmail)=1  
    
   update c set status='Unsubscribed' from  clientemails c join #mail_ids m on cast(c.guid as nvarchar(100))=m.mail_guid and c.BatchID=m.batchid    
             
   update EF set EF.IsProcess = 2 from EmailsFilter as EF with (nolock)                
       JOIN @TEMPTABLE TT ON EF.MAIL_ID=TT.MAIL_ID  where EF.Mail_UserID = 34594                   
         
      
      ;with cte as (select ROW_NUMBER() over (PARTITION by mail_guid order by (select 0)) RN,Mail_GUID,            
       MAIL_ID,                                                          
        MAIL_FROMEMAIL,                                                          
        MAIL_TOEMAIL,                                                          
        MAIL_SUBJECT,                                                          
       -- MAIL_TEMPLETENAME,            
        [Message],                                                      
        --cast ([MESSAGES] as nvarchar(max)) [MESSAGES],            
        MAIL_INSERTEDDATE,                                                          
        MAIL_USERID,                                                          
        ReplyTo,                                                          
        Mail_BatchID,                                                    
       -- Mail_Priority,                                                          
       -- Mail_ScheduleDate,                                            
       --  MAIL_ATTECHEMENT,                                                          
       -- MAIL_TEMPLETEBODY,      
       '' as smtpserver
	   ,MAIL_BATCHIDOnly 
       FROM   @TEMPTABLE t)            
 select * into #t from cte where RN=1            
   
   
  SELECT *                      
   FROM @TEMPTABLE t  
     where
      Mail_id in
         ( 
		   select MAIL_ID from #t      
         )
		 and
      Mail_GUID not in 
	      (
		    select MAIL_GUID from #mail_ids 
		  )         
      order by t.MAIL_BATCHID asc                
      

   --select
   --     Mail_GUID,            
   --     MAIL_ID,                                                          
   --     MAIL_FROMEMAIL,                                                          
   --     MAIL_TOEMAIL,                           
   --     MAIL_SUBJECT,                                                          
   --     [Message],                                                      
   --     MAIL_INSERTEDDATE,                                                          
   --     MAIL_USERID,                                                          
   --     ReplyTo,                                                          
   --     Mail_BatchID,                                                    
   --    smtpserver,
	  -- Mail_BatchIDOnly
	  -- from #t      
        
  
   update b set totalprocessed = isnull(totalprocessed,0) + isnull(Coun,0) from     
   (  
     select * from BatchEmail_Infos(nolock) where batchid in   
      (  
       select Mail_batchIDOnly  
       from @TEMPTABLE
	  )
   ) b                              
   join     
   (select MAIL_BATCHIDOnly  ,count(MAIL_BATCHIDOnly) coun from @TEMPTABLE group by MAIL_BATCHIDOnly)     
   tt on tt.MAIL_BATCHIDOnly=b.BatchID                               
    
     
   update b set isprocess=1,BatchProcessTime=GETDATE() from     
   (select * from BatchEmail_Infos(nolock) where batchid in  
    (  
      select MAIL_BATCHIDOnly from @TEMPTABLE  
    )  
     
   ) b                              
   where not exists(select 1 from emailsfilter(nolock) where mail_batchid=b.BatchID and IsProcess = 0)    
   and totalprocessed>=totalrecords    
     
   insert into emailcountracking(batchid,tablename,mailcount,createdon)    
   select batchid,'Unsubscribedmails',count(1),getdate() from #mail_ids group by batchid    
      
  drop table if exists #t       
  drop table if exists #mail_ids   
  
                                                                              
                      
commit                      
end try                      
BEGIN CATCH                                                             
IF @@TRANCOUNT>0                                                            
ROLLBACK                                                                                                           
EXECUTE USP_INSERTERRORINFO;                                                                                   
IF ERROR_NUMBER() = 1205 -- Deadlock Error Number                                                                        
BEGIN                                                                                              
WAITFOR DELAY '00:00:00.05' -- Wait for 5 ms                                                                                       
GOTO RETRY0 -- Go to Label RETRY                                                
END                                                                                                                           
END CATCH                 
                
                
End 


GO

/* ============================================================
   Procedure: [dbo].[Usp_getEmailsRecords_KarixAPI_WithBatchIDAndGUICombined_NoPersonalized]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[Usp_getEmailsRecords_KarixAPI_WithBatchIDAndGUICombined_NoPersonalized] --2,'',9                       
(                        
  @TOPCOUNT INT= 50,                                                                                  
  @SMTPSERVER VARCHAR(50)='',                                                   
  @div int                         
)                        
as                          
Begin                
set @TOPCOUNT = 1000              
    DECLARE @RESTCOUNTAFTERDIRECT INT                                                                                     
    DECLARE @RESTCOUNTAFTERPRIORITY  INT                                                                                  
    DEclare @BatchID bigint = 0                                                      
    DECLARE @TEMPTABLE TABLE                                                                                          
    (                                                           
    MAIL_GUID NVARCHAR(50),                                                        
    MAIL_ID BIGINT,                                                                                          
    --MAIL_BATCHID BIGINT,    
    MAIL_BATCHID nvarchar(500),    
    MAIL_FROMName nvarchar(500),                
