  --             dbo.fn_getNameFromMailID(ER.MAIL_FROMEMAIL)  
             end     
         
   )  as MAIL_FROMName,  
   (   
    Case              
       when t.Mail_Subject IS not null and t.mail_subject<>'' and t.IsPersonalized = 0              
       then t.Mail_Subject    
	   
	   when isnull(c.templateid,0)<>0 and t.IsPersonalized = 0 
	            and  c.Mail_Subject IS not null and c.mail_subject<>''
	   then c.Mail_Subject
             
	   when isnull(c.templateid,0)<>0 and t.IsPersonalized = 0 and umt.mailsubject IS not null and umt.mailsubject<>''
	   then umt.mailsubject
	   
	   
	   else                          
           t.MAIL_SUBJECT               
        
		
		end )              
