CREATE   PROCEDURE [dbo].[Usp_getEmailsRecords_KarixAPI_WithBatchIDAndGUICombined_NoPersonalized_temp1] --2,'',9                     
(                      
  @TOPCOUNT INT= 50,                                                                                
  @SMTPSERVER VARCHAR(50)='',                                                 
  @div int                       
)                      
as                        
Begin              
            
      set @TOPCOUNT = 50            
      /*                     
       select top 3 EF.Mail_UserID, EF.Mail_ID, EF.Mail_FromEmail , EF.Mail_ToEmail, EF.ReplyTo, EF.Mail_Subject, BMInfo.Message, EF.Mail_BatchID                      
          ,EF.Mail_Priority, BMInfo.ispersonalized, BMInfo.IsProcess from EmailsFilter as EF with(nolock)                      
          join BatchEmail_Infos as BMInfo with(nolock)                      
          on EF.Mail_BatchID = BMInfo.BatchID                      
          order by  EF.Mail_ID desc                           
      */                
                
    DECLARE @RESTCOUNTAFTERDIRECT INT                                                                                   
    DECLARE @RESTCOUNTAFTERPRIORITY  INT                                                                                
                                                    
    DECLARE @TEMPTABLE TABLE                                                                                        
    (                                                         
    MAIL_GUID NVARCHAR(50),                                                      
    MAIL_ID BIGINT,                                                                                        
    --MAIL_BATCHID BIGINT,  
    MAIL_BATCHID nvarchar(500),  
    MAIL_FROMName nvarchar(500),              
    MAIL_FROMEMAIL NVARCHAR(500),                                                                                        
    MAIL_TOEMAIL NVARCHAR(500),                                                          
    REPLYTO NVARCHAR(500),                                                                                     
    MAIL_SUBJECT NVARCHAR(1000),                                                                                      
    [Message] nvarchar(max),                
    --Mail_Priority int ,                
    IsPersonalized int ,                
    --MAIL_TEMPLETEBODY NTEXT,                                                                                        
    --MAIL_ATTECHEMENT VARCHAR(1000),                                                                                        
    --MAIL_TEMPLETENAME VARCHAR(1000),                                                                                        
    MAIL_INSERTEDDATE NVARCHAR(50),                                                                                        
    MAIL_USERID BIGINT,                                                                      
    MAIL_SCHEDULEDATE NVARCHAR(50),                        
    --smtpserver nvarchar(20)                                                                       
    MAIL_BATCHIDOnly BIGINT
	)                       
                
  RETRY0:                      
  begin try                      
  --begin transaction     
    
  drop table if exists #insertedid                                   
  create table #insertedid(mail_id bigint,mail_guid nvarchar(100))  
      
  INSERT INTO @TEMPTABLE  
   --output inserted.mail_id,inserted.mail_guid into #insertedid    
  select * from                         
    (                
    SELECT TOP (@TOPCOUNT) ER.Mail_GUID ,ER.MAIL_ID,  
   case when BMInfo.IsPersonalized = 1  
              then  cast(ER.Mail_GUID as nvarchar) + '~' + cast (isnull(ER.MAIL_BATCHID,0) as nvarchar)   
    else cast (ER.MAIL_BATCHID as nvarchar)   
             end   
            as MAIL_BATCHID,              
      /*
	  (
	     --select value from dbo.fn_split(ER.MAIL_FROMEMAIL,'@') where position=1
	    Select case
		         when isnull(frmMailID.[DisplayName], '') != ''
		          then frmMailID.[DisplayName]
				 when isnull(KarixMailID.[k_d_name] , '')  != ''
		          then KarixMailID.[k_d_name]
				 else
	               dbo.fn_getNameFromMailID(ER.MAIL_FROMEMAIL)
	             end   
	      
	  )  as MAIL_FROMName              
        */
     (select value from dbo.fn_split(ER.MAIL_FROMEMAIL,'@') where position=1) as MAIL_FROMName   		
     ,ER.MAIL_FROMEMAIL,ER.MAIL_TOEMAIL,ER.REPLYTO,            
   /*
  Case            
      when c.Mail_Subject IS not null and c.mail_subject<>'' and BMInfo.IsPersonalized = 0            
       then c.Mail_Subject             
      when isnull(c.templateid,0)<>0 and BMInfo.IsPersonalized = 0  then umt.mailsubject           
   else                        
        ER.MAIL_SUBJECT             
     end            
  as MAIL_SUBJECT,                             
    */  
	 ER.MAIL_SUBJECT as MAIL_SUBJECT,  
	 /*
	 case            
      when c.messages IS not null and c.messages<>'' and BMInfo.IsPersonalized = 0                    
           then c.Messages             
   when isnull(c.templateid,0)<>0 and BMInfo.IsPersonalized = 0  and umt.MailContent is not null and umt.MailContent <> ''              
     then umt.MailContent                     
         when BMInfo.IsPersonalized = 1            
then ER.MESSAGES            
   else            
      ER.MESSAGES            
     --ISNULL(MAIL_TEMPLETEBODY,ER.MESSAGES)             
     end             
     as [Message],                
	 */
	 ER.MESSAGES as [Message], 
                
    BMInfo.IsPersonalized,                
       ER.MAIL_INSERTEDDATE,ER.MAIL_USERID,ER.MAIL_SCHEDULEDATE ,ER.MAIL_BATCHID as MAIL_BATCHIDOnly                                                       
    FROM                         
      -- MAIL_EMAILSREPORT2 ER with (nolock)                         
    EmailsFilter as ER with(nolock)                      
     join BatchEmail_Infos as BMInfo with(nolock)                      
     on ER.Mail_BatchID = BMInfo.BatchID  and ER.Mail_UserID = BMInfo.UserID        
     
	 /*        
   left join [mysms].dbo.campaignmessages c with (nolock) on er.mail_batchid=c.batchid                        
   left join [mysms].dbo.usermailtemplate umt with (nolock) on c.templateid=umt.id  
   left join [mysms].dbo.[FromMailIDDetails] as frmMailID with(nolock) 
        on ER.Mail_UserID = frmMailID.user_id  
		   and ER.MAIL_FROMEMAIL = frmMailID.[Mail_ID]            
   left join [MySMS].[dbo].[karixmailroute] as  KarixMailID with(nolock)
           on ER.Mail_UserID = KarixMailID.parentid  
		   and ER.MAIL_FROMEMAIL = KarixMailID.[frommailid] 
   */
   WHERE 
    --ER.Mail_UserID = 34594 
	--ER.MAIL_BATCHID in ('123312406','123311953','123317172')
    -- and                  
    ISNULL(ER.MAIL_PRIORITY,0) <= 2  and                
     isnull(ER.IsProcess, 0) = 0           
        and (ER.MAIL_BATCHID % 2) = @div        
        and BMInfo.IsPersonalized = 0                            
   
    and   ER.MAIL_BATCHID 
	           in ( select top 1 ER_Inner.Mail_BatchID  from  EmailsFilter as ER_Inner with(nolock)                      
					 join BatchEmail_Infos as BMInfo_Inner with(nolock)                      
					 on ER_Inner.Mail_BatchID = BMInfo_Inner.BatchID  and ER_Inner.Mail_UserID = BMInfo_Inner.UserID        
				     WHERE
					 ISNULL(ER_Inner.MAIL_PRIORITY,0) <= 2  
					 and                
					 isnull(ER_Inner.IsProcess, 0) = 0           
					 and (ER_Inner.MAIL_BATCHID % 2) = @div        
					
					and BMInfo_Inner.IsPersonalized = 0                            
                     group by  ER_Inner.Mail_BatchID

				  )     
            
   
   --  order by ER.MAIL_BATCHID , ER.Mail_ID asc     
    order by case  when BMInfo.UserID=335 then 100  
     when BMInfo.totalrecords<10  then -2   
     --when b.UserID=17977 then -1  
     -- when  ce.id is not null then 0  
     else cast(BMInfo.TotalProcessed/cast(BMInfo.TotalRecords as float) as numeric(18,4))*100  end asc 

     --order by case when mail_batchid=119524978 then -1 when mail_userid<>335 then 0 else mail_id                 
     -- end                                                 
 ) A                      
        
     
   drop table if exists #mail_ids    
create table #mail_ids(id bigint,batchid bigint,mail_guid nvarchar(100))    
insert into Unsubscribedmails(mail_id,batchid,datesent,mail_guid,email_id) output inserted.mail_id as id,inserted.batchid as batchid,    
inserted.mail_guid as mail_guid into #mail_ids    
select mail_id,
                mail_batchidOnly  
    
  ,mail_inserteddate,mail_guid,Mail_ToEmail from @TEMPTABLE ef where     
  dbo.fn_isemailunsubscribed(EF.mail_userid,EF.Mail_ToEmail)=1  
    
   update c set status='Unsubscribed' from  clientemails c join #mail_ids m on cast(c.guid as nvarchar(100))=m.mail_guid and c.BatchID=m.batchid    
             
   update EF set EF.IsProcess = 2 from EmailsFilter as EF with (nolock)                
       JOIN @TEMPTABLE TT ON EF.MAIL_ID=TT.MAIL_ID  --where EF.Mail_UserID = 34594                   
         
      
      ;with cte as (select ROW_NUMBER() over (PARTITION by mail_guid order by (select 0)) RN,Mail_GUID,            
       MAIL_ID,                                                          
        MAIL_FROMEMAIL,                                                          
        MAIL_TOEMAIL,                                                          
        MAIL_SUBJECT,                                                          
       -- MAIL_TEMPLETENAME,            
        [Message],                                                      
        --cast ([MESSAGES] as nvarchar(max)) [MESSAGES],            
        MAIL_INSERTEDDATE,                                                          
        MAIL_USERID,                                                          
        ReplyTo,                                                          
        Mail_BatchID,                                                    
       -- Mail_Priority,                                                          
       -- Mail_ScheduleDate,                                            
       --  MAIL_ATTECHEMENT,                                                          
       -- MAIL_TEMPLETEBODY,      
       '' as smtpserver
	   ,MAIL_BATCHIDOnly 
       FROM   @TEMPTABLE t)            
 select * into #t from cte where RN=1            
   
   
  SELECT (  Select case
		         when isnull(frmMailID.[DisplayName], '') != ''
		          then frmMailID.[DisplayName]
				 when isnull(KarixMailID.[k_d_name] , '')  != ''
		         then KarixMailID.[k_d_name]
				 else
	              (  select top 1 value from dbo.fn_split(t.MAIL_FROMEMAIL,'@') where position=1  )
	 --             dbo.fn_getNameFromMailID(ER.MAIL_FROMEMAIL)
	            end   
	      
	  )  as MAIL_FROMName,
	  ( 
	   Case            
       when c.Mail_Subject IS not null and c.mail_subject<>'' and t.IsPersonalized = 0            
       then c.Mail_Subject             
       when isnull(c.templateid,0)<>0 and t.IsPersonalized = 0  then umt.mailsubject           
         else                        
           t.MAIL_SUBJECT             
        end )            
  as MAIL_SUBJECT,   
	  case            
      when c.messages IS not null and c.messages<>'' and t.IsPersonalized = 0                    
           then c.Messages             
   when isnull(c.templateid,0)<>0 and t.IsPersonalized = 0  and umt.MailContent is not null and umt.MailContent <> ''              
     then umt.MailContent                     
         when t.IsPersonalized = 1            
then MESSAGES            
   else            
      t.MESSAGE            
     end             
     as [Message],                
                
    t.MAIL_GUID ,                                                      
    t.MAIL_ID ,                                                                                        
    t.MAIL_BATCHID ,  
    --MAIL_FROMName ,              
    t.MAIL_FROMEMAIL ,                                                                                        
    t.MAIL_TOEMAIL ,                                                          
    t.REPLYTO ,                                                                                     
    --.MAIL_SUBJECT ,                                                                                      
    t.IsPersonalized  ,                
    t.MAIL_INSERTEDDATE ,                                                                                        
    t.MAIL_USERID ,                                                                      
    t.MAIL_SCHEDULEDATE ,                        
    t.MAIL_BATCHIDOnly  
	
   FROM @TEMPTABLE t  
       join #t as p
			  on t.MAIL_ID = p.MAIL_ID
			  
			  left join [mysms].dbo.campaignmessages c with (nolock) 
			  on 
			  --t.mail_batchid=c.batchid                        
              ( case when charindex('~',t.mail_batchid) <> 0
	                  then (select  value from fn_split(t.mail_batchid,'~') where Position = 2)
					  else
					     t.mail_batchid 
				end ) = c.batchid 
			  
			  left join [mysms].dbo.usermailtemplate umt with (nolock) on c.templateid=umt.id  
   		      left join [mysms].dbo.[FromMailIDDetails] as frmMailID with(nolock) 
        on T.Mail_UserID = frmMailID.user_id  
		   and t.MAIL_FROMEMAIL = frmMailID.[Mail_ID]            
   left join [MySMS].[dbo].[karixmailroute] as  KarixMailID with(nolock)
           on t.Mail_UserID = KarixMailID.MailUser  
		   and t.MAIL_FROMEMAIL = KarixMailID.[frommailid] 
		      where t.MAIL_GUID
		         not in ( select MAIL_GUID from #mail_ids ) 
			  order by t.MAIL_BATCHID asc                 
      

   --select
   --     Mail_GUID,            
   --     MAIL_ID,                                                          
   --     MAIL_FROMEMAIL,                                                          
   --     MAIL_TOEMAIL,                           
   --     MAIL_SUBJECT,                                                          
   --     [Message],                                                      
   --     MAIL_INSERTEDDATE,                                                          
   --     MAIL_USERID,                                                          
   --     ReplyTo,                                                          
   --     Mail_BatchID,                                                    
   --    smtpserver,
	  -- Mail_BatchIDOnly
	  -- from #t      
        
  
   update b set totalprocessed = isnull(totalprocessed,0) + isnull(Coun,0) from     
   (  
     select * from BatchEmail_Infos(nolock) where batchid in   
      (  
       select Mail_batchIDOnly  
       from @TEMPTABLE
	  )
   ) b                              
   join     
   (select MAIL_BATCHIDOnly  ,count(MAIL_BATCHIDOnly) coun from @TEMPTABLE group by MAIL_BATCHIDOnly)     
   tt on tt.MAIL_BATCHIDOnly=b.BatchID                               
    
     
   update b set isprocess=1,BatchProcessTime=GETDATE() from     
   (select * from BatchEmail_Infos(nolock) where batchid in  
    (  
      select MAIL_BATCHIDOnly from @TEMPTABLE  
    )  
     
   ) b                              
   where not exists(select 1 from emailsfilter(nolock) where mail_batchid=b.BatchID and IsProcess = 0)    
   and totalprocessed>=totalrecords    
     
   insert into emailcountracking(batchid,tablename,mailcount,createdon)    
   select batchid,'Unsubscribedmails',count(1),getdate() from #mail_ids group by batchid    
      
  drop table if exists #t       
  drop table if exists #mail_ids   
  
                                                                              
                      
--commit                      
end try                      
BEGIN CATCH                                                             
--IF @@TRANCOUNT>0                                                            
--ROLLBACK                                                                                                           
EXECUTE USP_INSERTERRORINFO;                                                                                   
IF ERROR_NUMBER() = 1205 -- Deadlock Error Number                                                                        
BEGIN                                                                                              
WAITFOR DELAY '00:00:00.05' -- Wait for 5 ms                                                                                       
GOTO RETRY0 -- Go to Label RETRY                                                
END                                                                                                                           
END CATCH                 
                
                
End 


