    t.MAIL_USERID ,                                                                        
    t.MAIL_SCHEDULEDATE ,                          
    t.MAIL_BATCHIDOnly                        
   FROM @TEMPTABLE t    
   join #t as p  
     on t.MAIL_ID = p.MAIL_ID  
       
     left join [mysms].dbo.campaignmessages as c with (nolock)   
     on    t.MAIL_BATCHIDOnly=c.batchid                          
    left join [mysms].dbo.usermailtemplate as umt with (nolock) on c.templateid=umt.id    
           left join [mysms].dbo.[FromMailIDDetails] as frmMailID with(nolock)   
        on T.Mail_UserID = frmMailID.user_id    
     and t.MAIL_FROMEMAIL = frmMailID.[Mail_ID]              
   left join [MySMS].[dbo].[karixmailroute] as  KarixMailID with(nolock)  
           on t.Mail_UserID = KarixMailID.MailUser    
     and t.MAIL_FROMEMAIL = KarixMailID.[frommailid]   
     where t.MAIL_GUID
		         not in ( select MAIL_GUID from #mail_ids ) 
	  
     order by t.MAIL_BATCHID asc                
                   
     print 'after select'  


       
     --commit
   end try
   begin catch
       -- IF @@TRANCOUNT>0                                                              
        --   ROLLBACK    
	  update EF set EF.IsProcess = 0 from EmailsFilter as EF with (nolock)                  
       JOIN @TEMPTABLE TT ON EF.MAIL_ID=TT.MAIL_ID  --where EF.Mail_UserID = 34594                     
      
          EXECUTE USP_INSERTERRORINFO;
   end catch    

   declare @tbl1 [tbl_BatchIDs] 
	declare @tbl2 [tbl_BatchIDs] 

   insert into @tbl1([Mail_BatchID],[Count])
	select MAIL_BATCHIDOnly as [Mail_BatchID],count(MAIL_BATCHIDOnly) as [Count] from @TEMPTABLE group by MAIL_BATCHIDOnly

	insert into @tbl2([Mail_BatchID],[Count])
	select MAIL_BATCHIDOnly as [Mail_BatchID],0 as [Count] from @TEMPTABLE  as t
	      where not exists(select 1 from emailsfilter(nolock) where mail_batchid=t.MAIL_BATCHIDOnly and IsProcess = 0)        
    


	Declare @tbl1Json nvarchar(max) = ( select * from 
	   (SELECT *
           FROM @tbl1) a
       FOR JSON AUTO , INCLUDE_NULL_VALUES )

	Declare @tbl2Json nvarchar(max) = ( select * from
	   (SELECT *
           FROM @tbl2 ) a
       FOR JSON AUTO , INCLUDE_NULL_VALUES)

	   print concat(format(getdate(),'dd-MM-yyyy hh:mm:sss'),': json create end', ', @tbl1: ',@tbl1json, ', @tbl2: ',@tbl2json)        

	  exec Usp_UpdateBatchInfos_WithJson @tbl1Json,@tbl2Json

		 

--   update b set isprocess=1,BatchProcessTime=GETDATE() from       
--   (select * from BatchEmail_Infos(nolock) where batchid in    
--    (    
--      select MAIL_BATCHIDOnly from @TEMPTABLE    
--    )    
       
--   ) b   
--   --BatchEmail_Infos b                   with (rowlock)              
--   where not exists(select 1 from emailsfilter(nolock) where mail_batchid=b.BatchID and IsProcess = 0)      
--   and totalprocessed>=totalrecords      
       
   insert into emailcountracking(batchid,tablename,mailcount,createdon)      
   select batchid,'Unsubscribedmails',count(1),getdate() from #mail_ids group by batchid      
        
  drop table if exists #t         
  drop table if exists #mail_ids     
    
                                                                                
                        
end try                        
BEGIN CATCH                                                               
EXECUTE USP_INSERTERRORINFO;                                                                                     
END CATCH                   
                  
                  
End 


