      when c.messages IS not null and c.messages<>'' and BMInfo.IsPersonalized = 0                    
           then c.Messages             
   when isnull(c.templateid,0)<>0 and BMInfo.IsPersonalized = 0  and umt.MailContent is not null and umt.MailContent <> ''              
     then umt.MailContent                     
         when BMInfo.IsPersonalized = 1            
then ER.MESSAGES            
   else            
      ER.MESSAGES            
     --ISNULL(MAIL_TEMPLETEBODY,ER.MESSAGES)             
     end             
     as [Message],                
                
    BMInfo.IsPersonalized,                
       ER.MAIL_INSERTEDDATE,ER.MAIL_USERID,ER.MAIL_SCHEDULEDATE ,ER.MAIL_BATCHID as MAIL_BATCHIDOnly                                                       
    FROM                         
      -- MAIL_EMAILSREPORT2 ER with (nolock)                         
    EmailsFilter as ER with(nolock)                      
     join BatchEmail_Infos as BMInfo with(nolock)                      
     on ER.Mail_BatchID = BMInfo.BatchID  and ER.Mail_UserID = BMInfo.UserID        
          
   left join [mysms].dbo.campaignmessages c with (nolock) on er.mail_batchid=c.batchid                        
    left join [mysms].dbo.usermailtemplate umt with (nolock) on c.templateid=umt.id                               
   WHERE  ER.Mail_UserID = 34594         
     and                  
    ISNULL(ER.MAIL_PRIORITY,0) = @Priority and                
     isnull(ER.IsProcess, 0) = 0           
        and (ER.MAIL_BATCHID % 6) = @div        
        and BMInfo.IsPersonalized = 1                            
   --  order by ER.MAIL_BATCHID , ER.Mail_ID asc     
    order by case  when BMInfo.UserID=335 then 100  
     when BMInfo.totalrecords<10  then -2   
     --when b.UserID=17977 then -1  
     -- when  ce.id is not null then 0  
     else cast(BMInfo.TotalProcessed/cast(BMInfo.TotalRecords as float) as numeric(18,4))*100  end asc 

     --order by case when mail_batchid=119524978 then -1 when mail_userid<>335 then 0 else mail_id                 
     -- end                                                 
 ) A                      
        
     
   drop table if exists #mail_ids    
create table #mail_ids(id bigint,batchid bigint,mail_guid nvarchar(100))    
insert into Unsubscribedmails(mail_id,batchid,datesent,mail_guid,email_id) output inserted.mail_id as id,inserted.batchid as batchid,    
inserted.mail_guid as mail_guid into #mail_ids    
select mail_id,
                mail_batchidOnly  
    
  ,mail_inserteddate,mail_guid,Mail_ToEmail from @TEMPTABLE ef where     
  dbo.fn_isemailunsubscribed(EF.mail_userid,EF.Mail_ToEmail)=1  
    
   update c set status='Unsubscribed' from  clientemails c join #mail_ids m on cast(c.guid as nvarchar(100))=m.mail_guid and c.BatchID=m.batchid    
             
   update EF set EF.IsProcess = 2 from EmailsFilter as EF with (nolock)                
       JOIN @TEMPTABLE TT ON EF.MAIL_ID=TT.MAIL_ID  where EF.Mail_UserID = 34594                   
         
      
      ;with cte as (select ROW_NUMBER() over (PARTITION by mail_guid order by (select 0)) RN,Mail_GUID,            
       MAIL_ID,                                                          
        MAIL_FROMEMAIL,                                                          
        MAIL_TOEMAIL,                                                          
        MAIL_SUBJECT,                                                          
       -- MAIL_TEMPLETENAME,            
        [Message],                                                      
        --cast ([MESSAGES] as nvarchar(max)) [MESSAGES],            
        MAIL_INSERTEDDATE,                                                          
        MAIL_USERID,                                                          
        ReplyTo,                                                          
        Mail_BatchID,                                                    
       -- Mail_Priority,                                                          
       -- Mail_ScheduleDate,                                            
       --  MAIL_ATTECHEMENT,                                                          
       -- MAIL_TEMPLETEBODY,      
       '' as smtpserver
	   ,MAIL_BATCHIDOnly 
       FROM   @TEMPTABLE t)            
 select * into #t from cte where RN=1            
   
   
  SELECT *                      
   FROM @TEMPTABLE t  
     where
      Mail_id in
         ( 
		   select MAIL_ID from #t      
         )
      and
	  t.MAIL_GUID
		         not in ( select MAIL_GUID from #mail_ids )      

      order by t.MAIL_BATCHID asc                
      

   --select
   --     Mail_GUID,            
   --     MAIL_ID,                                                          
   --     MAIL_FROMEMAIL,                                                          
   --     MAIL_TOEMAIL,                           
   --     MAIL_SUBJECT,                                                          
   --     [Message],                                                      
   --     MAIL_INSERTEDDATE,                                                          
   --     MAIL_USERID,                                                          
   --     ReplyTo,                                                          
   --     Mail_BatchID,                                                    
   --    smtpserver,
	  -- Mail_BatchIDOnly
	  -- from #t      
        
  
   update b set totalprocessed = isnull(totalprocessed,0) + isnull(Coun,0) from     
   (  
     select * from BatchEmail_Infos(nolock) where batchid in   
      (  
       select Mail_batchIDOnly  
       from @TEMPTABLE
	  )
   ) b                              
   join     
   (select MAIL_BATCHIDOnly  ,count(MAIL_BATCHIDOnly) coun from @TEMPTABLE group by MAIL_BATCHIDOnly)     
   tt on tt.MAIL_BATCHIDOnly=b.BatchID                               
    
     
   update b set isprocess=1,BatchProcessTime=GETDATE() from     
   (select * from BatchEmail_Infos(nolock) where batchid in  
    (  
      select MAIL_BATCHIDOnly from @TEMPTABLE  
    )  
     
   ) b                              
   where not exists(select 1 from emailsfilter(nolock) where mail_batchid=b.BatchID and IsProcess = 0)    
   and totalprocessed>=totalrecords    
     
   insert into emailcountracking(batchid,tablename,mailcount,createdon)    
   select batchid,'Unsubscribedmails',count(1),getdate() from #mail_ids group by batchid    
      
  drop table if exists #t       
  drop table if exists #mail_ids   
  
                                                                              
                      
commit                      
end try                      
BEGIN CATCH                                                             
IF @@TRANCOUNT>0                                                            
ROLLBACK                                                                                                           
EXECUTE USP_INSERTERRORINFO;                                                                                   
IF ERROR_NUMBER() = 1205 -- Deadlock Error Number                                                                        
BEGIN                                                                                              
WAITFOR DELAY '00:00:00.05' -- Wait for 5 ms                                                                                       
GOTO RETRY0 -- Go to Label RETRY                                                
END                                                                                                                           
END CATCH                 
                
                
End 


