CREATE   PROCEDURE usp_getengagementscore --'lead',988415
@entity nvarchar(20),
@entityid bigint,
@medium nvarchar(20)=null,
@fromdate date =null,
@todate date =null
as
begin
select @fromdate=coalesce(@fromdate,cast(dateadd(m,-6,getdate()) as date))
select @todate=coalesce(@todate,cast(dateadd(d,1,getdate()) as date))
declare @parentid bigint
drop table if exists #mobile
create table #mobile(Mobile nvarchar(50))
drop table if exists #email
create table #email(Email nvarchar(50))
if @entity='lead'
begin
insert into #mobile(Mobile)
select mobile from Userleads_Mobile_Email(nolock) u where mobile<>'0' and ulme_id=@entityid
insert into #email(email)
select email from Userleads_Mobile_Email(nolock) u where email<>'0' and ulme_id=@entityid
select @parentid=parentid from Userleads_Mobile_Email(nolock) u where ulme_id=@entityid
end
if @entity='enquiry'
begin
insert into #mobile(Mobile)
select mobile from Userenquiry_Mobile_Email(nolock) u where mobile<>'0' and enquiryid=@entityid
insert into #email(email)
select email from Userenquiry_Mobile_Email(nolock) u where email<>'0' and enquiryid=@entityid
select @parentid=parentid from Userenquiry_Mobile_Email(nolock) u where enquiryid=@entityid

end

if isnull(@medium,'All') in ('All' ,'SMS')
begin
Select Mobile,Sent,Delivered,dbo.fn_getmobile_linktracking_stats(Mobile,@fromdate,@todate,'Total',@parentid) TrackableSMS,
dbo.fn_getmobile_linktracking_stats(Mobile,@fromdate,@todate,'UniqueClicks',@parentid) UniqueClicks,
dbo.fn_getmobile_linktracking_stats(Mobile,@fromdate,@todate,'TotalClicks',@parentid) TotalClicks
from
(
select Mobile,sum(Sent) Sent,sum(Delivered) Delivered
from
(Select o.Mobile,count(1) Sent,sum(case when messagestatus='DELIVRD' then 1 else 0 end) Delivered 
from messagedeliverystatus (nolock) m join #mobile o on o.mobile=m.mobile
where dbo.[ufn_GetUserParentId](u_id)=@parentid and cast(messageinsertdate as date) between @fromdate and @todate
group by o.Mobile
union
Select o.Mobile,count(1) Sent,sum(case when messagestatus='DELIVRD' then 1 else 0 end) Delivered 
from thirtydayshistory (nolock) m join #mobile o on o.mobile=m.mobile
where dbo.[ufn_GetUserParentId](u_id)=@parentid and cast(messageinsertdate as date) between @fromdate and @todate
group by o.Mobile
union
Select o.Mobile,count(1) Sent,sum(case when messagestatus='DELIVRD' then 1 else 0 end) Delivered 
from mysmsreport.dbo.sixdayshistory (nolock) m join #mobile o on o.mobile=m.mobile
where dbo.[ufn_GetUserParentId](u_id)=@parentid and cast(messageinsertdate as date) between @fromdate and @todate
group by o.Mobile

) a
group by Mobile
) b
end

