/* ============================================================
   Procedure: [dbo].[usp_GetEnquiryDetailsByPlaceholders]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

---------------------------------------------------------

CREATE   PROCEDURE usp_GetEnquiryDetailsByPlaceholders    
    @UserID BIGINT,    
    @EnquiryID BIGINT,    
    @Placeholders NVARCHAR(MAX)    
AS    
BEGIN    
    DECLARE @SQL NVARCHAR(MAX);  
    DECLARE @Result NVARCHAR(MAX) = '';  
    DECLARE @Placeholder NVARCHAR(255);  
    DECLARE @DelimiterPos INT;  
    DECLARE @FetchedValue NVARCHAR(MAX);  
  
    -- Trim spaces from @Placeholders  
    SET @Placeholders = LTRIM(RTRIM(@Placeholders));  
  
    -- Process each placeholder individually  
    WHILE LEN(@Placeholders) > 0  
    BEGIN  
        -- Find the position of the next comma  
        SET @DelimiterPos = CHARINDEX(',', @Placeholders);  
  
        -- If no comma is found, take the whole string  
        IF @DelimiterPos = 0  
        BEGIN  
            SET @Placeholder = @Placeholders;  
            SET @Placeholders = '';  
        END  
        ELSE  
        BEGIN  
            SET @Placeholder = LEFT(@Placeholders, @DelimiterPos - 1);  
            SET @Placeholders = RIGHT(@Placeholders, LEN(@Placeholders) - @DelimiterPos);  
        END  
  
        -- Remove spaces from the current placeholder  
        SET @Placeholder = LTRIM(RTRIM(@Placeholder));  
  
        -- Handle specific cases and remove spaces if MobileNo  
        IF @Placeholder = 'MobileNo'  
        BEGIN  
            -- Construct dynamic SQL to concatenate MobileNo and CountryCode and remove spaces  
            SET @SQL = 'SELECT @FetchedValue = REPLACE(CONCAT(CountryCode, MobileNo), '' '', '''') FROM UserEnquiry WHERE EnquiryID = @EnquiryID';  
        END  
        ELSE  
        BEGIN  
            -- Construct dynamic SQL for other placeholders  
            SET @SQL = 'SELECT @FetchedValue = ' + QUOTENAME(@Placeholder) + ' FROM UserEnquiry WHERE EnquiryID = @EnquiryID';  
        END  
  
        -- Execute the dynamic SQL query and capture the result  
        EXEC sp_executesql @SQL, N'@EnquiryID BIGINT, @FetchedValue NVARCHAR(MAX) OUTPUT', @EnquiryID = @EnquiryID, @FetchedValue = @FetchedValue OUTPUT;  
  
        -- Concatenate the result, include NULL values as 'NULL'  
        IF @FetchedValue IS NULL OR @FetchedValue = ''  
        BEGIN  
            IF @Result = ''  
                SET @Result = 'NULL';  
            ELSE  
                SET @Result = @Result + ', NULL';  
        END  
        ELSE  
        BEGIN  
            IF @Result = ''  
                SET @Result = @FetchedValue;  
            ELSE  
                SET @Result = @Result + ', ' + @FetchedValue;  
        END  
    END  
  
    -- Return the concatenated result  
    SELECT @Result AS Result;  
END;  

-------------------------------------






GO

/* ============================================================
   Procedure: [dbo].[usp_getEnquiryDetailsPDF]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_getEnquiryDetailsPDF]                 
(                  
    @enquiryId BIGINT,        
    @ColumnNames NVARCHAR(MAX),      
 @ParentID BIGINT      
)                
AS      
BEGIN               
    SET NOCOUNT ON;      
    /* 
   
    -- Declare a variable for the SQL query      
    DECLARE @Sql NVARCHAR(MAX);      
      
    -- Construct the SQL query using the provided column names      
    SET @Sql = 'SELECT ' + @ColumnNames + ' FROM UserEnquiry WHERE EnquiryID = @enquiryId and ParentID = @ParentID';        
      
    -- Execute the dynamic SQL query with parameters      
   EXEC sp_executesql @Sql, N'@enquiryId BIGINT, @ParentID BIGINT', @enquiryId, @ParentID;      
   */

    DECLARE @Sql NVARCHAR(MAX);
    DECLARE @ValidColumns NVARCHAR(MAX);

    -- Split column names and keep only existing columns
    SELECT @ValidColumns = STRING_AGG(QUOTENAME(name), ',')
    FROM sys.columns
    WHERE object_id = OBJECT_ID('UserEnquiry')
    AND name IN (
        SELECT TRIM(value)
        FROM STRING_SPLIT(@ColumnNames, ',')
    );

    -- If no valid columns found
    IF @ValidColumns IS NULL OR @ValidColumns = ''
    BEGIN
        RAISERROR('No valid columns found.',16,1);
        RETURN;
    END

    -- Construct dynamic SQL
    SET @Sql = '
        SELECT ' + @ValidColumns + '
        FROM UserEnquiry
        WHERE EnquiryID = @enquiryId
        AND ParentID = @ParentID';

    EXEC sp_executesql 
        @Sql,
        N'@enquiryId BIGINT, @ParentID BIGINT',
        @enquiryId,
        @ParentID;
          

END 


GO

