/* ============================================================
   Procedure: [dbo].[usp_GetEnquiryLeadCustomColumnListWithDataType]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC [dbo].[usp_GetEnquiryLeadCustomColumnListWithDataType]   
 @ParentId BIGINT    
AS    
Begin  
  select * from (   
  SELECT column_name AS 'fieldname',       
               UPPER(       
     CASE column_name      
      WHEN 'CampaignName'       
       THEN 'VARCHAR'      
      WHEN 'MediumName'      
       THEN 'VARCHAR'      
      WHEN 'SourceName'      
       THEN 'VARCHAR'      
      ELSE      
       data_type      
      END      
    ) AS 'data_type'  , 'Predefined' as FieldType      
        FROM information_schema.columns      
        WHERE table_name = 'UserEnquiry'  
   UNiON    
    
   SELECT column_name AS 'fieldname',     
       UPPER(CASE column_name    
        WHEN 'CampaignName'    
        THEN 'VARCHAR'    
        WHEN 'MediumName'    
        THEN 'VARCHAR'    
        WHEN 'SourceName'    
        THEN 'VARCHAR'    
        WHEN 'FollowupStatus'    
        THEN 'VARCHAR'    
        ELSE data_type    
       END) AS 'data_type' , 'Predefined' as FieldType  
   FROM information_schema.columns    
   WHERE table_name = 'UserLeads'    
   UNION    
   SELECT fieldname,     
       UPPER((CASE datatype    
         WHEN 'd'    
         THEN 'DateTime'    
         WHEN 'f'    
         THEN 'Numeric'    
         WHEN 'v'    
         THEN 'VARCHAR'    
         WHEN 'm'    
         THEN 'VARCHAR'    
         WHEN 'e'    
         THEN 'VARCHAR'    
         WHEN 'r'    
         THEN 'VARCHAR'    
         WHEN 'c'    
         THEN 'VARCHAR'    
         WHEN 's'    
         THEN 'VARCHAR'    
                          
        END)) AS data_type , 'Custom' as FieldType   
   FROM customfields NOCOUNT    
   WHERE [ParentID] = @ParentId    
  ) as col where col.fieldname not in ('id','ModifiedOn','ModifiedBy','FollowupDate','LeadImage','temp_id','img_ext','ProfileImgFileName','enquirysource','WhatsAppNoColName','LastFollowupCreatedBy','parentid')  
End



GO

/* ============================================================
