CREATE   PROCEDURE [dbo].[usp_GetEnquiryLeadCustomColumnListWithDataType_All_t] --34594,'lead'
(
	@ParentID BIGINT, 
	@Mode     NVARCHAR(50)
)
AS
    BEGIN

	drop table if exists #t
	create table #t(fieldname nvarchar(50),datatype nvarchar(50),mode nvarchar(20))

	insert into #t(fieldname,datatype,mode)
	values ('CreatedByName','VARCHAR','Enquiry'),
           ('CreatedByPhone','VARCHAR','Enquiry'),
		   ('CreatedByEmail','VARCHAR','Enquiry'),
		   ('AssignedToName','VARCHAR','Lead'),
		   ('AssignedToPhone','VARCHAR','Lead'),
		   ('AssignedToEmail','VARCHAR','Lead')


        IF(@Mode = 'Enquiry')
            BEGIN
                SELECT *
                FROM
                (
                    SELECT(CASE
                               WHEN(column_name = 'MobileNo')
                                   OR (column_name = 'MobileNo1')
                                   OR (column_name = 'MobileNo2')
                               THEN 'MobileNo'
                               WHEN(column_name = 'EmailID')
                                   OR (column_name = 'EmailID1')
                                   OR (column_name = 'EmailID2')
                               THEN 'EmailID'
                               WHEN COLUMN_NAME = 'whereAddress'
                               THEN 'GoogleLocation'
                               ELSE column_name
                           END) AS 'fieldname', 
                          UPPER(CASE column_name
                                    WHEN 'CampaignName'
                                    THEN 'VARCHAR'
                                    WHEN 'MediumName'
                                    THEN 'VARCHAR'
                                    WHEN 'SourceName'
                                    THEN 'VARCHAR'
                                    WHEN 'CreatedBy'
                                    THEN 'VARCHAR'
                                    WHEN 'LastFollowupCreatedBy'
                                    THEN 'VARCHAR'
                                    ELSE data_type
                                END) AS 'data_type', 
                          'Enquiry' AS FieldType
                    FROM information_schema.columns
                    WHERE table_name = 'UserEnquiry'
					union
					select fieldname,datatype,'Enquiry' AS FieldType from #t where mode='Enquiry'
					UNION
			        SELECT fieldname, 
                           UPPER((CASE datatype
                                      WHEN 'd'
                                      THEN 'DateTime'
                                      WHEN 'f'
                                      THEN 'Numeric'
                                      WHEN 'v'
                                      THEN 'VARCHAR'
                                      WHEN 'm'
                                      THEN 'VARCHAR'
                                      WHEN 'e'
                                      THEN 'VARCHAR'
                                      WHEN 'r'
                                      THEN 'VARCHAR'
                                      WHEN 'c'
                                      THEN 'VARCHAR'
                                      WHEN 's'
                                      THEN 'VARCHAR'
									  WHEN 'l'
                                      THEN 'VARCHAR'
                                  END)) AS data_type, 
                           'Custom' AS FieldType
                    FROM customfields AS NOCOUNT
                    WHERE [ParentID] = @ParentId
                          AND isActive = 1
                    
					UNION
					SELECT  'Tag' AS column_name,
							'VARCHAR' AS data_type,
							'Enquiry' AS FieldType
                ) AS col
                WHERE col.fieldname NOT IN('id', 'ModifiedOn', 'NextStatusDate', 'longitude', 'latitude', 'ModifiedBy', 'LeadImage', 'temp_id', 'img_ext', 'ProfileImgFileName', 'enquirysource', 'WhatsAppNoColName', 'parentid');
        END;
            ELSE
            BEGIN
                IF(@Mode = 'Lead'
                   OR @Mode = 'Conversion')
                    BEGIN
                        SELECT *
                        FROM
                        (
                            SELECT(CASE
                                       WHEN(column_name = 'MobileNo')
                                           OR (column_name = 'MobileNo1')
                                           OR (column_name = 'MobileNo2')
                                       THEN 'MobileNo'
                                       WHEN(column_name = 'EmailID')
                                           OR (column_name = 'EmailID1')
                                           OR (column_name = 'EmailID2')
                                       THEN 'EmailID'
                                       WHEN COLUMN_NAME = 'whereAddress'
                                       THEN 'GoogleLocation'
                                       ELSE column_name
                                   END) AS 'fieldname', 
                                  UPPER(CASE column_name
                                            WHEN 'CampaignName'
                                            THEN 'VARCHAR'
                                            WHEN 'MediumName'
                                            THEN 'VARCHAR'
                                            WHEN 'SourceName'
                                            THEN 'VARCHAR'
                                            WHEN 'FollowupStatus'
                                            THEN 'VARCHAR'
                                            WHEN 'CreatedBy'
                                            THEN 'VARCHAR'
                                            WHEN 'AssignedTo'
                                            THEN 'VARCHAR'
                                            WHEN 'LastFollowupCreatedBy'
                                            THEN 'VARCHAR'
                                            WHEN 'NextStatusDate'
                                            THEN 'DATETIME'
                                            ELSE data_type
                                        END) AS 'data_type', 
                                  'Lead' AS FieldType
                            FROM information_schema.columns
                            WHERE table_name = 'UserLeads'
                            union
					       select fieldname,datatype,'Lead' AS FieldType from #t where mode='Lead'
							UNION
							SELECT fieldname, 
                                   UPPER((CASE datatype
                                              WHEN 'd'
                                              THEN 'DateTime'
                                              WHEN 'f'
                                              THEN 'Numeric'
                                              WHEN 'v'
                                              THEN 'VARCHAR'
                                              WHEN 'm'
                                              THEN 'VARCHAR'
                                              WHEN 'e'
                                              THEN 'VARCHAR'
                                              WHEN 'r'
                                              THEN 'VARCHAR'
                                              WHEN 'c'
                                              THEN 'VARCHAR'
                                              WHEN 's'
                                              THEN 'VARCHAR'
											  WHEN 'l'
                                              THEN 'VARCHAR'
                                          END)) AS data_type, 
                                   'Custom' AS FieldType
                            FROM customfields AS NOCOUNT
                            WHERE [ParentID] = @ParentId
                                  AND isActive = 1
                        ) AS col
                        WHERE col.fieldname NOT IN('id', 'ModifiedOn', 'NextStatusDate', 'longitude', 'latitude', 'ModifiedBy', 'LeadImage', 'temp_id', 'img_ext', 'ProfileImgFileName', 'enquirysource', 'WhatsAppNoColName', 'parentid','IsScoreeligible')
                        UNION
                        SELECT 'Pipeline' AS column_name, 
                               'VARCHAR' AS data_type, 
                               'Lead' AS FieldType
						UNION
						SELECT  'Tag' AS column_name,
								'VARCHAR' AS data_type,
								'Lead' AS FieldType
                END;
                    ELSE
                    BEGIN
                        IF(@Mode = 'All')
                            BEGIN
                                SELECT *
                                FROM
                                (
                                    SELECT(CASE
                                               WHEN(column_name = 'MobileNo')
                                                   OR (column_name = 'MobileNo1')
                                                   OR (column_name = 'MobileNo2')
                                               THEN 'MobileNo'
                                               WHEN(column_name = 'EmailID')
                                                   OR (column_name = 'EmailID1')
                                                   OR (column_name = 'EmailID2')
                                               THEN 'EmailID'
                                               WHEN COLUMN_NAME = 'whereAddress'
                                               THEN 'GoogleLocation'
                                               ELSE column_name
                                           END) AS 'fieldname', 
                                          UPPER(CASE column_name
                                                    WHEN 'CampaignName'
                                                    THEN 'VARCHAR'
                                                    WHEN 'MediumName'
                                                    THEN 'VARCHAR'
                                                    WHEN 'SourceName'
                                                    THEN 'VARCHAR'
                                                    WHEN 'CreatedBy'
                                                    THEN 'VARCHAR'
                                                    WHEN 'LastFollowupCreatedBy'
                                                    THEN 'VARCHAR'
                                                    WHEN 'NextStatusDate'
                                                    THEN 'DATETIME'
                                                    ELSE data_type
                                                END) AS 'data_type', 
                                          'Common' AS FieldType
                                    FROM information_schema.columns
                                    WHERE table_name = 'UserEnquiry'
                                    INTERSECT
                                    SELECT(CASE
                                               WHEN(column_name = 'MobileNo')
                                                   OR (column_name = 'MobileNo1')
                                                   OR (column_name = 'MobileNo2')
                                               THEN 'MobileNo'
                                               WHEN(column_name = 'EmailID')
                                                   OR (column_name = 'EmailID1')
                                                   OR (column_name = 'EmailID2')
                                               THEN 'EmailID'
                                               WHEN COLUMN_NAME = 'whereAddress'
                                               THEN 'GoogleLocation'
                                               ELSE column_name
                                           END) AS 'fieldname', 
                                          UPPER(CASE column_name
                                                    WHEN 'CampaignName'
                                                    THEN 'VARCHAR'
                                                    WHEN 'MediumName'
                                                    THEN 'VARCHAR'
                                                    WHEN 'SourceName'
                                                    THEN 'VARCHAR'
                                                    WHEN 'FollowupStatus'
                                                    THEN 'VARCHAR'
                                                    WHEN 'CreatedBy'
                                                    THEN 'VARCHAR'
                                                    WHEN 'AssignedTo'
                                                    THEN 'VARCHAR'
                                                    WHEN 'LastFollowupCreatedBy'
                                                    THEN 'VARCHAR'
                                                    WHEN 'NextStatusDate'
                                                    THEN 'DATETIME'
                                                    ELSE data_type
                                                END) AS 'data_type', 
                                          'Common' AS FieldType
                                    FROM information_schema.columns
                                    WHERE table_name = 'UserLeads'
                                    UNION
                                    SELECT fieldname, 
                                           UPPER((CASE datatype
                                                      WHEN 'd'
                                                      THEN 'DateTime'
                                                      WHEN 'f'
                                                      THEN 'Numeric'
                                                      WHEN 'v'
                                                      THEN 'VARCHAR'
                                                      WHEN 'm'
                                                      THEN 'VARCHAR'
                                                      WHEN 'e'
                                                      THEN 'VARCHAR'
                                                      WHEN 'r'
                                                      THEN 'VARCHAR'
                                                      WHEN 'c'
                                                      THEN 'VARCHAR'
                                                      WHEN 's'
                                                      THEN 'VARCHAR'
													   WHEN 'l'
                                                      THEN 'VARCHAR'
                                                  END)) AS data_type, 
                                           'Custom' AS FieldType
                                    FROM customfields AS NOCOUNT
                                    WHERE [ParentID] = @ParentId
                                          AND isActive = 1
									UNION
									SELECT  'Tag' AS column_name,
										'VARCHAR' AS data_type,
										'Common' AS FieldType
                                ) AS col
                                WHERE col.fieldname NOT IN('id', 'ModifiedOn', 'NextStatusDate', 'longitude', 'latitude', 'ModifiedBy', 'LeadImage', 'temp_id', 'img_ext', 'ProfileImgFileName', 'enquirysource', 'WhatsAppNoColName', 'parentid','IsScoreeligible');
                        END;
                END;
        END;
    END;



