/* ============================================================
   Procedure: [dbo].[usp_GetEnquiryLeadCustomColumnListWithDataType_WA]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC [dbo].[usp_GetEnquiryLeadCustomColumnListWithDataType_WA]     
 @ParentId BIGINT      
AS      
Begin    
  select * from (     
  SELECT column_name AS 'fieldname',         
               UPPER(         
     CASE column_name        
      WHEN 'CampaignName'         
       THEN 'VARCHAR'        
      WHEN 'MediumName'        
       THEN 'VARCHAR'        
      WHEN 'SourceName'        
       THEN 'VARCHAR'        
      ELSE        
       data_type        
      END        
    ) AS 'data_type'  , 'Predefined' as FieldType        
        FROM information_schema.columns        
        WHERE table_name = 'UserEnquiry'    
   UNiON      
      
   SELECT column_name AS 'fieldname',       
       UPPER(CASE column_name      
        WHEN 'CampaignName'      
        THEN 'VARCHAR'      
        WHEN 'MediumName'      
        THEN 'VARCHAR'      
        WHEN 'SourceName'      
        THEN 'VARCHAR'      
        WHEN 'FollowupStatus'      
        THEN 'VARCHAR'      
        ELSE data_type      
       END) AS 'data_type' , 'Predefined' as FieldType    
   FROM information_schema.columns      
   WHERE table_name = 'UserLeads'      
   UNION      
   SELECT fieldname,       
       UPPER((CASE datatype      
         WHEN 'd'      
         THEN 'DateTime'      
         WHEN 'f'      
         THEN 'Numeric'      
         WHEN 'v'      
         THEN 'VARCHAR'      
         WHEN 'm'      
         THEN 'VARCHAR'      
         WHEN 'e'      
         THEN 'VARCHAR'      
         WHEN 'r'      
         THEN 'VARCHAR'      
         WHEN 'c'      
         THEN 'VARCHAR'      
         WHEN 's'      
         THEN 'VARCHAR'      
                            
        END)) AS data_type , 'Custom' as FieldType     
   FROM customfields NOCOUNT      
   WHERE [ParentID] = @ParentId and isactive = 1      
  ) as col where col.fieldname not in ('id','ModifiedOn','ModifiedBy','FollowupDate','LeadImage','temp_id','img_ext','ProfileImgFileName','enquirysource','WhatsAppNoColName','LastFollowupCreatedBy','parentid') and col.fieldname not in (Select REPLACE(ColumnName, 'lead.', '') from tbl_TableFieldRistrict(nolock) where TableName = 'userLeads' and EditType = 0)
End



GO

/* ============================================================
   Procedure: [dbo].[usp_GetEnquiryLeadImportRemarks]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


-- Exec usp_GetEnquiryLeadImportRemarks 'E', 11
-- Exec usp_GetEnquiryLeadImportRemarks 'L', 2
CREATE   PROC usp_GetEnquiryLeadImportRemarks
(
    @ImportType varchar(1), -- [E]nquiry, [L]ead
    @ImportRow_Id bigint
)
AS
BEGIN
    -- declare @ImportRow_Id bigint=11
    Declare @Remarks nvarchar(max)

    If(@ImportType = 'E')
    Begin
	   Select @Remarks=Remarks from tbl_EnquiryImportSummary where ImportRow_Id=@ImportRow_id
    End

    If(@ImportType = 'L')
    Begin
	   Select @Remarks=Remarks from tbl_LeadImportSummary where ImportRow_Id=@ImportRow_id
    End

    select * from openjson(@Remarks)
    WITH 
    (   
        Sno   int '$.Sno',
        Remarks varchar(200) '$.Remarks'
    ) 

END



GO

/* ============================================================
   Procedure: [dbo].[usp_GetEnquiryLeadImportStatus]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

      
-- Exec usp_GetEnquiryLeadImportStatus 'E', '15-Sep-2019', '20-Sep-2019', 335        
-- Exec usp_GetEnquiryLeadImportStatus 'E', '15-Sep-2019', '20-Sep-2019', 335, 11        
-- Exec usp_GetEnquiryLeadImportStatus 'L', '15-Sep-2019', '21-Sep-2019', 335        
-- Exec usp_GetEnquiryLeadImportStatus 'L', '15-Sep-2019', '21-Sep-2019', 335, 2        
-- exec usp_GetEnquiryLeadImportStatus @ImportType='E',@FromDate='2020-02-01 00:00:00',@ToDate='2020-02-18 00:00:00',@UserId=33195,@ImportRow_Id=0        
CREATE   PROC [dbo].[usp_GetEnquiryLeadImportStatus] --'E','01-Mar-2024','08-Mar-2024',39698,0        
(        
    @ImportType varchar(1), -- [E]nquiry, [L]ead        
    @FromDate datetime,        
    @ToDate datetime,        
    @UserId  bigint,        
    @ImportRow_Id bigint=0        
)        
AS        
BEGIN        
        
 DECLARE @ParentId BIGINT = 0;                      
 DECLARE @IsAdmin bit = 0;                      
 DECLARE @RoleType varchar(10);                      
 Declare @TeamCode VARCHAR(20)                                    
        
SELECT @ParentId = ParentID, @IsAdmin = IsAdmin FROM User_Detail(nolock) WHERE User_ID = @UserId;                      
        
if object_id('tempdb..#tblUserIds') is not null begin drop table #tblUserIds end        
        
CREATE TABLE #tblUserIds(        
   UserId bigint  NOT NULL)        
        
select @TeamCode = tum.TeamCode from TBL_UA_TeamUserMappingMaster(nolock) tum        
inner join TBL_UA_TeamMaster(nolock) tm on tm.TeamCode = tum.TeamCode        
where tum.UserId = @UserId        
         
if((@TeamCode is null) and ( @ParentId = @UserId or @IsAdmin = 1))        
Begin        
--set @RoleType = 'Global'        
Insert into #tblUserIds (UserId)        
Select User_Id UserId FROM User_Detail(nolock) where ParentId = @ParentId         
End        
Else if(@TeamCode != null)         
Begin        
---set @RoleType = 'Team'        
Insert into #tblUserIds (UserId)        
Select UserId FROM TBL_UA_TeamUserMappingMaster(nolock) where TeamCode = @TeamCode        
End        
Else         
Begin        
--set @RoleType = 'User'        
Insert into #tblUserIds (UserId)        
select @UserId         
End        
        
    If(@ImportType = 'E')        
    Begin        
    If(@ImportRow_Id > 0)        
    Begin        
    Select  ImportRow_Id, [User_Id], Convert(varchar,ImportDate,0) as ImportDate,         
    IsProcessed = Case when IsProcessed=1 then 'Yes' else 'Under Process' end,         
    IsValid = Case when ISNULL(Remarks,'') = '' and IsProcessed=1 then 'Yes'         
        when ISNULL(Remarks,'') != '' and IsProcessed=1 then 'No' else '' end ,       
  TotalRecords,ImportFilename, case when EnquiryCnt>totalrecords then totalrecords else enquirycnt end totalCount,      
  [Status] =Case  when EnquiryCnt >= TotalRecords and IsProcessed=1  then 'Successful'       
     when  EnquiryCnt =0 and IsProcessed=1 and Remarks IS NOT NULL  then 'Failure'      
     when  EnquiryCnt < TotalRecords and IsProcessed=1 and Remarks IS NOT NULL then 'Partial'      
     else '' end      
  ,ISNULL(Remarks,'') as Remarks  
    --,Remarks = ISNULL(Remarks,'')        
    From  tbl_EnquiryImportSummary        
    Where  [User_Id] in (select UserId From #tblUserIds) and ImportRow_Id = @ImportRow_Id        
    End        
    Else        
    Begin        
    Select  ImportRow_Id, [User_Id], Convert(varchar,ImportDate,0) as ImportDate,         
    IsProcessed = Case when IsProcessed=1 then 'Yes' else 'Under Process' end,         
    IsValid = Case when  IsProcessed=1 then 'Yes'         
        when   IsProcessed=0 then 'No' else '' end  ,      
  TotalRecords,ImportFilename, case when EnquiryCnt+1>totalrecords then totalrecords else enquirycnt end  as  totalCount,      
  [Status] =Case  when EnquiryCnt + 1 >= TotalRecords and IsProcessed=1  then 'Successful'       
     when  EnquiryCnt =0 and IsProcessed=1 and Remarks IS NOT NULL  then 'Failure'      
     when  EnquiryCnt+1 < TotalRecords and IsProcessed=1 and Remarks IS NOT NULL then 'Partial'      
     else '' end   
  ,ISNULL(Remarks,'') as Remarks  
    --,Remarks = ISNULL(Remarks,'')        
    From  tbl_EnquiryImportSummary        
    Where  [User_Id] in (select User_id from User_Detail(nolock) where ParentId=@UserId or User_id=@UserId) and Convert(varchar,ImportDate,106) between @FromDate and @ToDate        
    Order by ImportDate desc        
    End        
    End        
        
    If(@ImportType = 'L')        
    Begin        
    If(@ImportRow_Id > 0)        
    Begin        
    Select  ImportRow_Id, [User_Id], Convert(varchar,ImportDate,0) as ImportDate,         
    IsProcessed = Case when IsProcessed=1 then 'Yes' else 'No' end,         
    IsValid = Case when ISNULL(Remarks,'') = '' then 'Yes' else 'No' end,      
 TotalRecords,ImportFilename, case when LeadCnt>totalrecords then totalrecords else leadcnt end totalCount,      
 [Status] =Case  when LeadCnt >= TotalRecords and IsProcessed=1  then 'Successful'       
     when  LeadCnt =0 and IsProcessed=1 and Remarks IS NOT NULL  then 'Failure'      
     when  LeadCnt < TotalRecords and IsProcessed=1 and Remarks IS NOT NULL then 'Partial'      
     else '' end      
  ,ISNULL(Remarks,'') as Remarks  
    --, Remarks = ISNULL(Remarks,'')        
    From  tbl_LeadImportSummary        
    Where  [User_Id] in (select UserId From #tblUserIds) and ImportRow_Id = @ImportRow_Id        
    End        
    Else        
    Begin        
    Select  ImportRow_Id, [User_Id], Convert(varchar,ImportDate,0) as ImportDate,         
    IsProcessed = Case when IsProcessed=1 then 'Yes' else 'No' end,         
    IsValid = Case when ISNULL(Remarks,'') = '' then 'Yes' else 'No' end ,      
 TotalRecords,ImportFilename, case when LeadCnt>totalrecords then totalrecords else leadcnt end totalCount,      
 [Status] =Case  when LeadCnt >= TotalRecords and IsProcessed=1  then 'Successful'       
     when  LeadCnt =0 and IsProcessed=1 and Remarks IS NOT NULL  then 'Failure'      
     when  LeadCnt < TotalRecords and IsProcessed=1 and Remarks IS NOT NULL then 'Partial'      
     else '' end    
  ,ISNULL(Remarks,'') as Remarks  
    --, Remarks = ISNULL(Remarks,'')        
    From  tbl_LeadImportSummary        
    Where  [User_Id] in (select User_id from User_Detail(nolock) where ParentId=@UserId or User_id=@UserId) and Convert(varchar,ImportDate,106) between @FromDate and @ToDate        
    Order by ImportDate desc        
    End        
    End        
        
END 


