										Order by ImportDate desc  
									End  
						End  
					
						If(@ImportType = 'L')  
						Begin  
							If(@ImportRow_Id > 0)  
								Begin  
									Select	    
											ImportRow_Id,
											[User_Id], 
											Convert(varchar,ImportDate,0) as ImportDate,   
											IsProcessed, 
											IsValid,
											TotalRecords,
											ImportFilename, 
											totalCount,
											[Status] 
											From  [tbl_ImportLeadStatus_Cache]  
									Where  [User_Id] in (select UserId From #tblUserIds) and ImportRow_Id = @ImportRow_Id  
								End  
							Else  
								Begin  
									Select 
											ImportRow_Id,
											[User_Id], 
											Convert(varchar,ImportDate,0) as ImportDate,   
											IsProcessed, 
											IsValid,
											TotalRecords,
											ImportFilename, 
											totalCount,
											[Status] 
											From  [tbl_ImportLeadStatus_Cache]  
									Where  [User_Id] in (select User_id from Mysms.dbo.User_Detail(nolock) where ParentId=@UserId or User_id=@UserId) and Convert(varchar,ImportDate,106) between @FromDate and @ToDate  
									Order by ImportDate desc  
								End  
						End  
				END
				ELSE IF (@FromDate < @MonthStart OR @ToDate < @MonthStart)
				BEGIN
						If(@ImportType = 'E')  
						Begin  
								If(@ImportRow_Id > 0)  
									Begin  
										Select 
												ImportRow_Id,
												[User_Id], 
												Convert(varchar,ImportDate,0) as ImportDate,   
