/* ============================================================
   Procedure: [dbo].[usp_GetEnquiryLeadTemplateMsg]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

    
-- exec usp_GetEnquiryLeadTemplateMsg 335, 0, 204849    
CREATE  PROCEDURE [dbo].[usp_GetEnquiryLeadTemplateMsg]    
(    
    @UserID INT,    
    @EnquiryId bigint=0,    
    @LeadId bigint=0    
)    
AS            
BEGIN    
  
 -- Declare @UserID INT = 32821,  @EnquiryId bigint=0 ,  @LeadId bigint=316338  
  
   
    
    Declare @UName varchar(100)='', @PName varchar(100)='', @LeadNo varchar(20)='', @NextStartDate varchar(25)='', @CompanyName varchar(100)='', @Msg varchar(500)='', @EmailId varchar(50)='', @MobileNo varchar(20)='' ,   
 @Followup varchar(100)='', @Remarks varchar(1000)='', @FollowupDate varchar(200)  
    
    
    Select @UName=rtrim(ltrim(isnull(FName,'') + ' ' + isnull(LName,'')))    
    
    from user_detail    
    where USER_ID=@UserID    
    
    Select @CompanyName=isnull(' - ' + CompnayName,'')    
    from user_detail    
    where USER_ID in (select ParentID from user_detail where USER_ID=@UserID)    
    
    
    If(@EnquiryId=0 and @LeadId=0)    
    Begin    
    select EMail, Mobile, '' as  SMSMsg, '' as EmailMsg    
    from user_detail    
    where USER_ID=@UserID    
    End    
    
    If(@EnquiryId > 0 and @LeadId = 0)    
    Begin    
    Select  @LeadNo='Lead No: ' + cast(UL.LeadNo as varchar(10)), @NextStartDate=isnull(left(UL.NextStatusDate,10),''), @PName = 'Lead Name: ' + UL.PersonName,    
    @MobileNo='M: ' + coalesce(UE.CountryCode,UE.CountryCode1,UE.CountryCode2,'') + ' ' + coalesce(UE.MobileNo,UE.MobileNo1,UE.MobileNo2), @EmailId= 'E: ' + coalesce(UE.EmailID,UE.EmailID1,UE.EmailID2)    
    from  UserEnquiry UE (nolock) inner Join UserLeads UL (nolock)   
    On  UE.LeadNo = UL.LeadNo and UE.ParentID = UL.ParentID    
    Where  UE.EnquiryID=@EnquiryId    
    
    Set @Msg = 'Dear ' + @UName + ', A new lead ' + isnull('' + @LeadNo, '') + isnull(', ' + @PName,'') + isnull(', ' + @MobileNo,'') + isnull(', ' + @EmailId,'') +  ' has been assigned to you. ' + @CompanyName    
    
    select EMail, Mobile, @Msg as SMSMsg, @Msg as EmailMsg    
    from user_detail  (nolock)  
    where USER_ID=@UserID    
    End    
    
    If(@EnquiryId = 0 and @LeadId > 0)    
    Begin    
    Select  @LeadNo='Lead No: ' + cast(UL.LeadNo as varchar(10)), @NextStartDate=isnull(left(UL.NextStatusDate,10),''), @PName = 'Lead Name: ' + UL.PersonName,    
    @MobileNo='M: ' + coalesce(UL.CountryCode,UL.CountryCode1,UL.CountryCode2,'') + ' ' + coalesce(UL.MobileNo,UL.MobileNo1,UL.MobileNo2), @EmailId= 'E: ' + coalesce(UL.EmailID,UL.EmailID1,UL.EmailID2),    
 @Followup = fs.FollowupStatus, @Remarks = 'Remarks: '+ul.Remarks, @FollowupDate = 'On '+convert(varchar(100),ul.FollowupDate,100)  
    from  UserLeads UL (nolock)  left outer join FollowUp_Status fs (nolock) on ul.FollowUpStatus = fs.ID  
    Where  UL.ID=@LeadId    
    
    Set @Msg = 'Dear ' + @UName + ', This is a Reminder message for ' + isnull(@Followup, '')+' for ' + isnull('' + @LeadNo, '') + isnull(', ' + @PName,'') + isnull(', ' + @MobileNo,'') + isnull(', ' + @EmailId,'')+ isnull(', ' + @Remarks,'') +  isnull(', ' 
+ @FollowupDate,'')     
    
    select EMail, Mobile, @Msg as SMSMsg, @Msg as EmailMsg    
    from user_detail   (nolock)  
    where USER_ID=@UserID    
    End   
	
	If(@EnquiryId = -1 and @LeadId > 0)    
    Begin    
    Select  @LeadNo='Lead No: ' + cast(UL.LeadNo as varchar(10)), @NextStartDate=isnull(left(UL.NextStatusDate,10),''), @PName = 'Lead Name: ' + UL.PersonName,    
    @MobileNo='M: ' + coalesce(UL.CountryCode,UL.CountryCode1,UL.CountryCode2,'') + ' ' + coalesce(UL.MobileNo,UL.MobileNo1,UL.MobileNo2), @EmailId= 'E: ' + coalesce(UL.EmailID,UL.EmailID1,UL.EmailID2),    
 @Followup = fs.FollowupStatus, @Remarks = 'Remarks: '+ul.Remarks, @FollowupDate = 'On '+convert(varchar(100),ul.FollowupDate,100)  
    from  UserLeads UL (nolock)  left outer join FollowUp_Status fs (nolock) on ul.FollowUpStatus = fs.ID  
    Where  UL.ID=@LeadId    
    
    Set @Msg = 'Dear ' + @UName + ', A new lead ' + isnull('' + @LeadNo, '') + isnull(', ' + @PName,'') + isnull(', ' + @MobileNo,'') + isnull(', ' + @EmailId,'') +  ' has been assigned to you. ' + @CompanyName    
-- Set @Msg = 'Dear ' + @UName + ', This is a Reminder message for ' + isnull(@Followup, '')+' for ' + isnull('' + @LeadNo, '') + isnull(', ' + @PName,'') + isnull(', ' + @MobileNo,'') + isnull(', ' + @EmailId,'')+ isnull(', ' + @Remarks,'') +  isnull(', ' 
--+ @FollowupDate,'')     
    
    select EMail, Mobile, @Msg as SMSMsg, @Msg as EmailMsg    
    from user_detail   (nolock)  
    where USER_ID=@UserID    
    End   
    
END     
  


GO

/* ============================================================
   Procedure: [dbo].[usp_GetEnquiryLeadUpdateImportStatus]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

  
CREATE   PROCEDURE [dbo].[usp_GetEnquiryLeadUpdateImportStatus]  --43966,'01-Aug-2024','07-Sep-2024','L',0,'view'   
@userid bigint =null,    
@fromDate datetime = null,    
@toDate datetime = null,    
@importtype varchar(50) = null,     
@ImportRow_Id bigint=0,       
@mode nvarchar(10) = null    
As    
BEGIN    
     
 Drop table if exists #tblUserIds    
 Declare @remarks nvarchar(max)    
 CREATE TABLE #tblUserIds(        
 UserId bigint  NOT NULL,    
 UserName nvarchar(100),    
 Image nvarchar(100))        
    
 Insert into #tblUserIDs     
 exec Use_GetUserDetails @userid    
    
 --select * from #tblUserIDs    
 if(@mode='view')    
 begin    
 if @importtype = 'L'     
 BEGIN    
  if(@ImportRow_id>0)    
  BEGIN    
   SELECT ImportRow_Id,[User_Id],  [dbo].[fn_getusertimefromindiantime](@userid,Importdate) Importdate,    
    Case IsProcessed WHen 0 Then 'No' ELse 'Yes' End IsProcessed,     
    Case IsValid When 0 Then 'No' Else 'Yes' End IsValid , TotalRecords, ImportFileName, LeadCnt totalCount,     
    [Status] = Case  when LeadCnt = TotalRecords and IsProcessed=1  then 'Successful'       
    when  LeadCnt =0 and IsProcessed=1 and Remarks IS NOT NULL  then 'Failure'      
    when  LeadCnt < TotalRecords and IsProcessed=1 and Remarks IS NOT NULL then 'Partial'      
    else '' end ,Remarks  FROM Tbl_Lead_LeadUpdateImportData     
    WHERE USER_ID in (Select UserId from #tblUserIds) and ImportRow_Id=@ImportRow_Id    
  END    
    
  Else     
  BEGIN    
       
   SELECT ImportRow_Id,[User_Id], [dbo].[fn_getusertimefromindiantime](@userid,Importdate) Importdate,     
    Case IsProcessed WHen 0 Then 'No' ELse 'Yes' End IsProcessed,     
    Case IsValid When 0 Then 'No' Else 'Yes' End IsValid , ImportFileName, TotalRecords, LeadCnt totalCount,     
    [Status] = Case  when LeadCnt = TotalRecords and IsProcessed=1  then 'Successful'       
    when  LeadCnt =0 and IsProcessed=1 and Remarks IS NOT NULL  then 'Failure'      
    when  LeadCnt < TotalRecords and IsProcessed=1 and Remarks IS NOT NULL then 'Partial'      
    else '' end ,Remarks  FROM Tbl_Lead_LeadUpdateImportData     
    WHERE USER_ID in (Select UserId from #tblUserIds) and  Convert(varchar,ImportDate,106)  between @fromDate and @todate    
    order by importdate desc    
  END    
    
 END     
    
 if @importtype = 'E'     
 BEGIN    
  if(@ImportRow_id>0)    
  BEGIN    
   SELECT ImportRow_Id, [User_Id],[dbo].[fn_getusertimefromindiantime](@userid,Importdate) Importdate,     
    Case IsProcessed WHen 0 Then 'No' ELse 'Yes' End IsProcessed,     
    Case ISNULL(IsValid,0) When 0 Then 'No' Else 'Yes' End IsValid , ImportFileName, TotalRecords, EnquiryCnt TotalCount,      
    [Status] = Case  when EnquiryCnt = TotalRecords and IsProcessed=1  then 'Successful'       
    when  EnquiryCnt =0 and IsProcessed=1 and Remarks IS NOT NULL  then 'Failure'      
    when  EnquiryCnt < TotalRecords and IsProcessed=1 and Remarks IS NOT NULL then 'Partial'      
    else '' end ,Remarks  FROM Tbl_Enquiry_EnquiryUpdateImportData     
    WHERE USER_ID in (Select UserId from #tblUserIds) and ImportRow_Id=@ImportRow_Id    
  END    
    
  Else     
  BEGIN    
       
   SELECT ImportRow_Id, [User_Id] , [dbo].[fn_getusertimefromindiantime](@userid,Importdate) Importdate,     
    Case IsProcessed WHen 0 Then 'No' ELse 'Yes' End IsProcessed,     
    Case ISNULL(IsValid,0) When 0 Then 'No' Else 'Yes' End IsValid , ImportFileName, TotalRecords, EnquiryCnt TotalCount,      
    [Status] = Case  when EnquiryCnt = TotalRecords and IsProcessed=1  then 'Successful'       
    when  EnquiryCnt =0 and IsProcessed=1 and Remarks IS NOT NULL  then 'Failure'      
    when  EnquiryCnt < TotalRecords and IsProcessed=1 and Remarks IS NOT NULL then 'Partial'      
    else '' end ,Remarks  FROM Tbl_Enquiry_EnquiryUpdateImportData     
    WHERE USER_ID in (Select UserId from #tblUserIds) and  Convert(varchar,ImportDate,106)  between @fromDate and  @todate    
    order by importdate desc    
  END    
    
 END     
 end    
       
  else if @mode ='Download'    
  begin    
      
  if @importtype = 'L'    
  begin     
   select @remarks= Remarks from  Tbl_Lead_LeadUpdateImportData where ImportRow_Id = @ImportRow_Id    
   select Sno, FieldName , Remarks from openjson(@remarks)    
   with (Sno nvarchar(10), FieldName nvarchar(max) , Remarks Nvarchar(max))   
  end    
  if @importtype = 'E'     
  begin    
   select @remarks= Remarks from  Tbl_Enquiry_EnquiryUpdateImportData where ImportRow_Id = @ImportRow_Id    
  end    
   select SNo, Field FieldName , Remarks from openjson(@remarks)    
   with (SNo nvarchar(10), Field nvarchar(max) , Remarks Nvarchar(max))    
  end    
END     


GO

