											  ,[ImportDate]
											  ,[IsProcessed]
											  ,[IsValid]
											  ,[TotalRecords]
											  ,[ImportFilename]
											  ,[totalCount]
											  ,[Status]  
										 FROM tbl_LeadUpdateImportStatus_Cache(nolock) 
								WHERE USER_ID in (Select UserId from #tblUserIds) and  Convert(varchar,ImportDate,106)  between @fromDate and @todate  
								order by importdate desc  
							  END  
						 END   
  
						 if @importtype = 'E'   
						 BEGIN  
							  if(@ImportRow_id>0)  
							  BEGIN  
									SELECT 
									   [ImportRow_Id]
									  ,[User_Id]
									  ,[ImportDate]
									  ,[IsProcessed]
									  ,[IsValid]
									  ,[TotalRecords]
									  ,[ImportFilename]
									  ,[totalCount]
									  ,[Status]  
								  FROM tbl_EnquiryUpdateImportStatus_Cache(nolock)   
								WHERE USER_ID in (Select UserId from #tblUserIds) and ImportRow_Id=@ImportRow_Id  
							  END  
  
							  Else   
							  BEGIN  
									SELECT 
								   [ImportRow_Id]
								  ,[User_Id]
								  ,[ImportDate]
								  ,[IsProcessed]
								  ,[IsValid]
								  ,[TotalRecords]
								  ,[ImportFilename]
								  ,[totalCount]
								  ,[Status]  
							  FROM tbl_EnquiryUpdateImportStatus_Cache(nolock)  
							WHERE USER_ID in (Select UserId from #tblUserIds) and  Convert(varchar,ImportDate,106)  between @fromDate and  @todate  
							order by importdate desc  
						      END  
						 END  
					END
				ELSE IF (@FromDate < @MonthStart OR @ToDate < @MonthStart)
					BEGIN
						 if @importtype = 'L'   
						 BEGIN  
							  if(@ImportRow_id>0)  
							  BEGIN  
									 SELECT  
									           [ImportRow_Id]
											  ,[User_Id]
											  ,[ImportDate]
											  ,[IsProcessed]
											  ,[IsValid]
											  ,[TotalRecords]
											  ,[ImportFilename]
											  ,[totalCount]
											  ,[Status]  
										 FROM tbl_LeadUpdateImportStatus_Archive(nolock)
										WHERE USER_ID in (Select UserId from #tblUserIds) and ImportRow_Id=@ImportRow_Id  
							  END  
							  Else   
							  BEGIN  
									 SELECT 
											   [ImportRow_Id]
											  ,[User_Id]
											  ,[ImportDate]
											  ,[IsProcessed]
											  ,[IsValid]
											  ,[TotalRecords]
											  ,[ImportFilename]
											  ,[totalCount]
											  ,[Status]  
