										WHERE USER_ID in (Select UserId from #tblUserIds) and  Convert(varchar,ImportDate,106)  between @fromDate and @todate  order by importdate desc  
							  END  
						 END   
  
						 if @importtype = 'E'   
						 BEGIN  
							  if(@ImportRow_id>0)  
							  BEGIN  
									SELECT 
