									  ,[User_Id]
									  ,[ImportDate]
									  ,[IsProcessed]
									  ,[IsValid]
									  ,[TotalRecords]
									  ,[ImportFilename]
									  ,[totalCount]
									  ,[Status]  
								  FROM tbl_EnquiryUpdateImportStatus_Archive(nolock)   
								WHERE USER_ID in (Select UserId from #tblUserIds) and ImportRow_Id=@ImportRow_Id  
							  END  
  
							  Else   
