   Procedure: [dbo].[usp_GetEnquiryMappingByDropdownSelection]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[usp_GetEnquiryMappingByDropdownSelection]
    @MappingId BIGINT,
	@Mode nvarchar(200)
AS
BEGIN
    SET NOCOUNT ON;

    DECLARE @ExcelColumns NVARCHAR(MAX);
    DECLARE @MappingDetails NVARCHAR(MAX);
	if(@Mode='Original')
	begin
	      SELECT 
        @ExcelColumns = ExcelColumns
    FROM 
       Enquiry_FieldMappingDetails
    WHERE 
        EField_MappingId = @MappingId;
    SELECT 
        OriginalColumn = JSON_TABLE.[value]
    FROM 
        OPENJSON(@ExcelColumns) AS JSON_TABLE;
    
  end
  else
  begin
  SELECT 
        @MappingDetails = MappingDetails,
        @ExcelColumns = ExcelColumns
    FROM 
        Enquiry_FieldMappingDetails
    WHERE 
        EField_MappingId = @MappingId;
    SELECT 
        COLUMN_NAME = JSON_TABLE.[value]
    FROM 
        OPENJSON(@MappingDetails) AS JSON_TABLE
    WHERE 
        JSON_TABLE.[value] NOT LIKE '%Other Field%';
		end
END;





