    --  ,[callname]    
    --  ,[dnid]    
        ,[recordurl]    
      --,[uniqueid]    
  FROM [CallLog] with(nolock)     
  where isnull(customerentity,'') = @EntityName and ISNULL(customerentityid,0) = @EntityID order by id desc     
    offset @offsets rows fetch next @pageSize rows only             
  
  
End


