/* ============================================================
   Procedure: [dbo].[usp_getEnquiryReport]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_getEnquiryReport] --34594,34594,'20220101','20220617'   --40204,40204,'20220601','20220607'                      
   @userid bigint,@parentid bigint,@fromdate date,@todate date ,@Isflag bit   ,@strCriteriaName nvarchar(max)  =''                  
as                      
begin    
 /*    
Source New Enquiries Enquiries converted to leads Enquiries matching existing leads Open Enquiries not matching leads     
          
Agent  New Enquiries Created Enquiries converted to leads        
*/    
  -- declare @parentid bigint=40204,@userid bigint=40204,@fromdate nvarchar(20)='20220601',@todate nvarchar(20)='20220607'    
  
        --Declare @UserIdTeamLst varchar(Max) = ''   
  Declare @IsAdmin bit = 0  
  
        declare @tbluser table (User_ID bigint,Name varchar(100), Image varchar(100))  
   select  @IsAdmin = isnull(IsAdmin,0) from User_Detail(nolock) where User_ID = @UserID   
   if(@IsAdmin = 1)  
   Begin  
   insert into @tbluser  
   exec Use_GetUserDetails @ParentId  
   end   
  else  
  Begin  
   insert into @tbluser  
   exec Use_GetUserDetails @UserID  
  End  
  --select @UserIdTeamLst=isnull(STRING_AGG(User_ID,','),'') From @tbluser     
  
 -- Print @Isflag
 if(@strCriteriaName='')
 begin
IF (@Isflag = 1)

	BEGIN	   
select FORMAT( start_dts, 'dd MMM yyyy') as Date, s.name as Source,isnull(m.name,'') as Medium,isnull(cs.name,'') as Campaign,    
count(1) as NewEnquiries,sum(case when isopen=0 then 1 else 0 end) as EnquiriesConvertedToLeads,    
sum(case when isnull(leadno,0) <>0 then 1 else 0 end) as EnquiriesmatchingLeads,    
sum(case when isopen=1 then 1 else 0 end) as OpenEnquiries,    
sum(case when isnull(leadno,0) =0 then 1 else 0 end) as EnquiriesNotmatchingLeads  
from     
calendar c (nolock)  join    
userenquiry u(nolock) on cast(start_dts as date)=cast(u.createddate as date)    
left join UserSourceSettings (nolock) s on s.SourceID=u.sourcename    
left join UserMediumSettings (nolock) m on m.MediumID=u.MediumName    
left join UserCampaignSettings (nolock) cs on cs.CampaignID=u.campaignname 
left join user_detail UD (nolock) on UD.User_ID=cs.UserID
where (  
        --u.parentid is null   
  --or   
     u.parentid=@parentid  
   )    
and c.start_dts between @fromdate and @todate  
  
and u.CreatedBy in (select isnull(USER_ID,0) from @tbluser)  
    
group by s.name,m.name,cs.name,FORMAT( start_dts, 'dd MMM yyyy'),cast(u.createddate as date)    
order by FORMAT( start_dts, 'dd MMM yyyy')    
	END


ELSE

	BEGIN
	 
select FORMAT( start_dts, 'dd MMM yyyy') as Date,     
dbo.fn_getentityfullname('user',u.CreatedBy) as AgentName,    
count(1) as NewEnquiries,    
count(t.createdby) EnquiriesConvertedToLeads,  
count(t1.createdbyMatchLeads) EnquiriesmatchingLeads ,  
count(t2.CreatedByOpenEnquiry) OpenEnquiries,  
count(t3.CreatedByEnquiriesNotmatchingLeads) EnquiriesNotmatchingLeads,  
   u.CreatedBy    
from     
calendar c (nolock)  join    
userenquiry u(nolock) on cast(start_dts as date)=cast(u.createddate as date)    
left join    
(select e.createdby,enquiryid--,l.id    
--from tbl_MergeLeadsEnquiry(nolock) t   
--join userleads(nolock) l on t.leadno=l.leadno and l.parentid=@parentid    
 from userenquiry(nolock) e  
  --on e.EnquiryID=t.EnquiryNo     
 where isnull( e.IsOpen,0) = 0 and cast(e.Createddate as date) between @fromdate and @todate    
) t on t.createdby=u.createdby and t.EnquiryID=u.EnquiryID  
left join    
(select ml.createdby as createdbyMatchLeads ,ml.EnquiryID    
 from userenquiry(nolock) ml   
 where isnull( ml.LeadNo,0) <> 0 and cast(ml.Createddate as date) between @fromdate and @todate    
) t1 on t1.createdbyMatchLeads=u.createdby and t1.EnquiryID=u.EnquiryID  
left join    
(select OE.createdby as CreatedByOpenEnquiry ,OE.EnquiryID    
 from userenquiry(nolock) as OE   
 where isnull( OE.IsOpen,0) = 1 and cast(OE.Createddate as date) between @fromdate and @todate    
) t2 on t2.CreatedByOpenEnquiry=u.createdby and t2.EnquiryID=u.EnquiryID  
left join    
(select ENotMatching.createdby as CreatedByEnquiriesNotmatchingLeads ,ENotMatching.EnquiryID    
 from userenquiry(nolock) as ENotMatching   
 where isnull( ENotMatching.LeadNo,0) = 0 and cast(ENotMatching.Createddate as date) between @fromdate and @todate    
) t3 on t3.CreatedByEnquiriesNotmatchingLeads=u.createdby and t3.EnquiryID=u.EnquiryID  
  
   
  
where  
  ( --u.parentid is null  
    --or   
    u.parentid=@parentid  
  )  
 and u.CreatedBy in (select isnull(USER_ID,0) from @tbluser)     
and c.start_dts between @fromdate and @todate    
group by dbo.fn_getentityfullname('user',u.CreatedBy),FORMAT( start_dts, 'dd MMM yyyy'),cast(u.createddate as date),u.CreatedBy    
order by FORMAT( start_dts, 'dd MMM yyyy')    
    

	END

	end
	else
	begin
	
DECLARE @listtopivot NVARCHAR(MAX) = '';  
DECLARE @sql NVARCHAR(MAX);  
DECLARE @ListPivotSelect NVARCHAR(MAX) = '',@ListPivotSelectClickable NVARCHAR(MAX) = '';  
 
        DECLARE @HierarchyJSON nvarchar(max);  
        DECLARE @FormattedUsername NVARCHAR(MAX);  
        DECLARE @FormattedHierarchyPath NVARCHAR(MAX);  
     
  
       
	   
	   CREATE TABLE #HierarchyDetail  
        (  
            User_id BIGINT,  
            UserName NVARCHAR(MAX),  
            Parentid BIGINT  
        );  
  
        IF EXISTS (SELECT 1 FROM tbl_UA_UserHierarchy (NOLOCK) WHERE ParentId = @ParentId AND IsActive = 1)  
        BEGIN  
            SELECT @HierarchyJSON = HierarchyJSON   
            FROM tbl_UA_UserHierarchy (NOLOCK)   
            WHERE IsActive = 1 AND ParentId = @ParentId;  
  
            INSERT INTO #HierarchyDetail  
            SELECT DISTINCT uh.User_id, uh.UserName, uh.Parentid  
            FROM OPENJSON(@HierarchyJSON) WITH   
            (  
                parentid BIGINT,  
                username NVARCHAR(500),  
                user_id BIGINT  
            ) UH   
            INNER JOIN User_detail (NOLOCK) UD  
                ON UH.user_id = UD.user_ID;  
        END  
        ELSE IF EXISTS (SELECT 1 FROM tbl_UA_RoleHierarchy (NOLOCK) WHERE ParentId = @ParentId AND IsActive = 1)  
        BEGIN  
            PRINT 'Role Hierarchy';          
   
            SELECT @HierarchyJSON = HierarchyJSON   
            FROM tbl_UA_RoleHierarchy (NOLOCK)   
            WHERE IsActive = 1 AND ParentId = @ParentId;  
  
            SELECT DISTINCT parentid  
            INTO #UserRoleHierarchy1  
            FROM OPENJSON(@HierarchyJSON) WITH   
            (  
                parentid BIGINT  
            );  
  
            INSERT INTO #HierarchyDetail  
            SELECT UH.Parentid, FName + ' ' + LName AS username, user_id   
            FROM #UserRoleHierarchy1 UH  
            LEFT JOIN User_Detail UD ON UD.User_ID = UH.parentid    
            WHERE FName IS NOT NULL AND LName IS NOT NULL;  
  
            DROP TABLE #UserRoleHierarchy1;  
        END;  
  
  --select * from #HierarchyDetail
    

	IF (@Isflag = 1)

	BEGIN	   
select FORMAT( start_dts, 'dd MMM yyyy') as Date, s.name as Source,isnull(m.name,'') as Medium,isnull(cs.name,'') as Campaign,    
count(1) as NewEnquiries,sum(case when isopen=0 then 1 else 0 end) as EnquiriesConvertedToLeads,    
sum(case when isnull(leadno,0) <>0 then 1 else 0 end) as EnquiriesmatchingLeads,    
sum(case when isopen=1 then 1 else 0 end) as OpenEnquiries,    
sum(case when isnull(leadno,0) =0 then 1 else 0 end) as EnquiriesNotmatchingLeads  
from     
calendar c (nolock)  join    
userenquiry u(nolock) on cast(start_dts as date)=cast(u.createddate as date)    
left join UserSourceSettings (nolock) s on s.SourceID=u.sourcename    
left join UserMediumSettings (nolock) m on m.MediumID=u.MediumName    
left join UserCampaignSettings (nolock) cs on cs.CampaignID=u.campaignname 
left join user_detail UD (nolock) on UD.User_ID=cs.UserID
where (  
        --u.parentid is null   
  --or   
     u.parentid=@parentid  
   )    
and c.start_dts between @fromdate and @todate  
  
and u.CreatedBy  in (select isnull(USER_ID,0) from #HierarchyDetail where ParentID=@strCriteriaName) or u.CreatedBy =@strCriteriaName
  
    
group by s.name,m.name,cs.name,FORMAT( start_dts, 'dd MMM yyyy'),cast(u.createddate as date)    
order by FORMAT( start_dts, 'dd MMM yyyy')    
	END


ELSE

	BEGIN
	
select FORMAT( start_dts, 'dd MMM yyyy') as Date,     
dbo.fn_getentityfullname('user',u.CreatedBy) as AgentName,    
count(1) as NewEnquiries,    
count(t.createdby) EnquiriesConvertedToLeads,  
count(t1.createdbyMatchLeads) EnquiriesmatchingLeads ,  
count(t2.CreatedByOpenEnquiry) OpenEnquiries,  
count(t3.CreatedByEnquiriesNotmatchingLeads) EnquiriesNotmatchingLeads,  
   u.CreatedBy    
from     
calendar c (nolock)  join    
userenquiry u(nolock) on cast(c.start_dts as date)=cast(u.createddate as date)  and cast(u.Createddate as date) between @fromdate and @todate    
left join    
(select e.createdby,enquiryid--,l.id    
--from tbl_MergeLeadsEnquiry(nolock) t   
--join userleads(nolock) l on t.leadno=l.leadno and l.parentid=@parentid    
 from userenquiry(nolock) e  
  --on e.EnquiryID=t.EnquiryNo     
 where isnull( e.IsOpen,0) = 0 and cast(e.Createddate as date) between @fromdate and @todate    
) t on t.createdby=u.createdby and t.EnquiryID=u.EnquiryID  
left join    
(select ml.createdby as createdbyMatchLeads ,ml.EnquiryID    
 from userenquiry(nolock) ml   
 where isnull( ml.LeadNo,0) <> 0 and cast(ml.Createddate as date) between @fromdate and @todate    
) t1 on t1.createdbyMatchLeads=u.createdby and t1.EnquiryID=u.EnquiryID  
left join    
(select OE.createdby as CreatedByOpenEnquiry ,OE.EnquiryID    
 from userenquiry(nolock) as OE   
 where isnull( OE.IsOpen,0) = 1 and cast(OE.Createddate as date) between @fromdate and @todate    
) t2 on t2.CreatedByOpenEnquiry=u.createdby and t2.EnquiryID=u.EnquiryID  
left join    
(select ENotMatching.createdby as CreatedByEnquiriesNotmatchingLeads ,ENotMatching.EnquiryID    
 from userenquiry(nolock) as ENotMatching   
 where isnull( ENotMatching.LeadNo,0) = 0 and cast(ENotMatching.Createddate as date) between @fromdate and @todate    
) t3 on t3.CreatedByEnquiriesNotmatchingLeads=u.createdby and t3.EnquiryID=u.EnquiryID  
  
   
  
where  
  ( --u.parentid is null  
    --or   
    u.parentid=@parentid  
  )  
and u.CreatedBy  in (select isnull(USER_ID,0) from #HierarchyDetail where ParentID=@strCriteriaName) or u.CreatedBy =@strCriteriaName    
and c.start_dts between @fromdate and @todate    
group by dbo.fn_getentityfullname('user',u.CreatedBy),FORMAT( start_dts, 'dd MMM yyyy'),cast(u.createddate as date),u.CreatedBy    
order by FORMAT( start_dts, 'dd MMM yyyy')    
    

	END

	end
   
end 

