/* ============================================================
   Procedure: [dbo].[usp_getentitydateplaceholders]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_getentitydateplaceholders] --31871,'lead'        
(@parentid bigint,@entity nvarchar(20))        
as        
begin        
--declare @parentid bigint=31871,@entity nvarchar(20)='lead'        
drop table if exists #eph        
create table #eph(fieldnameexposed nvarchar(200),fieldnameactual nvarchar(200),fieldtype nvarchar(10),fielddatatype nvarchar(20))        
insert into #eph(fieldnameexposed,fieldnameactual,fieldtype,fielddatatype)        
select * from        
(        
select cast(@entity+'.'+name as nvarchar(200)) fieldnameexposed,
cast(@entity+'.'+name as nvarchar(200)) fieldnameactual,'predefined'
 as fieldtype,'Datetime' fielddatatype from sys.all_columns (nolock)    
where object_id=(select object_id from sys.tables where name=case when @entity='lead' then 'userleads'         
when @entity='enquiry' then 'userenquiry' end)  and system_type_id=61       
and name not in ('id','ModifiedOn','ModifiedBy','FollowupDate','LeadImage','temp_id','img_ext',
'ProfileImgFileName','enquirysource','WhatsAppNoColName','LastFollowupCreatedBy','parentid',    
     'IsOpen','IsduplicateEmail','IsduplicateMobile','EnquiryID','whereaddress','logitude','latitude','LastFollowupCreatedON')        
union all        
select cast(@entity+'.'+fieldname as nvarchar(200)) fieldnameexposed,cast(@entity+'.'+fieldname as nvarchar(200)) fieldnameactual,'custom' fieldtype 
,'Date' fielddatatype from customfields(nolock) where parentid=@parentid and datatype in ('d')) a         
select * from #eph        
drop table if exists #eph        
end 


GO

/* ============================================================
   Procedure: [dbo].[USP_GetEntityDetailsSummeryWithPagingCustomButton]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

-------------------------------------------------

CREATE   PROCEDURE USP_GetEntityDetailsSummeryWithPagingCustomButton  
@WebhookURL NVARCHAR(MAX),  
@BatchSize INT,  
@Offset INT,  
@ProcessedEntityIds NVARCHAR(MAX) = NULL  
AS  
BEGIN  
    SET NOCOUNT ON;  
  
    -- Create a temporary table to store the processed entity IDs  
    CREATE TABLE #ProcessedEntityIds (EntityId BIGINT);  
  
    -- Insert the processed entity IDs into the temporary table from JSON  
    IF @ProcessedEntityIds IS NOT NULL  
    BEGIN  
        INSERT INTO #ProcessedEntityIds (EntityId)  
        SELECT value FROM OPENJSON(@ProcessedEntityIds) WITH (value BIGINT);  
    END;  
  
    -- Select the required data while excluding the processed entity IDs  
    SELECT DISTINCT  
        s.WebHookID,  
        s.UserID,  
        s.WebhookURL,  
        s.EntityType,  
        s.EntityId,  
        s.CreatedDate,  
        s.IsProcessed,  
        s.Params,  
        s.ErrorDetails,  
        ROW_NUMBER() OVER (ORDER BY s.EntityId) AS SerialNo  
    INTO #TempBatchDetails  
    FROM  
        tbl_cb_webhook_restbl s WITH (NOLOCK)  
    WHERE  
        --s.BatchID = @BatchID  
        s.WebhookURL = 'http://sipapidev.kit19.com/Enquiry/SendIntlSmsOneToMany'  
        AND s.IsProcessed = 0  
        AND (NOT EXISTS (SELECT 1 FROM #ProcessedEntityIds p WHERE p.EntityId = s.EntityId) OR @ProcessedEntityIds IS NULL);  
  
    -- Fetch the required page of data  
    SELECT  
          
        WebHookID,  
        UserID,  
        WebhookURL,  
        EntityType,  
        EntityId,  
        CreatedDate,  
        IsProcessed,  
        Params,  
        ErrorDetails,  
        SerialNo  
    FROM  
        #TempBatchDetails  
    ORDER BY  
        SerialNo  
    OFFSET @Offset ROWS  
    FETCH NEXT @BatchSize ROWS ONLY;  
  
    -- Drop the temporary tables  
    DROP TABLE #ProcessedEntityIds;  
    DROP TABLE #TempBatchDetails;  
END;




GO

/* ============================================================
   Procedure: [dbo].[Usp_getEntityLatLong]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

-- Usp_getEntityLatLong 'lead', 2725397, 28.594022, 77.30742, 6, 40584
CREATE   PROCEDURE [dbo].[Usp_getEntityLatLong]    
(    
@EntityType varchar(200),
@EntityId bigint,
@CurrentLatitude float,
@CurrentLongitude float,
@RadiusDistance bigint = 1000,
@TypeDistance varchar(10) = 'KM',
@UserId bigint    
)
as
Begin
Declare @ParentId bigint
select @ParentId = ParentID from User_detail (nolock) ud where ud.User_ID = @UserId
declare @newMeter float = ((@RadiusDistance * 1000) * 0.1 / 10000);
if(@TypeDistance = 'KM')
Begin
set @newMeter = ((@RadiusDistance * 1000) * 0.1 / 10000);
End
else if(@TypeDistance = 'MI')
Begin
set @newMeter = ((@RadiusDistance * 1.60934 * 1000) * 0.1 / 10000);
End
else
Begin
set @newMeter = ((@RadiusDistance * 1000) * 0.1 / 10000);
End
declare @lat1 float = @CurrentLatitude - @newMeter;
declare @lat2 float = @CurrentLatitude + @newMeter;
declare @lon1 float = @CurrentLongitude - @newMeter;
declare @lon2 float = @CurrentLongitude + @newMeter;

--select @lat1 lat1, @lon1 lon1, @lat2 lat2, @lon2 lon2
if(@EntityType = 'lead')
Begin
select Id, LeadNo, PersonName, '' PersonImage, CompanyName, MobileNo, MobileNo1, MobileNo2, 
CountryCode, CountryCode1, CountryCode2, EmailID, EmailID1, EmailID2, City, State, Country, 
SourceName, MediumName, CampaignName, '' Source, '' Medium, '' Campaign, PinCode, InitialRemarks, 
ResidentialAddress, OfficeAddress, latitude, longitude, isnull(LeadImage, '') LeadImage, isnull(img_ext, '') img_ext, isnull(ProfileImgFileName, '') ProfileImgFileName, ParentId, AssignedTo 
from Userleads ul(nolock) 
where ul.ParentID = @ParentId and (ul.latitude between @lat1 and @lat2 or ul.longitude between @lon1 and @lon2)

exec usp_tbl_UA_PageFieldsList_UserId_PageCode 'S', @ParentId, @UserId, 'PAG10031'

End
else if(@EntityType = 'enquiry')
Begin
select EnquiryId Id, LeadNo, PersonName, '' PersonImage, CompanyName, MobileNo, MobileNo1, MobileNo2, 
CountryCode, CountryCode1, CountryCode2, EmailID, EmailID1, EmailID2, City, State, Country, 
SourceName, MediumName, CampaignName, '' Source, '' Medium, '' Campaign, PinCode, InitialRemarks, 
ResidentialAddress, OfficeAddress, latitude, longitude, '' LeadImage, isnull(img_ext, '') img_ext, isnull(ProfileImgFileName, '') ProfileImgFileName, ParentId, 0 AssignedTo
from UserEnquiry ue(nolock) 
where ue.ParentID = @ParentId and (latitude between @lat1 and @lat2 or longitude between @lon1 and @lon2)

exec usp_tbl_UA_PageFieldsList_UserId_PageCode 'S', @ParentId, @UserId, 'PAG10002'

End
end



