/* ============================================================
   Procedure: [dbo].[usp_getentitynumericplaceholders]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_getentitynumericplaceholders]  
    @parentid BIGINT,  
    @entity NVARCHAR(20)  
AS  
BEGIN  
    SET NOCOUNT ON;  
  
    -- Drop temp table if exists  
    IF OBJECT_ID('tempdb..#eph') IS NOT NULL  
        DROP TABLE #eph;  
  
    -- Create temp table  
    CREATE TABLE #eph (  
        fieldnameexposed NVARCHAR(200),  
        fieldnameactual NVARCHAR(200),  
        fieldtype NVARCHAR(10)  
    );  
  
    -- Insert predefined fields with numeric data types  
    INSERT INTO #eph (fieldnameexposed, fieldnameactual, fieldtype)  
    SELECT   
        CAST(@entity + '.' + c.name AS NVARCHAR(200)) AS fieldnameexposed,  
        CAST(@entity + '.' + c.name AS NVARCHAR(200)) AS fieldnameactual,  
        'predefined' AS fieldtype  
    FROM   
        sys.all_columns c (NOLOCK)  
        INNER JOIN sys.types t (NOLOCK) ON c.user_type_id = t.user_type_id  
    WHERE   
        c.object_id = (  
            SELECT object_id   
            FROM sys.tables   
            WHERE name = CASE   
                            WHEN @entity = 'lead' THEN 'userleads'  
                            WHEN @entity = 'enquiry' THEN 'userenquiry'  
                            WHEN @entity = 'Entity' THEN 'TBL_ET_PhysicalAppointment'  
                            WHEN @entity = 'Scoring' THEN 'tbl_SM_ScoringCondition'  
                        END  
        )  
        AND t.name = 'numeric' -- Only numeric data type  
        AND c.name NOT IN (  
            'id', 'PhysicalAppointmentId', 'OutcomesId', 'GeoEntitySiteId', 'TaskTypeId', 'gCalendarId',   
            'GeoEntityId', 'ModifiedOn', 'ModifiedBy', 'FollowupDate', 'LeadImage', 'temp_id',   
            'img_ext', 'ProfileImgFileName', 'enquirysource', 'WhatsAppNoColName',   
            'LastFollowupCreatedBy', 'parentid', 'IsOpen', 'IsduplicateEmail', 'IsduplicateMobile', 'EnquiryID'  
        );  
  
    -- Insert custom fields with numeric data types  
    INSERT INTO #eph (fieldnameexposed, fieldnameactual, fieldtype)  
    SELECT   
        CAST(@entity + '.' + fieldname AS NVARCHAR(200)) AS fieldnameexposed,  
        CAST(@entity + '.' + fieldname AS NVARCHAR(200)) AS fieldnameactual,  
        'custom' AS fieldtype  
    FROM   
        customfields (NOLOCK)  
    WHERE   
        parentid = @parentid   
        AND isActive = 1  
        AND EXISTS (
            SELECT 1 
            FROM sys.all_columns c (NOLOCK)  
            INNER JOIN sys.types t (NOLOCK) ON c.user_type_id = t.user_type_id  
            WHERE t.name = 'numeric' -- Only numeric data type
            AND c.name = fieldname
        );  
  
    -- Select the results  
    SELECT * FROM #eph;  
  
    -- Drop the temp table  
    IF OBJECT_ID('tempdb..#eph') IS NOT NULL  
        DROP TABLE #eph;  
END;


GO

/* ============================================================
   Procedure: [dbo].[usp_getentityplaceholders]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

      
 CREATE   PROCEDURE [dbo].[usp_getentityplaceholders] --34594,'lead'--0,'user'--31871,'enquiry'              
(@parentid bigint,@entity nvarchar(20))              
as              
      
begin      
--declare @parentid bigint=34594,@entity nvarchar(20)='lead'              
drop table if exists #eph              
create table #eph(fieldnameexposed nvarchar(200),fieldnameactual nvarchar(200),fieldtype nvarchar(10))              
insert into #eph(fieldnameexposed,fieldnameactual,fieldtype)              
select * from              
(              
select cast(@entity+'.'+name as nvarchar(200)) fieldnameexposed,cast(@entity+'.'+name as nvarchar(200)) fieldnameactual,'predefined' fieldtype from sys.all_columns (nolock)          
where object_id=(select object_id from sys.tables where name=case when @entity='lead' then 'userleads'               
when @entity='enquiry' then 'userenquiry' when @entity='Entity' then 'TBL_ET_PhysicalAppointment' when @entity='Scoring' then 'tbl_SM_ScoringCondition'  end)              
and name not in 
('id','PhysicalAppointmentId','OutcomesId','GeoEntitySiteId','TaskTypeId','gCalendarId','GeoEntityId','ModifiedOn','ModifiedBy','FollowupDate','LeadImage','temp_id','img_ext',
'ProfileImgFileName','enquirysource','WhatsAppNoColName', 'parentid',          
     'IsOpen','IsduplicateEmail','IsduplicateMobile','EnquiryID','isscoreeligible')             
union all 
select cast(@entity+'.'+case when @entity='lead' then 'Assigned To Phone' else 'Created By Phone' end as nvarchar(200)) fieldnameexposed,cast(@entity+'.'+case when @entity='lead' then 'AssignedToPhone' else 'CreatedByPhone' end as nvarchar(200)) fieldnameactual,'predefined' fieldtype where @entity in ('lead','enquiry')
union all 
select cast(@entity+'.'+case when @entity='lead' then 'Assigned To Email' else 'Created By Email' end as nvarchar(200)) fieldnameexposed,cast(@entity+'.'+case when @entity='lead' then 'AssignedToEmail' else 'CreatedByEmail' end as nvarchar(200)) fieldnameactual,'predefined' fieldtype where @entity in ('lead','enquiry')
union all 
select cast(@entity+'.'+case when @entity='lead' then 'Assigned To Name' else 'Created By Name' end as nvarchar(200)) fieldnameexposed,cast(@entity+'.'+case when @entity='lead' then 'AssignedToName' else 'CreatedByName' end as nvarchar(200)) fieldnameactual,'predefined' fieldtype where @entity in ('lead','enquiry')
union all
select cast(@entity+'.'+fieldname as nvarchar(200)) fieldnameexposed,cast(@entity+'.'+fieldname as nvarchar(200)) fieldnameactual,'custom' fieldtype from customfields(nolock) where parentid=@parentid and isActive = 1  and @entity not in ('user' ,'partner')
union all  
select cast(@entity+'.calculatedfield.'+calculatedfield_name as nvarchar(200)) fieldnameexposed,cast(@entity+'.calculatedfield.'+calculatedfield_name as nvarchar(200)) 
fieldnameactual,'calculated' fieldtype from calculated_fields_master(nolock) where isnull(parentid,@parentid)=@parentid and applicable_entities like '%'+@entity+'%' and @entity not in ('user' ,'partner') 
union all
select cast(@entity+'.'+name as nvarchar(200)) fieldnameexposed,cast(@entity+'.'+name as nvarchar(200)) fieldnameactual,'predefined' fieldtype from sys.all_columns (nolock)          
where object_id=(select object_id from sys.views where name='vw_userdetails') and @entity='user' 
union all
select cast(@entity+'.'+name as nvarchar(200)) fieldnameexposed,cast(@entity+'.'+name as nvarchar(200)) fieldnameactual,'predefined' fieldtype from sys.all_columns (nolock)          
where object_id=(select object_id from sys.views where name='vw_partnerdetails') and @entity='partner' 


) a               
      
select * from #eph              
      
      
drop table if exists #eph              
end 


GO

