/* ============================================================
   Procedure: [dbo].[Usp_GetEshopOrderStatus]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.Usp_GetEshopOrderStatus --678993,33097      
(      
@EnqNo bigint,      
@kit19UserID bigint      
      
)       
      
as      
      
Begin      
      
  Declare @DateCurrentTo date = null      
  Declare @Status nvarchar(50) = 'Red'      
      
   CREATE TABLE #TempLinked                                        
    (                                        
      Result VARCHAR(200)                                        
    )               
                          
     INSERT INTO #TempLinked                                        
     EXEC GetStatusofLinkedServer 'CRM'                                        
     IF NOT EXISTS(                                        
        SELECT 'x'                                        
        FROM   #TempLinked                                        
    )                             
    begin         
      
   select top 1  @DateCurrentTo = convert(date,CreatedDate) From CRM.CRMDB.dbo.AccountSetup where EnqNo = @EnqNo and UserBy = @kit19UserID       
   and Stage = 'Customer Accepted Setup Request'        
       
    
    --Declare @DateCurrentTo date = null      
    --Declare @Status nvarchar(50) = 'Red'      
      
   --set  @DateCurrentTo = '2019-11-12 21:08:03.167'        
  

   if(exists( 
    select  'x'  from [order] where user_id = @Kit19UserID 
    and (CONVERT(date,OrderDate) >= convert(date,@DateCurrentTo) and (CONVERT(date,OrderDate) <= DATEADD(DAY,7,convert(date,@DateCurrentTo))))  
    --group by convert(date,OrderDate) order by convert(date,OrderDate) asc   
	))
	Begin

	  set @Status = 'Green'

	End
  
    select @Status as status         
      
   end      
      
  drop table  #TempLinked      
      
      
End      
      


GO

