/* ============================================================
   Procedure: [dbo].[usp_GetExecutedCampaignDetails]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

  
CREATE   PROCEDURE [dbo].[usp_GetExecutedCampaignDetails]  
AS  
BEGIN  
 SELECT cm.CampaignName,  
        CASE   
             WHEN ISNULL(cm.SenderID, '') = '' THEN 'Mail'  
             ELSE 'SMS'  
        END                TYPE,  
        cm.ExecuteTime  AS DATE,  
        cm.NoOfRecipients,  
        (  
            SELECT COUNT(*)  
            FROM   ClientLeadDetails AS cld  
            WHERE  cld.CampaignName = cm.CampaignName  
                   AND cld.cname IN (SELECT DISTINCT csu.URLName  
                                     FROM   CampaignShortURL AS csu  
                                     WHERE  csu.CampaignName = cld.CampaignName  
                                            AND csu.Track_Unsubscribe = 1)  
        )               AS Microsite_unsubscribe,  
        (  
            SELECT COUNT(*)  
            FROM   ClientLeadDetails AS cld  
            WHERE  cld.CampaignName = cm.CampaignName  
                   AND cld.cname IN (SELECT DISTINCT csu.URLName  
                                     FROM   CampaignShortURL AS csu  
                                     WHERE  csu.CampaignName = cld.CampaignName  
                                            AND csu.Track_Unsubscribe = 0)  
        )               AS Microsite_Response,  
        '' AS              Call_Response,  
        '' AS              Call_unsubscribe,  
        (  
            SELECT COUNT(ad.EnqNo)  
            FROM   [CRM].CRMDB.dbo.Appointment_details AS ad  
            WHERE  ad.MeetingStatus = 'Enrolled'  
                   AND (  
                           DATEDIFF(DAY, cm.ExecuteTime, GETDATE()) <= 30  
                           AND DATEDIFF(DAY, cm.ExecuteTime, GETDATE()) > 0  
                       )  
        )               AS withindays,  
        (  
            SELECT COUNT(ad.EnqNo)  
            FROM   [CRM].CRMDB.dbo.Appointment_details AS ad  
            WHERE  ad.MeetingStatus = 'Enrolled'  
                   AND (DATEDIFF(DAY, cm.ExecuteTime, GETDATE()) > 0)  
        )               AS total  
 FROM   CampaignMaster     cm  
 WHERE  IsExecuted = 1  
END  



GO

