   Procedure: [dbo].[usp_GetExecutedCampaignReports]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON



CREATE   PROCEDURE [dbo].[usp_GetExecutedCampaignReports]
AS
BEGIN
	SELECT cm.ID,
	       cm.CampaignName + ' (' + cm.[Message] + ')' AS CampaignName
	FROM   CampaignMaster AS cm
	WHERE  cm.IsExecuted = 1
	ORDER BY
	       cm.ExecuteTime DESC
END



