/* ============================================================
   Procedure: [dbo].[usp_GetExecutedKit19Users]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_GetExecutedKit19Users] --70--54       
 @SearchID INT,      
 @SearchText VARCHAR(50) = NULL,      
 @PageSize INT = 0      
AS      
BEGIN      
 IF EXISTS(      
        SELECT *      
        FROM   SearchDetails AS sd      
        WHERE  sd.ID = @SearchID      
               AND sd.IsKit19 = 1      
               AND sd.IsActive = 1      
    )      
 BEGIN      
     BEGIN TRY      
      DECLARE @UserName                VARCHAR(MAX),      
              @UserFilter              VARCHAR(MAX),      
              @UserType                VARCHAR(MAX),      
              @Mobile                  VARCHAR(50),      
              @EmailID                 VARCHAR(MAX),      
              @LastLoginBeforeFrom     VARCHAR(MAX),      
              @LastLoginBeforeTo       VARCHAR(MAX),      
              @LastPurchaseDaysFrom VARCHAR(MAX),      
              @LastPurchaseDaysTo      VARCHAR(MAX),      
              @LastPurchasePriceFrom VARCHAR(MAX),      
              @LastPurchasePriceTo     VARCHAR(MAX),      
              @TotalCreditPurchasedFrom VARCHAR(MAX),      
              @TotalCreditPurchasedTo VARCHAR(MAX),      
              @TotalCreditConsumedFrom VARCHAR(MAX),      
              @TotalCreditConsumedTo VARCHAR(MAX),      
              @CreatedBetweenFrom      VARCHAR(MAX),      
              @CreatedBetweenTo        VARCHAR(MAX),      
              @BalanceFrom             VARCHAR(MAX),      
              @BalanceTo               VARCHAR(MAX),      
              @IsNewUser               BIT,      
              @UserStatus              BIT,      
              @HasMicrosite            BIT,      
              @ID                      BIGINT                            
            
            
            
      SELECT @ID = sd.ID,      
             @HasMicrosite             = ISNULL(sd.HasMicrosite, 0),      
             @IsNewUser                = ISNULL(sd.IsNewUser, 0),      
             @BalanceFrom              = ISNULL(sd.BalanceFrom, ''),      
             @BalanceTo                = ISNULL(sd.BalanceTo, ''),      
             @UserName                 = ISNULL(sd.UserName, ''),      
             @UserFilter               = ISNULL(sd.UserFilter, ''),      
             @UserType                 = ISNULL(sd.UserType, ''),      
             @Mobile                   = ISNULL(sd.Mobile, ''),      
             @EmailID                  = ISNULL(sd.EmailID, ''),      
             @LastLoginBeforeFrom      = ISNULL(sd.LastLoginBeforeFrom, ''),      
             @LastLoginBeforeTo        = ISNULL(sd.LastLoginBeforeTo, ''),      
             @LastPurchaseDaysFrom     = ISNULL(sd.LastPurchaseDaysFrom, ''),      
             @LastPurchaseDaysTo       = ISNULL(sd.LastPurchaseDaysTo, ''),      
             @LastPurchasePriceFrom = ISNULL(sd.LastPurchasePriceFrom, ''),      
             @LastPurchasePriceTo      = ISNULL(sd.LastPurchasePriceTo, ''),      
             @TotalCreditPurchasedFrom = ISNULL(sd.TotalCreditPurchasedFrom, ''),      
             @TotalCreditPurchasedTo = ISNULL(sd.TotalCreditPurchasedTo, ''),      
             @TotalCreditConsumedFrom = ISNULL(sd.TotalCreditConsumedFrom, ''),      
             @TotalCreditConsumedTo = ISNULL(sd.TotalCreditConsumedTo, ''),      
             @CreatedBetweenFrom       = ISNULL(sd.CreatedBetweenFrom, ''),      
             @CreatedBetweenTo         = ISNULL(sd.CreatedBetweenTo, ''),      
             @UserStatus               = ISNULL(sd.UserStatus, 0)      
      FROM   SearchDetails AS sd      
      WHERE  sd.ID = @SearchID      
             AND sd.IsKit19 = 1      
             AND sd.IsActive = 1                      
            
            
      SELECT [User_ID],      
             User_Login,      
             FName,      
             LName,      
             EMail,      
             STR(Mobile)  AS Mobile,      
             Country,      
             [State],      
             City,      
             userfilter,      
             [Type] INTO     #TempUserDetail      
      FROM   user_detail      
      WHERE  m_id = 10043                        
            
            
            
      IF ISNULL(@UserStatus, 0) <> 0      
      BEGIN      
          --   SELECT 15                    
          DELETE       
          FROM   #TempUserDetail      
          WHERE  [User_ID] NOT IN (SELECT ud.[User_ID]      
                 FROM   User_Detail AS ud      
                                   WHERE  ud.[Status] = 1)      
      END                      
            
            
      IF ISNULL(@username, '') <> ''      
      BEGIN      
          --   SELECT 2                    
          DELETE       
          FROM   #TempUserDetail      
          WHERE  [User_ID] NOT IN (SELECT fs.value      
                                   FROM   dbo.fn_Split(@UserName, '#') AS       
                                          fs)      
      END                      
            
      IF ISNULL(@UserFilter, '') <> ''      
      BEGIN      
          --   SELECT 3                    
          DELETE       
          FROM   #TempUserDetail      
          WHERE  userfilter NOT IN (SELECT fs.[value]      
                                    FROM   dbo.fn_Split(@UserFilter, '#') AS       
                                           fs)      
      END                      
            
            
            
      IF ISNULL(@UserType, '') <> ''      
      BEGIN      
          --   SELECT 5                    
          DELETE       
          FROM   #TempUserDetail      
          WHERE  [Type] NOT IN (SELECT fs.[value]      
                                FROM   dbo.fn_Split(@UserType, '#') AS fs)      
      END                      
            
            
      IF ISNULL(@Mobile, '') <> ''      
      BEGIN      
          -- SELECT 6                    
          DELETE       
          FROM   #TempUserDetail      
          WHERE  USER_ID NOT IN (SELECT DISTINCT ss.[User_ID]      
                                 FROM   User_Detail AS ss      
                                 WHERE  STR(ss.Mobile, 10, 0) = @Mobile)       
                 --AND LEN(ss.Mobile) > 10)      
      END                      
            
      IF ISNULL(@EmailID, '') <> ''      
      BEGIN      
          --  SELECT 7                    
          DELETE       
          FROM   #TempUserDetail      
          WHERE  USER_ID NOT IN (SELECT DISTINCT ss.[User_ID]      
                                 FROM   User_Detail ss      
                                 WHERE  ss.EMail = @EmailID)      
      END              
            
            
            
      IF ISNULL(@CreatedBetweenFrom, '') <> ''      
         AND ISNULL(@CreatedBetweenTo, '') <> ''      
      BEGIN      
          --  SELECT 13                    
          DELETE       
          FROM   #TempUserDetail      
          WHERE  USER_ID NOT IN (SELECT DISTINCT cd.[USER_ID]      
                                 FROM   User_Detail AS cd      
                                 WHERE  cd.[User_ID] IN (SELECT tt.[User_ID]      
                                                         FROM         
                                                                #TempUserDetail       
                                                                tt)      
                                        AND DATEDIFF(d, DateCreated, GETDATE())       
                                            >= @CreatedBetweenFrom      
                                        AND DATEDIFF(d, DateCreated, GETDATE())       
                                            <= @CreatedBetweenTo)      
      END                    
            
      IF ISNULL(@IsNewUser, 0) <> 0      
      BEGIN      
          --  SELECT 1                    
                
          DELETE       
          FROM   #TempUserDetail      
          WHERE  [User_ID] NOT IN (SELECT cd.[User_ID]      
                                   FROM   [Credit_Details] cd      
                                   GROUP BY      
                                          cd.[User_ID]      
                              HAVING COUNT([User_ID]) > 1)      
      END           
            
            
      IF ISNULL(@HasMicrosite, 0) <> 0      
      BEGIN      
          --   SELECT 14                    
          DELETE       
          FROM   #TempUserDetail      
          WHERE  [User_ID] NOT IN (SELECT cpd.[User_ID]      
                                   FROM   ClientPageDetail AS cpd)      
      END                      
            
            
            
            
      IF ISNULL(@LastPurchaseDaysFrom, '') <> ''      
         AND ISNULL(@LastPurchaseDaysTo, '') <> ''      
      BEGIN      
          --    SELECT 9                    
          DELETE       
          FROM   #TempUserDetail      
          WHERE  USER_ID NOT IN (SELECT cd.UserID      
               FROM   AddCreditDetails AS cd      
                                 WHERE  (cd.Reason = 'Purchase' OR cd.Reason = 'Reason 1')      
                                        AND cd.[UserID] IN (SELECT tt.[User_ID]      
                                                            FROM         
                                                                   #TempUserDetail       
                                                                   tt)      
                                 GROUP BY      
                                        cd.UserID      
                                 HAVING (      
                                            DATEDIFF(DAY, MAX(cd.CreatedDate), GETDATE())       
                                            >= @LastPurchaseDaysFrom      
                                            AND DATEDIFF(DAY, MAX(cd.CreatedDate), GETDATE())       
                                                <= @LastPurchaseDaysTo      
                                        ))      
      END                      
            
            
      IF ISNULL(@LastPurchasePriceFrom, '') <> ''      
         AND ISNULL(@LastPurchasePriceTo, '') <> ''      
      BEGIN      
          --    SELECT 10                    
          DELETE       
          FROM   #TempUserDetail      
          WHERE  USER_ID NOT IN (SELECT cd.UserID      
                                 FROM   AddCreditDetails AS cd      
                                 WHERE  (cd.Reason = 'Purchase' OR cd.Reason = 'Reason 1')      
                                        AND cd.[UserID] IN (SELECT tt.[User_ID]      
                                                            FROM   #TempUserDetail tt)    
                                 --Changed on 130717, added following line for lastpurchase price    
                                 and cd.CreatedDate=(select MAX(createddate) from AddCreditDetails a where a.UserID=cd.UserID)     
                                 --changes end--    
                                 GROUP BY      
                                        cd.UserID,      
                                        cd.PricePerSMS      
                                 HAVING (      
                                            cd.PricePerSMS >= @LastPurchasePriceFrom      
                                            AND cd.PricePerSMS <= @LastPurchasePriceTo      
                                        ))      
      END                        
            
            
            
      IF ISNULL(@TotalCreditPurchasedFrom, '') <> ''      
         AND ISNULL(@TotalCreditPurchasedTo, '') <> ''      
      BEGIN      
          -- SELECT 11                    
          DELETE       
          FROM   #TempUserDetail      
          WHERE  USER_ID NOT IN (SELECT cd.[USERID]      
                                 FROM   AddCreditDetails cd      
                                 WHERE  (cd.Reason = 'Purchase' OR cd.Reason = 'Reason 1')      
                                        AND cd.[UserID] IN (SELECT tt.[User_ID]      
                                                            FROM         
                                                                   #TempUserDetail       
                                tt)      
                                 GROUP BY      
                                        cd.[UserID]      
                                 HAVING (      
                                            SUM(ISNULL(Credits, 0)) >= @TotalCreditPurchasedFrom      
                                            AND SUM(ISNULL(Credits, 0)) <=      
                                                @TotalCreditPurchasedTo      
                                        ))      
      END                      
          
      IF ISNULL(@BalanceFrom, '') <> ''      
         AND ISNULL(@BalanceTo, '') <> ''      
      BEGIN      
          --  SELECT 4                    
          DELETE       
          FROM   #TempUserDetail      
          WHERE  USER_ID NOT IN (SELECT DISTINCT USER_ID      
                                 FROM   Credit_Details d     
                                 WHERE credit_id=(select max(credit_id) from Credit_Details c where c.user_id=d.user_id and Balance >= @BalanceFrom      
                                        AND Balance <= @BalanceTo))      
      END        
            
            
      IF ISNULL(@LastLoginBeforeFrom, '') <> ''      
         AND ISNULL(@LastLoginBeforeTo, '') <> '' 
          
      BEGIN      
          --  SELECT 8                    
          DELETE       
          FROM   #TempUserDetail      
          WHERE  USER_ID NOT IN 
          (SELECT cd.[User_ID]      
                                 FROM   user_Detail AS cd   
                                 where DATEDIFF(DAY,(cd.LastLogin1), GETDATE())       
                                            >= @LastLoginBeforeFrom      
                                            AND DATEDIFF(DAY,(cd.LastLogin1), GETDATE())                                                 <= @LastLoginBeforeTo   
                                            and cd.lastlogin1 is not null        
          union
          SELECT cd.[User_ID]      
                                 FROM   Credit_Details AS cd   
                                 --180717 changes to optimize the query, added below block     
                                 where cd.credit_id =(  
                                 select max(credit_id) from credit_details c join 
                                 #tempuserdetail tt on c.user_id=tt.user_id  
                                 where c.user_id=cd.user_id 
                                 and DATEDIFF(DAY,(c.DateCreated), GETDATE())       
                                 >= @LastLoginBeforeFrom      
                                 AND DATEDIFF(DAY,(c.DateCreated), GETDATE())       
                                 <= @LastLoginBeforeTo and c.FromUser_ID=c.User_ID) )  
      END                      
            
            
      IF ISNULL(@TotalCreditConsumedFrom, '') <> ''      
         AND ISNULL(@TotalCreditConsumedTo, '') <> ''      
      BEGIN      
          -- SELECT 12                    
                
          SELECT cd.[User_ID],      
                 SUM(ISNULL(cd.Debits, 0)) AS Debits INTO #TempDebits      
          FROM   Credit_Details AS cd      
          WHERE  cd.[User_ID] IN (SELECT tt.[User_ID]      
                                  FROM   #TempUserDetail       
                                         tt)      
          GROUP BY      
                 cd.[User_ID]                    
                
          DELETE       
          FROM   #TempUserDetail      
          WHERE  USER_ID NOT IN (SELECT DISTINCT cd.[User_ID]      
                                 FROM   #TempDebits cd      
                WHERE  Debits >= @TotalCreditConsumedFrom      
                                        AND Debits <= @TotalCreditConsumedTo)       
                
          DROP TABLE #TempDebits      
      END          
            
            
      DELETE       
      FROM   #TempUserDetail      
      WHERE  ISNUMERIC(Mobile + '.0e0') = 0        
            
      SELECT [User_ID],      
             User_Login,      
             FName,      
             LName,      
             EMail,      
             STR(Mobile) AS Mobile,      
             Country,      
             [State],      
             City,      
             userfilter      
      FROM   #TempUserDetail      
      WHERE  ISNULL(@SearchText, '') = ''      
             OR  User_Login LIKE '%' + @SearchText + '%'      
             OR  FName LIKE '%' + @SearchText + '%'      
             OR  LName LIKE '%' + @SearchText + '%'      
             OR  EMail LIKE '%' + @SearchText + '%'      
             OR  Mobile LIKE '%' + @SearchText + '%'      
      ORDER BY      
             User_Login       
            
      DROP TABLE #TempUserDetail      
     END TRY          
     BEGIN CATCH      
      SELECT ERROR_MESSAGE() AS ErrorMessage      
     END CATCH      
 END      
END


