/* ============================================================
   Procedure: [dbo].[usp_GetExportLeadDetailsWithDateRange]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_GetExportLeadDetailsWithDateRange]
    @UserID BIGINT,
    @OffsetValue INT,
    @PagingSize INT,
    @FromDate DATETIME = NULL,
    @ToDate DATETIME = NULL
AS
BEGIN
    SET NOCOUNT ON;
 
    BEGIN TRY
 
 
	--declare
 
	--@UserID BIGINT=50344,
--   @OffsetValue INT=0,
--   @PagingSize INT=20,
--   @FromDate DATETIME = NULL,
--   @ToDate DATETIME = NULL
 
        DECLARE @TotalRows INT;
 
        SELECT @TotalRows = COUNT(1)
        FROM Tbl_ExportLeadDetails
        WHERE UserID = @UserID
          AND (@FromDate IS NULL OR CreatedDate >= @FromDate)
          AND (@ToDate IS NULL OR CreatedDate < DATEADD(DAY, 1, @ToDate));
 
        ;WITH Paged AS (
            SELECT
                ExportBatchID,
                ExportName,
                CreatedDate,
                ExportedFileName,
                TotalRecordsExported,
                ExportStartTime,
                ExportEndTime,
                IsProcessed,
                ExportedFilePath,
				Remarks,
                ROW_NUMBER() OVER (ORDER BY ExportBatchID DESC) AS RowNum
            FROM Tbl_ExportLeadDetails nolock
            WHERE UserID = @UserID
              AND (@FromDate IS NULL OR CreatedDate >= @FromDate)
              AND (@ToDate IS NULL OR CreatedDate < DATEADD(DAY, 1, @ToDate))
        )
        SELECT
            ExportBatchID,
            ExportName,
            FORMAT(CreatedDate, 'dd-MMM-yyyy') AS CreatedDate, 
            ExportedFileName,
            TotalRecordsExported,
            ExportStartTime,
            ExportEndTime,
            --IsProcessed,
			CASE 
        WHEN LOWER(Remarks) = '[exported]' THEN 'Processed'
        WHEN LOWER(Remarks) = '[under process]' THEN 'Unprocessed'
        ELSE 'Failed'
    END AS Status,
			 --CASE 
    --    WHEN IsProcessed = 1 AND DATEDIFF(SECOND, ExportEndTime, GETDATE()) >= 30 THEN 'Processed'
    --    WHEN IsProcessed = 1 AND DATEDIFF(SECOND, ExportEndTime, GETDATE()) < 30 THEN 'Unprocessed'
    --    WHEN IsProcessed = 0 THEN 'Unprocessed'
    --    ELSE 'Unprocessed'
    --END AS Status,
 
			--CASE 
   --     WHEN IsProcessed = 1 THEN 'Processed'
   --     ELSE 'Failed'
    --END AS Status,
            ExportedFilePath,
            @TotalRows AS TotalRows
        FROM Paged
        WHERE RowNum BETWEEN @OffsetValue + 1 AND @OffsetValue + @PagingSize
        ORDER BY RowNum;
    END TRY
    BEGIN CATCH
        EXEC usp_InsertErrorInfo;
    END CATCH
END


GO

/* ============================================================
   Procedure: [dbo].[Usp_GetFBUserAndPages]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON



CREATE   PROCEDURE Usp_GetFBUserAndPages @mode VARCHAR(10)            
 ,@userid BIGINT = NULL            
 ,@fbuserid NVARCHAR(max) = NULL            
 ,@fbAppid NVARCHAR(max) = NULL            
AS            
BEGIN            
 DECLARE @parentid BIGINT = (            
   SELECT parentid            
   FROM User_Detail            
   WHERE user_id = @userid            
   )            
            
 IF (@mode = 'fbusers')            
 BEGIN            
  SELECT PersonName            
   ,fat.LongAccessToken            
   ,FbUserId            
   ,apa.appsecret             
  FROM tbl_FbAdCmpgn_AccessToken fat WITH (NOLOCK)            
  JOIN tbl_Ad_AllPlatformAppIds apa WITH (NOLOCK) ON fat.App_Id = apa.App_Id            
  WHERE parentid = @userid            
   AND fat.App_Id = @fbAppid            
 END            
 ELSE IF (@mode = 'fbpages')            
 BEGIN            
  SELECT FP.FbPageId            
   ,FP.FbPageName            
   ,FP.FbUserId            
   ,FP.FbPageLongToken       
   ,UPM.ParentId    
   ,Pbia.InstagramId  
   ,UPM.Isactive    
  FROM  tbl_Ad_UserPageMapping UPM WITH (NOLOCK)            
 JOIN [tbl_FbAdCmpgn_FbPages] FP WITH (NOLOCK) on UPM.Pageid=FP.FbPageId      
 left Join tbl_ad_InstagramPBIA Pbia With (Nolock) on FP.FbPageId=Pbia.FBPageId  
 WHERE UPM.ParentId=@parentid  
  AND UPM.Isactive=1    
 END            
END       
      


GO

