CREATE   PROC [dbo].[usp_GetFileType]                
  (  
  @FType varchar(50)  
  )     
AS                
BEGIN                
Declare @Filetype varchar(50) = ''           
               
 set @Filetype= isnull((select top 1 FileType from tbl_FileTypeMaster where ISActive=1 and FileType=@FType),'')              
          if @Filetype <> ''      
      Begin      
      select @Filetype      
   End      
  else    
    begin      
   select 'Not Found'                
   end      
       
        
END



