/* ============================================================
   Procedure: [dbo].[usp_GetFilteredUserAccountsCRM_New]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

      
--------Modified By Abhishek Makkar ----------- Time: 8/17/2017 10:08:30 AM        
CREATE   PROCEDURE [dbo].[usp_GetFilteredUserAccountsCRM_New]-- 335        
 @ParentID BIGINT   ,  
 @Account nvarchar(max) = null  
AS        
BEGIN      
--declare @Account nvarchar(max)='test',@ParentID BIGINT=34594  
 SELECT ud.[User_ID]         AS ID,        
        ud.ParentID,        
        ud.[User_ID]         AS UserID,        
        ut.Name              AS UserType,        
        ud.FName + ISNULL(ud.LName, '') AS UserName,        
        ud.User_Login +'('+UF.Name+')'  AS AccountName,        
        ut.CreatedBy,        
            
      --ut.CreatedOn,    
        dbo.[fn_getusertimefromindiantime](ud.ParentID,ut.CreatedOn) as CreatedOn,    
                    
        ud.User_Login,        
        0                    AS IsEditable        
 FROM   User_Detail          AS ud        
        LEFT JOIN User_Type  AS ut(NOLOCK)        
             ON  ud.UserType = ut.ID        
        inner join User_Filter UF(Nolock)      
        on ud.userfilter = Uf.Code           
 WHERE  ud.[User_ID] = @ParentID        
 and ( @Account is null or  (ud.User_Login+' '+UF.Name like '%'+@Account+'%'))     
 UNION        
 SELECT ua.ID,        
        ua.ParentID,        
        ua.UserID,        
        ut.Name                AS UserType,        
        ua.UserName,        
        ua.AccountName + '('+UF.Name+')' as AccountName ,        
        ua.CreatedBy,        
            
     -- ua.CreatedOn,    
        dbo.[fn_getusertimefromindiantime](ua.ParentID,ua.CreatedOn) as CreatedOn,        
            
        ud.User_Login,        
        1                      AS IsEditable        
 FROM   UserAccounts           AS ua(NOLOCK)        
        LEFT JOIN User_Detail  AS ud(NOLOCK)        
             ON  ua.UserID = ud.User_ID        
        LEFT JOIN User_Type    AS ut(NOLOCK)        
             ON  ud.UserType = ut.ID        
        LEFT JOIN User_Detail UD1(NOLOCK)        
             ON  ua.CreatedBy = UD1.User_ID      
        inner join User_Filter as UF(Nolock)      
             ON ud.userfilter = UF.Code            
                     
 WHERE  ua.ParentID = @ParentID  and ( @Account is null or  (ua.AccountName+' '+UF.Name like '%'+@Account+'%'))     
END 


GO

/* ============================================================
   Procedure: [dbo].[usp_GetFilteredUserMailsSetting]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

    
CREATE   PROCEDURE [dbo].[usp_GetFilteredUserMailsSetting]  --335,1,1      
 @ParentID BIGINT,        
 @IsActive BIT,        
 @isInActive BIT,  
 @FilteredText NVARCHAR(MAX) = null  
AS        
BEGIN    
--declare  @ParentID BIGINT =34594,        
-- @IsActive BIT=1,        
-- @isInActive BIT=0,  
-- @FilteredText NVARCHAR(MAX)='test@gmail'  
 SELECT ums.ID,        
        ums.MailName,        
        ums.EmailAddress,        
        ums.IsActive,    
        isnull(USS.IsEditable,0) as IsEditable ,      
        Ud.User_Login        
 FROM   UserMailsSettings AS ums(nolock)      
        left join User_Detail UD(Nolock)      
        on ums.CreatedBy = UD.User_ID     
        left join UserSourceSettings as USS(nolock)    
        on ums.MailName = USS.Name         
               
 WHERE  ums.ParentID = @ParentID        
        AND (        
                ums.IsActive = CASE         
                                    WHEN @IsActive = 0 THEN NULL        
                                    ELSE @IsActive        
                               END        
                OR ums.IsActive = CASE         
                                       WHEN @isInActive = 0 THEN NULL        
                                       ELSE 0        
                                  END        
            )     
   AND (@FilteredText is null or ( ums.MailName like '%'+ @FilteredText +'%' or ums.EmailAddress like '%'+ @FilteredText +'%' ))  
 ORDER BY        
        ums.CreatedOn,ums.ModifiedOn DESC        
END 


