/* ============================================================
   Procedure: [dbo].[usp_GetFilterList]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


--------Modified By Abhishek Makkar ----------- Time: 8/18/2017 7:02:06 PM------/
CREATE   PROCEDURE [dbo].[usp_GetFilterList] --335
	@ParentID BIGINT
AS
BEGIN
	SELECT umf.FilterName,
	       umf.Source_EmailID,
	       COUNT(*)         AS FilterCount,
	       (
	           (
	               SELECT COUNT(*)
	               FROM   UserEnquiryRawEntries AS uere
	               WHERE  uere.FilterName = umf.FilterName
	                      AND uere.ParentID = @ParentID
	                      AND uere.IsValid = 1
	                      AND uere.IsTransfered = 0
	           ) + (
	               SELECT COUNT(*)
	               FROM   UserExtractedData AS ued
	               WHERE  ued.ParentID = @ParentID
	           )
	       )                AS ValidCount,
	       (
	           SELECT COUNT(*)
	           FROM   UserEnquiryRawEntries AS uere
	           WHERE  uere.FilterName = umf.FilterName
	                  AND uere.ParentID = @ParentID
	                  AND uere.IsInValid = 1
	       )                AS InValidCount,
	       (
	           SELECT COUNT(*)
	           FROM   UserEnquiryRawEntries AS uere
	           WHERE  uere.FilterName = umf.FilterName
	                  AND uere.ParentID = @ParentID
	                  AND uere.IsValid = 1
	                  AND uere.IsTransfered = 1
	       )                AS TransferreCount,
	       (
	           SELECT CASE 
	                       WHEN COUNTMapping > 0 THEN 'Yes'
	                       ELSE 'No'
	                  END
	           FROM   (
	                      SELECT COUNT(*) AS COUNTMapping
	                      FROM   UserMailsFilter AS umf2
	                      WHERE  umf2.FilterName = umf.FilterName
	                             AND umf2.UserID = @ParentID
	                             AND NULLIF(umf2.MappingColumn, '') IS NOT NULL
	                  ) A
	       )                AS IsMapped
	FROM   UserMailsFilter  AS umf
	WHERE  umf.UserID = @ParentID
	GROUP BY
	       umf.FilterName,
	       umf.Source_EmailID
END



GO

/* ============================================================
   Procedure: [dbo].[Usp_GetFilterMode]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC Usp_GetFilterMode --30000,1000005  
( @cost INT,    
@credit INT)    
AS    
Begin    
DECLARE @categary INT    
Declare @rate float    
    
SET @rate= cast((cast(@cost as float)*100/cast(@credit as float)) as float)    
if (@credit <  50000)    
Begin    
SET @categary=4    
End    
Else if(@credit >= 50000 and @credit<= 100000)    
Begin    
if(@rate < 5)    
Begin    
set @categary=4    
end    
Else if(@rate >=5 and @rate <6)    
Begin    
set @categary=3    
End     
Else if(@rate >=6 and @rate <8)    
Begin    
set @categary=2    
End    
Else if( @rate >= 8)    
Begin    
set @categary=1    
End    
End    
    
Else if(@credit > 100000 and @credit <= 500000)    
Begin    
if(@rate < 3.5)    
Begin    
set @categary=4    
end    
Else if(@rate >= 3.5 and @rate < 5)    
Begin    
set @categary=3    
End     
Else if(@rate >= 5 and @rate < 6)    
Begin    
set @categary=2    
End    
Else if( @rate >= 6)    
Begin    
set @categary=1    
End    
End    
    
Else if(@credit > 500000 and @credit <= 1000000)    
Begin    
if(@rate < 3)    
Begin    
set @categary=4    
end    
Else if(@rate >= 3 and @rate < 4.5)    
Begin    
set @categary=3    
End     
Else if(@rate >= 4.5 and @rate < 5.5)    
Begin    
set @categary=2    
End    
Else if( @rate >= 5.5)    
Begin    
set @categary=1    
End    
End    
    
Else if(@credit > 1000000 and @credit <= 5000000)    
Begin    
if(@rate < 2)    
Begin    
set @categary=4    
end    
Else if(@rate >= 2 and @rate < 3.5)    
Begin    
set @categary=3    
End     
Else if(@rate >= 3.5 and @rate < 4.5)    
Begin    
set @categary=2    
End    
Else if( @rate >= 4.5)    
Begin    
set @categary=1    
End    
End    
    
Else if(@credit > 5000000 and @credit <= 10000000)    
Begin    
if(@rate < 1.5)    
Begin    
set @categary=4    
end    
Else if(@rate >= 1.5 and @rate < 3)    
Begin    
set @categary=3    
End     
Else if(@rate >= 3 and @rate < 4)    
Begin    
set @categary=2    
End    
Else if( @rate >= 4)    
Begin    
set @categary=1    
End    
End    
    
Else if( @credit > 10000000)    
Begin    
if(@rate < 1)    
Begin    
set @categary=4    
end    
Else if(@rate >= 1 and @rate < 2)    
Begin    
set @categary=3    
End     
Else if(@rate >= 2 and @rate < 3)    
Begin    
set @categary=2    
End    
Else if( @rate >= 3)    
Begin    
set @categary=1    
End    
End    
--select @rate,@categary    
select @categary    
End


GO

