/* ============================================================
   Procedure: [dbo].[usp_GetFiltersParsingRulesForConsole]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[usp_GetFiltersParsingRulesForConsole]
AS
BEGIN
	SELECT DISTINCT umf.ParentID,
	       ump.FilterID,
	       ump.IsWithinText,
	       ump.StartFrom,
	       ump.EndWith,
	       ump.IsFullCapturedData,
	       ump.IsManupulatedText,
	       ump.IsRegex,
	       ump.IsNumbers,
	       ump.IsEmail,
	       ump.IsOthers,
	       ump.MinDigits,
	       ump.MaxDigits,
	       ump.IsWIldCard,
	       ump.RegexText,
	       ump.IsRemoveLineBreaks,
	       ump.IsTrim,
	       ump.MappingColumn,
	       ump.Prefix,
	       ump.Suffix,
	       ump.IsBetween,
	       ump.BtwLeft,
	       ump.BtwRight,
	       ump.BtwMid,
	       ump.BtwMidLength,
	       ump.ReplaceText,
	       ump.ReplaceTextWith,
	       ump.SourceID,
	       ump.MediumID,
	       ump.CampaignID,
	       ump.Instance,
	       ump.ID
	FROM   UserMailsFilters             AS umf
	       INNER JOIN UserMailsParsing  AS ump
	            ON  umf.ID = ump.FilterID
	WHERE  umf.IsActive = 1
	ORDER BY
	       ump.ID
END



