/* ============================================================
   Procedure: [dbo].[USP_GetFInalStatus]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[USP_GetFInalStatus] --'335','','',1,50 
@userid varchar(100), 
@SEndername varchar(20), 
@Mobile varchar(20), 
@pageIndex bigint, 
@PageSize bigint 
as 
DEclare @whereclause nvarchar(4000) 
DEclare @query nvarchar(4000) 
 
set @whereclause='' 
 
if @userid='' 
begin 
SET @whereclause=@whereclause+' 1=1 ' 
end 
else 
begin 
SET @whereclause=@whereclause+' md.u_id='+@userid 
end 
 
if @SEndername='' 
begin 
SET @whereclause=@whereclause+' and 1=1 ' 
end 
else 
begin 
SET @whereclause=@whereclause+' and md.SenderID='''+@SEndername+'''' 
end 
 
if @Mobile='' 
begin 
SET @whereclause=@whereclause+' and 1=1 ' 
end 
else 
begin 
SET @whereclause=@whereclause+' and md.Mobile='''+@Mobile+'''' 
end 
 
 
begin 
set @query='with cte as( 
SELECT md.Mobile as Mobile, md.[Message], md.SenderID as SenderID, md.BatchID, 
isnull(substring(rd.Statuswitherr,6,7), 
(CASE md.MessageStatus 
WHEN ''3'' THEN ''DND'' 
when ''6'' Then ''Invalid'' 
when ''5'' Then ''Blacklisted'' 
ELSE ''Sent'' END )) AS MessageStatus, 
Convert(varchar(8),md.MessageInsertDate,108) AS [DeliverTime],rd.SubmitRefID, 
ROW_NUMBER() over (partition by md.messageid order by md.messageid) as dlr 
FROM messagedeliverystatus md with (nolock) 
left join mysms.dbo.ReceiveDeliveryData rd with (nolock) 
on ''91''+md.mobile=rd.mobile and replace(md.senderid,''.'','' '')=replace(rd.senderid,''AM-'','''') 
Left Join mysms.dbo.MessageDeliveryStatusTemp mDST with (nolock) 
On md.MessageID = mDST.MessageID 
Left Join mysmstrans.dbo.SubmitDetail sd with (nolock) 
On rd.SubmitRefID = sD.Reference where '+@whereclause+' 
) 
SELECT Mobile,[Message],SenderID,MessageStatus,[DeliverTime],BatchID,SubmitRefID from cte where dlr=1 
'END 
 
-- declare @TempTable1 table 
--( 
--Id int identity(1,1), 
--Mobile varchar(20) , 
--[Message] nvarchar(1000), 
--SenderID varchar(20), 
--MessageStatus varchar(50), 
--[DeliverTime] varchar(50), 
--BatchID bigint, 
--SubmitRefID varchar(500) 
--) 
-- 
--insert into @TempTable1 (Mobile,[Message],SenderID,MessageStatus,[DeliverTime],BatchID,SubmitRefID) 
 exec sp_executesql @query,N''; 
 
-- select * from (SELECT *, ROW_NUMBER() OVER(ORDER BY Id ASC) AS rownum from @TempTable1) as TempTable 
-- where rownum between (@pageIndex-1)*@PageSize+1 AND @pageIndex*@PageSize 
 



GO

