/* ============================================================
   Procedure: [dbo].[usp_GetFollowUpListByUserId]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE usp_GetFollowUpListByUserId(                    
 @OffsetValue int = 0,                    
 @PagingSize int  = 20,                    
 @UserId bigint ,                  
 @FollowUpType int = 0,                  
 @NextStatusFromDate datetime = NULL,                  
 @NextStatusToDate datetime = NULL,                  
 @CreatedFromDate datetime = NULL,                  
 @CreatedToDate datetime = NULL,                  
 @LeadId bigint = NULL,                
 @Remarks nvarchar(500) = '',            
 @Overdue bit = 1,            
 @DueToday bit = 1,            
 @Scheduled bit = 1,            
 @NoFollowUp bit = 1,      
 @AssignedTo bigint = 0,      
 @CreatedBy  bigint = 0      
)                    
as                    
begin  


--  declare @OffsetValue int = 0, @PagingSize int  = 10,  @UserId bigint = 37540,  @FollowUpType int = 0,  @NextStatusFromDate datetime = NULL,   @NextStatusToDate datetime = NULL,   @CreatedFromDate datetime = NULL, @CreatedToDate datetime = NULL,  @LeadId bigint = NULL,   @Remarks nvarchar(500) = '',   @Overdue bit = 0,    @DueToday bit = 1,   @Scheduled bit = 0,  @NoFollowUp bit = 0,  @AssignedTo bigint = 0, @CreatedBy  bigint = 0 


 declare @ParentId bigint = 0, @IsAdmin bit = 0                    
                   
 select @IsAdmin = IsAdmin, @ParentId = ParentID from User_Detail(nolock) where User_ID = @UserId                  
                
 declare @filterCondition nvarchar(max) = ''                
                
 declare @followupFilter nvarchar(max) = ''        
        
if(@Overdue = 1)        
begin        
 set @followupFilter += IIF(ISNULL(@followupFilter, '') = '', '  FollowupDateStatus = ''overdue'' ',  '  FollowupDateStatus = ''overdue'' ')        
end        
        
if(@DueToday = 1)        
begin        
 set @followupFilter += IIF(ISNULL(@followupFilter, '') = '', ' FollowupDateStatus = ''duetoday'' ',  ' or FollowupDateStatus = ''duetoday'' ')        
end        
        
if(@Scheduled = 1)        
begin        
 set @followupFilter += IIF(ISNULL(@followupFilter, '') = '', ' FollowupDateStatus = ''scheduled'' ',  ' or FollowupDateStatus = ''scheduled'' ')        
end        
        
if(@NoFollowUp = 1)        
begin        
 set @followupFilter += IIF(ISNULL(@followupFilter, '') = '', ' FollowupDateStatus = ''nofollowup'' ',  '  or FollowupDateStatus = ''nofollowup'' ')        
end        
        
if(ISNULL(@followupFilter, '') = '')        
begin        
 set @followupFilter +=  ' 1 = 0 '        
end        
        
        
 if(Isnull(@NextStatusFromDate, '') <> '')                
 begin                
 if(Isnull(@NextStatusToDate, '')<>'')                
 begin                
  set @filterCondition += ' and CAST(TRY_CONVERT(DATETIME, lih.NextStatusDate) AS DATE) between CAST(TRY_CONVERT(DATETIME, '''+ cast(@NextStatusFromDate as nvarchar(50)) +''' ) as date) and CAST(TRY_CONVERT(DATETIME, '''+ cast( +@NextStatusToDate as nvarchar(50)) +''' ) as date)'                
 end                
 end                
                
                
if(Isnull(@CreatedFromDate, '') <> '')                
 begin                
 if(Isnull(@CreatedToDate, '')<>'')                
 begin                
  set @filterCondition += ' and CAST(TRY_CONVERT(DATETIME, lih.CreatedOn) AS DATE) between CAST(TRY_CONVERT(DATETIME, '''+ cast( @CreatedFromDate as nvarchar(50)) +''' ) as date) and CAST(TRY_CONVERT(DATETIME, '''+ cast( + @CreatedToDate as nvarchar(    
      
        
          
            
50)) +''' ) as date) '                
 end                
 end                
                
if(Isnull(@LeadId, '') <> '')                
 begin                
 set @filterCondition += ' and  ul.ID = ' + str(@LeadId) + ' '                
end         
        
                
 declare @sqlQuery nvarchar(max) = N'SELECT count(ID) over() as TotalRow, * FROM ( SELECT                     
                        
    lih.ID,                      
    fs.FollowupStatus AS Title,                     
    lih.Remarks AS Discription,                     
    lih.followupDate AS NextStatusDate,                
    lih.CreatedOn,                
    lih.AmountPaid,                
    ul.ID AS LeadId,               
 iif(isnull(ltrim(rtrim(ul.MobileNo)), '''') <> '''', concat(ul.CountryCode, '' '', ul.MobileNo), '''' ) as MobileNo,              
 iif(isnull(ltrim(rtrim(ul.MobileNo2)), '''') <> '''', concat(ul.CountryCode2, '' '', ul.MobileNo2), '''' ) as MobileNo2,              
 iif(isnull(ltrim(rtrim(ul.MobileNo1)), '''') <> '''', concat(ul.CountryCode1, '' '', ul.MobileNo1), '''' ) as MobileNo1,              
    ul.PersonName,                     
 ul.ProfileImgFileName,                
    iif(ul.AssignedTo = '+ str(@UserId) +' or '+ str(@IsAdmin) +' = 1, 1, 0) as [IsUIActive],                
    lih.AssignedTo,                     
    LTRIM(RTRIM(concat(ud.FName, '' '', ud.LName))) AS [Owner],                    
    '''' as [Status],                    
    ud.ParentID as [ParentId],              
  ( CASE                    
    WHEN CAST(lih.followupDate AS DATE) = CAST(getdate() AS DATE)          
    THEN 0                    
    WHEN CAST(lih.followupDate AS DATE) < CAST(getdate() AS DATE)                   
    THEN 1                    
    WHEN CAST(lih.followupDate AS DATE) > CAST(getdate() AS DATE)               
    THEN 2                    
    WHEN CAST(lih.followupDate AS DATE) IS NULL                    
    THEN 3                    
  END ) as [OrderSeq],          
 ( CASE                    
    WHEN CAST(lih.followupDate AS DATE) = CAST(getdate() AS DATE)                    
    THEN ''duetoday''                    
    WHEN CAST(lih.followupDate AS DATE) < CAST(getdate() AS DATE)                   
    THEN ''overdue''                    
    WHEN CAST(lih.followupDate AS DATE) > CAST(getdate() AS DATE)               
    THEN ''scheduled''                   
    WHEN CAST(lih.followupDate AS DATE) IS NULL                    
    THEN ''nofollowup''                    
  END ) as [FollowupDateStatus]           
  FROM LeadInteractionHistory(NOLOCK) lih                    
    INNER JOIN FollowUp_Status(NOLOCK) fs ON lih.FollowUpStatus = fs.ID                    
    INNER JOIN UserLeads(NOLOCK) ul ON lih.LeadNo = ul.LeadNo                    
      AND ul.ParentID = lih.ParentID                    
    LEFT JOIN User_Detail(NOLOCK) ud ON lih.AssignedTo = ud.User_ID                    
  WHERE  
  lih.id=case when '''+ ISNULL(cast(nullif(@CreatedFromDate,'') as nvarchar(50)), '')  + ''' = '''' and ' + cast(@createdby as nvarchar) +' = 0 then (select max(id) from leadinteractionhistory(nolock) where parentid=lih.parentid and leadno=lih.leadno) else lih.id end and 
  ul.ParentID = ' + str(@ParentId) + '  '         
 + IIF( @AssignedTo = 0, '' , '  and lih.AssignedTo = ' + str( @AssignedTo )) + '  '               
 + IIF( @CreatedBy = 0, '' , '  and lih.CreatedBy = ' + str( @CreatedBy )) + '  '               
  + IIF(@IsAdmin = 1, ' and  1 = 1 ', ' and lih.AssignedTo = ' + str( @UserId ))  +                    
  ' AND (                  
  ' +  case                   
   when @FollowUpType = 0                   
    then  ' 1 = 1 '                  
   when @FollowUpType = 1                   
    then  ' lih.FollowUpStatus = 1 '                  
   when @FollowUpType = 2                   
    then  ' lih.FollowUpStatus = 2 '                
   when @FollowUpType = 3                   
    then  ' lih.FollowUpStatus = 3 '                  
   when @FollowUpType = 4                   
    then  ' lih.FollowUpStatus = 4 '                  
   when @FollowUpType = 5                   
    then  ' lih.FollowUpStatus = 5 '                  
    else                  
     ' 1 = 1 '                  
   end                   
                  
   + IIF(ISNULL(@filterCondition, '') <> '', @filterCondition, '' ) +                  
                  
   + IIF(ISNULL(@Remarks, '') <> '', ' and lih.Remarks like '''+ @Remarks +'%'' ', '' ) +                  
   ') ) as fu          
           
   ' + IIF( ISNULL( @followupFilter, '') = '', '', '  where ' + @followupFilter + '' )  +'            
           
        
  ORDER BY  OrderSeq, CAST(NextStatusDate AS DATETIME)                 
  OFFSET ' + str(@OffsetValue) + '  Rows FETCH NEXT ' + str(@PagingSize) +'  ROWS ONLY  '                  
                  
   print @sqlQuery                  
                  
   execute sp_executesql @sqlQuery                  
                  
end 


GO

/* ============================================================
   Procedure: [dbo].[usp_GetFollowUpListByUserId_withScoreCard]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON



--exec usp_GetFollowUpListByUserId_withScoreCard @OffsetValue=0,@PagingSize=300,@UserId=39042,@FollowUpType=0,@NextStatusFromDate=N'01-Jan-1900',@NextStatusToDate=N'18-Apr-2022',@CreatedFromDate=N'',@CreatedToDate=N'',@LeadId=N'',@Remarks=N'',@Overdue=1,@DueToday=0,@Scheduled=0,@NoFollowUp=0,@AssignedTo=0,@CreatedBy=0
--exec usp_GetFollowUpListByUserId_withScoreCard @OffsetValue=0,@PagingSize=100,@UserId=36950,@FollowUpType=0,@NextStatusFromDate=N'',@NextStatusToDate=N'',@CreatedFromDate=N'',@CreatedToDate=N'',@LeadId=N'',@Remarks=N'',@Overdue=1,@DueToday=1,@Scheduled=1,@NoFollowUp=1,@AssignedTo=0,@CreatedBy=0
--exec usp_GetFollowUpListByUserId_withScoreCard$ @OffsetValue=0,@PagingSize=100,@UserId=39680,@FollowUpType=0,@NextStatusFromDate=N'',@NextStatusToDate=N'',@CreatedFromDate=N'11-May-2022 00:00:00',@CreatedToDate=N'12-May-2022 00:00:00', @LeadId=N'', @Remarks=N'', @Overdue=1, @DueToday=1, @Scheduled=1, @NoFollowUp=1,@AssignedTo=0,@CreatedBy=0, @IsReAssign=0
/*
Revision	: DBA
			: 2025-07-29
