--exec usp_GetFollowUpListByUserId_withScoreCard @OffsetValue=0,@PagingSize=100,@UserId=36950,@FollowUpType=0,@NextStatusFromDate=N'',@NextStatusToDate=N'',@CreatedFromDate=N'',@CreatedToDate=N'',@LeadId=N'',@Remarks=N'',@Overdue=1,@DueToday=1,@Scheduled=1,@NoFollowUp=1,@AssignedTo=0,@CreatedBy=0  
