CREATE   PROCEDURE [dbo].[usp_GetFollowUpListByUserId_withScoreCard_JK_optmz]
(
     @OffsetValue        INT = 0
    ,@PagingSize         INT = 20
    ,@UserId             BIGINT
    ,@FollowUpType       NVARCHAR(MAX) = N'0'
    ,@NextStatusFromDate DATETIME = NULL
    ,@NextStatusToDate   DATETIME = NULL
    ,@CreatedFromDate    DATETIME = NULL
    ,@CreatedToDate      DATETIME = NULL
    ,@LeadId             BIGINT = NULL
    ,@Remarks            NVARCHAR(500) = N''
    ,@Overdue            BIT = 1
    ,@DueToday           BIT = 1
    ,@Scheduled          BIT = 1
    ,@NoFollowUp         BIT = 1
    ,@AssignedTo         BIGINT = 0
    ,@CreatedBy          BIGINT = 0
    ,@IsReAssign         BIT = NULL
)
AS
BEGIN

--declare @OffsetValue int=0, @PagingSize int = 100, @UserId bigint = 39042, @FollowUpType int = 0, @NextStatusFromDate datetime = N'', @NextStatusToDate datetime = N'', @CreatedFromDate datetime = N'', @CreatedToDate datetime = N'', @LeadId bigint = N'', @Remarks nvarchar(500) = N'', @Overdue bit = 1, @DueToday bit= 1, @Scheduled bit = 1, @NoFollowUp bit = 1, @AssignedTo bigint = 0, @CreatedBy bigint = 0  
 --declare @OffsetValue int=0, @PagingSize int = 100, @UserId bigint = 35610, @FollowUpType int = 0, @NextStatusFromDate datetime = N'', @NextStatusToDate datetime = N'', @CreatedFromDate datetime = N'', @CreatedToDate datetime = N'', @LeadId bigint = N'', @Remarks nvarchar(500) = N'', @Overdue bit = 1, @DueToday bit= 1, @Scheduled bit = 1, @NoFollowUp bit = 1, @AssignedTo bigint = 0, @CreatedBy bigint = 0  
 --declare @OffsetValue int = 0,@PagingSize int = 100,@UserId bigint=36950,@FollowUpType int = 0,@NextStatusFromDate datetime = N'',@NextStatusToDate datetime = N'',@CreatedFromDate datetime = N'',@CreatedToDate datetime = N'',@LeadId bigint = N'',@Remarks nvarchar(500) = '',@Overdue bit = 1,@DueToday bit = 1,@Scheduled bit = 1,@NoFollowUp bit = 1,@AssignedTo bigint = 0,@CreatedBy bigint = 0  
 --declare @OffsetValue int=0,@PagingSize int=100,@UserId bigint=39680,@FollowUpType int=0,@NextStatusFromDate datetime=N'',@NextStatusToDate datetime=N'',@CreatedFromDate datetime=N'09-May-2022 00:00:00',@CreatedToDate datetime=N'10-May-2022 00:00:00',@LeadId bigint=N'',@Remarks nvarchar(500)=N'',@Overdue bit=1,@DueToday bit=1,@Scheduled bit=1,@NoFollowUp bit=1,@AssignedTo bigint=0,@CreatedBy bigint=40062  
 --declare @OffsetValue int=0,@PagingSize int=100,@UserId bigint=39680,@FollowUpType int=0,@NextStatusFromDate datetime=N'',@NextStatusToDate datetime=N'',@CreatedFromDate datetime=N'09-May-2022 00:00:00',@CreatedToDate datetime=N'10-May-2022 00:00:00',@LeadId bigint=N'',@Remarks nvarchar(500)=N'',@Overdue bit=1,@DueToday bit=1,@Scheduled bit=1,@NoFollowUp bit=1,@AssignedTo bigint=0,@CreatedBy bigint=40061  
 --declare @OffsetValue int=0,@PagingSize int=100,@UserId bigint=40058,@FollowUpType int=461,@NextStatusFromDate datetime=N'',@NextStatusToDate datetime=N'',@CreatedFromDate datetime=N'01-Jun-2022 12:30:00',@CreatedToDate datetime=N'03-Jun-2022 12:30:00',@LeadId bigint=N'',@Remarks nvarchar(500)=N'',@Overdue bit=1,@DueToday bit=1,@Scheduled bit=1,@NoFollowUp bit=1,@AssignedTo bigint=0,@CreatedBy bigint=40058, @IsReAssign bit=0  
  
 --declare @OffsetValue int=0, @PagingSize int=100, @UserId bigint=31031, @FollowUpType int=N'1927', @NextStatusFromDate datetime=N'', @NextStatusToDate datetime=N'', @CreatedFromDate datetime=N'', @CreatedToDate datetime=N'', @LeadId bigint=N'', @Remarksnvarchar(500)=N'', @Overdue bit=1, @DueToday bit=1, @Scheduled bit=1, @NoFollowUp bit=1, @AssignedTo bigint=0, @CreatedBy bigint=0, @IsReAssign bit=0  
 -------------------------------------  
  
 --declare @OffsetValue int=0, @PagingSize int=100, @UserId bigint=34594, @FollowUpType int=N'', @NextStatusFromDate datetime=N'01-Jan-1900 00:00:00', @NextStatusToDate datetime=N'23-Sep-2025 00:00:00', @CreatedFromDate datetime=N'', @CreatedToDate datetime=N'', @LeadId bigint=N'', @Remarks nvarchar(500)=N'', @Overdue bit=1, @DueToday bit=0, @Scheduled bit=0, @NoFollowUp bit=0, @AssignedTo bigint=0, @CreatedBy bigint=0, @IsReAssign bit=null --263119  
 --declare @OffsetValue int=0, @PagingSize int=100, @UserId bigint=34594, @FollowUpType int=N'', @NextStatusFromDate datetime=N'23-Sep-2025 00:00:00', @NextStatusToDate datetime=N'24-Sep-2025 00:00:00', @CreatedFromDate datetime=N'', @CreatedToDate datetime=N'', @LeadId bigint=N'', @Remarks nvarchar(500)=N'', @Overdue bit=0, @DueToday bit=1, @Scheduled bit=0, @NoFollowUp bit=1, @AssignedTo bigint=0, @CreatedBy bigint=0, @IsReAssign bit=null --268  
 --declare @OffsetValue int=0, @PagingSize int=100, @UserId bigint=34594, @FollowUpType int=N'', @NextStatusFromDate datetime=N'23-Sep-2025 00:00:00', @NextStatusToDate datetime=N'30-Sep-2025 00:00:00', @CreatedFromDate datetime=N'', @CreatedToDate datetime=N'', @LeadId bigint=N'', @Remarks nvarchar(500)=N'', @Overdue bit=0, @DueToday bit=1, @Scheduled bit=1, @NoFollowUp bit=1, @AssignedTo bigint=0, @CreatedBy bigint=0, @IsReAssign bit=null --290  
  
 --declare @OffsetValue int=0, @PagingSize int=100, @UserId bigint=34594, @FollowUpType int=N'', @NextStatusFromDate datetime=N'01-Sep-2025 00:00:00', @NextStatusToDate datetime=N'30-Sep-2025 00:00:00', @CreatedFromDate datetime=N'', @CreatedToDate datetime=N'', @LeadId bigint=N'', @Remarks nvarchar(500)=N'', @Overdue bit=1, @DueToday bit=1, @Scheduled bit=1, @NoFollowUp bit=1, @AssignedTo bigint=0, @CreatedBy bigint=0, @IsReAssign bit=null --3320  
  
  
 --SELECT @OffsetValue=0,@PagingSize=100,@UserId=50295,@FollowUpType=N'',@NextStatusFromDate=N'',@NextStatusToDate=N'',@CreatedFromDate=N'',@CreatedToDate=N'',@LeadId=N'',@Remarks=N'',@Overdue=1,@DueToday=1,@Scheduled=1,@NoFollowUp=1,@AssignedTo=0,@CreatedBy=0  

    SET NOCOUNT ON;

    DROP TABLE IF EXISTS #lihInner;
    DROP TABLE IF EXISTS #lsh;
    DROP TABLE IF EXISTS #lih;
    DROP TABLE IF EXISTS #page;
    DROP TABLE IF EXISTS #FollowUpFilter;

    DECLARE @ParentId BIGINT = 0,
            @IsAdmin  BIT    = 0;

    SELECT
        @IsAdmin  = ud.IsAdmin,
        @ParentId = ud.ParentID
    FROM dbo.User_Detail ud WITH (NOLOCK)
    WHERE ud.User_ID = @UserId;

    DECLARE @tbluser TABLE
    (
        User_ID BIGINT,
        Name    VARCHAR(100),
        [IMAGE] VARCHAR(100)
    );

    INSERT INTO @tbluser
    EXEC dbo.Use_GetUserDetails @UserId;

    CREATE TABLE #FollowUpFilter (ID INT NOT NULL PRIMARY KEY);

    INSERT INTO #FollowUpFilter(ID)
    SELECT DISTINCT TRY_CONVERT(INT, [value])
    FROM dbo.fn_Split(@FollowUpType, ',')
    WHERE TRY_CONVERT(INT, [value]) IS NOT NULL
      AND TRY_CONVERT(INT, [value]) <> 0;

    DECLARE @flpIDsCount INT = (SELECT COUNT(*) FROM #FollowUpFilter);

    DECLARE @maxScore NUMERIC(18,2) =
        ISNULL((
            SELECT (MAX(currentscore) * 100) / 99
            FROM dbo.lead_score_history e WITH (NOLOCK)
            WHERE e.parentid = @ParentId
        ), 0);

    DECLARE @hot INT, @warm INT, @cold INT;

    SELECT @hot = hot, @warm = warm, @cold = cold
    FROM dbo.lead_cateogy_thresholds WITH (NOLOCK)
    WHERE parentid = @ParentID;

    IF @hot IS NULL
    BEGIN
        SELECT @hot = hot, @warm = warm, @cold = cold
        FROM dbo.lead_cateogy_thresholds WITH (NOLOCK)
        WHERE parentid = 0;
    END;

    CREATE TABLE #lihInner (ID BIGINT NOT NULL PRIMARY KEY);

    IF (ISNULL(@CreatedFromDate, '19000101') > '19000101')
    BEGIN
        INSERT INTO #lihInner(ID)
        SELECT lih.ID
        FROM dbo.leadinteractionhistory lih WITH (NOLOCK)
        WHERE lih.ParentID = @ParentId;
    END
    ELSE
    BEGIN
        INSERT INTO #lihInner(ID)
        SELECT MAX(lih.ID) AS ID
        FROM dbo.leadinteractionhistory lih WITH (NOLOCK)
        WHERE lih.ParentID = @ParentId
        GROUP BY lih.LeadNo;
    END;

    ;WITH s AS
    (
        SELECT
            lsh.ParentID,
            lsh.LeadID,
            lsh.CurrentScore,
            lsh.ScoreAdded,
            rn = ROW_NUMBER() OVER
                 (PARTITION BY lsh.ParentID, lsh.LeadID ORDER BY lsh.ID DESC)
        FROM dbo.lead_score_history lsh WITH (NOLOCK)
        WHERE lsh.ParentID = @ParentID
    )
    SELECT ParentID, LeadID, CurrentScore, ScoreAdded
    INTO #lsh
    FROM s
    WHERE rn = 1;

    CREATE UNIQUE CLUSTERED INDEX CX_lsh_Parent_Lead
        ON #lsh(ParentID, LeadID);

    SELECT
        TotalRow       = COUNT_BIG(1) OVER(),
        lih.ID,
        NextStatusDate = lih.FollowUpDate,
        CreatedOn      = lih.CreatedOn,
        OrderSeq       =
            CASE
                WHEN CAST(lih.FollowUpDate AS DATE) = CAST(GETDATE() AS DATE) THEN 0
                WHEN CAST(lih.FollowUpDate AS DATE) < CAST(GETDATE() AS DATE) THEN 1
                WHEN CAST(lih.FollowUpDate AS DATE) > CAST(GETDATE() AS DATE) THEN 2
                WHEN lih.FollowUpDate IS NULL THEN 3
            END,
        FollowupDateStatus =
            CASE
                WHEN CAST(lih.FollowUpDate AS DATE) = CAST(GETDATE() AS DATE) THEN 'duetoday'
                WHEN CAST(lih.FollowUpDate AS DATE) < CAST(GETDATE() AS DATE) THEN 'overdue'
                WHEN CAST(lih.FollowUpDate AS DATE) > CAST(GETDATE() AS DATE) THEN 'scheduled'
                WHEN lih.FollowUpDate IS NULL THEN 'nofollowup'
            END,
        SortDT = CASE WHEN lih.FollowUpDate > lih.CreatedOn THEN lih.FollowUpDate ELSE lih.CreatedOn END
    INTO #lih
    FROM dbo.leadinteractionhistory lih WITH (NOLOCK)
    INNER JOIN #lihInner t ON t.ID = lih.ID
    INNER JOIN dbo.followup_status fs WITH (NOLOCK) ON fs.id = lih.followupstatus
    INNER JOIN dbo.userleads ul WITH (NOLOCK)
        ON ul.leadno   = lih.leadno
       AND ul.parentid = lih.parentid
    WHERE
        lih.ParentID = @ParentId
        AND ul.parentid = @ParentId

        AND lih.IsReassign =
            CASE
                WHEN @IsReAssign IS NULL AND @CreatedBy <> 0 THEN 0
                WHEN @IsReAssign IS NOT NULL THEN @IsReAssign
                ELSE lih.IsReassign
            END

        AND
        (
            (@flpIDsCount = 0 AND @NoFollowUp = 1 AND @Scheduled = 1 AND @DueToday = 1 AND @Overdue = 1)
            OR
            (@flpIDsCount = 0 AND fs.IsCallback = 1)
            OR
            (@flpIDsCount > 0 AND EXISTS (SELECT 1 FROM #FollowUpFilter f WHERE f.ID = lih.FollowUpStatus))
        )

        AND
        (
            @IsAdmin = 1
            OR EXISTS (SELECT 1 FROM @tbluser u WHERE u.User_ID = ISNULL(ul.AssignedTo,0))
            OR ISNULL(ul.AssignedTo,0) = @UserId
        )

        AND
        (
            ISNULL(@AssignedTo,0) = 0
            OR (ISNULL(@AssignedTo,0) > 0 AND lih.AssignedTo = @AssignedTo)
        )

        AND
        (
            ISNULL(@CreatedBy,0) = 0
            OR (ISNULL(@CreatedBy,0) > 0 AND lih.CreatedBy = @CreatedBy)
        )

        AND
        (
            @NextStatusFromDate IS NULL OR @NextStatusToDate IS NULL
            OR (CAST(lih.FollowUpDate AS DATE) BETWEEN CAST(@NextStatusFromDate AS DATE) AND CAST(@NextStatusToDate AS DATE))
        )

        AND
        (
            @CreatedFromDate IS NULL OR @CreatedToDate IS NULL
            OR (CAST(lih.CreatedOn AS DATE) BETWEEN CAST(@CreatedFromDate AS DATE) AND CAST(@CreatedToDate AS DATE))
        )

        AND
        (
            ISNULL(@LeadId,0) = 0
            OR ul.ID = @LeadId
        )

        AND
        (
            ISNULL(@Remarks,'') = ''
            OR lih.Remarks LIKE N'%' + @Remarks + N'%'
        )

        AND
        (
            (@flpIDsCount > 0 AND fs.IsConvert = 1)
            OR ( (@NextStatusFromDate IS NOT NULL AND @NextStatusToDate IS NOT NULL) )
            OR fs.IsConvert <> 1
        )

        AND
        (
            fs.IsConvert = 1
            OR (CAST(lih.FollowUpDate AS DATE) < CAST(GETDATE() AS DATE) AND @Overdue   = 1)
            OR (CAST(lih.FollowUpDate AS DATE) = CAST(GETDATE() AS DATE) AND @DueToday = 1)
            OR (CAST(lih.FollowUpDate AS DATE) > CAST(GETDATE() AS DATE) AND @Scheduled= 1)
            OR (lih.FollowUpDate IS NULL AND @NoFollowUp = 1)
        )
    OPTION (RECOMPILE);

    CREATE CLUSTERED INDEX CX_lih_OrderSort
        ON #lih (OrderSeq, SortDT DESC, ID);

    SELECT TotalRow, ID, NextStatusDate, CreatedOn, OrderSeq, FollowupDateStatus, SortDT
    INTO #page
    FROM #lih
    ORDER BY OrderSeq, SortDT DESC, ID
    OFFSET @OffsetValue ROWS
    FETCH NEXT @PagingSize ROWS ONLY;

    SELECT
        p.TotalRow,
        lih.ID,
        fs.followupstatus AS Title,
        fs.IsConvert,
        lih.remarks AS Discription,
        lih.followupdate AS NextStatusDate,
        lih.CreatedOn,
        lih.AmountPaid,
        ul.id AS LeadId,

        IIF(NULLIF(LTRIM(RTRIM(ul.mobileno)), '') IS NOT NULL, CONCAT(ul.countrycode,  ' ', ul.mobileno),  '') AS MobileNo,
        IIF(NULLIF(LTRIM(RTRIM(ul.mobileno2)), '') IS NOT NULL, CONCAT(ul.countrycode2, ' ', ul.mobileno2), '') AS MobileNo2,
        IIF(NULLIF(LTRIM(RTRIM(ul.mobileno1)), '') IS NOT NULL, CONCAT(ul.countrycode1, ' ', ul.mobileno1), '') AS MobileNo1,

        ul.PersonName,
        ul.ProfileImgFileName,

        IIF(ul.assignedto = @UserId OR @IsAdmin = 1, 1, 0) AS IsUIActive,

        lih.assignedto,
        LTRIM(RTRIM(CONCAT(ud.fname,' ',ud.lname))) AS [Owner],
        '' AS [Status],
        ud.parentid AS ParentId,

        p.OrderSeq,
        p.FollowupDateStatus,

        CASE
            WHEN ls.ScoreAdded > 0 THEN 'green_up'
            WHEN ls.ScoreAdded < 0 THEN 'red_down'
            ELSE ''
        END AS Profit_Loss,

        CAST(ISNULL((ls.CurrentScore / NULLIF(@maxScore, 0.00)) * 99, 0) AS INT) AS CurrentScore,

        CASE
            WHEN CAST(ISNULL((ls.CurrentScore / NULLIF(@maxScore, 0.00)) * 99, 0) AS INT) > @warm THEN 'hot'
            WHEN CAST(ISNULL((ls.CurrentScore / NULLIF(@maxScore, 0.00)) * 99, 0) AS INT) BETWEEN @cold AND @warm THEN 'warm'
            ELSE 'cold'
        END AS ThresholdColor
    FROM #page p
    INNER JOIN dbo.leadinteractionhistory lih WITH (NOLOCK) ON lih.ID = p.ID
    INNER JOIN dbo.followup_status fs WITH (NOLOCK) ON fs.id = lih.followupstatus
    INNER JOIN dbo.userleads ul WITH (NOLOCK)
        ON ul.leadno   = lih.leadno
       AND ul.parentid = lih.parentid
    LEFT JOIN #lsh ls
        ON ls.LeadID   = ul.ID
       AND ls.ParentID = ul.ParentID
    LEFT JOIN dbo.user_detail ud WITH (NOLOCK)
        ON ud.user_id = lih.assignedto
    ORDER BY p.OrderSeq, p.SortDT DESC, p.ID;

    EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId
         @User_id       = @UserId,
         @Activity_type = 'View_flwup',
         @ActionType    = 'F',
         @RowJson       = '',
         @Table_name    = 'leadinteractionhistory';
END



GO

