	--declare @OffsetValue int=0,@PagingSize int=100,@UserId bigint=39680,@FollowUpType int=0,@NextStatusFromDate datetime=N'',@NextStatusToDate datetime=N'',@CreatedFromDate datetime=N'09-May-2022 00:00:00',@CreatedToDate datetime=N'10-May-2022 00:00:00',@LeadId bigint=N'',@Remarks nvarchar(500)=N'',@Overdue bit=1,@DueToday bit=1,@Scheduled bit=1,@NoFollowUp bit=1,@AssignedTo bigint=0,@CreatedBy bigint=40061
	--declare @OffsetValue int=0,@PagingSize int=100,@UserId bigint=40058,@FollowUpType int=461,@NextStatusFromDate datetime=N'',@NextStatusToDate datetime=N'',@CreatedFromDate datetime=N'01-Jun-2022 12:30:00',@CreatedToDate datetime=N'03-Jun-2022 12:30:00',@LeadId bigint=N'',@Remarks nvarchar(500)=N'',@Overdue bit=1,@DueToday bit=1,@Scheduled bit=1,@NoFollowUp bit=1,@AssignedTo bigint=0,@CreatedBy bigint=40058, @IsReAssign bit=0

	--declare @OffsetValue int=0, @PagingSize int=100, @UserId bigint=31031, @FollowUpType int=N'1927', @NextStatusFromDate datetime=N'', @NextStatusToDate datetime=N'', @CreatedFromDate datetime=N'', @CreatedToDate datetime=N'', @LeadId bigint=N'', @Remarks nvarchar(500)=N'', @Overdue bit=1, @DueToday bit=1, @Scheduled bit=1, @NoFollowUp bit=1, @AssignedTo bigint=0, @CreatedBy bigint=0, @IsReAssign bit=0
	-------------------------------------

	--declare @OffsetValue int=0, @PagingSize int=100, @UserId bigint=34594, @FollowUpType int=N'', @NextStatusFromDate datetime=N'01-Jan-1900 00:00:00', @NextStatusToDate datetime=N'23-Sep-2025 00:00:00', @CreatedFromDate datetime=N'', @CreatedToDate datetime=N'', @LeadId bigint=N'', @Remarks nvarchar(500)=N'', @Overdue bit=1, @DueToday bit=0, @Scheduled bit=0, @NoFollowUp bit=0, @AssignedTo bigint=0, @CreatedBy bigint=0, @IsReAssign bit=null	--263119
	--declare @OffsetValue int=0, @PagingSize int=100, @UserId bigint=34594, @FollowUpType int=N'', @NextStatusFromDate datetime=N'23-Sep-2025 00:00:00', @NextStatusToDate datetime=N'24-Sep-2025 00:00:00', @CreatedFromDate datetime=N'', @CreatedToDate datetime=N'', @LeadId bigint=N'', @Remarks nvarchar(500)=N'', @Overdue bit=0, @DueToday bit=1, @Scheduled bit=0, @NoFollowUp bit=1, @AssignedTo bigint=0, @CreatedBy bigint=0, @IsReAssign bit=null	--268
	--declare @OffsetValue int=0, @PagingSize int=100, @UserId bigint=34594, @FollowUpType int=N'', @NextStatusFromDate datetime=N'23-Sep-2025 00:00:00', @NextStatusToDate datetime=N'30-Sep-2025 00:00:00', @CreatedFromDate datetime=N'', @CreatedToDate datetime=N'', @LeadId bigint=N'', @Remarks nvarchar(500)=N'', @Overdue bit=0, @DueToday bit=1, @Scheduled bit=1, @NoFollowUp bit=1, @AssignedTo bigint=0, @CreatedBy bigint=0, @IsReAssign bit=null	--290

	--declare @OffsetValue int=0, @PagingSize int=100, @UserId bigint=34594, @FollowUpType int=N'', @NextStatusFromDate datetime=N'01-Sep-2025 00:00:00', @NextStatusToDate datetime=N'30-Sep-2025 00:00:00', @CreatedFromDate datetime=N'', @CreatedToDate datetime=N'', @LeadId bigint=N'', @Remarks nvarchar(500)=N'', @Overdue bit=1, @DueToday bit=1, @Scheduled bit=1, @NoFollowUp bit=1, @AssignedTo bigint=0, @CreatedBy bigint=0, @IsReAssign bit=null	--3320


	--SELECT @OffsetValue=0,@PagingSize=100,@UserId=50295,@FollowUpType=N'',@NextStatusFromDate=N'',@NextStatusToDate=N'',@CreatedFromDate=N'',@CreatedToDate=N'',@LeadId=N'',@Remarks=N'',@Overdue=1,@DueToday=1,@Scheduled=1,@NoFollowUp=1,@AssignedTo=0,@CreatedBy=0



    SET NOCOUNT ON;

    SET @OffsetValue = CASE WHEN @OffsetValue < 0 THEN 0 ELSE @OffsetValue END;
    SET @PagingSize  = CASE WHEN @PagingSize  <= 0 THEN 20 ELSE @PagingSize  END;

    SET @CriteriaName = NULLIF(LTRIM(RTRIM(ISNULL(@CriteriaName, N''))), N'');
    SET @Remarks      = NULLIF(LTRIM(RTRIM(ISNULL(@Remarks, N''))), N'');

    IF @NextStatusFromDate IS NOT NULL AND @NextStatusFromDate <= '19000101' SET @NextStatusFromDate = NULL;
    IF @NextStatusToDate   IS NOT NULL AND @NextStatusToDate   <= '19000101' SET @NextStatusToDate   = NULL;
    IF @CreatedFromDate    IS NOT NULL AND @CreatedFromDate    <= '19000101' SET @CreatedFromDate    = NULL;
    IF @CreatedToDate      IS NOT NULL AND @CreatedToDate      <= '19000101' SET @CreatedToDate      = NULL;

    IF @NextStatusFromDate IS NOT NULL AND @NextStatusToDate IS NULL SET @NextStatusToDate = '21231231';
    IF @CreatedFromDate    IS NOT NULL AND @CreatedToDate    IS NULL SET @CreatedToDate    = '21231231';

    IF @NextStatusToDate IS NOT NULL AND @NextStatusFromDate IS NULL SET @NextStatusFromDate = '19000101';
    IF @CreatedToDate    IS NOT NULL AND @CreatedFromDate    IS NULL SET @CreatedFromDate    = '19000101';

    DECLARE @ParentId BIGINT = 0, @IsAdmin BIT = 0;

    SELECT
        @IsAdmin  = ud.IsAdmin,
        @ParentId = ud.ParentID
    FROM dbo.User_Detail ud WITH (NOLOCK)
    WHERE ud.User_ID = @UserId;

    IF @ParentId IS NULL OR @ParentId = 0
    BEGIN

        SELECT TOP (0) *
        FROM (VALUES (CAST(NULL AS BIGINT))) X(Dummy);
        RETURN;
    END

    DECLARE @tbluser TABLE
    (
        User_ID BIGINT PRIMARY KEY,
        Name    VARCHAR(100),
        [IMAGE] VARCHAR(100)
    );

    INSERT INTO @tbluser
    EXEC dbo.Use_GetUserDetails @UserId;

    DECLARE @FollowUpIDs TABLE (Id INT PRIMARY KEY);

    INSERT INTO @FollowUpIDs (Id)
    SELECT DISTINCT TRY_CONVERT(INT, s.value)
    FROM dbo.fn_Split(@FollowUpType, N',') s
    WHERE TRY_CONVERT(INT, s.value) IS NOT NULL
      AND TRY_CONVERT(INT, s.value) <> 0;

    DECLARE @HasFollowUpFilter BIT = CASE WHEN EXISTS (SELECT 1 FROM @FollowUpIDs) THEN 1 ELSE 0 END;

    CREATE TABLE #userleadsBySegment (ID BIGINT NOT NULL PRIMARY KEY);
    DECLARE @UseSegment BIT = CASE WHEN @CriteriaName IS NULL THEN 0 ELSE 1 END;

    IF @UseSegment = 1
    BEGIN
        DECLARE @SPID INT = @@SPID;
        DELETE FROM dbo.tbl_LeadID_WithSPID WHERE SP_ID = @SPID;

        DECLARE @LeadCount INT = (SELECT COUNT(1) FROM dbo.UserLeads WITH (NOLOCK) WHERE ParentID = @ParentId);

        EXEC dbo.Usp_ViewLeadDetailsBySearchCriteria_IDSegment_SPID
              1, @LeadCount, @CriteriaName, @UserId, 0, 'Name';

        INSERT INTO #userleadsBySegment (ID)
        SELECT LeadID
        FROM dbo.tbl_LeadID_WithSPID WITH (NOLOCK)
        WHERE SP_ID = @SPID;

        DELETE FROM dbo.tbl_LeadID_WithSPID WHERE SP_ID = @SPID;
    END

    DECLARE @maxScore NUMERIC(18,2) =
        ISNULL((
            SELECT (MAX(lsh.CurrentScore) * 100.0) / 99.0
            FROM dbo.lead_score_history lsh WITH (NOLOCK)
            WHERE lsh.ParentID = @ParentId
        ), 0);

    DECLARE @hot INT, @warm INT, @cold INT;

    SELECT @hot = hot, @warm = warm, @cold = cold
    FROM dbo.lead_cateogy_thresholds WITH (NOLOCK)
    WHERE ParentID = @ParentId;

    IF @hot IS NULL
    BEGIN
        SELECT @hot = hot, @warm = warm, @cold = cold
        FROM dbo.lead_cateogy_thresholds WITH (NOLOCK)
        WHERE ParentID = 0;
    END

    DROP TABLE IF EXISTS #lihInner;
    DROP TABLE IF EXISTS #page;
    DROP TABLE IF EXISTS #pageLeads;
    DROP TABLE IF EXISTS #lsh;

    CREATE TABLE #lihInner
    (
        ParentID BIGINT NOT NULL,
        LeadNo   BIGINT NOT NULL,
        ID       BIGINT NOT NULL
    );

    IF @CreatedFromDate IS NOT NULL
    BEGIN
        INSERT INTO #lihInner (ParentID, LeadNo, ID)
        SELECT ParentID, LeadNo, ID
        FROM dbo.LeadInteractionHistory WITH (NOLOCK)
        WHERE ParentID = @ParentId;
    END
    ELSE
    BEGIN
        INSERT INTO #lihInner (ParentID, LeadNo, ID)
        SELECT ParentID, LeadNo, MAX(ID)
        FROM dbo.LeadInteractionHistory WITH (NOLOCK)
        WHERE ParentID = @ParentId
        GROUP BY ParentID, LeadNo;
    END

    CREATE UNIQUE CLUSTERED INDEX CX_lihInner_ID ON #lihInner(ID);

    ;WITH cte AS
    (
        SELECT
              TotalRow = COUNT_BIG(1) OVER()
            , lih.ID
            , lih.FollowUpDate AS NextStatusDate
            , lih.CreatedOn
            , FollowupDateStatus =
                CASE
                    WHEN CAST(lih.FollowUpDate AS DATE) = CAST(GETDATE() AS DATE) THEN 'duetoday'
                    WHEN CAST(lih.FollowUpDate AS DATE) < CAST(GETDATE() AS DATE) THEN 'overdue'
                    WHEN CAST(lih.FollowUpDate AS DATE) > CAST(GETDATE() AS DATE) THEN 'scheduled'
                    WHEN lih.FollowUpDate IS NULL THEN 'nofollowup'
                END
            , OrderSeq =
                CASE
                    WHEN CAST(lih.FollowUpDate AS DATE) = CAST(GETDATE() AS DATE) THEN 0
                    WHEN CAST(lih.FollowUpDate AS DATE) < CAST(GETDATE() AS DATE) THEN 1
                    WHEN CAST(lih.FollowUpDate AS DATE) > CAST(GETDATE() AS DATE) THEN 2
                    WHEN lih.FollowUpDate IS NULL THEN 3
                END
            , SortDT = CASE WHEN lih.FollowUpDate > lih.CreatedOn THEN lih.FollowUpDate ELSE lih.CreatedOn END
        FROM dbo.LeadInteractionHistory lih WITH (NOLOCK)
        INNER JOIN #lihInner li ON li.ID = lih.ID
        INNER JOIN dbo.FollowUp_Status fs WITH (NOLOCK) ON fs.ID = lih.FollowUpStatus
        INNER JOIN dbo.UserLeads ul WITH (NOLOCK)
            ON ul.LeadNo = lih.LeadNo
           AND ul.ParentID = lih.ParentID
        WHERE
            lih.ParentID = @ParentId
            AND ul.ParentID = @ParentId

            AND (@UseSegment = 0 OR EXISTS (SELECT 1 FROM #userleadsBySegment s WHERE s.ID = ul.ID))

            AND ( @IsReAssign IS NULL OR lih.IsReassign = @IsReAssign )
AND (
                    @IsAdmin = 1
                    OR EXISTS (SELECT 1 FROM @tbluser tu WHERE tu.User_ID = ISNULL(ul.AssignedTo,0))
                    OR ISNULL(ul.AssignedTo,0) = @UserId
                )

            AND (@AssignedTo = 0 OR lih.AssignedTo = @AssignedTo)
            AND (@CreatedBy  = 0 OR lih.CreatedBy  = @CreatedBy)
            AND (ISNULL(@LeadId,0) = 0 OR ul.ID = @LeadId)
            AND (@Remarks IS NULL OR lih.Remarks LIKE N'%' + @Remarks + N'%')

            AND (
                @NextStatusFromDate IS NULL OR @NextStatusToDate IS NULL
                OR CAST(lih.FollowUpDate AS DATE) BETWEEN CAST(@NextStatusFromDate AS DATE) AND CAST(@NextStatusToDate AS DATE)
            )

            AND (
                @CreatedFromDate IS NULL OR @CreatedToDate IS NULL
                OR CAST(lih.CreatedOn AS DATE) BETWEEN CAST(@CreatedFromDate AS DATE) AND CAST(@CreatedToDate AS DATE)
            )

            AND (
                fs.IsConvert = 0
                OR @HasFollowUpFilter = 1
                OR (@NextStatusFromDate IS NOT NULL AND @NextStatusToDate IS NOT NULL)
            )

            AND (
                    (@HasFollowUpFilter = 1 AND EXISTS (SELECT 1 FROM @FollowUpIDs f WHERE f.Id = lih.FollowUpStatus))
                 OR (@HasFollowUpFilter = 0 AND ((@NoFollowUp=1 AND @Scheduled=1 AND @DueToday=1 AND @Overdue=1) OR fs.IsCallback = 1))
                )

            AND (
                fs.IsConvert = 1
                OR (CAST(lih.FollowUpDate AS DATE) < CAST(GETDATE() AS DATE) AND @Overdue  = 1)
                OR (CAST(lih.FollowUpDate AS DATE) = CAST(GETDATE() AS DATE) AND @DueToday = 1)
                OR (CAST(lih.FollowUpDate AS DATE) > CAST(GETDATE() AS DATE) AND @Scheduled = 1)
                OR (lih.FollowUpDate IS NULL AND @NoFollowUp = 1)
            )
    )
    SELECT
          TotalRow
        , ID
        , OrderSeq
        , NextStatusDate
        , CreatedOn
        , SortDT
    INTO #page
    FROM cte
    ORDER BY OrderSeq, SortDT DESC, ID
    OFFSET @OffsetValue ROWS FETCH NEXT @PagingSize ROWS ONLY;

    CREATE UNIQUE CLUSTERED INDEX CX_page_ID ON #page(ID);

    SELECT DISTINCT ul.ID AS LeadID
    INTO #pageLeads
    FROM #page p
    JOIN dbo.LeadInteractionHistory lih WITH (NOLOCK) ON lih.ID = p.ID
    JOIN dbo.UserLeads ul WITH (NOLOCK)
      ON ul.LeadNo = lih.LeadNo
     AND ul.ParentID = lih.ParentID;

    CREATE UNIQUE CLUSTERED INDEX CX_pageLeads ON #pageLeads(LeadID);

    ;WITH MaxScore AS
    (
        SELECT lsh.LeadID, MAX(lsh.ID) AS MaxID
        FROM dbo.lead_score_history lsh WITH (NOLOCK)
        JOIN #pageLeads pl ON pl.LeadID = lsh.LeadID
        WHERE lsh.ParentID = @ParentId
        GROUP BY lsh.LeadID
    )
    SELECT lsh.*
    INTO #lsh
    FROM dbo.lead_score_history lsh WITH (NOLOCK)
    JOIN MaxScore m ON m.MaxID = lsh.ID;

    CREATE UNIQUE CLUSTERED INDEX CX_lsh_LeadID ON #lsh(LeadID);

    SELECT
          p.TotalRow
        , lih.ID
        , fs.FollowupStatus AS Title
        , fs.IsConvert
        , lih.Remarks AS Discription
        , lih.FollowUpDate AS NextStatusDate
        , lih.CreatedOn
        , lih.AmountPaid
        , ul.ID AS LeadId
        , IIF(ISNULL(LTRIM(RTRIM(ul.MobileNo)), '') <> '', CONCAT(ul.CountryCode, ' ', ul.MobileNo), '') AS MobileNo
        , IIF(ISNULL(LTRIM(RTRIM(ul.MobileNo2)), '') <> '', CONCAT(ul.CountryCode2,' ', ul.MobileNo2), '') AS MobileNo2
        , IIF(ISNULL(LTRIM(RTRIM(ul.MobileNo1)), '') <> '', CONCAT(ul.CountryCode1,' ', ul.MobileNo1), '') AS MobileNo1
        , ul.PersonName
        , ul.ProfileImgFileName
        , IIF(ul.AssignedTo = @UserId OR @IsAdmin = 1, 1, 0) AS IsUIActive
        , lih.AssignedTo
        , LTRIM(RTRIM(CONCAT(ud.fname, ' ', ud.lname))) AS [Owner]
        , '' AS [Status]
        , ud.ParentID AS ParentId
        , p.OrderSeq
        , CASE
            WHEN CAST(lih.FollowUpDate AS DATE) = CAST(GETDATE() AS DATE) THEN 'duetoday'
            WHEN CAST(lih.FollowUpDate AS DATE) < CAST(GETDATE() AS DATE) THEN 'overdue'
            WHEN CAST(lih.FollowUpDate AS DATE) > CAST(GETDATE() AS DATE) THEN 'scheduled'
            WHEN lih.FollowUpDate IS NULL THEN 'nofollowup'
          END AS FollowupDateStatus
        , CASE
            WHEN ls.ScoreAdded > 0 THEN 'green_up'
            WHEN ls.ScoreAdded < 0 THEN 'red_down'
            ELSE ''
          END AS Profit_Loss
        , CAST(ISNULL((ls.CurrentScore / NULLIF(@maxScore, 0.00)) * 99, 0) AS INT) AS CurrentScore
        , CASE
            WHEN CAST(ISNULL((ls.CurrentScore / NULLIF(@maxScore, 0.00)) * 99, 0) AS INT) > @warm THEN 'hot'
            WHEN CAST(ISNULL((ls.CurrentScore / NULLIF(@maxScore, 0.00)) * 99, 0) AS INT) BETWEEN @cold AND @warm THEN 'warm'
            ELSE 'cold'
          END AS ThresholdColor
    FROM #page p
    JOIN dbo.LeadInteractionHistory lih WITH (NOLOCK) ON lih.ID = p.ID
    JOIN dbo.FollowUp_Status fs WITH (NOLOCK) ON fs.ID = lih.FollowUpStatus
    JOIN dbo.UserLeads ul WITH (NOLOCK)
      ON ul.LeadNo = lih.LeadNo
     AND ul.ParentID = lih.ParentID
    LEFT JOIN #lsh ls ON ls.LeadID = ul.ID
    LEFT JOIN dbo.User_Detail ud WITH (NOLOCK) ON ud.User_ID = lih.AssignedTo
    ORDER BY p.OrderSeq, p.SortDT DESC, p.ID;

    EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId
          @User_id = @UserId
        , @Activity_type = 'View_flwup'
        , @ActionType = 'F'
        , @RowJson = ''
        , @Table_name = 'leadinteractionhistory';
END



GO

/* ============================================================
   Procedure: [dbo].[usp_GetFollowUpListByUserId_withScoreCard_jk2]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[usp_GetFollowUpListByUserId_withScoreCard_jk2]
(
      @OffsetValue        INT            = 0
    , @PagingSize         INT            = 20
    , @UserId             BIGINT
    , @FollowUpType       NVARCHAR(MAX)  = N'0'
    , @NextStatusFromDate DATETIME       = NULL
    , @NextStatusToDate   DATETIME       = NULL
    , @CreatedFromDate    DATETIME       = NULL
    , @CreatedToDate      DATETIME       = NULL
    , @LeadId             BIGINT         = NULL
    , @Remarks            NVARCHAR(500)  = N''
    , @Overdue            BIT            = 1
    , @DueToday           BIT            = 1
    , @Scheduled          BIT            = 1
    , @NoFollowUp         BIT            = 1
    , @AssignedTo         BIGINT         = 0
    , @CreatedBy          BIGINT         = 0
    , @IsReAssign         BIT            = NULL
    , @CriteriaName       NVARCHAR(500)  = NULL
    , @SkipAudit          BIT            = 0
)
AS
BEGIN
    SET NOCOUNT ON;

    SET @OffsetValue = CASE WHEN @OffsetValue < 0  THEN 0  ELSE @OffsetValue END;
    SET @PagingSize  = CASE WHEN @PagingSize  <= 0 THEN 20 ELSE @PagingSize  END;

    SET @CriteriaName = NULLIF(LTRIM(RTRIM(ISNULL(@CriteriaName, N''))), N'');
    SET @Remarks      = NULLIF(LTRIM(RTRIM(ISNULL(@Remarks,      N''))), N'');

    IF @NextStatusFromDate IS NOT NULL AND @NextStatusFromDate <= '19000101' SET @NextStatusFromDate = NULL;
    IF @NextStatusToDate   IS NOT NULL AND @NextStatusToDate   <= '19000101' SET @NextStatusToDate   = NULL;
    IF @CreatedFromDate    IS NOT NULL AND @CreatedFromDate    <= '19000101' SET @CreatedFromDate    = NULL;
    IF @CreatedToDate      IS NOT NULL AND @CreatedToDate      <= '19000101' SET @CreatedToDate      = NULL;

    IF @NextStatusFromDate IS NOT NULL AND @NextStatusToDate   IS NULL SET @NextStatusToDate   = '21231231';
    IF @CreatedFromDate    IS NOT NULL AND @CreatedToDate      IS NULL SET @CreatedToDate      = '21231231';
    IF @NextStatusToDate   IS NOT NULL AND @NextStatusFromDate IS NULL SET @NextStatusFromDate = '19000101';
    IF @CreatedToDate      IS NOT NULL AND @CreatedFromDate    IS NULL SET @CreatedFromDate    = '19000101';

    DECLARE @Today               DATE = CAST(GETDATE() AS DATE);
    DECLARE @NextStatusFromDateD DATE = CAST(@NextStatusFromDate AS DATE);
    DECLARE @NextStatusToDateD   DATE = CAST(@NextStatusToDate   AS DATE);
    DECLARE @CreatedFromDateD    DATE = CAST(@CreatedFromDate    AS DATE);
    DECLARE @CreatedToDateD      DATE = CAST(@CreatedToDate      AS DATE);

    DECLARE @ParentId BIGINT = 0, @IsAdmin BIT = 0;
    SELECT @IsAdmin  = ud.IsAdmin,
           @ParentId = ud.ParentID
    FROM   dbo.User_Detail ud WITH (NOLOCK)
    WHERE  ud.User_ID = @UserId;

    IF @ParentId IS NULL OR @ParentId = 0
    BEGIN
        SELECT TOP (0) CAST(NULL AS BIGINT) AS Dummy;
        RETURN;
    END

    DROP TABLE IF EXISTS #tbluser;
    CREATE TABLE #tbluser (User_ID BIGINT NOT NULL PRIMARY KEY, Name VARCHAR(100), [IMAGE] VARCHAR(100));
    INSERT INTO #tbluser EXEC dbo.Use_GetUserDetails @UserId;

    DROP TABLE IF EXISTS #FollowUpIDs;
    CREATE TABLE #FollowUpIDs (Id INT NOT NULL PRIMARY KEY);
    INSERT INTO #FollowUpIDs (Id)
    SELECT DISTINCT TRY_CONVERT(INT, s.value)
    FROM   dbo.fn_Split(@FollowUpType, N',') s
    WHERE  TRY_CONVERT(INT, s.value) IS NOT NULL
      AND  TRY_CONVERT(INT, s.value) <> 0;

    DECLARE @HasFollowUpFilter BIT = CASE WHEN EXISTS (SELECT 1 FROM #FollowUpIDs) THEN 1 ELSE 0 END;

    DROP TABLE IF EXISTS #userleadsBySegment;
    CREATE TABLE #userleadsBySegment (ID BIGINT NOT NULL PRIMARY KEY);
    DECLARE @UseSegment BIT = CASE WHEN @CriteriaName IS NULL THEN 0 ELSE 1 END;

    IF @UseSegment = 1
    BEGIN
        DECLARE @SPID INT = @@SPID;
        DELETE FROM dbo.tbl_LeadID_WithSPID WHERE SP_ID = @SPID;
        DECLARE @LeadCount INT = (SELECT COUNT(1) FROM dbo.UserLeads WITH (NOLOCK) WHERE ParentID = @ParentId);
        EXEC dbo.Usp_ViewLeadDetailsBySearchCriteria_IDSegment_SPID 1, @LeadCount, @CriteriaName, @UserId, 0, 'Name';
        INSERT INTO #userleadsBySegment (ID)
        SELECT LeadID FROM dbo.tbl_LeadID_WithSPID WITH (NOLOCK) WHERE SP_ID = @SPID;
        DELETE FROM dbo.tbl_LeadID_WithSPID WHERE SP_ID = @SPID;
    END

    -- Uses IX_LeadScoreHistory_ParentID_MaxScore → 3 reads
    DECLARE @maxScore NUMERIC(18,2) =
        ISNULL((
            SELECT TOP(1) (lsh.CurrentScore * 100.0) / 99.0
            FROM   dbo.lead_score_history lsh WITH (NOLOCK)
            WHERE  lsh.ParentID = @ParentId
            ORDER BY lsh.CurrentScore DESC
        ), 0);

    DECLARE @hot INT, @warm INT, @cold INT;
    SELECT @hot = hot, @warm = warm, @cold = cold
    FROM   dbo.lead_cateogy_thresholds WITH (NOLOCK) WHERE ParentID = @ParentId;
    IF @hot IS NULL
        SELECT @hot = hot, @warm = warm, @cold = cold
        FROM   dbo.lead_cateogy_thresholds WITH (NOLOCK) WHERE ParentID = 0;

    -- Uses IX_LIH_ParentID_LeadNo_ID_Desc → stream aggregate, no sort spill
    DROP TABLE IF EXISTS #lihInner;
    CREATE TABLE #lihInner (ParentID BIGINT NOT NULL, LeadNo BIGINT NOT NULL, ID BIGINT NOT NULL);

    IF @CreatedFromDateD IS NOT NULL
    BEGIN
        INSERT INTO #lihInner (ParentID, LeadNo, ID)
        SELECT ParentID, LeadNo, ID
        FROM   dbo.LeadInteractionHistory WITH (NOLOCK)
        WHERE  ParentID = @ParentId
          AND  CAST(CreatedOn AS DATE) BETWEEN @CreatedFromDateD AND @CreatedToDateD;
    END
    ELSE
    BEGIN
        INSERT INTO #lihInner (ParentID, LeadNo, ID)
        SELECT ParentID, LeadNo, MAX(ID)
        FROM   dbo.LeadInteractionHistory WITH (NOLOCK)
        WHERE  ParentID = @ParentId
        GROUP BY ParentID, LeadNo
        OPTION (RECOMPILE);
    END

    CREATE UNIQUE CLUSTERED INDEX CX_lihInner_ID ON #lihInner (ID);

    -- ══════════════════════════════════════════════════════════════════════
    -- CORE FIX: Conditional UserLeads join
    --
    -- The UserLeads join in the filter phase is ONLY needed when one or more
    -- of these conditions is true:
    --   • @IsAdmin = 0  (need ul.AssignedTo to check team scope)
    --   • @UseSegment = 1  (need ul.ID for segment filter)
    --   • @LeadId IS NOT NULL  (need ul.ID = @LeadId filter)
    --
    -- For @IsAdmin=1 + @UseSegment=0 + @LeadId=NULL (the slow call):
    -- ALL UserLeads conditions collapse to 1=1, making the 605k×605k
    -- hash join completely wasted work → 4,440ms saved.
    --
    -- Both branches produce identical output — same columns, same filters.
    -- The UserLeads join is still performed in the enrichment SELECT at the
    -- end for all calls (that part only touches 100 rows, so it's free).
    -- ══════════════════════════════════════════════════════════════════════

    DROP TABLE IF EXISTS #filteredRows;
    DROP TABLE IF EXISTS #page;
    DROP TABLE IF EXISTS #pageLeads;
    DROP TABLE IF EXISTS #lsh;

    CREATE TABLE #filteredRows
    (
        ID       BIGINT   NOT NULL,
        OrderSeq TINYINT  NOT NULL,
        SortDT   DATETIME NOT NULL
    );

    -- Shared filter conditions (same in both branches, no UserLeads reference)
    -- Defined as comments here for maintainability — used in both IF/ELSE below

    IF @IsAdmin = 1 AND @UseSegment = 0 AND ISNULL(@LeadId, 0) = 0
    BEGIN
        -- ── FAST PATH: Admin user, no segment, no LeadId filter ───────────────
        -- Skips UserLeads join entirely — LIH + FollowUp_Status only
        -- Expected: ~300ms (was 4,440ms)
        INSERT INTO #filteredRows (ID, OrderSeq, SortDT)
        SELECT
              lih.ID
            , OrderSeq =
                CASE
                    WHEN CAST(lih.FollowUpDate AS DATE) = @Today THEN 0
                    WHEN CAST(lih.FollowUpDate AS DATE) < @Today THEN 1
                    WHEN CAST(lih.FollowUpDate AS DATE) > @Today THEN 2
                    ELSE 3
                END
            , SortDT = ISNULL(
                           CASE WHEN lih.FollowUpDate > lih.CreatedOn
                                THEN lih.FollowUpDate ELSE lih.CreatedOn END,
                           ISNULL(lih.FollowUpDate, ISNULL(lih.CreatedOn, '19000101'))
                       )
        FROM   dbo.LeadInteractionHistory lih WITH (NOLOCK)
        INNER  JOIN #lihInner li           ON li.ID = lih.ID
        INNER  JOIN dbo.FollowUp_Status fs WITH (NOLOCK) ON fs.ID = lih.FollowUpStatus
        WHERE
            lih.ParentID = @ParentId
            AND (@IsReAssign IS NULL OR lih.IsReassign = @IsReAssign)
            AND (@AssignedTo = 0 OR lih.AssignedTo = @AssignedTo)
            AND (@CreatedBy  = 0 OR lih.CreatedBy  = @CreatedBy)
            AND (@Remarks IS NULL OR lih.Remarks LIKE N'%' + @Remarks + N'%')
            AND (
                @NextStatusFromDateD IS NULL OR @NextStatusToDateD IS NULL
                OR CAST(lih.FollowUpDate AS DATE) BETWEEN @NextStatusFromDateD AND @NextStatusToDateD
            )
            AND (
                fs.IsConvert = 0
                OR @HasFollowUpFilter = 1
                OR (@NextStatusFromDate IS NOT NULL AND @NextStatusToDate IS NOT NULL)
            )
            AND (
                    (@HasFollowUpFilter = 1 AND EXISTS (SELECT 1 FROM #FollowUpIDs f WHERE f.Id = lih.FollowUpStatus))
                 OR (@HasFollowUpFilter = 0 AND ((@NoFollowUp=1 AND @Scheduled=1 AND @DueToday=1 AND @Overdue=1) OR fs.IsCallback = 1))
                )
            AND (
                fs.IsConvert = 1
                OR (CAST(lih.FollowUpDate AS DATE) < @Today AND @Overdue  = 1)
                OR (CAST(lih.FollowUpDate AS DATE) = @Today AND @DueToday = 1)
                OR (CAST(lih.FollowUpDate AS DATE) > @Today AND @Scheduled = 1)
                OR (lih.FollowUpDate IS NULL         AND @NoFollowUp = 1)
            )
        OPTION (RECOMPILE);
    END
    ELSE
    BEGIN
        -- ── FULL PATH: Non-admin, or segment filter, or LeadId filter ─────────
        -- Includes UserLeads join for team scope / segment / LeadId checks
        INSERT INTO #filteredRows (ID, OrderSeq, SortDT)
        SELECT
              lih.ID
            , OrderSeq =
                CASE
                    WHEN CAST(lih.FollowUpDate AS DATE) = @Today THEN 0
                    WHEN CAST(lih.FollowUpDate AS DATE) < @Today THEN 1
                    WHEN CAST(lih.FollowUpDate AS DATE) > @Today THEN 2
                    ELSE 3
                END
            , SortDT = ISNULL(
                           CASE WHEN lih.FollowUpDate > lih.CreatedOn
                                THEN lih.FollowUpDate ELSE lih.CreatedOn END,
                           ISNULL(lih.FollowUpDate, ISNULL(lih.CreatedOn, '19000101'))
                       )
        FROM   dbo.LeadInteractionHistory lih WITH (NOLOCK)
        INNER  JOIN #lihInner li           ON li.ID = lih.ID
        INNER  JOIN dbo.FollowUp_Status fs WITH (NOLOCK) ON fs.ID = lih.FollowUpStatus
        INNER  JOIN dbo.UserLeads ul       WITH (NOLOCK)
                     ON ul.LeadNo   = lih.LeadNo
                    AND ul.ParentID = lih.ParentID
        WHERE
            lih.ParentID = @ParentId
            AND ul.ParentID  = @ParentId
            AND (@UseSegment = 0 OR EXISTS (SELECT 1 FROM #userleadsBySegment s WHERE s.ID = ul.ID))
            AND (@IsReAssign IS NULL OR lih.IsReassign = @IsReAssign)
            AND (
                    @IsAdmin = 1
                    OR EXISTS (SELECT 1 FROM #tbluser tu WHERE tu.User_ID = ISNULL(ul.AssignedTo, 0))
                    OR ISNULL(ul.AssignedTo, 0) = @UserId
                )
            AND (@AssignedTo = 0 OR lih.AssignedTo = @AssignedTo)
            AND (@CreatedBy  = 0 OR lih.CreatedBy  = @CreatedBy)
            AND (ISNULL(@LeadId, 0) = 0 OR ul.ID = @LeadId)
            AND (@Remarks IS NULL OR lih.Remarks LIKE N'%' + @Remarks + N'%')
            AND (
                @NextStatusFromDateD IS NULL OR @NextStatusToDateD IS NULL
                OR CAST(lih.FollowUpDate AS DATE) BETWEEN @NextStatusFromDateD AND @NextStatusToDateD
            )
            AND (
                fs.IsConvert = 0
                OR @HasFollowUpFilter = 1
                OR (@NextStatusFromDate IS NOT NULL AND @NextStatusToDate IS NOT NULL)
            )
            AND (
                    (@HasFollowUpFilter = 1 AND EXISTS (SELECT 1 FROM #FollowUpIDs f WHERE f.Id = lih.FollowUpStatus))
                 OR (@HasFollowUpFilter = 0 AND ((@NoFollowUp=1 AND @Scheduled=1 AND @DueToday=1 AND @Overdue=1) OR fs.IsCallback = 1))
                )
            AND (
                fs.IsConvert = 1
                OR (CAST(lih.FollowUpDate AS DATE) < @Today AND @Overdue  = 1)
                OR (CAST(lih.FollowUpDate AS DATE) = @Today AND @DueToday = 1)
                OR (CAST(lih.FollowUpDate AS DATE) > @Today AND @Scheduled = 1)
                OR (lih.FollowUpDate IS NULL         AND @NoFollowUp = 1)
            )
        OPTION (RECOMPILE, MIN_GRANT_PERCENT = 25);
    END

    -- @@ROWCOUNT captures total filtered rows — free, no second scan
    DECLARE @TotalRow BIGINT = @@ROWCOUNT;

    -- Sort 605k rows once for paging — unavoidable, ~679ms
    CREATE CLUSTERED INDEX CX_filteredRows ON #filteredRows (OrderSeq, SortDT DESC, ID);

    SELECT ID, OrderSeq, SortDT
    INTO   #page
    FROM   #filteredRows
    ORDER BY OrderSeq, SortDT DESC, ID
    OFFSET @OffsetValue ROWS FETCH NEXT @PagingSize ROWS ONLY;

    CREATE UNIQUE CLUSTERED INDEX CX_page_ID ON #page (ID);

    -- ── Enrich paged 100 rows — fast (always was) ────────────────────────────
    SELECT DISTINCT ul.ID AS LeadID
    INTO #pageLeads
    FROM  #page p
    JOIN  dbo.LeadInteractionHistory lih WITH (NOLOCK) ON lih.ID = p.ID
    JOIN  dbo.UserLeads ul              WITH (NOLOCK)
      ON  ul.LeadNo   = lih.LeadNo
     AND  ul.ParentID = lih.ParentID;

    CREATE UNIQUE CLUSTERED INDEX CX_pageLeads ON #pageLeads (LeadID);

    ;WITH MaxScore AS
    (
        SELECT lsh.LeadID, MAX(lsh.ID) AS MaxID
        FROM   dbo.lead_score_history lsh WITH (NOLOCK)
        JOIN   #pageLeads pl ON pl.LeadID = lsh.LeadID
        WHERE  lsh.ParentID = @ParentId
        GROUP BY lsh.LeadID
    )
    SELECT lsh.*
    INTO   #lsh
    FROM   dbo.lead_score_history lsh WITH (NOLOCK)
    JOIN   MaxScore m ON m.MaxID = lsh.ID;

    CREATE UNIQUE CLUSTERED INDEX CX_lsh_LeadID ON #lsh (LeadID);

    SELECT
          @TotalRow AS TotalRow
        , lih.ID
        , fs.FollowupStatus AS Title
        , fs.IsConvert
        , lih.Remarks AS Discription
        , lih.FollowUpDate AS NextStatusDate
        , lih.CreatedOn
        , lih.AmountPaid
        , ul.ID AS LeadId
        , IIF(ISNULL(LTRIM(RTRIM(ul.MobileNo)),  '') <> '', CONCAT(ul.CountryCode,  ' ', ul.MobileNo),  '') AS MobileNo
        , IIF(ISNULL(LTRIM(RTRIM(ul.MobileNo2)), '') <> '', CONCAT(ul.CountryCode2, ' ', ul.MobileNo2), '') AS MobileNo2
        , IIF(ISNULL(LTRIM(RTRIM(ul.MobileNo1)), '') <> '', CONCAT(ul.CountryCode1, ' ', ul.MobileNo1), '') AS MobileNo1
        , ul.PersonName
        , ul.ProfileImgFileName
        , IIF(ul.AssignedTo = @UserId OR @IsAdmin = 1, 1, 0) AS IsUIActive
        , lih.AssignedTo
        , LTRIM(RTRIM(CONCAT(ud.fname, ' ', ud.lname))) AS [Owner]
        , '' AS [Status]
        , ud.ParentID AS ParentId
        , p.OrderSeq
        , CASE
            WHEN CAST(lih.FollowUpDate AS DATE) = @Today THEN 'duetoday'
            WHEN CAST(lih.FollowUpDate AS DATE) < @Today THEN 'overdue'
            WHEN CAST(lih.FollowUpDate AS DATE) > @Today THEN 'scheduled'
            WHEN lih.FollowUpDate IS NULL                THEN 'nofollowup'
          END AS FollowupDateStatus
        , CASE WHEN ls.ScoreAdded > 0 THEN 'green_up' WHEN ls.ScoreAdded < 0 THEN 'red_down' ELSE '' END AS Profit_Loss
        , CAST(ISNULL((ls.CurrentScore / NULLIF(@maxScore, 0.00)) * 99, 0) AS INT) AS CurrentScore
        , CASE
            WHEN CAST(ISNULL((ls.CurrentScore / NULLIF(@maxScore, 0.00)) * 99, 0) AS INT) > @warm            THEN 'hot'
            WHEN CAST(ISNULL((ls.CurrentScore / NULLIF(@maxScore, 0.00)) * 99, 0) AS INT) BETWEEN @cold AND @warm THEN 'warm'
            ELSE 'cold'
          END AS ThresholdColor
    FROM #page p
    JOIN dbo.LeadInteractionHistory lih WITH (NOLOCK) ON lih.ID = p.ID
    JOIN dbo.FollowUp_Status fs         WITH (NOLOCK) ON fs.ID  = lih.FollowUpStatus
    JOIN dbo.UserLeads ul               WITH (NOLOCK)
      ON ul.LeadNo   = lih.LeadNo
     AND ul.ParentID = lih.ParentID
    LEFT JOIN #lsh ls                              ON ls.LeadID  = ul.ID
    LEFT JOIN dbo.User_Detail ud        WITH (NOLOCK) ON ud.User_ID = lih.AssignedTo
    ORDER BY p.OrderSeq, p.SortDT DESC, p.ID;

    IF @SkipAudit = 0
    BEGIN
        EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId
              @User_id       = @UserId
            , @Activity_type = 'View_flwup'
            , @ActionType    = 'F'
            , @RowJson       = ''
            , @Table_name    = 'leadinteractionhistory';
    END
END



GO

/* ============================================================
   Procedure: [dbo].[usp_GetFollowUpListByUserId_withScoreCard_KK]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

--exec usp_GetFollowUpListByUserId_withScoreCard @OffsetValue=0,@PagingSize=300,@UserId=39042,@FollowUpType=0,@NextStatusFromDate=N'01-Jan-1900',@NextStatusToDate=N'18-Apr-2022',@CreatedFromDate=N'',@CreatedToDate=N'',@LeadId=N'',@Remarks=N'',@Overdue=1,@DueToday=0,@Scheduled=0,@NoFollowUp=0,@AssignedTo=0,@CreatedBy=0
--exec usp_GetFollowUpListByUserId_withScoreCard @OffsetValue=0,@PagingSize=100,@UserId=36950,@FollowUpType=0,@NextStatusFromDate=N'',@NextStatusToDate=N'',@CreatedFromDate=N'',@CreatedToDate=N'',@LeadId=N'',@Remarks=N'',@Overdue=1,@DueToday=1,@Scheduled=1,@NoFollowUp=1,@AssignedTo=0,@CreatedBy=0
--exec usp_GetFollowUpListByUserId_withScoreCard$ @OffsetValue=0,@PagingSize=100,@UserId=39680,@FollowUpType=0,@NextStatusFromDate=N'',@NextStatusToDate=N'',@CreatedFromDate=N'11-May-2022 00:00:00',@CreatedToDate=N'12-May-2022 00:00:00', @LeadId=N'', @Remarks=N'', @Overdue=1, @DueToday=1, @Scheduled=1, @NoFollowUp=1,@AssignedTo=0,@CreatedBy=0, @IsReAssign=0
/*
Revision	: DBA
			: 2025-07-29
			: 

Revision	: DBA
			: 2025-08-08
			: Fixing the wrong TotalRecords count
*/
CREATE   PROCEDURE [dbo].[usp_GetFollowUpListByUserId_withScoreCard_KK] (
	 @OffsetValue INT = 0
	,@PagingSize INT = 20
	,@UserId BIGINT
	--,@FollowUpType INT = 0
	,@FollowUpType nvarchar(max) = '0'
	,@NextStatusFromDate DATETIME = NULL
	,@NextStatusToDate DATETIME = NULL
	,@CreatedFromDate DATETIME = NULL
	,@CreatedToDate DATETIME = NULL
	,@LeadId BIGINT = NULL
	,@Remarks NVARCHAR(500) = ''
	,@Overdue BIT = 1
	,@DueToday BIT = 1
	,@Scheduled BIT = 1
	,@NoFollowUp BIT = 1
	,@AssignedTo BIGINT = 0
	,@CreatedBy BIGINT = 0
	,@IsReAssign BIT = NULL
	)
AS
BEGIN
	--declare @OffsetValue int=0, @PagingSize int = 100, @UserId bigint = 39042, @FollowUpType int = 0, @NextStatusFromDate datetime = N'', @NextStatusToDate datetime = N'', @CreatedFromDate datetime = N'', @CreatedToDate datetime = N'', @LeadId bigint = N'', @Remarks nvarchar(500) = N'', @Overdue bit = 1, @DueToday bit= 1, @Scheduled bit = 1, @NoFollowUp bit = 1, @AssignedTo bigint = 0, @CreatedBy bigint = 0
	--declare @OffsetValue int=0, @PagingSize int = 100, @UserId bigint = 35610, @FollowUpType int = 0, @NextStatusFromDate datetime = N'', @NextStatusToDate datetime = N'', @CreatedFromDate datetime = N'', @CreatedToDate datetime = N'', @LeadId bigint = N'', @Remarks nvarchar(500) = N'', @Overdue bit = 1, @DueToday bit= 1, @Scheduled bit = 1, @NoFollowUp bit = 1, @AssignedTo bigint = 0, @CreatedBy bigint = 0
	--declare @OffsetValue int = 0,@PagingSize int = 100,@UserId bigint=36950,@FollowUpType int = 0,@NextStatusFromDate datetime = N'',@NextStatusToDate datetime = N'',@CreatedFromDate datetime = N'',@CreatedToDate datetime = N'',@LeadId bigint = N'',@Remarks nvarchar(500) = '',@Overdue bit = 1,@DueToday bit = 1,@Scheduled bit = 1,@NoFollowUp bit = 1,@AssignedTo bigint = 0,@CreatedBy bigint = 0
	--declare @OffsetValue int=0,@PagingSize int=100,@UserId bigint=39680,@FollowUpType int=0,@NextStatusFromDate datetime=N'',@NextStatusToDate datetime=N'',@CreatedFromDate datetime=N'09-May-2022 00:00:00',@CreatedToDate datetime=N'10-May-2022 00:00:00',@LeadId bigint=N'',@Remarks nvarchar(500)=N'',@Overdue bit=1,@DueToday bit=1,@Scheduled bit=1,@NoFollowUp bit=1,@AssignedTo bigint=0,@CreatedBy bigint=40062
	--declare @OffsetValue int=0,@PagingSize int=100,@UserId bigint=39680,@FollowUpType int=0,@NextStatusFromDate datetime=N'',@NextStatusToDate datetime=N'',@CreatedFromDate datetime=N'09-May-2022 00:00:00',@CreatedToDate datetime=N'10-May-2022 00:00:00',@LeadId bigint=N'',@Remarks nvarchar(500)=N'',@Overdue bit=1,@DueToday bit=1,@Scheduled bit=1,@NoFollowUp bit=1,@AssignedTo bigint=0,@CreatedBy bigint=40061
	--declare @OffsetValue int=0,@PagingSize int=100,@UserId bigint=40058,@FollowUpType int=461,@NextStatusFromDate datetime=N'',@NextStatusToDate datetime=N'',@CreatedFromDate datetime=N'01-Jun-2022 12:30:00',@CreatedToDate datetime=N'03-Jun-2022 12:30:00',@LeadId bigint=N'',@Remarks nvarchar(500)=N'',@Overdue bit=1,@DueToday bit=1,@Scheduled bit=1,@NoFollowUp bit=1,@AssignedTo bigint=0,@CreatedBy bigint=40058, @IsReAssign bit=0

	--declare @OffsetValue int=0, @PagingSize int=100, @UserId bigint=31031, @FollowUpType int=N'1927', @NextStatusFromDate datetime=N'', @NextStatusToDate datetime=N'', @CreatedFromDate datetime=N'', @CreatedToDate datetime=N'', @LeadId bigint=N'', @Remarks nvarchar(500)=N'', @Overdue bit=1, @DueToday bit=1, @Scheduled bit=1, @NoFollowUp bit=1, @AssignedTo bigint=0, @CreatedBy bigint=0, @IsReAssign bit=0



	DECLARE @IsCallback INT = 0;
	DECLARE @IsConvert INT = 0;
	DECLARE @FollowUpName VARCHAR = '';

	
	/*
	SELECT @IsCallback = IsCallback
		,@IsConvert = IsConvert
	FROM FollowUp_Status(NOLOCK)
	WHERE Id = @FollowUpType
	*/

	Declare @flpIDsCount int = 0;
	set @flpIDsCount = isnull((select count(value) from fn_Split(@FollowUpType,',') where isnull(value,0) <> 0),0);



	DECLARE @ParentId BIGINT = 0
		,@IsAdmin BIT = 0
	DECLARE @tbluser TABLE (
		User_ID BIGINT
		,Name VARCHAR(100)
		,IMAGE VARCHAR(100)
		)

	SELECT @IsAdmin = IsAdmin
		,@ParentId = ParentID
	FROM User_Detail(NOLOCK)
	WHERE User_ID = @UserId

	DECLARE @TeamCode VARCHAR(10) = ''
	DECLARE @ScopeCode VARCHAR(10) = ''
	DECLARE @UserIdTeamLst VARCHAR(Max) = ''
	DECLARE @UserLoginTeamLst VARCHAR(Max) = ''

	--select @TeamCode = TeamCode, @ScopeCode = ScopeCode, @UserIdTeamLst = UserIdTeamLst, @UserLoginTeamLst = UserLoginTeamLst from dbo.ufn_GetUserRoleScope(@UserId)   
	INSERT INTO @tbluser
	EXEC Use_GetUserDetails @UserId

	SELECT @UserIdTeamLst = isnull(STRING_AGG(User_ID, ','), '')
	FROM @tbluser

	-- select @TeamCode TeamCode, @ScopeCode ScopeCode, @UserIdTeamLst UserIdTeamLst, @UserLoginTeamLst UserLoginTeamLst     
	DECLARE @maxScore NUMERIC(18, 2) = isnull((
				SELECT (max(currentscore) * 100) / 99
				FROM lead_score_history(NOLOCK) e
				WHERE parentid = @ParentId
				), 0)
	DECLARE @hot INT
		,@warm INT
		,@cold INT

	SELECT @hot = hot
		,@warm = warm
		,@cold = cold
	FROM lead_cateogy_thresholds(NOLOCK)
	WHERE parentid = @ParentID

	IF @hot IS NULL
	BEGIN
		SELECT @hot = hot
			,@warm = warm
			,@cold = cold
		FROM lead_cateogy_thresholds(NOLOCK)
		WHERE parentid = 0
	END

	PRINT @FollowUpType

	/*
	DBA : 2025-07-29
	*/
	
	CREATE TABLE #lihInner (ParentID BIGINT, LeadNo BIGINT, ID BIGINT);

	IF (isnull(@CreatedFromDate, '1900-01-01') > '1900-01-01')
		BEGIN
			-- All
			INSERT INTO #lihInner
			SELECT ParentId, LeadNo, ID
			FROM leadinteractionhistory(NOLOCK) as lih
			WHERE lih.ParentID = @ParentId

		END
	ELSE
		BEGIN
			-- Only the latest
			INSERT INTO #lihInner
			SELECT ParentId, LeadNo, MAX(ID) ID
			FROM leadinteractionhistory(NOLOCK) as lih
			WHERE lih.ParentID = @ParentId
			GROUP BY ParentId, LeadNo
		END;
		
	-- To avoiding the view lead_score_history_latest 
	-- from the dynamic query
	;WITH cte_scrore1
	AS
	(SELECT lsh.parentid, lsh.leadid, MAX(lsh.ID) AS ID
	FROM lead_score_history lsh WITH (NOLOCK)
	INNER JOIN  userleads ul WITH (NOLOCK)
		ON ul.id = lsh.leadid
	WHERE ul.ParentID = @ParentId
	GROUP BY lsh.parentid, lsh.leadid
	)
	SELECT lsh.* INTO #lsh
	FROM lead_score_history lsh WITH (NOLOCK)
	INNER JOIN cte_scrore1 
		ON cte_scrore1.ID = lsh.id;
		
	;with cte_lih
	AS
	(
		SELECT count(lih.ID) OVER () AS TotalRow, lih.ID
		,(
						CASE 
							WHEN cast(lih.followupdate AS DATE) = cast(getdate() AS DATE)
								THEN 0
							WHEN cast(lih.followupdate AS DATE) < cast(getdate() AS DATE)
								THEN 1
							WHEN cast(lih.followupdate AS DATE) > cast(getdate() AS DATE)
								THEN 2
							WHEN cast(lih.followupdate AS DATE) IS NULL
								THEN 3
							END
						) AS [OrderSeq]
		,lih.followupdate AS NextStatusDate
		FROM 
		(
			SELECT *,
			(
				CASE 
					WHEN cast(followupdate AS DATE) = cast(getdate() AS DATE)
						THEN 'duetoday'
					WHEN cast(followupdate AS DATE) < cast(getdate() AS DATE)
						THEN 'overdue'
					WHEN cast(followupdate AS DATE) > cast(getdate() AS DATE)
						THEN 'scheduled'
					WHEN cast(followupdate AS DATE) IS NULL
						THEN 'nofollowup'
					END
				) AS [FollowupDateStatus]
			FROM leadinteractionhistory(NOLOCK) 
		) AS lih
		     
				INNER JOIN followup_status(NOLOCK) fs ON lih.followupstatus = fs.id
				INNER JOIN userleads(NOLOCK) ul ON lih.leadno = ul.leadno
					AND ul.parentid = lih.parentid
				INNER JOIN #lihInner lihInner ON lihInner.ID = lih.ID
		WHERE
			lih.IsReassign = CASE 
				WHEN @IsReAssign IS NULL
					AND @CreatedBy <> 0
					THEN 0
				WHEN @IsReAssign IS NOT NULL
					THEN @IsReAssign
				ELSE lih.IsReassign
				END
			AND ul.parentid = @ParentId
			and lih.ParentID =  @ParentId
			/*and 1 = (case when isnull(@FollowUpType, 0) = 0 and fs.IsCallback = 1 then 1 
				when isnull(@FollowUpType, 0) > 0 and lih.FollowUpStatus = @FollowUpType then 1
			else 0 end )*/
			AND 1 = (
				CASE 
				    /*  
					  WHEN isnull(@FollowUpType, 0) = 0
						AND @NoFollowUp = 1
						AND @Scheduled = 1
						AND @DueToday = 1
						AND @Overdue = 1
						THEN 1
                    */ 
					when @flpIDsCount = 0
					    AND @NoFollowUp = 1
						AND @Scheduled = 1
						AND @DueToday = 1
						AND @Overdue = 1
						THEN 1 
					/*
				 	  WHEN isnull(@FollowUpType, 0) = 0
						AND fs.IsCallback = 1
						THEN 1
                    */  
					when @flpIDsCount = 0
					   AND fs.IsCallback = 1
					  THEN 1  
                    /*   
					  WHEN isnull(@FollowUpType, 0) > 0
						AND lih.FollowUpStatus = @FollowUpType
						THEN 1
                     */
                    WHEN @flpIDsCount > 0
						AND lih.FollowUpStatus in ( select value from fn_Split(@FollowUpType,',') )
						THEN 1
					ELSE 0
					END
				)
			AND 1 = (
				CASE 
					WHEN @isadmin = 1
						THEN 1
					WHEN isnull(ul.AssignedTo, 0) IN (
							SELECT [value]
							FROM dbo.fn_Split(@UserIdTeamLst, ',')
							)
						THEN 1
					WHEN isnull(ul.AssignedTo, 0) = @UserId
						THEN 1
					ELSE 0
					END
				)
			AND 1 = (
				CASE 
					WHEN isnull(@AssignedTo, 0) = 0
						THEN 1
					WHEN isnull(@AssignedTo, 0) > 0
						AND lih.AssignedTo = @AssignedTo
						THEN 1
					ELSE 0
					END
				)
			AND 1 = (
				CASE 
					WHEN isnull(@CreatedBy, 0) = 0
						THEN 1
					WHEN isnull(@CreatedBy, 0) > 0
						AND lih.CreatedBy = @CreatedBy
						THEN 1
					ELSE 0
					END
				)
			AND 1 = iif(Isnull(@NextStatusFromDate, '') <> ''
				AND Isnull(@NextStatusToDate, '') <> '', iif(CAST(TRY_CONVERT(DATETIME, lih.FollowupDate) AS DATE) BETWEEN cast(@NextStatusFromDate AS DATE)
						AND cast(@NextStatusToDate AS DATE)
							,1
							,0), 1)
			AND 1 = iif(Isnull(@CreatedFromDate, '') <> ''
				AND Isnull(@CreatedToDate, '') <> '', iif(CAST(TRY_CONVERT(DATETIME, lih.CreatedOn) AS DATE) BETWEEN cast(@CreatedFromDate AS DATE)
						AND cast(@CreatedToDate AS DATE)
							,1
							,0), 1)
			AND 1 = (
				CASE 
					WHEN isnull(@LeadId, 0) = 0
						THEN 1
					WHEN isnull(@LeadId, 0) > 0
						AND @LeadId = ul.ID
						THEN 1
					ELSE 0
					END
				)
			AND 1 = (
				CASE 
					WHEN isnull(@Remarks, '') = ''
						THEN 1
					WHEN isnull(@Remarks, '') <> ''
						AND lih.Remarks LIKE '%' + @Remarks + '%'
						THEN 1
					ELSE 0
					END
				)
			AND 1 = (
				CASE 
					/*
					 WHEN isnull(@FollowUpType, 0) > 0
					  AND fs.IsConvert = 1
					   THEN 1
                    */
					WHEN @flpIDsCount > 0
					  AND fs.IsConvert = 1
					   THEN 1

					WHEN Isnull(@NextStatusFromDate, '') = ''
						AND Isnull(@NextStatusToDate, '') = ''
						AND fs.IsConvert = 1
						THEN 0
					ELSE 1
					END
				)
			AND 1 = (
				CASE
					when IsConvert = 1 then 1
					WHEN followupdatestatus = 'overdue'
						AND @Overdue = 1
						THEN 1
					WHEN followupdatestatus = 'duetoday'
						AND @DueToday = 1
						THEN 1
					WHEN followupdatestatus = 'scheduled'
						AND @Scheduled = 1
						THEN 1
					WHEN followupdatestatus = 'nofollowup'
						AND @NoFollowUp = 1
						THEN 1
					ELSE 0
					END
				)
		)
	SELECT * INTO #lih
	FROM cte_lih
	ORDER BY orderseq ,nextstatusdate
	offset @OffsetValue rows
	FETCH NEXT (@PagingSize * 5) rows ONLY;
	
	SELECT fu.*
		FROM (
			SELECT tlih.TotalRow, lih.ID
			,fs.followupstatus AS Title
			,fs.IsConvert as [IsConvert]
			,lih.remarks AS Discription
			,lih.followupdate AS NextStatusDate
			,lih.CreatedOn
			,lih.AmountPaid
			,ul.id AS LeadId
			,iif(isnull(ltrim(rtrim(ul.mobileno)), '') <> '', CONCAT (
					ul.countrycode
					,' '
					,ul.mobileno
					), '') AS MobileNo
			,iif(isnull(ltrim(rtrim(ul.mobileno2)), '') <> '', CONCAT (
					ul.countrycode2
					,' '
					,ul.mobileno2
					), '') AS MobileNo2
			,iif(isnull(ltrim(rtrim(ul.mobileno1)), '') <> '', CONCAT (
					ul.countrycode1
					,' '
					,ul.mobileno1
					), '') AS MobileNo1
			,ul.PersonName
			,ul.ProfileImgFileName
			,iif(ul.assignedto = @UserId
				OR 1 = @IsAdmin, 1, 0) AS [IsUIActive]
			,lih.assignedto
			,ltrim(rtrim(CONCAT (
						ud.fname
						,' '
						,ud.lname
						))) AS [Owner]
			,'' AS [Status]
			,ud.parentid AS [ParentId]
			,(
				CASE 
					WHEN cast(lih.followupdate AS DATE) = cast(getdate() AS DATE)
						THEN 0
					WHEN cast(lih.followupdate AS DATE) < cast(getdate() AS DATE)
						THEN 1
					WHEN cast(lih.followupdate AS DATE) > cast(getdate() AS DATE)
						THEN 2
					WHEN cast(lih.followupdate AS DATE) IS NULL
						THEN 3
					END
				) AS [OrderSeq]
			,(
				CASE 
					WHEN cast(lih.followupdate AS DATE) = cast(getdate() AS DATE)
						THEN 'duetoday'
					WHEN cast(lih.followupdate AS DATE) < cast(getdate() AS DATE)
						THEN 'overdue'
					WHEN cast(lih.followupdate AS DATE) > cast(getdate() AS DATE)
						THEN 'scheduled'
					WHEN cast(lih.followupdate AS DATE) IS NULL
						THEN 'nofollowup'
					END
				) AS [FollowupDateStatus]
			,(
				CASE 
					WHEN ls.scoreadded > 0
						THEN 'green_up'
					WHEN ls.scoreadded < 0
						THEN 'red_down'
					ELSE ''
					END
				) AS [Profit_Loss]
			,cast(isnull((ls.currentscore / nullif(@maxScore, 0.00)) * 99, 0) AS INT) AS [CurrentScore]
			,(
				CASE 
					WHEN cast(isnull((ls.currentscore / nullif(@maxScore, 0.00)) * 99, 0) AS INT) > @warm
						THEN 'hot'
					WHEN cast(isnull((ls.currentscore / nullif(@maxScore, 0.00)) * 99, 0) AS INT) BETWEEN @cold
							AND @warm
						THEN 'warm'
					ELSE 'cold'
					END
				) AS [ThresholdColor]
			FROM leadinteractionhistory(NOLOCK) lih
		INNER JOIN #lih tlih ON tlih.ID = lih.ID  
		INNER JOIN followup_status(NOLOCK) fs ON lih.followupstatus = fs.id
		INNER JOIN userleads(NOLOCK) ul ON lih.leadno = ul.leadno
			AND ul.parentid = lih.parentid
		LEFT OUTER JOIN #lsh ls ON ls.leadid = ul.id
		LEFT JOIN user_detail(NOLOCK) ud ON lih.assignedto = ud.user_id
	) AS fu
	/*
	WHERE 1 = (
			CASE
				when IsConvert = 1 then 1
				WHEN followupdatestatus = 'overdue'
					AND @Overdue = 1
					THEN 1
				WHEN followupdatestatus = 'duetoday'
					AND @DueToday = 1
					THEN 1
				WHEN followupdatestatus = 'scheduled'
					AND @Scheduled = 1
					THEN 1
				WHEN followupdatestatus = 'nofollowup'
					AND @NoFollowUp = 1
					THEN 1
				ELSE 0
				END
			)
	*/
	ORDER BY orderseq
		,nextstatusdate 
	offset @OffsetValue rows
	FETCH NEXT @PagingSize rows ONLY;

	EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @UserId
		,@Activity_type = 'View_flwup'
		,@ActionType = 'F'
		,@RowJson = ''
		,@Table_name = 'leadinteractionhistory'
END



GO

/* ============================================================
   Procedure: [dbo].[usp_GetFollowUpListByUserId_withScoreCard_Search]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

--exec usp_GetFollowUpListByUserId_withScoreCard_Search @UserId=32222,@FollowUpType=0,@NextStatusFromDate=N'01-Jan-1900',@NextStatusToDate=N'18-Apr-2022',@CreatedFromDate=N'',@CreatedToDate=N'',@LeadId=N'',@Remarks=N'',@Overdue=1,@DueToday=0,@Scheduled=0,@NoFollowUp=0,@AssignedTo=0,@CreatedBy=0, @IsReAssign = NULL   
CREATE   PROCEDURE [dbo].[usp_GetFollowUpListByUserId_withScoreCard_Search] (
	@UserId BIGINT = 0
	--,@FollowUpType INT = 0
	,@FollowUpType nvarchar(max) = '0'
	,
	--@NextStatusFromDate VARCHAR(30) = NULL,        
	--@NextStatusToDate VARCHAR(30) = NULL,        
	--@CreatedFromDate VARCHAR(30) = NULL,        
	--@CreatedToDate VARCHAR(30) = NULL,        
	@NextStatusFromDate DATETIME = NULL
	,@NextStatusToDate DATETIME = NULL
	,@CreatedFromDate DATETIME = NULL
	,@CreatedToDate DATETIME = NULL
	,@LeadId BIGINT = NULL
	,@Remarks NVARCHAR(500) = ''
	,@Overdue BIT = 1
	,@DueToday BIT = 1
	,@Scheduled BIT = 1
	,@NoFollowUp BIT = 1
	,@AssignedTo BIGINT = 0
	,@CreatedBy BIGINT = 0
	,@IsReAssign BIT = NULL
	)
AS
BEGIN
	DECLARE @IsCallback INT = 0;
	DECLARE @IsConvert INT = 0;
	DECLARE @FollowUpName VARCHAR = '';

	
	/*
		SELECT @IsCallback = IsCallback
			,@IsConvert = IsConvert
		FROM FollowUp_Status(NOLOCK)
		WHERE Id = @FollowUpType
	*/

	Declare @flpIDsCount int = 0;
	set @flpIDsCount = isnull((select count(value) from fn_Split(@FollowUpType,',') where isnull(value,0) <> 0),0);

	DECLARE @ParentId BIGINT = 0
		,@IsAdmin BIT = 0
	DECLARE @tbluser TABLE (
		User_ID BIGINT
		,Name VARCHAR(100)
		,IMAGE VARCHAR(100)
		)

	SELECT @IsAdmin = IsAdmin
		,@ParentId = ParentID
	FROM User_Detail(NOLOCK)
	WHERE User_ID = @UserId

	DECLARE @TeamCode VARCHAR(10) = ''
	DECLARE @ScopeCode VARCHAR(10) = ''
	DECLARE @UserIdTeamLst VARCHAR(Max) = ''
	DECLARE @UserLoginTeamLst VARCHAR(Max) = ''

	INSERT INTO @tbluser
	EXEC Use_GetUserDetails @UserId

	SELECT @UserIdTeamLst = isnull(STRING_AGG(User_ID, ','), '')
	FROM @tbluser

	DECLARE @maxScore NUMERIC(18, 2) = isnull((
				SELECT (max(currentscore) * 100) / 99
				FROM lead_score_history(NOLOCK) e
				WHERE parentid = @ParentId
				), 0)
	DECLARE @hot INT
		,@warm INT
		,@cold INT

	SELECT @hot = hot
		,@warm = warm
		,@cold = cold
	FROM lead_cateogy_thresholds(NOLOCK)
	WHERE parentid = @ParentID

	IF @hot IS NULL
	BEGIN
		SELECT @hot = hot
			,@warm = warm
			,@cold = cold
		FROM lead_cateogy_thresholds(NOLOCK)
		WHERE parentid = 0
	END

	PRINT @FollowUpType

	SELECT count(id) OVER () AS TotalRow
		,Title
		,Discription
		,format(NextStatusDate, 'dd-MMM-yyyy HH:mm') as [NextStatusDate]
		,format(CreatedOn, 'dd-MMM-yyyy HH:mm') as [CreatedOn]
		,LeadNo
		,AmountPaid
		,PersonName
		,MobileNo
		,MobileNo1
		,MobileNo2
		,OWNER
		,FollowupDateStatus
		,CurrentScore
	FROM (
		SELECT lih.ID
			,fs.followupstatus AS Title
			,lih.remarks AS Discription
			,lih.followupdate AS NextStatusDate
			,lih.CreatedOn
			,lih.AmountPaid
			,ul.id AS LeadId
			,ul.LeadNo
			,iif(isnull(ltrim(rtrim(ul.mobileno)), '') <> '', CONCAT (
					ul.countrycode
					,' '
					,ul.mobileno
					), '') AS MobileNo
			,iif(isnull(ltrim(rtrim(ul.mobileno2)), '') <> '', CONCAT (
					ul.countrycode2
					,' '
					,ul.mobileno2
					), '') AS MobileNo2
			,iif(isnull(ltrim(rtrim(ul.mobileno1)), '') <> '', CONCAT (
					ul.countrycode1
					,' '
					,ul.mobileno1
					), '') AS MobileNo1
			,ul.PersonName
			,ul.ProfileImgFileName
			,iif(ul.assignedto = @UserId
				OR 1 = @IsAdmin, 1, 0) AS [IsUIActive]
			,lih.assignedto
			,ltrim(rtrim(CONCAT (
						ud.fname
						,' '
						,ud.lname
						))) AS [Owner]
			,'' AS [Status]
			,ud.parentid AS [ParentId]
			,(
				CASE 
					WHEN cast(lih.followupdate AS DATE) = cast(getdate() AS DATE)
						THEN 0
					WHEN cast(lih.followupdate AS DATE) < cast(getdate() AS DATE)
						THEN 1
					WHEN cast(lih.followupdate AS DATE) > cast(getdate() AS DATE)
						THEN 2
					WHEN cast(lih.followupdate AS DATE) IS NULL
						THEN 3
					END
				) AS [OrderSeq]
			,(
				CASE 
					WHEN cast(lih.followupdate AS DATE) = cast(getdate() AS DATE)
						THEN 'duetoday'
					WHEN cast(lih.followupdate AS DATE) < cast(getdate() AS DATE)
						THEN 'overdue'
					WHEN cast(lih.followupdate AS DATE) > cast(getdate() AS DATE)
						THEN 'scheduled'
					WHEN cast(lih.followupdate AS DATE) IS NULL
						THEN 'nofollowup'
					END
				) AS [FollowupDateStatus]
			,(
				CASE 
					WHEN ls.scoreadded > 0
						THEN 'green_up'
					WHEN ls.scoreadded < 0
						THEN 'red_down'
					ELSE ''
					END
				) AS [Profit_Loss]
			,cast(isnull((ls.currentscore / nullif(@maxScore, 0.00)) * 99, 0) AS INT) AS [CurrentScore]
			,(
				CASE 
					WHEN cast(isnull((ls.currentscore / nullif(@maxScore, 0.00)) * 99, 0) AS INT) > @warm
						THEN 'hot'
					WHEN cast(isnull((ls.currentscore / nullif(@maxScore, 0.00)) * 99, 0) AS INT) BETWEEN @cold
							AND @warm
						THEN 'warm'
					ELSE 'cold'
					END
				) AS [ThresholdColor]
		FROM leadinteractionhistory(NOLOCK) lih
		INNER JOIN followup_status(NOLOCK) fs ON lih.followupstatus = fs.id
		INNER JOIN userleads(NOLOCK) ul ON lih.leadno = ul.leadno
			AND ul.parentid = lih.parentid
		LEFT JOIN lead_score_history_latest(NOLOCK) ls ON ls.leadid = ul.id
		LEFT JOIN user_detail(NOLOCK) ud ON lih.assignedto = ud.user_id
		WHERE lih.IsReassign = CASE 
				WHEN @IsReAssign IS NULL
					AND @CreatedBy <> 0
					THEN 0
				WHEN @IsReAssign IS NOT NULL
					THEN @IsReAssign
				ELSE lih.IsReassign
				END
			AND lih.id = CASE 
				WHEN isnull(@CreatedFromDate, '1900-01-01') > '1900-01-01'
					THEN lih.id
				ELSE (
						SELECT max(id)
						FROM leadinteractionhistory(NOLOCK)
						WHERE parentid = lih.parentid
							AND leadno = lih.leadno
						)
				END
			AND ul.parentid = @ParentId
			/*and 1 = (case when isnull(@FollowUpType, 0) = 0 and fs.IsCallback = 1 then 1     
    when isnull(@FollowUpType, 0) > 0 and lih.FollowUpStatus = @FollowUpType then 1    
   else 0 end )*/
			AND 1 = (
				CASE 
					WHEN @flpIDsCount = 0
						AND @NoFollowUp = 1
						AND @Scheduled = 1
						AND @DueToday = 1
						AND @Overdue = 1
						THEN 1
					WHEN @flpIDsCount = 0
						AND fs.IsCallback = 1
						THEN 1
					WHEN @flpIDsCount > 0
						AND lih.FollowUpStatus in ( select value from fn_Split(@FollowUpType,',') )
						THEN 1
					ELSE 0
					END
				)
			AND 1 = (
				CASE 
					WHEN @isadmin = 1
						THEN 1
					WHEN isnull(ul.AssignedTo, 0) IN (
							SELECT [value]
							FROM dbo.fn_Split(@UserIdTeamLst, ',')
							)
						THEN 1
					WHEN isnull(ul.AssignedTo, 0) = @UserId
						THEN 1
					ELSE 0
					END
				)
			AND 1 = (
				CASE 
					WHEN isnull(@AssignedTo, 0) = 0
						THEN 1
					WHEN isnull(@AssignedTo, 0) > 0
						AND lih.AssignedTo = @AssignedTo
						THEN 1
					ELSE 0
					END
				)
			AND 1 = (
				CASE 
					WHEN isnull(@CreatedBy, 0) = 0
						THEN 1
					WHEN isnull(@CreatedBy, 0) > 0
						AND lih.CreatedBy = @CreatedBy
						THEN 1
					ELSE 0
					END
				)
			AND 1 = iif(Isnull(@NextStatusFromDate, '') <> ''
				AND Isnull(@NextStatusToDate, '') <> '', iif(CAST(TRY_CONVERT(DATETIME, lih.FollowupDate) AS DATE) BETWEEN cast(@NextStatusFromDate AS DATE)
						AND cast(@NextStatusToDate AS DATE)
							,1
							,0), 1)
			AND 1 = iif(Isnull(@CreatedFromDate, '') <> ''
				AND Isnull(@CreatedToDate, '') <> '', iif(CAST(TRY_CONVERT(DATETIME, lih.CreatedOn) AS DATE) BETWEEN cast(@CreatedFromDate AS DATE)
						AND cast(@CreatedToDate AS DATE)
							,1
							,0), 1)
			AND 1 = (
				CASE 
					WHEN isnull(@LeadId, 0) = 0
						THEN 1
					WHEN isnull(@LeadId, 0) > 0
						AND @LeadId = ul.ID
						THEN 1
					ELSE 0
					END
				)
			AND 1 = (
				CASE 
					WHEN isnull(@Remarks, '') = ''
						THEN 1
					WHEN isnull(@Remarks, '') <> ''
						AND lih.Remarks LIKE '%' + @Remarks + '%'
						THEN 1
					ELSE 0
					END
				)
			AND 1 = (
				CASE 
					WHEN  @flpIDsCount > 0
						AND fs.IsConvert = 1
						THEN 1
					WHEN Isnull(@NextStatusFromDate, '') = ''
						AND Isnull(@NextStatusToDate, '') = ''
						AND fs.IsConvert = 1
						THEN 0
					ELSE 1
					END
				)
		) AS fu
	WHERE 1 = (
			CASE 
				WHEN followupdatestatus = 'overdue'
					AND @Overdue = 1
					THEN 1
				WHEN followupdatestatus = 'duetoday'
					AND @DueToday = 1
					THEN 1
				WHEN followupdatestatus = 'scheduled'
					AND @Scheduled = 1
					THEN 1
				WHEN followupdatestatus = 'nofollowup'
					AND @NoFollowUp = 1
					THEN 1
				ELSE 0
				END
			)
	ORDER BY orderseq
		,cast(nextstatusdate AS DATETIME)

END



GO

/* ============================================================
   Procedure: [dbo].[usp_GetFollowUpListByUserId_withScoreCard_Search_Check]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

--exec usp_GetFollowUpListByUserId_withScoreCard_Search @UserId=32222,@FollowUpType=0,@NextStatusFromDate=N'01-Jan-1900',@NextStatusToDate=N'18-Apr-2022',@CreatedFromDate=N'',@CreatedToDate=N'',@LeadId=N'',@Remarks=N'',@Overdue=1,@DueToday=0,@Scheduled=0,@NoFollowUp=0,@AssignedTo=0,@CreatedBy=0, @IsReAssign = NULL   
CREATE   PROCEDURE [dbo].[usp_GetFollowUpListByUserId_withScoreCard_Search_Check]        
(      
 @UserId bigint =0,        
 @FollowUpType int = 0,    
 --@NextStatusFromDate VARCHAR(30) = NULL,        
 --@NextStatusToDate VARCHAR(30) = NULL,        
 --@CreatedFromDate VARCHAR(30) = NULL,        
 --@CreatedToDate VARCHAR(30) = NULL,        
 	@NextStatusFromDate datetime = NULL,
	@NextStatusToDate datetime = NULL,
	@CreatedFromDate datetime = NULL,
	@CreatedToDate datetime = NULL,
@LeadId bigint = NULL,        
 @Remarks nvarchar(500) = '',        
 @Overdue bit = 1,        
 @DueToday bit = 1,        
 @Scheduled bit = 1,        
 @NoFollowUp bit = 1,        
 @AssignedTo bigint = 0,        
 @CreatedBy bigint = 0,        
 @IsReAssign bit = NULL       
)        
as        
begin        
      
 Declare @IsCallback int = 0;      
 Declare @IsConvert int = 0;      
 Declare @FollowUpName varchar = '';      
      
 select @IsCallback = IsCallback, @IsConvert = IsConvert from FollowUp_Status(nolock) where Id = @FollowUpType     
              
 declare @ParentId bigint = 0, @IsAdmin bit = 0                                  
 declare @tbluser table (User_ID bigint,Name varchar(100), Image varchar(100))    
                                 
 select @IsAdmin = IsAdmin, @ParentId = ParentID from User_Detail(nolock) where User_ID = @UserId            
         
 Declare @TeamCode varchar(10) = ''      
 Declare @ScopeCode varchar(10) = ''       
 Declare @UserIdTeamLst varchar(Max) = ''       
 Declare @UserLoginTeamLst varchar(Max) = ''       
      
   insert into @tbluser    
 exec Use_GetUserDetails @UserId    
    
 select @UserIdTeamLst=isnull(STRING_AGG(User_ID,','),'') From @tbluser    
    
declare @maxScore numeric(18,2)=isnull((select (max(currentscore)*100)/99 from lead_score_history(nolock)e where parentid=@ParentId),0)            
        
declare @hot int,@warm int,@cold int     
            
 select @hot=hot,@warm=warm,@cold=cold from lead_cateogy_thresholds(nolock) where parentid=@ParentID                  
 if @hot is null                  
 begin                  
 select @hot=hot,@warm=warm,@cold=cold from lead_cateogy_thresholds(nolock) where parentid=0                  
 end                  
    
 print @FollowUpType    
    
select count(id) over() as TotalRow, Title, Discription , NextStatusDate,  
CreatedOn, LeadNo, AmountPaid, PersonName, MobileNo, MobileNo1, MobileNo2, Owner, FollowupDateStatus, CurrentScore  
  
from (    
  
    select lih.ID, fs.followupstatus as Title, lih.remarks as Discription,     
           lih.followupdate as NextStatusDate,     
           lih.CreatedOn,     
           lih.AmountPaid,     
           ul.id as LeadId,     
		   ul.LeadNo, 
           iif(isnull(ltrim(rtrim(ul.mobileno)), '') <> '', concat(ul.countrycode, ' ', ul.mobileno), '') as MobileNo,     
           iif(isnull(ltrim(rtrim(ul.mobileno2)), '') <> '', concat(ul.countrycode2, ' ', ul.mobileno2), '') as MobileNo2,     
           iif(isnull(ltrim(rtrim(ul.mobileno1)), '') <> '', concat(ul.countrycode1, ' ', ul.mobileno1), '') as MobileNo1,     
           ul.PersonName,     
           ul.ProfileImgFileName,     
           iif(ul.assignedto = @UserId or 1 = @IsAdmin, 1, 0) as [IsUIActive],     
           lih.assignedto,     
           ltrim(rtrim(concat(ud.fname, ' ', ud.lname))) as [Owner],     
           '' as [Status],     
           ud.parentid as [ParentId],     
           (case    
                when cast(lih.followupdate as date) = cast(getdate() as date)    
                then 0    
                when cast(lih.followupdate as date) < cast(getdate() as date)    
                then 1    
                when cast(lih.followupdate as date) > cast(getdate() as date)    
                then 2    
                when cast(lih.followupdate as date) is null    
                then 3    
            end) as [OrderSeq],     
    (case    
                when cast(lih.followupdate as date) = cast(getdate() as date)    
                then 'duetoday'    
                when cast(lih.followupdate as date) < cast(getdate() as date)    
                then 'overdue'    
                when cast(lih.followupdate as date) > cast(getdate() as date)    
                then 'scheduled'    
                when cast(lih.followupdate as date) is null    
                then 'nofollowup'    
            end) as [FollowupDateStatus],    
           (case when ls.scoreadded > 0 then 'green_up' when ls.scoreadded < 0 then 'red_down' else '' end) as [Profit_Loss],     
           cast(isnull((ls.currentscore / nullif(@maxScore, 0.00)) * 99, 0) as int) as [CurrentScore],    
           ( case when cast(isnull((ls.currentscore / nullif(@maxScore, 0.00)) * 99, 0) as int) > @warm then 'hot'    
               when cast(isnull((ls.currentscore / nullif(@maxScore, 0.00)) * 99, 0) as int) between @cold and @warm then 'warm'    
               else 'cold'end ) as [ThresholdColor]    
    from leadinteractionhistory(nolock) lih inner join followup_status(nolock) fs     
 on  lih.followupstatus = fs.id inner join userleads(nolock) ul     
 on  lih.leadno = ul.leadno and ul.parentid = lih.parentid left join lead_score_history_latest(nolock) ls     
 on  ls.leadid = ul.id left join user_detail(nolock) ud     
 on  lih.assignedto = ud.user_id    
  
  where    
  lih.IsReassign = case when @IsReAssign is null and  @CreatedBy <> 0 then 0 when @IsReAssign is not null then @IsReAssign else lih.IsReassign end and     
   lih.id = case when isnull(@CreatedFromDate,'1900-01-01') > '1900-01-01' then lih.id else (    
   select max(id) from leadinteractionhistory(nolock) where parentid = lih.parentid and leadno = lih.leadno    
  ) end    
        and ul.parentid = @ParentId    
  /*and 1 = (case when isnull(@FollowUpType, 0) = 0 and fs.IsCallback = 1 then 1     
    when isnull(@FollowUpType, 0) > 0 and lih.FollowUpStatus = @FollowUpType then 1    
   else 0 end )*/    
  and 1 = (case when isnull(@FollowUpType,0)=0 and @NoFollowUp=1 and @Scheduled = 1 and @DueToday = 1 and @Overdue = 1 then 1     
     when isnull(@FollowUpType, 0) = 0 and fs.IsCallback = 1 then 1     
     when isnull(@FollowUpType, 0) > 0 and lih.FollowUpStatus = @FollowUpType then 1    
   else 0 end )    
  and 1 = ( case when @isadmin=1 then 1     
     when isnull(ul.AssignedTo,0) in (select [value] from dbo.fn_Split(@UserIdTeamLst, ',')) then 1    
     when isnull(ul.AssignedTo,0) = @UserId then 1    
    else 0 end)    
  and 1 = (case when isnull(@AssignedTo, 0) = 0 then 1     
     when isnull(@AssignedTo, 0) > 0 and lih.AssignedTo = @AssignedTo then 1     
    else 0 end )    
  and 1 = (case when isnull(@CreatedBy, 0) = 0 then 1     
     when isnull(@CreatedBy, 0) > 0 and lih.CreatedBy = @CreatedBy then 1     
    else 0 end )    
        and 1 = iif( Isnull(@NextStatusFromDate, '') <> '' and Isnull(@NextStatusToDate, '') <> '',     
     iif(CAST(TRY_CONVERT(DATETIME, lih.FollowupDate) AS DATE) between cast(@NextStatusFromDate as date) and cast(@NextStatusToDate as date), 1, 0),    
    1)    
        and 1 = iif( Isnull(@CreatedFromDate, '') <> ''     
     and Isnull(@CreatedToDate, '') <> '',     
     iif(CAST(TRY_CONVERT(DATETIME, lih.CreatedOn) AS DATE) between cast(@CreatedFromDate as date) and cast( @CreatedToDate as date), 1, 0),    
    1)    
  and 1 = ( case when isnull(@LeadId, 0) = 0 then 1 when isnull(@LeadId, 0) > 0 and @LeadId = ul.ID then 1 else 0 end )    
  and 1 = ( case when isnull(@Remarks, '') =  '' then 1    
    when isnull(@Remarks, '') <>  '' and lih.Remarks like '%'+ @Remarks +'%' then 1     
     else 0 end )    
		and 1 = ( case when isnull(@FollowUpType, 0) > 0 and fs.IsConvert = 1 then 1
					 when Isnull(@NextStatusFromDate, '') = '' and Isnull(@NextStatusToDate, '') = ''
					and fs.IsConvert = 1 then 0 else 1 end  )
) as fu    
where 1 = ( case    
    when followupdatestatus =  'overdue' and @Overdue = 1 then 1    
 when followupdatestatus =  'duetoday' and @DueToday = 1 then 1    
 when followupdatestatus =  'scheduled' and @Scheduled = 1 then 1    
 when followupdatestatus =  'nofollowup' and @NoFollowUp = 1 then 1    
 else 0  end    
)    
order by orderseq, cast(nextstatusdate as datetime)    
  
end        


GO

/* ============================================================
   Procedure: [dbo].[usp_GetFollowUpListByUserId_withScoreCard_Search_WithSegment]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


--exec usp_GetFollowUpListByUserId_withScoreCard_Search @UserId=32222,@FollowUpType=0,@NextStatusFromDate=N'01-Jan-1900',@NextStatusToDate=N'18-Apr-2022',@CreatedFromDate=N'',@CreatedToDate=N'',@LeadId=N'',@Remarks=N'',@Overdue=1,@DueToday=0,@Scheduled=0,@NoFollowUp=0,@AssignedTo=0,@CreatedBy=0, @IsReAssign = NULL   
CREATE   PROCEDURE [dbo].[usp_GetFollowUpListByUserId_withScoreCard_Search_WithSegment]
(
	 @UserId BIGINT = 0
		--,@FollowUpType INT = 0
	,@FollowUpType nvarchar(max) = '0'
	,
	--@NextStatusFromDate VARCHAR(30) = NULL,        
	--@NextStatusToDate VARCHAR(30) = NULL,        
	--@CreatedFromDate VARCHAR(30) = NULL,        
	--@CreatedToDate VARCHAR(30) = NULL,        
	@NextStatusFromDate DATETIME = NULL
	,@NextStatusToDate DATETIME = NULL
	,@CreatedFromDate DATETIME = NULL
	,@CreatedToDate DATETIME = NULL
	,@LeadId BIGINT = NULL
	,@Remarks NVARCHAR(500) = ''
	,@Overdue BIT = 1
	,@DueToday BIT = 1
	,@Scheduled BIT = 1
	,@NoFollowUp BIT = 1
	,@AssignedTo BIGINT = 0
	,@CreatedBy BIGINT = 0
	,@IsReAssign BIT = NULL
	,@CriteriaName nvarchar(500) = null 
	)
AS
BEGIN


      if(trim(isnull(@CriteriaName,''))  = '')
	    begin
		    exec usp_GetFollowUpListByUserId_withScoreCard_Search
		         @UserId,@FollowUpType,@NextStatusFromDate,@NextStatusToDate 
	            ,@CreatedFromDate,@CreatedToDate,@LeadId,@Remarks 
	            ,@Overdue,@DueToday,@Scheduled,@NoFollowUp,@AssignedTo,@CreatedBy
				,@IsReAssign 
		    return		   
		end
		
		if(year(@NextStatusToDate) = '1900')
		  begin
              set @NextStatusToDate = CAST('31-Dec-2123' as date)    
		  end

        if(year(@CreatedToDate) = '1900')
		  begin
              set @CreatedToDate = CAST('31-Dec-2123' as date)    
		  end


	DECLARE @IsCallback INT = 0;
	DECLARE @IsConvert INT = 0;
	DECLARE @FollowUpName VARCHAR = '';


	/*
	SELECT @IsCallback = IsCallback
		,@IsConvert = IsConvert
	FROM FollowUp_Status(NOLOCK)
	WHERE Id = @FollowUpType
	*/
	  
	Declare @flpIDsCount int = 0;
	set @flpIDsCount = isnull((select count(value) from fn_Split(@FollowUpType,',') where isnull(value,0) <> 0),0);


	DECLARE @ParentId BIGINT = 0
		,@IsAdmin BIT = 0
	DECLARE @tbluser TABLE (
		User_ID BIGINT
		,Name VARCHAR(100)
		,IMAGE VARCHAR(100)
		)

	SELECT @IsAdmin = IsAdmin
		,@ParentId = ParentID
	FROM User_Detail(NOLOCK)
	WHERE User_ID = @UserId

	-- start Segmentation handling

	 declare @SPID bigint = isnull((select @@SPID),0)
     delete from [tbl_LeadID_WithSPID] where SP_ID = @SPID  
	
	 drop table if exists  #userleadsBySegment 
    
     declare @LeadCount int =  (select count(1) from Userleads(nolock) where ParentID = @ParentID)

	  exec Usp_ViewLeadDetailsBySearchCriteria_IDSegment_SPID 1,@LeadCount,@Criterianame,@UserID ,0,'Name'
      select LeadID as ID into #userleadsBySegment from tbl_LeadID_WithSPID with(nolock) where SP_ID = @SPID
	 
	 delete from [tbl_LeadID_WithSPID] where SP_ID = @SPID
	  
     declare @QueryTotality nvarchar(max) = ''
	    
    -- end Segmentation handling

	DECLARE @TeamCode VARCHAR(10) = ''
	DECLARE @ScopeCode VARCHAR(10) = ''
	DECLARE @UserIdTeamLst VARCHAR(Max) = ''
	DECLARE @UserLoginTeamLst VARCHAR(Max) = ''

	INSERT INTO @tbluser
	EXEC Use_GetUserDetails @UserId

	SELECT @UserIdTeamLst = isnull(STRING_AGG(User_ID, ','), '')
	FROM @tbluser

	DECLARE @maxScore NUMERIC(18, 2) = isnull((
				SELECT (max(currentscore) * 100) / 99
				FROM lead_score_history(NOLOCK) e
				WHERE parentid = @ParentId
				), 0)
	DECLARE @hot INT
		,@warm INT
		,@cold INT

	SELECT @hot = hot
		,@warm = warm
		,@cold = cold
	FROM lead_cateogy_thresholds(NOLOCK)
	WHERE parentid = @ParentID

	IF @hot IS NULL
	BEGIN
		SELECT @hot = hot
			,@warm = warm
			,@cold = cold
		FROM lead_cateogy_thresholds(NOLOCK)
		WHERE parentid = 0
	END

	PRINT @FollowUpType

    Declare @QuerySection nvarchar(max) =  Concat( @QueryTotality ,' ; ',N'SELECT count(id) OVER () AS TotalRow
		,*
	FROM (
		SELECT lih.ID
			,fs.followupstatus AS Title
			,lih.remarks AS Discription
			,fromat(lih.followupdate, ''dd-MMM-yyyy HH:mm'') AS NextStatusDate
			,fromat(lih.CreatedOn, ''dd-MMM-yyyy HH:mm'') as [CreatedOn]
			,lih.AmountPaid
			,ul.id AS LeadId
			,iif(isnull(ltrim(rtrim(ul.mobileno)), '''') <> '''', CONCAT (
					ul.countrycode
					,'' ''
					,ul.mobileno
					), '''') AS MobileNo
			,iif(isnull(ltrim(rtrim(ul.mobileno2)), '''') <> '''', CONCAT (
					ul.countrycode2
					,'' ''
					,ul.mobileno2
					), '''') AS MobileNo2
			,iif(isnull(ltrim(rtrim(ul.mobileno1)), '''') <> '''', CONCAT (
					ul.countrycode1
					,'' ''
					,ul.mobileno1
					), '''') AS MobileNo1
			,ul.PersonName
			,ul.ProfileImgFileName
			,iif(ul.assignedto = ', cast(@UserId as nvarchar(50)) ,'
				OR 1 = ', cast(@IsAdmin as nvarchar(10)) ,', 1, 0) AS [IsUIActive]
			,lih.assignedto
			,ltrim(rtrim(CONCAT (
						ud.fname
						,'' ''
						,ud.lname
						))) AS [Owner]
			,'''' AS [Status]
			,ud.parentid AS [ParentId]
			,(
				CASE 
					WHEN cast(lih.followupdate AS DATE) = cast(getdate() AS DATE)
						THEN 0
					WHEN cast(lih.followupdate AS DATE) < cast(getdate() AS DATE)
						THEN 1
					WHEN cast(lih.followupdate AS DATE) > cast(getdate() AS DATE)
						THEN 2
					WHEN cast(lih.followupdate AS DATE) IS NULL
						THEN 3
					END
				) AS [OrderSeq]
			,(
				CASE 
					WHEN cast(lih.followupdate AS DATE) = cast(getdate() AS DATE)
						THEN ''duetoday''
					WHEN cast(lih.followupdate AS DATE) < cast(getdate() AS DATE)
						THEN ''overdue''
					WHEN cast(lih.followupdate AS DATE) > cast(getdate() AS DATE)
						THEN ''scheduled''
					WHEN cast(lih.followupdate AS DATE) IS NULL
						THEN ''nofollowup''
					END
				) AS [FollowupDateStatus]
			,(
				CASE 
					WHEN ls.scoreadded > 0
						THEN ''green_up''
					WHEN ls.scoreadded < 0
						THEN ''red_down''
					ELSE ''''
					END
				) AS [Profit_Loss]
			,cast(isnull((ls.currentscore / nullif(', cast(@maxScore as nvarchar), ', 0.00)) * 99, 0) AS INT) AS [CurrentScore]
			,(
				CASE 
					WHEN cast(isnull((ls.currentscore / nullif(', cast(@maxScore as nvarchar), ', 0.00)) * 99, 0) AS INT) > ',cast(@warm as nvarchar(50)) ,'
						THEN ''hot''
					WHEN cast(isnull((ls.currentscore / nullif(', cast(@maxScore as nvarchar), ', 0.00)) * 99, 0) AS INT) BETWEEN ',cast(@cold as nvarchar(50)),'
							AND ',cast(@warm as nvarchar(50)) ,'
						THEN ''warm''
					ELSE ''cold''
					END
				) AS [ThresholdColor]
		FROM leadinteractionhistory(NOLOCK) lih
		     
		INNER JOIN followup_status(NOLOCK) fs ON lih.followupstatus = fs.id
		INNER JOIN userleads(NOLOCK) ul ON lih.leadno = ul.leadno
			AND ul.parentid = lih.parentid
        inner join #userleadsBySegment as uls on ul.ID = uls.ID        
		LEFT JOIN lead_score_history_latest(NOLOCK) ls ON ls.leadid = ul.id
		LEFT JOIN user_detail(NOLOCK) ud ON lih.assignedto = ud.user_id
		WHERE
			lih.IsReassign = CASE 
				WHEN ' , cast( isnull(@IsReAssign, '0') as nvarchar(10)) ,' = 0  --IS NULL
					AND ', cast(@CreatedBy as nvarchar(50)) ,' <> 0
					THEN 0
				WHEN ', cast( isnull(@IsReAssign,'0') as nvarchar(10)) ,' <> 0  --IS NOT NULL
					THEN ', cast( isnull(@IsReAssign, '0') as nvarchar(10)) ,'
				ELSE lih.IsReassign
				END
			AND

			lih.id = CASE 
				WHEN isnull(''', cast(@CreatedFromDate as nvarchar(50)) ,''', ''1900-01-01'') > ''1900-01-01''
					THEN lih.id
				ELSE (
						SELECT max(lihinner.id)
						FROM leadinteractionhistory(NOLOCK) as lihInner
						WHERE lihinner.parentid = lih.parentid
							AND lihinner.leadno = lih.leadno
						)
				END
			AND ul.parentid = ', cast(@ParentId as nvarchar(50)) ,'
			and lih.ParentID =  ', cast(@ParentId as nvarchar(50)) ,'
			AND 1 = (
				CASE 
					WHEN ', cast(@flpIDsCount as nvarchar(50) ) , ' = 0
						AND ', cast( @NoFollowUp as nvarchar ) ,' = 1
						AND ', cast(  @Scheduled as nvarchar ) ,' = 1
						AND ', cast( @DueToday as nvarchar ) ,' = 1
						AND ', cast( @Overdue as nvarchar ) ,' = 1
						THEN 1
					WHEN ', cast(@flpIDsCount as nvarchar(50) ) , ' = 0
						AND fs.IsCallback = 1
						THEN 1
					WHEN ', cast(@flpIDsCount as nvarchar(50)) , ' > 0
						AND lih.FollowUpStatus in ( select value from fn_Split(''', @FollowUpType ,''','','') )
						THEN 1
					ELSE 0
					END
				)
			AND 1 = (
				CASE 
					WHEN ', cast(@isadmin as nvarchar) ,' = 1
						THEN 1
					WHEN isnull(ul.AssignedTo, 0) IN (
							SELECT [value]
							FROM dbo.fn_Split(''', cast(@UserIdTeamLst as nvarchar) ,''','','')
							)
						THEN 1
					WHEN isnull(ul.AssignedTo, 0) = ',cast(@UserId  as nvarchar) , '
						THEN 1
					ELSE 0
					END
				)
			AND 1 = (
				CASE 
					WHEN isnull(', cast(@AssignedTo as nvarchar(50)) , ', 0) = 0
						THEN 1
					WHEN isnull(', cast(@AssignedTo as nvarchar(50)) , ', 0) > 0
						AND lih.AssignedTo = ', cast(@AssignedTo as nvarchar(50)) , '
						THEN 1
					ELSE 0
					END
				)
			AND 1 = (
				CASE 
					WHEN isnull(', cast( @CreatedBy as nvarchar(50)) , ', 0) = 0
						THEN 1
					WHEN isnull(', cast( @CreatedBy as nvarchar(50)) , ', 0) > 0
						AND lih.CreatedBy = ', cast( @CreatedBy as nvarchar(50)) , '
						THEN 1
					ELSE 0
					END
				)
			AND 1 = iif(Isnull( ''' , @NextStatusFromDate , ''', '''') <> ''''
				AND Isnull( ''',  @NextStatusToDate , ''', '''') <> '''', iif(CAST(TRY_CONVERT(DATETIME, isnull(lih.FollowupDate,cast( ''', @NextStatusFromDate ,''' AS DATE))) AS DATE) BETWEEN cast( ''', @NextStatusFromDate ,''' AS DATE)
						AND cast(''', @NextStatusToDate  ,''' AS DATE)
							,1
							,0), 1)
			AND 1 = iif(Isnull(''', @CreatedFromDate  ,''', '''') <> ''''
				AND Isnull(''', @CreatedToDate  ,''', '''') <> '''', iif(CAST(TRY_CONVERT(DATETIME, lih.CreatedOn) AS DATE) BETWEEN cast(''', @CreatedFromDate , ''' AS DATE)
						AND cast(''', @CreatedToDate ,''' AS DATE)
							,1
							,0), 1)
			AND 1 = (
				CASE 
					WHEN isnull(',cast(@LeadId as nvarchar(50)),', 0) = 0
						THEN 1
					WHEN isnull(',cast(@LeadId as nvarchar(50)),', 0) > 0
						AND ',cast(@LeadId as nvarchar(50)),' = ul.ID
						THEN 1
					ELSE 0
					END
				)
			AND 1 = (
				CASE 
					WHEN isnull(''', @Remarks, ''', '''') = ''''
						THEN 1
					WHEN isnull(''', @Remarks, ''', '''') <> ''''
						AND lih.Remarks LIKE ''%' , @Remarks , '%''
						THEN 1
					ELSE 0
					END
				)
			AND 1 = (
				CASE 
					WHEN ', cast(@flpIDsCount as nvarchar(50) ) ,' > 0
						AND fs.IsConvert = 1
						THEN 1
					WHEN Isnull(''', cast(@NextStatusFromDate as nvarchar) ,''', '''') = ''''
						AND Isnull(''', cast(@NextStatusToDate as nvarchar) ,''', '''') = ''''
						AND fs.IsConvert = 1
						THEN 0
					ELSE 1
					END
				)
		) AS fu
	WHERE 1 = (
			CASE 
				WHEN followupdatestatus = ''overdue''
					AND ',cast(@Overdue as nvarchar) ,' = 1
					THEN 1
				WHEN followupdatestatus = ''duetoday''
					AND ',cast( @DueToday as nvarchar) ,' = 1
					THEN 1
				WHEN followupdatestatus = ''scheduled''
					AND ',cast( @Scheduled as nvarchar) ,' = 1
					THEN 1
				WHEN followupdatestatus = ''nofollowup''
					AND ',cast( @NoFollowUp as nvarchar) ,' = 1
					THEN 1
				ELSE 0
				END
			)
	ORDER BY orderseq
		,cast(nextstatusdate AS DATETIME) ','')

    print cast(@QuerySection as varchar(max))
	exec sp_executesql @QuerySection

	EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @UserId
		,@Activity_type = 'View_flwup_exp'
		,@ActionType = 'S'
		,@RowJson = ''
		,@Table_name = 'leadinteractionhistory'

    drop table if exists  #userleadsBySegment   

END



GO

/* ============================================================
   Procedure: [dbo].[usp_GetFollowUpListByUserId_withScoreCard_Search_WithSegment_Temp]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

--exec usp_GetFollowUpListByUserId_withScoreCard_Search @UserId=32222,@FollowUpType=0,@NextStatusFromDate=N'01-Jan-1900',@NextStatusToDate=N'18-Apr-2022',@CreatedFromDate=N'',@CreatedToDate=N'',@LeadId=N'',@Remarks=N'',@Overdue=1,@DueToday=0,@Scheduled=0,@NoFollowUp=0,@AssignedTo=0,@CreatedBy=0, @IsReAssign = NULL   
CREATE   PROCEDURE [dbo].[usp_GetFollowUpListByUserId_withScoreCard_Search_WithSegment_Temp]
(
	 @UserId BIGINT = 0
		--,@FollowUpType INT = 0
	,@FollowUpType nvarchar(max) = '0'
	,
	--@NextStatusFromDate VARCHAR(30) = NULL,        
	--@NextStatusToDate VARCHAR(30) = NULL,        
	--@CreatedFromDate VARCHAR(30) = NULL,        
	--@CreatedToDate VARCHAR(30) = NULL,        
	@NextStatusFromDate DATETIME = NULL
	,@NextStatusToDate DATETIME = NULL
	,@CreatedFromDate DATETIME = NULL
	,@CreatedToDate DATETIME = NULL
	,@LeadId BIGINT = NULL
	,@Remarks NVARCHAR(500) = ''
	,@Overdue BIT = 1
	,@DueToday BIT = 1
	,@Scheduled BIT = 1
	,@NoFollowUp BIT = 1
	,@AssignedTo BIGINT = 0
	,@CreatedBy BIGINT = 0
	,@IsReAssign BIT = NULL
	,@CriteriaName nvarchar(500) = null 
	)
AS
BEGIN


      if(trim(isnull(@CriteriaName,''))  = '')
	    begin
		    exec usp_GetFollowUpListByUserId_withScoreCard_Search_Temp
		         @UserId,@FollowUpType,@NextStatusFromDate,@NextStatusToDate 
	            ,@CreatedFromDate,@CreatedToDate,@LeadId,@Remarks 
	            ,@Overdue,@DueToday,@Scheduled,@NoFollowUp,@AssignedTo,@CreatedBy
				,@IsReAssign 
		    return		   
		end
		
		if(year(@NextStatusToDate) = '1900')
		  begin
              set @NextStatusToDate = CAST('31-Dec-2123' as date)    
		  end

        if(year(@CreatedToDate) = '1900')
		  begin
              set @CreatedToDate = CAST('31-Dec-2123' as date)    
		  end


	DECLARE @IsCallback INT = 0;
	DECLARE @IsConvert INT = 0;
	DECLARE @FollowUpName VARCHAR = '';


	/*
	SELECT @IsCallback = IsCallback
		,@IsConvert = IsConvert
	FROM FollowUp_Status(NOLOCK)
	WHERE Id = @FollowUpType
	*/
	  
	Declare @flpIDsCount int = 0;
	set @flpIDsCount = isnull((select count(value) from fn_Split(@FollowUpType,',') where isnull(value,0) <> 0),0);


	DECLARE @ParentId BIGINT = 0
		,@IsAdmin BIT = 0
	DECLARE @tbluser TABLE (
		User_ID BIGINT
		,Name VARCHAR(100)
		,IMAGE VARCHAR(100)
		)

	SELECT @IsAdmin = IsAdmin
		,@ParentId = ParentID
	FROM User_Detail(NOLOCK)
	WHERE User_ID = @UserId

	-- start Segmentation handling

	 declare @SPID bigint = isnull((select @@SPID),0)
     delete from [tbl_LeadID_WithSPID] where SP_ID = @SPID  
	
	 drop table if exists  #userleadsBySegment 
    
     declare @LeadCount int =  (select count(1) from Userleads(nolock) where ParentID = @ParentID)

	  exec Usp_ViewLeadDetailsBySearchCriteria_IDSegment_SPID 1,@LeadCount,@Criterianame,@UserID ,0,'Name'
      select LeadID as ID into #userleadsBySegment from tbl_LeadID_WithSPID with(nolock) where SP_ID = @SPID
	 
	 delete from [tbl_LeadID_WithSPID] where SP_ID = @SPID
	  
     declare @QueryTotality nvarchar(max) = ''
	    
    -- end Segmentation handling

	DECLARE @TeamCode VARCHAR(10) = ''
	DECLARE @ScopeCode VARCHAR(10) = ''
	DECLARE @UserIdTeamLst VARCHAR(Max) = ''
	DECLARE @UserLoginTeamLst VARCHAR(Max) = ''

	INSERT INTO @tbluser
	EXEC Use_GetUserDetails @UserId

	SELECT @UserIdTeamLst = isnull(STRING_AGG(User_ID, ','), '')
	FROM @tbluser

	DECLARE @maxScore NUMERIC(18, 2) = isnull((
				SELECT (max(currentscore) * 100) / 99
				FROM lead_score_history(NOLOCK) e
				WHERE parentid = @ParentId
				), 0)
	DECLARE @hot INT
		,@warm INT
		,@cold INT

	SELECT @hot = hot
		,@warm = warm
		,@cold = cold
	FROM lead_cateogy_thresholds(NOLOCK)
	WHERE parentid = @ParentID

	IF @hot IS NULL
	BEGIN
		SELECT @hot = hot
			,@warm = warm
			,@cold = cold
		FROM lead_cateogy_thresholds(NOLOCK)
		WHERE parentid = 0
	END

	PRINT @FollowUpType

    Declare @QuerySection nvarchar(max) =  Concat( @QueryTotality ,' ; ',N'SELECT count(id) OVER () AS TotalRow
		,*
	FROM (
		SELECT lih.ID
			,fs.followupstatus AS Title
			,lih.remarks AS Discription
			,lih.followupdate AS NextStatusDate
			,lih.CreatedOn
			,lih.AmountPaid
			,ul.id AS LeadId
			,iif(isnull(ltrim(rtrim(ul.mobileno)), '''') <> '''', CONCAT (
					ul.countrycode
					,'' ''
					,ul.mobileno
					), '''') AS MobileNo
			,iif(isnull(ltrim(rtrim(ul.mobileno2)), '''') <> '''', CONCAT (
					ul.countrycode2
					,'' ''
					,ul.mobileno2
					), '''') AS MobileNo2
			,iif(isnull(ltrim(rtrim(ul.mobileno1)), '''') <> '''', CONCAT (
					ul.countrycode1
					,'' ''
					,ul.mobileno1
					), '''') AS MobileNo1
			,ul.PersonName
			,ul.ProfileImgFileName
			,iif(ul.assignedto = ', cast(@UserId as nvarchar(50)) ,'
				OR 1 = ', cast(@IsAdmin as nvarchar(10)) ,', 1, 0) AS [IsUIActive]
			,lih.assignedto
			,ltrim(rtrim(CONCAT (
						ud.fname
						,'' ''
						,ud.lname
						))) AS [Owner]
			,'''' AS [Status]
			,ud.parentid AS [ParentId]
			,(
				CASE 
					WHEN cast(lih.followupdate AS DATE) = cast(getdate() AS DATE)
						THEN 0
					WHEN cast(lih.followupdate AS DATE) < cast(getdate() AS DATE)
						THEN 1
					WHEN cast(lih.followupdate AS DATE) > cast(getdate() AS DATE)
						THEN 2
					WHEN cast(lih.followupdate AS DATE) IS NULL
						THEN 3
					END
				) AS [OrderSeq]
			,(
				CASE 
					WHEN cast(lih.followupdate AS DATE) = cast(getdate() AS DATE)
						THEN ''duetoday''
					WHEN cast(lih.followupdate AS DATE) < cast(getdate() AS DATE)
						THEN ''overdue''
					WHEN cast(lih.followupdate AS DATE) > cast(getdate() AS DATE)
						THEN ''scheduled''
					WHEN cast(lih.followupdate AS DATE) IS NULL
						THEN ''nofollowup''
					END
				) AS [FollowupDateStatus]
			,(
				CASE 
					WHEN ls.scoreadded > 0
						THEN ''green_up''
					WHEN ls.scoreadded < 0
						THEN ''red_down''
					ELSE ''''
					END
				) AS [Profit_Loss]
			,cast(isnull((ls.currentscore / nullif(', cast(@maxScore as nvarchar), ', 0.00)) * 99, 0) AS INT) AS [CurrentScore]
			,(
				CASE 
					WHEN cast(isnull((ls.currentscore / nullif(', cast(@maxScore as nvarchar), ', 0.00)) * 99, 0) AS INT) > ',cast(@warm as nvarchar(50)) ,'
						THEN ''hot''
					WHEN cast(isnull((ls.currentscore / nullif(', cast(@maxScore as nvarchar), ', 0.00)) * 99, 0) AS INT) BETWEEN ',cast(@cold as nvarchar(50)),'
							AND ',cast(@warm as nvarchar(50)) ,'
						THEN ''warm''
					ELSE ''cold''
					END
				) AS [ThresholdColor]
		FROM leadinteractionhistory(NOLOCK) lih
		     
		INNER JOIN followup_status(NOLOCK) fs ON lih.followupstatus = fs.id
		INNER JOIN userleads(NOLOCK) ul ON lih.leadno = ul.leadno
			AND ul.parentid = lih.parentid
        inner join #userleadsBySegment as uls on ul.ID = uls.ID        
		LEFT JOIN lead_score_history_latest(NOLOCK) ls ON ls.leadid = ul.id
		LEFT JOIN user_detail(NOLOCK) ud ON lih.assignedto = ud.user_id
		WHERE
			lih.IsReassign = CASE 
				WHEN ' , cast( isnull(@IsReAssign, '0') as nvarchar(10)) ,' = 0  --IS NULL
					AND ', cast(@CreatedBy as nvarchar(50)) ,' <> 0
					THEN 0
				WHEN ', cast( isnull(@IsReAssign,'0') as nvarchar(10)) ,' <> 0  --IS NOT NULL
					THEN ', cast( isnull(@IsReAssign, '0') as nvarchar(10)) ,'
				ELSE lih.IsReassign
				END
			AND

			lih.id = CASE 
				WHEN isnull(''', cast(@CreatedFromDate as nvarchar(50)) ,''', ''1900-01-01'') > ''1900-01-01''
					THEN lih.id
				ELSE (
						SELECT max(lihinner.id)
						FROM leadinteractionhistory(NOLOCK) as lihInner
						WHERE lihinner.parentid = lih.parentid
							AND lihinner.leadno = lih.leadno
						)
				END
			AND ul.parentid = ', cast(@ParentId as nvarchar(50)) ,'
			and lih.ParentID =  ', cast(@ParentId as nvarchar(50)) ,'
			AND 1 = (
				CASE 
					WHEN ', cast(@flpIDsCount as nvarchar(50) ) , ' = 0
						AND ', cast( @NoFollowUp as nvarchar ) ,' = 1
						AND ', cast(  @Scheduled as nvarchar ) ,' = 1
						AND ', cast( @DueToday as nvarchar ) ,' = 1
						AND ', cast( @Overdue as nvarchar ) ,' = 1
						THEN 1
					WHEN ', cast(@flpIDsCount as nvarchar(50) ) , ' = 0
						AND fs.IsCallback = 1
						THEN 1
					WHEN ', cast(@flpIDsCount as nvarchar(50)) , ' > 0
						AND lih.FollowUpStatus in ( select value from fn_Split(''', @FollowUpType ,''','','') )
						THEN 1
					ELSE 0
					END
				)
			AND 1 = (
				CASE 
					WHEN ', cast(@isadmin as nvarchar) ,' = 1
						THEN 1
					WHEN isnull(ul.AssignedTo, 0) IN (
							SELECT [value]
							FROM dbo.fn_Split(''', cast(@UserIdTeamLst as nvarchar) ,''','','')
							)
						THEN 1
					WHEN isnull(ul.AssignedTo, 0) = ',cast(@UserId  as nvarchar) , '
						THEN 1
					ELSE 0
					END
				)
			AND 1 = (
				CASE 
					WHEN isnull(', cast(@AssignedTo as nvarchar(50)) , ', 0) = 0
						THEN 1
					WHEN isnull(', cast(@AssignedTo as nvarchar(50)) , ', 0) > 0
						AND lih.AssignedTo = ', cast(@AssignedTo as nvarchar(50)) , '
						THEN 1
					ELSE 0
					END
				)
			AND 1 = (
				CASE 
					WHEN isnull(', cast( @CreatedBy as nvarchar(50)) , ', 0) = 0
						THEN 1
					WHEN isnull(', cast( @CreatedBy as nvarchar(50)) , ', 0) > 0
						AND lih.CreatedBy = ', cast( @CreatedBy as nvarchar(50)) , '
						THEN 1
					ELSE 0
					END
				)
			AND 1 = iif(Isnull( ''' , @NextStatusFromDate , ''', '''') <> ''''
				AND Isnull( ''',  @NextStatusToDate , ''', '''') <> '''', iif(CAST(TRY_CONVERT(DATETIME, isnull(lih.FollowupDate,cast( ''', @NextStatusFromDate ,''' AS DATE))) AS DATE) BETWEEN cast( ''', @NextStatusFromDate ,''' AS DATE)
						AND cast(''', @NextStatusToDate  ,''' AS DATE)
							,1
							,0), 1)
			AND 1 = iif(Isnull(''', @CreatedFromDate  ,''', '''') <> ''''
				AND Isnull(''', @CreatedToDate  ,''', '''') <> '''', iif(CAST(TRY_CONVERT(DATETIME, lih.CreatedOn) AS DATE) BETWEEN cast(''', @CreatedFromDate , ''' AS DATE)
						AND cast(''', @CreatedToDate ,''' AS DATE)
							,1
							,0), 1)
			AND 1 = (
				CASE 
					WHEN isnull(',cast(@LeadId as nvarchar(50)),', 0) = 0
						THEN 1
					WHEN isnull(',cast(@LeadId as nvarchar(50)),', 0) > 0
						AND ',cast(@LeadId as nvarchar(50)),' = ul.ID
						THEN 1
					ELSE 0
					END
				)
			AND 1 = (
				CASE 
					WHEN isnull(''', @Remarks, ''', '''') = ''''
						THEN 1
					WHEN isnull(''', @Remarks, ''', '''') <> ''''
						AND lih.Remarks LIKE ''%' , @Remarks , '%''
						THEN 1
					ELSE 0
					END
				)
			AND 1 = (
				CASE 
					WHEN ', cast(@flpIDsCount as nvarchar(50) ) ,' > 0
						AND fs.IsConvert = 1
						THEN 1
					WHEN Isnull(''', cast(@NextStatusFromDate as nvarchar) ,''', '''') = ''''
						AND Isnull(''', cast(@NextStatusToDate as nvarchar) ,''', '''') = ''''
						AND fs.IsConvert = 1
						THEN 0
					ELSE 1
					END
				)
		) AS fu
	WHERE 1 = (
			CASE 
				WHEN followupdatestatus = ''overdue''
					AND ',cast(@Overdue as nvarchar) ,' = 1
					THEN 1
				WHEN followupdatestatus = ''duetoday''
					AND ',cast( @DueToday as nvarchar) ,' = 1
					THEN 1
				WHEN followupdatestatus = ''scheduled''
					AND ',cast( @Scheduled as nvarchar) ,' = 1
					THEN 1
				WHEN followupdatestatus = ''nofollowup''
					AND ',cast( @NoFollowUp as nvarchar) ,' = 1
					THEN 1
				ELSE 0
				END
			)
	ORDER BY orderseq
		,cast(nextstatusdate AS DATETIME) ','')

    print cast(@QuerySection as varchar(max))
	exec sp_executesql @QuerySection

	EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @UserId
		,@Activity_type = 'View_flwup_exp'
		,@ActionType = 'S'
		,@RowJson = ''
		,@Table_name = 'leadinteractionhistory'

    drop table if exists  #userleadsBySegment   

END



GO

/* ============================================================
   Procedure: [dbo].[usp_GetFollowUpListByUserId_withScoreCard_Temp]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

--exec usp_GetFollowUpListByUserId_withScoreCard @OffsetValue=0,@PagingSize=300,@UserId=39042,@FollowUpType=0,@NextStatusFromDate=N'01-Jan-1900',@NextStatusToDate=N'18-Apr-2022',@CreatedFromDate=N'',@CreatedToDate=N'',@LeadId=N'',@Remarks=N'',@Overdue=1,@DueToday=0,@Scheduled=0,@NoFollowUp=0,@AssignedTo=0,@CreatedBy=0
--exec usp_GetFollowUpListByUserId_withScoreCard @OffsetValue=0,@PagingSize=100,@UserId=36950,@FollowUpType=0,@NextStatusFromDate=N'',@NextStatusToDate=N'',@CreatedFromDate=N'',@CreatedToDate=N'',@LeadId=N'',@Remarks=N'',@Overdue=1,@DueToday=1,@Scheduled=1,@NoFollowUp=1,@AssignedTo=0,@CreatedBy=0
--exec usp_GetFollowUpListByUserId_withScoreCard$ @OffsetValue=0,@PagingSize=100,@UserId=39680,@FollowUpType=0,@NextStatusFromDate=N'',@NextStatusToDate=N'',@CreatedFromDate=N'11-May-2022 00:00:00',@CreatedToDate=N'12-May-2022 00:00:00', @LeadId=N'', @Remarks=N'', @Overdue=1, @DueToday=1, @Scheduled=1, @NoFollowUp=1,@AssignedTo=0,@CreatedBy=0, @IsReAssign=0
CREATE   PROCEDURE [dbo].[usp_GetFollowUpListByUserId_withScoreCard_Temp] (
	 @OffsetValue INT = 0
	,@PagingSize INT = 20
	,@UserId BIGINT
	--,@FollowUpType INT = 0
	,@FollowUpType nvarchar(max) = '0'
	,@NextStatusFromDate DATETIME = NULL
	,@NextStatusToDate DATETIME = NULL
	,@CreatedFromDate DATETIME = NULL
	,@CreatedToDate DATETIME = NULL
	,@LeadId BIGINT = NULL
	,@Remarks NVARCHAR(500) = ''
	,@Overdue BIT = 1
	,@DueToday BIT = 1
	,@Scheduled BIT = 1
	,@NoFollowUp BIT = 1
	,@AssignedTo BIGINT = 0
	,@CreatedBy BIGINT = 0
	,@IsReAssign BIT = NULL
	)
AS
BEGIN
	--declare @OffsetValue int=0, @PagingSize int = 100, @UserId bigint = 39042, @FollowUpType int = 0, @NextStatusFromDate datetime = N'', @NextStatusToDate datetime = N'', @CreatedFromDate datetime = N'', @CreatedToDate datetime = N'', @LeadId bigint = N'', @Remarks nvarchar(500) = N'', @Overdue bit = 1, @DueToday bit= 1, @Scheduled bit = 1, @NoFollowUp bit = 1, @AssignedTo bigint = 0, @CreatedBy bigint = 0
	--declare @OffsetValue int=0, @PagingSize int = 100, @UserId bigint = 35610, @FollowUpType int = 0, @NextStatusFromDate datetime = N'', @NextStatusToDate datetime = N'', @CreatedFromDate datetime = N'', @CreatedToDate datetime = N'', @LeadId bigint = N'', @Remarks nvarchar(500) = N'', @Overdue bit = 1, @DueToday bit= 1, @Scheduled bit = 1, @NoFollowUp bit = 1, @AssignedTo bigint = 0, @CreatedBy bigint = 0
	--declare @OffsetValue int = 0,@PagingSize int = 100,@UserId bigint=36950,@FollowUpType int = 0,@NextStatusFromDate datetime = N'',@NextStatusToDate datetime = N'',@CreatedFromDate datetime = N'',@CreatedToDate datetime = N'',@LeadId bigint = N'',@Remarks nvarchar(500) = '',@Overdue bit = 1,@DueToday bit = 1,@Scheduled bit = 1,@NoFollowUp bit = 1,@AssignedTo bigint = 0,@CreatedBy bigint = 0
	--declare @OffsetValue int=0,@PagingSize int=100,@UserId bigint=39680,@FollowUpType int=0,@NextStatusFromDate datetime=N'',@NextStatusToDate datetime=N'',@CreatedFromDate datetime=N'09-May-2022 00:00:00',@CreatedToDate datetime=N'10-May-2022 00:00:00',@LeadId bigint=N'',@Remarks nvarchar(500)=N'',@Overdue bit=1,@DueToday bit=1,@Scheduled bit=1,@NoFollowUp bit=1,@AssignedTo bigint=0,@CreatedBy bigint=40062
	--declare @OffsetValue int=0,@PagingSize int=100,@UserId bigint=39680,@FollowUpType int=0,@NextStatusFromDate datetime=N'',@NextStatusToDate datetime=N'',@CreatedFromDate datetime=N'09-May-2022 00:00:00',@CreatedToDate datetime=N'10-May-2022 00:00:00',@LeadId bigint=N'',@Remarks nvarchar(500)=N'',@Overdue bit=1,@DueToday bit=1,@Scheduled bit=1,@NoFollowUp bit=1,@AssignedTo bigint=0,@CreatedBy bigint=40061
	--declare @OffsetValue int=0,@PagingSize int=100,@UserId bigint=40058,@FollowUpType int=461,@NextStatusFromDate datetime=N'',@NextStatusToDate datetime=N'',@CreatedFromDate datetime=N'01-Jun-2022 12:30:00',@CreatedToDate datetime=N'03-Jun-2022 12:30:00',@LeadId bigint=N'',@Remarks nvarchar(500)=N'',@Overdue bit=1,@DueToday bit=1,@Scheduled bit=1,@NoFollowUp bit=1,@AssignedTo bigint=0,@CreatedBy bigint=40058, @IsReAssign bit=0

	--declare @OffsetValue int=0,@PagingSize int=100,@UserId bigint=39680,@FollowUpType int=0,@NextStatusFromDate datetime=N'',@NextStatusToDate datetime=N'',@CreatedFromDate datetime=N'07-Dec-2022 00:00:00',@CreatedToDate datetime=N'07-Dec-2022 00:00:00',@LeadId bigint=N'',@Remarks nvarchar(500)=N'',@Overdue bit=1,@DueToday bit=1,@Scheduled bit=1,@NoFollowUp bit=1,@AssignedTo bigint=0,@CreatedBy bigint=40057, @IsReAssign bit=0



	DECLARE @IsCallback INT = 0;
	DECLARE @IsConvert INT = 0;
	DECLARE @FollowUpName VARCHAR = '';

	
	/*
	SELECT @IsCallback = IsCallback
		,@IsConvert = IsConvert
	FROM FollowUp_Status(NOLOCK)
	WHERE Id = @FollowUpType
	*/

	Declare @flpIDsCount int = 0;
	set @flpIDsCount = isnull((select count(value) from fn_Split(@FollowUpType,',') where isnull(value,0) <> 0),0);



	DECLARE @ParentId BIGINT = 0
		,@IsAdmin BIT = 0
	DECLARE @tbluser TABLE (
		User_ID BIGINT
		,Name VARCHAR(100)
		,IMAGE VARCHAR(100)
		)

	SELECT @IsAdmin = IsAdmin
		,@ParentId = ParentID
	FROM User_Detail(NOLOCK)
	WHERE User_ID = @UserId

	DECLARE @TeamCode VARCHAR(10) = ''
	DECLARE @ScopeCode VARCHAR(10) = ''
	DECLARE @UserIdTeamLst VARCHAR(Max) = ''
	DECLARE @UserLoginTeamLst VARCHAR(Max) = ''

	--select @TeamCode = TeamCode, @ScopeCode = ScopeCode, @UserIdTeamLst = UserIdTeamLst, @UserLoginTeamLst = UserLoginTeamLst from dbo.ufn_GetUserRoleScope(@UserId)   
	INSERT INTO @tbluser
	EXEC Use_GetUserDetails @UserId

	SELECT @UserIdTeamLst = isnull(STRING_AGG(User_ID, ','), '')
	FROM @tbluser

	-- select @TeamCode TeamCode, @ScopeCode ScopeCode, @UserIdTeamLst UserIdTeamLst, @UserLoginTeamLst UserLoginTeamLst     
	DECLARE @maxScore NUMERIC(18, 2) = isnull((
				SELECT (max(currentscore) * 100) / 99
				FROM lead_score_history(NOLOCK) e
				WHERE parentid = @ParentId
				), 0)
	DECLARE @hot INT
		,@warm INT
		,@cold INT

	SELECT @hot = hot
		,@warm = warm
		,@cold = cold
	FROM lead_cateogy_thresholds(NOLOCK)
	WHERE parentid = @ParentID

	IF @hot IS NULL
	BEGIN
		SELECT @hot = hot
			,@warm = warm
			,@cold = cold
		FROM lead_cateogy_thresholds(NOLOCK)
		WHERE parentid = 0
	END

	PRINT @FollowUpType

	SELECT count(id) OVER () AS TotalRow
		,*
	FROM (
		SELECT lih.ID
			,fs.followupstatus AS Title
			,lih.remarks AS Discription
			,lih.followupdate AS NextStatusDate
			,lih.CreatedOn
			,lih.AmountPaid
			,ul.id AS LeadId
			,iif(isnull(ltrim(rtrim(ul.mobileno)), '') <> '', CONCAT (
					ul.countrycode
					,' '
					,ul.mobileno
					), '') AS MobileNo
			,iif(isnull(ltrim(rtrim(ul.mobileno2)), '') <> '', CONCAT (
					ul.countrycode2
					,' '
					,ul.mobileno2
					), '') AS MobileNo2
			,iif(isnull(ltrim(rtrim(ul.mobileno1)), '') <> '', CONCAT (
					ul.countrycode1
					,' '
					,ul.mobileno1
					), '') AS MobileNo1
			,ul.PersonName
			,ul.ProfileImgFileName
			,iif(ul.assignedto = @UserId
				OR 1 = @IsAdmin, 1, 0) AS [IsUIActive]
			,lih.assignedto
			,ltrim(rtrim(CONCAT (
						ud.fname
						,' '
						,ud.lname
						))) AS [Owner]
			,'' AS [Status]
			,ud.parentid AS [ParentId]
			,(
				CASE 
					WHEN cast(lih.followupdate AS DATE) = cast(getdate() AS DATE)
						THEN 0
					WHEN cast(lih.followupdate AS DATE) < cast(getdate() AS DATE)
						THEN 1
					WHEN cast(lih.followupdate AS DATE) > cast(getdate() AS DATE)
						THEN 2
					WHEN cast(lih.followupdate AS DATE) IS NULL
						THEN 3
					END
				) AS [OrderSeq]
			,(
				CASE 
					WHEN cast(lih.followupdate AS DATE) = cast(getdate() AS DATE)
						THEN 'duetoday'
					WHEN cast(lih.followupdate AS DATE) < cast(getdate() AS DATE)
						THEN 'overdue'
					WHEN cast(lih.followupdate AS DATE) > cast(getdate() AS DATE)
						THEN 'scheduled'
					WHEN cast(lih.followupdate AS DATE) IS NULL
						THEN 'nofollowup'
					END
				) AS [FollowupDateStatus]
			,(
				CASE 
					WHEN ls.scoreadded > 0
						THEN 'green_up'
					WHEN ls.scoreadded < 0
						THEN 'red_down'
					ELSE ''
					END
				) AS [Profit_Loss]
			,cast(isnull((ls.currentscore / nullif(@maxScore, 0.00)) * 99, 0) AS INT) AS [CurrentScore]
			,(
				CASE 
					WHEN cast(isnull((ls.currentscore / nullif(@maxScore, 0.00)) * 99, 0) AS INT) > @warm
						THEN 'hot'
					WHEN cast(isnull((ls.currentscore / nullif(@maxScore, 0.00)) * 99, 0) AS INT) BETWEEN @cold
							AND @warm
						THEN 'warm'
					ELSE 'cold'
					END
				) AS [ThresholdColor]
		FROM leadinteractionhistory(NOLOCK) lih
		     
		INNER JOIN followup_status(NOLOCK) fs ON lih.followupstatus = fs.id
		INNER JOIN userleads(NOLOCK) ul ON lih.leadno = ul.leadno
			AND ul.parentid = lih.parentid
		LEFT JOIN lead_score_history_latest(NOLOCK) ls ON ls.leadid = ul.id
		LEFT JOIN user_detail(NOLOCK) ud ON lih.assignedto = ud.user_id
		-- outer apply dbo.functogetscoredetails(ul.id) f     
		WHERE
		     
		  -- lih.ID in (
		  --                  SELECT max(lihOuter.id)
				--		  FROM leadinteractionhistory(NOLOCK) as lihOuter
				--		  WHERE lihOuter.parentid = lih.parentid
				--		 	AND lihOuter.leadno = lih.leadno
				--			and lihOuter.ParentID = @ParentId 
		  --               )
          --   and    
			

			--lih.IsReassign = case when @CreatedBy <> 0 then 0 else lih.IsReassign end and 
			lih.IsReassign = CASE 
				WHEN @IsReAssign IS NULL
					AND @CreatedBy <> 0
					THEN 0
				WHEN @IsReAssign IS NOT NULL
					THEN @IsReAssign
				ELSE lih.IsReassign
				END
			AND
			/*lih.id =  (
			select max(id) from leadinteractionhistory(nolock) where parentid = lih.parentid and leadno = lih.leadno
		)*/
			lih.id = CASE 
				WHEN isnull(@CreatedFromDate, '1900-01-01') > '1900-01-01'
					THEN lih.id
				ELSE (
						SELECT max(lihinner.id)
						FROM leadinteractionhistory(NOLOCK) as lihInner
						WHERE lihinner.parentid = lih.parentid
							AND lihinner.leadno = lih.leadno
						)
				END
			AND ul.parentid = @ParentId
			and lih.ParentID =  @ParentId
			/*and 1 = (case when isnull(@FollowUpType, 0) = 0 and fs.IsCallback = 1 then 1 
				when isnull(@FollowUpType, 0) > 0 and lih.FollowUpStatus = @FollowUpType then 1
			else 0 end )*/
			AND 1 = (
				CASE 
				    /*  
					  WHEN isnull(@FollowUpType, 0) = 0
						AND @NoFollowUp = 1
						AND @Scheduled = 1
						AND @DueToday = 1
						AND @Overdue = 1
						THEN 1
                    */ 
					when @flpIDsCount = 0
					    AND @NoFollowUp = 1
						AND @Scheduled = 1
						AND @DueToday = 1
						AND @Overdue = 1
						THEN 1 
					/*
				 	  WHEN isnull(@FollowUpType, 0) = 0
						AND fs.IsCallback = 1
						THEN 1
                    */  
					when @flpIDsCount = 0
					   AND fs.IsCallback = 1
					  THEN 1  
                    /*   
					  WHEN isnull(@FollowUpType, 0) > 0
						AND lih.FollowUpStatus = @FollowUpType
						THEN 1
                     */
                    WHEN @flpIDsCount > 0
						AND lih.FollowUpStatus in ( select value from fn_Split(@FollowUpType,',') )
						THEN 1
					ELSE 0
					END
				)
			AND 1 = (
				CASE 
					WHEN @isadmin = 1
						THEN 1
					WHEN isnull(ul.AssignedTo, 0) IN (
							SELECT [value]
							FROM dbo.fn_Split(@UserIdTeamLst, ',')
							)
						THEN 1
					WHEN isnull(ul.AssignedTo, 0) = @UserId
						THEN 1
					ELSE 0
					END
				)
			AND 1 = (
				CASE 
					WHEN isnull(@AssignedTo, 0) = 0
						THEN 1
					WHEN isnull(@AssignedTo, 0) > 0
						AND lih.AssignedTo = @AssignedTo
						THEN 1
					ELSE 0
					END
				)
			AND 1 = (
				CASE 
					WHEN isnull(@CreatedBy, 0) = 0
						THEN 1
					WHEN isnull(@CreatedBy, 0) > 0
						AND lih.CreatedBy = @CreatedBy
						THEN 1
					ELSE 0
					END
				)
			AND 1 = iif(Isnull(@NextStatusFromDate, '') <> ''
				AND Isnull(@NextStatusToDate, '') <> '', iif(CAST(TRY_CONVERT(DATETIME, lih.FollowupDate) AS DATE) BETWEEN cast(@NextStatusFromDate AS DATE)
						AND cast(@NextStatusToDate AS DATE)
							,1
							,0), 1)
			AND 1 = iif(Isnull(@CreatedFromDate, '') <> ''
				AND Isnull(@CreatedToDate, '') <> '', iif(CAST(TRY_CONVERT(DATETIME, lih.CreatedOn) AS DATE) BETWEEN cast(@CreatedFromDate AS DATE)
						AND cast(@CreatedToDate AS DATE)
							,1
							,0), 1)
			AND 1 = (
				CASE 
					WHEN isnull(@LeadId, 0) = 0
						THEN 1
					WHEN isnull(@LeadId, 0) > 0
						AND @LeadId = ul.ID
						THEN 1
					ELSE 0
					END
				)
			AND 1 = (
				CASE 
					WHEN isnull(@Remarks, '') = ''
						THEN 1
					WHEN isnull(@Remarks, '') <> ''
						AND lih.Remarks LIKE '%' + @Remarks + '%'
						THEN 1
					ELSE 0
					END
				)
			AND 1 = (
				CASE 
					/*
					 WHEN isnull(@FollowUpType, 0) > 0
					  AND fs.IsConvert = 1
					   THEN 1
                    */
					WHEN @flpIDsCount > 0
					  AND fs.IsConvert = 1
					   THEN 1

					WHEN Isnull(@NextStatusFromDate, '') = ''
						AND Isnull(@NextStatusToDate, '') = ''
						AND fs.IsConvert = 1
						THEN 0
					ELSE 1
					END
				)
		) AS fu
	WHERE 1 = (
			CASE 
				WHEN followupdatestatus = 'overdue'
					AND @Overdue = 1
					THEN 1
				WHEN followupdatestatus = 'duetoday'
					AND @DueToday = 1
					THEN 1
				WHEN followupdatestatus = 'scheduled'
					AND @Scheduled = 1
					THEN 1
				WHEN followupdatestatus = 'nofollowup'
					AND @NoFollowUp = 1
					THEN 1
				ELSE 0
				END
			)
	ORDER BY orderseq
		,cast(nextstatusdate AS DATETIME) offset @OffsetValue rows

	FETCH NEXT @PagingSize rows ONLY

	EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @UserId
		,@Activity_type = 'View_flwup'
		,@ActionType = 'F'
		,@RowJson = ''
		,@Table_name = 'leadinteractionhistory'
END



GO

/* ============================================================
   Procedure: [dbo].[usp_GetFollowUpListByUserId_withScoreCard_withSegment]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


--exec usp_GetFollowUpListByUserId_withScoreCard @OffsetValue=0,@PagingSize=300,@UserId=39042,@FollowUpType=0,@NextStatusFromDate=N'01-Jan-1900',@NextStatusToDate=N'18-Apr-2022',@CreatedFromDate=N'',@CreatedToDate=N'',@LeadId=N'',@Remarks=N'',@Overdue=1,@DueToday=0,@Scheduled=0,@NoFollowUp=0,@AssignedTo=0,@CreatedBy=0
--exec usp_GetFollowUpListByUserId_withScoreCard @OffsetValue=0,@PagingSize=100,@UserId=36950,@FollowUpType=0,@NextStatusFromDate=N'',@NextStatusToDate=N'',@CreatedFromDate=N'',@CreatedToDate=N'',@LeadId=N'',@Remarks=N'',@Overdue=1,@DueToday=1,@Scheduled=1,@NoFollowUp=1,@AssignedTo=0,@CreatedBy=0
--exec usp_GetFollowUpListByUserId_withScoreCard$ @OffsetValue=0,@PagingSize=100,@UserId=39680,@FollowUpType=0,@NextStatusFromDate=N'',@NextStatusToDate=N'',@CreatedFromDate=N'11-May-2022 00:00:00',@CreatedToDate=N'12-May-2022 00:00:00', @LeadId=N'', @Remarks=N'', @Overdue=1, @DueToday=1, @Scheduled=1, @NoFollowUp=1,@AssignedTo=0,@CreatedBy=0, @IsReAssign=0

CREATE   PROCEDURE [dbo].[usp_GetFollowUpListByUserId_withScoreCard_withSegment]
  (
	@OffsetValue INT = 0
	,@PagingSize INT = 20
	,@UserId BIGINT
	--,@FollowUpType INT = 0
	,@FollowUpType nvarchar(max) = '0'
	,@NextStatusFromDate DATETIME = NULL
	,@NextStatusToDate DATETIME = NULL
	,@CreatedFromDate DATETIME = NULL
	,@CreatedToDate DATETIME = NULL
	,@LeadId BIGINT = NULL
	,@Remarks NVARCHAR(500) = ''
	,@Overdue BIT = 1
	,@DueToday BIT = 1
	,@Scheduled BIT = 1
	,@NoFollowUp BIT = 1
	,@AssignedTo BIGINT = 0
	,@CreatedBy BIGINT = 0
	,@IsReAssign BIT = NULL
	,@CriteriaName nvarchar(500) = null 
	)
AS
BEGIN
	--declare @OffsetValue int=0, @PagingSize int = 100, @UserId bigint = 39042, @FollowUpType int = 0, @NextStatusFromDate datetime = N'', @NextStatusToDate datetime = N'', @CreatedFromDate datetime = N'', @CreatedToDate datetime = N'', @LeadId bigint = N'', @Remarks nvarchar(500) = N'', @Overdue bit = 1, @DueToday bit= 1, @Scheduled bit = 1, @NoFollowUp bit = 1, @AssignedTo bigint = 0, @CreatedBy bigint = 0
	--declare @OffsetValue int=0, @PagingSize int = 100, @UserId bigint = 35610, @FollowUpType int = 0, @NextStatusFromDate datetime = N'', @NextStatusToDate datetime = N'', @CreatedFromDate datetime = N'', @CreatedToDate datetime = N'', @LeadId bigint = N'', @Remarks nvarchar(500) = N'', @Overdue bit = 1, @DueToday bit= 1, @Scheduled bit = 1, @NoFollowUp bit = 1, @AssignedTo bigint = 0, @CreatedBy bigint = 0
	--declare @OffsetValue int = 0,@PagingSize int = 100,@UserId bigint=36950,@FollowUpType int = 0,@NextStatusFromDate datetime = N'',@NextStatusToDate datetime = N'',@CreatedFromDate datetime = N'',@CreatedToDate datetime = N'',@LeadId bigint = N'',@Remarks nvarchar(500) = '',@Overdue bit = 1,@DueToday bit = 1,@Scheduled bit = 1,@NoFollowUp bit = 1,@AssignedTo bigint = 0,@CreatedBy bigint = 0
	--declare @OffsetValue int=0,@PagingSize int=100,@UserId bigint=39680,@FollowUpType int=0,@NextStatusFromDate datetime=N'',@NextStatusToDate datetime=N'',@CreatedFromDate datetime=N'09-May-2022 00:00:00',@CreatedToDate datetime=N'10-May-2022 00:00:00',@LeadId bigint=N'',@Remarks nvarchar(500)=N'',@Overdue bit=1,@DueToday bit=1,@Scheduled bit=1,@NoFollowUp bit=1,@AssignedTo bigint=0,@CreatedBy bigint=40062
	--declare @OffsetValue int=0,@PagingSize int=100,@UserId bigint=39680,@FollowUpType int=0,@NextStatusFromDate datetime=N'',@NextStatusToDate datetime=N'',@CreatedFromDate datetime=N'09-May-2022 00:00:00',@CreatedToDate datetime=N'10-May-2022 00:00:00',@LeadId bigint=N'',@Remarks nvarchar(500)=N'',@Overdue bit=1,@DueToday bit=1,@Scheduled bit=1,@NoFollowUp bit=1,@AssignedTo bigint=0,@CreatedBy bigint=40061
	--declare @OffsetValue int=0,@PagingSize int=100,@UserId bigint=40058,@FollowUpType int=461,@NextStatusFromDate datetime=N'',@NextStatusToDate datetime=N'',@CreatedFromDate datetime=N'01-Jun-2022 12:30:00',@CreatedToDate datetime=N'03-Jun-2022 12:30:00',@LeadId bigint=N'',@Remarks nvarchar(500)=N'',@Overdue bit=1,@DueToday bit=1,@Scheduled bit=1,@NoFollowUp bit=1,@AssignedTo bigint=0,@CreatedBy bigint=40058, @IsReAssign bit=0

	--declare @OffsetValue int=0,@PagingSize int=100,@UserId bigint=34594,@FollowUpType int=0,@NextStatusFromDate datetime=N'',@NextStatusToDate datetime=N'',@CreatedFromDate datetime=N'',@CreatedToDate datetime=N'',@LeadId bigint=N'',@Remarks nvarchar(500)=N'',@Overdue bit=1,@DueToday bit=1,@Scheduled bit=1,@NoFollowUp bit=1,@AssignedTo bigint=0,@CreatedBy bigint=0, @IsReAssign bit=0, @CriteriaName nvarchar(500) = N'' 
	

	  if( trim(isnull(@CriteriaName,''))  = '')
	    begin
		   exec  usp_GetFollowUpListByUserId_withScoreCard @OffsetValue,@PagingSize,@UserId,@FollowUpType,@NextStatusFromDate,@NextStatusToDate   
		              , @CreatedFromDate,@CreatedToDate,@LeadId,@Remarks,@Overdue,@DueToday, @Scheduled,@NoFollowUp,@AssignedTo,@CreatedBy,
					  @IsReAssign
			   return		   
		end

		
		if(year(@NextStatusToDate) = '1900')
		  begin
              set @NextStatusToDate = CAST('31-Dec-2123' as date)    
		  end

        if(year(@CreatedToDate) = '1900')
		  begin
              set @CreatedToDate = CAST('31-Dec-2123' as date)    
		  end
     


	DECLARE @IsCallback INT = 0;
	DECLARE @IsConvert INT = 0;
	DECLARE @FollowUpName VARCHAR = '';

	/*
	SELECT @IsCallback = IsCallback
		,@IsConvert = IsConvert
	FROM FollowUp_Status(NOLOCK)
	WHERE Id = @FollowUpType
	*/

	Declare @flpIDsCount int = 0;
	set @flpIDsCount = isnull((select count(value) from fn_Split(@FollowUpType,',') where isnull(value,0) <> 0),0);


	DECLARE @ParentId BIGINT = 0
		,@IsAdmin BIT = 0
	DECLARE @tbluser TABLE (
		User_ID BIGINT
		,Name VARCHAR(100)
		,IMAGE VARCHAR(100)
		)

	SELECT @IsAdmin = IsAdmin
		,@ParentId = ParentID
	FROM User_Detail(NOLOCK)
	WHERE User_ID = @UserId
	

	/*
    declare @LeadCount int =  (select count(1) from Userleads(nolock) where ParentID = @ParentID)  
    
	declare @ProcParam nvarchar(max) = N''' set nocount on ; exec Usp_ViewLeadDetailsBySearchCriteria_IDSegment 1,'+cast(@LeadCount as nvarchar(100))+',''''' + @Criterianame + ''''',' + cast(@UserID as nvarchar(50)) + ',0,''''Name''''  
    WITH RESULT SETS  
	 (  
	   (  
	  ID bigint  
	   )  
	 )'''   
      
 -- print @ProcParam  


    declare @QueryTotality nvarchar(max) = concat( N' SELECT ID into #userleadsBySegment    
     FROM    
      OPENROWSET(''sqlncli11'',''Server=10.0.0.132;Database=mysms_dev;Uid=kit19;PWD=P@ssword3110;'',', @ProcParam , ')' ) 
	 
	 */


	 declare @SPID bigint = isnull((select @@SPID),0)
     delete from [tbl_LeadID_WithSPID] where SP_ID = @SPID  
	
	 drop table if exists  #userleadsBySegment 
    
     declare @LeadCount int =  (select count(1) from Userleads(nolock) where ParentID = @ParentID)

	  exec Usp_ViewLeadDetailsBySearchCriteria_IDSegment_SPID 1,@LeadCount,@Criterianame,@UserID ,0,'Name'
      select LeadID as ID into #userleadsBySegment from tbl_LeadID_WithSPID with(nolock) where SP_ID = @SPID
	 
	 delete from [tbl_LeadID_WithSPID] where SP_ID = @SPID
	  
     declare @QueryTotality nvarchar(max) = ''





	/*
	declare @ProcParam nvarchar(max) = N''' set nocount on ; exec mysms_dev.dbo.Usp_ViewLeadDetailsBySearchCriteria_IDSegment 1,'+cast(@LeadCount as nvarchar(100))+',''''' + @Criterianame + ''''',' + cast(@UserID as nvarchar(50)) + ',0,''''Name''''  
    WITH RESULT SETS  
	 (  
	   (  
	  ID bigint  
	   )  
	 )'''   
    
      
   -- print @ProcParam  
  
    declare @QueryTotality nvarchar(max) = N' SELECT ID into #userleadsBySegment     
       FROM    
         OPENQUERY([20.244.133.86],' + @ProcParam + ')' 

    */



	DECLARE @TeamCode VARCHAR(10) = ''
	DECLARE @ScopeCode VARCHAR(10) = ''
	DECLARE @UserIdTeamLst VARCHAR(Max) = ''
	DECLARE @UserLoginTeamLst VARCHAR(Max) = ''

	--select @TeamCode = TeamCode, @ScopeCode = ScopeCode, @UserIdTeamLst = UserIdTeamLst, @UserLoginTeamLst = UserLoginTeamLst from dbo.ufn_GetUserRoleScope(@UserId)   
	INSERT INTO @tbluser
	EXEC Use_GetUserDetails @UserId

	SELECT @UserIdTeamLst = isnull(STRING_AGG(User_ID, ','), '')
	FROM @tbluser

	-- select @TeamCode TeamCode, @ScopeCode ScopeCode, @UserIdTeamLst UserIdTeamLst, @UserLoginTeamLst UserLoginTeamLst     
	DECLARE @maxScore NUMERIC(18, 2) = isnull((
				SELECT (max(currentscore) * 100) / 99
				FROM lead_score_history(NOLOCK) e
				WHERE parentid = @ParentId
				), 0)
	DECLARE @hot INT
		,@warm INT
		,@cold INT

	SELECT @hot = hot
		,@warm = warm
		,@cold = cold
	FROM lead_cateogy_thresholds(NOLOCK)
	WHERE parentid = @ParentID

	IF @hot IS NULL
	BEGIN
		SELECT @hot = hot
			,@warm = warm
			,@cold = cold
		FROM lead_cateogy_thresholds(NOLOCK)
		WHERE parentid = 0
	END

	PRINT @FollowUpType

   Declare @QuerySection nvarchar(max) =  Concat( @QueryTotality ,' ; ',N'SELECT count(id) OVER () AS TotalRow
		,*
	FROM (
		SELECT lih.ID
			,fs.followupstatus AS Title			
			,fs.IsConvert as [IsConvert]
			,lih.remarks AS Discription
			,lih.followupdate AS NextStatusDate
			,lih.CreatedOn
			,lih.AmountPaid
			,ul.id AS LeadId
			,iif(isnull(ltrim(rtrim(ul.mobileno)), '''') <> '''', CONCAT (
					ul.countrycode
					,'' ''
					,ul.mobileno
					), '''') AS MobileNo
			,iif(isnull(ltrim(rtrim(ul.mobileno2)), '''') <> '''', CONCAT (
					ul.countrycode2
					,'' ''
					,ul.mobileno2
					), '''') AS MobileNo2
			,iif(isnull(ltrim(rtrim(ul.mobileno1)), '''') <> '''', CONCAT (
					ul.countrycode1
					,'' ''
					,ul.mobileno1
					), '''') AS MobileNo1
			,ul.PersonName
			,ul.ProfileImgFileName
			,iif(ul.assignedto = ', cast(@UserId as nvarchar(50)) ,'
				OR 1 = ', cast(@IsAdmin as nvarchar(10)) ,', 1, 0) AS [IsUIActive]
			,lih.assignedto
			,ltrim(rtrim(CONCAT (
						ud.fname
						,'' ''
						,ud.lname
						))) AS [Owner]
			,'''' AS [Status]
			,ud.parentid AS [ParentId]
			,(
				CASE 
					WHEN cast(lih.followupdate AS DATE) = cast(getdate() AS DATE)
						THEN 0
					WHEN cast(lih.followupdate AS DATE) < cast(getdate() AS DATE)
						THEN 1
					WHEN cast(lih.followupdate AS DATE) > cast(getdate() AS DATE)
						THEN 2
					WHEN cast(lih.followupdate AS DATE) IS NULL
						THEN 3
					END
				) AS [OrderSeq]
			,(
				CASE 
					WHEN cast(lih.followupdate AS DATE) = cast(getdate() AS DATE)
						THEN ''duetoday''
					WHEN cast(lih.followupdate AS DATE) < cast(getdate() AS DATE)
						THEN ''overdue''
					WHEN cast(lih.followupdate AS DATE) > cast(getdate() AS DATE)
						THEN ''scheduled''
					WHEN cast(lih.followupdate AS DATE) IS NULL
						THEN ''nofollowup''
					END
				) AS [FollowupDateStatus]
			,(
				CASE 
					WHEN ls.scoreadded > 0
						THEN ''green_up''
					WHEN ls.scoreadded < 0
						THEN ''red_down''
					ELSE ''''
					END
				) AS [Profit_Loss]
			,cast(isnull((ls.currentscore / nullif(', cast(@maxScore as nvarchar), ', 0.00)) * 99, 0) AS INT) AS [CurrentScore]
			,(
				CASE 
					WHEN cast(isnull((ls.currentscore / nullif(', cast(@maxScore as nvarchar), ', 0.00)) * 99, 0) AS INT) > ',cast(@warm as nvarchar(50)) ,'
						THEN ''hot''
					WHEN cast(isnull((ls.currentscore / nullif(', cast(@maxScore as nvarchar), ', 0.00)) * 99, 0) AS INT) BETWEEN ',cast(@cold as nvarchar(50)),'
							AND ',cast(@warm as nvarchar(50)) ,'
						THEN ''warm''
					ELSE ''cold''
					END
				) AS [ThresholdColor]
		FROM leadinteractionhistory(NOLOCK) lih
		     
		INNER JOIN followup_status(NOLOCK) fs ON lih.followupstatus = fs.id
		INNER JOIN userleads(NOLOCK) ul ON lih.leadno = ul.leadno
			AND ul.parentid = lih.parentid
        inner join #userleadsBySegment as uls on ul.ID = uls.ID        
		LEFT JOIN lead_score_history_latest(NOLOCK) ls ON ls.leadid = ul.id
		LEFT JOIN user_detail(NOLOCK) ud ON lih.assignedto = ud.user_id
		WHERE
			lih.IsReassign = CASE 
				WHEN ' , cast( isnull(@IsReAssign, '0') as nvarchar(10)) ,' = 0  --IS NULL
					AND ', cast(@CreatedBy as nvarchar(50)) ,' <> 0
					THEN 0
				WHEN ', cast( isnull(@IsReAssign,'0') as nvarchar(10)) ,' <> 0  --IS NOT NULL
					THEN ', cast( isnull(@IsReAssign, '0') as nvarchar(10)) ,'
				ELSE lih.IsReassign
				END
			AND

			lih.id = CASE 
				WHEN isnull(''', cast(@CreatedFromDate as nvarchar(50)) ,''', ''1900-01-01'') > ''1900-01-01''
					THEN lih.id
				ELSE (
						SELECT max(lihinner.id)
						FROM leadinteractionhistory(NOLOCK) as lihInner
						WHERE lihinner.parentid = lih.parentid
							AND lihinner.leadno = lih.leadno
						)
				END
			AND ul.parentid = ', cast(@ParentId as nvarchar(50)) ,'
			and lih.ParentID =  ', cast(@ParentId as nvarchar(50)) ,'
			AND 1 = (
				   CASE 
					   WHEN ', cast(@flpIDsCount as nvarchar(50) ) , ' = 0
						AND ', cast( @NoFollowUp as nvarchar ) ,' = 1
						AND ', cast(  @Scheduled as nvarchar ) ,' = 1
						AND ', cast( @DueToday as nvarchar ) ,' = 1
						AND ', cast( @Overdue as nvarchar ) ,' = 1
						THEN 1
					WHEN ', cast(@flpIDsCount as nvarchar(50) ) , ' = 0
						AND fs.IsCallback = 1
						THEN 1
					WHEN ', cast(@flpIDsCount as nvarchar(50) ) , ' > 0
						AND lih.FollowUpStatus in ( select value from fn_Split(''', @FollowUpType ,''','','') )
						THEN 1
					ELSE 0
					END
				)
			AND 1 = (
				CASE 
					WHEN ', cast(@isadmin as nvarchar) ,' = 1
						THEN 1
					WHEN isnull(ul.AssignedTo, 0) IN (
							SELECT [value]
							FROM dbo.fn_Split(''', cast(@UserIdTeamLst as nvarchar) ,''','','')
							)
						THEN 1
					WHEN isnull(ul.AssignedTo, 0) = ',cast(@UserId  as nvarchar) , '
						THEN 1
					ELSE 0
					END
				)
			AND 1 = (
				CASE 
					WHEN isnull(', cast(@AssignedTo as nvarchar(50)) , ', 0) = 0
						THEN 1
					WHEN isnull(', cast(@AssignedTo as nvarchar(50)) , ', 0) > 0
						AND lih.AssignedTo = ', cast(@AssignedTo as nvarchar(50)) , '
						THEN 1
					ELSE 0
					END
				)
			AND 1 = (
				CASE 
					WHEN isnull(', cast( @CreatedBy as nvarchar(50)) , ', 0) = 0
						THEN 1
					WHEN isnull(', cast( @CreatedBy as nvarchar(50)) , ', 0) > 0
						AND lih.CreatedBy = ', cast( @CreatedBy as nvarchar(50)) , '
						THEN 1
					ELSE 0
					END
				)
			AND 1 = iif(Isnull( ''' , @NextStatusFromDate , ''', '''') <> ''''
				AND Isnull( ''',  @NextStatusToDate , ''', '''') <> '''', iif(CAST(TRY_CONVERT(DATETIME, isnull(lih.FollowupDate,cast( ''', @NextStatusFromDate ,''' AS DATE))) AS DATE) BETWEEN cast( ''', @NextStatusFromDate ,''' AS DATE)
						AND cast(''', @NextStatusToDate  ,''' AS DATE)
							,1
							,0), 1)
			AND 1 = iif(Isnull(''', @CreatedFromDate  ,''', '''') <> ''''
				AND Isnull(''', @CreatedToDate  ,''', '''') <> '''', iif(CAST(TRY_CONVERT(DATETIME, lih.CreatedOn) AS DATE) BETWEEN cast(''', @CreatedFromDate , ''' AS DATE)
						AND cast(''', @CreatedToDate ,''' AS DATE)
							,1
							,0), 1)
			AND 1 = (
				CASE 
					WHEN isnull(',cast(@LeadId as nvarchar(50)),', 0) = 0
						THEN 1
					WHEN isnull(',cast(@LeadId as nvarchar(50)),', 0) > 0
						AND ',cast(@LeadId as nvarchar(50)),' = ul.ID
						THEN 1
					ELSE 0
					END
				)
			AND 1 = (
				CASE 
					WHEN isnull(''', @Remarks, ''', '''') = ''''
						THEN 1
					WHEN isnull(''', @Remarks, ''', '''') <> ''''
						AND lih.Remarks LIKE ''%' , @Remarks , '%''
						THEN 1
					ELSE 0
					END
				)
			AND 1 = (
				CASE 
					WHEN ', cast(@flpIDsCount as nvarchar(50) ) ,' > 0
						AND fs.IsConvert = 1
						THEN 1
					WHEN Isnull(''', cast(@NextStatusFromDate as nvarchar) ,''', '''') = ''''
						AND Isnull(''', cast(@NextStatusToDate as nvarchar) ,''', '''') = ''''
						AND fs.IsConvert = 1
						THEN 0
					ELSE 1
					END
				)
		) AS fu
	WHERE 1 = (
			CASE
				WHEN IsConvert = 1 THEN 1
				WHEN followupdatestatus = ''overdue''
					AND ',cast(@Overdue as nvarchar) ,' = 1
					THEN 1
				WHEN followupdatestatus = ''duetoday''
					AND ',cast( @DueToday as nvarchar) ,' = 1
					THEN 1
				WHEN followupdatestatus = ''scheduled''
					AND ',cast( @Scheduled as nvarchar) ,' = 1
					THEN 1
				WHEN followupdatestatus = ''nofollowup''
					AND ',cast( @NoFollowUp as nvarchar) ,' = 1
					THEN 1
				ELSE 0
				END
			)
	ORDER BY orderseq
		,cast(nextstatusdate AS DATETIME) offset ',cast(@OffsetValue as nvarchar) ,' rows

	     FETCH NEXT ', cast( @PagingSize as nvarchar) ,' rows ONLY','')


    print cast( @QuerySection as varchar(max))
	
	exec sp_executeSql  @Querysection

	EXEC MySMSAudit.dbo.Usp_AuditTableDataByParentId @User_id = @UserId
		,@Activity_type = 'View_flwup'
		,@ActionType = 'F'
		,@RowJson = ''
		,@Table_name = 'leadinteractionhistory'

		drop table if exists  #userleadsBySegment 
END



