CREATE   PROCEDURE [dbo].[usp_GetFollowUpListByUserId_withScoreCard_withSegment_JK_optmz]
  (
	@OffsetValue INT = 0
	,@PagingSize INT = 20
	,@UserId BIGINT
	,@FollowUpType nvarchar(max) = '0'
	,@NextStatusFromDate DATETIME = NULL
	,@NextStatusToDate DATETIME = NULL
	,@CreatedFromDate DATETIME = NULL
	,@CreatedToDate DATETIME = NULL
	,@LeadId BIGINT = NULL
	,@Remarks NVARCHAR(500) = ''
	,@Overdue BIT = 1
	,@DueToday BIT = 1
	,@Scheduled BIT = 1
	,@NoFollowUp BIT = 1
	,@AssignedTo BIGINT = 0
	,@CreatedBy BIGINT = 0
	,@IsReAssign BIT = NULL
	,@CriteriaName nvarchar(500) = null
	)
AS
BEGIN

--declare @OffsetValue int=0, @PagingSize int = 100, @UserId bigint = 39042, @FollowUpType int = 0, @NextStatusFromDate datetime = N'', @NextStatusToDate datetime = N'', @CreatedFromDate datetime = N'', @CreatedToDate datetime = N'', @LeadId bigint = N'', @Remarks nvarchar(500) = N'', @Overdue bit = 1, @DueToday bit= 1, @Scheduled bit = 1, @NoFollowUp bit = 1, @AssignedTo bigint = 0, @CreatedBy bigint = 0
	--declare @OffsetValue int=0, @PagingSize int = 100, @UserId bigint = 35610, @FollowUpType int = 0, @NextStatusFromDate datetime = N'', @NextStatusToDate datetime = N'', @CreatedFromDate datetime = N'', @CreatedToDate datetime = N'', @LeadId bigint = N'', @Remarks nvarchar(500) = N'', @Overdue bit = 1, @DueToday bit= 1, @Scheduled bit = 1, @NoFollowUp bit = 1, @AssignedTo bigint = 0, @CreatedBy bigint = 0
	--declare @OffsetValue int = 0,@PagingSize int = 100,@UserId bigint=36950,@FollowUpType int = 0,@NextStatusFromDate datetime = N'',@NextStatusToDate datetime = N'',@CreatedFromDate datetime = N'',@CreatedToDate datetime = N'',@LeadId bigint = N'',@Remarks nvarchar(500) = '',@Overdue bit = 1,@DueToday bit = 1,@Scheduled bit = 1,@NoFollowUp bit = 1,@AssignedTo bigint = 0,@CreatedBy bigint = 0
	--declare @OffsetValue int=0,@PagingSize int=100,@UserId bigint=39680,@FollowUpType int=0,@NextStatusFromDate datetime=N'',@NextStatusToDate datetime=N'',@CreatedFromDate datetime=N'09-May-2022 00:00:00',@CreatedToDate datetime=N'10-May-2022 00:00:00',@LeadId bigint=N'',@Remarks nvarchar(500)=N'',@Overdue bit=1,@DueToday bit=1,@Scheduled bit=1,@NoFollowUp bit=1,@AssignedTo bigint=0,@CreatedBy bigint=40062
	--declare @OffsetValue int=0,@PagingSize int=100,@UserId bigint=39680,@FollowUpType int=0,@NextStatusFromDate datetime=N'',@NextStatusToDate datetime=N'',@CreatedFromDate datetime=N'09-May-2022 00:00:00',@CreatedToDate datetime=N'10-May-2022 00:00:00',@LeadId bigint=N'',@Remarks nvarchar(500)=N'',@Overdue bit=1,@DueToday bit=1,@Scheduled bit=1,@NoFollowUp bit=1,@AssignedTo bigint=0,@CreatedBy bigint=40061
	--declare @OffsetValue int=0,@PagingSize int=100,@UserId bigint=40058,@FollowUpType int=461,@NextStatusFromDate datetime=N'',@NextStatusToDate datetime=N'',@CreatedFromDate datetime=N'01-Jun-2022 12:30:00',@CreatedToDate datetime=N'03-Jun-2022 12:30:00',@LeadId bigint=N'',@Remarks nvarchar(500)=N'',@Overdue bit=1,@DueToday bit=1,@Scheduled bit=1,@NoFollowUp bit=1,@AssignedTo bigint=0,@CreatedBy bigint=40058, @IsReAssign bit=0

	--declare @OffsetValue int=0,@PagingSize int=100,@UserId bigint=34594,@FollowUpType int=0,@NextStatusFromDate datetime=N'',@NextStatusToDate datetime=N'',@CreatedFromDate datetime=N'',@CreatedToDate datetime=N'',@LeadId bigint=N'',@Remarks nvarchar(500)=N'',@Overdue bit=1,@DueToday bit=1,@Scheduled bit=1,@NoFollowUp bit=1,@AssignedTo bigint=0,@CreatedBy bigint=0, @IsReAssign bit=0, @CriteriaName nvarchar(500) = N'' 

	  if( trim(isnull(@CriteriaName,''))  = '')
	    begin
		   exec  usp_GetFollowUpListByUserId_withScoreCard_JK_optmz_v2 @OffsetValue,@PagingSize,@UserId,@FollowUpType,@NextStatusFromDate,@NextStatusToDate
		              , @CreatedFromDate,@CreatedToDate,@LeadId,@Remarks,@Overdue,@DueToday, @Scheduled,@NoFollowUp,@AssignedTo,@CreatedBy,
					  @IsReAssign
			   return
		end

		if(year(@NextStatusToDate) = '1900')
		  begin
              set @NextStatusToDate = CAST('31-Dec-2123' as date)
		  end

        if(year(@CreatedToDate) = '1900')
		  begin
              set @CreatedToDate = CAST('31-Dec-2123' as date)
		  end

	DECLARE @IsCallback INT = 0;
	DECLARE @IsConvert INT = 0;
	DECLARE @FollowUpName VARCHAR = '';

	Declare @flpIDsCount int = 0;
	set @flpIDsCount = isnull((select count(value) from fn_Split(@FollowUpType,',') where isnull(value,0) <> 0),0);

	DECLARE @ParentId BIGINT = 0
		,@IsAdmin BIT = 0
	DECLARE @tbluser TABLE (
		User_ID BIGINT
		,Name VARCHAR(100)
		,IMAGE VARCHAR(100)
		)

	SELECT @IsAdmin = IsAdmin
		,@ParentId = ParentID
	FROM User_Detail(NOLOCK)
	WHERE User_ID = @UserId

	 declare @SPID bigint = isnull((select @@SPID),0)
     delete from [tbl_LeadID_WithSPID] where SP_ID = @SPID

	 drop table if exists  #userleadsBySegment

     declare @LeadCount int =  (select count(1) from Userleads(nolock) where ParentID = @ParentID)

	  exec Usp_ViewLeadDetailsBySearchCriteria_IDSegment_SPID 1,@LeadCount,@Criterianame,@UserID ,0,'Name'
      select LeadID as ID into #userleadsBySegment from tbl_LeadID_WithSPID with(nolock) where SP_ID = @SPID

	  CREATE UNIQUE CLUSTERED INDEX CX_userleadsBySegment_ID ON #userleadsBySegment(ID);

	 delete from [tbl_LeadID_WithSPID] where SP_ID = @SPID

     declare @QueryTotality nvarchar(max) = ''

	DECLARE @TeamCode VARCHAR(10) = ''
	DECLARE @ScopeCode VARCHAR(10) = ''
	DECLARE @UserIdTeamLst VARCHAR(Max) = ''
	DECLARE @UserLoginTeamLst VARCHAR(Max) = ''

	INSERT INTO @tbluser
	EXEC Use_GetUserDetails @UserId

	SELECT @UserIdTeamLst = isnull(STRING_AGG(User_ID, ','), '')
	FROM @tbluser

	DECLARE @maxScore NUMERIC(18, 2) = isnull((
				SELECT (max(currentscore) * 100) / 99
				FROM lead_score_history(NOLOCK) e
				WHERE parentid = @ParentId
				), 0)
	DECLARE @hot INT
		,@warm INT
		,@cold INT

	SELECT @hot = hot
		,@warm = warm
		,@cold = cold
	FROM lead_cateogy_thresholds(NOLOCK)
	WHERE parentid = @ParentID

	IF @hot IS NULL
	BEGIN
		SELECT @hot = hot
			,@warm = warm
			,@cold = cold
		FROM lead_cateogy_thresholds(NOLOCK)
		WHERE parentid = 0
	END

	PRINT @FollowUpType

   Declare @QuerySection nvarchar(max) =  Concat( @QueryTotality ,' ; ',N'SELECT count(id) OVER () AS TotalRow
		,*
	FROM (
		SELECT lih.ID
			,fs.followupstatus AS Title
			,fs.IsConvert as [IsConvert]
			,lih.remarks AS Discription
			,lih.followupdate AS NextStatusDate
			,lih.CreatedOn
			,lih.AmountPaid
			,ul.id AS LeadId
			,iif(isnull(ltrim(rtrim(ul.mobileno)), '''') <> '''', CONCAT (
					ul.countrycode
					,'' ''
					,ul.mobileno
					), '''') AS MobileNo
			,iif(isnull(ltrim(rtrim(ul.mobileno2)), '''') <> '''', CONCAT (
					ul.countrycode2
					,'' ''
					,ul.mobileno2
					), '''') AS MobileNo2
			,iif(isnull(ltrim(rtrim(ul.mobileno1)), '''') <> '''', CONCAT (
					ul.countrycode1
					,'' ''
					,ul.mobileno1
					), '''') AS MobileNo1
			,ul.PersonName
			,ul.ProfileImgFileName
			,iif(ul.assignedto = ', cast(@UserId as nvarchar(50)) ,'
				OR 1 = ', cast(@IsAdmin as nvarchar(10)) ,', 1, 0) AS [IsUIActive]
			,lih.assignedto
			,ltrim(rtrim(CONCAT (
						ud.fname
						,'' ''
						,ud.lname
						))) AS [Owner]
			,'''' AS [Status]
			,ud.parentid AS [ParentId]
			,(
				CASE
					WHEN cast(lih.followupdate AS DATE) = cast(getdate() AS DATE)
						THEN 0
					WHEN cast(lih.followupdate AS DATE) < cast(getdate() AS DATE)
						THEN 1
					WHEN cast(lih.followupdate AS DATE) > cast(getdate() AS DATE)
						THEN 2
					WHEN cast(lih.followupdate AS DATE) IS NULL
						THEN 3
					END
				) AS [OrderSeq]
			,(
				CASE
					WHEN cast(lih.followupdate AS DATE) = cast(getdate() AS DATE)
						THEN ''duetoday''
					WHEN cast(lih.followupdate AS DATE) < cast(getdate() AS DATE)
						THEN ''overdue''
					WHEN cast(lih.followupdate AS DATE) > cast(getdate() AS DATE)
						THEN ''scheduled''
					WHEN cast(lih.followupdate AS DATE) IS NULL
						THEN ''nofollowup''
					END
				) AS [FollowupDateStatus]
			,(
				CASE
					WHEN ls.scoreadded > 0
						THEN ''green_up''
					WHEN ls.scoreadded < 0
						THEN ''red_down''
					ELSE ''''
					END
				) AS [Profit_Loss]
			,cast(isnull((ls.currentscore / nullif(', cast(@maxScore as nvarchar), ', 0.00)) * 99, 0) AS INT) AS [CurrentScore]
			,(
				CASE
					WHEN cast(isnull((ls.currentscore / nullif(', cast(@maxScore as nvarchar), ', 0.00)) * 99, 0) AS INT) > ',cast(@warm as nvarchar(50)) ,'
						THEN ''hot''
					WHEN cast(isnull((ls.currentscore / nullif(', cast(@maxScore as nvarchar), ', 0.00)) * 99, 0) AS INT) BETWEEN ',cast(@cold as nvarchar(50)),'
							AND ',cast(@warm as nvarchar(50)) ,'
						THEN ''warm''
					ELSE ''cold''
					END
				) AS [ThresholdColor]
		FROM leadinteractionhistory(NOLOCK) lih

		INNER JOIN followup_status(NOLOCK) fs ON lih.followupstatus = fs.id
		INNER JOIN userleads(NOLOCK) ul ON lih.leadno = ul.leadno
			AND ul.parentid = lih.parentid
        inner join #userleadsBySegment as uls on ul.ID = uls.ID
		LEFT JOIN lead_score_history_latest(NOLOCK) ls ON ls.leadid = ul.id
		LEFT JOIN user_detail(NOLOCK) ud ON lih.assignedto = ud.user_id
		WHERE
			( ', CASE WHEN @IsReAssign IS NULL THEN 'NULL' ELSE CAST(@IsReAssign AS NVARCHAR(10)) END ,' IS NULL OR lih.IsReassign = ', CASE WHEN @IsReAssign IS NULL THEN 'NULL' ELSE CAST(@IsReAssign AS NVARCHAR(10)) END ,' ) AND

			lih.id = CASE
				WHEN isnull(''', cast(@CreatedFromDate as nvarchar(50)) ,''', ''1900-01-01'') > ''1900-01-01''
					THEN lih.id
				ELSE (
						SELECT max(lihinner.id)
						FROM leadinteractionhistory(NOLOCK) as lihInner
						WHERE lihinner.parentid = lih.parentid
							AND lihinner.leadno = lih.leadno
						)
				END
			AND ul.parentid = ', cast(@ParentId as nvarchar(50)) ,'
			and lih.ParentID =  ', cast(@ParentId as nvarchar(50)) ,'
			AND 1 = (
				   CASE
					WHEN ', cast(@flpIDsCount as nvarchar(50) ) , ' = 0
					   WHEN ', cast(@flpIDsCount as nvarchar(50) ) , ' = 0
						AND ', cast( @NoFollowUp as nvarchar ) ,' = 1
						AND ', cast(  @Scheduled as nvarchar ) ,' = 1
						AND ', cast( @DueToday as nvarchar ) ,' = 1
						AND ', cast( @Overdue as nvarchar ) ,' = 1
						THEN 1
					WHEN ', cast(@flpIDsCount as nvarchar(50) ) , ' = 0
						AND fs.IsCallback = 1
						THEN 1
					WHEN ', cast(@flpIDsCount as nvarchar(50) ) , ' > 0
						AND lih.FollowUpStatus in ( select value from fn_Split(''', @FollowUpType ,''','','') )
						THEN 1
					ELSE 0
					END
				)
			AND 1 = (
				CASE
					WHEN ', cast(@isadmin as nvarchar) ,' = 1
						THEN 1
					WHEN isnull(ul.AssignedTo, 0) IN (
							SELECT [value]
							FROM dbo.fn_Split(''', cast(@UserIdTeamLst as nvarchar) ,''','','')
							)
						THEN 1
					WHEN isnull(ul.AssignedTo, 0) = ',cast(@UserId  as nvarchar) , '
						THEN 1
					ELSE 0
					END
				)
			AND 1 = (
				CASE
					WHEN isnull(', cast(@AssignedTo as nvarchar(50)) , ', 0) = 0
						THEN 1
					WHEN isnull(', cast(@AssignedTo as nvarchar(50)) , ', 0) > 0
						AND lih.AssignedTo = ', cast(@AssignedTo as nvarchar(50)) , '
						THEN 1
					ELSE 0
					END
				)
			AND 1 = (
				CASE
					WHEN isnull(', cast( @CreatedBy as nvarchar(50)) , ', 0) = 0
						THEN 1
					WHEN isnull(', cast( @CreatedBy as nvarchar(50)) , ', 0) > 0
						AND lih.CreatedBy = ', cast( @CreatedBy as nvarchar(50)) , '
						THEN 1
					ELSE 0
					END
				)
			AND 1 = iif(Isnull( ''' , @NextStatusFromDate , ''', '''') <> ''''
				AND Isnull( ''',  @NextStatusToDate , ''', '''') <> '''', iif(CAST(TRY_CONVERT(DATETIME, isnull(lih.FollowupDate,cast( ''', @NextStatusFromDate ,''' AS DATE))) AS DATE) BETWEEN cast( ''', @NextStatusFromDate ,''' AS DATE)
						AND cast(''', @NextStatusToDate  ,''' AS DATE)
							,1
							,0), 1)
			AND 1 = iif(Isnull(''', @CreatedFromDate  ,''', '''') <> ''''
				AND Isnull(''', @CreatedToDate  ,''', '''') <> '''', iif(CAST(TRY_CONVERT(DATETIME, lih.CreatedOn) AS DATE) BETWEEN cast(''', @CreatedFromDate , ''' AS DATE)
						AND cast(''', @CreatedToDate ,''' AS DATE)
							,1
							,0), 1)
			AND 1 = (
				CASE
					WHEN isnull(',cast(@LeadId as nvarchar(50)),', 0) = 0
						THEN 1
					WHEN isnull(',cast(@LeadId as nvarchar(50)),', 0) > 0
						AND ',cast(@LeadId as nvarchar(50)),' = ul.ID
						THEN 1
					ELSE 0
					END
				)
			AND 1 = (
				CASE
					WHEN isnull(''', @Remarks, ''', '''') = ''''
						THEN 1
					WHEN isnull(''', @Remarks, ''', '''') <> ''''
						AND lih.Remarks LIKE ''%' , @Remarks , '%''
						THEN 1
					ELSE 0
					END
				)
			AND 1 = (
				CASE
					WHEN ', cast(@flpIDsCount as nvarchar(50) ) ,' > 0
						AND fs.IsConvert = 1
						THEN 1
					WHEN Isnull(''', cast(@NextStatusFromDate as nvarchar) ,''', '''') = ''''
						AND Isnull(''', cast(@NextStatusToDate as nvarchar) ,''', '''') = ''''
						AND fs.IsConvert = 1
						THEN 0
					ELSE 1
					END
				)
		) AS fu
	WHERE 1 = (
			CASE
				WHEN IsConvert = 1 THEN 1
				WHEN followupdatestatus = ''overdue''
					AND ',cast(@Overdue as nvarchar) ,' = 1
					THEN 1
				WHEN followupdatestatus = ''duetoday''
					AND ',cast( @DueToday as nvarchar) ,' = 1
					THEN 1
				WHEN followupdatestatus = ''scheduled''
					AND ',cast( @Scheduled as nvarchar) ,' = 1
					THEN 1
				WHEN followupdatestatus = ''nofollowup''
					AND ',cast( @NoFollowUp as nvarchar) ,' = 1
					THEN 1
				ELSE 0
				END
			)
	ORDER BY orderseq
		,cast(nextstatusdate AS DATETIME) offset ',cast(@OffsetValue as nvarchar) ,' rows

	     FETCH NEXT ', cast( @PagingSize as nvarchar) ,' rows ONLY','')

    print cast( @QuerySection as varchar(max))

	exec sp_executeSql  @Querysection

	EXEC MySMSAudit.dbo.Usp_AuditTableDataByParentId @User_id = @UserId
		,@Activity_type = 'View_flwup'
		,@ActionType = 'F'
		,@RowJson = ''
		,@Table_name = 'leadinteractionhistory'

		drop table if exists  #userleadsBySegment
END




GO

