CREATE   PROCEDURE [dbo].[usp_GetFollowUpListByUserId_withScoreCard_withSegment_KK]
  (
	@OffsetValue INT = 0
	,@PagingSize INT = 20
	,@UserId BIGINT
	--,@FollowUpType INT = 0
	,@FollowUpType nvarchar(max) = '0'
