/* ============================================================
   Procedure: [dbo].[Usp_GetFollowUpStatus_ParentId]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[Usp_GetFollowUpStatus_ParentId]            
(        
	@ParentId bigint = null
)        
AS            
BEGIN
 
	--declare @ParentId bigint = 48296

	SET @ParentId = dbo.ufn_GetUserParentId(@ParentId) -- hardcoded as of now, can be passed as parameter if needed
 
	If(isnull(@ParentId,0) > 0 and not exists (SELECT * FROM FollowUp_status(NOLOCK) FUM WHERE FUM.ParentId = @ParentId))
	Begin
		print 'User followup does not exist'
		Insert into FollowUp_status(FollowupStatus,OrderNumber,IsActive,Intent,IsCallback,IsConvert,IsDisabled,ParentId,CreatedBy,CreatedDate)
		SELECT FollowupStatus,OrderNumber,IsActive,Intent,IsCallback,IsConvert,0 as IsDisabled,@ParentId as ParentId,@ParentId as CreatedBy,getdate() as CreatedDate
		FROM FollowUp_status(NOLOCK) UTM    
		WHERE UTM.ParentId IS NULL AND UTM.IsActive = 1    
		ORDER BY IsDisabled desc, OrderNumber ASC 
	End

	if Exists(select * from FollowUp_Status (nolock)where ParentId = @ParentId)        
	Begin        
		SELECT (Cast(ID as varchar(10)) +','+ Cast(IsCallback as varchar) +','+ Cast(IsConvert as varchar)) FUPValue, fus.ID, fus.FollowupStatus, fus.Intent, OrderNumber, IsCallback, IsConvert, IsDisabled     
		FROM FollowUp_Status (nolock) AS fus         
		WHERE fus.IsActive = 1 and IsDisabled = 0 and fus.ParentId = @ParentId        
		ORDER BY fus.OrderNumber Asc        
	End        
	Else        
	Begin        
		SELECT (Cast(ID as varchar(10)) +','+ Cast(IsCallback as varchar) +','+ Cast(IsConvert as varchar)) FUPValue, fus.ID, fus.FollowupStatus, fus.Intent, OrderNumber, IsCallback, IsConvert, IsDisabled    
		FROM FollowUp_Status (nolock) AS  fus         
		WHERE fus.IsActive = 1 and ParentId is null        
		ORDER BY fus.OrderNumber Asc        
	End        
END     



GO

