  select TRIM(Mail_ID) Mail_ID from DefaultMailID(nolock) where user_id in (SELECT user_id FROM User_Detail(nolock) WHERE ParentID=@ParentId)    
 union             
  select TRIM(Mail_ID) Mail_ID from FromMailIDDetails(nolock) where user_id in (SELECT user_id FROM User_Detail(nolock) WHERE ParentID=@ParentId) and Status = 1  
 End  
  
End        


