/* ============================================================
   Procedure: [dbo].[usp_getGoogleFormList]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_getGoogleFormList]
(
    @userId bigint,
    @FilterText nvarchar(255),
    @OffsetValue bigint,
    @PagingSize bigint
)
AS
BEGIN
--declare 
--@userId bigint =34594,
--@FilterText nvarchar(255)='',
--@OffsetValue bigint=0,
--@PagingSize bigint=20
    DECLARE @StartPoint int = (@OffsetValue + 1), 
            @Endpoint int = (@OffsetValue + @PagingSize);

    SELECT * 
    FROM 
    (
        SELECT 
            ROW_NUMBER() OVER (PARTITION BY A.userId ORDER BY A.Id DESC) AS SNo,
            COUNT(A.UserId) OVER() AS TotalRow,
            A.FormName, 
            A.FormGUID, 
            A.WebhookUrl, 
            A.GoogleKey,
            FORMAT(COALESCE(A.UpdatedAt, A.CreatedAt), 'dd-MMM-yyyy hh:mm:ss tt') AS UpdatedAt,
            COALESCE(A.UpdatedBy, A.CreatedBy) AS UpdatedBy, 
            A.Id,
            CONCAT(ud.FName, ' ', ud.LName) AS PersonName,
            A.Status, 
            A.JsonSetting,'0' as LeadCount
        FROM tbl_GoogleFormIntegration (NOLOCK) A
        LEFT JOIN User_Detail (NOLOCK) ud ON ud.User_ID = A.CreatedBy OR ud.User_ID = A.UpdatedBy
        WHERE A.UserId = @userId
          AND A.ProgressStep = 1
          AND (ISNULL(@FilterText, '') = '' OR A.FormName LIKE '%' + @FilterText + '%')
    ) b
    WHERE b.SNo BETWEEN @StartPoint AND @Endpoint;
END



GO

