/* ============================================================
   Procedure: [dbo].[usp_GetGroupDetailsUser]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

  
CREATE   PROCEDURE [dbo].[usp_GetGroupDetailsUser] --335  
 @ParentID BIGINT  
AS  
BEGIN  
 SELECT utgd.ID,  
        utgd.GroupName,  
        ud.User_Login,  
        utgd.IsSMS,  
        utgd.IsMail,  
        utgd.IsEditable,  
        
        --utgd.CreatedOn,  
        dbo.[fn_getusertimefromindiantime](@ParentID,utgd.CreatedOn) as CreatedOn,
        
        ud.FName + ISNULL(ud.LName, '') AS CreatedBy,  
        (  
            SELECT COUNT(*)  
            FROM   UserGroupTemplateMix AS ugtm  
            WHERE  ugtm.ParentID = @ParentID  
                   AND ugtm.GroupID = utgd.ID  
        )                         AS TemplateCount  
 FROM   UserTemplateGroupDetails  AS utgd  
        LEFT JOIN User_Detail     AS ud  
             ON  ud.[User_ID] = utgd.CreatedBy  
 WHERE  utgd.ParentID = @ParentID  
 ORDER BY  
        CreatedOn DESC  
END  



GO

