/* ============================================================
   Procedure: [dbo].[usp_GetGroupDetailsUserBind]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[usp_GetGroupDetailsUserBind] --335
	@ParentID BIGINT,
	@IsSMS BIT,
	@isMail BIT
AS
BEGIN
	SELECT A.ID,
	       A.GroupName + ' ( ' + CAST(A.TemplateCount AS VARCHAR(50)) + ' )' AS 
	       GroupName
	FROM   (
	           SELECT utgd.ID,
	                  utgd.GroupName,
	                  ud.User_Login,
	                  utgd.IsSMS,
	                  utgd.IsMail,
	                  utgd.IsEditable,
	                  utgd.CreatedOn,
	                  ud.FName + ISNULL(ud.LName, '') AS CreatedBy,
	                  (
	                      SELECT COUNT(*)
	                      FROM   UserGroupTemplateMix AS ugtm
	                      WHERE  ugtm.ParentID = @ParentID
	                             AND ugtm.GroupID = utgd.ID
	                  ) AS TemplateCount
	           FROM   UserTemplateGroupDetails AS utgd
	                  LEFT JOIN User_Detail AS ud
	                       ON  ud.[User_ID] = utgd.CreatedBy
	           WHERE  utgd.ParentID = @ParentID
	                  AND utgd.IsSMS = @IsSMS
	                  AND utgd.IsMail = @isMail
	       ) A
	WHERE A.TemplateCount<>0
	ORDER BY
	       CreatedOn DESC
END



GO

