/* ============================================================
   Procedure: [dbo].[usp_GetGroupDetailsUserCRM]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.usp_GetGroupDetailsUserCRM

	@UserID BIGINT

AS

BEGIN

	SELECT gd.Group_ID         AS ID,

	       gd.Group_Name       AS SearchName,

	       'Custom Groups' AS     SearchTyp,

	       'Custom' AS            SearchCriteria

	FROM   Group_Detail           gd

	WHERE  gd.[User_ID] = @UserID

	UNION

	SELECT uilc.ID,

	       uilc.ImportName,

	       'Custom List' AS           SearchTyp,

	       'Custom' AS                SearchCriteria

	FROM   UserImportedListColumn     uilc

	WHERE  uilc.ParentID IN (SELECT ud.ParentID

	                         FROM   User_Detail ud

	                         WHERE  ud.[User_ID] = @UserID)

END


