/* ============================================================
   Procedure: [dbo].[usp_getGroupMessageHistory]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROC [dbo].[usp_getGroupMessageHistory]  --'1989+919509274990@conference.103.25.130.241','+919001670667@103.25.130.241','1458563115141','@conference.103.25.130.241'    
@ToJid nvarchar(100),          
@FromJid nvarchar(100),    
@FromTime nvarchar(100),     
@PostFix nvarchar(100)     
as    
BEGIN    
IF @FromTime='0'    
BEGIN    
select   @FromTime=jointime from [chat_app].[dbo].ofMucRoom  Room       
inner join  [chat_app].[dbo].ofMucAffiliation  Affiliation    
on Room.roomId=Affiliation.roomId  where jid=@FromJid and Room.name+@PostFix=@ToJid    
select @FromTime=isnull(@FromTime,0)    
IF @FromTime<>'0'    
BEGIN    
select cast(Datediff(s, '1970-01-01', cast (@FromTime as datetime)) AS bigint)*1000    
End     
    
SELECT top 50      
[RoomChatParsingId] ,[FromJid] ,[ToJid] ,[MessageBody] ,[chatTagXmlns]  ,[MessageType] ,[Username] ,[UserId]        
,[MessageId] ,[BaseString] , [MessageTime] ,[IsStarred] ,[addedtime],MessageStatus     
 FROM [chatapp].[dbo].[tblRoomChatParsing] where  ToJid=@ToJid  and ([MessageTime] >@FromTime )    
 order by [MessageTime] desc    
 END    
 else    
 begin    
 SELECT top 50      
[RoomChatParsingId] ,[FromJid] ,[ToJid] ,[MessageBody] ,[chatTagXmlns]  ,[MessageType] ,[Username] ,[UserId]        
,[MessageId] ,[BaseString] , [MessageTime] ,[IsStarred] ,[addedtime],MessageStatus     
 FROM [chatapp].[dbo].[tblRoomChatParsing] where  ToJid=@ToJid  and ([MessageTime] <@FromTime )    
 order by [MessageTime] desc    
 end    
 END



GO

/* ============================================================
   Procedure: [dbo].[usp_getgroupnumbers]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[usp_getgroupnumbers]
(@f nvarchar(max),@callerno nvarchar(20))
as
begin
--declare @f nvarchar(max)=(select flow from Cloud_flow_api(nolock) where appid=3139)
--declare @callerno nvarchar(20)='0000000000'
declare @c int=len(@f)-len(replace(@f,'#Group:','#Group')),@p nvarchar(500),@stringstart int,@stringend int=0
create table #temp(numbers nvarchar(max))
--@clientid bigint=27741,--cast((select SUBSTRING(@f,charindex('"Client":"',@f,1)+10,CHARINDEX(',',@f,charindex('"Client":"',@f,1))-(charindex('"Client":"',@f,1)+10))) as bigint),    
while @c>0    
begin    
--select @stringstart,@stringend
select @stringstart=charindex('"Name":"call',@f,@stringend+1)
select @stringend=charindex('"next":',@f,@stringstart)
--select @stringstart,@stringend
while @f like '%#Group%' and substring(@f,@stringstart,@stringend-@stringstart) not like '%#Group%'
begin
select @stringstart=charindex('"Name":"call',@f,@stringend+1)
select @stringend=charindex('"next":',@f,@stringstart)
--select @stringstart,@stringend
end
select @p =substring(@f,@stringstart,@stringend-@stringstart)
--select @p

--'"Name":"call","Client":"36350","appid":"3139","number":"#Group:1584","Sticky":"off","group-dial":"off","Record":"on","ringingduration":"30","conversationduration":"14400","DefaultPlay":"default_moh","moh_tag":"global","queue":"on"'
declare @sticky int =0,@sequence nvarchar(30)='Random',@groupid varchar(20),@appid varchar(20),@s int,@e int 
if @p like '%"Sticky":"on"%'
set @sticky=1
if @p like '%"group-dial":"on"%'
set @sequence='Equally'

select @s=charindex('"appid":',@p,1)
select @e=charindex(',',@p,@s)

--select @s,@e
select @appid=replace(substring(@p,@s+len('"appid":'),@e-(@s+len('"appid":'))),'"','')

select @s=charindex('"#Group:',@p,1)
select @e=charindex(',',@p,@s)

select @groupid=replace(replace(substring(@p,@s+len('"#Group:'),@e-(@s+len('"#Group:'))),'"',''),'#','')
--select @s,@e

--select @groupid

--select @sticky,@groupid,@appid,@callerno,@sequence


insert into #temp(numbers)
exec [get_Cloud_agent_no_new_withSequence] @sticky,@groupid,@appid,@callerno,@sequence

--select * from #temp

select top 1 @f=replace(@f,@p,replace(@p,'#Group:'+cast(@groupid as nvarchar)+'#',numbers)) from #temp
--select @f
truncate table #temp

select @c=len(@f)-len(replace(@f,'#Group:','#Group'))
--select @c,getdate()
--select @stringstart,@stringend
end
select @f
drop table #temp
end
--select * from Cloud_user_Group where parentid =36350





GO

