/* ============================================================
   Procedure: [dbo].[Usp_GetHeirarchicalDataMenu_New]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.Usp_GetHeirarchicalDataMenu_New  --'c',335      
 (       
   @FilterText nvarchar(500),    
   @CurrentPageURL nvarchar(max),      
   @UserID bigint        
 )       
 as       
  Begin         
  
      Declare @SeekingPageID int = 0         
      select  top 1  @SeekingPageID =  isnull(id,0) from Page where RIGHT(@CurrentPageURL,LEN(Path)-1) =  right(Path,LEN(Path)-1)   
  
  
      ;WITH Hierarchy(ChildId, ChildName, ParentId, Parents) AS (     SELECT Id, menuName, menuParentId, CAST(MenuName AS VARCHAR(MAX))      
      
     FROM menu AS FirtGeneration        
         WHERE MenuParentID =0          
        UNION ALL        
       SELECT NextGeneration.Id, NextGeneration.MenuName, Parent.ParentId,       
       CAST(CASE WHEN Parent.Parents = ''       
    THEN(CAST(NextGeneration.menuParentId AS VARCHAR(MAX)))        
         ELSE(Parent.Parents + ' > ' + CAST(NextGeneration.MenuName AS VARCHAR(MAX)))       
          END AS VARCHAR(MAX))       
          FROM Menu AS NextGeneration       
           INNER JOIN Hierarchy AS Parent      
              ON NextGeneration.MenuParentID = Parent.ChildId       
         )       
          SELECT      
       h.Parents as MenuItems_HRC,m.MenuName, Pg.Path,pg.id as PageID       
                FROM Hierarchy h join menu m on h.ChildId=m.ID and pageid<>0       
       join Page(nolock) as pg on m.PageID = pg.ID       
         where PageID       
         not in (      
                  select PageID from UserQuickLinks(nolock) where USERID =       
                                       @UserID and SeekingPageID = @SeekingPageID)      
                  
               --and PG.PageName like '%' + @FilterText + '%'   OPTION(MAXRECURSION 32767)       
           and h.Parents like '%' + @FilterText + '%'       
     order by case when @filtertext=menuname then 0 else pageid end    
         
     OPTION(MAXRECURSION 32767)       
              
      end 


GO

