 where urmp.UserId = @UserId or utumm.UserId = @UserId and isnull(umod.Active,0) = 1    
 --Select @IsAdmin IsAdmin, @IsClassic IsClassic, @IsExpired IsExpired, @ScopeCode ScopeCode, @RoleCode RoleCode             
        
   if(@ScopeCode = '' or @IsExpired = 1)            
