                                 else FirtGeneration.IsInternal                  
             end                     
                  
    UNION ALL                          
       SELECT NextGeneration.ModuleId, NextGeneration.ModuleCode, NextGeneration.ModuleName, Parent.Generation + 1, Parent.ChildId,     
