        FROM tbl_ua_ModuleMaster(nolock) AS NextGeneration                    
        INNER JOIN Hierarchy AS Parent ON NextGeneration.ParentModuleId = Parent.ChildId                  
        where isnull(NextGeneration.Active,0) = 1     
