   FROM Hierarchy  as HR     
      where HR.ChildId not in (296, 297, 299, 300)        
)t    
 where ((t.[Type] = 'Module') or (t.[Type] = 'Page' and t.[URL] != ''))    
    
order by t.Sequence asc                   
 --  OPTION(MAXRECURSION 32767)                   
                   
   End                  
  Else if(@IsExpired = 1 and (@IsAdmin = 0 or (@ScopeCode = 'USER' and @RoleCode = 'SYS_GUEST')))                  
 Begin                  
 Print 4    
                  
  set @ParentId = 335                  
  --set @ScopeCode = 'USER'                  
                   
  ;WITH Hierarchy(ChildId, ChildCode, ChildName, Generation, ParentId, sequence, [Type],SequnceStructure)          
