             end                     
                  
    UNION ALL                 
       SELECT NextGeneration.ModuleId, NextGeneration.ModuleCode, NextGeneration.ModuleName, Parent.Generation + 1, Parent.ChildId, NextGeneration.Sequence,                   
    NextGeneration.[Type],CAST(Parent.SequnceStructure + '/' + NextGeneration.ModuleName AS VARCHAR(255))                        
        FROM tbl_ua_ModuleMaster(nolock) AS NextGeneration                          
