/* ============================================================
   Procedure: [dbo].[Usp_GetImprotListExecute]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[Usp_GetImprotListExecute]
	@PArentID BIGINT,
	@ID BIGINT
AS
BEGIN
	SELECT A.Column1,
	       A.Column2,
	       A.Column3,
	       A.Column4,
	       A.Column5,
	       A.Column6,
	       A.Column7,
	       A.Column8,
	       A.Column9,
	       A.Column10
	FROM   (
	           SELECT uilc.Column1,
	                  uilc.Column2,
	                  uilc.Column3,
	                  uilc.Column4,
	                  uilc.Column5,
	                  uilc.Column6,
	                  uilc.Column7,
	                  uilc.Column8,
	                  uilc.Column9,
	                  uilc.Column10,
	                  'H' AS Header
	           FROM   UserImportedListColumn uilc
	           WHERE  uilc.ParentID = @PArentID
	                  AND uilc.ID = @ID
	           UNION
	           SELECT usd.MobileNumber,
	                  usd.EmailID,
	                  usd.Column1,
	                  usd.Column2,
	                  usd.Column3,
	                  usd.Column4,
	                  usd.Column5,
	                  usd.Column6,
	                  usd.Column7,
	                  usd.Column8,
	                  'R' AS             Header
	           FROM   UserSearchData     usd
	           WHERE  usd.ParentID = @PArentID
	                  AND usd.ImportedListID = @ID
	       ) A
	ORDER BY
	       A.Header
END



GO

