   Procedure: [dbo].[usp_getinhousetickets]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_getinhousetickets]  
as  
begin  
DECLARE @xml NVARCHAR(MAX)DECLARE @body NVARCHAR(MAX)        
  
select  date_created DateCreated,ticketno,requester Raisedby,Subject,replace(replace(dbo.fncRemove_HTML(Description),'char(13)',''),'char(10)','') Description,
replace(replace(dbo.fncRemove_HTML(isnull(remarks,'')),'char(13)',''),'char(10)','') remarks,Stat_Desc as Status   
into #temp  
from Serv_TicketMaster(nolock) s  
join Serv_Ticket_Stat_Mast(nolock) t on s.Status=t.Stat_ID  
 where date_created>'20220124' and parentid=335  
  
 SET @xml =CAST(( SELECT DateCreated AS 'td','',TicketNo AS 'td','',Raisedby AS 'td','',Subject AS 'td','',         
Description  AS 'td','',remarks AS 'td','',Status from #temp FOR XML PATH('tr'), ELEMENTS ) AS NVARCHAR(MAX))        
SET @body ='<html><H1>Inhouse Ticket Report as on '+cast (getdate() as nvarchar)  
+'</H1><body><table border = 2><tr><th>DateCreated</th><th>Ticketno</th><th>Raisedby</th><th>Subject</th><th>Description</th>  
<th>Remarks</th><th>Status</th></tr>'         
SET @body = @body + @xml +'</table></body></html>'        
EXEC usp_enqueueemail        
@profile_name='Alerts',         
@recipients='csshukla@pelsoftlabs.in;animesh.shukla@pelsoftlabs.in',        
@blind_copy_recipients='karuna@pelsoftlabs.in',        
@subject='Ticket Report Till Date',        
@body = @body,        
@body_format ='HTML'        
drop table #temp        
  
 end



