/* ============================================================
   Procedure: [dbo].[usp_GetIntCredtAuditLogList]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[usp_GetIntCredtAuditLogList]
    @UserId BIGINT,
	@UserIds NVARCHAR(255) = null,
	@FilterText NVARCHAR(255) = null,
    @OffsetValue INT,
    @PagingSize INT
AS
BEGIN
	SET NOCOUNT ON;

	--DECLARE
	--	@UserId BIGINT = 32222,
	--	@UserIds NVARCHAR(255) = '32222',
	--	@FilterText NVARCHAR(255) = '',
	--	@OffsetValue INT=0,
	--	@PagingSize INT=20


    DECLARE @ParentId BIGINT;
    DECLARE @StartPoint INT = (@OffsetValue + 1), 
            @EndPoint INT = (@OffsetValue + @PagingSize);
    
	DECLARE @tblUserIds as table ( UserId bigint)
	insert into @tblUserIds(UserId)
	select cast([value] as bigint) from string_split(trim(@UserIds), ',') where len(trim([value])) > 0
    

	;WITH auditThread as (
	SELECT 
		ROW_NUMBER() OVER (PARTITION BY A.ParentId ORDER BY A.CreatedDate DESC) AS SNo, A.LogId, pt.CreditName AS ServiceName, A.CreditTypeId, 
		Format(A.CreatedDate,'dd-MMM-yyyy hh:mm tt') CreatedOn, A.Amount, A.IsLock,A.CreatedBy, Credit, Debit, Remarks, 
		isnull(StartingfAmount,0) StartAmount, concat(User_Login,'(',FName,' ',LName,')' ) as UserName, User_Login,a.Action

	FROM tbl_IntCreditAuditLog(NOLOCK) A
	inner join @tblUserIds u on A.ParentId = u.UserId
	LEFT JOIN Price_Master_TypeCredit(NOLOCK) pt ON pt.CreditTypeID = A.CreditTypeId
	LEFT JOIN User_Detail(Nolock) ud on a.ParentId=ud.User_ID

	WHERE 1 = ( case 
			when isnull(@FilterText, '') = '' then 1 
			when pt.CreditName LIKE '%' + @FilterText + '%' then 1
			else 0 end 
		)
	)
	select SNo, LogId, ServiceName, CreditTypeId, CreatedOn, Amount, IsLock, CreatedBy, 
		Credit, Debit, Remarks, StartAmount, UserName, User_Login, Action, (select count(1) from auditThread) as [TotalRow]
	from auditThread b WHERE b.SNo BETWEEN @StartPoint AND @EndPoint;

END



GO

