/* ============================================================
   Procedure: [dbo].[Usp_getJsonDataForDisplay]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.Usp_getJsonDataForDisplay    
(    
  @EnqNo bigint,    
  @EnqPipelineID bigint    
)    
as    
begin    
       --declare @JsonData nvarchar(max) = N'[{"NoOfUsers":"34","TentativeDateOfFinalization":"16-Dec-2023","TentativeTicketSize":"124"    
   --,"PainArea":"this is testing material","TentativeDateTimeForDemo":"15-Dec-2023 13:09","OTPSent":"","OTPStatus":""}]'    
    
   declare @JsonData nvarchar(max) = N''   
   declare @ClientResponse nvarchar(500) = ''  
    
   select top 1 @JsonData = isnull(jsonInfo,'') , @ClientResponse = isnull(ClientResponse,'') from tbl_PipelineJsonInfo with(nolock)   
   where Enqno =  @EnqNo and EnqPipelineID = @EnqPipelineID    
    
  if(isnull(@JsonData,'') != '')
    begin
	select * , @ClientResponse as ClientResponse from openjson(@JsonData)    
    With (        
             NoOfUsers nvarchar(max) '$.NoOfUsers',      
    TentativeDateOfFinalization nvarchar(max) '$.TentativeDateOfFinalization',      
    TentativeTicketSize nvarchar(max) '$.TentativeTicketSize',      
    PainArea nvarchar(max) '$.PainArea',      
    TentativeDateTimeForDemo nvarchar(max) '$.TentativeDateTimeForDemo'      
        )  
	 end
	else
	 begin
	      select '' as NoOfUsers, '' as TentativeDateOfFinalization, '' as TentativeTicketSize
		    , '' as PainArea,'' as TentativeDateTimeForDemo , @ClientResponse as ClientResponse    
	 end


end 


