/* ============================================================
   Procedure: [dbo].[Usp_getKeyFromTradeIndia]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

  
CREATE   PROCEDURE dbo.Usp_getKeyFromTradeIndia                                          
  as                                          
  Begin                              
                              
    select                            
       t.[ID]                            
      ,[TradeIndia_Key]                            
      ,[Kit19ParentID]          
      ,isnull(u.EMail,'') as Email                           
      ,(select top 1 isnull(EMail,'')  from User_Detail where User_ID = 335 ) as EmailMain      
   ,isnull(u.User_Login,'') as UserLogin        
   ,[Trade_UserID]                            
      ,[Trade_ProfileID]                            
      ,[LastAPIHit]                            
      ,[LastDateFetched]                            
      ,[ExpiredOn]                            
      ,t.[Status]                            
    from TradeIndia_Mapping t(nolock)     
 join user_detail u (nolock) on t.Kit19ParentID=u.User_ID    
 join Price_UserSubscriptionDetails(nolock) p on p.UserID=u.User_ID and u.user_id=u.ParentID   
  and isnewplan=1 and planenddate>getdate()                             
    where t.Status = 1 and u.status=1 and                          
    
	(
	  ISNULL(LastAPIHit,'') = ''
	 or
	
	 (DATEDIFF(minute,ISNULL(LastAPIHit,''),getdate()))>= 10
	 
	  ) 
	
	 order by ID desc                                
                                  
  End 


