    -- and  ISNULL(resolved_dt,'')<> '' and DATEDIFF(HOUR,Date_Created,resolved_dt ) <= 24 and Status = 2  
    
   select convert(date,VisitDate) as Date ,count(convert(date,VisitDate)) as Count  from VisitPageDetails where ParentID = @kit19UserID and Type='LandingPage' and convert(date,VisitDate) > convert(date,@DateCurrentTo) group by convert(date,VisitDate)
