CREATE   PROCEDURE dbo.Usp_GetLandingPageForGraph_Kit19_New --233,335            
(            
@EnqNo bigint,            
@kit19UserID bigint            
            
)             
            
as            
            
Begin            
            
  Declare @DateCurrentTo datetime = null            
            
   CREATE TABLE #TempLinked                                              
    (                                              
      Result VARCHAR(200)                                              
    )                     
                                
     INSERT INTO #TempLinked                                              
     EXEC GetStatusofLinkedServer 'CRM'                                              
     IF NOT EXISTS(                                              
        SELECT 'x'                                              
        FROM   #TempLinked                                              
    )                                   
    begin               
            
    select @DateCurrentTo = convert(date,CreatedDate) From CRM.CRMDB.dbo.AccountSetup where EnqNo = @EnqNo and UserBy = @kit19UserID             
 and Stage = 'Customer Accepted Setup Request'              
             
 --for temp            
              
   -- Declare @DateCurrentTo datetime = null            
          
 --set @DateCurrentTo = '2019-01-01 21:08:03.167'            
            
      --declare @TicketsCount int = 0      
    --declare @ResolvedTicketsCount int = 0      
       -- select @TicketsCount = Count(*)  From Serv_TicketMaster where ParentID = @kit19UserID and convert(date,Date_Created) > = convert(date,@DateCurrentTo)      
           
    --   select @ResolvedTicketsCount = Count(*)  From Serv_TicketMaster where ParentID = @kit19UserID and convert(date,Date_Created) > = convert(date,@DateCurrentTo)      
    -- and  ISNULL(resolved_dt,'')<> '' and DATEDIFF(HOUR,Date_Created,resolved_dt ) <= 24 and Status = 2      
        
    select convert(date,VisitDate) as Date ,count(convert(date,VisitDate)) as Count  into #t1 from VisitPageDetails where ParentID = @kit19UserID and Type='LandingPage' and convert(date,VisitDate) > convert(date,@DateCurrentTo)  
  group by convert(date,VisitDate)       
    order by convert(date,VisitDate) asc      
       
     select convert(date,DateCreated) as Date ,count(convert(date,DateCreated)) as Count  into #t2 From ClientPageDetail where User_ID = @kit19UserID     
   and convert(date,DateCreated) >= convert(date,@DateCurrentTo) group by  convert(date,DateCreated)    
     order by CONVERT(date,DateCreated) asc      
       
     --select date,visits,leads        
         
    
  select tbl.Date as Date ,isnull(tbl.Visits,0) as Visits,isnull(tbl.Leads,0) as Leads from    
  (    
  select Date,isnull(#t1.Count,0) as Visits ,(select ISNULL(#t2.Count,0) from #t2 where #t2.Date = #t1.date) as Leads  From #t1     
  union    
  Select Date,(select ISNULL(#t1.Count,0) from #t1 where #t1.Date = #t2.date) as Visits , isnull(#t2.Count,0) as Leads    From #t2 --on #t1.Date = #t2.Date    
 ) as tbl order by date asc    
            
   end            
            
  drop table  #TempLinked      
  drop table #t1    
  drop table #t2          
        
            
End 





