/* ============================================================
   Procedure: [dbo].[Usp_GetLandingPageStatus_Kit19]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

  
  
      
CREATE   PROCEDURE dbo.Usp_GetLandingPageStatus_Kit19 --233,335            
(            
@EnqNo bigint,            
@kit19UserID bigint            
            
)             
            
as            
            
Begin            
            
     Declare @DateCurrentTo datetime = null      
  Declare @VisitCount int = 0      
  Declare @TotaDistinctDay int = 0       
  Declare @AverageVisitCount int = 0        
  Declare @Status nvarchar(50) = 'Red'        
         
   CREATE TABLE #TempLinked                                              
    (                                              
      Result VARCHAR(200)                                              
    )                     
                                
     INSERT INTO #TempLinked                                              
     EXEC GetStatusofLinkedServer 'CRM'                                              
     IF NOT EXISTS(                                              
        SELECT 'x'                                              
        FROM   #TempLinked                                              
    )                                   
    begin               
          
           
       
      
      
  --set @DateCurrentTo = '2019-01-01 21:08:03.167'            
           
      
      
  select @VisitCount = ISNULL(Count(*),0)  from VisitPageDetails where ParentID = 335 and Type='LandingPage' and convert(date,VisitDate) >= convert(date,@DateCurrentTo)      
      
  select @TotaDistinctDay = count( distinct  convert(date,VisitDate))  from VisitPageDetails where ParentID = @kit19UserID and Type='LandingPage' and convert(date,VisitDate) >= convert(date,@DateCurrentTo)       
      
	  if(@VisitCount <> 0)
	  Begin
  set @AverageVisitCount = (@VisitCount/@TotaDistinctDay)      
      End
      
      
      
  if(exists(      
  select 1 from ClientPageDetail where User_ID = @kit19UserID and convert(date,DateCreated) >= CONVERT(date,@DateCurrentTo)       
  ))      
  Begin      
           
          if(@AverageVisitCount >= 1)      
      Begin      
       set @Status ='Green'      
   End      
      
  End      
               
  end            
              
  drop table  #TempLinked            
        
  select @Status as Status      
      
            
End            
            
      


GO

/* ============================================================
   Procedure: [dbo].[Usp_GetLast10EntryOfRecipients]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

  
     
CREATE   PROCEDURE [dbo].[Usp_GetLast10EntryOfRecipients]  --26,'',''
(  
    @CampaignID BIGINT,  
    @DateFrom VARCHAR(100),  
    @DateTo VARCHAR(100)  
)        
 AS        
BEGIN  
  
 
 
 IF (@DateFrom <> '' AND @DateTo <> '')  
 BEGIN  
     SELECT TOP 10
      
       [ID]
      ,[CampaignID]
      
      --,[ExecutionTime]
      ,dbo.[fn_getusertimefromindiantime](ParentID,ExecutionTime) as ExecutionTime
      
      ,[NoOfRecipients]
      ,[Response]
      ,[BatchID]
      ,[IsRecipients]
      ,[IsMessages]
      ,[IsExecuted]
      ,[ParentID]
      ,[Jobid]
      ,[TemplateSequence]
      ,[templateId]
     
     FROM   UserCampaignExecutionHistory  
     WHERE  [CampaignID] = @CampaignID  
            AND 
            [ExecutionTime]
            
             BETWEEN 
             CONVERT(DATE,dbo.[fn_getISTtimefromusertime](ParentID,@DateFrom)) 
                AND 
             DATEADD(DAY, 1, CONVERT(DATE,dbo.[fn_getISTtimefromusertime](ParentID,@DateTo)))  
     
     ORDER BY  
            ExecutionTime DESC  
 END  
 ELSE  
 BEGIN  
     SELECT TOP 10 
     
       [ID]
      ,[CampaignID]
      
        --,[ExecutionTime]
      ,dbo.[fn_getusertimefromindiantime](ParentID,ExecutionTime) as ExecutionTime
      
      ,[NoOfRecipients]
      ,[Response]
      ,[BatchID]
      ,[IsRecipients]
      ,[IsMessages]
      ,[IsExecuted]
      ,[ParentID]
      ,[Jobid]
      ,[TemplateSequence]
      ,[templateId]  
     
     
     FROM   UserCampaignExecutionHistory  
     WHERE  [CampaignID] = @CampaignID  
     ORDER BY  
            ExecutionTime DESC  
 END  
END  



GO

