CREATE   PROCEDURE [dbo].[usp_GetLastctrl_count]    
 @ParentID BIGINT,    
 @Name VARCHAR(500)    
AS    
BEGIN    
 
if exists(select 1  FROM   dbo.WebFormTbl AS uwf    
 WHERE  uwf.ParentID = @ParentID    
        AND uwf.FormName = @Name)
begin
with cte as
(
