/* ============================================================
   Procedure: [dbo].[Usp_GetLastYearMonthlyConversion]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.Usp_GetLastYearMonthlyConversion --335      
(      
 @UserID bigint       
)      
as      
Begin      
    --declare @UserID bigint =335  
  Declare @LastDateConversion datetime = getdate()         
  Declare @IsAdmin bit = 0         
  select @IsAdmin = isnull(IsAdmin,0) from User_Detail(nolock) where User_ID = @UserID    
  
select date_id dates,date_month [month],
isnull(Amount,0) Amount,row_number() over (partition by 1 order by cast(date_id as date) asc) rownum
from calendar(nolock) c left join 
(select datepart(month,createdon) mc,datepart(year,createdon) yc,isnull(sum(isnull(AmountPaid,0)),0) Amount
from  
leadInteractionHistory(nolock) l where 
--parentid=335 
@userid=case when @isadmin=0 then createdby else parentid end
and datediff(month,CreatedOn,getdate()) <=  12
group by datepart(month,createdon),datepart(year,createdon)
) l
on l.mc=c.date_month and l.yc=c.date_year
where datepart(dd,date_id)=datepart(dd,getdate())
and DATEDIFF(mm,date_id,getdate()) between 0 and 11    
  /*    
   --select top 1 @LastDateConversion = CreatedOn  from leadInteractionHistory(nolock)      
   -- where      
   -- (AmountPaid <> 0)        
   --and      
   -- (@UserID = case when @IsAdmin = 0        
   --                  then CreatedBy        
   --                  else ParentID        
   --  end)                      
   --  order by Createdon desc         
 -- select @LastDateConversion      
      
  set @LastDateConversion = isnull(@LastDateConversion,GETDATE());           
          
   CREATE TABLE #TempLast12Dates          
    (          
       Dates nvarchar(50),          
       RowNum int          
    )          
          
   insert into #TempLast12Dates          
   SELECT Dates, RowNum   FROM          
    (          
        
  SELECT CAST(@LastDateConversion AS DATE) AS Dates, 12 as RowNum          
  UNION          
  SELECT CAST(DATEADD(Month, -1, @LastDateConversion) AS DATE) AS Dates, 11 as RowNum           
  UNION          
