SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE usp_getleadactivitysummary
(@parentid bigint,@fromdate date,@todate date
)
as
begin
--declare @parentid bigint,@fromdate date,@todate date
--select @parentid=34594,@fromdate='20260401' ,@todate='20260416'

select eventid,eventname,COUNT(1) TotalCount ,COUNT(distinct LeadID) as DistinctLeads
from tbl_LeadEventHistory(nolock) t join ActivityMaster a (nolock)
on t.EventID=a.ID 
where t.parentid=@parentid and EventDate between @fromdate and dateadd(d,1,@todate) group by eventname,eventid
end



