CREATE   PROC [dbo].[Usp_GetLeadDetails] --335
(@txtSearch NVARCHAR(100), @ParentID BIGINT)
AS 
BEGIN
	SELECT *
	FROM   UserLeads
	WHERE  ParentID = @ParentID
