    -- Return the concatenated result    
    SELECT @Result AS Result;    
END*/  
BEGIN      

    --declare     @UserID BIGINT=34594,@LeadID BIGINT=16467402,@Placeholders NVARCHAR(MAX)='MobileNo'      


    DECLARE @SQL NVARCHAR(MAX);    
    DECLARE @Result NVARCHAR(MAX) = '';    
    DECLARE @Placeholder NVARCHAR(255);    
    DECLARE @DelimiterPos INT;    
    DECLARE @FetchedValue NVARCHAR(MAX);    
  
    -- Trim spaces from @Placeholders    
    SET @Placeholders = LTRIM(RTRIM(@Placeholders));    
  
    -- Process each placeholder individually    
    WHILE LEN(@Placeholders) > 0    
    BEGIN    
        -- Find the position of the next comma    
        SET @DelimiterPos = CHARINDEX(',', @Placeholders);    
  
        -- If no comma is found, take the whole string    
        IF @DelimiterPos = 0    
        BEGIN    
            SET @Placeholder = @Placeholders;    
            SET @Placeholders = '';    
        END    
        ELSE    
        BEGIN    
            SET @Placeholder = LEFT(@Placeholders, @DelimiterPos - 1);    
            SET @Placeholders = RIGHT(@Placeholders, LEN(@Placeholders) - @DelimiterPos);    
        END    
  
        -- Remove spaces from the current placeholder    
        SET @Placeholder = LTRIM(RTRIM(@Placeholder));    
  
        -- Construct dynamic SQL for all placeholders uniformly  
        If(@Placeholder='MobileNo')
        Begin
            SET @SQL = 'SELECT @FetchedValue = REPLACE(CONCAT(CountryCode, MobileNo), '' '', '''') FROM UserLeads WHERE ID = @LeadID';
        End
        Else
        Begin
            SET @SQL = 'SELECT @FetchedValue = ' + QUOTENAME(@Placeholder) + ' FROM UserLeads WHERE ID = @LeadID';    
        End
  
        -- Print the dynamic SQL query for debugging    
        PRINT @SQL;    
  
        -- Execute the dynamic SQL query and capture the result    
        EXEC sp_executesql @SQL, N'@LeadID BIGINT, @FetchedValue NVARCHAR(MAX) OUTPUT', @LeadID = @LeadID, @FetchedValue = @FetchedValue OUTPUT;    
  
        -- Concatenate the result    
        IF @FetchedValue IS NULL OR @FetchedValue = ''    
        BEGIN    
            IF @Result = ''    
                SET @Result = 'NULL';    
            ELSE    
                SET @Result = @Result + ', NULL';    
        END    
        ELSE    
        BEGIN    
            IF @Result = ''    
                SET @Result = @FetchedValue;    
            ELSE    
                SET @Result = @Result + ', ' + @FetchedValue;    
        END    
    END    
  
    -- Return the concatenated result    
    SELECT @Result AS Result;    
END



