/* ============================================================
   Procedure: [dbo].[usp_GetLeadDetailsByPlaceholders1]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

--------------------------------------------------------------

CREATE   PROCEDURE [dbo].[usp_GetLeadDetailsByPlaceholders1]  
    @UserID BIGINT,  
    @LeadID BIGINT,  
    @Placeholders NVARCHAR(MAX)  
AS  
BEGIN  
    DECLARE @SQL NVARCHAR(MAX);  
  
    -- Trim spaces from @Placeholders  
    SET @Placeholders = LTRIM(RTRIM(@Placeholders));   
  
    -- Handle specific cases and remove spaces if MobileNo  
    IF @Placeholders = 'MobileNo'  
    BEGIN  
        -- Construct dynamic SQL to concatenate MobileNo and CountryCode and remove spaces  
        SET @SQL = '  
            SELECT REPLACE(CONCAT(CountryCode, MobileNo), '' '', '''') AS MobileNo   
            FROM UserLeads   
            WHERE ID = @LeadID';  
    END  
    ELSE  
    BEGIN  
        -- Construct dynamic SQL for other placeholders  
        SET @SQL = 'SELECT ' + QUOTENAME(@Placeholders) + ' FROM UserLeads WHERE ID = @LeadID';  
    END  
  
    -- Print the dynamic SQL query for debugging  
    PRINT @SQL;  
  
    -- Execute the dynamic SQL query  
    EXEC sp_executesql @SQL, N'@LeadID BIGINT', @LeadID;  
END 





GO

