CREATE   PROCEDURE dbo.Usp_GetLeadDocumentDetail (
	@ParentID VARCHAR(10)
	,@UserID VARCHAR(10)
	,@LeadID VARCHAR(10) NULL
	)
AS
BEGIN
	SELECT l.DocUpID
		,l.UserID
		,l.LeadID
		,u.User_Login
		,l.DocumentName
		,l.FileType
		,l.FileLocation
		,l.UploadedDate
		,l.UpdatedDate
		,l.DeletedDate
	FROM tbl_LeadDocumentUpload l(NOLOCK)
	INNER JOIN User_Detail(NOLOCK) u ON u.User_ID = l.UserID
	WHERE /*l.ParentID = @ParentID  
              AND */
		l.LeadID = @LeadID
		AND l.ISDeleted = 0
	ORDER BY DocUpID DESC;

	-- END   
	EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @UserID
		,@Activity_type = 'View_Docu_Lead'
		,@ActionType = 'S'
		,@RowJson = ''
		,@Table_name = 'tbl_LeadDocumentUpload'
END;



