-- exec usp_GetLeadEnquiryCustomFields @Id=502793, @FieldId=0, @IsMandatory=0, @IsQuickAdd=0, @Type='L'    
-- exec usp_GetLeadEnquiryCustomFields @Id=502793, @FieldId=375, @IsMandatory=default, @IsQuickAdd=default, @Type='L'    
-- exec usp_GetLeadEnquiryCustomFields @Id=2926869, @FieldId=0, @IsMandatory=default, @IsQuickAdd=default, @Type='E'    
-- exec usp_GetLeadEnquiryCustomFields @Id=2982136, @FieldId=0, @IsMandatory=0, @IsQuickAdd=0, @Type='E'    
-- exec usp_GetLeadEnquiryCustomFields @Id=2926869, @FieldId=365, @IsMandatory=default, @IsQuickAdd=default, @Type='E'    
CREATE   PROCEDURE [dbo].[usp_GetLeadEnquiryCustomFields]    
(    
 @Id bigint,    
 @FieldId bigint=0,    
 @IsMandatory int=-1,    
 @IsQuickAdd int=-1,    
 @Type varchar(1)='L' --'E'    
)    
as                                
begin                                
set nocount on    
 -- declare @Id bigint=756222, @FieldId bigint=0,  @IsMandatory int=-1,  @IsQuickAdd int=-1, @Type varchar(1)='L'  
  
 declare @ParentID bigint=0    
 If(@Type='L')    
 Begin    
  select @ParentID=ParentID from UserLeads(nolock) Where ID=@Id    
    
  select c.field_ID, c.fieldname, fieldvalue=isnull(cl.fieldvalue,'')    
  ,(case [datatype] when 'd' then 'Date' when 'f' then 'Numeric' when 'v' then 'Text' when 'r' then 'Radio' when 'm' then 'Multiline' when 's' then 'Select' when 'c' then 'Checkbox' end) as [datatype]    
  ,c.[sequence],c.[addedon],c.[isActive],c.[isMandatory],c.[quickAdd],c.[currentDate],  
  [defaultValue]=case[datatype] when 'd' then isnull(c.[defaultValue],'01/01/1900') when 'f' then isnull(c.[defaultValue],0) when 'v' then isnull(c.[defaultValue],'') else c.[defaultValue] end,  
  [minvalue]=case[datatype] when 'd' then isnull(c.[minvalue],'01/01/1900') when 'f' then isnull(c.[minvalue],0) when 'v' then isnull(c.[minvalue],'') else c.[minvalue] end,  
  [maxvalue]=case[datatype] when 'd' then isnull(c.[maxvalue],'01/01/1900') when 'f' then isnull(c.[maxvalue],0) when 'v' then isnull(c.[maxvalue],'') else c.[maxvalue] end  
  from customfields(nolock) c left join customfieldLeadvalue(nolock) cl    
  on  c.field_ID=cl.fieldID and cl.LeadID=@Id    
  where c.ParentID=@ParentID and isActive=1     
  and c.Field_Id=Case when @FieldId=0 then c.Field_Id else @FieldId end    
  and c.isMandatory=Case when @IsMandatory=-1 then c.isMandatory else @IsMandatory end    
  and c.quickAdd=Case when @IsQuickAdd=-1 then c.quickAdd else @IsQuickAdd end    
  Order By sequence    
 End    
    
 If(@Type='E')    
 Begin    
  select @ParentID=ParentID from UserEnquiry(nolock) Where EnquiryID=@Id    
    
  select c.field_ID, c.fieldname, fieldvalue=isnull(cl.fieldvalue,'')    
  ,(case [datatype] when 'd' then 'Date' when 'f' then 'Numeric' when 'v' then 'Text' when 'r' then 'Radio' when 'm' then 'Multiline' when 's' then 'Select' when 'c' then 'Checkbox' end) as [datatype]   
  ,c.[sequence],c.[addedon],c.[isActive],c.[isMandatory],c.[quickAdd],c.[currentDate],  
  [defaultValue]=case[datatype] when 'd' then isnull(c.[defaultValue],'01/01/1900') when 'f' then isnull(c.[defaultValue],0) when 'v' then isnull(c.[defaultValue],'') else c.[defaultValue] end,  
  [minvalue]=case[datatype] when 'd' then isnull(c.[minvalue],'01/01/1900') when 'f' then isnull(c.[minvalue],0) when 'v' then isnull(c.[minvalue],'') else c.[minvalue] end,  
  [maxvalue]=case[datatype] when 'd' then isnull(c.[maxvalue],'01/01/1900') when 'f' then isnull(c.[maxvalue],0) when 'v' then isnull(c.[maxvalue],'') else c.[maxvalue] end  
  from customfields(nolock) c left join customfieldEnquiryvalue(nolock) cl    
  on  c.field_ID=cl.fieldID and cl.EnquiryID=@Id    
  where c.ParentID=@ParentID and isActive=1     
  and c.Field_Id=Case when @FieldId=0 then c.Field_Id else @FieldId end    
  and c.isMandatory=Case when @IsMandatory=-1 then c.isMandatory else @IsMandatory end    
  and c.quickAdd=Case when @IsQuickAdd=-1 then c.quickAdd else @IsQuickAdd end    
  Order By sequence    
 End    
    
end        


