-- exec usp_GetLeadInteractionHistory 359,32821    
--------Modified By Abhishek Makkar ----------- Time: 8/18/2017 10:31:06 PM                
CREATE   PROCEDURE [dbo].[usp_GetLeadInteractionHistory] --7,34594 -- 50302, 335             
 @LeadNo BIGINT,                
 @ParentID BIGINT                
AS                
BEGIN  
--declare @LeadNo BIGINT = 359,                
-- @ParentID BIGINT = 32821    
   
      exec Usp_createProductMasterTable @ParentID

      Declare @Query nvarchar(max) = Concat( N'  select * from ( 

         /*
           SELECT ul.FollowupStatus,     
           dbo.fn_getusertimefromindiantime(@ParentID, [ul].[followupdate]) AS NextStatusDate,
		   ul.Remarks,
		   --ul.Products,
		   (                
            SELECT STUFF(                
                       (                
                           SELECT N'', '' + ss.Name                
                           FROM   ProductMaster AS ss  (NOLOCK)                
                                  INNER JOIN dbo.fn_Split(ul.Products, ''#'') AS                 
                                       fs                
                                       ON  ss.ProductID = fs.[value]                 
                                           FOR XML                 
                                           PATH(''''),                
                                  TYPE                
                       )                 
                       .value(''text()[1]'', ''nvarchar(max)''),                
                       1,                
                       2,                
                       N''''                
                   )                
        ) AS Products,              
          ul.AmountPaid,
		  (select ud.FName + '' '' + ISNULL(ud.LName, '''') from User_Detail(nolock) as ud where User_ID = ul.AssignedTo) as
		   AssignedTo
               
   FROM userleads ul (nolock)
   where 
	     ul.LeadNo = @LeadNo                
        AND ul.ParentID = @ParentID 
		
  union
    */       

 SELECT distinct fus.FollowupStatus,    
        convert(varchar(25),dbo.[fn_getusertimefromindiantime](', Cast(@ParentID as nvarchar(max)) , ',lih.FollowupDate)) as NextStatusDate,              
        lih.Remarks,                
        (                
            SELECT STUFF(                
                       (                
                           SELECT N'', '' + ss.Name                
                           FROM   tbl_ProductMaster_' , Cast(@ParentID as nvarchar(max)) , '  AS ss  (NOLOCK)                
                                  INNER JOIN dbo.fn_Split(lih.Products, ''#'') AS                 
                                       fs                
                                       ON  ss.ProductID = fs.[value]                 
                                           FOR XML                 
                                           PATH(''''),                
                                  TYPE                
                       )                 
                       .value(''text()[1]'', ''nvarchar(max)''),                
                       1,                
                       2,                
                       N''''                
                   )                
        ) AS Products,                
        lih.AmountPaid,                
        ud.FName + '' '' + ISNULL(ud.LName, '''') AS AssignedTo --, lih.createdon                
 FROM   LeadInteractionHistory      AS lih (NOLOCK)  
        INNER JOIN FollowUp_Status  AS fus (NOLOCK)                
             ON  fus.ID = lih.FollowUpStatus                
        LEFT JOIN User_Detail       AS ud  (NOLOCK)                
             ON  ud.[User_ID] = lih.AssignedTo                
 WHERE  lih.LeadNo = ', Cast(@LeadNo as nvarchar(max)) ,'                
        AND lih.ParentID = ', Cast(@ParentID as nvarchar(max)) ,'          
            
 -- ORDER BY NextStatusDate DESC
 
 ) as tbl ORDER BY NextStatusDate DESC')

   exec sp_executesql @Query 
                 
END 


