/* ============================================================
   Procedure: [dbo].[Usp_GetLeadMessageNew]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.Usp_GetLeadMessageNew
(
   @ID VARCHAR(Max) 
  ,@Message NVARCHAR(2000)  
  ,@Mobile BIT  
  ,@mobile1 BIT  
  ,@Mobile2 BIT  
  ,@AccountID BIGINT 
)
as
Begin

     set nocount on  

	 drop table if exists #tblTempLeadIDs
	 drop table if exists #tmpFinalTbl
	 drop table if exists #tmpflind_sub


    Declare @ParentID bigint = (select isnull(ParentID,0) from User_Detail with(nolock)  where User_ID = @AccountID)     
    select row_number() over(order by value asc) as RowNum,Value as LeadID  into #tblTempLeadIDs from fn_Split(@ID,'#')  

   set  @Message = REPLACE(@Message,'#Name#','#PersonName#')                     
   set  @Message = REPLACE(@Message,'#Company Name#','#CompanyName#')                    
   set  @Message = REPLACE(@Message,'#Mobile1#','#MobileNo#')                    
   set  @Message = REPLACE(@Message,'#Mobile2#','#MobileNo1#')                    
   set  @Message = REPLACE(@Message,'#Mobile3#','#MobileNo2#')                    
   set  @Message = REPLACE(@Message,'#EmailID1#','#EmailID#')                    
   set  @Message = REPLACE(@Message,'#EmailID2#','#EmailID1#')                    
   set  @Message = REPLACE(@Message,'#EmailID3#','#EmailID2#')                    
   set  @Message = REPLACE(@Message,'#Created Date#','#CreatedOn#')                    
   set  @Message = REPLACE(@Message,'#Created By#','#CreatedBy#')                   
   set  @Message = REPLACE(@Message,'#Created On#','#CreatedOn#')                 
   set  @Message = REPLACE(@Message,'#Last Followup Date#','#LastFollowupDate#')                 
   set  @Message = REPLACE(@Message,'#Next Followup Date#','#NextFollowupDate#')                
   set  @Message = REPLACE(@Message,'#Last Remarks#','#LastRemarks#')                
