/* ============================================================
   Procedure: [dbo].[Usp_GetLeadNoFromUserLeads]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROC [dbo].[Usp_GetLeadNoFromUserLeads] --335 
(@ParentID BIGINT)  
AS  
BEGIN
	DECLARE @Tag VARCHAR(50) = '';
	SELECT @Tag = LeadNo
	FROM   UserLeads
	WHERE  ParentID = @ParentID
	
	IF (@Tag = '')
	BEGIN
	    SELECT '1'
	END
	ELSE
	BEGIN
	    SELECT MAX(ISNULL(LeadNo, 0)) + 1
	    FROM   UserLeads
	    WHERE  ParentID = @ParentID
	END
END



