 DECLARE @tbluser TABLE (  
  User_ID BIGINT  
  ,Name VARCHAR(100)  
  ,IMAGE VARCHAR(100)  
  )  
 DECLARE @IsAdmin BIT = 0  
  
 SELECT @IsAdmin = IsAdmin  
 FROM User_Detail(NOLOCK)  
 WHERE User_ID = @Userid  
  
 IF (@IsAdmin = 1)  
 BEGIN  
  --set @Userid = 0;            
  INSERT INTO @tbluser  
  EXEC Use_GetUserDetails @ParentId  
 END  
 ELSE  
 BEGIN  
  INSERT INTO @tbluser  
  EXEC Use_GetUserDetails @UserId  
 END  
  
 DECLARE @TeamCode VARCHAR(10) = ''  
 DECLARE @ScopeCode VARCHAR(10) = ''  
 DECLARE @UserIdTeamLst VARCHAR(4000) = ''  
 DECLARE @HierarchyJSON VARCHAR(Max) = ''  
  
 SELECT @UserIdTeamLst = isnull(STRING_AGG(User_ID, ','), '')  
 FROM @tbluser  
  
 PRINT '@UserIdTeamLst: ' + @UserIdTeamLst  
  
 IF OBJECT_ID(N'tempdb..#followup_status') IS NOT NULL  
 BEGIN  
  DROP TABLE #followup_status  
 END  
  
 select * into #leadinteractionhistory from LeadInteractionHistory(nolock) where parentid=@parentid and cast(CreatedOn as date) between @fromdate and @todate  
 select * into #leadinteractionhistoryWithdatrange from LeadInteractionHistory(nolock) where parentid=@parentid 
 --and cast(CreatedOn as date) between @fromdate and @todate    
  
  
 SELECT u.user_id  
  ,u.user_login  
  ,isnull(NewLeadsAdded, 0) NewLeadsAdded  
  ,isnull(TotalLeadsAssignedCurrently, 0) TotalLeadsAssignedCurrently  
  ,isnull(UniqueLeadsFollowedUp, 0) UniqueLeadsFollowedUp  
  ,isnull(TotalFollowupsMarked, 0) TotalFollowupsMarked  
  ,isnull(UntouchedLeads, 0) UntouchedLeads  
  ,isnull(LeadsOverDue, 0) LeadsOverDue  
  ,u.User_Login + ' (' + isnull(u.FName, '') + ' ' + isnull(u.LName, '') + ')' AS UserByName  
 FROM user_detail(NOLOCK) u  
 LEFT JOIN (  
  SELECT user_login  
   ,sum(CASE   
     WHEN cast(u.createdon as date) BETWEEN @fromdate  
       AND @todate  
      THEN 1  
     ELSE 0  
     END) AS NewLeadsAdded  
  FROM userleads u(NOLOCK)  
  JOIN user_detail(NOLOCK) ul ON ul.User_ID = u.CreatedBy  
  WHERE u.parentid = @parentid  
  GROUP BY user_login  
  ) nwl ON nwl.User_Login = u.User_Login  
 LEFT JOIN (  
  SELECT user_login  
   ,sum(CASE   
     WHEN cast(followupdate as date) < cast(getdate() as date)  
      AND isnull(f.IsConvert, 0) <> 1  
      THEN 1  
     ELSE 0  
     END) AS LeadsOverDue  
   ,count(1) TotalLeadsAssignedCurrently  
  FROM userleads u(NOLOCK)  
  JOIN user_detail(NOLOCK) ul ON ul.User_ID = u.AssignedTo  
  LEFT JOIN FollowUp_Status(NOLOCK) f ON f.id = u.FollowUpStatus  
  WHERE u.parentid = @parentid  
  GROUP BY user_login  
  ) OD ON OD.User_Login = u.User_Login  
 LEFT JOIN (  
  SELECT user_login  
   ,count(1) AS UntouchedLeads  
  FROM userleads u(NOLOCK)  
  JOIN user_detail(NOLOCK) ul ON u.AssignedTo = ul.User_ID  
  WHERE u.parentid = @parentid  
   AND (  
    isnull(LastFollowupCreatedBy, 0) = 0  
    OR NOT EXISTS (  
     SELECT 1  
     FROM #leadinteractionhistoryWithdatrange(NOLOCK)  
     WHERE isreassign = 0  
      AND leadno = u.leadno  
      AND parentid = u.parentid  
     )  
    )  
  GROUP BY user_login  
  ) UL ON UL.User_Login = u.User_Login  
 LEFT JOIN (  
  SELECT user_login  
   ,sum(CASE   
     WHEN l.createdby = User_ID  
      THEN 1  
     ELSE 0  
     END) AS UniqueLeadsFollowedUp  
   ,sum(TotalFollowupsMarked) TotalFollowupsMarked --,sum(case when l.createdby is null then 1 else 0 end) as UntouchedLeads                  
  FROM (  
   SELECT lih1.leadno  
    ,lih1.parentid  
    ,lih1.createdby  
    ,count(1) AS TotalFollowupsMarked  
   FROM #leadinteractionhistory(NOLOCK) as lih1  
   join followup_status(nolock) as fs1  
   on lih1.FollowUpStatus = fs1.ID  
    WHERE lih1.parentid = @parentid  
    AND lih1.IsReassign = 0  
    AND cast(lih1.createdon as date) BETWEEN @fromdate  
     AND @todate  
                And isnull(fs1.IsConvert,0) <> 1      
   GROUP BY leadno  
    ,lih1.parentid  
    ,lih1.createdby  
   ) l  
  JOIN user_detail(NOLOCK) ul ON ul.User_ID = l.createdby  
  WHERE l.parentid = @parentid  
  GROUP BY User_Login  
  ) LF ON u.user_login = LF.User_Login  
 WHERE u.parentid = @parentid  
  AND (  
   u.User_ID IN (  
    CASE   
     WHEN @IsAdmin = 1  
      THEN u.User_ID  
     END  
    )  
   OR u.User_ID IN (  
    SELECT User_ID  
    FROM @tbluser  
    )  
   )  
  
drop table if exists #leadinteractionhistory  
drop table if exists #leadinteractionhistoryWithdatrange  
 SELECT *  
 INTO #followup_status  
 FROM followup_status(NOLOCK) f  
 WHERE isactive = 1  
  AND isnull(parentid, @parentid) = @parentid  
  AND id = (  
   SELECT max(id)  
   FROM followup_status(nolock)  
   WHERE FollowupStatus = f.FollowupStatus  
    AND isactive = 1  
    AND isnull(parentid, @parentid) = @parentid  
    and isnull(IsConvert,0) <> 1  
   )  
  
 DECLARE @listtopivot NVARCHAR(max)  
  ,@sql NVARCHAR(max)  
  
 SELECT @listtopivot = coalesce(@listtopivot + ',', '') + '[' + FollowUpStatus + ']'  
 FROM #followup_status(NOLOCK) where FollowupStatus != ''  
  
 --where parentid=@parentid and IsActive=1  and isdisabled=0                    
 SELECT @sql = 'SELECT * FROM (                          
   select    ul.User_ID, user_login,f.followupstatus,                  
   sum(case when l.createdby=User_ID and l.followupstatus=f.id then 1 else 0 end) as Count      
    , ul.User_Login + '' ('' + isnull(ul.FName,'''') + '' '' + isnull(ul.LName,'''') + '')'' as UserByName                          
   from leadinteractionhistory(nolock) l                     
   join user_detail(nolock) ul on ul.User_ID=l.createdby                    
   join #followup_status(nolock) f on f.ID=l.FollowUpStatus                   
   where l.parentid=' + cast(@parentid AS NVARCHAR) + ' and IsReassign=0                   
   and cast(createdon as date) between ''' + cast(@fromdate AS NVARCHAR) + ''' and ''' + cast(@todate AS NVARCHAR) + '''            
               
    and (ul.User_ID in ( case when ''' + CAST(@IsAdmin AS NVARCHAR) + ''' = ''1'' then ul.User_ID            
       end             
       )            
      or     
       ul.User_ID in ((select * from STRING_SPLIT(''' + isnull(  
   @UserIdTeamLst, '') + ''', '','')))     
   )     
            
                     
   group by ul.User_ID,user_login,f.followupstatus,ul.FName,ul.LName      )                   
   FollowupsDone                        
   PIVOT (                  
   SUM([Count])                          
   FOR [followupstatus]                          
   IN ( ' + @listtopivot + '                  
   )                  
   ) AS PivotTable'  
  
 PRINT @sql  
  
 EXEC (@sql)  
  
 SELECT u.User_ID  
  ,u.user_login  
  ,u.User_Login + ' (' + isnull(u.FName, '') + ' ' + isnull(u.LName, '') + ')' AS UserByName  
  ,isnull(NewAdded, 0) NewAdded  
  ,isnull(Deleted, 0) Deleted  
  ,isnull(Expired, 0) Expired  
  ,isnull(Won, 0) Won  
  ,isnull(Lost, 0) Lost  
  ,isnull(AverageDaysToWin, 0) AverageDaysToWin  
  ,isnull(CurrentlyinPipeline, 0) CurrentlyinPipeline  
  ,ISNULL(Stagnant, 0) AS Stagnant  
 FROM user_detail(NOLOCK) u  
 LEFT JOIN (  
  SELECT user_login  
   ,sum(CASE   
     WHEN cast(createddate as date) BETWEEN @fromdate  
       AND @todate  
      THEN 1  
     ELSE 0  
     END) AS NewAdded  
   ,sum(CASE   
     WHEN cast(DeletedOn as date) BETWEEN @fromdate  
       AND @todate  
      THEN 1  
     ELSE 0  
     END) AS Deleted  
  --FROM LeadPipelineMapping_earliest(NOLOCK) l  
  FROM LeadPipelineMapping_latest(NOLOCK) l  
  JOIN user_detail(NOLOCK) u ON u.user_id = l.CreatedBy  
  WHERE parentid = @parentid  
  GROUP BY user_login  
  ) ND ON ND.User_Login = u.user_login  
 LEFT JOIN (  
  SELECT user_login  
   ,sum(CASE   
     WHEN cast(lpm.createddate as date) BETWEEN @fromdate  
       AND @todate  
      AND PS.Name = 'Won'  
      THEN 1  
     ELSE 0  
     END) AS Won  
   ,sum(CASE   
     WHEN cast(lpm.createddate as date) BETWEEN @fromdate  
       AND @todate  
      AND PS.Name = 'Lost'  
      THEN 1  
     ELSE 0  
     END) AS Lost  
   ,sum(CASE   
     WHEN datediff(d, lpm.createddate, getdate()) >= 30  
      AND PS.name NOT IN (  
       'won'  
       ,'Lost'  
       )  
      AND lpm.IsDeleted = 0  
      THEN 1  
     ELSE 0  
     END) AS Stagnant  
   ,sum(CASE   
     WHEN PS.name NOT IN (  
       'won'  
       ,'Lost'  
       )  
      AND lpm.IsDeleted = 0  
      THEN 1  
     ELSE 0  
     END) AS CurrentlyinPipeline  
   ,sum(CASE   
     WHEN datediff(d, l.createddate, lpm.createddate) > pm.DealExpiry  
      THEN 1  
     ELSE 0  
     END) AS Expired  
   ,avg(CASE   
     WHEN PS.Name = 'Won'  
      AND l.leadid IS NOT NULL  
      THEN datediff(d, l.createddate, lpm.createddate)  
     ELSE - 1  
     END) AverageDaysToWin  
  FROM LeadPipelineMapping_latest(NOLOCK) lpm  
  INNER JOIN Pipeline_Master AS PM WITH (NOLOCK) ON LPM.PipelineID = PM.ID  
  INNER JOIN PipelineStages AS PS WITH (NOLOCK) ON LPM.PipeLineStage = PS.ID  
  LEFT JOIN (  
   SELECT leadid  
    ,createddate  
   --FROM LeadPipelineMapping_earliest(NOLOCK)  
   FROM LeadPipelineMapping_latest(NOLOCK)  
   WHERE isdeleted = 0  
   ) l ON l.leadid = lpm.LeadID  
  JOIN user_detail(NOLOCK) u ON u.user_id = lpm.DealOwner  
  WHERE pm.parentid = @parentid  
  GROUP BY user_login  
  ) wl ON wl.User_Login = u.User_Login  
 WHERE u.parentID = @parentid  
  AND (  
   u.User_ID IN (  
    CASE   
     WHEN @IsAdmin = 1  
      THEN u.User_ID  
       --else @UserIdTeamLst             
     END  
    )  
   OR u.User_ID IN (  
    SELECT User_ID  
    FROM @tbluser  
    )  
   )  
  AND u.STATUS = 1  
  
 SELECT u.User_ID  
  ,u.user_login  
  ,u.User_Login + ' (' + isnull(u.FName, '') + ' ' + isnull(u.LName, '') + ')' AS UserByName  
  ,Pipeline  
  ,isnull(NewAdded, 0) NewAdded  
  ,isnull(Deleted, 0) Deleted  
  ,isnull(Expired, 0) Expired  
  ,isnull(Won, 0) Won  
  ,isnull(Lost, 0) Lost  
  ,isnull(AverageDaysToWin, 0) AverageDaysToWin  
  ,isnull(CurrentlyinPipeline, 0) CurrentlyinPipeline  
  ,ISNULL(Stagnant, 0) Stagnant  
 FROM user_detail(NOLOCK) u  
 LEFT JOIN (  
  SELECT id  
   ,name AS Pipeline  
   ,ParentID  
  FROM Pipeline_Master(NOLOCK)  
  WHERE parentid = @parentid  
   AND isdeleted = 0  
  ) p ON p.parentid = u.ParentID  
 LEFT JOIN (  
  SELECT user_login  
   ,pm.Name AS PipelineN  
   ,sum(CASE   
     WHEN cast(l.createddate as date) BETWEEN @fromdate  
       AND @todate  
      THEN 1  
     ELSE 0  
     END) AS NewAdded  
   ,sum(CASE   
     WHEN cast(DeletedOn as date) BETWEEN @fromdate  
       AND @todate  
      THEN 1  
     ELSE 0  
     END) AS Deleted  
  --FROM LeadPipelineMapping_earliest(NOLOCK) l  
  FROM LeadPipelineMapping_latest(NOLOCK) l  
  INNER JOIN Pipeline_Master AS PM WITH (NOLOCK) ON L.PipelineID = PM.ID  
  JOIN user_detail(NOLOCK) u ON u.user_id = l.CreatedBy  
  WHERE u.parentid = @parentid  
  GROUP BY user_login  
   ,pm.Name  
  ) ND ON ND.User_Login = u.user_login  
  AND ND.PipelineN = p.pipeline  
 LEFT JOIN (  
  SELECT user_login  
   ,pm.Name AS PipelineN  
   ,sum(CASE   
     WHEN cast( lpm.createddate as date) BETWEEN @fromdate  
       AND @todate  
      AND PS.Name = 'Won'  
      THEN 1  
     ELSE 0  
     END) AS Won  
   ,sum(CASE   
     WHEN  cast(lpm.createddate as date) BETWEEN @fromdate  
       AND @todate  
      AND PS.Name = 'Lost'  
      THEN 1  
     ELSE 0  
     END) AS Lost  
   ,sum(CASE   
     WHEN datediff(d, lpm.createddate, getdate()) >= 30  
      AND PS.name NOT IN (  
       'won'  
       ,'Lost'  
       )  
      AND lpm.IsDeleted = 0  
      THEN 1  
     ELSE 0  
     END) AS Stagnant  
   ,sum(CASE   
     WHEN PS.name NOT IN (  
       'won'  
       ,'Lost'  
       )  
      AND lpm.IsDeleted = 0  
      THEN 1  
     ELSE 0  
     END) AS CurrentlyinPipeline  
   ,  
   --sum(case when datediff(d,l.createddate,lpm.createddate)>pm.DealExpiry then 1 else 0 end) as Expired,        
   sum(CASE   
     WHEN datediff(DAY, getdate(), lpm.EstimatedClosureDate) <= 0  
      THEN 1  
     ELSE 0  
     END) AS Expired  
   ,avg(CASE   
     WHEN PS.Name = 'Won'  
      AND l.leadid IS NOT NULL  
      THEN datediff(d, l.createddate, lpm.createddate)  
     ELSE - 1  
     END) AverageDaysToWin  
  FROM LeadPipelineMapping_latest(NOLOCK) lpm  
  INNER JOIN Pipeline_Master AS PM WITH (NOLOCK) ON LPM.PipelineID = PM.ID  
  INNER JOIN PipelineStages AS PS WITH (NOLOCK) ON LPM.PipeLineStage = PS.ID  
  LEFT JOIN (  
   SELECT leadid  
    ,createddate  
   --FROM LeadPipelineMapping_earliest(NOLOCK)  
   FROM LeadPipelineMapping_latest(NOLOCK)  
   WHERE isdeleted = 0  
   ) l ON l.leadid = lpm.LeadID  
  JOIN user_detail(NOLOCK) u ON u.user_id = lpm.DealOwner  
  WHERE pm.parentid = @parentid  
  GROUP BY user_login  
   ,pm.Name  
  ) wl ON wl.User_Login = u.User_Login  
  AND wl.PipelineN = p.Pipeline  
 WHERE u.parentID = @parentid  
  AND (  
   u.User_ID IN (  
    CASE   
     WHEN @IsAdmin = 1  
      THEN u.User_ID  
       --else @UserIdTeamLst             
     END  
    )  
   OR u.User_ID IN (  
    SELECT User_ID  
    FROM @tbluser  
    )  
   )  
  AND u.STATUS = 1  
 ORDER BY u.User_Login  
  
 EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @userid  
  ,@Activity_type = 'View_Rpt_Lead'  
  ,@ActionType = 'S'  
  ,@RowJson = ''  
  ,@Table_name = 'Userleads and LeadPipelineMapping_latest'  
  
  
   drop table if exists #followup_statusTemp  
      drop table if exists #followup_status  
   drop table if exists #leadinteractionhistory  
   drop table if exists #leadinteractionhistoryWithdatrange  
END  


GO

/* ============================================================
   Procedure: [dbo].[usp_getleadreport$]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_getleadreport$] --32222,32222,'20220101','20220405'                
@userid bigint,@parentid bigint,@fromdate date,@todate date                
as                
begin                
                
     declare @tbluser table (User_ID bigint,Name varchar(100), Image varchar(100))          
  declare @IsAdmin bit = 0          
  select @IsAdmin = IsAdmin from User_Detail(nolock) where User_ID = @Userid          
  if(@IsAdmin = 1)          
  begin          
   --set @Userid = 0;          
   insert into @tbluser          
   exec Use_GetUserDetails @ParentId          
  end          
  else          
  Begin          
   insert into @tbluser          
   exec Use_GetUserDetails @UserId          
  End          
          
  Declare @TeamCode varchar(10) = ''          
  Declare @ScopeCode varchar(10) = ''           
  Declare @UserIdTeamLst varchar(4000) = ''           
  Declare @HierarchyJSON varchar(Max) = ''          
          
  select @UserIdTeamLst=isnull(STRING_AGG(User_ID,','),'') From @tbluser          
          
  print '@UserIdTeamLst: ' + @UserIdTeamLst          
          
          
          
          
declare @listtopivot nvarchar(max),@sql nvarchar(max)                
select @listtopivot=coalesce(@listtopivot+',','')+'['+FollowUpStatus+']' from followup_status(nolock)                
where parentid=@parentid and IsActive=1  and isdisabled=0                  
                
select u.user_id,u.user_login,isnull(NewLeadsAdded,0) NewLeadsAdded,isnull(TotalLeadsAssignedCurrently,0) TotalLeadsAssignedCurrently,isnull(UniqueLeadsFollowedUp,0) UniqueLeadsFollowedUp,                
isnull(TotalFollowupsMarked,0) TotalFollowupsMarked,                
isnull(UntouchedLeads,0) UntouchedLeads,isnull(LeadsOverDue,0) LeadsOverDue , u.User_Login + ' (' + isnull(u.FName,'') + ' ' + isnull(u.LName,'') + ')' as UserByName                 
from                
user_detail(nolock) u                 
left join                
(select user_login,sum(case when u.createdon between @fromdate and @todate then 1 else 0 end) as NewLeadsAdded                
from userleads u(nolock)                
join user_detail(nolock) ul on ul.User_ID=u.CreatedBy                
where u.parentid=@parentid                
group by user_login                
) nwl                
on nwl.User_Login=u.User_Login                
left join                 
(select user_login,sum(case when followupdate<getdate() then 1 else 0 end) as LeadsOverDue,count(1) TotalLeadsAssignedCurrently                
from userleads u(nolock)                 
join user_detail(nolock) ul on ul.User_ID=u.AssignedTo                
where u.parentid=@parentid                
group by user_login) OD                
on OD.User_Login=u.User_Login                 
left join                
(select user_login,count(1) as UntouchedLeads                
from userleads u(nolock)                 
join user_detail(nolock) ul on u.AssignedTo=ul.User_ID                
where u.parentid=@parentid and                 
(isnull(LastFollowupCreatedBy,0)=0                
 or not exists (select 1 from leadinteractionhistory(nolock) where isreassign=0                
 and leadno=u.leadno and parentid=u.parentid                
 ))                
group by user_login) UL                
on UL.User_Login=u.User_Login                 
left join                 
(select user_login,sum(case when l.createdby=User_ID then 1 else 0 end) as UniqueLeadsFollowedUp,                
sum(TotalFollowupsMarked) TotalFollowupsMarked--,sum(case when l.createdby is null then 1 else 0 end) as UntouchedLeads                
from                 
(select leadno,parentid,createdby,                
count(1)                
as TotalFollowupsMarked                
from leadinteractionhistory(nolock) where parentid=@parentid and IsReassign=0 and createdon between @fromdate and @todate                
group by leadno,parentid,createdby)                
l join user_detail(nolock) ul on ul.User_ID=l.createdby                
where l.parentid=@parentid    
group by User_Login) LF                 
on u.user_login=LF.User_Login                
where u.parentid=@parentid                
   and u.User_ID in ( case when @IsAdmin = 1 then u.User_ID          
                      else @UserIdTeamLst           
       end           
                    )            
  select  * into #followup_status from followup_status(nolock) f      
where isactive=1 and isnull(parentid,@parentid)=@parentid and id=      
(select max(id) from followup_status where FollowupStatus=f.FollowupStatus and isactive=1 and isnull(parentid,@parentid)=@parentid)      
         
                
select @sql=                
'SELECT * FROM (                        
   select    ul.User_ID, user_login,f.followupstatus,                
   sum(case when l.createdby=User_ID and l.followupstatus=f.id then 1 else 0 end) as Count    
    , ul.User_Login + '' ('' + isnull(ul.FName,'''') + '' '' + isnull(ul.LName,'''') + '')'' as UserByName                        
   from leadinteractionhistory(nolock) l                   
   join user_detail(nolock) ul on ul.User_ID=l.createdby                  
   join #followup_status(nolock) f on f.ID=l.FollowUpStatus                 
   where l.parentid='+cast(@parentid as nvarchar)+' and IsReassign=0                 
   and createdon between '''+cast(@fromdate as nvarchar)+''' and '''                
   +cast(@todate as nvarchar)+'''          
             
    and ul.User_ID in ( case when '+ CAST(@IsAdmin as nvarchar) + ' = ''1'' then ul.User_ID          
                      else ''' + isnull( @UserIdTeamLst,'') + '''           
       end           
                    )            
          
                   
   group by ul.User_ID,user_login,f.followupstatus,ul.FName,ul.LName      )                 
   FollowupsDone                      
   PIVOT (                
   SUM([Count])                        
   FOR [followupstatus]                        
   IN ( '+@listtopivot+'                
   )                
   ) AS PivotTable'                
          
  print @sql                   
   exec (@sql)                
             
   select u.User_ID,u.user_login  , u.User_Login + ' (' + isnull(u.FName,'') + ' ' + isnull(u.LName,'') + ')' as UserByName   ,isnull(NewAdded,0) NewAdded,isnull(Deleted,0) Deleted, isnull(Expired,0) Expired,isnull(Won,0) Won,                
isnull(Lost,0) Lost,isnull(AverageDaysToWin,0) AverageDaysToWin,isnull(CurrentlyinPipeline,0) CurrentlyinPipeline, ISNULL(Stagnant,0) as Stagnant                
from                
user_detail(nolock) u                 
left join                
(                
select user_login,                 
sum(case when createddate between @fromdate and @todate then 1 else 0 end) as NewAdded,                
sum(case when DeletedOn between @fromdate and @todate then 1 else 0 end) as Deleted                
from LeadPipelineMapping_earliest(nolock) l                
join user_detail(nolock) u on u.user_id=l.CreatedBy                
where parentid=@parentid                
group by user_login                 
) ND on ND.User_Login=u.user_login                
left join                
(                
select user_login,                 
sum(case when lpm.createddate between @fromdate and @todate and PS.Name='Won' then 1 else 0 end) as Won,                
sum(case when lpm.createddate between @fromdate and @todate and PS.Name='Lost' then 1 else 0 end) as Lost,                
sum(case when datediff(d,lpm.createddate,getdate())>=30 and PS.name not in ('won','Lost') and lpm.IsDeleted=0 then 1 else 0 end) as Stagnant,                
sum(case when PS.name not in ('won','Lost') and lpm.IsDeleted=0 then 1 else 0 end) as CurrentlyinPipeline,                
sum(case when datediff(d,l.createddate,lpm.createddate)>pm.DealExpiry then 1 else 0 end) as Expired,                
avg(case when PS.Name='Won' and l.leadid is not null then datediff(d,l.createddate,lpm.createddate)                
else -1 end) AverageDaysToWin                
from LeadPipelineMapping_latest(nolock) lpm          
INNER JOIN Pipeline_Master AS PM WITH (nolock)                 
ON  LPM.PipelineID = PM.ID INNER JOIN PipelineStages AS PS WITH (nolock)                 
ON  LPM.PipeLineStage = PS.ID                
left join (select leadid,createddate from LeadPipelineMapping_earliest(nolock) where isdeleted=0) l on l.leadid=lpm.LeadID                
join user_detail(nolock) u on u.user_id=lpm.DealOwner                
where pm.parentid=@parentid                
group by user_login                 
) wl on wl.User_Login=u.User_Login                
where u.parentID=@parentid           
 and u.User_ID in ( case when @IsAdmin = 1 then u.User_ID          
                    else @UserIdTeamLst           
        end           
                  )           
  and u.status=1                
                
select u.User_ID,u.user_login , u.User_Login + ' (' + isnull(u.FName,'') + ' ' + isnull(u.LName,'') + ')' as UserByName ,Pipeline,isnull(NewAdded,0) NewAdded,isnull(Deleted,0) Deleted, isnull(Expired,0) Expired,isnull(Won,0) Won,                
isnull(Lost,0) Lost,isnull(AverageDaysToWin,0) AverageDaysToWin,isnull(CurrentlyinPipeline,0) CurrentlyinPipeline, ISNULL(Stagnant,0) Stagnant                
from                
user_detail(nolock) u                 
left join                
(select id,name as Pipeline,ParentID from Pipeline_Master(nolock) where parentid=@parentid                
and isdeleted=0) p                
on p.parentid=u.ParentID                
left join                
(                
select user_login,pm.Name as PipelineN,                 
sum(case when l.createddate between @fromdate and @todate then 1 else 0 end) as NewAdded,                
sum(case when DeletedOn between @fromdate and @todate then 1 else 0 end) as Deleted                
from LeadPipelineMapping_earliest(nolock) l                
INNER JOIN Pipeline_Master AS PM WITH (nolock)                 
ON  L.PipelineID = PM.ID                 
join user_detail(nolock) u on u.user_id=l.CreatedBy                
where u.parentid=@parentid                 
group by user_login ,pm.Name                
) ND on ND.User_Login=u.user_login and ND.PipelineN=p.pipeline                
left join                
(                
select user_login,pm.Name as PipelineN,                 
sum(case when lpm.createddate between @fromdate and @todate and PS.Name='Won' then 1 else 0 end) as Won,                
sum(case when lpm.createddate between @fromdate and @todate and PS.Name='Lost' then 1 else 0 end) as Lost,                
sum(case when datediff(d,lpm.createddate,getdate())>=30 and PS.name not in ('won','Lost') and lpm.IsDeleted=0 then 1 else 0 end) as Stagnant,                
sum(case when PS.name not in ('won','Lost') and lpm.IsDeleted=0 then 1 else 0 end) as CurrentlyinPipeline,                
--sum(case when datediff(d,l.createddate,lpm.createddate)>pm.DealExpiry then 1 else 0 end) as Expired,      
sum(case when datediff(DAY,getdate(),lpm.EstimatedClosureDate) <= 0 then 1 else 0 end) as Expired,                
avg(case when PS.Name='Won' and l.leadid is not null then datediff(d,l.createddate,lpm.createddate)                
else -1 end) AverageDaysToWin                
from LeadPipelineMapping_latest(nolock) lpm                
INNER JOIN Pipeline_Master AS PM WITH (nolock)                 
ON  LPM.PipelineID = PM.ID INNER JOIN PipelineStages AS PS WITH (nolock)                 
ON  LPM.PipeLineStage = PS.ID                
left join (select leadid,createddate from LeadPipelineMapping_earliest(nolock) where isdeleted=0) l on l.leadid=lpm.LeadID                
join user_detail(nolock) u on u.user_id=lpm.DealOwner                
where pm.parentid=@parentid                
group by user_login,pm.Name                 
) wl on wl.User_Login=u.User_Login and wl.PipelineN=p.Pipeline                
where u.parentID=@parentid          
 and u.User_ID in ( case when @IsAdmin = 1 then u.User_ID          
                      else @UserIdTeamLst           
       end           
                  )           
 and u.status=1                
order by u.User_Login                
                
end  



GO

/* ============================================================
   Procedure: [dbo].[usp_getleadreport_1]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_getleadreport_1] --39680,39680,'20221001','20221231'  --34149,34149,'20220721','20220722'                
	@userid BIGINT
	,@parentid BIGINT
	,@fromdate DATE
	,@todate DATE
AS
BEGIN
	--Declare @userid bigint=34594,@parentid bigint=34594,@fromdate date='2022-05-26',@todate date='2022-05-27'  
	--Admin 39680  
	--IsAdmin 40068  
	--Hirarchy Team head 40060  
	--User 40059  
	--Declare @userid bigint=40060,@parentid bigint=39680,@fromdate date='2022-05-26',@todate date='2022-05-27'  
	DECLARE @tbluser TABLE (
		User_ID BIGINT
		,Name VARCHAR(100)
		,IMAGE VARCHAR(100)
		)
	DECLARE @IsAdmin BIT = 0

	SELECT @IsAdmin = IsAdmin
	FROM User_Detail(NOLOCK)
	WHERE User_ID = @Userid

	IF (@IsAdmin = 1)
	BEGIN
		--set @Userid = 0;          
		INSERT INTO @tbluser
		EXEC Use_GetUserDetails @ParentId
	END
	ELSE
	BEGIN
		INSERT INTO @tbluser
		EXEC Use_GetUserDetails @UserId
	END

	DECLARE @TeamCode VARCHAR(10) = ''
	DECLARE @ScopeCode VARCHAR(10) = ''
	DECLARE @UserIdTeamLst VARCHAR(4000) = ''
	DECLARE @HierarchyJSON VARCHAR(Max) = ''

	SELECT @UserIdTeamLst = isnull(STRING_AGG(User_ID, ','), '')
	FROM @tbluser

	PRINT '@UserIdTeamLst: ' + @UserIdTeamLst

	IF OBJECT_ID(N'tempdb..#followup_status') IS NOT NULL
	BEGIN
		DROP TABLE #followup_status
	END

	select * into #leadinteractionhistory from LeadInteractionHistory(nolock) where parentid=@parentid and cast(CreatedOn as date) between @fromdate and @todate

	SELECT u.user_id
		,u.user_login
		,isnull(NewLeadsAdded, 0) NewLeadsAdded
		,isnull(TotalLeadsAssignedCurrently, 0) TotalLeadsAssignedCurrently
		,isnull(UniqueLeadsFollowedUp, 0) UniqueLeadsFollowedUp
		,isnull(TotalFollowupsMarked, 0) TotalFollowupsMarked
		,isnull(UntouchedLeads, 0) UntouchedLeads
		,isnull(LeadsOverDue, 0) LeadsOverDue
		,u.User_Login + ' (' + isnull(u.FName, '') + ' ' + isnull(u.LName, '') + ')' AS UserByName
	FROM user_detail(NOLOCK) u
	LEFT JOIN (
		SELECT user_login
			,sum(CASE 
					WHEN cast(u.createdon as date) BETWEEN @fromdate
							AND @todate
						THEN 1
					ELSE 0
					END) AS NewLeadsAdded
		FROM userleads u(NOLOCK)
		JOIN user_detail(NOLOCK) ul ON ul.User_ID = u.CreatedBy
		WHERE u.parentid = @parentid
		GROUP BY user_login
		) nwl ON nwl.User_Login = u.User_Login
	LEFT JOIN (
		SELECT user_login
			,sum(CASE 
					WHEN cast(followupdate as date) < cast(getdate() as date)
						AND isnull(f.IsConvert, 0) <> 1
						THEN 1
					ELSE 0
					END) AS LeadsOverDue
			,count(1) TotalLeadsAssignedCurrently
		FROM userleads u(NOLOCK)
		JOIN user_detail(NOLOCK) ul ON ul.User_ID = u.AssignedTo
		LEFT JOIN FollowUp_Status(NOLOCK) f ON f.id = u.FollowUpStatus
		WHERE u.parentid = @parentid
		GROUP BY user_login
		) OD ON OD.User_Login = u.User_Login
	LEFT JOIN (
		SELECT user_login
			,count(1) AS UntouchedLeads
		FROM userleads u(NOLOCK)
		JOIN user_detail(NOLOCK) ul ON u.AssignedTo = ul.User_ID
		WHERE u.parentid = @parentid
			AND (
				isnull(LastFollowupCreatedBy, 0) = 0
				OR NOT EXISTS (
					SELECT 1
					FROM #leadinteractionhistory(NOLOCK)
					WHERE isreassign = 0
						AND leadno = u.leadno
						AND parentid = u.parentid
					)
				)
		GROUP BY user_login
		) UL ON UL.User_Login = u.User_Login
	LEFT JOIN (
		SELECT user_login
			,sum(CASE 
					WHEN l.createdby = User_ID
						THEN 1
					ELSE 0
					END) AS UniqueLeadsFollowedUp
			,sum(TotalFollowupsMarked) TotalFollowupsMarked --,sum(case when l.createdby is null then 1 else 0 end) as UntouchedLeads                
		FROM (
			SELECT lih1.leadno
				,lih1.parentid
				,lih1.createdby
				,count(1) AS TotalFollowupsMarked
			FROM #leadinteractionhistory(NOLOCK) as lih1
			join FollowUp_Status(nolock) as fs1
			on lih1.FollowUpStatus = fs1.ID
 			WHERE lih1.parentid = @parentid
				AND lih1.IsReassign = 0
				AND cast(lih1.createdon as date) BETWEEN @fromdate
					AND @todate
                And isnull(fs1.IsConvert,0) <> 1    
			GROUP BY leadno
				,lih1.parentid
				,lih1.createdby
			) l
		JOIN user_detail(NOLOCK) ul ON ul.User_ID = l.createdby
		WHERE l.parentid = @parentid
		GROUP BY User_Login
		) LF ON u.user_login = LF.User_Login
	WHERE u.parentid = @parentid
		AND (
			u.User_ID IN (
				CASE 
					WHEN @IsAdmin = 1
						THEN u.User_ID
					END
				)
			OR u.User_ID IN (
				SELECT User_ID
				FROM @tbluser
				)
			)

drop table if exists #leadinteractionhistory
	SELECT *
	INTO #followup_status
	FROM followup_status(NOLOCK) f
	WHERE isactive = 1
		AND isnull(parentid, @parentid) = @parentid
		AND id = (
			SELECT max(id)
			FROM followup_status
			WHERE FollowupStatus = f.FollowupStatus
				AND isactive = 1
				AND isnull(parentid, @parentid) = @parentid
			)

	DECLARE @listtopivot NVARCHAR(max)
		,@sql NVARCHAR(max)

	SELECT @listtopivot = coalesce(@listtopivot + ',', '') + '[' + FollowUpStatus + ']'
	FROM #followup_status(NOLOCK) where FollowupStatus != ''

	--where parentid=@parentid and IsActive=1  and isdisabled=0                  
	SELECT @sql = 'SELECT * FROM (                        
   select    ul.User_ID, user_login,f.followupstatus,                
   sum(case when l.createdby=User_ID and l.followupstatus=f.id then 1 else 0 end) as Count    
    , ul.User_Login + '' ('' + isnull(ul.FName,'''') + '' '' + isnull(ul.LName,'''') + '')'' as UserByName                        
   from leadinteractionhistory(nolock) l                   
   join user_detail(nolock) ul on ul.User_ID=l.createdby                  
   join #followup_status(nolock) f on f.ID=l.FollowUpStatus                 
   where l.parentid=' + cast(@parentid AS NVARCHAR) + ' and IsReassign=0                 
   and cast(createdon as date) between ''' + cast(@fromdate AS NVARCHAR) + ''' and ''' + cast(@todate AS NVARCHAR) + '''          
             
    and (ul.User_ID in ( case when ''' + CAST(@IsAdmin AS NVARCHAR) + ''' = ''1'' then ul.User_ID          
       end           
       )          
      or   
       ul.User_ID in ((select * from STRING_SPLIT(''' + isnull(
			@UserIdTeamLst, '') + ''', '','')))   
   )   
          
                   
   group by ul.User_ID,user_login,f.followupstatus,ul.FName,ul.LName      )                 
   FollowupsDone                      
   PIVOT (                
   SUM([Count])                        
   FOR [followupstatus]                        
   IN ( ' + @listtopivot + '                
   )                
   ) AS PivotTable'

	PRINT @sql

	EXEC (@sql)

	SELECT u.User_ID
		,u.user_login
		,u.User_Login + ' (' + isnull(u.FName, '') + ' ' + isnull(u.LName, '') + ')' AS UserByName
		,isnull(NewAdded, 0) NewAdded
		,isnull(Deleted, 0) Deleted
		,isnull(Expired, 0) Expired
		,isnull(Won, 0) Won
		,isnull(Lost, 0) Lost
		,isnull(AverageDaysToWin, 0) AverageDaysToWin
		,isnull(CurrentlyinPipeline, 0) CurrentlyinPipeline
		,ISNULL(Stagnant, 0) AS Stagnant
	FROM user_detail(NOLOCK) u
	LEFT JOIN (
		SELECT user_login
			,sum(CASE 
					WHEN cast(createddate as date) BETWEEN @fromdate
							AND @todate
						THEN 1
					ELSE 0
					END) AS NewAdded
			,sum(CASE 
					WHEN cast(DeletedOn as date) BETWEEN @fromdate
							AND @todate
						THEN 1
					ELSE 0
					END) AS Deleted
		FROM LeadPipelineMapping_earliest(NOLOCK) l
		JOIN user_detail(NOLOCK) u ON u.user_id = l.CreatedBy
		WHERE parentid = @parentid
		GROUP BY user_login
		) ND ON ND.User_Login = u.user_login
	LEFT JOIN (
		SELECT user_login
			,sum(CASE 
					WHEN cast(lpm.createddate as date) BETWEEN @fromdate
							AND @todate
						AND PS.Name = 'Won'
						THEN 1
					ELSE 0
					END) AS Won
			,sum(CASE 
					WHEN cast(lpm.createddate as date) BETWEEN @fromdate
							AND @todate
						AND PS.Name = 'Lost'
						THEN 1
					ELSE 0
					END) AS Lost
			,sum(CASE 
					WHEN datediff(d, lpm.createddate, getdate()) >= 30
						AND PS.name NOT IN (
							'won'
							,'Lost'
							)
						AND lpm.IsDeleted = 0
						THEN 1
					ELSE 0
					END) AS Stagnant
			,sum(CASE 
					WHEN PS.name NOT IN (
							'won'
							,'Lost'
							)
						AND lpm.IsDeleted = 0
						THEN 1
					ELSE 0
					END) AS CurrentlyinPipeline
			,sum(CASE 
					WHEN datediff(d, l.createddate, lpm.createddate) > pm.DealExpiry
						THEN 1
					ELSE 0
					END) AS Expired
			,avg(CASE 
					WHEN PS.Name = 'Won'
						AND l.leadid IS NOT NULL
						THEN datediff(d, l.createddate, lpm.createddate)
					ELSE - 1
					END) AverageDaysToWin
		FROM LeadPipelineMapping_latest(NOLOCK) lpm
		INNER JOIN Pipeline_Master AS PM WITH (NOLOCK) ON LPM.PipelineID = PM.ID
		INNER JOIN PipelineStages AS PS WITH (NOLOCK) ON LPM.PipeLineStage = PS.ID
		LEFT JOIN (
			SELECT leadid
				,createddate
			FROM LeadPipelineMapping_earliest(NOLOCK)
			WHERE isdeleted = 0
			) l ON l.leadid = lpm.LeadID
		JOIN user_detail(NOLOCK) u ON u.user_id = lpm.DealOwner
		WHERE pm.parentid = @parentid
		GROUP BY user_login
		) wl ON wl.User_Login = u.User_Login
	WHERE u.parentID = @parentid
		AND (
			u.User_ID IN (
				CASE 
					WHEN @IsAdmin = 1
						THEN u.User_ID
							--else @UserIdTeamLst           
					END
				)
			OR u.User_ID IN (
				SELECT User_ID
				FROM @tbluser
				)
			)
		AND u.STATUS = 1

	SELECT u.User_ID
		,u.user_login
		,u.User_Login + ' (' + isnull(u.FName, '') + ' ' + isnull(u.LName, '') + ')' AS UserByName
		,Pipeline
		,isnull(NewAdded, 0) NewAdded
		,isnull(Deleted, 0) Deleted
		,isnull(Expired, 0) Expired
		,isnull(Won, 0) Won
		,isnull(Lost, 0) Lost
		,isnull(AverageDaysToWin, 0) AverageDaysToWin
		,isnull(CurrentlyinPipeline, 0) CurrentlyinPipeline
		,ISNULL(Stagnant, 0) Stagnant
	FROM user_detail(NOLOCK) u
	LEFT JOIN (
		SELECT id
			,name AS Pipeline
			,ParentID
		FROM Pipeline_Master(NOLOCK)
		WHERE parentid = @parentid
			AND isdeleted = 0
		) p ON p.parentid = u.ParentID
	LEFT JOIN (
		SELECT user_login
			,pm.Name AS PipelineN
			,sum(CASE 
					WHEN cast(l.createddate as date) BETWEEN @fromdate
							AND @todate
						THEN 1
					ELSE 0
					END) AS NewAdded
			,sum(CASE 
					WHEN cast(DeletedOn as date) BETWEEN @fromdate
							AND @todate
						THEN 1
					ELSE 0
					END) AS Deleted
		FROM LeadPipelineMapping_earliest(NOLOCK) l
		INNER JOIN Pipeline_Master AS PM WITH (NOLOCK) ON L.PipelineID = PM.ID
		JOIN user_detail(NOLOCK) u ON u.user_id = l.CreatedBy
		WHERE u.parentid = @parentid
		GROUP BY user_login
			,pm.Name
		) ND ON ND.User_Login = u.user_login
		AND ND.PipelineN = p.pipeline
	LEFT JOIN (
		SELECT user_login
			,pm.Name AS PipelineN
			,sum(CASE 
					WHEN cast( lpm.createddate as date) BETWEEN @fromdate
							AND @todate
						AND PS.Name = 'Won'
						THEN 1
					ELSE 0
					END) AS Won
			,sum(CASE 
					WHEN  cast(lpm.createddate as date) BETWEEN @fromdate
							AND @todate
						AND PS.Name = 'Lost'
						THEN 1
					ELSE 0
					END) AS Lost
			,sum(CASE 
					WHEN datediff(d, lpm.createddate, getdate()) >= 30
						AND PS.name NOT IN (
							'won'
							,'Lost'
							)
						AND lpm.IsDeleted = 0
						THEN 1
					ELSE 0
					END) AS Stagnant
			,sum(CASE 
					WHEN PS.name NOT IN (
							'won'
							,'Lost'
							)
						AND lpm.IsDeleted = 0
						THEN 1
					ELSE 0
					END) AS CurrentlyinPipeline
			,
			--sum(case when datediff(d,l.createddate,lpm.createddate)>pm.DealExpiry then 1 else 0 end) as Expired,      
			sum(CASE 
					WHEN datediff(DAY, getdate(), lpm.EstimatedClosureDate) <= 0
						THEN 1
					ELSE 0
					END) AS Expired
			,avg(CASE 
					WHEN PS.Name = 'Won'
						AND l.leadid IS NOT NULL
						THEN datediff(d, l.createddate, lpm.createddate)
					ELSE - 1
					END) AverageDaysToWin
		FROM LeadPipelineMapping_latest(NOLOCK) lpm
		INNER JOIN Pipeline_Master AS PM WITH (NOLOCK) ON LPM.PipelineID = PM.ID
		INNER JOIN PipelineStages AS PS WITH (NOLOCK) ON LPM.PipeLineStage = PS.ID
		LEFT JOIN (
			SELECT leadid
				,createddate
			FROM LeadPipelineMapping_earliest(NOLOCK)
			WHERE isdeleted = 0
			) l ON l.leadid = lpm.LeadID
		JOIN user_detail(NOLOCK) u ON u.user_id = lpm.DealOwner
		WHERE pm.parentid = @parentid
		GROUP BY user_login
			,pm.Name
		) wl ON wl.User_Login = u.User_Login
		AND wl.PipelineN = p.Pipeline
	WHERE u.parentID = @parentid
		AND (
			u.User_ID IN (
				CASE 
					WHEN @IsAdmin = 1
						THEN u.User_ID
							--else @UserIdTeamLst           
					END
				)
			OR u.User_ID IN (
				SELECT User_ID
				FROM @tbluser
				)
			)
		AND u.STATUS = 1
	ORDER BY u.User_Login

	EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @userid
		,@Activity_type = 'View_Rpt_Lead'
		,@ActionType = 'S'
		,@RowJson = ''
		,@Table_name = 'Userleads and LeadPipelineMapping_earliest'
END



GO

/* ============================================================
   Procedure: [dbo].[usp_getleadreport_daywise]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_getleadreport_daywise] --31871,31871,'17-Jul-2023','22-Jul-2023'   --39680,39680,'20221001','20221231'  --34149,34149,'20220721','20220722'                      
  @userid BIGINT      
 ,@parentid BIGINT      
 ,@fromdate DATE      
 ,@todate DATE      
AS      
BEGIN      
 --Declare @userid bigint=34594,@parentid bigint=34594,@fromdate date='2022-05-26',@todate date='2022-05-27'        
 --Admin 39680        
 --IsAdmin 40068        
 --Hirarchy Team head 40060        
 --User 40059        
 --Declare @userid bigint=40060,@parentid bigint=39680,@fromdate date='2022-05-26',@todate date='2022-05-27'       
       
 drop table if exists #followup_statusTemp      
drop table if exists #followup_status      
 drop table if exists #leadinteractionhistory      
 drop table if exists #leadinteractionhistoryWithdatrange      
      
 /*      
 SELECT *      
 INTO #followup_statusTemp      
 FROM followup_status(NOLOCK) f      
 WHERE isactive = 1      
  AND isnull(parentid, @parentid) = @parentid      
  AND id = (      
   SELECT max(id)      
   FROM followup_status      
   WHERE FollowupStatus = f.FollowupStatus      
    AND isactive = 1      
    AND isnull(parentid, @parentid) = @parentid      
   )      
 */      
       
        
 DECLARE @tbluser TABLE (      
  User_ID BIGINT      
  ,Name VARCHAR(100)      
  ,IMAGE VARCHAR(100)      
  )      
 DECLARE @IsAdmin BIT = 0      
      
 SELECT @IsAdmin = IsAdmin      
 FROM User_Detail(NOLOCK)      
 WHERE User_ID = @Userid      
      
 IF (@IsAdmin = 1)      
 BEGIN      
  --set @Userid = 0;                
  INSERT INTO @tbluser      
  EXEC Use_GetUserDetails @ParentId      
 END      
 ELSE      
 BEGIN      
  INSERT INTO @tbluser      
  EXEC Use_GetUserDetails @UserId      
 END      
      
 DECLARE @TeamCode VARCHAR(10) = ''      
 DECLARE @ScopeCode VARCHAR(10) = ''      
 DECLARE @UserIdTeamLst VARCHAR(4000) = ''      
 DECLARE @HierarchyJSON VARCHAR(Max) = ''      
      
 SELECT @UserIdTeamLst = isnull(STRING_AGG(User_ID, ','), '')      
 FROM @tbluser      
      
 PRINT '@UserIdTeamLst: ' + @UserIdTeamLst      
      
 IF OBJECT_ID(N'tempdb..#followup_status') IS NOT NULL      
 BEGIN      
  DROP TABLE #followup_status      
 END      
      
 select * into #leadinteractionhistory from LeadInteractionHistory(nolock) where parentid=@parentid and cast(CreatedOn as date) between @fromdate and @todate      
 select * into #leadinteractionhistoryWithdatrange from LeadInteractionHistory(nolock) where parentid=@parentid     
 --and cast(CreatedOn as date) between @fromdate and @todate        
      
      
 SELECT u.user_id      
  ,u.user_login      
  ,isnull(NewLeadsAdded, 0) NewLeadsAdded      
  ,isnull(TotalLeadsAssignedCurrently, 0) TotalLeadsAssignedCurrently      
  ,isnull(UniqueLeadsFollowedUp, 0) UniqueLeadsFollowedUp      
  ,isnull(TotalFollowupsMarked, 0) TotalFollowupsMarked  
   ,isnull(TotalFollowupsDue, 0) TotalFollowupsDue      
    ,isnull(TotalFollowupsDonefromDue, 0) TotalFollowupsDonefromDue      
  ,isnull(UntouchedLeads, 0) UntouchedLeads      
  ,isnull(LeadsOverDue, 0) LeadsOverDue      
  ,u.User_Login + ' (' + isnull(u.FName, '') + ' ' + isnull(u.LName, '') + ')' AS UserByName      
 FROM user_detail(NOLOCK) u      
 LEFT JOIN (      
  SELECT user_login      
   ,sum(CASE       
     WHEN cast(u.createdon as date) BETWEEN @fromdate      
       AND @todate      
      THEN 1      
     ELSE 0      
     END) AS NewLeadsAdded      
  FROM userleads u(NOLOCK)      
  JOIN user_detail(NOLOCK) ul ON ul.User_ID = u.CreatedBy      
  WHERE u.parentid = @parentid      
  GROUP BY user_login      
  ) nwl ON nwl.User_Login = u.User_Login      
 LEFT JOIN (      
  SELECT user_login      
   ,sum(CASE       
     WHEN cast(followupdate as date) < cast(getdate() as date)      
      AND isnull(f.IsConvert, 0) <> 1      
      THEN 1      
     ELSE 0      
     END) AS LeadsOverDue      
   ,count(1) TotalLeadsAssignedCurrently      
  FROM userleads u(NOLOCK)      
  JOIN user_detail(NOLOCK) ul ON ul.User_ID = u.AssignedTo      
  LEFT JOIN FollowUp_Status(NOLOCK) f ON f.id = u.FollowUpStatus      
  WHERE u.parentid = @parentid      
  GROUP BY user_login      
  ) OD ON OD.User_Login = u.User_Login      
 LEFT JOIN (      
  SELECT user_login      
   ,count(1) AS UntouchedLeads      
  FROM userleads u(NOLOCK)      
  JOIN user_detail(NOLOCK) ul ON u.AssignedTo = ul.User_ID      
  WHERE u.parentid = @parentid      
   AND (      
    isnull(LastFollowupCreatedBy, 0) = 0      
    OR NOT EXISTS (      
     SELECT 1      
     FROM #leadinteractionhistoryWithdatrange(NOLOCK)      
     WHERE isreassign = 0      
      AND leadno = u.leadno      
      AND parentid = u.parentid      
     )      
    )      
  GROUP BY user_login      
  ) UL ON UL.User_Login = u.User_Login      
 LEFT JOIN (      
  SELECT user_login      
   ,sum(CASE       
     WHEN l.createdby = User_ID      
      THEN 1      
     ELSE 0      
     END) AS UniqueLeadsFollowedUp      
   ,sum(TotalFollowupsMarked) TotalFollowupsMarked --,sum(case when l.createdby is null then 1 else 0 end) as UntouchedLeads                      
  FROM (      
   SELECT lih1.leadno      
    ,lih1.parentid      
    ,lih1.createdby      
    ,count(1) AS TotalFollowupsMarked      
   FROM #leadinteractionhistory(NOLOCK) as lih1      
   join followup_status(nolock) as fs1      
   on lih1.FollowUpStatus = fs1.ID      
    WHERE lih1.parentid = @parentid      
    AND lih1.IsReassign = 0      
    AND cast(lih1.createdon as date) BETWEEN @fromdate      
     AND @todate      
                And isnull(fs1.IsConvert,0) <> 1          
   GROUP BY leadno      
    ,lih1.parentid      
    ,lih1.createdby      
   ) l      
  JOIN user_detail(NOLOCK) ul ON ul.User_ID = l.createdby      
  WHERE l.parentid = @parentid      
  GROUP BY User_Login      
  ) LF ON u.user_login = LF.User_Login   
  LEFT JOIN (      
  SELECT user_login      
      ,sum(TotalFollowupsDue) TotalFollowupsDue   
   ,   sum(TotalFollowupsDonefromDue) as TotalFollowupsDonefromDue                      
  FROM (      
   SELECT lih1.leadno      
    ,lih1.parentid      
    ,lih1.AssignedTo      
    ,count(1) AS TotalFollowupsDue  
 ,sum(dbo.fn_isleadfollowed_withrange(lih1.id,@fromdate,@todate)) TotalFollowupsDonefromDue  
   FROM #leadinteractionhistoryWithdatrange(NOLOCK) as lih1      
   join followup_status(nolock) as fs1      
   on lih1.FollowUpStatus = fs1.ID  
    WHERE lih1.parentid = @parentid      
     AND cast(lih1.FollowupDate as date) BETWEEN @fromdate      
     AND @todate      
     And isnull(fs1.IsConvert,0) <> 1          
   GROUP BY leadno      
    ,lih1.parentid      
    ,lih1.AssignedTo      
   ) l      
  JOIN user_detail(NOLOCK) ul ON ul.User_ID = l.AssignedTo      
  WHERE l.parentid = @parentid      
  GROUP BY User_Login      
  ) LTF ON u.user_login = LTF.User_Login      
  
  
  
 WHERE u.parentid = @parentid      
  AND (      
   u.User_ID IN (      
    CASE       
     WHEN @IsAdmin = 1      
      THEN u.User_ID      
     END      
    )      
   OR u.User_ID IN (      
    SELECT User_ID      
    FROM @tbluser      
    )      
   )      
  
 SELECT cast(c.start_dts as date) as Date,u.user_id      
  ,u.user_login     
 ,count(1) FollowupsDue      
 ,sum(dbo.fn_isleadfollowed(lih.id)) FollowupsDoneTillDate   
 ,sum(dbo.fn_isleadfollowed_withrange(lih.id,@fromdate,@fromdate)) FollowupsDoneInTime
 ,sum(dbo.fn_isleadfollowedbyothers(lih.id)) FollowedUpByOthers
 ,sum(dbo.fn_isleadnotfollowedtilldate(lih.id)) NotFollowedTillDate
 ,u.User_Login + ' (' + isnull(u.FName, '') + ' ' + isnull(u.LName, '') + ')' AS UserByName      
 FROM user_detail(NOLOCK) u      
 LEFT JOIN   
 #leadinteractionhistoryWithdatrange(NOLOCK)  lih on lih.assignedto=u.user_id  
 left join FollowUp_Status (nolock) f on f.id=lih.FollowUpStatus
 left join calendar (nolock) c on cast(c.start_dts as date)=cast(lih.followupdate as date)  
 WHERE isreassign = 0  and lih.FollowupDate is not null  
  AND (u.User_ID IN (CASE WHEN @IsAdmin = 1 THEN u.User_ID END)      
   OR u.User_ID IN (SELECT User_ID  FROM @tbluser ))      
 and cast(c.start_dts as date) between @fromdate and @todate  
 and f.IsCallback=1
  GROUP BY user_id,user_login ,cast(c.start_dts as date),u.FName,u.LName     
   
  
  
  
  
      
drop table if exists #leadinteractionhistory      
drop table if exists #leadinteractionhistoryWithdatrange      
  
  
select cast(c.date_id as date) as CreatedDate,user_login as Executive,count(1) TotalCreated  
,sum(case when t.Status='completed' then 1 else 0 end) as CompletedTillDate  
,sum(case when t.Status='completed' and cast(completedon as date)<=cast(t.enddate as date) then 1 else 0 end) as CompletedInTime  
,sum(case when t.status='Open' then 1 else 0 end) as [Open]  
 ,u.User_Login + ' (' + isnull(u.FName, '') + ' ' + isnull(u.LName, '') + ')' AS UserByName      
from [dbo].[tbl_tsk_TaskHistory] t with (nolock) 
join user_detail u with (nolock) on t.createdby=u.User_ID 
right join calendar c with (nolock) on cast(c.date_id as date)=cast(t.createdon as date)
where u.parentid=@parentid and cast(c.date_id as date) BETWEEN @fromdate AND @todate 
and istask=1  
 AND (u.User_ID IN (CASE WHEN @IsAdmin = 1 THEN u.User_ID END)      
   OR u.User_ID IN (SELECT User_ID  FROM @tbluser ))      
group by user_login,cast(c.date_id as date),u.FName,u.LName,createdby     
  
  select cast(c.date_id as date) as CreatedDate,user_login as Executive,count(1) TotalCreated  
,sum(case when t.Status='completed' then 1 else 0 end) as CompletedTillDate  
,sum(case when t.Status='completed' and cast(completedon as date)<=cast(t.enddate as date) then 1 else 0 end) as CompletedInTime  
,sum(case when t.status='Open' then 1 else 0 end) as [Open]  
 ,u.User_Login + ' (' + isnull(u.FName, '') + ' ' + isnull(u.LName, '') + ')' AS UserByName      
from [dbo].[tbl_tsk_TaskHistory] t with (nolock) 
join user_detail u with (nolock) on t.createdby=u.User_ID 
right join calendar c with (nolock) on cast(c.date_id as date)=cast(t.createdon as date)
where u.parentid=@parentid and cast(c.date_id as date) BETWEEN @fromdate AND @todate 
and isappointment=1  
 AND (u.User_ID IN (CASE WHEN @IsAdmin = 1 THEN u.User_ID END)      
   OR u.User_ID IN (SELECT User_ID  FROM @tbluser ))      
group by user_login,cast(c.date_id as date),u.FName,u.LName,createdby     

--select dbo.fn_appointmentcreated(t.AssignedTo,cast(t.StartDate as date)),cast(t.StartDate as date) as DueDate,user_login as Executive,count(1) TotalAssigned  
--,sum(case when t.Status='completed' then 1 else 0 end) as CompletedTillDate  
--,sum(case when t.Status='completed' and cast(completedon as date)<=cast(t.StartDate as date) then 1 else 0 end) as CompletedInTime  
--,sum(case when t.status='Open' then 1 else 0 end) as [Open]  
-- ,u.User_Login + ' (' + isnull(u.FName, '') + ' ' + isnull(u.LName, '') + ')' AS UserByName      
--from [dbo].[tbl_tsk_TaskHistory] t with (nolock) join user_detail u with (nolock) on t.AssignedTo=u.User_ID  
--where u.parentid=@parentid and cast(t.enddate as date) BETWEEN @fromdate AND @todate and IsAppointment=1  
-- AND (u.User_ID IN (CASE WHEN @IsAdmin = 1 THEN u.User_ID END)      
--   OR u.User_ID IN (SELECT User_ID  FROM @tbluser ))      
--group by user_login,cast(t.StartDate as date),u.FName,u.LName,AssignedTo    
  
  
  
  
 SELECT *      
 INTO #followup_status      
 FROM followup_status(NOLOCK) f      
 WHERE isactive = 1      
  AND isnull(parentid, @parentid) = @parentid      
  AND id = (      
   SELECT max(id)      
   FROM followup_status(nolock)      
   WHERE FollowupStatus = f.FollowupStatus      
    AND isactive = 1      
    AND isnull(parentid, @parentid) = @parentid      
    and isnull(IsConvert,0) <> 1      
   )      
      
 DECLARE @listtopivot NVARCHAR(max)      
  ,@sql NVARCHAR(max)      
      
 SELECT @listtopivot = coalesce(@listtopivot + ',', '') + '[' + FollowUpStatus + ']'      
 FROM #followup_status(NOLOCK) where FollowupStatus != ''      
      
 --where parentid=@parentid and IsActive=1  and isdisabled=0                        
 SELECT @sql = 'SELECT * FROM (                              
   select    ul.User_ID, user_login,f.followupstatus,                      
   sum(case when l.createdby=User_ID and l.followupstatus=f.id then 1 else 0 end) as Count          
    , ul.User_Login + '' ('' + isnull(ul.FName,'''') + '' '' + isnull(ul.LName,'''') + '')'' as UserByName                              
   from leadinteractionhistory(nolock) l                         
   join user_detail(nolock) ul on ul.User_ID=l.createdby                        
   join #followup_status(nolock) f on f.ID=l.FollowUpStatus                       
   where l.parentid=' + cast(@parentid AS NVARCHAR) + ' and IsReassign=0                       
   and cast(createdon as date) between ''' + cast(@fromdate AS NVARCHAR) + ''' and ''' + cast(@todate AS NVARCHAR) + '''                
                   
    and (ul.User_ID in ( case when ''' + CAST(@IsAdmin AS NVARCHAR) + ''' = ''1'' then ul.User_ID                
       end                 
       )                
      or         
       ul.User_ID in ((select * from STRING_SPLIT(''' + isnull(      
   @UserIdTeamLst, '') + ''', '','')))         
   )         
                
                         
   group by ul.User_ID,user_login,f.followupstatus,ul.FName,ul.LName      )                       
   FollowupsDone                            
   PIVOT (                      
   SUM([Count])                              
   FOR [followupstatus]                              
   IN ( ' + @listtopivot + '                      
   )                      
   ) AS PivotTable'      
      
 PRINT @sql      
      
 EXEC (@sql)      
      
 SELECT u.User_ID      
  ,u.user_login      
  ,u.User_Login + ' (' + isnull(u.FName, '') + ' ' + isnull(u.LName, '') + ')' AS UserByName      
  ,isnull(NewAdded, 0) NewAdded      
  ,isnull(Deleted, 0) Deleted      
  ,isnull(Expired, 0) Expired      
  ,isnull(Won, 0) Won      
  ,isnull(Lost, 0) Lost      
  ,isnull(AverageDaysToWin, 0) AverageDaysToWin      
  ,isnull(CurrentlyinPipeline, 0) CurrentlyinPipeline      
  ,ISNULL(Stagnant, 0) AS Stagnant      
 FROM user_detail(NOLOCK) u      
 LEFT JOIN (      
  SELECT user_login      
   ,sum(CASE       
     WHEN cast(createddate as date) BETWEEN @fromdate      
       AND @todate      
      THEN 1      
     ELSE 0      
     END) AS NewAdded      
   ,sum(CASE       
     WHEN cast(DeletedOn as date) BETWEEN @fromdate      
       AND @todate      
      THEN 1      
     ELSE 0      
     END) AS Deleted      
  --FROM LeadPipelineMapping_earliest(NOLOCK) l      
  FROM LeadPipelineMapping_latest(NOLOCK) l      
  JOIN user_detail(NOLOCK) u ON u.user_id = l.CreatedBy      
  WHERE parentid = @parentid      
  GROUP BY user_login      
  ) ND ON ND.User_Login = u.user_login      
 LEFT JOIN (      
  SELECT user_login      
   ,sum(CASE       
     WHEN cast(lpm.createddate as date) BETWEEN @fromdate      
       AND @todate      
      AND PS.Name = 'Won'      
      THEN 1      
     ELSE 0      
     END) AS Won      
   ,sum(CASE       
     WHEN cast(lpm.createddate as date) BETWEEN @fromdate      
       AND @todate      
      AND PS.Name = 'Lost'      
      THEN 1      
     ELSE 0      
     END) AS Lost      
   ,sum(CASE       
     WHEN datediff(d, lpm.createddate, getdate()) >= 30      
      AND PS.name NOT IN (      
       'won'      
       ,'Lost'      
       )      
      AND lpm.IsDeleted = 0      
      THEN 1      
     ELSE 0      
     END) AS Stagnant      
   ,sum(CASE       
     WHEN PS.name NOT IN (      
       'won'      
       ,'Lost'      
       )      
      AND lpm.IsDeleted = 0      
      THEN 1      
     ELSE 0      
     END) AS CurrentlyinPipeline      
   ,sum(CASE       
     WHEN datediff(d, l.createddate, lpm.createddate) > pm.DealExpiry      
      THEN 1      
     ELSE 0      
     END) AS Expired      
   ,avg(CASE       
     WHEN PS.Name = 'Won'      
      AND l.leadid IS NOT NULL      
      THEN datediff(d, l.createddate, lpm.createddate)      
     ELSE - 1      
     END) AverageDaysToWin      
  FROM LeadPipelineMapping_latest(NOLOCK) lpm      
  INNER JOIN Pipeline_Master AS PM WITH (NOLOCK) ON LPM.PipelineID = PM.ID      
  INNER JOIN PipelineStages AS PS WITH (NOLOCK) ON LPM.PipeLineStage = PS.ID      
  LEFT JOIN (      
   SELECT leadid      
    ,createddate      
   --FROM LeadPipelineMapping_earliest(NOLOCK)      
   FROM LeadPipelineMapping_latest(NOLOCK)      
   WHERE isdeleted = 0      
   ) l ON l.leadid = lpm.LeadID      
  JOIN user_detail(NOLOCK) u ON u.user_id = lpm.DealOwner      
  WHERE pm.parentid = @parentid      
  GROUP BY user_login      
  ) wl ON wl.User_Login = u.User_Login      
 WHERE u.parentID = @parentid      
  AND (      
   u.User_ID IN (      
    CASE       
     WHEN @IsAdmin = 1      
      THEN u.User_ID      
       --else @UserIdTeamLst                 
     END      
    )      
   OR u.User_ID IN (      
    SELECT User_ID      
    FROM @tbluser      
    )      
   )      
  AND u.STATUS = 1      
      
 SELECT u.User_ID      
  ,u.user_login      
  ,u.User_Login + ' (' + isnull(u.FName, '') + ' ' + isnull(u.LName, '') + ')' AS UserByName      
  ,Pipeline      
  ,isnull(NewAdded, 0) NewAdded      
  ,isnull(Deleted, 0) Deleted      
  ,isnull(Expired, 0) Expired      
  ,isnull(Won, 0) Won      
  ,isnull(Lost, 0) Lost      
  ,isnull(AverageDaysToWin, 0) AverageDaysToWin      
  ,isnull(CurrentlyinPipeline, 0) CurrentlyinPipeline      
  ,ISNULL(Stagnant, 0) Stagnant      
 FROM user_detail(NOLOCK) u      
 LEFT JOIN (      
  SELECT id      
   ,name AS Pipeline      
   ,ParentID      
  FROM Pipeline_Master(NOLOCK)      
  WHERE parentid = @parentid      
   AND isdeleted = 0      
  ) p ON p.parentid = u.ParentID      
 LEFT JOIN (      
  SELECT user_login      
   ,pm.Name AS PipelineN      
   ,sum(CASE       
     WHEN cast(l.createddate as date) BETWEEN @fromdate      
       AND @todate      
      THEN 1      
     ELSE 0      
     END) AS NewAdded      
   ,sum(CASE       
     WHEN cast(DeletedOn as date) BETWEEN @fromdate      
       AND @todate      
      THEN 1      
     ELSE 0      
     END) AS Deleted      
  --FROM LeadPipelineMapping_earliest(NOLOCK) l      
  FROM LeadPipelineMapping_latest(NOLOCK) l      
  INNER JOIN Pipeline_Master AS PM WITH (NOLOCK) ON L.PipelineID = PM.ID      
  JOIN user_detail(NOLOCK) u ON u.user_id = l.CreatedBy      
  WHERE u.parentid = @parentid      
  GROUP BY user_login      
   ,pm.Name      
  ) ND ON ND.User_Login = u.user_login      
  AND ND.PipelineN = p.pipeline      
 LEFT JOIN (      
  SELECT user_login      
   ,pm.Name AS PipelineN      
   ,sum(CASE       
     WHEN cast( lpm.createddate as date) BETWEEN @fromdate      
       AND @todate      
      AND PS.Name = 'Won'      
      THEN 1      
     ELSE 0      
     END) AS Won      
   ,sum(CASE       
     WHEN  cast(lpm.createddate as date) BETWEEN @fromdate      
       AND @todate      
      AND PS.Name = 'Lost'      
      THEN 1      
     ELSE 0      
     END) AS Lost      
   ,sum(CASE       
     WHEN datediff(d, lpm.createddate, getdate()) >= 30      
      AND PS.name NOT IN (      
       'won'      
       ,'Lost'      
       )      
      AND lpm.IsDeleted = 0      
      THEN 1      
     ELSE 0      
     END) AS Stagnant      
   ,sum(CASE       
     WHEN PS.name NOT IN (      
       'won'      
       ,'Lost'      
       )      
      AND lpm.IsDeleted = 0      
      THEN 1      
     ELSE 0      
     END) AS CurrentlyinPipeline      
   ,      
   --sum(case when datediff(d,l.createddate,lpm.createddate)>pm.DealExpiry then 1 else 0 end) as Expired,            
   sum(CASE       
     WHEN datediff(DAY, getdate(), lpm.EstimatedClosureDate) <= 0      
      THEN 1      
     ELSE 0      
     END) AS Expired      
   ,avg(CASE       
     WHEN PS.Name = 'Won'      
      AND l.leadid IS NOT NULL      
      THEN datediff(d, l.createddate, lpm.createddate)      
     ELSE - 1      
     END) AverageDaysToWin      
  FROM LeadPipelineMapping_latest(NOLOCK) lpm      
  INNER JOIN Pipeline_Master AS PM WITH (NOLOCK) ON LPM.PipelineID = PM.ID      
  INNER JOIN PipelineStages AS PS WITH (NOLOCK) ON LPM.PipeLineStage = PS.ID      
  LEFT JOIN (      
   SELECT leadid      
    ,createddate      
   --FROM LeadPipelineMapping_earliest(NOLOCK)      
   FROM LeadPipelineMapping_latest(NOLOCK)      
   WHERE isdeleted = 0      
   ) l ON l.leadid = lpm.LeadID      
  JOIN user_detail(NOLOCK) u ON u.user_id = lpm.DealOwner      
  WHERE pm.parentid = @parentid      
  GROUP BY user_login      
   ,pm.Name      
  ) wl ON wl.User_Login = u.User_Login      
  AND wl.PipelineN = p.Pipeline      
 WHERE u.parentID = @parentid      
  AND (      
   u.User_ID IN (      
    CASE       
     WHEN @IsAdmin = 1      
      THEN u.User_ID      
       --else @UserIdTeamLst                 
     END      
    )      
   OR u.User_ID IN (      
    SELECT User_ID      
    FROM @tbluser      
    )      
   )      
  AND u.STATUS = 1      
 ORDER BY u.User_Login      
      
 EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @userid      
  ,@Activity_type = 'View_Rpt_Lead'      
  ,@ActionType = 'S'      
  ,@RowJson = ''      
  ,@Table_name = 'Userleads and LeadPipelineMapping_latest'      
      
      
   drop table if exists #followup_statusTemp      
      drop table if exists #followup_status      
   drop table if exists #leadinteractionhistory      
   drop table if exists #leadinteractionhistoryWithdatrange      
END 


GO

/* ============================================================
   Procedure: [dbo].[usp_getleadreport_daywise_LeadAndFollowup]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_getleadreport_daywise_LeadAndFollowup] --44558,44558,'13-Jun-2024','14-Jul-2024'   --39680,39680,'20221001','20221231'  --34149,34149,'20220721','20220722'                          
  @userid BIGINT          
 ,@parentid BIGINT          
 ,@fromdate DATE          
 ,@todate DATE          
AS
BEGIN          
 --Declare @userid bigint=44558,@parentid  bigint=44558,@fromdate date='13-Jun-2024',@todate date='14-Jul-2024'           
  --Declare @userid bigint=32222,@parentid  bigint=32222,@fromdate date='03-Oct-2025',@todate date='04-Oct-2025'           

 --Admin 39680            
 --IsAdmin 40068            
 --Hirarchy Team head 40060            
 --User 40059            
 --Declare @userid bigint=40060,@parentid bigint=39680,@fromdate date='2022-05-26',@todate date='2022-05-27'           
           
 drop table if exists #followup_statusTemp          
drop table if exists #followup_status          
 drop table if exists #leadinteractionhistory          
 drop table if exists #leadinteractionhistoryWithdatrange  
 DROP TABLE IF EXISTS #user_login;-- DBA
          
 /*          
 SELECT *          
 INTO #followup_statusTemp          
 FROM followup_status(NOLOCK) f          
 WHERE isactive = 1          
  AND isnull(parentid, @parentid) = @parentid          
  AND id = (          
   SELECT max(id)          
   FROM followup_status          
   WHERE FollowupStatus = f.FollowupStatus          
    AND isactive = 1          
    AND isnull(parentid, @parentid) = @parentid          
   )          
 */          
           
            
 DECLARE @tbluser TABLE (          
  User_ID BIGINT          
  ,Name VARCHAR(100)          
  ,IMAGE VARCHAR(100)          
  )          
 DECLARE @IsAdmin BIT = 0          
          
 SELECT @IsAdmin = IsAdmin          
 FROM User_Detail(NOLOCK)          
 WHERE User_ID = @Userid          
          
 IF (@IsAdmin = 1)          
 BEGIN          
  --set @Userid = 0;                    
  INSERT INTO @tbluser          
  EXEC Use_GetUserDetails @ParentId          
 END          
 ELSE          
 BEGIN          
  INSERT INTO @tbluser          
  EXEC Use_GetUserDetails @UserId          
 END          
          
 DECLARE @TeamCode VARCHAR(10) = ''          
 DECLARE @ScopeCode VARCHAR(10) = ''          
 DECLARE @UserIdTeamLst VARCHAR(4000) = ''          
 DECLARE @HierarchyJSON VARCHAR(Max) = ''          
          
 SELECT @UserIdTeamLst = isnull(STRING_AGG(User_ID, ','), '')          
 FROM @tbluser          
          
 PRINT '@UserIdTeamLst: ' + @UserIdTeamLst          
          
 IF OBJECT_ID(N'tempdb..#followup_status') IS NOT NULL          
 BEGIN          
  DROP TABLE #followup_status          
 END          
          
 select * into #leadinteractionhistory from LeadInteractionHistory(nolock) where parentid=@parentid and cast(CreatedOn as date) between @fromdate and @todate          
 select * into #leadinteractionhistoryWithdatrange from LeadInteractionHistory(nolock) where parentid=@parentid         
 --and cast(CreatedOn as date) between @fromdate and @todate            
          
    -- DBA
 CREATE NONCLUSTERED INDEX IX_#leadinteractionhistoryWithdatrange_1
ON #leadinteractionhistoryWithdatrange (LeadNo, [ParentID],[IsReassign])

-- DBA
;WITH cte_user_login
 AS
 (
 SELECT user_login , LastFollowupCreatedBy, u.parentid , u.leadno
  FROM userleads u(NOLOCK)          
  JOIN user_detail(NOLOCK) ul ON u.AssignedTo = ul.User_ID          
  WHERE u.parentid = @parentid 
 )
 SELECT user_login,count(1) AS UntouchedLeads INTO #user_login
 FROM
 (
 SELECT user_login
  FROM cte_user_login
  WHERE
  isnull(LastFollowupCreatedBy, 0) = 0
  UNION ALL
  SELECT user_login
  FROM cte_user_login u
  WHERE NOT EXISTS (          
     SELECT 1          
     FROM #leadinteractionhistoryWithdatrange(NOLOCK)          
     WHERE isreassign = 0          
      AND leadno = u.leadno          
      AND parentid = u.parentid          
     )  
	) AS t
GROUP BY user_login

 SELECT u.user_id          
  ,u.user_login          
  ,isnull(NewLeadsAdded, 0) NewLeadsAdded          
  ,isnull(TotalLeadsAssignedCurrently, 0) TotalLeadsAssignedCurrently          
  ,isnull(UniqueLeadsFollowedUp, 0) UniqueLeadsFollowedUp          
  ,isnull(TotalFollowupsMarked, 0) TotalFollowupsMarked      
   ,isnull(TotalFollowupsDue, 0) TotalFollowupsDue          
    ,isnull(TotalFollowupsDonefromDue, 0) TotalFollowupsDonefromDue          
  ,isnull(UntouchedLeads, 0) UntouchedLeads          
  ,isnull(LeadsOverDue, 0) LeadsOverDue          
  ,u.User_Login + ' (' + isnull(u.FName, '') + ' ' + isnull(u.LName, '') + ')' AS UserByName  
    , isnull(u.FName, '') + ' ' + isnull(u.LName, '')  AS UserName  
 FROM user_detail(NOLOCK) u          
 LEFT JOIN (          
  SELECT user_login          
   ,sum(CASE           
     WHEN cast(u.createdon as date) BETWEEN @fromdate          
       AND @todate          
      THEN 1          
     ELSE 0          
     END) AS NewLeadsAdded          
  FROM userleads u(NOLOCK)          
  JOIN user_detail(NOLOCK) ul ON ul.User_ID = u.CreatedBy 
  --join @tbluser t on t.User_ID=ul.user_id
  join @tbluser t on t.User_ID=ul.user_id and u.AssignedTo = t.User_ID
  WHERE u.parentid = @parentid   
   AND u.CreatedBy = t.User_ID  
 GROUP BY user_login     
  ) nwl ON nwl.User_Login = u.User_Login          
 LEFT JOIN (          
  SELECT user_login          
   ,sum(CASE           
     WHEN cast(followupdate as date) < cast(getdate() as date)          
      AND isnull(f.IsConvert, 0) <> 1          
      THEN 1          
     ELSE 0          
     END) AS LeadsOverDue          
   ,count(1) TotalLeadsAssignedCurrently          
  FROM userleads u(NOLOCK)          
  JOIN user_detail(NOLOCK) ul ON ul.User_ID = u.AssignedTo          
  LEFT JOIN FollowUp_Status(NOLOCK) f ON f.id = u.FollowUpStatus          
  WHERE u.parentid = @parentid          
  GROUP BY user_login          
  ) OD ON OD.User_Login = u.User_Login          
 LEFT JOIN /*(    -- Commented By DBA      
  SELECT user_login          
   ,count(1) AS UntouchedLeads          
  FROM userleads u(NOLOCK)          
  JOIN user_detail(NOLOCK) ul ON u.AssignedTo = ul.User_ID          
  WHERE u.parentid = @parentid          
   AND (          
    isnull(LastFollowupCreatedBy, 0) = 0          
    OR NOT EXISTS (          
     SELECT 1          
     FROM #leadinteractionhistoryWithdatrange(NOLOCK)          
     WHERE isreassign = 0          
      AND leadno = u.leadno          
      AND parentid = u.parentid          
     )          
    )          
  GROUP BY user_login          
  )*/
   #user_login UL ON UL.User_Login = u.User_Login          -- #user_login Added by DBA
 LEFT JOIN (          
  SELECT user_login          
   ,sum(CASE           
     WHEN l.createdby = User_ID          
      THEN 1          
     ELSE 0          
     END) AS UniqueLeadsFollowedUp          
   ,sum(TotalFollowupsMarked) TotalFollowupsMarked --,sum(case when l.createdby is null then 1 else 0 end) as UntouchedLeads                          
  FROM (          
   SELECT lih1.leadno          
    ,lih1.parentid          
    ,lih1.createdby          
    ,count(1) AS TotalFollowupsMarked          
   FROM #leadinteractionhistory(NOLOCK) as lih1          
   join followup_status(nolock) as fs1          
   on lih1.FollowUpStatus = fs1.ID          
    WHERE lih1.parentid = @parentid          
    AND lih1.IsReassign = 0          
    AND cast(lih1.createdon as date) BETWEEN @fromdate          
     AND @todate          
                And isnull(fs1.IsConvert,0) <> 1              
   GROUP BY leadno          
    ,lih1.parentid          
    ,lih1.createdby          
   ) l          
  JOIN user_detail(NOLOCK) ul ON ul.User_ID = l.createdby          
  WHERE l.parentid = @parentid          
  GROUP BY User_Login          
  ) LF ON u.user_login = LF.User_Login       
  LEFT JOIN (          
  SELECT user_login          
      ,sum(TotalFollowupsDue) TotalFollowupsDue       
   ,   sum(TotalFollowupsDonefromDue) as TotalFollowupsDonefromDue                          
  FROM (          
   SELECT lih1.leadno          
    ,lih1.parentid          
    ,lih1.AssignedTo          
    ,count(1) AS TotalFollowupsDue      
 ,sum(dbo.fn_isleadfollowed_withrange(lih1.id,@fromdate,@todate)) TotalFollowupsDonefromDue      
   FROM #leadinteractionhistoryWithdatrange(NOLOCK) as lih1          
   join followup_status(nolock) as fs1          
   on lih1.FollowUpStatus = fs1.ID      
    WHERE lih1.parentid = @parentid          
     AND cast(lih1.FollowupDate as date) BETWEEN @fromdate          
     AND @todate          
     And isnull(fs1.IsConvert,0) <> 1              
   GROUP BY leadno          
    ,lih1.parentid          
    ,lih1.AssignedTo          
   ) l          
  JOIN user_detail(NOLOCK) ul ON ul.User_ID = l.AssignedTo          
  WHERE l.parentid = @parentid          
  GROUP BY User_Login          
  ) LTF ON u.user_login = LTF.User_Login          
      
      
      
 WHERE u.parentid = @parentid          
  AND (          
   u.User_ID IN (          
    CASE           
     WHEN @IsAdmin = 1          
      THEN u.User_ID          
     END          
    )          
   OR u.User_ID IN (          
    SELECT User_ID          
    FROM @tbluser          
    )          
   )          
      
 
 select cast(getdate() as date) as Date,* from 
 (
 SELECT 
   ---cast(c.start_dts as date) as Date,
   --cast(getdate() as date) as Date
  --'01-Jan-2024' as Date
  --,
  u.user_id          
  ,u.user_login         
 ,count(1) FollowupsDue          
 ,sum(dbo.fn_isleadfollowed(lih.id)) FollowupsDoneTillDate       
 ,sum(dbo.fn_isleadfollowed_withrange(lih.id,@fromdate,@fromdate)) FollowupsDoneInTime    
 ,sum(dbo.fn_isleadfollowedbyothers(lih.id)) FollowedUpByOthers    
 ,sum(dbo.fn_isleadnotfollowedtilldate(lih.id)) NotFollowedTillDate    
 ,u.User_Login + ' (' + isnull(u.FName, '') + ' ' + isnull(u.LName, '') + ')' AS UserByName   
  , isnull(u.FName, '') + ' ' + isnull(u.LName, '')  AS UserName   
 FROM user_detail(NOLOCK) u        
 LEFT JOIN       
 #leadinteractionhistoryWithdatrange(NOLOCK)  lih on lih.assignedto=u.user_id      
 left join FollowUp_Status (nolock) f on f.id=lih.FollowUpStatus    
 left join calendar (nolock) c on cast(c.start_dts as date)=cast(lih.followupdate as date)      
 WHERE isreassign = 0  and lih.FollowupDate is not null      
  AND (u.User_ID IN (CASE WHEN @IsAdmin = 1 THEN u.User_ID END)          
   OR u.User_ID IN (SELECT User_ID  FROM @tbluser ))          
 and cast(c.start_dts as date) between @fromdate and @todate      
 and f.IsCallback=1    
  GROUP BY user_id,user_login 
  --,cast(c.start_dts as date)
  --,cast(getdate() as date) 
  --,'01-Jan-2024'
  ,u.FName,u.LName
  ) as tbl
          
drop table if exists #leadinteractionhistory          
drop table if exists #leadinteractionhistoryWithdatrange          
      
      
 SELECT *          
 INTO #followup_status          
 FROM followup_status(NOLOCK) f          
 WHERE isactive = 1          
  AND isnull(parentid, @parentid) = @parentid          
  AND id = (          
   SELECT max(id)          
   FROM followup_status(nolock)          
   WHERE FollowupStatus = f.FollowupStatus          
    AND isactive = 1          
    AND isnull(parentid, @parentid) = @parentid          
    and isnull(IsConvert,0) <> 1          
   )          
          
 DECLARE @listtopivot NVARCHAR(max)          
  ,@sql NVARCHAR(max)          
          
 SELECT @listtopivot = coalesce(@listtopivot + ',', '') + '[' + FollowUpStatus + ']'          
 FROM #followup_status(NOLOCK) where FollowupStatus != ''          
          
 --where parentid=@parentid and IsActive=1  and isdisabled=0                            
 SELECT @sql = 'SELECT * FROM (                                  
   select    ul.User_ID, user_login,f.followupstatus,                          
   sum(case when l.createdby=User_ID and l.followupstatus=f.id then 1 else 0 end) as Count              
    , ul.User_Login + '' ('' + isnull(ul.FName,'''') + '' '' + isnull(ul.LName,'''') + '')'' as UserByName  
	,  isnull(ul.FName,'''') + '' '' + isnull(ul.LName,'''')  as UserName  
   from leadinteractionhistory(nolock) l                             
   join user_detail(nolock) ul on ul.User_ID=l.createdby                            
   join #followup_status(nolock) f on f.ID=l.FollowUpStatus                           
   where l.parentid=' + cast(@parentid AS NVARCHAR) + ' and IsReassign=0                           
   and cast(createdon as date) between ''' + cast(@fromdate AS NVARCHAR) + ''' and ''' + cast(@todate AS NVARCHAR) + '''                    
                       
    and (ul.User_ID in ( case when ''' + CAST(@IsAdmin AS NVARCHAR) + ''' = ''1'' then ul.User_ID                    
       end                     
       )                    
      or             
       ul.User_ID in ((select * from STRING_SPLIT(''' + isnull(          
   @UserIdTeamLst, '') + ''', '','')))             
   )             
                    
                             
   group by ul.User_ID,user_login,f.followupstatus,ul.FName,ul.LName      )                           
   FollowupsDone                                
   PIVOT (                          
   SUM([Count])                                  
   FOR [followupstatus]                                  
   IN ( ' + @listtopivot + '                          
   )                          
   ) AS PivotTable'          
          
 PRINT @sql          
          
 EXEC (@sql)          
   
   
 EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @userid          
  ,@Activity_type = 'View_Rpt_Lead'          
  ,@ActionType = 'S'          
  ,@RowJson = ''          
  ,@Table_name = 'Userleads and LeadPipelineMapping_latest'          
          
          
   drop table if exists #followup_statusTemp          
      drop table if exists #followup_status          
