  @userid BIGINT          
 ,@parentid BIGINT          
 ,@fromdate DATE          
 ,@todate DATE          
AS
BEGIN          
 --Declare @userid bigint=32222,@parentid  bigint=32222,@fromdate date='03-Oct-2025',@todate date='04-Oct-2025'           
 --Admin 39680            
 --IsAdmin 40068            
 --Hirarchy Team head 40060            
 --User 40059            
 --Declare @userid bigint=40060,@parentid bigint=39680,@fromdate date='2022-05-26',@todate date='2022-05-27'           
           
 drop table if exists #followup_statusTemp          
drop table if exists #followup_status          
