 select * into #leadinteractionhistory from LeadInteractionHistory(nolock) where parentid=@parentid and cast(CreatedOn as date) between @fromdate and @todate          
 select * into #leadinteractionhistoryWithdatrange from LeadInteractionHistory(nolock) where parentid=@parentid         
 --and cast(CreatedOn as date) between @fromdate and @todate            
          
    -- KK
 CREATE NONCLUSTERED INDEX IX_#leadinteractionhistoryWithdatrange_1
ON #leadinteractionhistoryWithdatrange (LeadNo, [ParentID],[IsReassign])

-- KK
;WITH cte_user_login
 AS
 (
 SELECT user_login , LastFollowupCreatedBy, u.parentid , u.leadno
  FROM userleads u(NOLOCK)          
  JOIN user_detail(NOLOCK) ul ON u.AssignedTo = ul.User_ID          
  WHERE u.parentid = @parentid 
 )
 SELECT user_login,count(1) AS UntouchedLeads INTO #user_login
 FROM
 (
 SELECT user_login
  FROM cte_user_login
  WHERE
  isnull(LastFollowupCreatedBy, 0) = 0
  UNION ALL
  SELECT user_login
  FROM cte_user_login u
  WHERE NOT EXISTS (          
     SELECT 1          
     FROM #leadinteractionhistoryWithdatrange(NOLOCK)          
     WHERE isreassign = 0          
      AND leadno = u.leadno          
      AND parentid = u.parentid          
     )  
	) AS t
GROUP BY user_login

 SELECT u.user_id          
  ,u.user_login          
  ,isnull(NewLeadsAdded, 0) NewLeadsAdded          
  ,isnull(TotalLeadsAssignedCurrently, 0) TotalLeadsAssignedCurrently          
  ,isnull(UniqueLeadsFollowedUp, 0) UniqueLeadsFollowedUp          
  ,isnull(TotalFollowupsMarked, 0) TotalFollowupsMarked      
   ,isnull(TotalFollowupsDue, 0) TotalFollowupsDue          
    ,isnull(TotalFollowupsDonefromDue, 0) TotalFollowupsDonefromDue          
  ,isnull(UntouchedLeads, 0) UntouchedLeads          
  ,isnull(LeadsOverDue, 0) LeadsOverDue          
  ,u.User_Login + ' (' + isnull(u.FName, '') + ' ' + isnull(u.LName, '') + ')' AS UserByName  
    , isnull(u.FName, '') + ' ' + isnull(u.LName, '')  AS UserName  
 FROM user_detail(NOLOCK) u          
 LEFT JOIN (          
  SELECT user_login          
   ,sum(CASE           
     WHEN cast(u.createdon as date) BETWEEN @fromdate          
       AND @todate          
      THEN 1          
     ELSE 0          
     END) AS NewLeadsAdded          
  FROM userleads u(NOLOCK)          
  JOIN user_detail(NOLOCK) ul ON ul.User_ID = u.CreatedBy 
  join @tbluser t on t.User_ID=ul.user_id
  WHERE u.parentid = @parentid   
   AND u.CreatedBy = t.User_ID  
 GROUP BY user_login     
  ) nwl ON nwl.User_Login = u.User_Login          
 LEFT JOIN (          
  SELECT user_login          
   ,sum(CASE           
     WHEN cast(followupdate as date) < cast(getdate() as date)          
      AND isnull(f.IsConvert, 0) <> 1          
      THEN 1          
     ELSE 0          
     END) AS LeadsOverDue          
   ,count(1) TotalLeadsAssignedCurrently          
  FROM userleads u(NOLOCK)          
  JOIN user_detail(NOLOCK) ul ON ul.User_ID = u.AssignedTo          
  LEFT JOIN FollowUp_Status(NOLOCK) f ON f.id = u.FollowUpStatus          
  WHERE u.parentid = @parentid          
  GROUP BY user_login          
  ) OD ON OD.User_Login = u.User_Login          
 LEFT JOIN /*(          
  SELECT user_login          
   ,count(1) AS UntouchedLeads          
  FROM userleads u(NOLOCK)          
  JOIN user_detail(NOLOCK) ul ON u.AssignedTo = ul.User_ID          
  WHERE u.parentid = @parentid          
   AND (          
    isnull(LastFollowupCreatedBy, 0) = 0          
    OR NOT EXISTS (          
     SELECT 1          
     FROM #leadinteractionhistoryWithdatrange(NOLOCK)          
     WHERE isreassign = 0          
      AND leadno = u.leadno          
      AND parentid = u.parentid          
     )          
    )          
  GROUP BY user_login          
  )*/
   #user_login UL ON UL.User_Login = u.User_Login          -- KK
 LEFT JOIN (          
  SELECT user_login          
   ,sum(CASE           
     WHEN l.createdby = User_ID          
      THEN 1          
     ELSE 0          
     END) AS UniqueLeadsFollowedUp          
   ,sum(TotalFollowupsMarked) TotalFollowupsMarked --,sum(case when l.createdby is null then 1 else 0 end) as UntouchedLeads                          
  FROM (          
   SELECT lih1.leadno          
    ,lih1.parentid          
    ,lih1.createdby          
    ,count(1) AS TotalFollowupsMarked          
   FROM #leadinteractionhistory(NOLOCK) as lih1          
   join followup_status(nolock) as fs1          
   on lih1.FollowUpStatus = fs1.ID          
    WHERE lih1.parentid = @parentid          
    AND lih1.IsReassign = 0          
    AND cast(lih1.createdon as date) BETWEEN @fromdate          
     AND @todate          
                And isnull(fs1.IsConvert,0) <> 1              
   GROUP BY leadno          
    ,lih1.parentid          
    ,lih1.createdby          
   ) l          
  JOIN user_detail(NOLOCK) ul ON ul.User_ID = l.createdby          
  WHERE l.parentid = @parentid          
  GROUP BY User_Login          
  ) LF ON u.user_login = LF.User_Login       
  LEFT JOIN (          
  SELECT user_login          
      ,sum(TotalFollowupsDue) TotalFollowupsDue       
   ,   sum(TotalFollowupsDonefromDue) as TotalFollowupsDonefromDue                          
  FROM (          
   SELECT lih1.leadno          
    ,lih1.parentid          
    ,lih1.AssignedTo          
    ,count(1) AS TotalFollowupsDue      
 ,sum(dbo.fn_isleadfollowed_withrange(lih1.id,@fromdate,@todate)) TotalFollowupsDonefromDue      
   FROM #leadinteractionhistoryWithdatrange(NOLOCK) as lih1          
   join followup_status(nolock) as fs1          
   on lih1.FollowUpStatus = fs1.ID      
    WHERE lih1.parentid = @parentid          
     AND cast(lih1.FollowupDate as date) BETWEEN @fromdate          
     AND @todate          
     And isnull(fs1.IsConvert,0) <> 1              
   GROUP BY leadno          
    ,lih1.parentid          
    ,lih1.AssignedTo          
   ) l          
  JOIN user_detail(NOLOCK) ul ON ul.User_ID = l.AssignedTo          
  WHERE l.parentid = @parentid          
  GROUP BY User_Login          
  ) LTF ON u.user_login = LTF.User_Login          
      
      
      
 WHERE u.parentid = @parentid          
  AND (          
   u.User_ID IN (          
    CASE           
     WHEN @IsAdmin = 1          
      THEN u.User_ID          
     END          
    )          
   OR u.User_ID IN (          
    SELECT User_ID          
    FROM @tbluser          
    )          
   )          
      
 
 select cast(getdate() as date) as Date,* from 
 (
 SELECT 
   ---cast(c.start_dts as date) as Date,
   --cast(getdate() as date) as Date
  --'01-Jan-2024' as Date
  --,
  u.user_id          
  ,u.user_login         
 ,count(1) FollowupsDue          
 ,sum(dbo.fn_isleadfollowed(lih.id)) FollowupsDoneTillDate       
 ,sum(dbo.fn_isleadfollowed_withrange(lih.id,@fromdate,@fromdate)) FollowupsDoneInTime    
 ,sum(dbo.fn_isleadfollowedbyothers(lih.id)) FollowedUpByOthers    
 ,sum(dbo.fn_isleadnotfollowedtilldate(lih.id)) NotFollowedTillDate    
 ,u.User_Login + ' (' + isnull(u.FName, '') + ' ' + isnull(u.LName, '') + ')' AS UserByName   
  , isnull(u.FName, '') + ' ' + isnull(u.LName, '')  AS UserName   
 FROM user_detail(NOLOCK) u        
 LEFT JOIN       
 #leadinteractionhistoryWithdatrange(NOLOCK)  lih on lih.assignedto=u.user_id      
 left join FollowUp_Status (nolock) f on f.id=lih.FollowUpStatus    
 left join calendar (nolock) c on cast(c.start_dts as date)=cast(lih.followupdate as date)      
 WHERE isreassign = 0  and lih.FollowupDate is not null      
  AND (u.User_ID IN (CASE WHEN @IsAdmin = 1 THEN u.User_ID END)          
   OR u.User_ID IN (SELECT User_ID  FROM @tbluser ))          
 and cast(c.start_dts as date) between @fromdate and @todate      
 and f.IsCallback=1    
  GROUP BY user_id,user_login 
  --,cast(c.start_dts as date)
  --,cast(getdate() as date) 
  --,'01-Jan-2024'
  ,u.FName,u.LName
  ) as tbl
          
drop table if exists #leadinteractionhistory          
drop table if exists #leadinteractionhistoryWithdatrange          
      
      
 SELECT *          
 INTO #followup_status          
 FROM followup_status(NOLOCK) f          
 WHERE isactive = 1          
  AND isnull(parentid, @parentid) = @parentid          
  AND id = (          
   SELECT max(id)          
   FROM followup_status(nolock)          
   WHERE FollowupStatus = f.FollowupStatus          
    AND isactive = 1          
    AND isnull(parentid, @parentid) = @parentid          
    and isnull(IsConvert,0) <> 1          
   )          
          
 DECLARE @listtopivot NVARCHAR(max)          
  ,@sql NVARCHAR(max)          
          
 SELECT @listtopivot = coalesce(@listtopivot + ',', '') + '[' + FollowUpStatus + ']'          
 FROM #followup_status(NOLOCK) where FollowupStatus != ''          
          
 --where parentid=@parentid and IsActive=1  and isdisabled=0                            
 SELECT @sql = 'SELECT * FROM (                                  
   select    ul.User_ID, user_login,f.followupstatus,                          
   sum(case when l.createdby=User_ID and l.followupstatus=f.id then 1 else 0 end) as Count              
    , ul.User_Login + '' ('' + isnull(ul.FName,'''') + '' '' + isnull(ul.LName,'''') + '')'' as UserByName  
	,  isnull(ul.FName,'''') + '' '' + isnull(ul.LName,'''')  as UserName  
   from leadinteractionhistory(nolock) l                             
   join user_detail(nolock) ul on ul.User_ID=l.createdby                            
   join #followup_status(nolock) f on f.ID=l.FollowUpStatus                           
   where l.parentid=' + cast(@parentid AS NVARCHAR) + ' and IsReassign=0                           
   and cast(createdon as date) between ''' + cast(@fromdate AS NVARCHAR) + ''' and ''' + cast(@todate AS NVARCHAR) + '''                    
                       
    and (ul.User_ID in ( case when ''' + CAST(@IsAdmin AS NVARCHAR) + ''' = ''1'' then ul.User_ID                    
       end                     
       )                    
      or             
       ul.User_ID in ((select * from STRING_SPLIT(''' + isnull(          
   @UserIdTeamLst, '') + ''', '','')))             
   )             
                    
                             
   group by ul.User_ID,user_login,f.followupstatus,ul.FName,ul.LName      )                           
   FollowupsDone                                
   PIVOT (                          
   SUM([Count])                                  
   FOR [followupstatus]                                  
   IN ( ' + @listtopivot + '                          
   )                          
   ) AS PivotTable'          
          
 PRINT @sql          
          
 EXEC (@sql)          
   
   
 EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @userid          
  ,@Activity_type = 'View_Rpt_Lead'          
  ,@ActionType = 'S'          
  ,@RowJson = ''          
  ,@Table_name = 'Userleads and LeadPipelineMapping_latest'          
          
          
   drop table if exists #followup_statusTemp          
      drop table if exists #followup_status          
   drop table if exists #leadinteractionhistory          
   drop table if exists #leadinteractionhistoryWithdatrange          
END 


GO

/* ============================================================
   Procedure: [dbo].[usp_getleadreport_daywise_Pipeline]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_getleadreport_daywise_Pipeline] --34594,34594,'17-Jul-2023','04-Aug-2023'   --39680,39680,'20221001','20221231'  --34149,34149,'20220721','20220722'                          
  @userid BIGINT          
 ,@parentid BIGINT          
 ,@fromdate DATE          
 ,@todate DATE          
AS          
BEGIN          
 --Declare @userid bigint=34594,@parentid bigint=34594,@fromdate date='2022-05-26',@todate date='2022-05-27'            
 --Admin 39680            
 --IsAdmin 40068            
 --Hirarchy Team head 40060            
 --User 40059            
 --Declare @userid bigint=40060,@parentid bigint=39680,@fromdate date='2022-05-26',@todate date='2022-05-27'           
           
 drop table if exists #followup_statusTemp          
drop table if exists #followup_status          
 drop table if exists #leadinteractionhistory          
 drop table if exists #leadinteractionhistoryWithdatrange          
           
            
 DECLARE @tbluser TABLE (          
  User_ID BIGINT          
  ,Name VARCHAR(100)          
  ,IMAGE VARCHAR(100)          
  )          
 DECLARE @IsAdmin BIT = 0          
          
 SELECT @IsAdmin = IsAdmin          
 FROM User_Detail(NOLOCK)          
 WHERE User_ID = @Userid          
          
 IF (@IsAdmin = 1)          
 BEGIN          
  --set @Userid = 0;                    
  INSERT INTO @tbluser          
  EXEC Use_GetUserDetails @ParentId          
 END          
 ELSE          
 BEGIN          
  INSERT INTO @tbluser          
  EXEC Use_GetUserDetails @UserId          
 END          
          
 DECLARE @TeamCode VARCHAR(10) = ''          
 DECLARE @ScopeCode VARCHAR(10) = ''          
 DECLARE @UserIdTeamLst VARCHAR(4000) = ''          
 DECLARE @HierarchyJSON VARCHAR(Max) = ''          
          
 SELECT @UserIdTeamLst = isnull(STRING_AGG(User_ID, ','), '')          
 FROM @tbluser          
          
 PRINT '@UserIdTeamLst: ' + @UserIdTeamLst          
          
 IF OBJECT_ID(N'tempdb..#followup_status') IS NOT NULL          
 BEGIN          
  DROP TABLE #followup_status          
 END          
          
 select * into #leadinteractionhistory from LeadInteractionHistory(nolock) where parentid=@parentid and cast(CreatedOn as date) between @fromdate and @todate          
 select * into #leadinteractionhistoryWithdatrange from LeadInteractionHistory(nolock) where parentid=@parentid         
 --and cast(CreatedOn as date) between @fromdate and @todate            
                          
          
 SELECT u.User_ID          
  ,u.user_login          
  ,u.User_Login + ' (' + isnull(u.FName, '') + ' ' + isnull(u.LName, '') + ')' AS UserByName          
  ,isnull(NewAdded, 0) NewAdded          
  ,isnull(Deleted, 0) Deleted          
  ,isnull(Expired, 0) Expired          
  ,isnull(Won, 0) Won          
  ,isnull(Lost, 0) Lost          
  ,isnull(AverageDaysToWin, 0) AverageDaysToWin          
  ,isnull(CurrentlyinPipeline, 0) CurrentlyinPipeline          
  ,ISNULL(Stagnant, 0) AS Stagnant          
 FROM user_detail(NOLOCK) u          
 LEFT JOIN (          
  SELECT user_login          
   ,sum(CASE           
     WHEN cast(createddate as date) BETWEEN @fromdate          
       AND @todate          
      THEN 1          
     ELSE 0          
     END) AS NewAdded          
   ,sum(CASE           
     WHEN cast(DeletedOn as date) BETWEEN @fromdate          
       AND @todate          
      THEN 1          
     ELSE 0          
     END) AS Deleted          
  --FROM LeadPipelineMapping_earliest(NOLOCK) l          
  FROM LeadPipelineMapping_latest(NOLOCK) l          
  JOIN user_detail(NOLOCK) u ON u.user_id = l.CreatedBy          
  WHERE parentid = @parentid          
  GROUP BY user_login          
  ) ND ON ND.User_Login = u.user_login          
 LEFT JOIN (          
  SELECT user_login          
   ,sum(CASE           
     WHEN cast(lpm.createddate as date) BETWEEN @fromdate          
       AND @todate          
      AND PS.Name = 'Won'          
      THEN 1          
     ELSE 0          
     END) AS Won          
   ,sum(CASE       
     WHEN cast(lpm.createddate as date) BETWEEN @fromdate          
       AND @todate          
      AND PS.Name = 'Lost'          
      THEN 1          
     ELSE 0          
     END) AS Lost          
   ,sum(CASE           
     WHEN datediff(d, lpm.createddate, getdate()) >= 30          
      AND PS.name NOT IN (          
       'won'          
 ,'Lost'          
       )          
      AND lpm.IsDeleted = 0          
      THEN 1          
     ELSE 0          
     END) AS Stagnant          
   ,sum(CASE           
     WHEN PS.name NOT IN (          
       'won'          
       ,'Lost'          
       )          
      AND lpm.IsDeleted = 0          
      THEN 1          
     ELSE 0          
     END) AS CurrentlyinPipeline          
   ,sum(CASE           
     WHEN datediff(d, l.createddate, lpm.createddate) > pm.DealExpiry          
      THEN 1          
     ELSE 0          
     END) AS Expired          
   ,avg(CASE           
     WHEN PS.Name = 'Won'          
      AND l.leadid IS NOT NULL          
      THEN datediff(d, l.createddate, lpm.createddate)          
     ELSE - 1          
     END) AverageDaysToWin          
  FROM LeadPipelineMapping_latest(NOLOCK) lpm          
  INNER JOIN Pipeline_Master AS PM WITH (NOLOCK) ON LPM.PipelineID = PM.ID          
  INNER JOIN PipelineStages AS PS WITH (NOLOCK) ON LPM.PipeLineStage = PS.ID          
  LEFT JOIN (          
   SELECT leadid          
    ,createddate          
   --FROM LeadPipelineMapping_earliest(NOLOCK)          
   FROM LeadPipelineMapping_latest(NOLOCK)          
   WHERE isdeleted = 0          
   ) l ON l.leadid = lpm.LeadID          
  JOIN user_detail(NOLOCK) u ON u.user_id = lpm.DealOwner          
  WHERE pm.parentid = @parentid          
  GROUP BY user_login          
  ) wl ON wl.User_Login = u.User_Login          
 WHERE u.parentID = @parentid          
  AND (          
   u.User_ID IN (          
    CASE           
     WHEN @IsAdmin = 1          
      THEN u.User_ID          
       --else @UserIdTeamLst                     
     END          
    )          
   OR u.User_ID IN (          
    SELECT User_ID          
    FROM @tbluser          
    )          
   )          
  AND u.STATUS = 1          
          
 SELECT u.User_ID          
  ,u.user_login          
  ,u.User_Login + ' (' + isnull(u.FName, '') + ' ' + isnull(u.LName, '') + ')' AS UserByName          
  ,Pipeline          
  ,isnull(NewAdded, 0) NewAdded          
  ,isnull(Deleted, 0) Deleted          
  ,isnull(Expired, 0) Expired          
  ,isnull(Won, 0) Won          
  ,isnull(Lost, 0) Lost          
  ,isnull(AverageDaysToWin, 0) AverageDaysToWin          
  ,isnull(CurrentlyinPipeline, 0) CurrentlyinPipeline          
  ,ISNULL(Stagnant, 0) Stagnant          
 FROM user_detail(NOLOCK) u          
 LEFT JOIN (          
  SELECT id          
   ,name AS Pipeline          
   ,ParentID          
  FROM Pipeline_Master(NOLOCK)          
  WHERE parentid = @parentid          
   AND isdeleted = 0          
  ) p ON p.parentid = u.ParentID          
 LEFT JOIN (          
  SELECT user_login          
   ,pm.Name AS PipelineN          
   ,sum(CASE           
     WHEN cast(l.createddate as date) BETWEEN @fromdate          
       AND @todate          
      THEN 1          
     ELSE 0          
     END) AS NewAdded          
   ,sum(CASE           
     WHEN cast(DeletedOn as date) BETWEEN @fromdate          
       AND @todate          
      THEN 1          
     ELSE 0          
     END) AS Deleted          
  --FROM LeadPipelineMapping_earliest(NOLOCK) l          
  FROM LeadPipelineMapping_latest(NOLOCK) l          
  INNER JOIN Pipeline_Master AS PM WITH (NOLOCK) ON L.PipelineID = PM.ID          
  JOIN user_detail(NOLOCK) u ON u.user_id = l.CreatedBy          
  WHERE u.parentid = @parentid          
  GROUP BY user_login          
   ,pm.Name          
  ) ND ON ND.User_Login = u.user_login          
  AND ND.PipelineN = p.pipeline          
 LEFT JOIN (          
  SELECT user_login          
   ,pm.Name AS PipelineN          
   ,sum(CASE           
     WHEN cast( lpm.createddate as date) BETWEEN @fromdate          
       AND @todate          
      AND PS.Name = 'Won'          
      THEN 1          
     ELSE 0          
     END) AS Won          
   ,sum(CASE           
     WHEN  cast(lpm.createddate as date) BETWEEN @fromdate          
       AND @todate          
      AND PS.Name = 'Lost'          
      THEN 1          
     ELSE 0          
     END) AS Lost          
   ,sum(CASE           
     WHEN datediff(d, lpm.createddate, getdate()) >= 30          
      AND PS.name NOT IN (          
       'won'          
       ,'Lost'          
       )          
      AND lpm.IsDeleted = 0          
      THEN 1          
     ELSE 0          
     END) AS Stagnant          
   ,sum(CASE           
     WHEN PS.name NOT IN (          
       'won'          
       ,'Lost'          
       )          
      AND lpm.IsDeleted = 0          
      THEN 1          
     ELSE 0          
     END) AS CurrentlyinPipeline          
   ,          
   --sum(case when datediff(d,l.createddate,lpm.createddate)>pm.DealExpiry then 1 else 0 end) as Expired,                
   sum(CASE           
     WHEN datediff(DAY, getdate(), lpm.EstimatedClosureDate) <= 0          
      THEN 1          
     ELSE 0          
     END) AS Expired          
   ,avg(CASE           
     WHEN PS.Name = 'Won'          
      AND l.leadid IS NOT NULL          
      THEN datediff(d, l.createddate, lpm.createddate)          
     ELSE - 1          
     END) AverageDaysToWin          
  FROM LeadPipelineMapping_latest(NOLOCK) lpm          
  INNER JOIN Pipeline_Master AS PM WITH (NOLOCK) ON LPM.PipelineID = PM.ID          
  INNER JOIN PipelineStages AS PS WITH (NOLOCK) ON LPM.PipeLineStage = PS.ID          
  LEFT JOIN (          
   SELECT leadid          
    ,createddate          
   --FROM LeadPipelineMapping_earliest(NOLOCK)          
   FROM LeadPipelineMapping_latest(NOLOCK)          
   WHERE isdeleted = 0          
   ) l ON l.leadid = lpm.LeadID          
  JOIN user_detail(NOLOCK) u ON u.user_id = lpm.DealOwner          
  WHERE pm.parentid = @parentid          
  GROUP BY user_login          
   ,pm.Name          
  ) wl ON wl.User_Login = u.User_Login          
  AND wl.PipelineN = p.Pipeline          
 WHERE u.parentID = @parentid          
  AND (          
   u.User_ID IN (          
    CASE           
     WHEN @IsAdmin = 1          
      THEN u.User_ID          
       --else @UserIdTeamLst                     
     END          
    )          
   OR u.User_ID IN (          
    SELECT User_ID          
    FROM @tbluser          
    )          
   )          
  AND u.STATUS = 1          
 ORDER BY u.User_Login          
          
 EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @userid          
  ,@Activity_type = 'View_Rpt_Lead'          
  ,@ActionType = 'S'          
  ,@RowJson = ''          
  ,@Table_name = 'Userleads and LeadPipelineMapping_latest'          
          
          
   drop table if exists #followup_statusTemp          
      drop table if exists #followup_status          
   drop table if exists #leadinteractionhistory          
   drop table if exists #leadinteractionhistoryWithdatrange          
END 


GO

/* ============================================================
   Procedure: [dbo].[usp_getleadreport_daywise_TaskAndAppointment]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_getleadreport_daywise_TaskAndAppointment] --34594,34594,'17-Jul-2023','04-Aug-2023'   --39680,39680,'20221001','20221231'  --34149,34149,'20220721','20220722'                        
  @userid BIGINT        
 ,@parentid BIGINT        
 ,@fromdate DATE        
 ,@todate DATE        
AS        
BEGIN        
 --Declare @userid bigint=34594,@parentid bigint=34594,@fromdate date='2022-05-26',@todate date='2022-05-27'          
 --Admin 39680          
 --IsAdmin 40068          
 --Hirarchy Team head 40060          
 --User 40059          
 --Declare @userid bigint=40060,@parentid bigint=39680,@fromdate date='2022-05-26',@todate date='2022-05-27'         
         
 drop table if exists #followup_statusTemp        
drop table if exists #followup_status        
 drop table if exists #leadinteractionhistory        
 drop table if exists #leadinteractionhistoryWithdatrange        
          
 DECLARE @tbluser TABLE (        
  User_ID BIGINT        
  ,Name VARCHAR(100)        
  ,IMAGE VARCHAR(100)        
  )        
 DECLARE @IsAdmin BIT = 0        
        
 SELECT @IsAdmin = IsAdmin        
 FROM User_Detail(NOLOCK)        
 WHERE User_ID = @Userid        
        
 IF (@IsAdmin = 1)        
 BEGIN        
  --set @Userid = 0;                  
  INSERT INTO @tbluser        
  EXEC Use_GetUserDetails @ParentId        
 END        
 ELSE        
 BEGIN        
  INSERT INTO @tbluser        
  EXEC Use_GetUserDetails @UserId        
 END        
        
 DECLARE @TeamCode VARCHAR(10) = ''        
 DECLARE @ScopeCode VARCHAR(10) = ''        
 DECLARE @UserIdTeamLst VARCHAR(4000) = ''        
 DECLARE @HierarchyJSON VARCHAR(Max) = ''        
        
 SELECT @UserIdTeamLst = isnull(STRING_AGG(User_ID, ','), '')        
 FROM @tbluser        
        
 PRINT '@UserIdTeamLst: ' + @UserIdTeamLst        
        
 IF OBJECT_ID(N'tempdb..#followup_status') IS NOT NULL        
 BEGIN        
  DROP TABLE #followup_status        
 END        
        
 select * into #leadinteractionhistory from LeadInteractionHistory(nolock) where parentid=@parentid and cast(CreatedOn as date) between @fromdate and @todate        
 select * into #leadinteractionhistoryWithdatrange from LeadInteractionHistory(nolock) where parentid=@parentid       
 --and cast(CreatedOn as date) between @fromdate and @todate          
    
select cast(c.date_id as date) as CreatedDate,user_login as Executive,count(1) TotalCreated    
,sum(case when t.Status='completed' then 1 else 0 end) as CompletedTillDate    
,sum(case when t.Status='completed' and cast(completedon as date)<=cast(t.enddate as date) then 1 else 0 end) as CompletedInTime    
,sum(case when t.status='Open' then 1 else 0 end) as [Open]    
 ,u.User_Login + ' (' + isnull(u.FName, '') + ' ' + isnull(u.LName, '') + ')' AS UserByName        
from [dbo].[tbl_tsk_TaskHistory] t with (nolock)   
join user_detail u with (nolock) on t.createdby=u.User_ID   
right join calendar c with (nolock) on cast(c.date_id as date)=cast(t.createdon as date)  
where u.parentid=@parentid and cast(c.date_id as date) BETWEEN @fromdate AND @todate   
and istask=1 and isnull(isactive,0) = 1   
 AND (u.User_ID IN (CASE WHEN @IsAdmin = 1 THEN u.User_ID END)        
   OR u.User_ID IN (SELECT User_ID  FROM @tbluser ))        
group by user_login,cast(c.date_id as date),u.FName,u.LName,createdby       
    
  select cast(c.date_id as date) as CreatedDate,user_login as Executive,count(1) TotalCreated    
,sum(case when t.Status='completed' then 1 else 0 end) as CompletedTillDate    
,sum(case when t.Status='completed' and cast(completedon as date)<=cast(t.enddate as date) then 1 else 0 end) as CompletedInTime    
,sum(case when t.status='Open' then 1 else 0 end) as [Open]    
 ,u.User_Login + ' (' + isnull(u.FName, '') + ' ' + isnull(u.LName, '') + ')' AS UserByName        
from [dbo].[tbl_tsk_TaskHistory] t with (nolock)   
join user_detail u with (nolock) on t.createdby=u.User_ID   
right join calendar c with (nolock) on cast(c.date_id as date)=cast(t.createdon as date)  
where u.parentid=@parentid and cast(c.date_id as date) BETWEEN @fromdate AND @todate   
and isappointment=1 and isnull(isactive,0) = 1    
 AND (u.User_ID IN (CASE WHEN @IsAdmin = 1 THEN u.User_ID END)        
   OR u.User_ID IN (SELECT User_ID  FROM @tbluser ))        
group by user_login,cast(c.date_id as date),u.FName,u.LName,createdby       
  
  
 EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @userid        
  ,@Activity_type = 'View_Rpt_Lead'        
  ,@ActionType = 'S'        
  ,@RowJson = ''        
  ,@Table_name = 'Userleads and LeadPipelineMapping_latest'        
        
        
   drop table if exists #followup_statusTemp        
   drop table if exists #followup_status        
   drop table if exists #leadinteractionhistory        
   drop table if exists #leadinteractionhistoryWithdatrange        
END 


GO

/* ============================================================
   Procedure: [dbo].[usp_getleadreport_fudue]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_getleadreport_fudue] --31871,31871,'17-Jul-2023','18-Jul-2023'   --39680,39680,'20221001','20221231'  --34149,34149,'20220721','20220722'                    
  @userid BIGINT    
 ,@parentid BIGINT    
 ,@fromdate DATE    
 ,@todate DATE    
AS    
BEGIN    
 --Declare @userid bigint=34594,@parentid bigint=34594,@fromdate date='2022-05-26',@todate date='2022-05-27'      
 --Admin 39680      
 --IsAdmin 40068      
 --Hirarchy Team head 40060      
 --User 40059      
 --Declare @userid bigint=40060,@parentid bigint=39680,@fromdate date='2022-05-26',@todate date='2022-05-27'     
     
 drop table if exists #followup_statusTemp    
    drop table if exists #followup_status    
 drop table if exists #leadinteractionhistory    
 drop table if exists #leadinteractionhistoryWithdatrange    
    
 /*    
 SELECT *    
 INTO #followup_statusTemp    
 FROM followup_status(NOLOCK) f    
 WHERE isactive = 1    
  AND isnull(parentid, @parentid) = @parentid    
  AND id = (    
   SELECT max(id)    
   FROM followup_status    
   WHERE FollowupStatus = f.FollowupStatus    
    AND isactive = 1    
    AND isnull(parentid, @parentid) = @parentid    
   )    
 */    
     
      
 DECLARE @tbluser TABLE (    
  User_ID BIGINT    
  ,Name VARCHAR(100)    
  ,IMAGE VARCHAR(100)    
  )    
 DECLARE @IsAdmin BIT = 0    
    
 SELECT @IsAdmin = IsAdmin    
 FROM User_Detail(NOLOCK)    
 WHERE User_ID = @Userid    
    
 IF (@IsAdmin = 1)    
 BEGIN    
  --set @Userid = 0;              
  INSERT INTO @tbluser    
  EXEC Use_GetUserDetails @ParentId    
 END    
 ELSE    
 BEGIN    
  INSERT INTO @tbluser    
  EXEC Use_GetUserDetails @UserId    
 END    
    
 DECLARE @TeamCode VARCHAR(10) = ''    
 DECLARE @ScopeCode VARCHAR(10) = ''    
 DECLARE @UserIdTeamLst VARCHAR(4000) = ''    
 DECLARE @HierarchyJSON VARCHAR(Max) = ''    
    
 SELECT @UserIdTeamLst = isnull(STRING_AGG(User_ID, ','), '')    
 FROM @tbluser    
    
 PRINT '@UserIdTeamLst: ' + @UserIdTeamLst    
    
 IF OBJECT_ID(N'tempdb..#followup_status') IS NOT NULL    
 BEGIN    
  DROP TABLE #followup_status    
 END    
    
 select * into #leadinteractionhistory from LeadInteractionHistory(nolock) where parentid=@parentid and cast(CreatedOn as date) between @fromdate and @todate    
 select * into #leadinteractionhistoryWithdatrange from LeadInteractionHistory(nolock) where parentid=@parentid   
 --and cast(CreatedOn as date) between @fromdate and @todate      
    
    
 SELECT u.user_id    
  ,u.user_login    
  ,isnull(NewLeadsAdded, 0) NewLeadsAdded    
  ,isnull(TotalLeadsAssignedCurrently, 0) TotalLeadsAssignedCurrently    
  ,isnull(UniqueLeadsFollowedUp, 0) UniqueLeadsFollowedUp    
  ,isnull(TotalFollowupsMarked, 0) TotalFollowupsMarked
   ,isnull(TotalFollowupsDue, 0) TotalFollowupsDue    
    ,isnull(TotalFollowupsDonefromDue, 0) TotalFollowupsDonefromDue    
  ,isnull(UntouchedLeads, 0) UntouchedLeads    
  ,isnull(LeadsOverDue, 0) LeadsOverDue    
  ,u.User_Login + ' (' + isnull(u.FName, '') + ' ' + isnull(u.LName, '') + ')' AS UserByName    
 FROM user_detail(NOLOCK) u    
 LEFT JOIN (    
  SELECT user_login    
   ,sum(CASE     
     WHEN cast(u.createdon as date) BETWEEN @fromdate    
       AND @todate    
      THEN 1    
     ELSE 0    
     END) AS NewLeadsAdded    
  FROM userleads u(NOLOCK)    
  JOIN user_detail(NOLOCK) ul ON ul.User_ID = u.CreatedBy    
  WHERE u.parentid = @parentid    
  GROUP BY user_login    
  ) nwl ON nwl.User_Login = u.User_Login    
 LEFT JOIN (    
  SELECT user_login    
   ,sum(CASE     
     WHEN cast(followupdate as date) < cast(getdate() as date)    
      AND isnull(f.IsConvert, 0) <> 1    
      THEN 1    
     ELSE 0    
     END) AS LeadsOverDue    
   ,count(1) TotalLeadsAssignedCurrently    
  FROM userleads u(NOLOCK)    
  JOIN user_detail(NOLOCK) ul ON ul.User_ID = u.AssignedTo    
  LEFT JOIN FollowUp_Status(NOLOCK) f ON f.id = u.FollowUpStatus    
  WHERE u.parentid = @parentid    
  GROUP BY user_login    
  ) OD ON OD.User_Login = u.User_Login    
 LEFT JOIN (    
  SELECT user_login    
   ,count(1) AS UntouchedLeads    
  FROM userleads u(NOLOCK)    
  JOIN user_detail(NOLOCK) ul ON u.AssignedTo = ul.User_ID    
  WHERE u.parentid = @parentid    
   AND (    
    isnull(LastFollowupCreatedBy, 0) = 0    
    OR NOT EXISTS (    
     SELECT 1    
     FROM #leadinteractionhistoryWithdatrange(NOLOCK)    
     WHERE isreassign = 0    
      AND leadno = u.leadno    
      AND parentid = u.parentid    
     )    
    )    
  GROUP BY user_login    
  ) UL ON UL.User_Login = u.User_Login    
 LEFT JOIN (    
  SELECT user_login    
   ,sum(CASE     
     WHEN l.createdby = User_ID    
      THEN 1    
     ELSE 0    
     END) AS UniqueLeadsFollowedUp    
   ,sum(TotalFollowupsMarked) TotalFollowupsMarked --,sum(case when l.createdby is null then 1 else 0 end) as UntouchedLeads                    
  FROM (    
   SELECT lih1.leadno    
    ,lih1.parentid    
    ,lih1.createdby    
    ,count(1) AS TotalFollowupsMarked    
   FROM #leadinteractionhistory(NOLOCK) as lih1    
   join followup_status(nolock) as fs1    
   on lih1.FollowUpStatus = fs1.ID    
    WHERE lih1.parentid = @parentid    
    AND lih1.IsReassign = 0    
    AND cast(lih1.createdon as date) BETWEEN @fromdate    
     AND @todate    
                And isnull(fs1.IsConvert,0) <> 1        
   GROUP BY leadno    
    ,lih1.parentid    
    ,lih1.createdby    
   ) l    
  JOIN user_detail(NOLOCK) ul ON ul.User_ID = l.createdby    
  WHERE l.parentid = @parentid    
  GROUP BY User_Login    
  ) LF ON u.user_login = LF.User_Login 
  LEFT JOIN (    
  SELECT user_login    
      ,sum(TotalFollowupsDue) TotalFollowupsDue 
	  ,	  sum(TotalFollowupsDonefromDue) as TotalFollowupsDonefromDue                    
  FROM (    
   SELECT lih1.leadno    
    ,lih1.parentid    
    ,lih1.AssignedTo    
    ,count(1) AS TotalFollowupsDue
	,sum(dbo.fn_isleadfollowed(lih1.id)) TotalFollowupsDonefromDue
   FROM #leadinteractionhistory(NOLOCK) as lih1    
   join followup_status(nolock) as fs1    
   on lih1.FollowUpStatus = fs1.ID
    WHERE lih1.parentid = @parentid    
     AND cast(lih1.FollowupDate as date) BETWEEN @fromdate    
     AND @todate    
     And isnull(fs1.IsConvert,0) <> 1        
   GROUP BY leadno    
    ,lih1.parentid    
    ,lih1.AssignedTo    
   ) l    
  JOIN user_detail(NOLOCK) ul ON ul.User_ID = l.AssignedTo    
  WHERE l.parentid = @parentid    
  GROUP BY User_Login    
  ) LTF ON u.user_login = LTF.User_Login    



 WHERE u.parentid = @parentid    
  AND (    
   u.User_ID IN (    
    CASE     
     WHEN @IsAdmin = 1    
      THEN u.User_ID    
     END    
    )    
   OR u.User_ID IN (    
    SELECT User_ID    
    FROM @tbluser    
    )    
   )    
    
drop table if exists #leadinteractionhistory    
drop table if exists #leadinteractionhistoryWithdatrange    
 SELECT *    
 INTO #followup_status    
 FROM followup_status(NOLOCK) f    
 WHERE isactive = 1    
  AND isnull(parentid, @parentid) = @parentid    
  AND id = (    
   SELECT max(id)    
   FROM followup_status(nolock)    
   WHERE FollowupStatus = f.FollowupStatus    
    AND isactive = 1    
    AND isnull(parentid, @parentid) = @parentid    
    and isnull(IsConvert,0) <> 1    
   )    
    
 DECLARE @listtopivot NVARCHAR(max)    
  ,@sql NVARCHAR(max)    
    
 SELECT @listtopivot = coalesce(@listtopivot + ',', '') + '[' + FollowUpStatus + ']'    
 FROM #followup_status(NOLOCK) where FollowupStatus != ''    
    
 --where parentid=@parentid and IsActive=1  and isdisabled=0                      
 SELECT @sql = 'SELECT * FROM (                            
   select    ul.User_ID, user_login,f.followupstatus,                    
   sum(case when l.createdby=User_ID and l.followupstatus=f.id then 1 else 0 end) as Count        
    , ul.User_Login + '' ('' + isnull(ul.FName,'''') + '' '' + isnull(ul.LName,'''') + '')'' as UserByName                            
   from leadinteractionhistory(nolock) l                       
   join user_detail(nolock) ul on ul.User_ID=l.createdby                      
   join #followup_status(nolock) f on f.ID=l.FollowUpStatus                     
   where l.parentid=' + cast(@parentid AS NVARCHAR) + ' and IsReassign=0                     
   and cast(createdon as date) between ''' + cast(@fromdate AS NVARCHAR) + ''' and ''' + cast(@todate AS NVARCHAR) + '''              
                 
    and (ul.User_ID in ( case when ''' + CAST(@IsAdmin AS NVARCHAR) + ''' = ''1'' then ul.User_ID              
       end               
       )              
      or       
       ul.User_ID in ((select * from STRING_SPLIT(''' + isnull(    
   @UserIdTeamLst, '') + ''', '','')))       
   )       
              
                       
   group by ul.User_ID,user_login,f.followupstatus,ul.FName,ul.LName      )                     
   FollowupsDone                          
   PIVOT (                    
   SUM([Count])                            
   FOR [followupstatus]                            
   IN ( ' + @listtopivot + '                    
   )                    
   ) AS PivotTable'    
    
 PRINT @sql    
    
 EXEC (@sql)    
    
 SELECT u.User_ID    
  ,u.user_login    
  ,u.User_Login + ' (' + isnull(u.FName, '') + ' ' + isnull(u.LName, '') + ')' AS UserByName    
  ,isnull(NewAdded, 0) NewAdded    
  ,isnull(Deleted, 0) Deleted    
  ,isnull(Expired, 0) Expired    
  ,isnull(Won, 0) Won    
  ,isnull(Lost, 0) Lost    
  ,isnull(AverageDaysToWin, 0) AverageDaysToWin    
  ,isnull(CurrentlyinPipeline, 0) CurrentlyinPipeline    
  ,ISNULL(Stagnant, 0) AS Stagnant    
 FROM user_detail(NOLOCK) u    
 LEFT JOIN (    
  SELECT user_login    
   ,sum(CASE     
     WHEN cast(createddate as date) BETWEEN @fromdate    
       AND @todate    
      THEN 1    
     ELSE 0    
     END) AS NewAdded    
   ,sum(CASE     
     WHEN cast(DeletedOn as date) BETWEEN @fromdate    
       AND @todate    
      THEN 1    
     ELSE 0    
     END) AS Deleted    
  --FROM LeadPipelineMapping_earliest(NOLOCK) l    
  FROM LeadPipelineMapping_latest(NOLOCK) l    
  JOIN user_detail(NOLOCK) u ON u.user_id = l.CreatedBy    
  WHERE parentid = @parentid    
  GROUP BY user_login    
  ) ND ON ND.User_Login = u.user_login    
 LEFT JOIN (    
  SELECT user_login    
   ,sum(CASE     
     WHEN cast(lpm.createddate as date) BETWEEN @fromdate    
       AND @todate    
      AND PS.Name = 'Won'    
      THEN 1    
     ELSE 0    
     END) AS Won    
   ,sum(CASE     
     WHEN cast(lpm.createddate as date) BETWEEN @fromdate    
       AND @todate    
      AND PS.Name = 'Lost'    
      THEN 1    
     ELSE 0    
     END) AS Lost    
   ,sum(CASE     
     WHEN datediff(d, lpm.createddate, getdate()) >= 30    
      AND PS.name NOT IN (    
       'won'    
       ,'Lost'    
       )    
      AND lpm.IsDeleted = 0    
      THEN 1    
     ELSE 0    
     END) AS Stagnant    
   ,sum(CASE     
     WHEN PS.name NOT IN (    
       'won'    
       ,'Lost'    
       )    
      AND lpm.IsDeleted = 0    
      THEN 1    
     ELSE 0    
     END) AS CurrentlyinPipeline    
   ,sum(CASE     
     WHEN datediff(d, l.createddate, lpm.createddate) > pm.DealExpiry    
      THEN 1    
     ELSE 0    
     END) AS Expired    
   ,avg(CASE     
     WHEN PS.Name = 'Won'    
      AND l.leadid IS NOT NULL    
      THEN datediff(d, l.createddate, lpm.createddate)    
     ELSE - 1    
     END) AverageDaysToWin    
  FROM LeadPipelineMapping_latest(NOLOCK) lpm    
  INNER JOIN Pipeline_Master AS PM WITH (NOLOCK) ON LPM.PipelineID = PM.ID    
  INNER JOIN PipelineStages AS PS WITH (NOLOCK) ON LPM.PipeLineStage = PS.ID    
  LEFT JOIN (    
   SELECT leadid    
    ,createddate    
   --FROM LeadPipelineMapping_earliest(NOLOCK)    
   FROM LeadPipelineMapping_latest(NOLOCK)    
   WHERE isdeleted = 0    
   ) l ON l.leadid = lpm.LeadID    
  JOIN user_detail(NOLOCK) u ON u.user_id = lpm.DealOwner    
  WHERE pm.parentid = @parentid    
  GROUP BY user_login    
  ) wl ON wl.User_Login = u.User_Login    
 WHERE u.parentID = @parentid    
  AND (    
   u.User_ID IN (    
    CASE     
     WHEN @IsAdmin = 1    
      THEN u.User_ID    
       --else @UserIdTeamLst               
     END    
    )    
   OR u.User_ID IN (    
    SELECT User_ID    
    FROM @tbluser    
    )    
   )    
  AND u.STATUS = 1    
    
 SELECT u.User_ID    
  ,u.user_login    
  ,u.User_Login + ' (' + isnull(u.FName, '') + ' ' + isnull(u.LName, '') + ')' AS UserByName    
  ,Pipeline    
  ,isnull(NewAdded, 0) NewAdded    
  ,isnull(Deleted, 0) Deleted    
  ,isnull(Expired, 0) Expired    
  ,isnull(Won, 0) Won    
  ,isnull(Lost, 0) Lost    
  ,isnull(AverageDaysToWin, 0) AverageDaysToWin    
  ,isnull(CurrentlyinPipeline, 0) CurrentlyinPipeline    
  ,ISNULL(Stagnant, 0) Stagnant    
 FROM user_detail(NOLOCK) u    
 LEFT JOIN (    
  SELECT id    
   ,name AS Pipeline    
   ,ParentID    
  FROM Pipeline_Master(NOLOCK)    
  WHERE parentid = @parentid    
   AND isdeleted = 0    
  ) p ON p.parentid = u.ParentID    
 LEFT JOIN (    
  SELECT user_login    
   ,pm.Name AS PipelineN    
   ,sum(CASE     
     WHEN cast(l.createddate as date) BETWEEN @fromdate    
       AND @todate    
      THEN 1    
     ELSE 0    
     END) AS NewAdded    
   ,sum(CASE     
     WHEN cast(DeletedOn as date) BETWEEN @fromdate    
       AND @todate    
      THEN 1    
     ELSE 0    
     END) AS Deleted    
  --FROM LeadPipelineMapping_earliest(NOLOCK) l    
  FROM LeadPipelineMapping_latest(NOLOCK) l    
  INNER JOIN Pipeline_Master AS PM WITH (NOLOCK) ON L.PipelineID = PM.ID    
  JOIN user_detail(NOLOCK) u ON u.user_id = l.CreatedBy    
  WHERE u.parentid = @parentid    
  GROUP BY user_login    
   ,pm.Name    
  ) ND ON ND.User_Login = u.user_login    
  AND ND.PipelineN = p.pipeline    
 LEFT JOIN (    
  SELECT user_login    
   ,pm.Name AS PipelineN    
   ,sum(CASE     
     WHEN cast( lpm.createddate as date) BETWEEN @fromdate    
       AND @todate    
      AND PS.Name = 'Won'    
      THEN 1    
     ELSE 0    
     END) AS Won    
   ,sum(CASE     
     WHEN  cast(lpm.createddate as date) BETWEEN @fromdate    
       AND @todate    
      AND PS.Name = 'Lost'    
      THEN 1    
     ELSE 0    
     END) AS Lost    
   ,sum(CASE     
     WHEN datediff(d, lpm.createddate, getdate()) >= 30    
      AND PS.name NOT IN (    
       'won'    
       ,'Lost'    
       )    
      AND lpm.IsDeleted = 0    
      THEN 1    
     ELSE 0    
     END) AS Stagnant    
   ,sum(CASE     
     WHEN PS.name NOT IN (    
       'won'    
       ,'Lost'    
       )    
      AND lpm.IsDeleted = 0    
      THEN 1    
     ELSE 0    
     END) AS CurrentlyinPipeline    
   ,    
   --sum(case when datediff(d,l.createddate,lpm.createddate)>pm.DealExpiry then 1 else 0 end) as Expired,          
   sum(CASE     
     WHEN datediff(DAY, getdate(), lpm.EstimatedClosureDate) <= 0    
      THEN 1    
     ELSE 0    
     END) AS Expired    
   ,avg(CASE     
     WHEN PS.Name = 'Won'    
      AND l.leadid IS NOT NULL    
      THEN datediff(d, l.createddate, lpm.createddate)    
     ELSE - 1    
     END) AverageDaysToWin    
  FROM LeadPipelineMapping_latest(NOLOCK) lpm    
  INNER JOIN Pipeline_Master AS PM WITH (NOLOCK) ON LPM.PipelineID = PM.ID    
  INNER JOIN PipelineStages AS PS WITH (NOLOCK) ON LPM.PipeLineStage = PS.ID    
  LEFT JOIN (    
   SELECT leadid    
    ,createddate    
   --FROM LeadPipelineMapping_earliest(NOLOCK)    
   FROM LeadPipelineMapping_latest(NOLOCK)    
   WHERE isdeleted = 0    
   ) l ON l.leadid = lpm.LeadID    
  JOIN user_detail(NOLOCK) u ON u.user_id = lpm.DealOwner    
  WHERE pm.parentid = @parentid    
  GROUP BY user_login    
   ,pm.Name    
  ) wl ON wl.User_Login = u.User_Login    
  AND wl.PipelineN = p.Pipeline    
 WHERE u.parentID = @parentid    
  AND (    
   u.User_ID IN (    
    CASE     
     WHEN @IsAdmin = 1    
      THEN u.User_ID    
       --else @UserIdTeamLst               
     END    
    )    
   OR u.User_ID IN (    
    SELECT User_ID    
    FROM @tbluser    
    )    
   )    
  AND u.STATUS = 1    
 ORDER BY u.User_Login    
    
 EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @userid    
  ,@Activity_type = 'View_Rpt_Lead'    
  ,@ActionType = 'S'    
  ,@RowJson = ''    
  ,@Table_name = 'Userleads and LeadPipelineMapping_latest'    
    
    
   drop table if exists #followup_statusTemp    
      drop table if exists #followup_status    
   drop table if exists #leadinteractionhistory    
   drop table if exists #leadinteractionhistoryWithdatrange    
END 


GO

/* ============================================================
   Procedure: [dbo].[usp_getleadreport_MobAPP]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_getleadreport_MobAPP]    
	@userid BIGINT,
	@parentid BIGINT,
	@fromdate DATE,
	@todate DATE  
AS  
BEGIN

    --declare
    --  @userid bigint=34594,
    --  @parentid bigint=34594,
    --  @fromdate date='04-Nov-2024',
    --  @todate date='05-Nov-2024'

    drop table if exists #followup_statusTemp
    drop table if exists #followup_status
    drop table if exists #leadinteractionhistory
    drop table if exists #leadinteractionhistoryWithdatrange

    DECLARE @tbluser TABLE (
      User_ID BIGINT,
      Name VARCHAR(100),
      IMAGE VARCHAR(100)
    )

    DECLARE @IsAdmin BIT = 0

    SELECT @IsAdmin = IsAdmin FROM User_Detail(NOLOCK) WHERE User_ID = @Userid

    IF (@IsAdmin = 1)
    BEGIN
        --set @Userid = 0;            
        INSERT INTO @tbluser
        EXEC Use_GetUserDetails @ParentId
    END  
    ELSE  
    BEGIN
        INSERT INTO @tbluser
        EXEC Use_GetUserDetails @UserId
    END

    DECLARE @TeamCode VARCHAR(10) = ''
    DECLARE @ScopeCode VARCHAR(10) = ''
    DECLARE @UserIdTeamLst VARCHAR(4000) = ''
    DECLARE @HierarchyJSON VARCHAR(Max) = ''

    SELECT @UserIdTeamLst = isnull(STRING_AGG(User_ID, ','), '') FROM @tbluser

    PRINT '@UserIdTeamLst: ' + @UserIdTeamLst

    IF OBJECT_ID(N'tempdb..#followup_status') IS NOT NULL  
    BEGIN
        DROP TABLE #followup_status
    END

	 select * into #leadinteractionhistory from LeadInteractionHistory(nolock) where parentid = @parentid and cast(CreatedOn as date) between @fromdate and @todate
	 select * into #leadinteractionhistoryWithdatrange from LeadInteractionHistory(nolock) where parentid=@parentid

	drop table if exists #tempLeads
	select ID, createdon, CreatedBy, AssignedTo, FollowUpStatus, ParentID, FollowupDate
		into #tempLeads
	from UserLeads(nolock) where ParentId = @ParentId

	
    ;WITH NewLeads AS (
		SELECT 
			User_ID, 
			SUM(CASE WHEN CAST(u.createdon AS date) BETWEEN @fromdate AND @todate THEN 1 ELSE 0 END) AS NewLeadsAdded
		FROM #tempLeads u WITH (NOLOCK)
		JOIN user_detail ul WITH (NOLOCK) ON ul.User_ID = u.CreatedBy AND u.ParentID = ul.ParentID
		WHERE u.parentid = @parentid 
		GROUP BY User_ID
	),
	OverdueLeads AS (
		SELECT 
			User_ID,
			SUM(CASE WHEN CAST(followupdate AS date) < CAST(GETDATE() AS date) AND ISNULL(f.IsConvert, 0) <> 1 THEN 1 ELSE 0 END) AS LeadsOverDue,
			COUNT(1) AS TotalLeadsAssignedCurrently
		FROM #tempLeads u WITH (NOLOCK)
		INNER JOIN user_detail ul WITH (NOLOCK) ON ul.User_ID = u.AssignedTo AND u.ParentID = ul.ParentID
		LEFT JOIN FollowUp_Status f WITH (NOLOCK) ON f.id = u.FollowUpStatus
		WHERE u.parentid = @parentid 
		GROUP BY User_ID
	),
	UntouchedLeads AS (
		SELECT 
			AssignedTo AS User_ID,
			COUNT(1) AS UntouchedLeads
		FROM userleads u WITH (NOLOCK)
		WHERE u.parentid = @parentid 
		  AND (ISNULL(LastFollowupCreatedBy, 0) = 0 OR NOT EXISTS (
			  SELECT 1 FROM #leadinteractionhistoryWithdatrange lwh WITH (NOLOCK)
			  WHERE lwh.isreassign = 0 AND lwh.leadno = u.leadno AND lwh.parentid = u.parentid
		  ))
		GROUP BY AssignedTo
	),
	Followups AS (
		SELECT 
			createdby AS User_ID, 
			COUNT(DISTINCT lih1.leadno) AS UniqueLeadsFollowedUp, 
			SUM(lih1.TotalFollowupsMarked) AS TotalFollowupsMarked
		FROM (
			SELECT 
				leadno, lih1.parentid, lih1.createdby, 
				COUNT(1) AS TotalFollowupsMarked 
			FROM #leadinteractionhistory lih1 WITH (NOLOCK)
			JOIN followup_status fs1 WITH (NOLOCK) ON lih1.FollowUpStatus = fs1.ID
			WHERE lih1.parentid = @parentid 
			  AND lih1.IsReassign = 0 
			  AND CAST(lih1.createdon AS date) BETWEEN @fromdate AND @todate 
			  AND ISNULL(fs1.IsConvert, 0) <> 1 
			GROUP BY leadno, lih1.parentid, lih1.createdby
		) AS lih1
		GROUP BY createdby
	)
	SELECT 
		u.user_id, 
		u.user_login, 
		COALESCE(nl.NewLeadsAdded, 0) AS NewLeadsAdded, 
		COALESCE(od.TotalLeadsAssignedCurrently, 0) AS TotalLeadsAssignedCurrently, 
		COALESCE(fl.UniqueLeadsFollowedUp, 0) AS UniqueLeadsFollowedUp, 
		COALESCE(fl.TotalFollowupsMarked, 0) AS TotalFollowupsMarked, 
		COALESCE(ul.UntouchedLeads, 0) AS UntouchedLeads, 
		COALESCE(od.LeadsOverDue, 0) AS LeadsOverDue, 
		u.User_Login + ' (' + COALESCE(u.FName, '') + ' ' + COALESCE(u.LName, '') + ')' AS UserByName 
	FROM user_detail u WITH (NOLOCK)
	LEFT JOIN NewLeads nl ON nl.User_ID = u.User_ID 
	LEFT JOIN OverdueLeads od ON od.User_ID = u.User_ID 
	LEFT JOIN UntouchedLeads ul ON ul.User_ID = u.User_ID 
	LEFT JOIN Followups fl ON fl.User_ID = u.User_ID 
	WHERE u.parentid = @parentid 
	  AND (
		  u.User_ID IN (CASE WHEN @IsAdmin = 1 THEN u.User_ID END) 
		  OR u.User_ID IN (SELECT User_ID FROM @tbluser)
	  );

    drop table if exists #leadinteractionhistory
    drop table if exists #leadinteractionhistoryWithdatrange

	;WITH MaxFollowupStatus AS (
		SELECT 
			f.*, 
			ROW_NUMBER() OVER (PARTITION BY FollowupStatus ORDER BY id DESC) AS rn
		FROM followup_status f WITH (NOLOCK)
		WHERE 
			isactive = 1
			AND ISNULL(parentid, @parentid) = @parentid
			AND ISNULL(IsConvert, 0) <> 1
	)
	SELECT * INTO #followup_status FROM MaxFollowupStatus WHERE rn = 1;

   DECLARE @listtopivot NVARCHAR(MAX), @sql NVARCHAR(MAX), @ListPivotSelect NVARCHAR(MAX);

	-- Generate @listtopivot with STRING_AGG for columns to pivot
	SELECT @listtopivot = STRING_AGG(QUOTENAME(FollowUpStatus), ',') FROM #followup_status WITH (NOLOCK) WHERE FollowUpStatus != '';

	-- Generate @ListPivotSelect with STRING_AGG for pivoted column selections
	SELECT @ListPivotSelect = STRING_AGG(
		'ISNULL(' + QUOTENAME(FollowUpStatus) + ', 0) AS ' + 
		QUOTENAME(REPLACE(REPLACE(FollowUpStatus, ' ', ''), '-', '')), 
		','
	) FROM #followup_status WITH (NOLOCK) WHERE FollowUpStatus != '';
    --where parentid=@parentid and IsActive=1  and isdisabled=0      
	

	-- Build dynamic SQL query
	SET @sql = 'SELECT User_ID, user_login, ' + @ListPivotSelect + ', UserByName 
				FROM (
					SELECT 
						ul.User_ID,
						ul.user_login,
						f.followupstatus,
						SUM(CASE WHEN l.createdby = ul.User_ID AND l.followupstatus = f.id THEN 1 ELSE 0 END) AS Count,
						ul.User_Login + '' ('' + ISNULL(ul.FName, '''') + '' '' + ISNULL(ul.LName, '''') + '')'' AS UserByName
					FROM leadinteractionhistory l WITH (NOLOCK)
					JOIN user_detail ul WITH (NOLOCK) ON ul.User_ID = l.createdby
					JOIN #followup_status f WITH (NOLOCK) ON f.ID = l.FollowUpStatus
					WHERE l.parentid = ' + CAST(@parentid AS NVARCHAR) + ' 
					  AND l.IsReassign = 0
					  AND CAST(l.createdon AS date) BETWEEN ''' + CAST(@fromdate AS NVARCHAR) + ''' AND ''' + CAST(@todate AS NVARCHAR) + '''
					  AND (ul.User_ID IN (CASE WHEN ' + CAST(@IsAdmin AS NVARCHAR) + ' = 1 THEN ul.User_ID END)
						   OR ul.User_ID IN (SELECT value FROM STRING_SPLIT(''' + @UserIdTeamLst + ''', '','')))
					GROUP BY ul.User_ID, ul.user_login, f.followupstatus, ul.FName, ul.LName
				) AS FollowupsDone
				PIVOT (
					SUM(Count)
					FOR followupstatus IN (' + @listtopivot + ')
				) AS PivotTable;';

	-- Print the generated SQL for debugging purposes
	PRINT @sql;

	-- Execute the dynamic SQL query
	EXEC sp_executesql @sql;

   
   SELECT 
		u.User_ID,
		u.user_login,
		u.User_Login + ' (' + ISNULL(u.FName, '') + ' ' + ISNULL(u.LName, '') + ')' AS UserByName,
		ISNULL(SUMMARY.NewAdded, 0) AS NewAdded,
		ISNULL(SUMMARY.Deleted, 0) AS Deleted,
		ISNULL(SUMMARY.Expired, 0) AS Expired,
		ISNULL(SUMMARY.Won, 0) AS Won,
		ISNULL(SUMMARY.Lost, 0) AS Lost,
		ISNULL(SUMMARY.AverageDaysToWin, 0) AS AverageDaysToWin,
		ISNULL(SUMMARY.CurrentlyinPipeline, 0) AS CurrentlyinPipeline,
		ISNULL(SUMMARY.Stagnant, 0) AS Stagnant
	FROM 
		user_detail u WITH (NOLOCK)
	LEFT JOIN (
		SELECT 
			u.user_login,
			SUM(CASE WHEN CAST(l.createddate AS DATE) BETWEEN @fromdate AND @todate THEN 1 ELSE 0 END) AS NewAdded,
			SUM(CASE WHEN CAST(l.DeletedOn AS DATE) BETWEEN @fromdate AND @todate THEN 1 ELSE 0 END) AS Deleted,
			SUM(CASE WHEN CAST(lpm.createddate AS DATE) BETWEEN @fromdate AND @todate AND PS.Name = 'Won' THEN 1 ELSE 0 END) AS Won,
			SUM(CASE WHEN CAST(lpm.createddate AS DATE) BETWEEN @fromdate AND @todate AND PS.Name = 'Lost' THEN 1 ELSE 0 END) AS Lost,
			SUM(CASE WHEN DATEDIFF(DAY, lpm.createddate, GETDATE()) >= 30 AND PS.name NOT IN ('Won', 'Lost') AND lpm.IsDeleted = 0 THEN 1 ELSE 0 END) AS Stagnant,
			SUM(CASE WHEN PS.name NOT IN ('Won', 'Lost') AND lpm.IsDeleted = 0 THEN 1 ELSE 0 END) AS CurrentlyinPipeline,
			SUM(CASE WHEN DATEDIFF(DAY, l.createddate, lpm.createddate) > pm.DealExpiry THEN 1 ELSE 0 END) AS Expired,
			AVG(CASE WHEN PS.Name = 'Won' AND l.leadid IS NOT NULL THEN DATEDIFF(DAY, l.createddate, lpm.createddate) ELSE NULL END) AS AverageDaysToWin
		FROM 
			LeadPipelineMapping_latest lpm WITH (NOLOCK)
		INNER JOIN 
			Pipeline_Master pm WITH (NOLOCK) ON lpm.PipelineID = pm.ID
		INNER JOIN 
			PipelineStages PS WITH (NOLOCK) ON lpm.PipeLineStage = PS.ID
		LEFT JOIN 
			(SELECT leadid, createddate, DeletedOn FROM LeadPipelineMapping_latest WITH (NOLOCK) WHERE isdeleted = 0) l ON l.leadid = lpm.LeadID
		JOIN 
			user_detail u WITH (NOLOCK) ON u.User_ID = lpm.DealOwner
		WHERE 
			pm.parentid = @parentid
		GROUP BY 
			u.user_login
	) AS SUMMARY ON SUMMARY.user_login = u.user_login
	WHERE 
		u.parentID = @parentid
		AND u.STATUS = 1
		AND (
			@IsAdmin = 1 OR 
			u.User_ID IN (SELECT User_ID FROM @tbluser)
		);


	;WITH PipelineData AS (
		SELECT 
			id,
			name AS Pipeline,
			ParentID
		FROM 
			Pipeline_Master (NOLOCK)
		WHERE 
			parentid = @parentid
			AND isdeleted = 0
	),
	NewDeletedData AS (
		SELECT 
			u.user_login,
			pm.Name AS PipelineN,
			SUM(CASE WHEN CAST(l.createddate AS DATE) BETWEEN @fromdate AND @todate THEN 1 ELSE 0 END) AS NewAdded,
			SUM(CASE WHEN CAST(DeletedOn AS DATE) BETWEEN @fromdate AND @todate THEN 1 ELSE 0 END) AS Deleted
		FROM 
			LeadPipelineMapping_latest l (NOLOCK)
		INNER JOIN 
			Pipeline_Master pm (NOLOCK) ON l.PipelineID = pm.ID
		JOIN 
			user_detail u (NOLOCK) ON u.user_id = l.CreatedBy
		WHERE 
			u.parentid = @parentid
		GROUP BY 
			u.user_login, pm.Name
	),
	WonLostPipelineData AS (
		SELECT 
			u.user_login,
			pm.Name AS PipelineN,
			SUM(CASE WHEN CAST(lpm.createddate AS DATE) BETWEEN @fromdate AND @todate AND PS.Name = 'Won' THEN 1 ELSE 0 END) AS Won,
			SUM(CASE WHEN CAST(lpm.createddate AS DATE) BETWEEN @fromdate AND @todate AND PS.Name = 'Lost' THEN 1 ELSE 0 END) AS Lost,
			SUM(CASE WHEN DATEDIFF(DAY, lpm.createddate, GETDATE()) >= 30 AND PS.name NOT IN ('Won', 'Lost') AND lpm.IsDeleted = 0 THEN 1 ELSE 0 END) AS Stagnant,
			SUM(CASE WHEN PS.name NOT IN ('Won', 'Lost') AND lpm.IsDeleted = 0 THEN 1 ELSE 0 END) AS CurrentlyinPipeline,
			SUM(CASE WHEN DATEDIFF(DAY, GETDATE(), lpm.EstimatedClosureDate) <= 0 THEN 1 ELSE 0 END) AS Expired,
			AVG(CASE WHEN PS.Name = 'Won' AND l.leadid IS NOT NULL THEN DATEDIFF(DAY, l.createddate, lpm.createddate) ELSE NULL END) AS AverageDaysToWin
		FROM 
			LeadPipelineMapping_latest lpm (NOLOCK)
		INNER JOIN 
			Pipeline_Master pm (NOLOCK) ON lpm.PipelineID = pm.ID
		INNER JOIN 
			PipelineStages PS (NOLOCK) ON lpm.PipeLineStage = PS.ID
		LEFT JOIN (
			SELECT 
				leadid,
				createddate
			FROM 
				LeadPipelineMapping_latest (NOLOCK)
			WHERE 
				isdeleted = 0
		) l ON l.leadid = lpm.LeadID
		JOIN 
			user_detail u (NOLOCK) ON u.user_id = lpm.DealOwner
		WHERE 
			pm.parentid = @parentid
		GROUP BY 
			u.user_login, pm.Name
	)
	SELECT 
		u.User_ID,
		u.user_login,
		u.User_Login + ' (' + ISNULL(u.FName, '') + ' ' + ISNULL(u.LName, '') + ')' AS UserByName,
		p.Pipeline,
		ISNULL(ND.NewAdded, 0) AS NewAdded,
		ISNULL(ND.Deleted, 0) AS Deleted,
		ISNULL(WL.Expired, 0) AS Expired,
		ISNULL(WL.Won, 0) AS Won,
		ISNULL(WL.Lost, 0) AS Lost,
		ISNULL(WL.AverageDaysToWin, 0) AS AverageDaysToWin,
		ISNULL(WL.CurrentlyinPipeline, 0) AS CurrentlyinPipeline,
		ISNULL(WL.Stagnant, 0) AS Stagnant
	FROM 
		user_detail u (NOLOCK)
	LEFT JOIN 
		PipelineData p ON p.ParentID = u.ParentID
	LEFT JOIN 
		NewDeletedData ND ON ND.user_login = u.user_login AND ND.PipelineN = p.Pipeline
	LEFT JOIN 
		WonLostPipelineData WL ON WL.user_login = u.user_login AND WL.PipelineN = p.Pipeline
	WHERE 
		u.parentID = @parentid
	

	EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId 
		@User_id = @userid,
		@Activity_type = 'View_Rpt_Lead',
		@ActionType = 'S',
		@RowJson = '',
		@Table_name = 'Userleads and LeadPipelineMapping_latest'
  

    drop table if exists #followup_statusTemp
    drop table if exists #followup_status
    drop table if exists #leadinteractionhistory
    drop table if exists #leadinteractionhistoryWithdatrange
END  







GO

/* ============================================================
   Procedure: [dbo].[usp_getleadreport_MobAPP_WithSegmentation]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_getleadreport_MobAPP_WithSegmentation] --34594,34594,'01-Apr-2023','30-Apr-2023'     --31871,31871,'17-Mar-2023','18-Mar-2023'   --39680,39680,'20221001','20221231'  --34149,34149,'20220721','20220722'                  
 
  @userid BIGINT  
 ,@parentid BIGINT  
 ,@fromdate DATE  
 ,@todate DATE
 ,@CriteriaName nvarchar(500) 

AS  
BEGIN  
 --Declare @userid bigint=34594,@parentid bigint=34594,@fromdate date='2022-05-26',@todate date='2022-05-27'    
 --Admin 39680    
 --IsAdmin 40068    
 --Hirarchy Team head 40060    
 --User 40059    
 --Declare @userid bigint=40060,@parentid bigint=39680,@fromdate date='2022-05-26',@todate date='2022-05-27'   
   

        if(rtrim(ltrim(isnull(@CriteriaName,''))) = '')
	    begin
		     exec usp_getleadreport_MobAPP @userid, @parentid, @fromdate , @todate 
			 return ;
		end
        
      if(not exists(select 1 from tbl_SearchCriteria with(nolock) where ParentID = @parentid
	             and CriteriaName = @CriteriaName and rtrim(ltrim(isnull(@CriteriaName,''))) != ''))
	     begin
		     return;
		 end




 drop table if exists #followup_statusTemp  
    drop table if exists #followup_status  
 drop table if exists #leadinteractionhistory  
 drop table if exists #leadinteractionhistoryWithdatrange  
  
   /*
    declare @LeadCount int =  (select count(1) from Userleads(nolock) where ParentID = @ParentID)
  --declare @UserID bigint = 34594
  -- declare @Criterianame nvarchar(500) = 'All Leads'
   declare @ProcParam nvarchar(max) = N''' set nocount on ; exec Usp_ViewLeadDetailsBySearchCriteria_IDSegment 1,'+cast(@LeadCount as nvarchar(100))+',''''' + @Criterianame + ''''',' + cast(@UserID as nvarchar(50)) + ',0,''''Name''''
    WITH RESULT SETS
	(
	  (
		ID bigint
	  )
	)''' 
    -- print @ProcParam

    declare @QueryTotality nvarchar(max) = concat( N' SELECT ID into #userleadsBySegment  
     FROM  
      OPENROWSET(''sqlncli11'',''Server=10.0.0.132;Database=mysms;Uid=kit19;PWD=P@ssword3110;'',', @ProcParam , ')' )  
   
	*/

	 declare @SPID bigint = isnull((select @@SPID),0)
     delete from [tbl_LeadID_WithSPID] where SP_ID = @SPID  
	
	 drop table if exists  #userleadsBySegment 
    
     declare @LeadCount int =  (select count(1) from Userleads(nolock) where ParentID = @ParentID)

	  exec Usp_ViewLeadDetailsBySearchCriteria_IDSegment_SPID 1,@LeadCount,@Criterianame,@UserID ,0,'Name'
      select LeadID as ID into #userleadsBySegment from tbl_LeadID_WithSPID with(nolock) where SP_ID = @SPID
	 
	 delete from [tbl_LeadID_WithSPID] where SP_ID = @SPID
	  
     declare @QueryTotality nvarchar(max) = ''
    

 /*  
 SELECT *  
 INTO #followup_statusTemp  
 FROM followup_status(NOLOCK) f  
 WHERE isactive = 1  
  AND isnull(parentid, @parentid) = @parentid  
  AND id = (  
   SELECT max(id)  
   FROM followup_status  
   WHERE FollowupStatus = f.FollowupStatus  
    AND isactive = 1  
    AND isnull(parentid, @parentid) = @parentid  
   )  
 */  
   
    
 DECLARE @tbluser TABLE (  
  User_ID BIGINT  
  ,Name VARCHAR(100)  
  ,IMAGE VARCHAR(100)  
  )  
 DECLARE @IsAdmin BIT = 0  
  
 SELECT @IsAdmin = IsAdmin  
 FROM User_Detail(NOLOCK)  
 WHERE User_ID = @Userid  
  
 IF (@IsAdmin = 1)  
 BEGIN  
  --set @Userid = 0;            
  INSERT INTO @tbluser  
  EXEC Use_GetUserDetails @ParentId  
 END  
 ELSE  
 BEGIN  
  INSERT INTO @tbluser  
  EXEC Use_GetUserDetails @UserId  
 END  
  
 DECLARE @TeamCode VARCHAR(10) = ''  
 DECLARE @ScopeCode VARCHAR(10) = ''  
 DECLARE @UserIdTeamLst VARCHAR(4000) = ''  
 DECLARE @HierarchyJSON VARCHAR(Max) = ''  
  
 SELECT @UserIdTeamLst = isnull(STRING_AGG(User_ID, ','), '')  
 FROM @tbluser  
  
 PRINT '@UserIdTeamLst: ' + @UserIdTeamLst  
  
 IF OBJECT_ID(N'tempdb..#followup_status') IS NOT NULL  
 BEGIN  
  DROP TABLE #followup_status  
 END  
  

  set @QueryTotality = concat( @QueryTotality , N' select * into #leadinteractionhistory from LeadInteractionHistory(nolock) 
	where parentid= ',cast( @parentid as nvarchar(50)),' and cast(CreatedOn as date) between ''', @fromdate ,''' and ''', @todate, '''')
	
	
	set @QueryTotality = concat( @QueryTotality , N' select * into #leadinteractionhistoryWithdatrange from LeadInteractionHistory(nolock)
	 where parentid = ', @parentid  )
  
  
   set @QueryTotality = CONCAT(@QueryTotality , N'
	SELECT u.user_id
		,u.user_login
		,isnull(NewLeadsAdded, 0) NewLeadsAdded
		,isnull(TotalLeadsAssignedCurrently, 0) TotalLeadsAssignedCurrently
		,isnull(UniqueLeadsFollowedUp, 0) UniqueLeadsFollowedUp
		,isnull(TotalFollowupsMarked, 0) TotalFollowupsMarked
		,isnull(UntouchedLeads, 0) UntouchedLeads
		,isnull(LeadsOverDue, 0) LeadsOverDue
		,u.User_Login + '' ('' + isnull(u.FName, '''') + '' '' + isnull(u.LName, '''') + '')'' AS UserByName
	FROM user_detail(NOLOCK) u
	LEFT JOIN (
		SELECT user_login
			,sum(CASE 
					WHEN cast(u.createdon as date) BETWEEN ''', @fromdate , '''
							AND ''', @todate ,'''
						THEN 1
					ELSE 0
					END) AS NewLeadsAdded
		FROM userleads u(NOLOCK)
		join #userleadsBySegment as uls on u.ID = uls.ID
		JOIN user_detail(NOLOCK) ul ON ul.User_ID = u.CreatedBy
		WHERE u.parentid = ', cast( @parentid as nvarchar(50) ), '
		GROUP BY user_login
		) nwl ON nwl.User_Login = u.User_Login
	LEFT JOIN (
		SELECT user_login
			,sum(CASE 
					WHEN cast(followupdate as date) < cast(getdate() as date)
						AND isnull(f.IsConvert, 0) <> 1
						THEN 1
					ELSE 0
					END) AS LeadsOverDue
			,count(1) TotalLeadsAssignedCurrently
		FROM userleads u(NOLOCK)
		join #userleadsBySegment as uls on u.ID = uls.ID
		JOIN user_detail(NOLOCK) ul ON ul.User_ID = u.AssignedTo
		LEFT JOIN FollowUp_Status(NOLOCK) f ON f.id = u.FollowUpStatus
		WHERE u.parentid = ', cast(@parentid as nvarchar(50)), '
		GROUP BY user_login
		) OD ON OD.User_Login = u.User_Login
	LEFT JOIN (
		SELECT user_login
			,count(1) AS UntouchedLeads
		FROM userleads u(NOLOCK) 
		join #userleadsBySegment as uls on u.ID = uls.ID
		JOIN user_detail(NOLOCK) ul ON u.AssignedTo = ul.User_ID
		WHERE u.parentid = ', cast( @parentid as nvarchar(50)) , '
			AND (
				isnull(LastFollowupCreatedBy, 0) = 0
				OR NOT EXISTS (
					SELECT 1
					FROM #leadinteractionhistoryWithdatrange(NOLOCK)
					WHERE isreassign = 0
						AND leadno = u.leadno
						AND parentid = u.parentid
					)
				)
		GROUP BY user_login
		) UL ON UL.User_Login = u.User_Login
	LEFT JOIN (
		SELECT user_login
			,sum(CASE 
					WHEN l.createdby = User_ID
						THEN 1
					ELSE 0
					END) AS UniqueLeadsFollowedUp
			,sum(TotalFollowupsMarked) TotalFollowupsMarked --,sum(case when l.createdby is null then 1 else 0 end) as UntouchedLeads                
		FROM (
			SELECT lih1.leadno
				,lih1.parentid
				,lih1.createdby
				,count(1) AS TotalFollowupsMarked
			FROM #leadinteractionhistory(NOLOCK) as lih1
			join followup_status(nolock) as fs1
			on lih1.FollowUpStatus = fs1.ID
 			WHERE lih1.parentid = ', CAST(@parentid as nvarchar(50)),'
				AND lih1.IsReassign = 0
				AND cast(lih1.createdon as date) BETWEEN ''', @fromdate , '''
					AND ''' , @todate ,
                ''' And  isnull(fs1.IsConvert,0) <> 1    
			GROUP BY leadno
				,lih1.parentid
				,lih1.createdby
			) l
		JOIN user_detail(NOLOCK) ul ON ul.User_ID = l.createdby
		WHERE l.parentid = ', CAST(@parentid as nvarchar(50)) , '
		GROUP BY User_Login
		) LF ON u.user_login = LF.User_Login
	WHERE u.parentid = ', cast(@parentid as nvarchar(50)) , '
		AND (
			u.User_ID IN (
				CASE 
					WHEN ', cast( @IsAdmin as nvarchar(50)) ,' = 1
						THEN u.User_ID
					END
				)
			OR u.User_ID IN (
				  ', @UserIdTeamLst ,'
				--SELECT User_ID
				--FROM @tbluser
				)
			)')

  
    --drop table if exists #leadinteractionhistory  
    --drop table if exists #leadinteractionhistoryWithdatrange  
 
 SELECT *  
 INTO #followup_status  
 FROM followup_status(NOLOCK) f  
 WHERE isactive = 1  
  AND isnull(parentid, @parentid) = @parentid  
  AND id = (  
   SELECT max(id)  
   FROM followup_status(nolock)  
   WHERE FollowupStatus = f.FollowupStatus  
    AND isactive = 1  
    AND isnull(parentid, @parentid) = @parentid  
    and isnull(IsConvert,0) <> 1  
   )  
  
 DECLARE @listtopivot NVARCHAR(max)  
  ,@sql NVARCHAR(max)  
  , @ListPivotSelect nvarchar(max)   
 SELECT @listtopivot = coalesce(@listtopivot + ',', '') + '[' + FollowUpStatus + ']'  
 FROM #followup_status(NOLOCK) where FollowupStatus != ''  
  
 SELECT @ListPivotSelect = STRING_AGG( + ' isnull(' + QUOTENAME(FollowUpStatus) + ',0) as ' + Replace(replace(FollowUpStatus,' ',''),'-','') ,',')  
 FROM #followup_status(NOLOCK) where FollowupStatus != ''   
  
  
  
 --where parentid=@parentid and IsActive=1  and isdisabled=0                    
 SELECT @sql = 'select User_ID, user_login, '+ @ListPivotSelect +' , UserByName from ( SELECT * FROM (                          
   select    ul.User_ID, user_login,f.followupstatus,                  
   sum(case when l.createdby=User_ID and l.followupstatus=f.id then 1 else 0 end) as Count      
    , ul.User_Login + '' ('' + isnull(ul.FName,'''') + '' '' + isnull(ul.LName,'''') + '')'' as UserByName                          
   from leadinteractionhistory(nolock) l                     
   join user_detail(nolock) ul on ul.User_ID=l.createdby                    
   join #followup_status(nolock) f on f.ID=l.FollowUpStatus                   
   where l.parentid=' + cast(@parentid AS NVARCHAR) + ' and IsReassign=0                   
   and cast(createdon as date) between ''' + cast(@fromdate AS NVARCHAR) + ''' and ''' + cast(@todate AS NVARCHAR) + '''            
               
    and (ul.User_ID in ( case when ''' + CAST(@IsAdmin AS NVARCHAR) + ''' = ''1'' then ul.User_ID            
       end             
       )            
      or     
       ul.User_ID in ((select * from STRING_SPLIT(''' + isnull(  
   @UserIdTeamLst, '') + ''', '','')))     
   )     
            
                     
   group by ul.User_ID,user_login,f.followupstatus,ul.FName,ul.LName      )                   
   FollowupsDone                        
   PIVOT (                  
   SUM([Count])                          
   FOR [followupstatus]                          
   IN ( ' + @listtopivot + '                  
   )                  
   ) AS PivotTable ) as tblSelectAlias '  
  
 --PRINT @sql  
  
  -- EXEC (@sql)  
   set @QueryTotality = concat(@QueryTotality , ' ; ',@sql)

    set @QueryTotality  = concat( @QueryTotality,' ; ',' SELECT u.User_ID
		,u.user_login
		,u.User_Login + '' ('' + isnull(u.FName, '''') + '' '' + isnull(u.LName, '''') + '')'' AS UserByName
		,isnull(NewAdded, 0) NewAdded
		,isnull(Deleted, 0) Deleted
		,isnull(Expired, 0) Expired
		,isnull(Won, 0) Won
		,isnull(Lost, 0) Lost
		,isnull(AverageDaysToWin, 0) AverageDaysToWin
		,isnull(CurrentlyinPipeline, 0) CurrentlyinPipeline
		,ISNULL(Stagnant, 0) AS Stagnant
	FROM user_detail(NOLOCK) u
	LEFT JOIN (
		SELECT user_login
			,sum(CASE 
					WHEN cast(createddate as date) BETWEEN ''', @fromdate , '''
							AND ''', @todate ,'''
						THEN 1
					ELSE 0
					END) AS NewAdded
			,sum(CASE 
					WHEN cast(DeletedOn as date) BETWEEN ''', @fromdate , '''
							AND ''', @todate ,'''
						THEN 1
					ELSE 0
					END) AS Deleted
		--FROM LeadPipelineMapping_earliest(NOLOCK) l
		FROM LeadPipelineMapping_latest(NOLOCK) l
		JOIN user_detail(NOLOCK) u ON u.user_id = l.CreatedBy
		WHERE parentid = ', cast(@parentid as nvarchar(50)) , '
		GROUP BY user_login
		) ND ON ND.User_Login = u.user_login
	LEFT JOIN (
		SELECT user_login
			,sum(CASE 
					WHEN cast(lpm.createddate as date) BETWEEN ''', @fromdate , '''
							AND ''', @todate ,'''
						AND PS.Name = ''Won''
						THEN 1
					ELSE 0
					END) AS Won
			,sum(CASE 
					WHEN cast(lpm.createddate as date) BETWEEN ''', @fromdate , '''
							AND ''', @todate ,'''
						AND PS.Name = ''Lost''
						THEN 1
					ELSE 0
					END) AS Lost
			,sum(CASE 
					WHEN datediff(d, lpm.createddate, getdate()) >= 30
						AND PS.name NOT IN (
							''won''
							,''Lost''
							)
						AND lpm.IsDeleted = 0
						THEN 1
					ELSE 0
					END) AS Stagnant
			,sum(CASE 
					WHEN PS.name NOT IN (
							''won''
							,''Lost''
							)
						AND lpm.IsDeleted = 0
						THEN 1
					ELSE 0
					END) AS CurrentlyinPipeline
			,sum(CASE 
					WHEN datediff(d, l.createddate, lpm.createddate) > pm.DealExpiry
						THEN 1
					ELSE 0
					END) AS Expired
			,avg(CASE 
					WHEN PS.Name = ''Won''
						AND l.leadid IS NOT NULL
						THEN datediff(d, l.createddate, lpm.createddate)
					ELSE - 1
					END) AverageDaysToWin
		FROM LeadPipelineMapping_latest(NOLOCK) lpm
		      join #userleadsBySegment as uls on lpm.LeadID = uls.ID 
		INNER JOIN Pipeline_Master AS PM WITH (NOLOCK) ON LPM.PipelineID = PM.ID
		INNER JOIN PipelineStages AS PS WITH (NOLOCK) ON LPM.PipeLineStage = PS.ID
		LEFT JOIN (
			SELECT leadid
				,createddate
			--FROM LeadPipelineMapping_earliest(NOLOCK)
			FROM LeadPipelineMapping_latest(NOLOCK)
			WHERE isdeleted = 0
			 and LeadId in (select Id from #userleadsBySegment ) 

			) l ON l.leadid = lpm.LeadID
		JOIN user_detail(NOLOCK) u ON u.user_id = lpm.DealOwner
		WHERE pm.parentid = ', cast(@parentid as nvarchar(50)) , '
		GROUP BY user_login
		) wl ON wl.User_Login = u.User_Login
	WHERE u.parentID = ', cast(@parentid as nvarchar(50)) , '
		AND (
			u.User_ID IN (
				CASE 
					WHEN ', cast( @IsAdmin as nvarchar(50)) ,' = 1
						THEN u.User_ID
							--else @UserIdTeamLst           
					END
				)
			OR u.User_ID IN (
				', @UserIdTeamLst ,'
				--SELECT User_ID
				--FROM @tbluser
				)
			)
		AND u.STATUS = 1 ' )

 



 	set @QueryTotality = concat(@QueryTotality , ' ; ' ,
	N'
	SELECT u.User_ID
		,u.user_login
		,u.User_Login + '' ('' + isnull(u.FName, '''') + '' '' + isnull(u.LName, '''') + '')'' AS UserByName
		,Pipeline
		,isnull(NewAdded, 0) NewAdded
		,isnull(Deleted, 0) Deleted
		,isnull(Expired, 0) Expired
		,isnull(Won, 0) Won
		,isnull(Lost, 0) Lost
		,isnull(AverageDaysToWin, 0) AverageDaysToWin
		,isnull(CurrentlyinPipeline, 0) CurrentlyinPipeline
		,ISNULL(Stagnant, 0) Stagnant
	FROM user_detail(NOLOCK) u
	LEFT JOIN (
		SELECT id
			,name AS Pipeline
			,ParentID
		FROM Pipeline_Master(NOLOCK)
		WHERE parentid = ', cast(@parentid as nvarchar(50)) , '			AND isdeleted = 0
		) p ON p.parentid = u.ParentID
	LEFT JOIN (
		SELECT user_login
			,pm.Name AS PipelineN
			,sum(CASE 
					WHEN cast(l.createddate as date) BETWEEN ''', @fromdate , '''
							AND ''', @todate ,'''
						THEN 1
					ELSE 0
					END) AS NewAdded
			,sum(CASE 
					WHEN cast(DeletedOn as date) BETWEEN ''', @fromdate , '''
							AND ''', @todate ,'''
						THEN 1
					ELSE 0
					END) AS Deleted
		--FROM LeadPipelineMapping_earliest(NOLOCK) l
		FROM LeadPipelineMapping_latest(NOLOCK) l
		join #userleadsBySegment as uls on l.LeadID = uls.ID
		INNER JOIN Pipeline_Master AS PM WITH (NOLOCK) ON L.PipelineID = PM.ID
		JOIN user_detail(NOLOCK) u ON u.user_id = l.CreatedBy
		WHERE u.parentid = ', cast(@parentid as nvarchar(50)) , '
		GROUP BY user_login
			,pm.Name
		) ND ON ND.User_Login = u.user_login
		AND ND.PipelineN = p.pipeline
	LEFT JOIN (
		SELECT user_login
			,pm.Name AS PipelineN
			,sum(CASE 
					WHEN cast( lpm.createddate as date) BETWEEN ''', @fromdate , '''
							AND ''', @todate ,'''
						AND PS.Name = ''Won''
						THEN 1
					ELSE 0
					END) AS Won
			,sum(CASE 
					WHEN  cast(lpm.createddate as date) BETWEEN ''', @fromdate , '''
							AND ''', @todate ,'''
						AND PS.Name = ''Lost''
						THEN 1
					ELSE 0
					END) AS Lost
			,sum(CASE 
					WHEN datediff(d, lpm.createddate, getdate()) >= 30
						AND PS.name NOT IN (
							''won''
							,''Lost''
							)
						AND lpm.IsDeleted = 0
						THEN 1
					ELSE 0
					END) AS Stagnant
			,sum(CASE 
					WHEN PS.name NOT IN (
							''won''
							,''Lost''
							)
						AND lpm.IsDeleted = 0
						THEN 1
					ELSE 0
					END) AS CurrentlyinPipeline
			,
			--sum(case when datediff(d,l.createddate,lpm.createddate)>pm.DealExpiry then 1 else 0 end) as Expired,      
			sum(CASE 
					WHEN datediff(DAY, getdate(), lpm.EstimatedClosureDate) <= 0
						THEN 1
					ELSE 0
					END) AS Expired
			,avg(CASE 
					WHEN PS.Name = ''Won''
						AND l.leadid IS NOT NULL
						THEN datediff(d, l.createddate, lpm.createddate)
					ELSE - 1
					END) AverageDaysToWin
		FROM LeadPipelineMapping_latest(NOLOCK) lpm
		join #userleadsBySegment as uls on lpm.LeadID = uls.ID
		INNER JOIN Pipeline_Master AS PM WITH (NOLOCK) ON LPM.PipelineID = PM.ID
		INNER JOIN PipelineStages AS PS WITH (NOLOCK) ON LPM.PipeLineStage = PS.ID
		LEFT JOIN (
			SELECT leadid
				,createddate
			--FROM LeadPipelineMapping_earliest(NOLOCK)
			FROM LeadPipelineMapping_latest(NOLOCK)
			WHERE isdeleted = 0
			   and LeadId in (select Id from #userleadsBySegment )
			) l ON l.leadid = lpm.LeadID
		JOIN user_detail(NOLOCK) u ON u.user_id = lpm.DealOwner
		WHERE pm.parentid = ', cast(@parentid as nvarchar(50)) , '
		GROUP BY user_login
			,pm.Name
		) wl ON wl.User_Login = u.User_Login
		AND wl.PipelineN = p.Pipeline
	WHERE u.parentID = ', cast(@parentid as nvarchar(50)) , '
		AND (
			u.User_ID IN (
				CASE 
					WHEN ', cast( @IsAdmin as nvarchar(50)) ,' = 1
						THEN u.User_ID
							--else @UserIdTeamLst           
					END
				)
			OR u.User_ID IN (
				', @UserIdTeamLst ,'
				--SELECT User_ID
				--FROM @tbluser
				)
			)
		AND u.STATUS = 1
	ORDER BY u.User_Login ')

	exec sp_executesql @QueryTotality  
  
 EXEC MySMSAudit.dbo.Usp_AuditTableDataByParentId @User_id = @userid  
  ,@Activity_type = 'View_Rpt_Lead'  
  ,@ActionType = 'S'  
  ,@RowJson = ''  
  ,@Table_name = 'Userleads and LeadPipelineMapping_latest'  
  
  
   drop table if exists #followup_statusTemp  
      drop table if exists #followup_status  
   drop table if exists #leadinteractionhistory  
   drop table if exists #leadinteractionhistoryWithdatrange  
   drop table if exists  #userleadsBySegment 
END  


GO

/* ============================================================
   Procedure: [dbo].[usp_getleadreport_withSegmentation]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_getleadreport_withSegmentation] --31871,31871,'17-Mar-2023','18-Mar-2023'   --39680,39680,'20221001','20221231'  --34149,34149,'20220721','20220722'                
	 @userid BIGINT
	,@parentid BIGINT
	,@fromdate DATE
	,@todate DATE
	,@CriteriaName nvarchar(500) = null
AS
BEGIN
	--Declare @userid bigint=34594,@parentid bigint=34594,@fromdate date='2022-05-26',@todate date='2022-05-27'  
	--Admin 39680  
	--IsAdmin 40068  
	--Hirarchy Team head 40060  
	--User 40059  
	--Declare @userid bigint=40060,@parentid bigint=39680,@fromdate date='2022-05-26',@todate date='2022-05-27' 
	

	 if(rtrim(ltrim(isnull(@CriteriaName,''))) = '')
	    begin
		     exec usp_getleadreport @userid, @parentid, @fromdate , @todate 
			 return ;
		end
        
      if( not exists(select 1 from tbl_SearchCriteria with(nolock)  where ParentID = @parentid and CriteriaName = @CriteriaName
	      and rtrim(ltrim(isnull(@CriteriaName,''))) != '')
	  )
	     begin
		     return;
		 end



	drop table if exists #followup_statusTemp
    drop table if exists #followup_status
	drop table if exists #leadinteractionhistory
	drop table if exists #leadinteractionhistoryWithdatrange
	drop table if exists #userleadsBySegment 

	/*

	declare @LeadCount int =  (select count(1) from Userleads(nolock) where ParentID = @ParentID)

  --declare @UserID bigint = 34594
  -- declare @Criterianame nvarchar(500) = 'All Leads'
   declare @ProcParam nvarchar(max) = N''' set nocount on ; exec Usp_ViewLeadDetailsBySearchCriteria_IDSegment 1,'+cast(@LeadCount as nvarchar(100))+',''''' + @Criterianame + ''''',' + cast(@UserID as nvarchar(50)) + ',0,''''Name''''
    WITH RESULT SETS
	(
	  (
		ID bigint
	  )
	)''' 
   
 -- print @ProcParam
 
    declare @QueryTotality nvarchar(max) = concat( N' SELECT ID into #userleadsBySegment  
     FROM  
      OPENROWSET(''sqlncli11'',''Server=10.0.0.132;Database=mysms_dev;Uid=kit19;PWD=P@ssword3110;'',', @ProcParam , ')' )   
    
	*/

		 declare @SPID bigint = isnull((select @@SPID),0)
     delete from [tbl_LeadID_WithSPID] where SP_ID = @SPID  
	
	 drop table if exists  #userleadsBySegment 
    
     declare @LeadCount int =  (select count(1) from Userleads(nolock) where ParentID = @ParentID)

	  exec Usp_ViewLeadDetailsBySearchCriteria_IDSegment_SPID 1,@LeadCount,@Criterianame,@UserID ,0,'Name'
      select LeadID as ID into #userleadsBySegment from tbl_LeadID_WithSPID with(nolock) where SP_ID = @SPID
	 
	 delete from [tbl_LeadID_WithSPID] where SP_ID = @SPID
	  
     declare @QueryTotality nvarchar(max) = ''




	--print (@Query)
	--exec sp_executesql @Query

	/*
	SELECT *
	INTO #followup_statusTemp
	FROM followup_status(NOLOCK) f
	WHERE isactive = 1
		AND isnull(parentid, @parentid) = @parentid
		AND id = (
			SELECT max(id)
			FROM followup_status
			WHERE FollowupStatus = f.FollowupStatus
				AND isactive = 1
				AND isnull(parentid, @parentid) = @parentid
			)
	*/
	
	 
	DECLARE @tbluser TABLE (
		User_ID BIGINT
		,Name VARCHAR(100)
		,IMAGE VARCHAR(100)
		)
	DECLARE @IsAdmin BIT = 0

	SELECT @IsAdmin = IsAdmin
	FROM User_Detail(NOLOCK)
	WHERE User_ID = @Userid

	IF (@IsAdmin = 1)
	BEGIN
		--set @Userid = 0;          
		INSERT INTO @tbluser
		EXEC Use_GetUserDetails @ParentId
	END
	ELSE
	BEGIN
		INSERT INTO @tbluser
		EXEC Use_GetUserDetails @UserId
	END

	DECLARE @TeamCode VARCHAR(10) = ''
	DECLARE @ScopeCode VARCHAR(10) = ''
	DECLARE @UserIdTeamLst VARCHAR(4000) = ''
	DECLARE @HierarchyJSON VARCHAR(Max) = ''

	SELECT @UserIdTeamLst = isnull(STRING_AGG(User_ID, ','), '')
	FROM @tbluser

	PRINT '@UserIdTeamLst: ' + @UserIdTeamLst

	IF OBJECT_ID(N'tempdb..#followup_status') IS NOT NULL
	BEGIN
		DROP TABLE #followup_status
	END

	set @QueryTotality = concat( @QueryTotality , N' select * into #leadinteractionhistory from LeadInteractionHistory(nolock) 
	where parentid= ',cast( @parentid as nvarchar(50)),' and cast(CreatedOn as date) between ''', @fromdate ,''' and ''', @todate, '''')
	
	
	set @QueryTotality = concat( @QueryTotality , N' select * into #leadinteractionhistoryWithdatrange from LeadInteractionHistory(nolock)
	 where parentid = ', @parentid  )


  set @QueryTotality = CONCAT(@QueryTotality , N'
	SELECT u.user_id
		,u.user_login
		,isnull(NewLeadsAdded, 0) NewLeadsAdded
		,isnull(TotalLeadsAssignedCurrently, 0) TotalLeadsAssignedCurrently
		,isnull(UniqueLeadsFollowedUp, 0) UniqueLeadsFollowedUp
		,isnull(TotalFollowupsMarked, 0) TotalFollowupsMarked
		,isnull(UntouchedLeads, 0) UntouchedLeads
		,isnull(LeadsOverDue, 0) LeadsOverDue
		,u.User_Login + '' ('' + isnull(u.FName, '''') + '' '' + isnull(u.LName, '''') + '')'' AS UserByName
	FROM user_detail(NOLOCK) u
	LEFT JOIN (
		SELECT user_login
			,sum(CASE 
					WHEN cast(u.createdon as date) BETWEEN ''', @fromdate , '''
							AND ''', @todate ,'''
						THEN 1
					ELSE 0
					END) AS NewLeadsAdded
		FROM userleads u(NOLOCK)
		join #userleadsBySegment as uls on u.ID = uls.ID
		JOIN user_detail(NOLOCK) ul ON ul.User_ID = u.CreatedBy
		WHERE u.parentid = ', cast( @parentid as nvarchar(50) ), '
		GROUP BY user_login
		) nwl ON nwl.User_Login = u.User_Login
	LEFT JOIN (
		SELECT user_login
			,sum(CASE 
					WHEN cast(followupdate as date) < cast(getdate() as date)
						AND isnull(f.IsConvert, 0) <> 1
						THEN 1
					ELSE 0
					END) AS LeadsOverDue
			,count(1) TotalLeadsAssignedCurrently
		FROM userleads u(NOLOCK)
		join #userleadsBySegment as uls on u.ID = uls.ID
		JOIN user_detail(NOLOCK) ul ON ul.User_ID = u.AssignedTo
		LEFT JOIN FollowUp_Status(NOLOCK) f ON f.id = u.FollowUpStatus
		WHERE u.parentid = ', cast(@parentid as nvarchar(50)), '
		GROUP BY user_login
		) OD ON OD.User_Login = u.User_Login
	LEFT JOIN (
		SELECT user_login
			,count(1) AS UntouchedLeads
		FROM userleads u(NOLOCK) 
		join #userleadsBySegment as uls on u.ID = uls.ID
		JOIN user_detail(NOLOCK) ul ON u.AssignedTo = ul.User_ID
		WHERE u.parentid = ', cast( @parentid as nvarchar(50)) , '
			AND (
				isnull(LastFollowupCreatedBy, 0) = 0
				OR NOT EXISTS (
					SELECT 1
					FROM #leadinteractionhistoryWithdatrange(NOLOCK)
					WHERE isreassign = 0
						AND leadno = u.leadno
						AND parentid = u.parentid
					)
				)
		GROUP BY user_login
		) UL ON UL.User_Login = u.User_Login
	LEFT JOIN (
		SELECT user_login
			,sum(CASE 
					WHEN l.createdby = User_ID
						THEN 1
					ELSE 0
					END) AS UniqueLeadsFollowedUp
			,sum(TotalFollowupsMarked) TotalFollowupsMarked --,sum(case when l.createdby is null then 1 else 0 end) as UntouchedLeads                
		FROM (
			SELECT lih1.leadno
				,lih1.parentid
				,lih1.createdby
				,count(1) AS TotalFollowupsMarked
			FROM #leadinteractionhistory(NOLOCK) as lih1
			join userleads(nolock) as ulr
			 on ulr.LeadNo = lih1.LeadNo and ulr.ParentID = lih1.ParentID
            join #userleadsBySegment as uls on ulr.ID = uls.ID   
			join followup_status(nolock) as fs1
			on lih1.FollowUpStatus = fs1.ID
 			WHERE lih1.parentid = ', CAST(@parentid as nvarchar(50)),'
				AND lih1.IsReassign = 0
				 And  isnull(fs1.IsConvert,0) <> 1    
			GROUP BY lih1.leadno
				,lih1.parentid
				,lih1.createdby
			) l
		JOIN user_detail(NOLOCK) ul ON ul.User_ID = l.createdby
		WHERE l.parentid = ', CAST(@parentid as nvarchar(50)) , '
		GROUP BY User_Login
		) LF ON u.user_login = LF.User_Login
	WHERE u.parentid = ', cast(@parentid as nvarchar(50)) , '
		AND (
			u.User_ID IN (
				CASE 
					WHEN ', cast( @IsAdmin as nvarchar(50)) ,' = 1
						THEN u.User_ID
					END
				)
			OR u.User_ID IN (
				  ', @UserIdTeamLst ,'
				--SELECT User_ID
				--FROM @tbluser
				)
			)')


     -- print 'Query:  ' + @QueryTotality
     -- exec sp_executesql @QueryTotality


      -- drop table if exists #leadinteractionhistory
       -- drop table if exists #leadinteractionhistoryWithdatrange
	
	--return
	
	SELECT *
	INTO #followup_status
	FROM followup_status(NOLOCK) f
	WHERE isactive = 1
		AND isnull(parentid, @parentid) = @parentid
		AND id = (
			SELECT max(id)
			FROM followup_status(nolock)
			WHERE FollowupStatus = f.FollowupStatus
				AND isactive = 1
				AND isnull(parentid, @parentid) = @parentid
				and isnull(IsConvert,0) <> 1
			)

	DECLARE @listtopivot NVARCHAR(max)
		,@sql NVARCHAR(max)

	SELECT @listtopivot = coalesce(@listtopivot + ',', '') + '[' + FollowUpStatus + ']'
	FROM #followup_status(NOLOCK) where FollowupStatus != ''

	--where parentid=@parentid and IsActive=1  and isdisabled=0                  
	SELECT @sql = 'SELECT * FROM (                        
   select    ul.User_ID, user_login,f.followupstatus,                
   sum(case when l.createdby=User_ID and l.followupstatus=f.id then 1 else 0 end) as Count    
    , ul.User_Login + '' ('' + isnull(ul.FName,'''') + '' '' + isnull(ul.LName,'''') + '')'' as UserByName                        
   from leadinteractionhistory(nolock) l 
   left join userleads (nolock) as ul_tbl on l.Leadno = ul_tbl.leadno and l.parentID = ul_tbl.parentID
   and ul_tbl.parentID = ' + cast(@parentid AS NVARCHAR) + '
   join #userleadsBySegment as uls on ul_tbl.ID = uls.ID
   join user_detail(nolock) ul on ul.User_ID=l.createdby                  
   join #followup_status(nolock) f on f.ID=l.FollowUpStatus                 
   where l.parentid=' + cast(@parentid AS NVARCHAR) + ' and IsReassign=0                 
   and cast(l.createdon as date) between ''' + cast(@fromdate AS NVARCHAR) + ''' and ''' + cast(@todate AS NVARCHAR) + '''          
             
    and (ul.User_ID in ( case when ''' + CAST(@IsAdmin AS NVARCHAR) + ''' = ''1'' then ul.User_ID          
       end           
       )          
      or   
       ul.User_ID in ((select * from STRING_SPLIT(''' + isnull(
			@UserIdTeamLst, '') + ''', '','')))   
   )   
          
                   
   group by ul.User_ID,user_login,f.followupstatus,ul.FName,ul.LName      )                 
   FollowupsDone                      
   PIVOT (                
   SUM([Count])                        
   FOR [followupstatus]                        
   IN ( ' + @listtopivot + '                
   )                
   ) AS PivotTable'

	--PRINT @sql

	--EXEC (@sql)

     set @QueryTotality = concat(@QueryTotality , ' ; ',@sql)
--	exec sp_executesql @QueryTotality
--	return ;

   set @QueryTotality  = concat( @QueryTotality,' ; ',' SELECT u.User_ID
		,u.user_login
		,u.User_Login + '' ('' + isnull(u.FName, '''') + '' '' + isnull(u.LName, '''') + '')'' AS UserByName
		,isnull(NewAdded, 0) NewAdded
		,isnull(Deleted, 0) Deleted
		,isnull(Expired, 0) Expired
		,isnull(Won, 0) Won
		,isnull(Lost, 0) Lost
		,isnull(AverageDaysToWin, 0) AverageDaysToWin
		,isnull(CurrentlyinPipeline, 0) CurrentlyinPipeline
		,ISNULL(Stagnant, 0) AS Stagnant
	FROM user_detail(NOLOCK) u
	LEFT JOIN (
		SELECT user_login
			,sum(CASE 
					WHEN cast(createddate as date) BETWEEN ''', @fromdate , '''
							AND ''', @todate ,'''
						THEN 1
					ELSE 0
					END) AS NewAdded
			,sum(CASE 
					WHEN cast(DeletedOn as date) BETWEEN ''', @fromdate , '''
							AND ''', @todate ,'''
						THEN 1
					ELSE 0
					END) AS Deleted
		--FROM LeadPipelineMapping_earliest(NOLOCK) l
		FROM LeadPipelineMapping_latest(NOLOCK) l
		JOIN user_detail(NOLOCK) u ON u.user_id = l.CreatedBy
		WHERE parentid = ', cast(@parentid as nvarchar(50)) , '
		GROUP BY user_login
		) ND ON ND.User_Login = u.user_login
	LEFT JOIN (
		SELECT user_login
			,sum(CASE 
					WHEN cast(lpm.createddate as date) BETWEEN ''', @fromdate , '''
							AND ''', @todate ,'''
						AND PS.Name = ''Won''
						THEN 1
					ELSE 0
					END) AS Won
			,sum(CASE 
					WHEN cast(lpm.createddate as date) BETWEEN ''', @fromdate , '''
							AND ''', @todate ,'''
						AND PS.Name = ''Lost''
						THEN 1
					ELSE 0
					END) AS Lost
			,sum(CASE 
					WHEN datediff(d, lpm.createddate, getdate()) >= 30
						AND PS.name NOT IN (
							''won''
							,''Lost''
							)
						AND lpm.IsDeleted = 0
						THEN 1
					ELSE 0
					END) AS Stagnant
			,sum(CASE 
					WHEN PS.name NOT IN (
							''won''
							,''Lost''
							)
						AND lpm.IsDeleted = 0
						THEN 1
					ELSE 0
					END) AS CurrentlyinPipeline
			,sum(CASE 
					WHEN datediff(d, l.createddate, lpm.createddate) > pm.DealExpiry
						THEN 1
					ELSE 0
					END) AS Expired
			,avg(CASE 
					WHEN PS.Name = ''Won''
						AND l.leadid IS NOT NULL
						THEN datediff(d, l.createddate, lpm.createddate)
					ELSE - 1
					END) AverageDaysToWin
		FROM LeadPipelineMapping_latest(NOLOCK) lpm
		      join #userleadsBySegment as uls on lpm.LeadID = uls.ID 
		INNER JOIN Pipeline_Master AS PM WITH (NOLOCK) ON LPM.PipelineID = PM.ID
		INNER JOIN PipelineStages AS PS WITH (NOLOCK) ON LPM.PipeLineStage = PS.ID
		LEFT JOIN (
			SELECT leadid
				,createddate
			--FROM LeadPipelineMapping_earliest(NOLOCK)
			FROM LeadPipelineMapping_latest(NOLOCK)
			WHERE isdeleted = 0
			 and LeadId in (select Id from #userleadsBySegment ) 

			) l ON l.leadid = lpm.LeadID
		JOIN user_detail(NOLOCK) u ON u.user_id = lpm.DealOwner
		WHERE pm.parentid = ', cast(@parentid as nvarchar(50)) , '
		GROUP BY user_login
		) wl ON wl.User_Login = u.User_Login
	WHERE u.parentID = ', cast(@parentid as nvarchar(50)) , '
		AND (
			u.User_ID IN (
				CASE 
					WHEN ', cast( @IsAdmin as nvarchar(50)) ,' = 1
						THEN u.User_ID
							--else @UserIdTeamLst           
					END
				)
			OR u.User_ID IN (
				', @UserIdTeamLst ,'
				--SELECT User_ID
				--FROM @tbluser
				)
			)
		AND u.STATUS = 1 ' )

	
	-- exec sp_executesql @QueryTotality ;
	 --return ;
	
	set @QueryTotality = concat(@QueryTotality , ' ; ' ,
	N'
	SELECT u.User_ID
		,u.user_login
		,u.User_Login + '' ('' + isnull(u.FName, '''') + '' '' + isnull(u.LName, '''') + '')'' AS UserByName
		,Pipeline
		,isnull(NewAdded, 0) NewAdded
		,isnull(Deleted, 0) Deleted
		,isnull(Expired, 0) Expired
		,isnull(Won, 0) Won
		,isnull(Lost, 0) Lost
		,isnull(AverageDaysToWin, 0) AverageDaysToWin
		,isnull(CurrentlyinPipeline, 0) CurrentlyinPipeline
		,ISNULL(Stagnant, 0) Stagnant
	FROM user_detail(NOLOCK) u
	LEFT JOIN (
		SELECT id
			,name AS Pipeline
			,ParentID
		FROM Pipeline_Master(NOLOCK)
		WHERE parentid = ', cast(@parentid as nvarchar(50)) , '			AND isdeleted = 0
		) p ON p.parentid = u.ParentID
	LEFT JOIN (
		SELECT user_login
			,pm.Name AS PipelineN
			,sum(CASE 
					WHEN cast(l.createddate as date) BETWEEN ''', @fromdate , '''
							AND ''', @todate ,'''
						THEN 1
					ELSE 0
					END) AS NewAdded
			,sum(CASE 
					WHEN cast(DeletedOn as date) BETWEEN ''', @fromdate , '''
							AND ''', @todate ,'''
						THEN 1
					ELSE 0
					END) AS Deleted
		--FROM LeadPipelineMapping_earliest(NOLOCK) l
		FROM LeadPipelineMapping_latest(NOLOCK) l
		join #userleadsBySegment as uls on l.LeadID = uls.ID
		INNER JOIN Pipeline_Master AS PM WITH (NOLOCK) ON L.PipelineID = PM.ID
		JOIN user_detail(NOLOCK) u ON u.user_id = l.CreatedBy
		WHERE u.parentid = ', cast(@parentid as nvarchar(50)) , '
		GROUP BY user_login
			,pm.Name
		) ND ON ND.User_Login = u.user_login
		AND ND.PipelineN = p.pipeline
	LEFT JOIN (
		SELECT user_login
			,pm.Name AS PipelineN
			,sum(CASE 
					WHEN cast( lpm.createddate as date) BETWEEN ''', @fromdate , '''
							AND ''', @todate ,'''
						AND PS.Name = ''Won''
						THEN 1
					ELSE 0
					END) AS Won
			,sum(CASE 
					WHEN  cast(lpm.createddate as date) BETWEEN ''', @fromdate , '''
							AND ''', @todate ,'''
						AND PS.Name = ''Lost''
						THEN 1
					ELSE 0
					END) AS Lost
			,sum(CASE 
					WHEN datediff(d, lpm.createddate, getdate()) >= 30
						AND PS.name NOT IN (
							''won''
							,''Lost''
							)
						AND lpm.IsDeleted = 0
						THEN 1
					ELSE 0
					END) AS Stagnant
			,sum(CASE 
					WHEN PS.name NOT IN (
							''won''
							,''Lost''
							)
						AND lpm.IsDeleted = 0
						THEN 1
					ELSE 0
					END) AS CurrentlyinPipeline
			,
			--sum(case when datediff(d,l.createddate,lpm.createddate)>pm.DealExpiry then 1 else 0 end) as Expired,      
			sum(CASE 
					WHEN datediff(DAY, getdate(), lpm.EstimatedClosureDate) <= 0
						THEN 1
					ELSE 0
					END) AS Expired
			,avg(CASE 
					WHEN PS.Name = ''Won''
						AND l.leadid IS NOT NULL
						THEN datediff(d, l.createddate, lpm.createddate)
					ELSE - 1
					END) AverageDaysToWin
		FROM LeadPipelineMapping_latest(NOLOCK) lpm
		join #userleadsBySegment as uls on lpm.LeadID = uls.ID
		INNER JOIN Pipeline_Master AS PM WITH (NOLOCK) ON LPM.PipelineID = PM.ID
		INNER JOIN PipelineStages AS PS WITH (NOLOCK) ON LPM.PipeLineStage = PS.ID
		LEFT JOIN (
			SELECT leadid
				,createddate
			--FROM LeadPipelineMapping_earliest(NOLOCK)
			FROM LeadPipelineMapping_latest(NOLOCK)
			WHERE isdeleted = 0
			   and LeadId in (select Id from #userleadsBySegment )
			) l ON l.leadid = lpm.LeadID
		JOIN user_detail(NOLOCK) u ON u.user_id = lpm.DealOwner
		WHERE pm.parentid = ', cast(@parentid as nvarchar(50)) , '
		GROUP BY user_login
			,pm.Name
		) wl ON wl.User_Login = u.User_Login
		AND wl.PipelineN = p.Pipeline
	WHERE u.parentID = ', cast(@parentid as nvarchar(50)) , '
		AND (
			u.User_ID IN (
				CASE 
					WHEN ', cast( @IsAdmin as nvarchar(50)) ,' = 1
						THEN u.User_ID
							--else @UserIdTeamLst           
					END
				)
			OR u.User_ID IN (
				', @UserIdTeamLst ,'
				--SELECT User_ID
				--FROM @tbluser
				)
			)
		AND u.STATUS = 1
	ORDER BY u.User_Login ')

	exec sp_executesql @QueryTotality



	EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @userid
		,@Activity_type = 'View_Rpt_Lead'
		,@ActionType = 'S'
		,@RowJson = ''
		,@Table_name = 'Userleads and LeadPipelineMapping_latest'


	  drop table if exists #followup_statusTemps
      drop table if exists #followup_status
	  drop table if exists #leadinteractionhistory
	  drop table if exists #leadinteractionhistoryWithdatrange
	  drop table if exists #userleadsBySegment 

	  drop table if exists  #userleadsBySegment 
END



