/* ============================================================
   Procedure: [dbo].[Usp_GetLeadScoreRules]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.Usp_GetLeadScoreRules --'Lead Attributes',335  
 (  
   @Category nvarchar(100),  
   @ParentID bigint  
 )  
 as  
 Begin  
  
     declare @CategoryID int = 0  
   select @CategoryID = isnull(id,0) from lead_scoring_categories(nolock)  
      where Category = @Category    
  
  
      SELECT   
    id  
      ,parentid  
      ,cat_id  
      ,event_id  
   ,(select  isnull(EventName,'') from ActivityMaster(nolock) where id = event_id) as EventName  
      ,rule_desc  
      ,Operation  
      ,points  
      ,createdby  
      ,createdon  
      ,isdeleted  
      ,lastupdatedon  
      ,lastupdatedby  
       FROM lead_scoring_rules(nolock) as LSR  
    where  
     cat_id = @CategoryID  
     and  
     parentid = @ParentID   
  and   
  isdeleted = 0  
  
     order by id desc
  
end  


