/* ============================================================
   Procedure: [dbo].[Usp_getLeadsLastProducts]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

      
CREATE   PROCEDURE [dbo].[Usp_getLeadsLastProducts]  
(  
    @LeadNo       BIGINT,  
    @ParentID     BIGINT,
    @Out nvarchar(max) output
)  
 as
BEGIN  
 DECLARE @String NVARCHAR(max)
 Declare @FinalString nvarchar(max)

           exec Usp_createProductMasterTable @ParentID

 Declare @Query nvarchar(max) = N' 
     
 SELECT TOP 1 @String = A.ProductName  
 FROM   (  
            SELECT TOP 2(  
                       SELECT STUFF(  
                                  (  
                                      SELECT N'', '' + pm.Name    
                                      FROM   tbl_ProductMaster_' + cast(@ParentID as nvarchar(20)) + '  (nolock) pm  
                                             INNER JOIN dbo.fn_Split(lih.Products, ''#'') AS   
                                                  fs  
                                                  ON  pm.ProductID = fs.[value]   
                                                      FOR XML   
                                                      PATH(''''),  
                                             TYPE  
                                  )   
                                  .value(''text()[1]'', ''nvarchar(max)''),  
                                  1,  
                                  2,  
                                  N''''  
                              )  
            ) AS ProductName,  
                   lih.CreatedOn  
            FROM   LeadInteractionHistory lih  
            WHERE  lih.LeadNo = ' + cast(@LeadNo as nvarchar(20)) + '  
                   AND lih.ParentID = '+ cast(@ParentID as nvarchar(20)) +' 
            ORDER BY  
                   lih.CreatedOn DESC  
        ) A  
 ORDER BY  
        A.CreatedOn '
	
	--print @Query	
    exec sp_executesql @Query, N' @String nvarchar(max) out',@FinalString out     
	set @Out = @FinalString 
	
END   


GO

