     FROM   (  
            SELECT TOP 1(  
                       SELECT STUFF(  
                                  (  
                                      SELECT N'', '' + pm.Name  
                                      FROM   tbl_ProductMaster_' + cast(@ParentID as nvarchar(20)) + '  (nolock) pm  
                                             INNER JOIN dbo.fn_Split(lih.Products, ''#'') AS   
                                                  fs  
                                                  ON  pm.ProductID = fs.[value]   
                                                        
                                                      FOR XML   
                                                        
                                                      PATH(''''),  
