/* ============================================================
   Procedure: [dbo].[usp_GetLicenceTransDetailsByUserID]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[usp_GetLicenceTransDetailsByUserID]
    @UserID BIGINT
AS
BEGIN
    SET NOCOUNT ON;

    BEGIN TRY
        -- Declare variable to store M_ID
        DECLARE @M_ID BIGINT;

        -- Step 1: Retrieve M_ID for the given UserID
        SELECT TOP 1 @M_ID = M_ID
        FROM [dbo].[User_Detail] with(nolock)
        WHERE [User_ID] = @UserID;

        -- Step 2: If M_ID is found, retrieve the associated details
        IF @M_ID IS NOT NULL
        BEGIN
            SELECT 
                --[ID],
                [Transaction_ID],
                --[M_ID],
                --[FromUser_ID],
                --[ToUser_ID],
				 CONCAT(udFrom.[fname], ' ', udFrom.[lname]) AS FromUserName,
                CONCAT(udTo.[fname], ' ', udTo.[lname]) AS ToUserName,
                [Debits],
                [Credits],
                [Balance],
                [Validity],
                [Default_Credit],
                [FromDate],
                [ToDate],
                [typecredit],
                [batchid],
                [CreatedBy],
                [CreatedDate],
                [ModifiedDate],
                --[LastModified],
				[Remarks],
				[TotalLicence]
            FROM [dbo].[Licence_Trans_Details] ltd
			LEFT JOIN 
                [dbo].[User_Detail] udFrom with(nolock) ON ltd.[FromUser_ID] = udFrom.[User_ID]
            LEFT JOIN 
                [dbo].[User_Detail] udTo with(nolock) ON ltd.[ToUser_ID] = udTo.[User_ID]
            WHERE ltd.[M_ID] = @M_ID and [IsActive]=1;
        END
        ELSE
        BEGIN
            -- If no M_ID is found, return a message
            SELECT 
                'No data found for the provided UserID.' AS Message;
        END
    END TRY
    BEGIN CATCH
       exec usp_InsertErrorInfo  
    END CATCH
END;


-------------------------------------------------------------------------------------------------



GO

/* ============================================================
   Procedure: [dbo].[usp_GetLicenceTransDetailsByUserID_new1]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[usp_GetLicenceTransDetailsByUserID_new1]
    @UserID BIGINT,
	@LicenseType NVARCHAR(50) -- 'Monthly' or 'Annual'
AS
BEGIN
    SET NOCOUNT ON;

    BEGIN TRY
        
	    IF @LicenseType = 'Monthly'
        BEGIN
            SELECT 
                
				 CONCAT(udFrom.[fname], ' ', udFrom.[lname]) AS FromUserName,
                CONCAT(udTo.[fname], ' ', udTo.[lname]) AS ToUserName,
                [Debit],
                [Credit],
                [Balance],
               
                CreatedOn,
                LicenceExpiryDate,
                [typecredit],
                --[CreatedBy],
				CONCAT(udCreatedBy.[fname], ' ', udCreatedBy.[lname]) AS CreatedByName,
                CreatedOn,
				[Remarks]
				
            FROM [dbo].tbl_pt_PartnerMonthlyLicence pm with(nolock)
			LEFT JOIN 
                [dbo].[User_Detail] as udFrom with(nolock)  ON pm.FromUserId = udFrom.[User_ID]
            LEFT JOIN 
                [dbo].[User_Detail] as udTo with(nolock)  ON pm.ToUserId = udTo.[User_ID]
				LEFT JOIN [dbo].[User_Detail] udCreatedBy 
                ON pm.CreatedBy = udCreatedBy.[User_ID] 
            WHERE pm.ToUserId = @UserID order by pm.CreatedOn desc;
        END
         ELSE IF @LicenseType = 'Annual'
        BEGIN
		 SELECT 
                
				 CONCAT(udFrom.[fname], ' ', udFrom.[lname]) AS FromUserName,
                CONCAT(udTo.[fname], ' ', udTo.[lname]) AS ToUserName,
                [Debit],
                [Credit],
                [Balance],
               
                CreatedOn,
                LicenceExpiryDate,
                [typecredit],
                --[CreatedBy],
				 CONCAT(udCreatedBy.[fname], ' ', udCreatedBy.[lname]) AS CreatedByName,
                CreatedOn,
				[Remarks]
				
            FROM [dbo].tbl_pt_ParnerAnnualLicence pa with(nolock)
			LEFT JOIN 
                [dbo].[User_Detail] udFrom with(nolock) ON pa.FromUserId = udFrom.[User_ID]
            LEFT JOIN 
                [dbo].[User_Detail] udTo with(nolock) ON pa.ToUserId = udTo.[User_ID]
				LEFT JOIN [dbo].[User_Detail] udCreatedBy 
                ON pa.CreatedBy = udCreatedBy.[User_ID]
            WHERE pa.ToUserId = @UserID order by pa.CreatedOn desc;
        END
		 ELSE
        BEGIN
            THROW 50003, 'Invalid LicenseType provided. Use ''Monthly'' or ''Annual''.', 1;
        END

    END TRY
    BEGIN CATCH
       exec usp_InsertErrorInfo  
    END CATCH
END; 

-----------------------------------------------------------------



GO

/* ============================================================
   Procedure: [dbo].[usp_GetListCampaignSearch]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.usp_GetListCampaignSearch
AS
BEGIN
	SELECT A.ID,
	       A.SearchName,
	       (
	           '<p><b>Campaign Name :</b>' + A.CampaignName +
	           '</p><p><b>Sender ID :</b>' +
	           A.SenderID + '</p><p><b>Message :</b>' +
	           A.[Message] + '</p><p><b>Microsite :</b>' + ISNULL(A.MicrositeName, '') 
	           +
	           '</p>'
	       )  AS SearchCriteria
	FROM   (
	           SELECT sd.ID,
	                  sd.SearchName,
	                  cm.CampaignName,
	                  cm.SenderID,
	                  cm.[Message],
	                  (
	                      SELECT TOP 1 csu.URLName
	                      FROM   CampaignShortURL AS csu
	                      WHERE  csu.CampaignName = cm.CampaignName
	                  )              AS MicrositeName,
	                  sd.CreatedDate
	           FROM   SearchDetails  AS sd
	                  INNER JOIN CampaignMaster AS cm
	                       ON  sd.CampaignID = cm.ID 
	                           --AND cm.IsExecuted = 1
	           WHERE  sd.IsList = 1
	       )     A
	ORDER BY
	       A.CreatedDate DESC
END


GO

/* ============================================================
   Procedure: [dbo].[Usp_GetLocationSetting]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

-- dbo.Usp_GetLocationSetting 33819
CREATE   PROCEDURE dbo.Usp_GetLocationSetting (@UserId BIGINT = 0)
AS
BEGIN
	-- declare @UserId bigint=33819
	DECLARE @isadmin BIT = 0
		,@ParentId BIGINT = 0

	SELECT @isadmin = isadmin
		,@ParentId = ParentId
	FROM user_detail(NOLOCK)
	WHERE user_id = @UserId

	IF (@UserId = @ParentId)
	BEGIN
		SET @isadmin = 1
	END

	IF (@isadmin = 1)
	BEGIN
		SELECT h.User_ID ExecutiveID
			,u.FName + ' ' + u.LName Executive
			,Convert(BIGINT, h.FrequencyUnit) Frequency
			,h.Uninstalled Uninstalled
			,h.logout Logout
			,h.Untrackable Untrackable
			,Convert(BIGINT, h.Untrackableunit) UntrackableUnit
		FROM tbl_location_setting h(NOLOCK)
		INNER JOIN User_Detail u(NOLOCK) ON h.User_ID = u.User_ID
			AND u.ParentID = @ParentId
	END
	ELSE
	BEGIN
		SELECT h.User_ID ExecutiveID
			,u.FName + ' ' + u.LName Executive
			,Convert(BIGINT, h.FrequencyUnit) Frequency
			,h.Uninstalled Uninstalled
			,h.logout Logout
			,h.Untrackable Untrackable
			,Convert(BIGINT, h.Untrackableunit) UntrackableUnit
		FROM tbl_location_setting h(NOLOCK)
		INNER JOIN User_Detail u(NOLOCK) ON h.User_ID = u.User_ID
		WHERE h.User_ID = - 1
	END

	EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @UserId
		,@Activity_type = 'View_UsrLocatn'
		,@ActionType = 'S'
		,@RowJson = ''
		,@Table_name = 'tbl_location_setting'
END



GO

