SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.Usp_GetLocationSettinghistory --27701
(                
    @UserID bigint=0              
)                
as                
Begin           
      
select u.FName+' '+ u.LName Executive, case when h.Status = 1 then 'OnField' else 'OffField' end Status, h.Type,    
Convert(Bigint,h.FrequencyUnit) Frequency,    
h.Uninstalled Uninstalled,    
h.logout Logout,    
h.Untrackable Untrackable,    
Convert(Bigint,h.Untrackableunit) UntrackableUnit, u1.FName+' '+ u1.LName Createdby, h.CreatedOn    
from tbl_location_setting_history h(nolock)  inner join User_Detail u(nolock) on h.User_ID = u.User_ID    
inner join User_Detail u1(nolock) on h.Createdby = u1.User_ID  
where h.User_ID  = @UserID    
end   



