/* ============================================================
   Procedure: [dbo].[usp_GetLocationTrackingDetail]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_GetLocationTrackingDetail]  
  
@Userid bigint=0,  
@ParentId bigint=0,  
@mode nvarchar(100) ='',
@FromDate varchar(50) = '',
@ToDate varchar(50) = '',
@UserIds varchar(max) = '',
@Contain varchar(max) = ''
 
as  
begin 


declare @IsAdmin bit  
  

DECLARE @tbluser TABLE (  
  User_ID BIGINT  
  ,Name VARCHAR(100)  
  ,IMAGE VARCHAR(100)  
  )  
  
 SELECT @IsAdmin = IsAdmin  
 FROM User_Detail(NOLOCK)  
 WHERE User_ID = @Userid  
  
 IF (@IsAdmin = 1 and @mode != 'liveLocationTrackingHistory')  
 BEGIN  
  SET @Userid = 0;  
  
  INSERT INTO @tbluser  
  EXEC Use_GetUserDetails @ParentId  
 END  
 ELSE  
 BEGIN  
  INSERT INTO @tbluser  
  EXEC Use_GetUserDetails @UserId  
 END  
 
 if(@mode='User')  
 begin  
	select * from @tbluser  
 end  

if(@mode='liveLocationTrackingDetail')  
begin  
  
WITH RankedLocations AS (  
    SELECT ult.user_id, User_Login  + '('  + FName+ ' ' +LName + ')'  as UserName,
	FName+ ' ' +LName as Name , User_Login as Login ,lastlocationtracked,Currentlytrackable,lastlocationreason,  
           ROW_NUMBER() OVER (PARTITION BY FName ORDER BY lastlocationtracked DESC) AS rn  
    from Userlocationtracking (NOLOCK) ULT  
  
left join User_Detail(NOLOCK) UD on UD.User_ID=Ult.user_id  
left join [TBL_ET_UserLocationTracking](nolock) ULTM on ult.locationid=Ultm.UserLocationTrackingId where fname is not null  
  
)  
SELECT  distinct user_id,UserName,Name,Login,case when Currentlytrackable=0 then 'OFF' else 'ON' end TrackingOn, CASE  
        WHEN  DATEADD(MINUTE, 15, lastlocationtracked) < GETDATE() and Currentlytrackable=0 THEN 'Possibly user has not turned auto start on for the app'  
        ELSE lastlocationreason  
    END AS  Reason, isnull(cast(lastlocationtracked as nvarchar(100)),'NEVER') as lastlocationtrackedTime  
FROM RankedLocations  
WHERE rn = 1 and USER_ID in (select User_id from @tbluser);  
  
end  

if(@mode='liveLocationTrackingHistory')  
begin  
SELECT  distinct ULT.user_id, isnull(cast(lastlocationtracked as nvarchar(100)),'NEVER') as [lastlocationtrackedTime], 
 User_Login + '('  + FName+ ' ' +LName + ')' as UserName, FName+ ' ' +LName as Name , User_Login as Login,case when Currentlytrackable=0 then 'OFF' else 'ON' end TrackingOn, CASE  
        WHEN  DATEADD(MINUTE, 15, lastlocationtracked) < GETDATE() and Currentlytrackable=0 THEN 'Possibly user has not turned auto start on for the app'  
        ELSE lastlocationreason  
    END AS  Reason
FROM   Userlocationtracking (NOLOCK) ULT  
  
left join User_Detail(NOLOCK) UD on UD.User_ID=Ult.user_id  
left join ( 
		select ult.UserLocationTrackingId from [TBL_ET_UserLocationTracking](nolock) ult 
			where ult.UserId in (select item from dbo.fu_SplitString( cast(@UserIds as nvarchar(max)),','))
		union 
		select ulta.UserLocationTrackingId from [TBL_ET_UserLocationTracking_Archived](nolock) ulta
			where ulta.UserId in (select item from dbo.fu_SplitString( cast(@UserIds as nvarchar(max)),','))
				and 1 = ( case when cast(@FromDate as date) <= CAST(GETDATE() as date) and CAST(LocationDateTime as date)
						between CAST(@FromDate AS DATE)  and CAST(@ToDate AS DATE)  then 1 else 0 end )
	) ULTM on ult.locationid=Ultm.UserLocationTrackingId    
WHERE  ULT.user_id =@Userid  --and cast(lastlocationtracked as date)=cast(getdate() as date) 
  
end  

if(@mode='SM')  
begin  
if(@FromDate='1900-01-01')
begin
set @FromDate=''
set @ToDate=''
end

if(@Contain='0')
begin

SELECT  distinct ULT.user_id, isnull(cast(lastlocationtracked as nvarchar(100)),'NEVER') as [lastlocationtrackedTime], 
 User_Login + '('  + FName+ ' ' +LName + ')' as UserName, FName+ ' ' +LName as Name , User_Login as Login,case when Currentlytrackable=0 then 'OFF' else 'ON' end TrackingOn, CASE  
        WHEN  DATEADD(MINUTE, 15, lastlocationtracked) < GETDATE() and Currentlytrackable=0 THEN 'Possibly user has not turned auto start on for the app'  
        ELSE lastlocationreason  
    END AS  Reason
FROM   Userlocationtracking (NOLOCK) ULT  
  
left join User_Detail(NOLOCK) UD on UD.User_ID=Ult.user_id  
left join ( 
		select ult.UserLocationTrackingId from [TBL_ET_UserLocationTracking](nolock) ult 
			where ult.UserId in (select item from dbo.fu_SplitString( cast(@UserIds as nvarchar(max)),','))
		union 
		select ulta.UserLocationTrackingId from [TBL_ET_UserLocationTracking_Archived](nolock) ulta
			where ulta.UserId in (select item from dbo.fu_SplitString( cast(@UserIds as nvarchar(max)),','))
				and 1 = ( case when cast(@FromDate as date) <= CAST(GETDATE() as date) and CAST(LocationDateTime as date)
						between CAST(@FromDate AS DATE)  and CAST(@ToDate AS DATE)  then 1 else 0 end )
	) ULTM on ult.locationid=Ultm.UserLocationTrackingId   
  where ud.User_Id in (select item from dbo.fu_SplitString( cast(@UserIds as nvarchar(max)),',')) 
 and (@FromDate = '' OR cast(lastlocationtracked as date) >=  cast(@FromDate as date)) and (@ToDate ='' OR cast(lastlocationtracked as date)  <= cast(@ToDate as date))
 end


 else if(@Contain='1')
begin

WITH RankedLocations AS (  
    SELECT ult.user_id, User_Login  + '('  + FName+ ' ' +LName + ')'  as UserName,
	FName+ ' ' +LName as Name , User_Login as Login ,lastlocationtracked,Currentlytrackable,lastlocationreason,  
           ROW_NUMBER() OVER (PARTITION BY FName ORDER BY lastlocationtracked DESC) AS rn  
    from Userlocationtracking (NOLOCK) ULT  
  
left join User_Detail(NOLOCK) UD on UD.User_ID=Ult.user_id  
left join ( 
		select ult.UserLocationTrackingId from [TBL_ET_UserLocationTracking](nolock) ult 
			where ult.UserId in (select item from dbo.fu_SplitString( cast(@UserIds as nvarchar(max)),','))
		union 
		select ulta.UserLocationTrackingId from [TBL_ET_UserLocationTracking_Archived](nolock) ulta
			where ulta.UserId in (select item from dbo.fu_SplitString( cast(@UserIds as nvarchar(max)),','))
				and 1 = ( case when cast(@FromDate as date) <= CAST(GETDATE() as date) and CAST(LocationDateTime as date)
						between CAST(@FromDate AS DATE)  and CAST(@ToDate AS DATE)  then 1 else 0 end )
	) ULTM on ult.locationid=Ultm.UserLocationTrackingId where fname is not null  
  
)  
SELECT  distinct user_id,UserName,Name,Login,case when Currentlytrackable=0 then 'OFF' else 'ON' end TrackingOn, CASE  
        WHEN  DATEADD(MINUTE, 15, lastlocationtracked) < GETDATE() and Currentlytrackable=0 THEN 'Possibly user has not turned auto start on for the app'  
        ELSE lastlocationreason  
    END AS  Reason, isnull(cast(lastlocationtracked as nvarchar(100)),'NEVER') as lastlocationtrackedTime  
FROM RankedLocations  
WHERE rn = 1 and User_Id in (select item from dbo.fu_SplitString( cast(@UserIds as nvarchar(max)),',')) 
 and (@FromDate = '' OR lastlocationtracked >= @FromDate) and (@ToDate ='' OR lastlocationtracked <= @ToDate)    
end
  
end  

end  



GO

