CREATE   PROC usp_GetLoginDetails      
(      
 @User_Login varchar(25)=null,      
 @Password varchar(15)=null,      
 @Url varchar(50)=null,      
 @User_Id bigint=null,      
 @Mode varchar(50)='Authenticate' -- GetData      
)      
AS      
BEGIN      
      
 -- declare @User_Login varchar(25)='sms19',@Password varchar(15)='Kit@nything',@Url varchar(50)='www.kit19.com', @User_Id bigint=null, @Mode varchar(50)='Authenticate'      
 declare @type varchar(2), @Theme varchar(30), @IsUserNonIndian varchar(3), @UserId bigint=0, @pos int=0      
       
 Select @pos=CHARINDEX('localhost',@Url)      
 print 'A0:- ' + cast(@pos as varchar)      
      
 If(@pos > 0 or @User_Login='Abhi01' or @User_Login='sms19' or @User_Login='+917840002738' or CHARINDEX('kit19.com', @Url) > 0)      
 Begin      
  Set @Url = 'www.kit19.com'      
 End      
 print 'A1:- ' + @Url      
      
 SELECT @type=UD.Type, @UserId=(case when @User_Id is null then UD.User_ID else @User_Id end)      
 FROM User_Detail AS UD INNER JOIN reseller_detail AS RD       
 ON UD.M_ID = RD.Reseller_ID       
 WHERE (UD.User_Login = @User_Login) AND (UD.Pwd = @Password) AND (RD.Domain = @Url) or (UD.User_ID=@User_Id)      
 print 'A2:- ' + @type      
      
 If(ISNULL(@type,'') = '')      
 Begin      
  SELECT @type=UD.Type, @UserId=(case when @User_Id is null then UD.User_ID else @User_Id end)      
  FROM User_Detail AS UD INNER JOIN reseller_detail AS RD       
  ON UD.User_ID = RD.User_ID       
  WHERE (UD.User_Login = @User_Login) AND (UD.Pwd = @Password) AND (RD.Domain = @Url) or (UD.User_ID=@User_Id)      
  print 'A3:- ' + @type      
 End      
      
 if(@type='1')      
 Begin      
  SELECT @Theme=theme from themes where u_id=@UserId      
 End      
 else      
 Begin      
  SELECT @Theme=theme from themes where u_id in(select user_id from reseller_detail where reseller_id=(Select m_id from user_detail where user_id=@UserId))      
 End      
 print 'A3.1:- ' + @Theme      
      
 if(exists(select 'x' from user_detail where USER_ID = @UserId and Country_ID <> 110))      
 Begin      
  select @IsUserNonIndian='Yes'      
 end      
 else      
 Begin      
  select @IsUserNonIndian='No'      
 end      
 print 'A3.2:- ' + @IsUserNonIndian      
      
 If(@Mode = 'Authenticate')      
 Begin      
  If(@User_Login is null or @Password is null or @Url is null)      
  Begin      
   print 'Invalid Auth parameters'      
   RETURN      
  End      
 End      
      
 If(@Mode = 'GetData')      
 Begin      
  If(@User_Id is null)      
  Begin      
   print 'Invalid Get parameters'      
   RETURN      
  End      
 End      
      
      
 If(@Mode = 'Authenticate' or @Mode = 'GetData')      
 Begin      
  print 'A4'      
  if @type='0' or @type='2'      
  begin      
   print 'A5'      
   SELECT UD.M_ID, UD.User_ID, UD.User_Login, '****' AS Pwd, UD.FName, UD.LName, UD.EMail, UD.Mobile, UD.City, UD.State, UD.Country, UD.Type, UD.Stype,     
   UD.ACType, UD.STATUS, UD.Banner_ID, UD.Banner_IDR, UD.Banner_ID_Owner, UD.Banner_ID_Reseller, UD.Priority, UD.DateCreated, UD.DateUpdated, UD.EmpUpdated,    
   UD.MachineName, UD.LastModified, UD.SmppID, UD.R_mode, UD.userfilter, UD.FilterMode, UD.ServiceTypeID, UD.ServiceType, UD.UserGroup, UD.Gender, UD.Pincode,    
   UD.Address, UD.LoginType, UD.Merchant_Code, UD.Merchant_Url, UD.User_DOB, UD.ProfilePictureName, UD.ProfilePicturePath, UD.UserType, UD.CompnayName,    
   UD.Office_Name, UD.CountryCode, UD.Usercategory, UD.OnlineStatus, UD.DOE, UD.DeviceID, UD.Version, UD.AccountType, UD.IsInternalUser, UD.IsAdmin,     
   UD.ParentID, UD.LastLogin2, UD.LastLogin1, UD.isverify, UD.randomnumber, UD.IsSuperReseller, UD.HasVirtualCredits, UD.ParentSuperResellerId, UD.Isdemo,    
   UD.resetguid, UD.resetrequested, UD.resetexpired, UD.referrerid, UD.referredcontactid, UD.Source, UD.Medium, UD.Campaign, UD.Timezone, UD.Country_ID,    
   UD.Cloudrole, UD.onduty, UD.MobileCountryCode, UD.Support_Access, UD.Image, UD.isdemoaccount, UD.Presence, RD.Reseller_ID, RD.User_ID AS ResellerUserID,    
   RD.Title, RD.Domain, RD.Slogan, ISNULL(UD.Timezone,'') as TimeZone, ISNULL(UD.isverify,0) as IsVerify, @Theme as Theme,      
   (case UD.userfilter when 'MT' then 'MOMT' when 'MTIX_PRO' then 'Promotional' when 'TRANS' then 'Transactional'           
   when 'OPEN' then 'OPEN DND' when 'TR_CURVE' then 'SCRUB' when 'MT_TRANS' then 'Transactional' when 'MTIX_TR' then 'Transactional'           
   when 'MTIX_TRC' then 'SCRUB' WHEN 'CRITICAL' THEN 'CRITICAL' else 'Promotional' end) as AccType, @IsUserNonIndian as IsUserNonIndian      
   FROM User_Detail AS UD INNER JOIN reseller_detail AS RD      
   ON UD.M_ID = RD.Reseller_ID      
   WHERE (UD.User_ID = @UserId) AND (UD.STATUS = 1);      
  end      
  else      
  begin      
   print 'A6'      
   SELECT UD.M_ID, UD.User_ID, UD.User_Login, '****' AS Pwd, UD.FName, UD.LName, UD.EMail, UD.Mobile, UD.City, UD.State, UD.Country, UD.Type, UD.Stype,     
