CREATE   PROCEDURE [dbo].[usp_GetM_CouponDetailsEdit] --''                
 @Search VARCHAR(100)                
AS                
BEGIN                
 SELECT mc.ID,                
        mc.CouponCode,                
        CASE mc.[Route]                
             WHEN 'All' THEN 'All'                
             ELSE uf.Name                
        END                    AS NAME,                
        mc.MinVolume,                
        mc.MaxVolume,                
        mc.Validity,                
        --CONVERT(VARCHAR(50), mc.ValidFrom, 101) AS ValidFrom,                
        --CONVERT(VARCHAR(50), mc.ValidTo, 101) AS ValidTo,                
        mc.ValidFrom,              
        mc.ValidTo,              
        mc.Discount,                
        mc.[Status],                
        mc.Remarks,                
        mc.SavedSearch,                
        mc.IsSMS,                
        mc.IsMail,              
        mc.IsAmount,              
        mc.IsSMSCredit,              
        mc.SMSCredits,              
        mc.IsMailCredit,              
        mc.MailCredits,              
        mc.MinMailVolume,              
        mc.MaxMailVolume,                
        (                
            SELECT STUFF(                
                       (                
                           SELECT N', ' + ss.SearchName                
                           FROM   SearchDetails AS ss                
                                  INNER JOIN dbo.fn_Split(mc.SavedSearch, '#') AS                 
                                       fs                
                                       ON  ss.ID = CAST( fs.[value] AS BIGINT)                 
                                                           
                                           FOR XML                 
                                                           
                                           PATH(''),                
                                  TYPE                
                       )                 
                                       
                       .value('text()[1]', 'nvarchar(max)'),                
                       1,                
                       2,                
                       N''                
                   )                
        )                      AS SearchName,    
  mc.FreeCredits ,    
  mc.NoofWebforms,    
  mc.NoofLandingPage,    
  mc.NoofUsers,    
  mc.NoofPhoneNo,    
  mc.IsFreeCredit,    
  mc.PlansID,
    mc.N1,mc.N2,mc.N3,
  mc.V1,mc.V2,mc.V3,
  mc.VV1,mc.VV2,mc.VV3,     
  isnull(mc.CouponBased,1) as CouponBased             
