/* ============================================================
   Procedure: [dbo].[usp_GetM_CouponDetailsEdit_with_int]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

              
CREATE   PROCEDURE [dbo].[usp_GetM_CouponDetailsEdit_with_int] --''                
 @Search VARCHAR(100)                
AS                
BEGIN                
 SELECT mc.ID,                
        mc.CouponCode,                
        CASE mc.[Route]                
             WHEN 'All' THEN 'All'                
             ELSE uf.Name                
        END                    AS NAME,                
        mc.MinVolume,                
        mc.MaxVolume,                
        mc.Validity,                
        --CONVERT(VARCHAR(50), mc.ValidFrom, 101) AS ValidFrom,                
        --CONVERT(VARCHAR(50), mc.ValidTo, 101) AS ValidTo,                
        mc.ValidFrom,              
        mc.ValidTo,              
        mc.Discount,                
        mc.[Status],                
        mc.Remarks,                
        mc.SavedSearch,                
        mc.IsSMS,                
        mc.IsMail,              
        mc.IsAmount,              
        mc.IsSMSCredit,              
        mc.SMSCredits,              
        mc.IsMailCredit,              
        mc.MailCredits,              
        mc.MinMailVolume,              
        mc.MaxMailVolume,      
         mc.IsIntSMSCredit,      
  mc.IntSmsCredit,       
  mc.MinIntVolume,      
  mc.MaxIntVolume,    
 mc.isintsms, iscloud,                  
      (select dbo.Cloud_Coupen_plan(mc.CouponCode)) as plan_nm,              
        (                
            SELECT STUFF(                
                       (                
                           SELECT N', ' + ss.SearchName                
                           FROM   SearchDetails AS ss                
                                  INNER JOIN dbo.fn_Split(mc.SavedSearch, '#') AS                 
                                       fs                
                                       ON  ss.ID = CAST( fs.[value] AS BIGINT)                 
                                                           
                                           FOR XML                 
                                                           
                                           PATH(''),                
                                  TYPE                
                       )                 
                                       
                       .value('text()[1]', 'nvarchar(max)'),                
                       1,                
                       2,                
                       N''                
                   )                
        )                      AS SearchName                
 FROM   M_Coupon               AS mc                
        LEFT JOIN User_Filter  AS uf                
             ON  uf.Code = mc.[Route]                
 WHERE  mc.CouponCode=@search        
 --ISNULL(@Search, '') = ''                
 --       OR  mc.CouponCode LIKE '%' + @Search + '%'                
 --       OR  uf.Name LIKE '%' + @Search + '%'                
 --       OR  mc.MinVolume LIKE '%' + @Search + '%'                
 --       OR  mc.MaxVolume LIKE '%' + @Search + '%'                
 --       OR  mc.Validity LIKE '%' + @Search + '%'                
 --       OR  mc.Discount LIKE '%' + @Search + '%'                
 --       OR  mc.[Status] LIKE '%' + @Search + '%'                
 --ORDER BY                
 --       mc.DateCreated DESC                
END 


