/* ============================================================
   Procedure: [dbo].[Usp_GetMailCampaign_ByID_1]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[Usp_GetMailCampaign_ByID_1]      
(      
  @CampaignID bigint      
)      
AS      
BEGIN      
    -- Start TRY block
    BEGIN TRY
        SELECT  
            ISNULL(FromMailId, '') AS FromMailId, 
            ISNULL(MailReplyTo, '') AS MailReplyTo, 
            ISNULL(TemplateID, 0) AS TemplateID,      
            ISNULL(MailSubject, '') AS MailSubject, 
            ISNULL(MailContent, '') AS MailContent, 
            ISNULL(IsActive, 0) AS IsActive,       
            TimeBeforeEvent, 
            TimeUnit, 
            MaxLimit,
            MailBotId,
            AdditionalInstruction
        FROM UserCampaignMaster (NOLOCK) 
        WHERE ID = @CampaignID;  
    END TRY
    
    -- Start CATCH block
    BEGIN CATCH
        -- Declare variables to capture error details
        DECLARE @ErrorMessage NVARCHAR(4000);
        DECLARE @ErrorSeverity INT;
        DECLARE @ErrorState INT;

        -- Capture error details
        SET @ErrorMessage = ERROR_MESSAGE();
        SET @ErrorSeverity = ERROR_SEVERITY();
        SET @ErrorState = ERROR_STATE();

        -- Insert error details into a custom error logging procedure (assuming usp_InsertErrorInfo is defined for logging)
        EXEC usp_InsertErrorInfo @ErrorMessage, @ErrorSeverity, @ErrorState;

        -- Optionally, re-raise the error if you want the calling application to handle it
        RAISERROR (@ErrorMessage, @ErrorSeverity, @ErrorState);
    END CATCH
END;



