/* ============================================================
   Procedure: [dbo].[usp_GetMailConsumptionByMID_2]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_GetMailConsumptionByMID_2] --10043
    @m_id INT
AS
BEGIN
    SET NOCOUNT ON;

    -- Main query to retrieve total consumption for each User_ID
    SELECT TOP 5 
        u.User_ID,
        u.FName + ' ' + u.LName + ' (' + u.user_login + ')' AS FullName,
        ISNULL(SUM(dc.TotalMailConsumption), 0) AS TotalConsumption
    FROM 
       
        User_Detail (nolock) AS u 
    LEFT JOIN 
        DailyMailConsumption AS dc ON u.User_ID = dc.User_ID 
    WHERE 
        u.m_id = @m_id AND month(dc.Date)=MONTH(getdate()) and year(dc.Date)=year(getdate())
    GROUP BY 
        u.User_ID, u.FName, u.LName, u.user_login  -- Include FName and LName here
    ORDER BY 
        u.User_ID DESC;
END;


GO

