/* ============================================================
   Procedure: [dbo].[Usp_GetMailReport]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[Usp_GetMailReport] --335,'03/10/2021','03/10/2022'                      
 @UserID bigINT      
 ,@FromDate VARCHAR(50) = NULL      
 ,@toDate VARCHAR(50) = NULL      
AS      
BEGIN      
 SET @FromDate = coalesce(@fromdate, CONVERT(VARCHAR(50), try_CONVERT(DATETIME, getdate(), 101), 101))      
 SET @ToDate = coalesce(@todate, CONVERT(VARCHAR(50), try_CONVERT(DATETIME, getdate(), 101), 101))      
 Declare @ParentID bigint = isnull((select top 1 ParentId from user_detail with(nolock) where user_id = @UserID),0)
 
      
 DECLARE @TimeZoneName NVARCHAR(255) = isnull((      
    SELECT TimeZone      
    FROM User_Detail(NOLOCK)      
    WHERE User_ID = @Userid      
    ), 'india standard time')      
      
 IF try_convert(DATE, @fromdate, 101) = CAST(getdate() AS DATE)      
 BEGIN      
  SELECT Id      
   ,Email_id      
   ,SentDatetime      
   ,ReplyTo      
   ,STATUS      
   ,--Message,          
   Email_subject      
  FROM (      
   SELECT CE.Id      
    ,CE.Email_Id      
    ,dbo.fn_ConvertDateTime(CE.SentDateTime, @TimeZoneName, 0) SentDateTime      
    ,CE.ReplyTo      
    ,CE.STATUS      
    ,      
    --isnull(MDR.Event,CE.Status) as Status,                      
    -- CE.Message,                      
    Be.Email_Subject      
   FROM ClientEmails CE(NOLOCK)      
   INNER JOIN BatchEmail_Infos BE(NOLOCK) ON BE.BatchID = CE.BatchID      
   --left join [PelConnectDB].[dbo].[MailDeliveryReport] MDR (nolock) on MDR.APIHEADER=cast(CE.GUID as nvarchar(100))              
   WHERE --ce.UserId = @UserID  
      (
    -- Parent user: own + child users
    (@ParentID = @UserID AND
        (
            ce.UserId = @UserID
            OR ce.UserId IN (
                SELECT user_id
                FROM user_detail WITH (NOLOCK)
                WHERE ParentId = @UserID
            )
        )
    )

    -- Child user: only own data
    OR (@ParentID <> @UserID AND ce.UserId = @UserID)
)




    -- dbo.[ufn_GetUserParentId](ce.userID) = case when @UserID = @Parentid
      --                 then dbo.[ufn_GetUserParentId](@Userid)
        --               else 



    AND CONVERT(VARCHAR(50), try_CONVERT(DATETIME, CE.SentDateTime, 101), 101) BETWEEN  try_CONVERT(DATETIME,@FromDate, 101) AND try_CONVERT(DATETIME,@toDate , 101)      
   ) A      
  ORDER BY A.Id DESC      
 END      
 ELSE      
 BEGIN      
  SELECT Id      
   ,Email_id      
   ,SentDatetime      
   ,ReplyTo      
   ,STATUS      
   ,--Message,          
   Email_subject      
  FROM (      
   SELECT CE.Id      
    ,CE.Email_Id      
    ,dbo.fn_ConvertDateTime(CE.SentDateTime, @TimeZoneName, 0) SentDateTime      
    ,CE.ReplyTo      
    ,CE.STATUS      
    ,      
    --isnull(MDR.Event,CE.Status) as Status,                      
    -- CE.Message,                      
    Be.Email_Subject      
   FROM ClientEmails CE(NOLOCK)      
   INNER JOIN BatchEmail_Infos BE(NOLOCK) ON BE.BatchID = CE.BatchID      
   --left join [PelConnectDB].[dbo].[MailDeliveryReport] MDR (nolock) on MDR.APIHEADER=cast(CE.GUID as nvarchar(100))              
   WHERE --ce.UserId = @UserID      
    
        (
    -- Parent user: own + child users
    (@ParentID = @UserID AND
        (
            ce.UserId = @UserID
            OR ce.UserId IN (
                SELECT user_id
                FROM user_detail WITH (NOLOCK)
                WHERE ParentId = @UserID
            )
        )
    )

    -- Child user: only own data
    OR (@ParentID <> @UserID AND ce.UserId = @UserID)
)
  
    
    
    AND CONVERT(VARCHAR(50), try_CONVERT(DATETIME, CE.SentDateTime, 101), 101) BETWEEN try_CONVERT(DATETIME,@FromDate, 101) AND try_CONVERT(DATETIME,@toDate , 101)      
   --and (mdr.id is null or MDR.ID=(select MAX(id) from [PelConnectDB].[dbo].[MailDeliveryReport] mm (nolock) where mm.APIHEADER=mdr.APIHEADER))              
         
   UNION      
         
   SELECT CE.Id      
    ,CE.Email_Id      
    ,      
    -- CE.SentDateTime,      
    dbo.fn_ConvertDateTime(CE.SentDateTime, @TimeZoneName, 0) SentDateTime      
    ,CE.ReplyTo      
    ,CE.STATUS      
    ,      
    --isnull(mdr.event,CE.Status) as Status,                      
    -- TM.Message,                      
    Be.Email_Subject      
   FROM MySMS.dbo.ThirtyDaysClientEmails CE(NOLOCK)      
   INNER JOIN BatchEmail_Infos BE(NOLOCK) ON BE.BatchID = CE.BatchID      
   --INNER JOIN MySMS.dbo.ThirtyDaysMessages TM ON CE.BatchID = TM.BatchID      
   --left join [PelConnectDB].[dbo].[MailDeliveryReport] MDR (nolock) on MDR.APIHEADER=cast(CE.GUID as nvarchar(100))              
   WHERE --ce.UserId = @UserID      
  
     (
    -- Parent user: own + child users
    (@ParentID = @UserID AND
        (
            ce.UserId = @UserID
            OR ce.UserId IN (
                SELECT user_id
                FROM user_detail WITH (NOLOCK)
                WHERE ParentId = @UserID
            )
        )
    )

    -- Child user: only own data
    OR (@ParentID <> @UserID AND ce.UserId = @UserID)
  )
    
    AND CONVERT(VARCHAR(50), try_CONVERT(DATETIME, CE.SentDateTime, 101), 101) BETWEEN try_CONVERT(DATETIME,@FromDate, 101) AND try_CONVERT(DATETIME,@toDate , 101)      
      --and (mdr.id is null or MDR.ID=(select MAX(id) from [PelConnectDB].[dbo].[MailDeliveryReport] mm (nolock) where mm.APIHEADER=mdr.APIHEADER))               
   ) A      
  ORDER BY A.Id DESC      
 END      
      
 EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @UserID      
  ,@Activity_type = 'View_MailRpt'      
  ,@ActionType = 'S'      
  ,@RowJson = ''      
  ,@Table_name = 'ClientEmails'      
END 


GO

/* ============================================================
   Procedure: [dbo].[Usp_GetMailReport_BeforeLive]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[Usp_GetMailReport_BeforeLive] --34594,'03/10/2018','03/10/2022'                
 @UserID INT,                
 @FromDate VARCHAR(50)= null,                
 @toDate VARCHAR(50)= null                
AS                
BEGIN  
       
set @FromDate =coalesce(@fromdate,CONVERT(VARCHAR(50), CONVERT(DATETIME, getdate(), 101), 101))        
set @ToDate =coalesce(@todate,CONVERT(VARCHAR(50), CONVERT(DATETIME, getdate(), 101), 101))        

   declare @TimeZoneName nvarchar(255) = isnull( ( select TimeZone from User_Detail(nolock) where User_ID = @Userid),'india standard time') 

if convert(date,@fromdate,101)=CAST(getdate() as DATE)        
begin        
Select Id,Email_id,SentDatetime,ReplyTo,Status, --Message,    
 Email_subject from               
(SELECT CE.Id,            
        CE.Email_Id,                 
        dbo.fn_ConvertDateTime(CE.SentDateTime,@TimeZoneName,0)  SentDateTime,                
        CE.ReplyTo,          
        CE.Status,        
        --isnull(MDR.Event,CE.Status) as Status,                
       -- CE.Message,                
        Be.Email_Subject                
 FROM   ClientEmails CE(NOLOCK)                
        INNER JOIN BatchEmail_Infos BE(NOLOCK) ON  BE.BatchID = CE.BatchID        
        --left join [PelConnectDB].[dbo].[MailDeliveryReport] MDR (nolock) on MDR.APIHEADER=cast(CE.GUID as nvarchar(100))        
        WHERE  ce.UserId = @UserID AND CONVERT(VARCHAR(50), CONVERT(DATETIME, CE.SentDateTime, 101), 101)                 
            BETWEEN @FromDate AND @toDate ) A order by A.Id desc        
end        
else        
begin        
Select Id,Email_id,SentDatetime,ReplyTo,Status, --Message,    
Email_subject from               
(SELECT CE.Id,            
        CE.Email_Id,                 
        dbo.fn_ConvertDateTime(CE.SentDateTime,@TimeZoneName,0)  SentDateTime,                
        CE.ReplyTo,          
        CE.Status,        
        --isnull(MDR.Event,CE.Status) as Status,                
       -- CE.Message,                
        Be.Email_Subject                
 FROM   ClientEmails CE(NOLOCK)                
        INNER JOIN BatchEmail_Infos BE(NOLOCK) ON  BE.BatchID = CE.BatchID        
        --left join [PelConnectDB].[dbo].[MailDeliveryReport] MDR (nolock) on MDR.APIHEADER=cast(CE.GUID as nvarchar(100))        
        WHERE  ce.UserId = @UserID AND CONVERT(VARCHAR(50), CONVERT(DATETIME, CE.SentDateTime, 101), 101)                 
            BETWEEN @FromDate AND @toDate         
            --and (mdr.id is null or MDR.ID=(select MAX(id) from [PelConnectDB].[dbo].[MailDeliveryReport] mm (nolock) where mm.APIHEADER=mdr.APIHEADER))        
union        
SELECT CE.Id,            
        CE.Email_Id,                 
        CE.SentDateTime,                
        CE.ReplyTo,        
        CE.Status,                
        --isnull(mdr.event,CE.Status) as Status,                
       -- TM.Message,                
        Be.Email_Subject                
 FROM   MySMS.dbo.ThirtyDaysClientEmails CE(NOLOCK)                
        INNER JOIN BatchEmail_Infos BE(NOLOCK) ON  BE.BatchID = CE.BatchID         
        inner join MySMS.dbo.ThirtyDaysMessages TM on CE.BatchID=TM.BatchID         
        --left join [PelConnectDB].[dbo].[MailDeliveryReport] MDR (nolock) on MDR.APIHEADER=cast(CE.GUID as nvarchar(100))        
        WHERE  ce.UserId = @UserID AND CONVERT(VARCHAR(50), CONVERT(DATETIME, CE.SentDateTime, 101), 101)                 
            BETWEEN @FromDate AND @toDate         
            --and (mdr.id is null or MDR.ID=(select MAX(id) from [PelConnectDB].[dbo].[MailDeliveryReport] mm (nolock) where mm.APIHEADER=mdr.APIHEADER))         
            ) A order by A.Id desc              
end        
END 


