/* ============================================================
   Procedure: [dbo].[Usp_GetMailReport_Pagination]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.Usp_GetMailReport_Pagination
(
    @UserID      BIGINT,
    @FromDate    VARCHAR(50) = NULL,
    @ToDate      VARCHAR(50) = NULL,
    @PageNumber  INT = 1,
    @PageSize    INT = 50
)
AS
BEGIN
    SET NOCOUNT ON;

    DECLARE @FromDt DATETIME = ISNULL(TRY_CONVERT(DATETIME, @FromDate, 101), CAST(GETDATE() AS DATE));
    DECLARE @ToDt   DATETIME = ISNULL(TRY_CONVERT(DATETIME, @ToDate, 101),   GETDATE());

    DECLARE @TimeZoneName NVARCHAR(255) =
    ISNULL((SELECT TimeZone FROM User_Detail WITH (NOLOCK) WHERE User_ID = @UserID),
           'india standard time');

    /* Temp table */
    CREATE TABLE #MailDataTemp
    (
        Id BIGINT,
        Email_Id NVARCHAR(255),
        SentDateTime DATETIME,
        ReplyTo NVARCHAR(255),
        Status NVARCHAR(50),
        Email_Subject NVARCHAR(MAX)
    );

    /* User scope */
    ;WITH UserScope AS
    (
        SELECT user_id FROM user_detail WITH (NOLOCK) WHERE ParentId = @UserID
        UNION ALL
        SELECT @UserID
    )
    INSERT INTO #MailDataTemp
    SELECT
        CE.Id,
        CE.Email_Id,
        dbo.fn_ConvertDateTime(CE.SentDateTime, @TimeZoneName, 0),
        CE.ReplyTo,
        CE.Status,
        BE.Email_Subject
    FROM ClientEmails CE WITH (NOLOCK)
    INNER JOIN BatchEmail_Infos BE WITH (NOLOCK)
        ON BE.BatchID = CE.BatchID
    WHERE
        CE.UserId IN (SELECT user_id FROM UserScope)
        AND CE.SentDateTime >= @FromDt
        AND CE.SentDateTime < DATEADD(DAY, 1, @ToDt)

    UNION ALL

    SELECT
        CE.Id,
        CE.Email_Id,
        dbo.fn_ConvertDateTime(CE.SentDateTime, @TimeZoneName, 0),
        CE.ReplyTo,
        CE.Status,
        BE.Email_Subject
    FROM MySMS.dbo.ThirtyDaysClientEmails CE WITH (NOLOCK)
    INNER JOIN BatchEmail_Infos BE WITH (NOLOCK)
        ON BE.BatchID = CE.BatchID
    WHERE
        CE.UserId IN (SELECT user_id FROM UserScope)
        AND CE.SentDateTime >= @FromDt
        AND CE.SentDateTime < DATEADD(DAY, 1, @ToDt);

    /* Total Count */
    SELECT COUNT(1) AS TotalCount
    FROM #MailDataTemp;

    /* Paged Data */
    SELECT *
    FROM #MailDataTemp
    ORDER BY Id DESC
    OFFSET (@PageNumber - 1) * @PageSize ROWS
    FETCH NEXT @PageSize ROWS ONLY;
     EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @UserID      
  ,@Activity_type = 'View_MailRpt'      
  ,@ActionType = 'S'      
