/* ============================================================
   Procedure: [dbo].[Usp_GetMailReport1]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[Usp_GetMailReport1] -- 17626,'12/21/2017','12/21/2017'          
 @UserID INT,          
 @FromDate VARCHAR(50)= null,          
 @toDate VARCHAR(50)= null          
AS          
BEGIN   
set @FromDate =coalesce(@fromdate,CONVERT(VARCHAR(50), CONVERT(DATETIME, getdate(), 101), 101))  
set @ToDate =coalesce(@fromdate,CONVERT(VARCHAR(50), CONVERT(DATETIME, getdate(), 101), 101))  
if convert(date,@fromdate,101)=CAST(getdate() as DATE)  
begin  
Select Id,Email_id,SentDatetime,ReplyTo,Status,Message,Email_subject from         
(SELECT CE.Id,      
        CE.Email_Id,           
        CE.SentDateTime,          
        CE.ReplyTo,    
        CE.Status,  
        --isnull(MDR.Event,CE.Status) as Status,          
        CE.Message,          
        Be.Email_Subject          
 FROM   ClientEmails CE(NOLOCK)          
        INNER JOIN BatchEmail_Infos BE(NOLOCK) ON  BE.BatchID = CE.BatchID  
        --left join [PelConnectDB].[dbo].[MailDeliveryReport] MDR (nolock) on MDR.APIHEADER=cast(CE.GUID as nvarchar(100))  
        WHERE  ce.UserId = @UserID AND CONVERT(VARCHAR(50), CONVERT(DATETIME, CE.SentDateTime, 101), 101)           
            BETWEEN @FromDate AND @toDate ) A order by A.Id desc  
end  
else  
begin  
Select Id,Email_id,SentDatetime,ReplyTo,Status,Message,Email_subject from         
( SELECT CE.Id,      
        CE.Email_Id,           
        CE.SentDateTime,          
        CE.ReplyTo,       
        CE.Status,     
        --isnull(MDR.EVENT,CE.Status) as Status,          
        CE.Message,          
        Be.Email_Subject          
 FROM   ClientEmails CE(NOLOCK)          
        INNER JOIN BatchEmail_Infos BE(NOLOCK) ON  BE.BatchID = CE.BatchID   
        --left join [PelConnectDB].[dbo].[MailDeliveryReport] MDR (nolock) on MDR.APIHEADER=cast(CE.GUID as nvarchar(50))  
        WHERE  ce.UserId = @UserID AND CONVERT(VARCHAR(50), CONVERT(DATETIME, CE.SentDateTime, 101), 101)           
            BETWEEN @FromDate AND @toDate   
            --and (mdr.id is null or MDR.ID=(select MAX(id) from [PelConnectDB].[dbo].[MailDeliveryReport] mm (nolock) where mm.APIHEADER=mdr.APIHEADER))  
union  
SELECT CE.Id,      
        CE.Email_Id,           
        CE.SentDateTime,          
        CE.ReplyTo,  
        CE.Status,          
       -- isnull(MDR.Event,CE.Status) as Status,          
        TM.Message,          
        Be.Email_Subject          
 FROM   MySMS.dbo.ThirtyDaysClientEmails CE(NOLOCK)          
        INNER JOIN BatchEmail_Infos BE(NOLOCK) ON  BE.BatchID = CE.BatchID   
        inner join MySMS.dbo.ThirtyDaysMessages TM on CE.BatchID=TM.BatchID   
        --left join [PelConnectDB].[dbo].[MailDeliveryReport] MDR (nolock) on MDR.APIHEADER=cast(CE.GUID as nvarchar(100))  
        WHERE  ce.UserId = @UserID AND CONVERT(VARCHAR(50), CONVERT(DATETIME, CE.SentDateTime, 101), 101)           
            BETWEEN @FromDate AND @toDate   
           -- and (mdr.id is null or MDR.ID=(select MAX(id) from [PelConnectDB].[dbo].[MailDeliveryReport] mm (nolock) where mm.APIHEADER=mdr.APIHEADER))  
           ) A order by A.Id desc   
end       
END 






