/* ============================================================
   Procedure: [dbo].[usp_GetMailsForOldMailsParsing]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

  
CREATE   PROCEDURE [dbo].[usp_GetMailsForOldMailsParsing]  
 @FilterID BIGINT,  
 @ParentID BIGINT  
AS  
BEGIN  
 DECLARE @FromMail     VARCHAR(500),  
         @ToEmail      VARCHAR(500),  
         @Subject      VARCHAR(500),  
         @Body         VARCHAR(500)  
   
 SELECT @FromMail = umf.FromEmail,  
        @ToEmail     = umf.ToEmail,  
        @Subject     = umf.SubjectContains,  
        @Body        = umf.MailContentContains  
 FROM   UserMailsFilters AS umf  
 WHERE  umf.ID = @FilterID  
   
 SELECT um.ID,  
        (  
            SELECT TOP 1           ParentID  
            FROM   User_Detail  AS ud  
            WHERE  ud.[User_ID] = um.UserID  
        )                       AS ParentID,  
        um.UserID,  
        um.FromMail,  
        
        dbo.[fn_getusertimefromindiantime](@ParentID,um.MailDate) MailDate,
          
        um.MailSubject,  
        um.MailContent,  
        um.ToEmail  
 FROM   UserMails               AS um  
        INNER JOIN User_Detail  AS ud  
             ON  um.UserID = ud.[User_ID]  
 WHERE  ud.ParentID = @ParentID  
        AND (  
                um.FromMail LIKE '%' + @FromMail + '%'  
                AND um.ToEmail LIKE '%' + @ToEmail + '%'  
                AND um.MailSubject LIKE '%' + @subject + '%'  
                AND um.MailContent LIKE '%' + @Body + '%'  
            )  
END  



GO

