CREATE   PROCEDURE [dbo].[usp_GetMailsForOldMailsParsingforConsole]        
 @FilterID BIGINT,        
 @ParentID BIGINT        
AS        
BEGIN        
 DECLARE @FromMail     VARCHAR(500),        
         @ToEmail      VARCHAR(500),        
         @Subject      VARCHAR(500),        
         @Body         VARCHAR(500)        
 SELECT @FromMail = umf.FromEmail,        
        @ToEmail     = umf.ToEmail,        
        @Subject     = umf.SubjectContains,        
        @Body        = umf.MailContentContains        
 FROM   UserMailsFilters AS umf (nolock)       
 WHERE  umf.ID = @FilterID        
         
 SELECT top 20 um.ID,        
        ud.ParentID,        
        um.UserID,        
        um.FromMail,        
        um.MailDate,        
        um.MailSubject,        
        um.MailContent,        
        um.ToEmail,um.HTMLBody        
 FROM   UserMails               AS um  (nolock)      
        INNER JOIN User_Detail  AS ud  (nolock)      
             ON  um.UserID = ud.[User_ID]        
 WHERE  ud.ParentID = @ParentID        
        AND (        
                um.FromMail LIKE '%' + @FromMail + '%'        
                AND um.ToEmail LIKE '%' + @ToEmail + '%'        
                AND um.MailSubject LIKE '%' + @subject + '%'        
                --AND um.MailContent LIKE '%' + @Body + '%'        
            )        
        AND um.IsFiltered = 0    order by um.id    
