SET QUOTED_IDENTIFIER ON

  
CREATE   PROCEDURE [dbo].[usp_GetMailsFrodb] --335  
 @UserID BIGINT  
AS  
BEGIN  
  
  Declare @ParentID bigint = 0 
  select @ParentID = isnull(ParentID,0) from user_Detail where user_ID = @UserID      



 SELECT um.ID,  
        um.FromMail,  
        --um.MailDate,  
       case when  ISDATE(um.MailDate) = 1
       then
        dbo.[fn_getusertimefromindiantime](@ParentID,nullif(um.MailDate,'')) 
       else
         null
       end as MailDate,
         
       -- um.MailDate  AS MaildateFormat,
        
       -- dbo.[fn_getusertimefromindiantime](@ParentID,nullif(um.MailDate,'')) as MaildateFormat,
     
       case when  ISDATE(um.MailDate) = 1
       then
        dbo.[fn_getusertimefromindiantime](@ParentID,nullif(um.MailDate,'')) 
       else
         null
       end as MaildateFormat,
     
          
        um.MailSubject,  
        um.MailContent,  
        (  
            SELECT STUFF(  
                       (  
                           SELECT DISTINCT N', ' + umf.FilterName  
                           FROM   UserMailsFilter AS umf  
                           WHERE  umf.Source_EmailID = um.FromMail  
                                    
                                    
                                    
                                    
                                    
                                    
                                    
                                  FOR XML   
                                    
                                    
                                    
                                    
                                    
                                    
                                    
                                  PATH(''),  
                                    
                                    
                                    
                                    
                                    
                                    
                                    
                                  TYPE  
                       )   
                         
                         
                         
                         
                         
                         
                         
                       .value('text()[1]', 'nvarchar(max)'),  
                       1,  
                       2,  
                       N''  
                   )  
        )            AS FilterName,  
        um.HTMLBody  
 FROM   UserMails    AS um  
 WHERE  um.UserID = @UserID  
END  



