/* ============================================================
   Procedure: [dbo].[usp_GetMailsFrodbWithFilter]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.usp_GetMailsFrodbWithFilter --@userid=29453,@filterid=0                
	@UserID BIGINT
	,@FilterID BIGINT
AS
BEGIN
	DECLARE @FromMail VARCHAR(500)
		,@ToEmail VARCHAR(500)
		,@Subject VARCHAR(500)
		,@Body VARCHAR(500)
	DECLARE @ParentId BIGINT = 0;
	DECLARE @IsAdmin BIT = 0;
	DECLARE @RoleType VARCHAR(10);
	DECLARE @TeamCode VARCHAR(20)

	SELECT @ParentId = ParentID
		,@IsAdmin = IsAdmin
	FROM User_Detail(NOLOCK)
	WHERE User_ID = @UserId;

	IF object_id('tempdb..#tblUserIds') IS NOT NULL
	BEGIN
		DROP TABLE #tblUserIds
	END

	CREATE TABLE #tblUserIds (UserId BIGINT NOT NULL)

	SELECT @TeamCode = tum.TeamCode
	FROM TBL_UA_TeamUserMappingMaster(NOLOCK) tum
	INNER JOIN TBL_UA_TeamMaster(NOLOCK) tm ON tm.TeamCode = tum.TeamCode
	WHERE tum.UserId = @UserId

	IF (
			(@TeamCode IS NULL)
			AND (
				@ParentId = @UserId
				OR @IsAdmin = 1
				)
			)
	BEGIN
		--set @RoleType = 'Global'  
		INSERT INTO #tblUserIds (UserId)
		SELECT User_Id UserId
		FROM User_Detail(NOLOCK)
		WHERE ParentId = @ParentId
	END
	ELSE IF (@TeamCode != NULL)
	BEGIN
		---set @RoleType = 'Team'  
		INSERT INTO #tblUserIds (UserId)
		SELECT UserId
		FROM TBL_UA_TeamUserMappingMaster(NOLOCK)
		WHERE TeamCode = @TeamCode
	END
	ELSE
	BEGIN
		--set @RoleType = 'User'  
		INSERT INTO #tblUserIds (UserId)
		SELECT @UserId
	END

	SELECT @FromMail = umf.FromEmail
		,@ToEmail = umf.ToEmail
		,@Subject = umf.SubjectContains
		,@Body = umf.MailContentContains
	FROM UserMailsFilters AS umf
	WHERE umf.ID = @FilterID

	SELECT *
	INTO #usermails
	FROM usermails(NOLOCK)
	WHERE UserID IN (
			SELECT UserId
			FROM #tblUserIds
			)
		AND DATEDIFF(d, CreatedOn, getdate()) <= 30

	UPDATE #usermails
	SET MailDate = CreatedOn
	WHERE ISDATE(MailDate) = 0

	IF @filterid <> 0
	BEGIN
		SELECT um.ID
			,um.FromMail
			,dbo.[fn_getusertimefromindiantime](UserID, um.MailDate) AS MailDate
			,dbo.[fn_getusertimefromindiantime](UserID, um.MailDate) AS MaildateFormat
			,um.MailSubject
			,
			--um.MailContent,                
			dbo.[fn_getusertimefromindiantime](UserID, um.CreatedOn) AS CreatedOn
			,CAST(ISNULL((
						SELECT TOP 1 1
						FROM UserMailsFilters AS umf(NOLOCK)
						WHERE umf.SampleEmailID = um.ID
							AND umf.ID = @FilterID
						), '') AS BIT) AS IsSample
			,(
				SELECT STUFF((
							SELECT DISTINCT N', ' + umf.Name
							FROM UserMailsFilters AS umf(NOLOCK)
							WHERE um.UserID IN (
									SELECT ud.[User_ID]
									FROM User_Detail AS ud(NOLOCK)
									WHERE ud.ParentID = umf.ParentID
									)
								AND um.FromMail LIKE '%' + umf.FromEmail + '%'
								AND um.ToEmail LIKE '%' + umf.ToEmail + '%'
								AND um.MailContent LIKE '%' + umf.MailContentContains + '%'
								AND um.MailSubject LIKE '%' + umf.SubjectContains + '%'
							FOR XML PATH('')
								,TYPE
							).value('text()[1]', 'nvarchar(max)'), 1, 2, N'')
				) AS FilterName
			,(
				SELECT STUFF((
							SELECT DISTINCT N', ' + umf.Name + '#' + CAST(umf.ID AS VARCHAR(50)) + '#' + CASE 
									WHEN umf.IsMapped = 1
										THEN 'Mapped'
									ELSE 'Not Mapped'
									END
							FROM UserMailsFilters AS umf(NOLOCK)
							WHERE um.UserID IN (
									SELECT ud.[User_ID]
									FROM User_Detail AS ud
									WHERE ud.ParentID = umf.ParentID
									)
								AND um.FromMail LIKE '%' + umf.FromEmail + '%'
								AND um.ToEmail LIKE '%' + umf.ToEmail + '%'
								AND um.MailContent LIKE '%' + umf.MailContentContains + '%'
								AND um.MailSubject LIKE '%' + umf.SubjectContains + '%'
							FOR XML PATH('')
								,TYPE
							).value('text()[1]', 'nvarchar(max)'), 1, 2, N'')
				) AS FilterIDWithName
			,um.ToEmail
			,isnull(u.enquiryid, 0) AS Enquiryid
		FROM #UserMails AS um
		LEFT JOIN UserEnquiryRawEntries AS u(NOLOCK) ON u.Mail_ID = um.ID
		WHERE um.UserID IN (
				SELECT UserId
				FROM #tblUserIds
				)
			AND um.FromMail LIKE '%' + ISNULL(@FromMail, um.FromMail) + '%'
			AND um.ToEmail LIKE '%' + ISNULL(@ToEmail, um.ToEmail) + '%'
			AND um.MailSubject LIKE '%' + ISNULL(@Subject, um.MailSubject) + '%'
			AND um.MailContent LIKE '%' + ISNULL(@Body, um.MailContent) + '%'
		ORDER BY um.CreatedOn DESC
	END
	ELSE
	BEGIN
		SELECT um.ID
			,um.FromMail
			,dbo.[fn_getusertimefromindiantime](UserID, um.MailDate) AS MailDate
			,dbo.[fn_getusertimefromindiantime](UserID, um.MailDate) AS MaildateFormat
			,um.MailSubject
			,
			--um.MailContent,                
			dbo.[fn_getusertimefromindiantime](UserID, um.CreatedOn) AS CreatedOn
			,CAST(ISNULL((
						SELECT TOP 1 1
						FROM UserMailsFilters AS umf
						WHERE umf.SampleEmailID = um.ID
							AND umf.ID = @FilterID
						), '') AS BIT) AS IsSample
			,(
				SELECT STUFF((
							SELECT DISTINCT N', ' + umf.Name
							FROM UserMailsFilters AS umf(NOLOCK)
							WHERE um.UserID IN (
									SELECT ud.[User_ID]
									FROM User_Detail AS ud
									WHERE ud.ParentID = umf.ParentID
									)
								AND um.FromMail LIKE '%' + umf.FromEmail + '%'
								AND um.ToEmail LIKE '%' + umf.ToEmail + '%'
								AND um.MailContent LIKE '%' + umf.MailContentContains + '%'
								AND um.MailSubject LIKE '%' + umf.SubjectContains + '%'
							FOR XML PATH('')
								,TYPE
							).value('text()[1]', 'nvarchar(max)'), 1, 2, N'')
				) AS FilterName
			,(
				SELECT STUFF((
							SELECT DISTINCT N', ' + umf.Name + '#' + CAST(umf.ID AS VARCHAR(50)) + '#' + CASE 
									WHEN umf.IsMapped = 1
										THEN 'Mapped'
									ELSE 'Not Mapped'
									END
							FROM UserMailsFilters AS umf(NOLOCK)
							WHERE um.UserID IN (
									SELECT ud.[User_ID]
									FROM User_Detail AS ud
									WHERE ud.ParentID = umf.ParentID
									)
								AND um.FromMail LIKE '%' + umf.FromEmail + '%'
								AND um.ToEmail LIKE '%' + umf.ToEmail + '%'
								AND um.MailContent LIKE '%' + umf.MailContentContains + '%'
								AND um.MailSubject LIKE '%' + umf.SubjectContains + '%'
							FOR XML PATH('')
								,TYPE
							).value('text()[1]', 'nvarchar(max)'), 1, 2, N'')
				) AS FilterIDWithName
			,um.ToEmail
			,isnull(u.enquiryid, 0) AS Enquiryid
		FROM #UserMails AS um
		LEFT JOIN UserEnquiryRawEntries AS u(NOLOCK) ON u.Mail_ID = um.ID
		WHERE um.UserID IN (
				SELECT UserId
				FROM #tblUserIds
				)
		ORDER BY um.CreatedOn DESC
	END

	EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @UserID
		,@Activity_type = 'View_UsrMails_List'
		,@ActionType = 'S'
		,@RowJson = ''
		,@Table_name = 'usermails'
END



GO

/* ============================================================
   Procedure: [dbo].[usp_GetMailsFrodbWithFilter_INTDateTime]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

 CREATE   PROCEDURE [dbo].[usp_GetMailsFrodbWithFilter_INTDateTime] --@userid=27726,@filterid=0        
 @UserID BIGINT,        
 @FilterID BIGINT        
AS        
BEGIN        
 DECLARE @FromMail     VARCHAR(500),        
         @ToEmail      VARCHAR(500),        
         @Subject      VARCHAR(500),        
         @Body         VARCHAR(500)  
         
 SELECT @FromMail = umf.FromEmail,        
        @ToEmail     = umf.ToEmail,        
        @Subject     = umf.SubjectContains,        
        @Body        = umf.MailContentContains        
 FROM   UserMailsFilters AS umf        
 WHERE  umf.ID = @FilterID        
   
 select * into #usermails from usermails where UserID = @UserID and DATEDIFF(d,CreatedOn,getdate())<=30  
         
 SELECT um.ID,        
        um.FromMail,        
        dbo.[fn_getusertimefromindiantime](UserID,um.MailDate) as MailDate,        
        dbo.[fn_getusertimefromindiantime](UserID,um.MailDate) AS MaildateFormat,        
        um.MailSubject,        
        --um.MailContent,        
       dbo.[fn_getusertimefromindiantime](UserID,um.CreatedOn) as CreatedOn,        
        CAST(        
            ISNULL(        
                (        
                    SELECT TOP 1 1        
                    FROM   UserMailsFilters AS umf        
                    WHERE  umf.SampleEmailID = um.ID        
                           AND umf.ID = @FilterID        
                ),        
                ''        
            ) AS BIT        
        )            AS IsSample,        
        (SELECT STUFF(      
                       (      
                           SELECT DISTINCT N', ' + umf.Name      
                           FROM   UserMailsFilters AS umf      
                           WHERE um.UserID IN (SELECT ud.[User_ID]      
                                                FROM   User_Detail AS ud      
                                                WHERE  ud.ParentID = umf.ParentID)      
                                  AND um.FromMail LIKE '%' + umf.FromEmail + '%'      
                                  AND um.ToEmail LIKE '%' + umf.ToEmail + '%'      
                                  AND um.MailContent LIKE      
                                      '%' + umf.MailContentContains +      
                                      '%'      
                                  AND um.MailSubject LIKE      
                                      '%' + umf.SubjectContains +      
                                      '%'      
                                      FOR XML PATH(''), TYPE      
                       ) .value('text()[1]', 'nvarchar(max)'),      
                       1,      
                       2,      
                       N''      
                   )            
        )            AS FilterName,        
        (SELECT STUFF(      
                       (      
                           SELECT DISTINCT N', ' + umf.Name + '#'      
                                  + CAST(umf.ID AS VARCHAR(50)) + '#'      
                                  +      
                                  CASE       
                                       WHEN umf.IsMapped =      
                                            1 THEN 'Mapped'      
                                       ELSE 'Not Mapped'      
                                  END      
                           FROM   UserMailsFilters AS umf      
                           WHERE  um.UserID IN (SELECT ud.[User_ID]      
                                                FROM   User_Detail AS ud      
                                                WHERE  ud.ParentID = umf.ParentID)      
                                  AND um.FromMail LIKE '%' + umf.FromEmail +       
                                      '%'      
                                  AND um.ToEmail LIKE '%' + umf.ToEmail + '%'      
                                  AND um.MailContent LIKE      
                                      '%' + umf.MailContentContains +      
                                      '%'      
                                  AND um.MailSubject LIKE      
                                      '%' + umf.SubjectContains +      
      '%'      
                                      FOR XML PATH(''), TYPE      
                       ) .value('text()[1]', 'nvarchar(max)'),      
                       1,      
                       2,      
                       N''      
                   ) )AS FilterIDWithName,        
        um.ToEmail        
 FROM   #UserMails    AS um        
 WHERE  um.UserID = @UserID        
        AND um.FromMail LIKE '%' + ISNULL(@FromMail, um.FromMail) + '%'        
        AND um.ToEmail LIKE '%' + ISNULL(@ToEmail, um.ToEmail) + '%'        
        AND um.MailSubject LIKE '%' + ISNULL(@Subject, um.MailSubject) +        
            '%'        
        AND um.MailContent LIKE '%' + ISNULL(@Body, um.MailContent) + '%'        
 ORDER BY        
        um.CreatedOn DESC        
END 


GO

