/* ============================================================
   Procedure: [dbo].[usp_GetMailSmsCreditBalance]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


-- Exec usp_GetMailSmsCreditBalance 10043, 32222
CREATE   PROCEDURE dbo.usp_GetMailSmsCreditBalance
(    
	@M_ID bigint,
	@User_ID bigint
)    
AS    
BEGIN    

	DECLARE @Intcredit DECIMAL(18, 2)= 0, @Mailcredit DECIMAL(18, 2)= 0, @Smscredit DECIMAL(18, 2)= 0;

	SELECT TOP 1 @Intcredit = ISNULL(Balance, 0) FROM IntCredit_Details WHERE USER_ID = @User_Id ORDER BY Credit_ID DESC;    

	IF EXISTS ( SELECT 1 FROM user_detail WHERE HasVirtualCredits = 1 AND IsSuperReseller = 1 AND USER_ID = @User_Id )
	BEGIN
		DECLARE @Actualbalance BIGINT= ISNULL(( SELECT TOP 1 balance FROM superresellercredit_details WHERE m_id = @M_Id AND user_id = @User_Id ORDER BY credit_id DESC ), 0);
		SELECT TOP 1 @Smscredit=balance + @Actualbalance
		FROM credit_details --with(index(idx_Credit_id_user_id_m_id))           
		WHERE m_id = @M_Id AND user_id = @User_Id
		ORDER BY credit_id DESC;
	END
	ELSE
	BEGIN
		SELECT TOP 1 @Smscredit=balance
		FROM credit_details --with(index(idx_Credit_id_user_id_m_id))           
		WHERE m_id = @M_Id AND user_id = @User_Id
		ORDER BY credit_id DESC;
	END


	IF EXISTS ( SELECT 1 FROM user_detail WHERE HasVirtualCredits = 1 AND IsSuperReseller = 1 AND USER_ID = @User_Id )
	BEGIN
		DECLARE @Actualbal BIGINT= ISNULL((SELECT TOP 1 balance FROM SuperResellerMailCreditDetails WHERE m_id = @M_Id AND user_id = @User_Id ORDER BY credit_id DESC ), 0);
		SELECT TOP 1 @Mailcredit = balance + @Actualbal
		FROM MailCreditDetails
		WHERE m_id = @M_Id AND USER_ID = @User_Id
		ORDER BY credit_id DESC;
	END;
		ELSE
	BEGIN
		SELECT TOP 1 @Mailcredit = balance
		FROM MailCreditDetails
		WHERE m_id = @M_Id AND USER_ID = @User_Id
		ORDER BY credit_id DESC;
	END;

	Select @Intcredit as Intcredit, @Mailcredit as Mailcredit, @Smscredit as Smscredit
	
END                



GO

