/* ============================================================
   Procedure: [dbo].[Usp_getMappedPipeLine_byID]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.Usp_getMappedPipeLine_byID  --3        
(        
   @PipeLineID bigint        
)        
as        
Begin        
        
   Declare @TotalAmount numeric(18,2) = 0          
   Declare @MaxAmount numeric(18,2) = 0    
        
   select @TotalAmount = Sum(isnull(Amount,0)) from LeadPipelineMapping(nolock) where PipelineID = @PipeLineID         
   select @MaxAmount = max(isnull(Amount,0)) from LeadPipelineMapping(nolock) where PipelineID = @PipeLineID         
        
  
    select          
       @TotalAmount as TotalAmount  
    ,@MaxAmount  as MaxAmount      
      ,[ID]  as MappedPipelineID       
      ,[LeadID]        
      ,[PipelineID]        
      ,[PipeLineStage]        
      ,(select isnull(Name,'')  from PipelineStages where ID = PipeLineStage and  PipelineID = @PipeLineID ) as StageName        
        
   --,(select top 1 count(lpm.PipeLineStage) as Dealcount from LeadPipelineMapping as lpm  where lpm.PipeLineStage = PipeLineStage and lpm.PipelineID = @PipeLineID   group by lpm.PipeLineStage )   as DealCount  
       
     
   ,[Probability]        
      ,[Amount]        
      ,[Remarks]        
      ,[CreatedDate]        
      ,[CreatedBy]        
      ,[EstimatedClosureDate]        
      ,[DealOwner]        
   ,(select isnull(user_login,'') from User_Detail where user_id = DealOwner ) as Owner        
  from LeadPipelineMapping where PipelineID = @PipeLineID            
        
 end


GO

/* ============================================================
   Procedure: [dbo].[usp_GetMappingByDropdownSelection]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[usp_GetMappingByDropdownSelection]
    @MappingId BIGINT,
	@Mode nvarchar(200)
AS
BEGIN
    SET NOCOUNT ON;

    DECLARE @ExcelColumns NVARCHAR(MAX);
    DECLARE @MappingDetails NVARCHAR(MAX);
	if(@Mode='Original')
	begin
	      SELECT 
        @ExcelColumns = ExcelColumns
    FROM 
        Lead_FieldMappingDetails
    WHERE 
        LField_MappingId = @MappingId;
    SELECT 
        OriginalColumn = JSON_TABLE.[value]
    FROM 
        OPENJSON(@ExcelColumns) AS JSON_TABLE;
    
  end
  else
  begin
  SELECT 
        @MappingDetails = MappingDetails,
        @ExcelColumns = ExcelColumns
    FROM 
        Lead_FieldMappingDetails
    WHERE 
        LField_MappingId = @MappingId;
    SELECT 
        COLUMN_NAME = JSON_TABLE.[value]
    FROM 
        OPENJSON(@MappingDetails) AS JSON_TABLE
    WHERE 
        JSON_TABLE.[value] NOT LIKE '%Other Field%';
		end
END;




