/* ============================================================
   Procedure: [dbo].[usp_getMaskedData]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_getMaskedData]                  
(              
 @TableName varchar(100),              
 @ParentId bigint = 0,  
  @UserId bigint = 0  
)              
AS              
  SET NOCOUNT ON              
               
 BEGIN              
          
 select  phs.PageFieldId  , paghf.PageCode,             
 Case when pagfi.TableName != '' then pagfi.TableName            
else 'Custom'            
End TableName, urm.UserId, pagfi.FieldName, phs.HiddenType, phs.IsExportAllow              
 from tbl_UA_PageHiddenFields paghf            
inner join TBL_UA_UserRoleMappingMaster urm on paghf.RoleCode = urm.RoleCode            
inner join tbl_UA_PageHiddenFieldsSettings phs on paghf.PageHiddenFieldsId = phs.PageHiddenFieldsId            
inner join tbl_UA_PageFields pagfi on phs.PageFieldId = pagfi.PageFieldId              
where      
       urm.UserId = @UserId   and pagfi.TableName =  @TableName  and paghf.ParentId = @ParentId           
end          
                              
                             


GO

/* ============================================================
   Procedure: [dbo].[usp_GetMassOperationDetails]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


---------------------------------------------------------------------------------------

CREATE   PROCEDURE usp_GetMassOperationDetails  
    @BatchID INT  
AS  
BEGIN  
    DECLARE @EntityType VARCHAR(20);  
  
    SELECT   
        @EntityType = EntityType  
    FROM   
        Tbl_MassOperationSummary  
    WHERE   
        BatchID = @BatchID;  
  
    DECLARE @EntityDetails TABLE (  
        PersonName NVARCHAR(100),  
        ID INT,  
        LeadNo INT,  
        Status VARCHAR(50)  
    );  
  
    IF @EntityType = 'Enquiry'  
    BEGIN  
        INSERT INTO @EntityDetails (PersonName, ID, LeadNo, Status)  
        SELECT   
            ue.PersonName,  
            ue.EnquiryID,  
            NULL AS LeadNo,  
            CASE   
                WHEN MOS.ScheduleDateTime IS NOT NULL THEN 'Scheduled'  
                WHEN MOS.IsProcessed = 1 THEN 'Processed'  
                ELSE 'Not Processed'  
            END AS Status  
        FROM   
            UserEnquiry ue  
        INNER JOIN   
            Tbl_MassOperationDetails MOD ON ue.EnquiryID = MOD.EntityID  
        INNER JOIN   
            Tbl_MassOperationSummary MOS ON MOD.SummaryID = MOS.BatchID  
        WHERE   
            MOD.SummaryID = @BatchID;  
    END  
    ELSE IF @EntityType = 'Lead'  
    BEGIN  
        INSERT INTO @EntityDetails (PersonName, ID, LeadNo, Status)  
        SELECT   
            ul.PersonName,  
            NULL AS ID,  
            ul.LeadNo,  
            CASE   
                WHEN MOS.ScheduleDateTime IS NOT NULL THEN 'Scheduled'  
                WHEN MOS.IsProcessed = 1 THEN 'Processed'  
                ELSE 'Not Processed'  
            END AS Status  
        FROM   
            UserLeads ul  
        INNER JOIN   
            Tbl_MassOperationDetails MOD ON ul.ID = MOD.EntityID  
        INNER JOIN   
            Tbl_MassOperationSummary MOS ON MOD.SummaryID = MOS.BatchID  
        WHERE   
            MOD.SummaryID = @BatchID;  
    END  
  
    SELECT   
        PersonName,  
        ID,  
        LeadNo,  
        Status  
    FROM   
        @EntityDetails;  
END  





