SET QUOTED_IDENTIFIER ON

-------------run this sp on mysmsconversasation

CREATE   PROCEDURE [dbo].[usp_GetMassSequenceDetails]    
    @UserId BIGINT   
    --@SequenceType VARCHAR(50),    
    --@ActionType VARCHAR(100),    
 --@SequenceEventFor VARCHAR(100)    
AS    
BEGIN    
    -- Ensure no previous result sets interfere    
    SET NOCOUNT ON;    
    --declare @ParentId bigint
    --SELECT @ParentId = ParentID
    --FROM User_Detail (NOLOCK)
    --WHERE User_ID = @UserId;

    -- Select statement to fetch the required data    
    SELECT    
 m.SequenceId,  
 --a.SequenceActionId,  
        m.Name    
        --a.ActionType,    
       -- a.ActionDetails  
    FROM    
        tbl_WA_SequenceMaster m    
    INNER JOIN    
        tbl_WA_SequenceActionMaster a ON m.SequenceId = a.SequenceId    
    WHERE    
        m.UserId = @UserId    
        --AND m.SequenceType = @SequenceType    
        --AND a.ActionType = @ActionType    
  --AND m.SequenceEventFor = 'Lead'    
        AND m.IsActive = 1    
        AND m.IsDeleted = 0    
        AND a.IsActive = 1    
        AND a.IsDeleted = 0;    
END



