   Procedure: [dbo].[usp_GetMassStatus]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_GetMassStatus]  
(  
    @ImportType CHAR(1), -- 'D' or 'L'  
    @FromDate datetime = NULL,  
    @ToDate datetime = NULL,  
    @UserId BIGINT,  
    @BatchID BIGINT = NULL,  
    @MassOperation NVARCHAR(100) =null,  
    @EntityType NVARCHAR(100) = NULL  
)  
AS  
BEGIN  
/*declare 
 @ImportType CHAR(1)='D', -- 'D' or 'L'
   @FromDate datetime = '2025-03-04',--'2024-01-02',--'2025-03-04',
@ToDate datetime = '2025-06-19',--'2024-01-04',--'2025-03-19',
    @UserId BIGINT=32222,--47482,
    @BatchID BIGINT = NULL,
    @MassOperation NVARCHAR(100) = NULL,
    @EntityType NVARCHAR(100) = 'Enquiry'*/
/*declare 
 @ImportType CHAR(1)='D', -- 'D' or 'L'
   @FromDate datetime = '2024-01-02',--'2025-03-04',
@ToDate datetime = '2024-01-04',--'2025-03-19',
    @UserId BIGINT=47482,
    @BatchID BIGINT = NULL,
    @MassOperation NVARCHAR(100) = NULL,
    @EntityType NVARCHAR(100) = NULL*/

	/*declare 
@ImportType CHAR(1)='D',
@FromDate datetime = '9/6/2024 12:00:00 AM',
@ToDate datetime = '10/4/2024 11:59:59 PM',
@UserId BIGINT=32222,
@BatchID BIGINT = NULL,
@MassOperation NVARCHAR(100) = NULL,
@EntityType NVARCHAR(100) = 'Enquiry'*/

    SET NOCOUNT ON;  
   begin try
   IF @MassOperation = '' SET @MassOperation = NULL;
    DECLARE @ParentId BIGINT = 0;  
    DECLARE @IsAdmin BIT = 0;  
    DECLARE @RoleType VARCHAR(10);  
    DECLARE @TeamCode VARCHAR(20);  
  
    SELECT @ParentId = ParentID, @IsAdmin = IsAdmin  
    FROM User_Detail (NOLOCK)  
    WHERE User_ID = @UserId;  
  
    IF OBJECT_ID('tempdb..#tblUserIds') IS NOT NULL  
    BEGIN  
        DROP TABLE #tblUserIds;  
    END  
  
    CREATE TABLE #tblUserIds (  
        UserId BIGINT NOT NULL  
    );  
  
    SELECT @TeamCode = tum.TeamCode  
    FROM TBL_UA_TeamUserMappingMaster (NOLOCK) tum  
    INNER JOIN TBL_UA_TeamMaster (NOLOCK) tm ON tm.TeamCode = tum.TeamCode  
    WHERE tum.UserId = @UserId;  
  
    IF ((@TeamCode IS NULL) AND (@ParentId = @UserId OR @IsAdmin = 1))  
    BEGIN  
        INSERT INTO #tblUserIds (UserId)  
        SELECT User_Id  
        FROM User_Detail (NOLOCK)  
        WHERE ParentId = @ParentId;  
    END  
    ELSE IF (@TeamCode IS NOT NULL)  
    BEGIN  
        INSERT INTO #tblUserIds (UserId)  
        SELECT UserId  
        FROM TBL_UA_TeamUserMappingMaster (NOLOCK)  
        WHERE TeamCode = @TeamCode;  
    END  
    ELSE  
    BEGIN  
        INSERT INTO #tblUserIds (UserId)  
        SELECT @UserId;  
    END  
  
    IF @ImportType = 'D' AND @BatchID > 0  
    BEGIN  
	print 1
        -- Query for MassOperationSummary  
        SELECT  
            mos.BatchID,  
            mos.MassOperationName AS Batch,  
            mos.UserID AS CreatedByUserID,  
            CONCAT(ud.user_login, ' (', ud.fname, ' ', ud.lname, ')') AS CreatedBy,  
            mos.CreatedDate,  
            CASE  
                WHEN mos.ScheduleDateTime IS NOT NULL AND mos.BatchStartTime IS NULL AND mos.IsProcessed = 0 THEN 'Scheduled'  
			    WHEN mos.IsProcessed = 1 AND mos.ScheduleDateTime IS NOT NULL AND mos.BatchStartTime IS NOT NULL AND mos.BatchEndTime IS NOT NULL THEN 'Processed'  
                WHEN mos.IsProcessed = 1 AND mos.ScheduleDateTime IS NOT NULL AND mos.BatchStartTime IS NOT NULL THEN 'UnderProcessed'  
                ELSE 'Not Scheduled'  
            END AS Status,  
            --mos.ScheduleDateTime AS ScheduleDate, 
			CASE 
    WHEN mos.ScheduleDateTime IS NULL 
         OR CAST(mos.ScheduleDateTime AS DATE) = '1900-01-01' THEN '' 
    ELSE CONVERT(VARCHAR, mos.ScheduleDateTime, 120) 
END AS ScheduleDate,
            mos.BatchStartTime AS ProcessDate,  
            mos.ErrorDetails AS StatusReason,  
			(
        SELECT COUNT(*) 
        FROM Tbl_MassOperationDetails WITH (NOLOCK) 
        WHERE SummaryID = mos.BatchID
    ) AS TotalCount,
   'MassOperation' AS ButtonType  
        FROM  
            dbo.Tbl_MassOperationSummary mos  
        INNER JOIN  
            #tblUserIds uids ON mos.UserID = uids.UserId  
        INNER JOIN  
            User_Detail ud ON mos.UserID = ud.User_ID  
        WHERE  
            mos.UserID IN (SELECT User_id FROM User_Detail (NOLOCK) WHERE ParentId = @UserId OR User_id = @UserId) AND  
            (@MassOperation IS NULL OR mos.MassOperationName = @MassOperation) AND  
            mos.BatchID =ISNULL( @BatchID, mos.BatchID) AND  
            mos.EntityType =ISNULL( @EntityType, mos.EntityType) AND isvalid = 1  
  
        UNION ALL  
    
        -- Query for Webhook related data  
        SELECT   
            whs.WebhookID AS BatchID,  
            cb.ButtonName AS Batch,  
            whs.UserId AS CreatedByUserID,  
            CONCAT(ud.user_login, ' (', ud.fname, ' ', ud.lname, ')') AS CreatedBy,  
            cb.CreatedDate,  
            NULL AS Status,  
            NULL AS ScheduleDate,  
            whs.ProcessedDate AS ProcessDate,  
            whs.ErrorDetails AS StatusReason,
			   (
        SELECT COUNT(*) 
        FROM tbl_cb_webhook_restbl WITH (NOLOCK)
        WHERE WebhookID = whs.WebhookID
    ) AS TotalCount,
   'CustomButton' AS ButtonType  
        FROM   
            tbl_CB_CustomButtons cb  
        --INNER JOIN   
        --    tbl_cb_webhook_restbl wr ON cb.WebhookID = wr.WebhookID  
        INNER JOIN   
            Tbl_CB_WebhookSummary whs ON cb.WebhookID = whs.WebhookID  
        INNER JOIN   
            User_Detail ud ON cb.UserId = ud.User_ID  
        WHERE   
            cb.UserId = @UserId  
            AND (@BatchID IS NULL OR whs.WebhookID = @BatchID)  
   AND (@MassOperation IS NULL OR 'Custom Button' = @MassOperation)  
            AND (@EntityType IS NULL OR cb.ModuleCode = 'PAG10002')  
  
         
     
    END  
    ELSE IF @ImportType = 'L' AND @BatchID > 0  
    BEGIN  
	print 2
        -- Query for MassOperationSummary  
        SELECT  
            mos.BatchID,  
            mos.MassOperationName AS Batch,  
            mos.UserID AS CreatedByUserID,  
            CONCAT(ud.user_login, ' (', ud.fname, ' ', ud.lname, ')') AS CreatedBy,  
            mos.CreatedDate,  
            CASE  
                WHEN mos.ScheduleDateTime IS NOT NULL AND mos.BatchStartTime IS NULL AND mos.IsProcessed = 0 THEN 'Scheduled' 
				WHEN mos.IsProcessed = 1 AND mos.ScheduleDateTime IS NOT NULL AND mos.BatchStartTime IS NOT NULL AND mos.BatchEndTime IS NOT NULL THEN 'Processed'  

                WHEN mos.IsProcessed = 1 AND mos.ScheduleDateTime IS NOT NULL AND mos.BatchStartTime IS NOT NULL THEN 'UnderProcessed'  
                ELSE 'Not Scheduled'  
            END AS Status,  
            --mos.ScheduleDateTime AS ScheduleDate, 
			CASE 
    WHEN mos.ScheduleDateTime IS NULL 
         OR CAST(mos.ScheduleDateTime AS DATE) = '1900-01-01' THEN '' 
    ELSE CONVERT(VARCHAR, mos.ScheduleDateTime, 120) 
END AS ScheduleDate,
            mos.BatchStartTime AS ProcessDate,  
            mos.ErrorDetails AS StatusReason,  
			(
        SELECT COUNT(*) 
        FROM Tbl_MassOperationDetails WITH (NOLOCK) 
        WHERE SummaryID = mos.BatchID
    ) AS TotalCount,
   'MassOperation' AS ButtonType  
        FROM  
            dbo.Tbl_MassOperationSummary mos  
        INNER JOIN  
            #tblUserIds uids ON mos.UserID = uids.UserId  
        INNER JOIN  
            User_Detail ud ON mos.UserID = ud.User_ID  
        WHERE  
            mos.UserID IN (SELECT User_id FROM User_Detail (NOLOCK) WHERE ParentId = @UserId OR User_id = @UserId) AND  
            (@MassOperation IS NULL OR mos.MassOperationName = @MassOperation) AND  
           mos.BatchID =ISNULL( @BatchID, mos.BatchID) AND  
            mos.EntityType =ISNULL( @EntityType, mos.EntityType) AND isvalid = 1  
		   
  
        UNION ALL  
  
        -- Query for Webhook related data  
        SELECT   
            whs.WebhookID AS BatchID,  
            cb.ButtonName AS Batch,  
            whs.UserId AS CreatedByUserID,  
            CONCAT(ud.user_login, ' (', ud.fname, ' ', ud.lname, ')') AS CreatedBy,  
            cb.CreatedDate,  
            NULL AS Status,  
            NULL AS ScheduleDate,  
            whs.ProcessedDate AS ProcessDate,  
            whs.ErrorDetails AS StatusReason,
			   (
        SELECT COUNT(*) 
        FROM tbl_cb_webhook_restbl WITH (NOLOCK)
        WHERE WebhookID = whs.WebhookID
    ) AS TotalCount,
   'CustomButton' AS ButtonType  
        FROM   
            tbl_CB_CustomButtons cb  
        --INNER JOIN   
        --    tbl_cb_webhook_restbl wr ON cb.WebhookID = wr.WebhookID  
        INNER JOIN   
            Tbl_CB_WebhookSummary whs ON cb.WebhookID = whs.WebhookID  
        INNER JOIN   
            User_Detail ud ON cb.UserId = ud.User_ID  
        WHERE   
            cb.UserId = @UserId  
            AND (@BatchID IS NULL OR whs.WebhookID = @BatchID)  
   AND (@MassOperation IS NULL OR 'Custom Button' = @MassOperation)  
            AND (@EntityType IS NULL OR cb.ModuleCode = 'PAG10031')  
  
          
    END  
    ELSE IF @ImportType = 'D' AND (@BatchID IS NULL OR @BatchID = 0)  
    BEGIN
	print 3
        -- Query for MassOperationSummary  
        SELECT  
            mos.BatchID,  
            mos.MassOperationName AS Batch,  
            mos.UserID AS CreatedByUserID,  
            CONCAT(ud.user_login, ' (', ud.fname, ' ', ud.lname, ')') AS CreatedBy,  
            mos.CreatedDate,  
            CASE  
                WHEN mos.ScheduleDateTime IS NOT NULL AND mos.BatchStartTime IS NULL AND mos.IsProcessed = 0 THEN 'Scheduled' 
			    WHEN mos.IsProcessed = 1 AND mos.ScheduleDateTime IS NOT NULL AND mos.BatchStartTime IS NOT NULL AND mos.BatchEndTime IS NOT NULL THEN 'Processed'  
                WHEN mos.IsProcessed = 1 AND mos.ScheduleDateTime IS NOT NULL AND mos.BatchStartTime IS NOT NULL THEN 'UnderProcessed'  
                ELSE 'Not Scheduled'  
            END AS Status,  
            --mos.ScheduleDateTime AS ScheduleDate,  
			CASE 
    WHEN mos.ScheduleDateTime IS NULL 
         OR CAST(mos.ScheduleDateTime AS DATE) = '1900-01-01' THEN '' 
    ELSE CONVERT(VARCHAR, mos.ScheduleDateTime, 120) 
END AS ScheduleDate,
            mos.BatchStartTime AS ProcessDate,  
            mos.ErrorDetails AS StatusReason,  
			(
        SELECT COUNT(*) 
        FROM Tbl_MassOperationDetails WITH (NOLOCK) 
        WHERE SummaryID = mos.BatchID
    ) AS TotalCount,
   'MassOperation' AS ButtonType  
        FROM  
            dbo.Tbl_MassOperationSummary mos  
        INNER JOIN  
            #tblUserIds uids ON mos.UserID = uids.UserId  
        INNER JOIN  
            User_Detail ud ON mos.UserID = ud.User_ID  
        WHERE  
            mos.UserID IN (SELECT User_id FROM User_Detail (NOLOCK) WHERE ParentId = @UserId OR User_id = @UserId) AND  
            (@MassOperation IS NULL OR mos.MassOperationName = @MassOperation) AND  
            mos.CreatedDate BETWEEN @FromDate AND @ToDate AND  
            mos.EntityType = ISNULL( @EntityType, mos.EntityType) AND isvalid = 1  
  
        UNION ALL  
  
        -- Query for Webhook related data  
        SELECT   
            whs.WebhookID AS BatchID,  
            cb.ButtonName AS Batch,  
            whs.UserId AS CreatedByUserID,  
            CONCAT(ud.user_login, ' (', ud.fname, ' ', ud.lname, ')') AS CreatedBy,  
            cb.CreatedDate,  
            NULL AS Status,  
            NULL AS ScheduleDate,  
            whs.ProcessedDate AS ProcessDate,  
            whs.ErrorDetails AS StatusReason, 
			   (
        SELECT COUNT(*) 
        FROM tbl_cb_webhook_restbl WITH (NOLOCK)
        WHERE WebhookID = whs.WebhookID
    ) AS TotalCount,
   'CustomButton' AS ButtonType  
        FROM   
            tbl_CB_CustomButtons cb  
        --INNER JOIN   
        --    tbl_cb_webhook_restbl wr ON cb.WebhookID = wr.WebhookID  
        INNER JOIN   
            Tbl_CB_WebhookSummary whs ON cb.WebhookID = whs.WebhookID  
        INNER JOIN   
            User_Detail ud ON cb.UserId = ud.User_ID  
        WHERE   
            cb.UserId = @UserId  
            AND (@EntityType IS NULL OR cb.ModuleCode = 'PAG10002')  
   AND (@MassOperation IS NULL OR 'Custom Button' = @MassOperation)  
            AND cb.CreatedDate BETWEEN @FromDate AND @ToDate  
  
         
    END  
    ELSE IF @ImportType = 'L' AND (@BatchID IS NULL OR @BatchID = 0)  
    BEGIN  
	print 4
        -- Query for MassOperationSummary  
        SELECT  
            mos.BatchID,  
            mos.MassOperationName AS Batch,  
            mos.UserID AS CreatedByUserID,  
            CONCAT(ud.user_login, ' (', ud.fname, ' ', ud.lname, ')') AS CreatedBy,  
            mos.CreatedDate,  
            CASE  
                WHEN mos.ScheduleDateTime IS NOT NULL AND mos.BatchStartTime IS NULL AND mos.IsProcessed = 0 THEN 'Scheduled'  
				WHEN mos.IsProcessed = 1 AND mos.ScheduleDateTime IS NOT NULL AND mos.BatchStartTime IS NOT NULL AND mos.BatchEndTime IS NOT NULL THEN 'Processed'  
                WHEN mos.IsProcessed = 1 AND mos.ScheduleDateTime IS NOT NULL AND mos.BatchStartTime IS NOT NULL THEN 'UnderProcessed'  
                
                ELSE 'Not Scheduled'  
            END AS Status,  
            --mos.ScheduleDateTime AS ScheduleDate, 
			CASE 
    WHEN mos.ScheduleDateTime IS NULL 
         OR CAST(mos.ScheduleDateTime AS DATE) = '1900-01-01' THEN '' 
    ELSE CONVERT(VARCHAR, mos.ScheduleDateTime, 120) 
END AS ScheduleDate,
            mos.BatchStartTime AS ProcessDate,  
            mos.ErrorDetails AS StatusReason,  
			(
        SELECT COUNT(*) 
        FROM Tbl_MassOperationDetails WITH (NOLOCK) 
        WHERE SummaryID = mos.BatchID
    ) AS TotalCount,
   'MassOperation' AS ButtonType  
        FROM  
            dbo.Tbl_MassOperationSummary mos  
        INNER JOIN  
            #tblUserIds uids ON mos.UserID = uids.UserId  
        INNER JOIN  
            User_Detail ud ON mos.UserID = ud.User_ID  
        WHERE  
            mos.UserID IN (SELECT User_id FROM User_Detail (NOLOCK) WHERE ParentId = @UserId OR User_id = @UserId) AND  
            (@MassOperation IS NULL OR mos.MassOperationName = @MassOperation) AND  
            mos.CreatedDate BETWEEN @FromDate AND @ToDate AND  
            mos.EntityType = isnull(@EntityType,mos.entitytype) AND
			isvalid = 1  
  
        UNION ALL  
  
        -- Query for Webhook related data  
        SELECT   
            whs.WebhookID AS BatchID,  
            cb.ButtonName AS Batch,  
            whs.UserId AS CreatedByUserID,  
            CONCAT(ud.user_login, ' (', ud.fname, ' ', ud.lname, ')') AS CreatedBy,  
            cb.CreatedDate,  
            NULL AS Status,  
            NULL AS ScheduleDate,  
            whs.ProcessedDate AS ProcessDate,  
            whs.ErrorDetails AS StatusReason,  
			   (
        SELECT COUNT(*) 
        FROM tbl_cb_webhook_restbl WITH (NOLOCK)
        WHERE WebhookID = whs.WebhookID
    ) AS TotalCount,
   'CustomButton' AS ButtonType  
        FROM   
            tbl_CB_CustomButtons cb  
        --INNER JOIN   
        --    tbl_cb_webhook_restbl wr ON cb.WebhookID = wr.WebhookID  
        INNER JOIN   
            Tbl_CB_WebhookSummary whs ON cb.WebhookID = whs.WebhookID  
        INNER JOIN   
            User_Detail ud ON cb.UserId = ud.User_ID  
        WHERE   
            cb.UserId = @UserId  
            AND (@EntityType IS NULL OR cb.ModuleCode = 'PAG10031')  
   AND (@MassOperation IS NULL OR 'Custom Button' = @MassOperation)  
            AND cb.CreatedDate BETWEEN @FromDate AND @ToDate  
  
         
    END  
    ELSE  
    BEGIN  
        -- Default condition if no valid parameters are provided  
        PRINT 'Invalid parameters provided.';  
    END  
  
    DROP TABLE #tblUserIds;  
	end try
	 BEGIN CATCH
        exec usp_InsertErrorInfo 
    END CATCH
END  


