									BatchID = @BatchID AND
									(@EntityType IS NULL OR EntityType = @EntityType or @EntityType ='PAG10031') And isvalid = 1
						END
						ELSE IF @ImportType = 'D' AND (@BatchID IS NULL OR @BatchID = 0)
						BEGIN
							SELECT 
								   [BatchID]
								  ,[Batch]
								  ,[CreatedByUserID]
								  ,[CreatedBy]
								  ,[CreatedDate]
								  ,[Status]
								  --,[ScheduleDate]
								  ,CASE 
			WHEN CAST([ScheduleDate] AS DATETIME) = '1/1/1900 12:00:00 AM' THEN ''
			ELSE CONVERT(VARCHAR, [ScheduleDate], 120)
		END AS [ScheduleDate]
								  ,[ProcessDate]
								  ,[StatusReason]
								  ,[ButtonType]
								  ,[MassOperationName]
								  ,[EntityType]
								  FROM [dbo].[tbl_MassOperationStatus_Archive](nolock)
								Where UserId = @UserId and
								   (@MassOperation IS NULL OR MassOperationName = @MassOperation) AND
									CreatedDate BETWEEN @FromDate AND @ToDate AND
									(@EntityType IS NULL OR EntityType = @EntityType or @EntityType ='PAG10002') And isvalid = 1
						END
						ELSE IF  @ImportType = 'L' AND (@BatchID IS NULL OR @BatchID = 0)
						BEGIN
							SELECT 
								   [BatchID]
								  ,[Batch]
								  ,[CreatedByUserID]
								  ,[CreatedBy]
								  ,[CreatedDate]
								  ,[Status]
								  --,[ScheduleDate]
								  ,CASE 
			WHEN CAST([ScheduleDate] AS DATETIME) = '1/1/1900 12:00:00 AM' THEN ''
			ELSE CONVERT(VARCHAR, [ScheduleDate], 120)
		END AS [ScheduleDate]
								  ,[ProcessDate]
								  ,[StatusReason]
								  ,[ButtonType]
								  ,[MassOperationName]
								  ,[EntityType]
								  FROM [dbo].[tbl_MassOperationStatus_Archive](nolock)
								Where UserId = @UserId and
								   (@MassOperation IS NULL OR MassOperationName = @MassOperation) AND
									CreatedDate BETWEEN @FromDate AND @ToDate AND
									(@EntityType IS NULL OR EntityType = @EntityType or @EntityType ='PAG10031') And isvalid = 1
						END
					END
				ELSE
					BEGIN
					    EXEC [Mysms].[dbo].usp_GetMassStatus @ImportType, @FromDate, @ToDate, @UserId, @BatchID, @MassOperation, @EntityType;
					END*/
END


