/* ============================================================
   Procedure: [dbo].[Usp_GetMasterTagOfUser]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE dbo.Usp_GetMasterTagOfUser    
(    
  @UserID bigint    
)    
as    
Begin    
    
   Declare @ParentID bigint = 0       
       
   select top 1  @ParentID = isnull(ParentID,User_ID) from User_Detail(nolock) where User_ID = @UserID      
    
   SELECT [ID]    
      ,[Tag]    
      ,[ParentID]    
      ,[CreatedDate]    
      ,[CreatedBy]    
  FROM [TagMaster](nolock)     
       where ((ParentID = 0 ) or ( ParentID = @ParentID ) )     
    
end





GO

