SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE usp_getmatchingleadfromenquiry --'986823,986827'
@ids nvarchar(max)
as
begin
select value into #temp from dbo.fn_split(@ids,',')
select e.parentid,e.enquiryid,l.leadno,e.CreatedDate,e.mobileno,l.mobileno,l.mobileno1,l.mobileno2,e.emailid,l.emailid,l.emailid2,l.emailid1 from userenquiry 
e join userleads l on e.parentid=l.parentid 
join #temp t on t.value=enquiryid and e.leadno=l.LeadNo
end




