SET QUOTED_IDENTIFIER ON


-------------------------------------------------------------------------
 
  

CREATE   PROCEDURE [dbo].[usp_GetMediumSettings] --51724 

@UserID BIGINT  

AS  

BEGIN 

--declare @UserID BIGINT=51336   

DECLARE @ParentId BIGINT;   

SELECT @ParentId = ParentID   

    FROM User_Detail (NOLOCK)   

    WHERE User_ID = @UserID;

SELECT ums.MediumID,  

        ums.Name  

FROM   UserMediumSettings AS ums with(nolock)

WHERE  ums.IsActive = 1  

        AND ums.UserID = @ParentId  

END  




