/* ============================================================
   Procedure: [dbo].[usp_GetMenuData]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.usp_GetMenuData
As
Begin

    SELECT 
       MN1.[ID]
      ,MN1.[MenuName]
      ,MN1.[MenuParentID]
      ,isnull((select top 1 isnull(MenuName,'') from Menu where ID = MN1.MenuParentID),'') as MenuParentName
	  ,MN1.[PageID]
	  ,isnull((select top 1   isnull(PageName,'') from Page where ID = MN1.PageID),'') as PageName
      ,MN1.[Sequence]
      ,MN1.[CreatedDate]
    FROM [Menu] as MN1  --join Menu as MN2 on MN1.ID = MN2.ID  
	
	order by CreatedDate desc


 
End  




GO

