/* ============================================================
   Procedure: [dbo].[Usp_GetMergeLeadDetails]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROC [dbo].[Usp_GetMergeLeadDetails]
(
    @MobileNo VARCHAR(100),
    @MobileNo1 VARCHAR(100),
    @MobileNo2 VARCHAR(100),
    @EmailID VARCHAR(100),
    @EmailID1 VARCHAR(100),
    @EmailID2 VARCHAR(100)
)
AS
BEGIN
	SELECT ID
	FROM   UserLeads
	WHERE  MobileNo IN (@MobileNo, @MobileNo1, @MobileNo2)
	       OR  MobileNo1 IN (@MobileNo, @MobileNo1, @MobileNo2)
	       OR  MobileNo2 IN (@MobileNo, @MobileNo1, @MobileNo2)
	       OR  EmailID  IN (@EmailID, @EmailID1, @EmailID2)
	       OR  EmailID1  IN (@EmailID, @EmailID1, @EmailID2)
	       OR  EmailID2  IN (@EmailID, @EmailID1, @EmailID2)
END




GO

