 FROM MySMS.dbo.messagedeliverystatus md with (nolock) left join mysms.dbo.ReceiveDeliveryData rd with (nolock) 
 on '91'+md.mobile=rd.mobile left join mysms.dbo.MessageDeliveryStatusTemp mtp 
 on md.BatchID=mtp.BatchID--and replace(md.senderid,'.',' ')=replace(rd.senderid,'AM-','') 
 WHERE md.BatchID = @BatchID AND md.Mobile = @Mobile) 
 SELECT ct.Mobile,'*********' [Message],ct.SenderID,ct.MessageStatus,ct.[DeliverTime],ct.BatchID,Account from cte ct where dlr=1 
 END 
 ELSE 
 BEGIN 
with cte as( 
 SELECT md.Mobile as Mobile, md.[Message], md.SenderID as SenderID, md.BatchID, 
 isnull(rd.Statuswitherr,(CASE md.MessageStatus WHEN '3' THEN 'DND' when '6' 
 then 'Invalid' when '5' then 'Blacklisted' ELSE 'Sent' END )) 
 AS MessageStatus,Convert(varchar(8),md.MessageInsertDate,108) AS [DeliverTime],mtp.Account, 
 ROW_NUMBER() over (partition by md.messageid order by md.messageid) as dlr 
 FROM MySMS.dbo.messagedeliverystatus md with (nolock) left join mysms.dbo.ReceiveDeliveryData rd with (nolock) 
 on '91'+md.mobile=rd.mobile left join mysms.dbo.MessageDeliveryStatusTemp mtp 
 on md.BatchID=mtp.BatchID--and replace(md.senderid,'.',' ')=replace(rd.senderid,'AM-','') 
 WHERE md.BatchID = @BatchID AND md.Mobile = @Mobile) 
 SELECT ct.Mobile,ct.[Message],ct.SenderID,ct.MessageStatus,ct.[DeliverTime],ct.BatchID,Account from cte ct where dlr=1 
 END 
 END 
END 




GO

/* ============================================================
   Procedure: [dbo].[USP_GetMessageInfoByBatchIDOnDays1]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

---------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------
CREATE   PROC [dbo].[USP_GetMessageInfoByBatchIDOnDays1]      
@BatchID bigint,   -- frm varchr 19-08-2010     
@Mobile Varchar(12)       
AS      
BEGIN      
    IF (IsNull(@Mobile,'') = '')        
    BEGIN      
   with cte as(        
		SELECT md.Mobile as Mobile, Message, md.SenderID as SenderID, md.BatchID,
		CASE MessageStatus 
		WHEN '3' THEN 'DND' 
		when '6' then 'Invalid' 
		when '5' then 'Blacklisted' 
		WHEN 'DELIVRD' THEN 'DELIVRD'
		WHEN 'EXPIRED' THEN 'EXPIRED'
		WHEN 'UNDELIV' THEN 'UNDELIV'
		ELSE 'Sent' END
		AS MessageStatus,Convert(varchar(8),MessageInsertDate,108) AS [DeliverTime],
		ROW_NUMBER() over (partition by md.messageid order by md.messageid) as dlr
		FROM SixDaysHistory1 md(nolock)         
		WHERE BatchID = @BatchID )        
		SELECT Mobile,[Message],SenderID,MessageStatus,[DeliverTime],BatchID from cte where dlr=1     
   END      
   ELSE       
    BEGIN      
   with cte as(        
  	SELECT md.Mobile as Mobile, Message, md.SenderID as SenderID, md.BatchID,
		CASE MessageStatus 
		WHEN '3' THEN 'DND' 
		when '6' then 'Invalid' 
		when '5' then 'Blacklisted' 
		WHEN 'DELIVRD' THEN 'DELIVRD'
		WHEN 'EXPIRED' THEN 'EXPIRED'
		WHEN 'UNDELIV' THEN 'UNDELIV'
		ELSE 'Sent' END
		AS MessageStatus,Convert(varchar(8),MessageInsertDate,108) AS [DeliverTime],
		ROW_NUMBER() over (partition by md.messageid order by md.messageid) as dlr
		FROM SixDaysHistory1 md(nolock)      
		WHERE BatchID = @BatchID AND  md.Mobile = @Mobile)        
   SELECT Mobile,[Message],SenderID,MessageStatus,[DeliverTime],BatchID from cte where dlr=1   
    END       
END 




GO

