/* ============================================================
   Procedure: [dbo].[Usp_GetMessagesInWaiting]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

/*  
AUTHOR : MADAN LAL SHARMA  
DATE : 22-OCT-2013  
PURPOSE : FOR THE GETTING PENDING MESSAGES  OF USERS FOR RESEND MESSAGE IF MESSAGES NOT SENT AS FILTERMODE PERCENTAGE IN User_Detail TABLE  
*/  
CREATE   PROC [dbo].[Usp_GetMessagesInWaiting]  
 as  
  begin    
   SET NOCOUNT ON  
    DECLARE @USERID VARCHAR(20),@TOTALNUMBER BIGINT, @TOTALSMS BIGINT, @TOTALSENTSMS BIGINT, @USERFILTER VARCHAR(20), @FILTERMODE  VARCHAR(20),  @MID VARCHAR(20),@BATCHID VARCHAR(20), @ACOUNTType VARCHAR(20), @CREDITBALANCE BIGINT, @rows bigint;  
    declare @TempTableRec table (Records bigint, UserID bigint, MID bigint, TotalRecords bigint);  
   WITH SMSBALANCE AS (  
    SELECT count(mq.MessageQueueID) as Rowcounts, ud.User_ID, ud.M_ID, count(*) over () TotalRec   FROM [MySMS].[dbo].[MessageQueueMTIXTRC] mq (NOLOCK)  
   join [MySMS].[dbo].[user_detail] ud (nolock) on mq.U_ID=ud.User_ID group by ud.User_ID,UD.M_ID  
    union     
    SELECT count(mq.MessageQueueID) as Rowcounts, ud.User_ID, ud.M_ID, count(*) over () TotalRec FROM [MySMS].[dbo].[MessageQueueMTIXTRC2] mq (NOLOCK)  
   join [MySMS].[dbo].[user_detail] ud (nolock) on mq.U_ID=ud.User_ID group by ud.User_ID,UD.M_ID  
    union     
   SELECT count(mq.MessageQueueID) as Rowcounts, ud.User_ID, ud.M_ID,count(*) over () TotalRec FROM [MySMS].[dbo].[MessageQueueMTIXTRC3] mq (NOLOCK)  
   join [MySMS].[dbo].[user_detail] ud (nolock) on mq.U_ID=ud.User_ID group by ud.User_ID,UD.M_ID  
   union      
   SELECT count(mq.MessageQueueID) as Rowcounts, ud.User_ID, ud.M_ID, count(*) over () TotalRec FROM [MySMS].[dbo].[MessageQueueMTIXTRC4] mq (NOLOCK)  
   join [MySMS].[dbo].[user_detail] ud(nolock) on mq.U_ID=ud.User_ID group by ud.User_ID,UD.M_ID  
   union         
   SELECT count(mq.MessageQueueID) as Rowcounts, ud.User_ID, ud.M_ID, count(*) over () TotalRec FROM [MySMS].[dbo].[MessageQueueProMTIX] mq (NOLOCK)  
   join [MySMS].[dbo].[user_detail] ud(nolock) on mq.U_ID=ud.User_ID group by ud.User_ID,UD.M_ID  
   union  
   SELECT count(mq.MessageQueueID) as Rowcounts, ud.User_ID, ud.M_ID,count(*) over () TotalRec FROM [MySMS].[dbo].[MessageQueueProMTIX2]  mq (NOLOCK)  
   join [MySMS].[dbo].[user_detail] ud(nolock) on mq.U_ID=ud.User_ID group by ud.User_ID,UD.M_ID  
   union  
   SELECT count(mq.MessageQueueID) as Rowcounts,ud.User_ID, ud.M_ID,count(*) over () TotalRec FROM [MySMS].[dbo].[MessageQueueProMTIX3]mq (NOLOCK)  
   join [MySMS].[dbo].[user_detail] ud(nolock) on mq.U_ID=ud.User_ID group by ud.User_ID,UD.M_ID  
   union  
   SELECT count(mq.MessageQueueID) as Rowcounts, ud.User_ID, ud.M_ID,count(*) over () TotalRec FROM [MySMS].[dbo].[MessageQueueProMTIX4] mq (NOLOCK)  
   join [MySMS].[dbo].[user_detail] ud(nolock) on mq.U_ID=ud.User_ID group by ud.User_ID,UD.M_ID  
   union  
   SELECT  count(mq.MessageSourceID) as Rowcounts, ud.User_ID, ud.M_ID, count(*) over () TotalRec from [MySMS].[dbo].[MessageSource] mq (NOLOCK)  
   join [MySMS].[dbo].[user_detail] ud (nolock) on mq.U_ID=ud.User_ID group by ud.User_ID,UD.M_ID  
   )  
   insert into @TempTableRec SELECT Rowcounts, User_ID, M_ID,TotalRec FROM SMSBALANCE  ;  
   SET @TOTALNUMBER=isnull((SELECT top 1 TotalRecords  FROM @TempTableRec),0);  
  -- select @TOTALNUMBER
   IF (@TOTALNUMBER=0)  
    BEGIN  
    print 'queue null'      
    declare @toSentSMS bigint, @BALANCERECORD BIGINT, @DNDSMS BIGINT, @PENDINGRECORDS BIGINT, @CNTR BIGINT;  
    declare @TempTable  Table (TotalRows bigint, UserID bigint, BatchId bigint);  
    insert into @TempTable SELECT count(MessageDeliveryStatusID),U_ID,BatchID FROM [MySMS].[dbo].[MessageDeliveryStatusTemp](NOLOCK) group by U_ID,BatchID          
        SET @PENDINGRECORDS =(SELECT COUNT(*) FROM @TempTable )   
       -- select * from @TempTable  
     SET @CNTR=@PENDINGRECORDS; 
      set @rows=0; 
     WHILE @CNTR>0  
      BEGIN  
      --print 'in loop' 
      
       SET @USERID =(SELECT  TOP 1 UserID FROM @TempTable )  
       SET @BATCHID=(SELECT  TOP 1 BATCHID FROM @TempTable  WHERE UserID=@USERID)  
       
       select @DNDSMS=(select count(*) from messagedeliverystatustemp (NOLOCK) where messagerefid in  
       (select subreference from submitdetail(nolock) where resultcode='0x00000436') AND BatchID=@BATCHID)
       --U_ID=@USERID AND BatchID=@BATCHID)       
       
       select @TOTALSENTSMS= (SELECT count(MessageDeliveryStatusID) from [MySMS].[dbo].[MessageDeliveryStatusTemp] (NOLOCK) WHERE BatchID=@BATCHID)
       --U_ID=@USERID AND BatchID=@BATCHID)  
       SET @TOTALSENTSMS=@TOTALSENTSMS-@DNDSMS  
                 
       SELECT @TOTALSMS=BI.TotalRecords, @USERFILTER=BI.userfilter, @FILTERMODE=UD.FilterMode    FROM [MySMS].[dbo].[BatchInfo] BI (nolock) join  [MySMS].[dbo].[User_Detail] UD (nolock)  
       on BI.UserID=UD.User_ID where BI.BatchId=@BATCHID --and UD.User_ID=@USERID  
         
       SET @toSentSMS=@TOTALSMS*@FILTERMODE*10/100;          
        IF (@TOTALSENTSMS<@toSentSMS)  
         BEGIN  
          SET @BALANCERECORD=@toSentSMS-@TOTALSENTSMS  
        --  select @BALANCERECORD, @BATCHID, @USERFILTER
           IF @USERFILTER='MTIX_TRC'  
            BEGIN  
            set rowcount @BALANCERECORD
            INSERT INTO [MySMS].[dbo].[MessageQueueMTIXTRC4]([MessageID],[Mobile],[Message],[SenderID] ,[SmppID]  
            ,[MessageInsertDate],[Priority],[U_ID],[IsUniCode],[IsDND],[Operator],[BatchID],[Isallowdnd])   
            SELECT [MessageID],[Mobile],[Message],[SenderID],[SmppID],[MessageInsertDate],[Priority],[U_ID]  
            ,[IsUniCode] ,[IsDND] ,[Operator] ,[BatchID],[Isallowdnd] FROM [MySMS].[dbo].[PremiumMessage] (NOLOCK) WHERE BatchID=@BATCHID --U_ID=@USERID AND BatchID=@BATCHID  
            set @rows=@rows+rowcount_big()
          
           set rowcount 0
           END  
           ELSE IF @USERFILTER='MTIX_PRO'  
            BEGIN 
            set rowcount @BALANCERECORD
            INSERT INTO [MySMS].[dbo].[MessageQueueProMTIX4]([MessageID],[Mobile],[Message],[SenderID] ,[SmppID]  
            ,[MessageInsertDate],[Priority],[U_ID],[IsUniCode],[IsDND],[Operator],[BatchID],[Isallowdnd])   
            
            SELECT [MessageID],[Mobile],[Message],[SenderID],[SmppID],[MessageInsertDate],[Priority],[U_ID]  
            ,[IsUniCode] ,[IsDND] ,[Operator] ,[BatchID],[Isallowdnd] FROM [MySMS].[dbo].[PremiumMessage] (NOLOCK) WHERE BatchID=@BATCHID --U_ID=@USERID AND BatchID=@BATCHID  
             set @rows=@rows+rowcount_big();
          
            set rowcount 0
            END   
            
         END  
         DELETE  @TempTable WHERE UserID=@USERID AND BatchId=@BATCHID  
         SET @CNTR=@CNTR-1;  
         
     END  
   END  
    select isnull(@rows,0) as Effeected_Rows
    
  end  
  RETURN;  
   
    
 -- declare @TempTable  Table (TotalRows bigint, UserID bigint, BatchId bigint);  
 -- INSERT INTO @TempTable SELECT Mobile, U_ID, BatchID FROM [MySMS].[dbo].[MessageQueueMTIXTRC]


GO

/* ============================================================
   Procedure: [dbo].[Usp_getMessageStatusByBatchID]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.Usp_getMessageStatusByBatchID --124785507,'SMS'  -- 124786731,'Mail'   --'124785507','SMS'     
 (    
  @BatchID bigint,    
  @Mode nvarchar(50)    
)    
as    
 Begin    
      if(@Mode = 'SMS')    
     begin    
           select     
           distinct        
     Mobile    
    ,'XXXXXX' Message    
    ,MessageStatus    
    ,MessageInsertDate as MessageDate    
    ,StatusDescription    
                 from MessageDeliveryStatus with(nolock)     
            where BatchID = @BatchID  -- 124785507     
        end     
   else if(@Mode = 'Mail')    
      begin    
     select    
          distinct      
     eds.message_tag3 as ToEmail    
     ,'XXXXXX' as Message
	     -- ,ce.Message    

    , case when event_status = '001'  
                then 'Succeeded'  
    else 'Failed'  
    end event_status  
   
    ,event_desc    
    ,accept_time    
    ,event_time    
    ,Reason    
    ,CreatedOn    
           from EmailDeliveryStatus as EDS with(nolock)    
            join ClientEmails as CE with(nolock)    
      on EDS.BatchID = CE.BatchID     
     where EDS.batchid = @BatchID  --order by EDS.id desc          
   end    
 End 


GO

