CREATE   PROCEDURE [dbo].[usp_getmetadata_foractivity] --61138627,'enquiry',--58848730,'lead'--52288558,'enquiry'    
(@activityid bigint,@entityname nvarchar(100))                                      
as                                      
begin                                      
      --declare @activityid bigint=34962809, @entityname nvarchar(100) = 'Lead'  
 --declare @activityid bigint=5293562, @entityname nvarchar(100) = 'user'   
 	--declare @activityid bigint=58438496, @entityname nvarchar(100) = 'Lead'    
    
 DECLARE @eventtype NVARCHAR(100), @jsonentity NVARCHAR(MAX), @jsonactivity NVARCHAR(MAX), @jsonusers NVARCHAR(MAX),@eventby nvarchar(50);    
     
 DECLARE @userids NVARCHAR(MAX), @user BIGINT, @parentid BIGINT, @eventid INT, @eventname NVARCHAR(100), @entityid BIGINT, @reftables NVARCHAR(MAX), @refids NVARCHAR(MAX), @seektable NVARCHAR(100), @context NVARCHAR(100), @notificationid BIGINT= 0, 
 @ispredefined bit = 0;  
  
 Declare @StrQuery nvarchar(max)=''  
              
 IF @entityname = 'lead'              
 BEGIN              
  SELECT @user = [userid], @parentid = [ParentID], @eventid = [eventid], @entityid = [LeadID],               
    @reftables = [reftables], @refids = [refids], @seektable = 'tbl_LeadEventHistory'              
  FROM tbl_LeadEventHistory(NOLOCK)              
  WHERE [historyid] = @activityid;              
 END;              
              
 IF @entityname = 'enquiry'              
 BEGIN              
  SELECT @user = [userid], @parentid = [ParentID], @eventid = [eventid], @entityid = [EnquiryID],               
    @reftables = [reftables], @refids = [refids], @seektable = 'tbl_enquiryEventHistory'              
  FROM   tbl_enquiryEventHistory(NOLOCK)              
  WHERE  [historyid] = @activityid;              
 END;              
              
 IF @entityname = 'user'              
 BEGIN              
  SELECT @user = [userid], @parentid = [ParentID], @eventid = [eventid], @entityid = [userid],               
    @reftables = [reftables], @refids = [refids], @seektable = 'tbl_userEventHistory'              
  FROM tbl_userEventHistory(NOLOCK)              
  WHERE [historyid] = @activityid;              
 END;              
              
 DECLARE @query NVARCHAR(MAX);              
              
 SELECT @eventname = [eventname], @eventtype = [eventtype], @context = [context] , @ispredefined = IsPredefind,@eventby=eventby             
 FROM activitymaster(NOLOCK)              
 WHERE [id] = @eventid;              
              
 DROP TABLE IF EXISTS #entitydetails;              
              
 DROP TABLE IF EXISTS #activitydetails;              
              
 DROP TABLE IF EXISTS #userdetails;              
              
 CREATE TABLE #entitydetails              
 (              
  [Entityid]        BIGINT,              
  [leadno]          BIGINT NULL,              
  [personname]      NVARCHAR(200) NULL,              
  [MobileNo]        NVARCHAR(50) NULL,              
  [MobileNo1]       NVARCHAR(50) NULL,              
  [MobileNo2]       NVARCHAR(50) NULL,              
  [EmailID]         NVARCHAR(200) NULL,              
  [EmailID1]        NVARCHAR(200) NULL,              
  [EmailID2]        NVARCHAR(200) NULL,              
  [FollowupStatus]  NVARCHAR(100) NULL,              
  [Source]          NVARCHAR(100) NULL,              
  [Medium]          NVARCHAR(100) NULL,              
  [Campaign]        NVARCHAR(100) NULL,              
  [EntityCreatedOn] DATETIME NULL              
 );  
 
 
 --exec usp_replaceentityplaceholders_allfields_insert @entityid, @entityname
 
              
 IF @context = 'lead'              
 BEGIN              
  INSERT INTO #entitydetails([Entityid], [leadno], [personname], [MobileNo], [MobileNo1], [MobileNo2],              
  [EmailID], [EmailID1], [EmailID2], [FollowupStatus], [Source], [Medium], [Campaign], [EntityCreatedOn])    
  SELECT [u].[id] AS [Entityid], [leadno], [personname], [MobileNo], [MobileNo1], [MobileNo2], [EmailID],             
  [EmailID1], [EmailID2],isnull([f].[FollowupStatus],'') FollowupStatus, [s].[Name] AS [Source], [m].[Name] AS [Medium], [c].[Name] AS [Campaign], [u].[CreatedOn] AS [EntityCreatedOn]              
      -- select *                                     
  FROM   userleads(NOLOCK) AS u left JOIN FollowUp_Status AS f              
  ON u.FollowUpStatus = f.ID LEFT JOIN UserSourceSettings AS s(NOLOCK)              
  ON s.SourceID = u.SourceName LEFT JOIN UsermediumSettings AS m(NOLOCK)              
  ON m.mediumID = u.mediumName LEFT JOIN UsercampaignSettings AS c(NOLOCK)              
  ON c.campaignID = u.campaignName         
  WHERE  [u].[id] = @entityid;              
              
  IF EXISTS(SELECT 1 FROM #entitydetails)              
  BEGIN           
            
  if @ispredefined=0          
  begin          
 set @jsonactivity= (select requestjson from tbl_ce_EventWebhook(nolock) where id=@refids)          
  end          
          
   IF @eventtype = 'support'              
   BEGIN              
    SET @jsonactivity = (SELECT * FROM               
    (SELECT [t].[Ticketno], [t].[Subject] AS [SupportTitle], [m].[Type_Desc] AS [TicketType], [t].[Priority] AS [TicketPriority], [t].[Date_Created] AS [ActivityObjectCreatedOn], [t].[update_date] AS [TicketLastUpdated],               
     ISNULL((SELECT [login_id] FROM [Serv_User_Detail] AS [d](NOLOCK) WHERE [d].User_id = [t].[Assignedby]), '') AS [TicketCreatedBy],               
     CASE WHEN [t].[assignto] = 0 AND [t].[Assign_Group] > 0 THEN 'Group' WHEN [t].[AssignTo] > 0 THEN 'Individual' ELSE '' END AS [TicketAssignType],               
     ISNULL((SELECT [login_id] FROM [Serv_User_Detail] AS [d](NOLOCK) WHERE [d].User_id = [t].[AssignTo]), '') AS [TicketAssignedToIndividual],               
     ISNULL((SELECT [Group_Name] FROM [Serv_Group_Mast] AS [d](NOLOCK) WHERE [d]. [groupid] = [t].[Assign_Group]), '') AS [TicketAssignedToGroup],               
     [t].[AssignedDateTime] AS [TicketAssignedOn], [t].[Source] AS [TicketSource], [s].[stat_desc] AS [TicketLatestStatus],    
  ISNULL( [t].[note], '') AS [TicketLatestNote], ISNULL([h].[note], '') AS [TicketNote], ISNULL([t].[remarks], '')    
  AS [TicketLatestUpdateRemarks], ISNULL([h].[remarks], '') AS [TicketUpdateRemarks],               
     ISNULL((SELECT [login_id] FROM [serv_user_detail] WHERE user_id = [h].[raisedby]), '') AS [TicketUpdatedBy],               
     ISNULL((SELECT [stat_desc] FROM [Serv_Ticket_Stat_Mast] WHERE [stat_id] = [h].STATUS), '') AS [TicketStatus], ISNULL([f].[rating], '') AS [TicketFeedback],               
     ISNULL((SELECT [login_id] FROM [serv_user_detail] WHERE user_id = [h].[raisedby]), '') AS [FeedbackForAgent],               
     ISNULL(CAST([f].[submitdate] AS NVARCHAR), '') AS [FeedbackDate],               
     ISNULL(CAST([f].[comments] AS NVARCHAR), '') AS [FeedbackComments]               
     FROM serv_ticketmaster AS t(NOLOCK) JOIN Serv_Ticket_Stat_Mast(NOLOCK) AS s              
     ON s.stat_id = t.STATUS LEFT JOIN Serv_TicketHistory AS h(NOLOCK)              
     ON t.ticketid = h.TicketID LEFT JOIN Serv_TicketType_Mast AS m(NOLOCK)              
     ON m.type_id = t.Ticket_type LEFT JOIN Serv_ticket_feedback_tbl(NOLOCK) AS f              
     ON f.TICKETID = t.ticketid              
     WHERE 1 = CASE WHEN @reftables = 'serv_ticketmaster' AND CAST([h].[TicketHistoryID] AS NVARCHAR) = (SELECT MAX([tickethistoryid]) FROM [serv_tickethistory] WHERE CAST([ticketid] AS NVARCHAR) = @refids)              
        THEN 1              
       WHEN @reftables = 'serv_ticketmaster'              
        AND [h].[tickethistoryid] IS NULL              
        THEN 1              
       WHEN @reftables = 'Serv_ticket_feedback_tbl'              
        AND CAST([f].[TicketHistoryID] AS NVARCHAR) = @refids              
        THEN 1              
       WHEN @reftables = 'Serv_TicketHistory'              
        AND CAST([h].[TicketHistoryID] AS NVARCHAR) = @refids              
        THEN 1              
       WHEN @reftables = 'Serv_ticket_feedback_tbl'              
        AND CAST([f].[ID] AS NVARCHAR) = @refids              
        THEN 1              
       ELSE 0              
       END) AS a FOR JSON AUTO, INCLUDE_NULL_VALUES);              
   END;              
      
   IF @eventtype = 'Ticket Portal'              
   BEGIN               
   print @eventtype  
    set @strQuery = Concat(' SET @jsonactivity1 = (SELECT * FROM               
 ( SELECT top 1 [t].[Ticketno], [t].[Subject] AS [SupportTitle], [m].[Type_Desc] AS [TicketType], [p].[PriorityName] AS [TicketPriority], [t].[CreatedOn] AS [ActivityObjectCreatedOn], [t].[ModifiedOn] AS [TicketLastUpdated], ISNULL((SELECT [LoginName] FROM [tbl_tp_UserLogin] AS [d](NOLOCK) 
	WHERE [d].TpUser_id = [t].[Createdby]), '''') AS [TicketCreatedBy],               
     CASE WHEN [t].[AssignedUser] = 0 AND [t].[AssignedGroup] > 0 THEN ''Group'' WHEN [t].[AssignedUser] > 0 THEN ''Individual'' ELSE '''' END AS [TicketAssignType], 
	 isnull(ttul.loginname,'''') AS [TicketAssignedToIndividual],
	 isnull(ttul.Country_Code,'''') AS [TicketAssignedToIndividual_Countrycode],
	 isnull(ttul.Mobile,'''') AS [TicketAssignedToIndividual_Mobile],
	 isnull(ttul.Email,'''') AS [TicketAssignedToIndividual_Email],
	 isnull(ttul.Name,'''') AS [TicketAssignedToIndividual_Name],
	 --ISNULL((SELECT [LoginName] FROM [tbl_tp_UserLogin] AS [d](NOLOCK) WHERE [d].TpUser_id = [t].[AssignedUser]), '''') AS [TicketAssignedToIndividual],               
     ISNULL((SELECT [GroupName] FROM [tbl_tp_GroupMaster] AS [d](NOLOCK) WHERE [d]. [groupid] = [t].[AssignedGroup]), '''') AS [TicketAssignedToGroup],               
     [h].[ActionDateTime] AS [TicketAssignedOn], [sm].TicketSourceName AS [TicketSource], [s].[TicketStatus] AS [TicketLatestStatus],    
  ISNULL( [t].[note], '''') AS [TicketLatestNote], ISNULL([h].[note], '''') AS [TicketNote], ISNULL([t].[remarks],'''') AS [TicketLatestUpdateRemarks], ISNULL([h].[remarks], '''') AS [TicketUpdateRemarks],  
     ISNULL((SELECT [LoginName] FROM [tbl_tp_UserLogin] WHERE Tpuser_id = [h].[AssignedBy]), '''') AS [TicketUpdatedBy],               
     ISNULL((SELECT [TicketStatus] FROM [tbl_tp_TicketStatusMaster] WHERE [TicketStatus_ID] = [h].TicketStatusID), '''') AS [TicketStatus], ISNULL([f].[rating], '''') AS [TicketFeedback],  
     ISNULL((SELECT [LoginName] FROM [tbl_tp_UserLogin] WHERE Tpuser_id = [h].[AssignedBy]), '''') AS [FeedbackForAgent],               
     ISNULL(CAST([f].[submitdate] AS NVARCHAR), '''') AS [FeedbackDate],               
     ISNULL(CAST([f].[comments] AS NVARCHAR), '''') AS [FeedbackComments],  
  isnull(u.ShortUrl,'''') as feedbackurl  
     FROM tbl_tp_ticketmaster_',@parentid,' AS t(NOLOCK) JOIN tbl_tp_TicketStatusMaster(NOLOCK) AS s  
     ON s.TicketStatus_ID = t.TicketStatusID LEFT JOIN tbl_tp_TicketHistory AS h(NOLOCK)              
     ON t.ticketid = h.TicketID and t.parentid=h.parentid LEFT JOIN tbl_tp_TicketType_Master AS m(NOLOCK)  
     ON m.type_id = t.TicketTypeId LEFT JOIN tbl_tp_TicketRatingFeedback(NOLOCK) AS f              
     ON f.TICKETID = t.ticketid left join tbl_tp_TicketSourceMaster(nolock) sm   
     on t.TicketSourceId=sm.TicketSourceId LEFT JOIN tbl_tp_TicketPriorityMaster(NOLOCK) p   
     ON t.TicketPriority = p.Priority_ID LEFT JOIN Serv_Ticket_url_link(nolock) u   
     ON h.TicketHistoryID=u.TicketHistoryID and h.ParentID=u.ParentID
	 left join tbl_tp_UserLogin ttul on ttul.TpUser_Id=[t].[AssignedUser]
	 LEFT JOIN tbl_tp_TicketActivity_',@parentid,' (NOLOCK) AS ta              
     ON ta.TICKETID = t.ticketid
     WHERE 1 = CASE WHEN @reftables1 = ''tbl_tp_ticketmaster_',@parentid,''' AND CAST([h].[TicketHistoryID] AS NVARCHAR) = (SELECT MAX([tickethistoryid]) FROM [tbl_tp_TicketHistory] WHERE CAST([ticketid] AS NVARCHAR) = @refids1)              
        THEN 1              
       WHEN @reftables1 = ''tbl_tp_ticketmaster_',@parentid,'''              
        AND [h].[tickethistoryid] IS NULL              
        THEN 1              
       WHEN @reftables1 = ''tbl_tp_TicketRatingFeedback''              
        AND CAST([f].[TicketHistoryID] AS NVARCHAR) = @refids1              
        THEN 1              
       WHEN @reftables1 = ''tbl_tp_TicketHistory''              
        AND CAST([h].[TicketHistoryID] AS NVARCHAR) = @refids1              
        THEN 1              
       WHEN @reftables1 = ''tbl_tp_TicketRatingFeedback''              
        AND CAST([f].[RatingId] AS NVARCHAR) = @refids1              
        THEN 1              
	   	WHEN @reftables1 = ''tbl_tp_TicketActivity_',@parentid,'''                
        AND CAST([ta].[activityId] AS NVARCHAR) = @refids1              
        THEN 1  
       ELSE 0              
       END
	   order by case when  @reftables1 = ''tbl_tp_TicketActivity_',@parentid,'''   then ta.activityid else 0 end desc) AS a FOR JSON AUTO, INCLUDE_NULL_VALUES);')   
	   	   print concat('@reftables: ',@reftables,', @refids1: ',@refids)

	   print concat('strquery: ',@strquery)
    --select cast (@strQuery as nvarchar(max)) 
    Exec sp_executesql @strQuery,N'@reftables1 NVARCHAR(MAX), @refids1 NVARCHAR(MAX), @jsonactivity1 nvarchar(max) out',@reftables1=@reftables,@refids1=@refids,@jsonactivity1=@jsonactivity out  
    print @jsonactivity  
   END     
      
   if(@eventtype = 'AI Bot')
   begin
            
        IF(@reftables='tbl_ai_VisitorsLastResponse')
        Begin
            SET @jsonactivity = (Select * From (SELECT VLR.entityName, VLR.entityId, VLR.lastmessage_at, VLR.createdon, VLR.mode, VLR.direction, VLR.lastmessage, VLR.last_status_date, VLR.is_junk, VLR.IsOpen, VLR.IsGoalFulfilled, VLR.IsMilestoneAchieved, VLR.goalSlotJson, VLR.mileStoreJson as  MileStonejson, UL.LeadNo, UL.PersonName, UL.CompanyName, UL.MobileNo, UL.MobileNo1, UL.MobileNo2, UL.EmailID, UL.EmailID1, UL.EmailID2,  UL.CountryCode, UL.CountryCode1, UL.CountryCode2, UL.InitialRemarks, UL.NextStatusDate, UL.Remarks, UL.AmountPaid, UL.FollowupDate,  AG.Name as AgentName, AG.Email, AG.Role, AG.DetailsJson, AG.IsBot, UL.LastFollowupCreatedBy, isnull(dbo.fn_getentityfullname('user', ud.User_ID),'') as ActivityOwner, isnull(str(ud.mobile),'') as ActivityOwnerMobile,isnull(ud.email,'') as ActivityOwnerEmail
            FROM    tbl_ai_VisitorsLastResponse AS VLR WITH (nolock) LEFT OUTER JOIN UserLeads AS UL WITH (NOLOCK) 
            ON  VLR.entityName = 'lead' AND VLR.entityId = UL.ID LEFT OUTER JOIN tbl_ai_Agents AS AG WITH (nolock) 
            ON  VLR.agentId = AG.AgentId  left join User_Detail(nolock) ud 
            on  UL.AssignedTo = ud.User_ID
            Where VLR.id=@refids) AS a FOR JSON AUTO, INCLUDE_NULL_VALUES);

            declare @mileStoneJson nvarchar(max) = N'{}'
            select @mileStoneJson = mileStoreJson from tbl_ai_VisitorsLastResponse with (nolock) where id=@refids

            select @jsonactivity = json_modify(@jsonactivity, '$.' + [key], [value] )  from openjson(@mileStoneJson)

        End
            
        IF(@reftables='tbl_ai_Conversations')
        Begin
            SET @jsonactivity = (Select * From (SELECT CONV.Channel, CONV.Type, CONV.Direction, CONV.DetailsJson as ConvDetailsJson, CONV.CreatedOn, CONV.StartedAt, CONV.LastMessageAt, CONV.Metadata, CONV.EntityName, CONV.EntityId, UL.LeadNo, UL.PersonName, UL.CompanyName, UL.MobileNo, UL.MobileNo1, UL.MobileNo2, UL.EmailID, UL.EmailID1, UL.EmailID2,  UL.CountryCode, UL.CountryCode1, UL.CountryCode2, UL.InitialRemarks,  UL.NextStatusDate, UL.Remarks,  UL.AmountPaid, UL.FollowupDate, AG.AssistantId, AG.Name as AgentName, AG.Email, AG.Role, AG.DetailsJson, AG.IsBot, UL.LastFollowupCreatedBy, isnull(dbo.fn_getentityfullname('user', ud.User_ID),'') as ActivityOwner, isnull(str(ud.mobile),'') as ActivityOwnerMobile,isnull(ud.email,'') as ActivityOwnerEmail
            FROM    tbl_ai_Conversations AS CONV WITH (nolock) LEFT OUTER JOIN UserLeads AS UL WITH (NOLOCK) 
            ON      CONV.EntityName = 'lead' AND CONV.EntityId = UL.ID LEFT OUTER JOIN tbl_ai_Agents AS AG WITH (nolock) 
            ON      CONV.AgentId = AG.AgentId LEFT OUTER JOIN User_Detail AS ud WITH (nolock) 
            ON      UL.AssignedTo = ud.User_ID
            WHERE   CONV.ConversationId = @refids) AS a FOR JSON AUTO, INCLUDE_NULL_VALUES);
        End

        IF(@reftables = 'calllog')
        begin
            print 'fetching from calllogs'
            print concat('@refids => ', @refids)

            declare @callLogJson nvarchar(max), @botId bigint = 0

            set @callLogJson = ( select  Direction, Customernumber, customercountrycode, Agentnumber, agentcountrycode, Callstarttime, Callendtime, Agentpickuptime, Customerpickuptime, Calldurationseconds, Billdurationseconds, customerduration, agentduration, lastdtmf, agentmode, agentcalldisposition, customercalldisposition, o.OutcomeName, o.Indent as [Intent], remarks, customerentity, customerentityid, callcreatedby, callscheduledfor, callcreatedon, callname, dnid, recordurl, calling_agentid, bot_answer_time, human_handoff_time, human_handoff_trigger_id, last_updated from CallLog  c with (nolock) left join tbl_CallLogOutcomeMaster o with (nolock) on c.outcomeid = o.id
            WHERE c.id = @refids for json auto, without_array_wrapper)

             print concat('@callLogJson => ', @callLogJson)

            declare @callAdditionJson nvarchar(max), @callSummary nvarchar(max)
            select @callAdditionJson = additional_details, @callSummary = call_summary from call_summaries with (nolock) where calllog_id = @refids

            declare @goalSlotJson nvarchar(max) = '{}'

            print concat('@callAdditionJson => ', @callAdditionJson)

            select @goalSlotJson = DetailsJson from tbl_ai_GoalSlots with (nolock) where isnull(botType, '') = 'voicebot' 
                and GoalId  = (select top 1 bot_id from calllog with (nolock) where id = @refids)

            DECLARE @originalJson NVARCHAR(MAX) = @callLogJson, @turnNumbers int = 0;
            select @callLogJson = json_modify(@callLogJson, '$.' + [key], [value] )  from openjson(@goalSlotJson)

            select top 1 @turnNumbers = turn_number from voice_bot_conversation_turns with (nolock) where calllog_id = @refids order by turn_number desc
             print concat('@callAdditionJson => ', @callAdditionJson)

            select @callLogJson = json_modify(@callLogJson, '$.' + [key], [value] )  from openjson(@callAdditionJson)
            
            set @callLogJson = json_modify(@callLogJson, '$.call_summary', @callSummary)
            set @callLogJson = json_modify(@callLogJson, '$.turn_numbers', @turnNumbers)

            set @jsonactivity = @callLogJson
            print concat('@MergedJson => ', @jsonactivity)
             
        end


   end

  
   IF @eventid =9              
   BEGIN              
   print concat('eventid: ',@eventid,', refid: ',@refids,', reftable: ',@reftables)      
    SET @jsonactivity = (SELECT     *              
          FROM       (SELECT [t].[fieldname], isnull(dbo.fn_getentityfullname('user',ud.user_id),'') ModifiedBy,       
    [t].[CreatedOn] AS [ActivityObjectCreatedOn], isnull(str(ud.mobile),'') [ModifiedByPhone],isnull(ud.email,'') [ModifiedByEmail]      
    ,case when tablename='userleads' then 'Predefined' else 'Custom' end as Fieldtype      
             FROM   fieldupdated(NOLOCK) AS t JOIN  user_detail(nolock) ud on ud.user_id=t.createdby            
             WHERE  [t].[id] = @refids) AS a FOR JSON AUTO, INCLUDE_NULL_VALUES);              
    END;              
    
 if @eventid=28    
 begin    
 print 'Eventid: 28'    
 if @reftables='tbl_MergeLeadsEnquiry'    
 begin    
 select top 1 @refids=enquiryno from tbl_MergeLeadsEnquiry(nolock) where id=@refids    
 end    
 print concat('@refids: ',@refids)    
 SET @jsonactivity = (SELECT     *              
    FROM    (select EnquiryID,PersonName,CompanyName,isnull(v.CountryCode,'')+isnull(MobileNo,'')+isnull(', '+nullif(mobileno1,''),'')    
+isnull(', '+nullif(mobileno2,''),'') as Mobile,isnull(v.Emailid,'')+isnull(', '+nullif(EmailID1,''),'')+isnull(', '+nullif(EmailID2,''),'') as Email    
,v.City,v.State,v.Country,v.PinCode,v.ResidentialAddress,v.OfficeAddress,v.SourceName,v.MediumName,v.CampaignName,v.InitialRemarks,user_login CreatedBy from   [V_UserEnquiry] v join user_detail(nolock) u on v.createdby=u.user_id    
 where enquiryid=@refids) AS a FOR JSON AUTO, INCLUDE_NULL_VALUES);    
    print @jsonactivity    
 end    
      
              
   IF @eventtype IN('appointment', 'task')              
   BEGIN              
    --drop table if exists #activitydetails                                      
	if @reftables='tbl_tsk_TaskComments'
	begin
SET @jsonactivity = (SELECT     *              
          FROM       (SELECT [t].[Title], [u].[TasKName],c.remarks as CommentAdded,dbo.fn_getentityfullname('user',created_by) as CommentCreatedBy, [o].[OutcomeName], [t].[IsAppointment], [t].[Address], [t]              
          .[CompleteAddress], [t].[CompletedOn], [t].[CreatedOn] AS [ActivityObjectCreatedOn], [t].[Description],              
          [t].STATUS AS [ActivityObjectstatus], ISNULL(NULLIF([t].[StartDate], '1900-01-01 00:00:00.000'), [t].              
          [EndDate]) AS [ActivityObjectStartDate], CAST(CASE              
                       WHEN [t].[IsActive] = 0              
                        THEN 1              
                       ELSE 0              
  END AS BIT) AS [IsDeleted], ISNULL(CAST([task_deletedOn] AS              
                       NVARCHAR), '') AS [DeletedOn],isnull(dbo.fn_getentityfullname('user',ud.user_id),'') as ActivityOwner,            
        isnull(str(ud.mobile),'') as ActivityOwnerMobile,isnull(ud.email,'') as ActivityOwnerEmail,o.Indent as OutcomeIntent            
             --into #activitydetails                                      
             FROM   tbl_tsk_TaskHistory(NOLOCK) AS t 
			 JOIN tbl_tsk_UserTaskMaster(NOLOCK) AS u ON u.id = t.TaskId 
			 join tbl_tsk_TaskComments(nolock) as c on c.task_history_id=t.id
			 LEFT JOIN tbl_tsk_UserOutcomeMaster(NOLOCK) AS o ON t.OutcomesId = o.Id              
			inner join user_detail(nolock) ud on ud.user_id=t.assignedto            
             WHERE  [c].[id] = @refids) AS a FOR JSON AUTO, INCLUDE_NULL_VALUES);              

	end
	else
	begin
    SET @jsonactivity = (SELECT     *              
          FROM       (SELECT [t].[Title], [u].[TasKName], [o].[OutcomeName], [t].[IsAppointment], [t].[Address], [t]              
          .[CompleteAddress], [t].[CompletedOn], [t].[CreatedOn] AS [ActivityObjectCreatedOn], [t].[Description],              
          [t].STATUS AS [ActivityObjectstatus], ISNULL(NULLIF([t].[StartDate], '1900-01-01 00:00:00.000'), [t].              
          [EndDate]) AS [ActivityObjectStartDate], CAST(CASE              
                       WHEN [t].[IsActive] = 0              
                        THEN 1              
                       ELSE 0              
  END AS BIT) AS [IsDeleted], ISNULL(CAST([task_deletedOn] AS              
                       NVARCHAR), '') AS [DeletedOn],isnull(dbo.fn_getentityfullname('user',ud.user_id),'') as ActivityOwner,            
        isnull(str(ud.mobile),'') as ActivityOwnerMobile,isnull(ud.email,'') as ActivityOwnerEmail,o.Indent as OutcomeIntent            
             --into #activitydetails                                      
             FROM   tbl_tsk_TaskHistory(NOLOCK) AS t JOIN tbl_tsk_UserTaskMaster(NOLOCK) AS u              
             ON u.id = t.TaskId LEFT JOIN tbl_tsk_UserOutcomeMaster(NOLOCK) AS o              
             ON t.OutcomesId = o.Id              
    inner join user_detail(nolock) ud on ud.user_id=t.assignedto            
             WHERE  [t].[id] = @refids) AS a FOR JSON AUTO, INCLUDE_NULL_VALUES);              
     end

    --select @jsonactivity=(select   
--Title,TasKName,OutcomeName,IsAppointment,Address,CompleteAddress,CompletedOn,ActivityObjectCreatedOn,                                       
    --Description,ActivityObjectstatus,ActivityObjectStartDate from #activitydetails ) a for json auto , INCLUDE_NULL_VALUES)                                      
    --drop table #activitydetails                                      
   END;              
     
     
    if(@eventtype = 'Physical Appointment')
    begin
        SET @jsonactivity = (SELECT     *              
            FROM ( select 
	            pa.PhysicalAppointmentId, pa.Title, pa.Description, pa.Address, pa.StartDate, pa.EndDate, pa.CompleteAddress, 
	            pa.CreatedDate as [ActivityObjectCreatedOn], pa.Status as ActivityObjectstatus,
	            co.CheckIn, co.CheckOut, co.LatitudeIn, co.LongitudeIn, co.LatitudeOut, co.LongitudeOut,
	            om.OutcomeName, om.Indent, isnull(dbo.fn_getentityfullname('user', ud.User_ID),'') as ActivityOwner,
	            isnull(str(ud.mobile),'') as ActivityOwnerMobile,isnull(ud.email,'') as ActivityOwnerEmail
            from TBL_ET_PhysicalAppointment(nolock) pa 
	            left join TBL_ET_GeoEntityCheckInOut(nolock) co on pa.PhysicalAppointmentId = co.PhysicalAppointmentId
	            left join tbl_tsk_UserOutcomeMaster(nolock) om on pa.OutcomesId = om.Id
	            left join User_Detail(nolock) ud on pa.AssignedTo = ud.User_ID
            where pa.PhysicalAppointmentId = @refids) AS a FOR JSON AUTO, INCLUDE_NULL_VALUES);    

    end

   IF @eventtype = 'call'              
   BEGIN              
    DROP TABLE IF EXISTS #activitydetails;              
    SET @jsonactivity = (SELECT     *              
     FROM       (SELECT top 1 [k].[call_start_time] AS [ActivityObjectStartTime], [k].[callerid], [k].[dnid], [k].              
          [context], [k].[recordurl], [d].[dialstatus], ISNULL([a].[AppName], 'none') AS [AppNAme], [c].              
          [CampaignName], [dbo].[fn_getcallstatus](ISNULL([k].[uniqueid], 0)) AS [CallStatus], [dbo].              
          [lastagentattended](ISNULL([k].[uniqueid], 0)) AS [LastAgentDialed],isnull(k.call_last_dtmf,'') LastDTMFInput,    
k.[call_start_time] Activityobjectcreatedon,isnull(f.Dialstatus,'') CutomerCallStatus,    
    isnull(dbo.fn_getentityfullname('user',ud.user_id),'') as AgentName,            
        isnull(isnull(cloud_no,str(ud.mobile)),'') as AgentMobile,isnull(ud.email,'') as AgentEmail              
             --into #activitydetails                                      
             FROM   Kit19Calls AS k(NOLOCK) LEFT JOIN Kit19CallsDialled AS d(NOLOCK)              
             ON k.uniqueid = d.puniqueid LEFT JOIN Kit19Cloudvoicefinaltbl AS f(NOLOCK)              
             ON f.kit19uniqueid = k.uniqueid LEFT JOIN BatchVoiceInfo AS b(NOLOCK)              
             ON b.batchid = f.batchid LEFT JOIN usercampaignmaster AS c(NOLOCK)              
             ON c.id = b.Campaignid LEFT JOIN Cloud_app_master AS a(NOLOCK)              
       ON a.AppId = ISNULL(k.appid, b.Appid)         
        
    left join (select ud.*,cc.cloud_no,cc.cloud_countrycode from User_Detail ud (nolock) left join cloud_call_no cc(nolock) on cc.user_id=ud.user_id) ud
	on  dbo.fn_trim0prefix(d.agentnumber)=            
    case when d.agenttype='mobile' then isnull(cloud_no,str(ud.mobile)) else cast(ud.user_id as nvarchar(50)) end                  
             WHERE  @refids = CASE              
                  WHEN @reftables = 'Kit19callsdialled'              
                   THEN [d].[id]              
                  WHEN @reftables = 'Kit19calls'              
                   THEN [k].[id]              
         WHEN @reftables = 'Batchvoiceinfo'              
                   THEN [b].[BatchID]              
                  END   order by case when f.dialstatus='ANSWER' then 0 else 1 end) AS a FOR JSON AUTO, INCLUDE_NULL_VALUES);     
          
   END;      
     
   if @reftables like '%tbl_ims_schedule_message%'--eventid=144  
   begin  
   set @strQuery =   
Concat(' SET @jsonactivity1 = (SELECT * FROM               
    (SELECT ''Whatsapp'' [Channelname],              
              CASE              
              WHEN [c].[messagetype] = ''text''              
               THEN [c].[bodytext]              
              WHEN [c].[messagetype] = ''template''              
    THEN [t].[templatebody]              
              ELSE [c].[messagetype]              
              END AS [bodytext],              
                  CASE              
                  WHEN [c].[messagetype] = ''text''              
                   THEN LEFT([c].[bodytext], 15)              
                  WHEN [c].[messagetype] = ''template''             
                   THEN LEFT([t].[templatebody], 15)              
                  ELSE [c].[messagetype]              
    END AS [subbodytext], [c].[templateid], [t].[templatename],   
 [c].[messagetype],   
      [i].[createddate] AS              
                  [ActivityObjectCreatedOn]              
            FROM   tbl_conversations_',@parentid,'(NOLOCK) AS c   
   LEFT JOIN convtemplates(NOLOCK) AS t              
            ON t.id = c.templateid    
   left join tbl_ims_schedule_message(nolock) as i   
   on i.wa_message_id=c.messageid  
            WHERE ',@refids,             
            ' = CASE              
               WHEN ''',@reftables,''' LIKE ''%tbl_ims_schedule_message%''   
     then i.id  
                ELSE [c].[id]              
                END) AS a FOR JSON AUTO, INCLUDE_NULL_VALUES);')      
      
  
    print @strQuery  
    Exec sp_executesql @strQuery,N'@reftables1 NVARCHAR(MAX), @refids1 NVARCHAR(MAX), @jsonactivity1 nvarchar(max) out',@reftables1=@reftables,@refids1=@refids,@jsonactivity1=@jsonactivity out  
   end  
              
   IF @eventtype = 'chat' AND @eventid IN(127, 128)              
   BEGIN              
    /*SET @jsonactivity = (SELECT     *              
          FROM       (SELECT [h].[Channelname], [v].[channelprofileid], [v].[createdon] AS [ActivityObjectCreatedOn],              
          [isdeactivatedon] AS [deletedon], CAST(CASE              
                   WHEN [v].[isactive] = 0              
                    THEN 0              
                   ELSE 1              
                   END AS BIT) AS [IsActive]              
             --into #activitydetails                                      
             FROM   mysmsconversations.dbo.convusers AS v(NOLOCK) JOIN mysmsconversations.dbo.channels AS h              
             (NOLOCK)              
             ON h.id = v.Channelid              
             WHERE  [v].[id] = @refids) AS a FOR JSON AUTO, INCLUDE_NULL_VALUES);   */ 
			 SET @query = '
    SELECT 
        [h].[Channelname], 
        [v].[channelprofileid], 
        [v].[createdon] AS [ActivityObjectCreatedOn], 
        [isdeactivatedon] AS [deletedon], 
        CAST(CASE 
                WHEN [v].[isactive] = 0 THEN 0 
                ELSE 1 
             END AS BIT) AS [IsActive]
    FROM 
        convusers AS v (NOLOCK)
    JOIN 
        channels AS h (NOLOCK) 
        ON h.id = v.Channelid
    WHERE 
        [v].[id] = ' + CAST(@refids AS NVARCHAR) + '
 FOR JSON AUTO, INCLUDE_NULL_VALUES;';
 EXEC usp_clr_GetRemoteStringValue @query, @retval=@jsonactivity out;

   END;              
              
   IF @eventtype = 'chat' AND @eventid IN(99, 101,144)             
   BEGIN              
   /* SET @jsonactivity = (SELECT *              
          FROM   (SELECT [h].[Channelname],              
              CASE              
              WHEN [c].[messagetype] = 'text'              
               THEN [c].[bodytext]              
              WHEN [c].[messagetype] = 'template'              
    THEN [t].[templatebody]              
              ELSE [c].[messagetype]              
              END AS [bodytext],              
                  CASE              
                  WHEN [c].[messagetype] = 'text'              
                   THEN LEFT([c].[bodytext], 15)              
                  WHEN [c].[messagetype] = 'template'              
                   THEN LEFT([t].[templatebody], 15)              
                  ELSE [c].[messagetype]              
    END AS [subbodytext], [c].[templateid], [t].[templatename], [p].              
                  [conversationtype], [c].[messagetype], [p].[createdon] AS              
                  [ActivityObjectCreatedOn]              
            --into #activitydetails                                      
            FROM   mysmsconversations.dbo.conversations(NOLOCK) AS c JOIN mysmsconversations.dbo.convparentid(              
            NOLOCK) AS p              
            ON p.id = c.parentconvid JOIN mysmsconversations.dbo.convusers AS v(NOLOCK)              
            ON v.id = c.senderid JOIN mysmsconversations.dbo.channels AS h(NOLOCK)              
            ON h.id = v.Channelid              
            --left join mysmsconversations.dbo.webhooks w (nolock) on w.id=c.webhookid                                       
            LEFT JOIN MySMSConversations.dbo.convtemplates(NOLOCK) AS t              
            ON t.id = c.templateid              
            WHERE              
            --c.id=(select min(id) from mysmsconversations.dbo.conversations(nolock) where parentconvid=c.parentconvid)                   
            --and                                       
            @refids = CASE              
                WHEN @reftables LIKE '%convuser%'              
                 THEN [p].[id]              
                ELSE [c].[id]              
                END) AS a FOR JSON AUTO, INCLUDE_NULL_VALUES);     */  

		declare @retval nvarchar(max)
		SET @query = 'set @retval = (
			SELECT * FROM (
				SELECT 
					h.Channelname,
					CASE 
						WHEN c.messagetype = ''text'' THEN c.bodytext
						WHEN c.messagetype = ''template'' THEN t.templatebody
						ELSE c.messagetype
					END AS bodytext,
					CASE 
						WHEN c.messagetype = ''text'' THEN LEFT(c.bodytext, 15)
						WHEN c.messagetype = ''template'' THEN LEFT(t.templatebody, 15)
						ELSE c.messagetype
					END AS subbodytext,
					c.templateid,
					t.templatename,
					p.conversationtype,
					c.messagetype,
					p.createdon AS ActivityObjectCreatedOn
				FROM [10.0.0.135].MySMSConversations.dbo.tbl_conversations_'+ cast(@parentid as nvarchar) +' as c with (NOLOCK)
				JOIN [10.0.0.135].MySMSConversations.dbo.convparentid as p with (NOLOCK) ON p.id = c.parentconvid
				JOIN [10.0.0.135].MySMSConversations.dbo.convusers as v with (NOLOCK)  ON v.id = c.senderid
				JOIN [10.0.0.135].MySMSConversations.dbo.channels as h with (NOLOCK)  ON h.id = v.Channelid
				LEFT JOIN  [10.0.0.135].MySMSConversations.dbo.convtemplates as t with (NOLOCK) ON t.id = c.templateid
				WHERE ' + QUOTENAME(@refids, '''') + ' = 
					CASE 
						WHEN ' + QUOTENAME(@reftables, '''') + ' LIKE ''%convuser%'' THEN CAST(p.id AS NVARCHAR)
						ELSE CAST(c.id AS NVARCHAR)
					END
			) AS a FOR JSON AUTO, INCLUDE_NULL_VALUES)
		';


		print @query

		EXEC sp_executesql @query, N'@retval NVARCHAR(MAX) OUTPUT', @retval = @jsonactivity OUTPUT;

 --EXEC usp_clr_GetRemoteStringValue @query, @retval=@jsonactivity out;

   END;              
              
   IF @eventtype = 'chat' AND @eventid IN(102)              
   BEGIN              
    /*SET @jsonactivity = (SELECT     *              
          FROM       (SELECT TOP 1 CASE              
                 WHEN [c].[messagetype] = 'text'              
                  THEN [c].[bodytext]              
                 ELSE [c].[messagetype]              
                 END AS [bodytext],              
                  CASE              
                  WHEN [c].[messagetype] = 'text'              
                   THEN LEFT([c].[bodytext], 15)              
                  ELSE [c].[messagetype]              
                  END AS [subbodytext], [c].[messagetype], [p].[createdon] AS              
                  [ActivityObjectCreatedOn]              
     FROM         mysmsconversations.dbo.conversations(NOLOCK) AS c JOIN mysmsconversations.dbo.              
             conversationstatus(NOLOCK) AS p              
             ON p.messageid = c.messageid              
             WHERE        [p].[id] = @refids) AS a FOR JSON AUTO, INCLUDE_NULL_VALUES);      */    
		

SET @query = '
    SELECT * 
    FROM (
        SELECT TOP 1 
            CASE 
                WHEN [c].[messagetype] = ''text'' 
                THEN [c].[bodytext] 
                ELSE [c].[messagetype] 
            END AS [bodytext],
            CASE 
                WHEN [c].[messagetype] = ''text'' 
                THEN LEFT([c].[bodytext], 15) 
                ELSE [c].[messagetype] 
            END AS [subbodytext],
            [c].[messagetype], 
            [p].[createdon] AS [ActivityObjectCreatedOn]
        FROM conversations (NOLOCK) AS c
        JOIN conversationstatus (NOLOCK) AS p
            ON p.messageid = c.messageid
        WHERE [p].[id] = ' + CAST(@refids AS NVARCHAR) + '
    ) AS a
    FOR JSON AUTO, INCLUDE_NULL_VALUES
';

 EXEC usp_clr_GetRemoteStringValue @query, @retval=@jsonactivity out;

   END;              
              
   IF @eventtype = 'deal'              
   BEGIN              
    SET @jsonactivity = (SELECT     *              
          FROM       (SELECT [p].[name] AS [PipelineName], [s].[name] AS [StageName], [l].[CreatedDate] AS              
          [ActivityObjectCreatedOn], [l].[Amount], [l].[Probability], [l].[DeletedOn], [l].[EstimatedClosureDate],              
          [l].[Remarks], [dbo].[fn_getleadpipelineexpirydate]([l].[LeadID], [p].[id]) AS [ExpiringOn],          
    [u].user_login as DealOwner,left(l.remarks,30) as SubRemarks          
             --into #activitydetails                                      
             FROM   LeadPipelineMapping AS l(NOLOCK) JOIN Pipeline_Master AS p(NOLOCK)              
             ON p.ID = l.PipelineID           
    JOIN PipelineStages AS s(NOLOCK)              
             ON s.id = l.PipeLineStage              
    join user_detail as u(nolock) on u.user_id=l.dealowner          
             WHERE  [l].[id] = @refids) AS a FOR JSON AUTO, INCLUDE_NULL_VALUES);              
   END;              
              
   IF @eventtype = 'documents'              
   BEGIN              
    SET @jsonactivity = (SELECT     *              
          FROM       (SELECT [t].[DocumentName], [t].[FileLocation], [t].[FileType], [t].[DeletedDate], [t].              
          [UploadedDate] AS [ActivityObjectCreatedOn]              
             --into #activitydetails                                      
             FROM   tbl_LeadDocumentUpload(NOLOCK) AS t              
             WHERE  [t].[DocUpID] = @refids) AS a FOR JSON AUTO, INCLUDE_NULL_VALUES);              
   END;              
             
   IF @eventtype = 'notes'              
   BEGIN              
    SET @jsonactivity = (SELECT     *              
          FROM       (SELECT [t].[Notes], SUBSTRING([t].[notes], 1, 30) + '...' AS [NotesSubText], [t].[CreatedDate]              
          AS [ActivityObjectCReatedOn], [t].[DeletedDate]              
             --into #activitydetails                                      
             FROM   tbl_LeadNotes(NOLOCK) AS t              
             WHERE  [t].[NoteID] = @refids) AS a FOR JSON AUTO, INCLUDE_NULL_VALUES);              
   END;              
              
   IF @eventtype = 'webform'              
   BEGIN              
    SET @jsonactivity = (SELECT     *              
          FROM       (SELECT [w].[formname], replace([dynimicattr], ';', ',') AS [WebFormData], [w].[EntryDate] AS              
          [ActivityObjectCreatedOn]              
             --into #activitydetails                                      
             FROM   WebEntryTbl(NOLOCK) AS w              
             WHERE  [w].[EntryId] = @refids) AS a FOR JSON AUTO, INCLUDE_NULL_VALUES);              
   END;              
              
   IF @eventtype = 'landingPage'              
   BEGIN              
    SET @jsonactivity = (SELECT     *              
          FROM       (SELECT 'kit19.com/' + [w].[cname] AS [PageName], [w].[FirstName], [w].[LastName], [w].              
          [Address], [w].[City], CAST([w].[CountryCode] AS NVARCHAR) + [w].[Mobile] AS [MobileProvided], [w].[Email]              
          AS [EmailProvided], [w].[DateCreated] AS [ActivityObjectCreatedOn]              
             --into #activitydetails                                      
             FROM   clientleaddetails(NOLOCK) AS w              
             WHERE  [w].[Id] = @refids) AS a FOR JSON AUTO, INCLUDE_NULL_VALUES);              
   END;              
              
   IF @eventtype = 'sms'              
   BEGIN              
    IF @reftables = 'batchinfo'              
    BEGIN              
     SET @jsonactivity = (SELECT     *              
           FROM       (SELECT [b].[BatchInsertTime] AS [ActivityObjectCreatedOn], [b].[bmessage] AS [MessageText],              
           SUBSTRING([b].[bmessage], 1, 30) + '...' AS [MessageSubText], [u].[CampaignName], [u].[eventid], [u].              
           [IsEventBased]              
              --into #activitydetails                          
              FROM   batchinfo(NOLOCK) AS b LEFT JOIN UserCampaignExecutionHistory(NOLOCK) AS c              
              ON c.BatchID = b.BatchID LEFT JOIN usercampaignmaster(NOLOCK) AS u              
              ON u.id = c.CampaignID              
              WHERE  [b].[batchid] = @refids) AS a FOR JSON AUTO, INCLUDE_NULL_VALUES);              
    END;              
    IF @reftables = 'link_smstrack'              
    BEGIN              
     SET @jsonactivity = (SELECT     *              
           FROM       (SELECT [m].[Mobile] AS [ActivityMobile], [l].[ipAddress], [l].[Long_Url], [l].[VisitDate]              
           AS [ActivityObjectCreatedOn], [b].[bmessage] AS [MessageText], CAST(ISNULL(NULLIF([b].[ScheduledDate],              
           ''), [b].[BatchInsertTime]) AS DATE) AS [DateSMSSent], [u].[CampaignName], [u].[eventid], [u].              
           [IsEventBased]              
              --into #activitydetails                                      
              FROM   link_smstrack(NOLOCK) AS l JOIN Link_smsMobile(NOLOCK) AS m              
              ON l.link_id = m.mobile_url_id JOIN batchinfo(NOLOCK) AS b              
              ON b.BatchID = m.batchid LEFT JOIN UserCampaignExecutionHistory(NOLOCK) AS c              
              ON c.BatchID = b.BatchID LEFT JOIN usercampaignmaster(NOLOCK) AS u              
              ON u.id = c.CampaignID              
              WHERE  [l].[trackid] = @refids) AS a FOR JSON AUTO, INCLUDE_NULL_VALUES);              
    END;              
   END;              
              
   IF @eventtype = 'lifecycle'  and @eventid not in (9,28)            
   BEGIN              
    IF @eventid = 36              
    BEGIN              
     SET @jsonactivity = (SELECT     *              
           FROM       (SELECT [eventdescription] AS [ActivityMessage]              
              FROM   tbl_leadeventhistory(NOLOCK)              
              WHERE  [historyid] = @activityid) AS a FOR JSON AUTO, INCLUDE_NULL_VALUES);              
    END;              
    IF @eventid NOT IN(36, 9)              
    BEGIN              
     IF @eventid = 95              
     BEGIN              
      SET @jsonactivity = (SELECT     *              
        FROM       (SELECT [leadcnt] AS [LeadsImported], [importdate] AS [ActivityObjectCreatedOn],              
            [remarks] AS [ImportProcessedDetails]              
               FROM   tbl_LeadImportSummary(NOLOCK)              
               WHERE  [ImportRow_Id] = @refids) AS a FOR JSON AUTO, INCLUDE_NULL_VALUES);              
     END              
      --lead added, added from enquiry, lead merged from enquiry/lead,lead edited,leads imported,followup added,new interest through enquiry                        ;              
     ELSE              
     BEGIN              
      IF @eventid IN(37, 17, 10, 97, 153)              
      BEGIN              
       DECLARE @productids NVARCHAR(MAX)= '', @products NVARCHAR(MAX),@sqlq1 nvarchar(max);              
                   
    if @reftables = 'LeadInteractionHistory'          
    begin          
    select * into #LeadInteractionHistory from LeadInteractionHistory (nolock) where id=@refids          
   SELECT @productids = [leh].[products]              
                FROM #LeadInteractionHistory leh          
                 
    IF ISNULL(@productids, '') <> ''              
       BEGIN              
    set @sqlq1='SELECT @products1 = COALESCE(@products1+ '','', '''') + [p].name              
        FROM   dbo.fn_split('''+@productids+''', ''#'') AS f CROSS APPLY tbl_productmaster_'+cast(@parentid as nvarchar)          
  +' AS p(NOLOCK)              
        WHERE  [productid] = [f].value';            
  print @sqlq1          
  execute sp_executesql @sqlq1, N'@products1 nvarchar(max) output',@products1=@products output          
      END;           
          
    SET @jsonactivity = (SELECT     *              
             FROM       (SELECT [f].[FollowupStatus] AS [ActivityFollowupStatus], [leh].[remarks] AS              
             [ActivityRemarks], [leh].[AmountPaid] AS [ActivityAmountPaid], ISNULL(@products, '') AS              
      [ActivityProducts], [leh].[CreatedOn] AS [ActivityObjectCreatedOn],     
   case when iscallback=1 then ISNULL(CAST([leh].[FollowupDate] AS NVARCHAR), '') else null end AS [FollowupDueOn],    
   f.intent As FollowupIntent,cast(case when f.IsCallback=1 then 1 else 0 end as int) as IsCallBack,    
   cast(case when f.IsConvert=1 then 1 else 0 end as int) IsConversion,    
      case when isconvert=1 then ISNULL(CAST([leh].[FollowupDate] AS NVARCHAR), '') else null end AS [ConversionDate]    
       --into #activitydetails                                      
                FROM   #LeadInteractionHistory AS leh(NOLOCK)           
    LEFT JOIN FollowUp_Status AS f (nolock)             
                ON f.id = leh.FollowUpStatus              
                ) AS a FOR JSON AUTO, INCLUDE_NULL_VALUES);           
  drop table if exists #LeadInteractionHistory            
     end          
  else          
  begin          
    select * into #userleads from userleads (nolock) where id=@refids          
          
    SELECT @productids = [u].[products]              
                FROM #userleads u          
          
    IF ISNULL(@productids, '') <> ''              
       BEGIN              
    set @sqlq1='SELECT @products1 = COALESCE(@products1+ '','', '''') + [p].name              
        FROM   dbo.fn_split('''+@productids+''', ''#'') AS f CROSS APPLY tbl_productmaster_'+cast(@parentid as nvarchar)          
  +' AS p(NOLOCK)              
        WHERE  [productid] = [f].value';            
  print @sqlq1          
  execute sp_executesql @sqlq1, N'@products1 nvarchar(max) output',@products1=@products output          
      END;           
    SET @jsonactivity = (SELECT     *              
             FROM       (SELECT [f].[FollowupStatus] AS [ActivityFollowupStatus], [u].[remarks] AS              
             [ActivityRemarks], [u].[AmountPaid] AS [ActivityAmountPaid], ISNULL(@products, '') AS              
             [ActivityProducts], [u].[CreatedOn] AS [ActivityObjectCreatedOn], ISNULL(CAST([u].              
             [FollowupDate] AS NVARCHAR), '') AS [FollowupDueOn]              
                --into #activitydetails                                      
                FROM   #userleads(NOLOCK) AS u              
                LEFT JOIN FollowUp_Status AS f (nolock)             
                ON f.id = u.FollowUpStatus              
                ) AS a FOR JSON AUTO, INCLUDE_NULL_VALUES);           
         drop table if exists #userleads          
  end          
      ENd;              
      ELSE              
      BEGIN              
       IF @eventid IN(38, 39)              
       BEGIN              
        SET @jsonactivity = (SELECT                                      *              
              FROM                                        (SELECT [u].[searchname] AS [GroupName]              
                          --into #activitydetails                                      
                          FROM usersearchlist AS u(NOLOCK) WHERE [ID] =              
                          @refids) AS a FOR JSON AUTO,              
                          INCLUDE_NULL_VALUES);              
       END;              
       ELSE              
       BEGIN              
        IF @eventid IN(18, 19, 28, 148)              
        BEGIN              
         IF @reftables = 'tbl_MergeLeadsEnquiry'              
         BEGIN              
          SET @jsonactivity = (SELECT     *              
                FROM       (SELECT 'Enquiry' AS [activityentityname], [EnquiryNo] AS              
                [activityentitymerged]              
                   --into #activitydetails                                      
                   FROM   tbl_MergeLeadsEnquiry(NOLOCK) AS t              
                   WHERE  [id] = @refids) AS a FOR JSON AUTO, INCLUDE_NULL_VALUES);              
         END;              
         ELSE              
         BEGIN              
          IF @reftables = 'tbl_MergeLeads'              
 BEGIN              
           SET @jsonactivity = (SELECT     *              
                 FROM       (SELECT 'Lead' AS [activityentityname], [LeadIDMergedFrom] AS              
                 [activityentitymerged]              
                    --into #activitydetails                                      
                    FROM   tbl_MergeLeads(NOLOCK) AS t              
                    WHERE  [id] = @refids) AS a FOR JSON AUTO, INCLUDE_NULL_VALUES);              
          END;              
         END;              
        END;              
       END;              
      END;              
   END;              
    END;              
   END;              
              
   IF @eventtype = 'email'              
   BEGIN              
    IF @eventid IN(57, 58)              
    BEGIN              
     SET @jsonactivity = (SELECT     *              
           FROM       (SELECT [MailSubject], [FromAddr], [createdtime] AS [Activityobjectcreatedon], LEFT(              
           [mailsubject], 15) AS [SubMailSubject]              
              --into #activitydetails                                      
              FROM   Mysmst.dbo.tbl_email(NOLOCK)              
              WHERE  [id] = @refids) AS a FOR JSON AUTO, INCLUDE_NULL_VALUES);              
    END;              
    ELSE              
    BEGIN              
     IF @eventid = 4              
     BEGIN              
      SET @jsonactivity = (SELECT     *              
            FROM       (SELECT [OpenCount], [FirstOpened], [LastOpened], [CreatedOn] AS              
            [ActivityObjectCreatedOn]              
               --into #activitydetails                                      
               FROM   Mysmst.dbo.Tbl_EmailTracking(NOLOCK)              
               WHERE  [id] = @refids) AS a FOR JSON AUTO, INCLUDE_NULL_VALUES);              
     END;              
     ELSE              
     BEGIN              
      IF @eventid = 40              
      BEGIN              
       SET @jsonactivity = (SELECT     *              
             FROM       (SELECT [Emails] AS [ActivityThroughEmail], [createdon] AS              
             [ActivityObjectCreatedOn], [email_subject] AS [MailSubject], LEFT([email_subject], 15) AS              
             [SubMailSubject]              
                --into #activitydetails                                      
     FROM   tbl_subscription(NOLOCK) AS t LEFT JOIN BatchEmail_Infos(NOLOCK) AS b              
                ON b.batchid = t.batchid              
                WHERE  [t].[id] = @refids) AS a FOR JSON AUTO, INCLUDE_NULL_VALUES);              
      END;              
      ELSE              
      BEGIN              
       IF @eventid = 3              
       BEGIN              
        IF @reftables = 'Batchemail_infos'              
        BEGIN              
         SET @jsonactivity = (SELECT     *              
               FROM       (SELECT [email_subject] AS [MailSubject], [SenderName] AS [FromAddr],              
               [batchinsertTime] AS [Activityobjectcreatedon], LEFT([email_subject], 15) AS              
               [SubMailSubject]              
                  --into #activitydetails                                      
                  FROM   Batchemail_infos(NOLOCK)              
                  WHERE  [BatchID] = @refids) AS a FOR JSON AUTO, INCLUDE_NULL_VALUES);              
        END;              
       END;              
       ELSE              
       BEGIN              
        IF @eventid = 5              
           AND @reftables = 'EngagementEventOpenClick'              
        BEGIN              
         --SET @jsonactivity = (SELECT     *              
         --      FROM  (SELECT [destination_url] AS [MailLinkVisited], [CreatedOn] AS              
         --      [ActivityObjectCreatedOn], [b].[Email_Subject] AS [MailSubject], LEFT([b].              
         --      [email_subject], 15) AS [SubMailSubject]              
         --         --into #activitydetails                                      
         --         FROM   EngagementEventOpenClick(NOLOCK) AS e JOIN BatchEmail_Infos AS b(              
         --         NOLOCK)              
         --         ON e.BatchID = b.BatchID              
         --         WHERE  [e].[ID] = @refids) AS a FOR JSON AUTO, INCLUDE_NULL_VALUES);          
		 SET @jsonactivity = (
    SELECT 
        '[{' + STRING_AGG(
            '"MailLinkVisited": ' + ISNULL('"' + destination_url + '"', 'null') + ',' +
            '"ActivityObjectCreatedOn": ' + ISNULL('"' + CONVERT(VARCHAR, CreatedOn, 126) + '"', 'null') + ',' +
            '"MailSubject": ' + ISNULL('"' + Email_Subject + '"', 'null') + ',' +
            '"SubMailSubject": ' + ISNULL('"' + LEFT(email_subject, 15) + '"', 'null'),
            '}'
        ) + '}]'
    FROM (
        SELECT 
            [destination_url], 
            [CreatedOn], 
            [b].[Email_Subject]
        FROM EngagementEventOpenClick AS e
        JOIN BatchEmail_Infos AS b
            ON e.BatchID = b.BatchID
        WHERE [e].[ID] = @refids
    ) AS a
);
        END;              
        ELSE              
        BEGIN              
         IF @reftables = 'MySMST.dbo.Tbl_Email'              
         BEGIN              
          SET @jsonactivity = (SELECT     *              
                FROM       (SELECT [MailSubject], [FromAddr], [CreatedTime] AS              
                [Activityobjectcreatedon], LEFT([mailsubject], 15) AS [SubMailSubject]              
                   --into #activitydetails                                      
                   FROM   MySMST.dbo.Tbl_Email(NOLOCK)              
                   WHERE  [ID] = @refids) AS a FOR JSON AUTO, INCLUDE_NULL_VALUES);              
         END;              
        END;              
       END;              
      END;              
     END;              
    END;              
   END;              
              
   IF @eventtype = 'Quotation'              
   BEGIN              
    SET @jsonactivity = (SELECT              
    *              
          FROM              
          (SELECT                                                   [quote_number] AS [QuotationNumber], [h].STATUS,              
          [quoted_at] AS [QuotationDate], [due_at] AS [QuotationValidity], [Billperiodfrom], [Billperiodto], CAST(              
          [amount] AS DECIMAL(18, 2)) AS [QuotationAmount], [contact_name] AS [BillingContactName], [contact_email]              
          AS [BillingContactEmail], [contact_tax_number] AS [BillingTaxNumber], [contact_phone] AS              
          [BillingContactPhone], [contact_address] AS [BillingAddress], [mysms].[dbo].[fn_getlocation](              
          [BillToCountryId], 'Country') AS [BillingCountry], [mysms].[dbo].[fn_getlocation]([BillToStateId], 'State')              
          AS [BillingState], [mysms].[dbo].[fn_getlocation]([BillToCityId], 'City') AS [BllingCity], [Billtopincode]              
          AS [BillingPincode], [ShipToName] AS [ShippingContactName], [ShipToEmailId] AS [ShippingContactEmail],              
          [ShipToPhone] AS [ShippingContactPhone], [ShipToAddress] AS [ShippingAddress], [mysms].[dbo].              
          [fn_getlocation]([ShipToCountryId], 'Country') AS [ShippingCountry], [mysms].[dbo].[fn_getlocation](              
          [ShipToStateId], 'State') AS [ShippingState], [mysms].[dbo].[fn_getlocation]([ShipToCityId], 'City') AS              
          [ShippingCity], [ShipToPincode] AS [ShippingPincode], [mysms].[dbo].[fn_getuserlogins]([SalesOwner]) AS              
          [SalesOwner], [notes] AS [Notes], [footer] AS [FooterRemarks], [h].[created_at] AS              
          [ActivityObjectCreatedOn], [q].[updated_at] AS [QuotationLastModifiedOn], [q].[deleted_at] AS              
          [QuotationDeletedDate], [company_name] AS [BillerCompany], [company_email] AS [BillerEmail],              
          [company_tax_number] AS [BillerTaxNumber], [company_phone] AS [BillerPhone], [company_address] AS              
          [BillerAddress], [mysms].[dbo].[fn_getlocation]([CompanyCountryId], 'Country') AS [BillerCountry], [mysms]              
          .[dbo].[fn_getlocation]([CompanyStateId], 'State') AS [BillerState], [mysms].[dbo].[fn_getlocation](              
          [CompanyCityId], 'City') AS [BillerCity], [CompanyPincode] AS [BillerPincode], [CompanyOriginname] AS              
          [PlaceOfOrigin], [CompanySupplyname] AS [PlaceOfSupply], [CompanyTermCondition] AS [QuotationTerms],              
          [company_logo] AS [BillerLogo], [title] AS [QuotationTitle], [sub_heading] AS [QuotationSubject],              
          [sub_total] AS [ItemsAmountBeforeTaxAndDiscount], [mysms].[dbo].[fn_getuserlogins]([h].[createdby]) AS              
          [CreatedBy], ISNULL([invoice_number], '') AS [InvoiceNumber], [q].[created_at] AS [QuotationCreatedDate],              
          [mysms].[dbo].[fn_getuserlogins]([q].[createdby]) AS [QuotationCreatedBy], ISNULL((SELECT     *              
                              FROM              (              
                              SELECT [qc].[name] AS [Chargename],              
                              [amount] AS [Charges],              
                              [a].[name] AS [Chargeaccountname]              
                              FROM   [mysmsinvoicing]              
                              .[dbo].[quote_other_charges] AS [qc](NOLOCK)              
                              LEFT JOIN [mysmsinvoicing].[dbo].[accounts] AS [a](NOLOCK)              
                              ON [qc].[account_id] =              
                              [a].[id]              
                              WHERE  [qc].[quote_id]              
                              = [q].[id]) AS [a] FOR              
             JSON AUTO,       
                              INCLUDE_NULL_VALUES),              
                              '0') AS              
                              [OtherChargesJson], (              
                              SELECT                                                                 *              
                              FROM              
                              (SELECT                                                             [name] AS [Itemname],              
                              ISNULL([sku], '') AS              
                              [SKU], CAST([Quantity]              
                              AS DECIMAL(18, 2)) AS              
                              [Quantity], CAST(              
                              [Price] AS DECIMAL(18,              
                              2)) AS [Price],              
                              [description] AS [ItemDescription],              
                              ISNULL((SELECT     *              
                                FROM              
                                (SELECT [name] AS [TaxName],              
                                CAST([Rate] AS NVARCHAR)              
                                + '%' AS [TaxRate],              
                                [amount] AS [TaxAmount]              
                                 FROM              
                                 [mysmsinvoicing].[dbo].[quote_item_taxes](NOLOCK)              
                      AS [i]              
                                 WHERE              
                                 [tax_id] <> 0              
                                 AND [i].              
                                 [quote_item_id] = [qi].[id])              
                                AS [a] FOR JSON AUTO,              
                                INCLUDE_NULL_VALUES),              
                                '0') AS [Taxes],              
                                ISNULL((SELECT     *              
                                  FROM              
                                  (SELECT [name] AS [Discountname],              
                                        CASE              
                         WHEN              
                                        [i].[type] = 'V'              
                                         THEN              
                                         'Value'              
                                        ELSE              
                                        'Percent'              
                                        END              
                                        AS [DiscountType],              
                                        [amount] AS [DiscountAmount]              
                                   FROM              
                                   [mysmsinvoicing].[dbo].[quote_item_taxes](NOLOCK)              
                                   AS [i]              
                                   WHERE              
                                   [tax_id] = 0              
                                   AND              
                                   [i].[quote_item_id] = [qi].[id])              
                                  AS [a] FOR JSON AUTO,              
                                  INCLUDE_NULL_VALUES),              
                                  '0') AS              
                                  [Discounts]              
                               FROM [mysmsinvoicing].              
                               [dbo].[quote_items](NOLOCK)              
                               AS [qi]              
                               WHERE [quote_id] = [q]              
                               .[id]) AS [a] FOR JSON              
                               AUTO,              
                               INCLUDE_NULL_VALUES)              
                               AS [ItemsJson]              
           FROM mysmsinvoicing.dbo.quote_histories(NOLOCK) AS h JOIN mysmsinvoicing.dbo.quotes AS q(NOLOCK)              
           ON h.quote_id = q.id LEFT JOIN(SELECT [id], [invoice_number] FROM mysmsinvoicing.dbo.invoices(NOLOCK)) AS              
           i              
           ON i.id = q.invoice_id              
           WHERE 1 = CASE              
            WHEN @reftables = 'mysmsinvoicing.dbo.quotes'              
              AND CAST([q].[id] AS NVARCHAR) = @refids              
           THEN 1              
            WHEN @reftables = 'mysmsinvoicing.dbo.quote_histories'              
              AND CAST([h].[id] AS NVARCHAR) = @refids              
             THEN 1              
            ELSE 0              
            END) AS a FOR JSON AUTO, INCLUDE_NULL_VALUES);              
   END;              
              
   IF @eventtype = 'eshop'              
   BEGIN              
    IF @eventid IN(20,21,22,23,59,60,61,62,63,64,65,66,67,68,69,70,71,72,75,76)              
    BEGIN              
     select OrderNo=isnull(O.OrderNo,''),CreatedOn=case @reftables when 'Order' then O.OrderDate when 'tbl_es_ProcessLoyaltyTransaction' then PLT.CreatedOn when 'Order_Fulfillment' then FF.FulfillmentDate end,            
  Event=isnull(case @reftables when 'Order' then 'OrderCreated' when 'tbl_es_ProcessLoyaltyTransaction' then RM.ActivityType when 'Order_Fulfillment' then FF.FulfillmentStatus end,''),            
  O.CustomerName,fulfillmentdetails=isnull(O.fulfillmentdetails,''),Points=isnull(RM.Points,0),PointsBalance=isnull(RM.PointsBalance,0),Description=isnull(RM.description,''),            
  TxStatus=isnull(RM.TxStatus,'')              
     From [Order](nolock) O left join tbl_es_ProcessLoyaltyTransaction(nolock) PLT              
     ON O.OrderID=PLT.OrderID left join eshop_rewardsmapping(NOLOCK) RM               
     ON PLT.RewardMapId=RM.id left join Order_Fulfillment(NOLOCK) FF              
     ON O.OrderID=FF.OrderNo              
     Where (case @reftables when 'Order' then O.OrderID when 'tbl_es_ProcessLoyaltyTransaction' then PLT.RowID when 'Order_Fulfillment' then FF.ID end) in (@refids)              
    END              
              
    IF @eventid IN(24,34,77)              
    BEGIN              
     select ReturnRequestNo=isnull(EOR.ReturnRequestNo,''), OrderNo=isnull(O.OrderNo,''),              
      EOR.ProductName, Variant=isnull(EOR.Variant,''), EOR.Quantity_Return,              
      EOR.ReturnInitiatedDate, EOR.StageDate, Remarks=isnull(EOR.Remarks,''), Reason=isnull(EOR.Reason,''), Expected_Outcome=isnull(EOR.Expected_Outcome,''), EOR.Stage_Name              
     From [Order](nolock) O inner join eshop_Order_Return(nolock) EOR              
     ON O.OrderID=EOR.OrderID              
     Where EOR.ReturnID in (@refids)                   
    END              
              
    IF @eventid IN(16)              
    BEGIN              
     Select First_Name, Last_Name, UserName, Gender=isnull(Gender,''), DateofBirth,              
       Country_Name=isnull(Country_Name,''), State_Name=isnull(State_Name,''),              
       City_Name=isnull(City_Name,''), PostalCode=isnull(PostalCode,''), Email,              
       Mobile1, Address1=isnull(Address1,''), Created              
     from Customers(nolock)              
     Where CustomerID in (@refids)              
    END              
              
    IF @eventid IN(73,74)              
    BEGIN              
     Select NL.EmailId, NL.Status, UserName=UD.User_Login, NL.CreatedOn               
     From tbl_es_NewsLetterSubscriber(nolock) NL inner join User_Detail(nolock) UD              
     On  NL.UserId = UD.User_ID              
     Where NL.Id in (@refids)              
    END              
              
    IF @eventid IN(25)              
    BEGIN              
     Select Customer=RV.Name, RV.Email, RV.Review, Rating=RV.Rate, Product=Prod.Name,               
     ReviewDate=RV.DateTime              
     From Review(nolock) RV inner join Products(nolock) Prod              
     On RV.ProductID=Prod.ProductID              
     Where ReviewId in (@refids)              
    END              
   END              
  END;              
 END;              
 ELSE              
 BEGIN              
  IF @context = 'enquiry'              
  BEGIN              
   INSERT INTO #entitydetails([Entityid], [leadno], [personname], [MobileNo], [MobileNo1], [MobileNo2], [EmailID],    
   [EmailID1], [EmailID2], [FollowupStatus], [Source], [Medium], [Campaign], [EntityCreatedOn])              
   SELECT [u].[EnquiryID] AS [Entityid], NULL, [personname], [MobileNo], [MobileNo1], [MobileNo2], [EmailID], [EmailID1], [EmailID2], NULL, [s].[Name] AS [Source], [m].[Name] AS [Medium], [c].[Name] AS [Campaign], [u].[CreatedDate] AS [EntityCreatedOn]  
  
            
       --into #entitydetails                                     
    FROM   userenquiry(NOLOCK) AS u LEFT JOIN UserSourceSettings AS s(NOLOCK)              
    ON s.SourceID = u.SourceName LEFT JOIN UsermediumSettings AS m(NOLOCK)              
    ON m.mediumID = u.mediumName LEFT JOIN UsercampaignSettings AS c(NOLOCK)              
    ON c.campaignID = u.campaignName              
    WHERE  [u].[EnquiryID] = @entityid;              
    
   IF EXISTS(SELECT 1 FROM #entitydetails)              
   BEGIN              
    if @ispredefined=0          
 begin          
  set @jsonactivity= (select requestjson from tbl_ce_EventWebhook where id=@refids)          
 end          
      
 IF @eventid =617              
   BEGIN              
         
    SET @jsonactivity = (SELECT     *              
          FROM       (SELECT [t].[fieldname], isnull(dbo.fn_getentityfullname('user',ud.user_id),'') ModifiedBy,       
    [t].[CreatedOn] AS [ActivityObjectCreatedOn], isnull(str(ud.mobile),'') [ModifiedByPhone],isnull(ud.email,'') [ModifiedByEmail]      
    ,case when tablename='userenquiry' then 'Predefined' else 'Custom' end as Fieldtype      
             FROM   fieldupdated(NOLOCK) AS t JOIN  user_detail(nolock) ud on ud.user_id=t.createdby            
             WHERE  [t].[id] = @refids) AS a FOR JSON AUTO, INCLUDE_NULL_VALUES);              
    END;    
	
   IF @eventtype = 'Ticket Portal'              
   BEGIN               
   print @eventtype  
    set @strQuery = Concat(' SET @jsonactivity1 = (SELECT * FROM               
 ( SELECT top 1 [t].[Ticketno], [t].[Subject] AS [SupportTitle], [m].[Type_Desc] AS [TicketType], [p].[PriorityName] AS [TicketPriority], [t].[CreatedOn] AS [ActivityObjectCreatedOn], [t].[ModifiedOn] AS [TicketLastUpdated], ISNULL((SELECT [LoginName] FROM [tbl_tp_UserLogin] AS [d](NOLOCK) 
	WHERE [d].TpUser_id = [t].[Createdby]), '''') AS [TicketCreatedBy],               
     CASE WHEN [t].[AssignedUser] = 0 AND [t].[AssignedGroup] > 0 THEN ''Group'' WHEN [t].[AssignedUser] > 0 THEN ''Individual'' ELSE '''' END AS [TicketAssignType], 
	 isnull(ttul.loginname,'''') AS [TicketAssignedToIndividual],
	 isnull(ttul.Country_Code,'''') AS [TicketAssignedToIndividual_Countrycode],
	 isnull(ttul.Mobile,'''') AS [TicketAssignedToIndividual_Mobile],
	 isnull(ttul.Email,'''') AS [TicketAssignedToIndividual_Email],
	 isnull(ttul.Name,'''') AS [TicketAssignedToIndividual_Name],
	 --ISNULL((SELECT [LoginName] FROM [tbl_tp_UserLogin] AS [d](NOLOCK) WHERE [d].TpUser_id = [t].[AssignedUser]), '''') AS [TicketAssignedToIndividual],               
     ISNULL((SELECT [GroupName] FROM [tbl_tp_GroupMaster] AS [d](NOLOCK) WHERE [d]. [groupid] = [t].[AssignedGroup]), '''') AS [TicketAssignedToGroup],               
     [h].[ActionDateTime] AS [TicketAssignedOn], [sm].TicketSourceName AS [TicketSource], [s].[TicketStatus] AS [TicketLatestStatus],    
  ISNULL( [t].[note], '''') AS [TicketLatestNote], ISNULL([h].[note], '''') AS [TicketNote], ISNULL([t].[remarks],'''') AS [TicketLatestUpdateRemarks], ISNULL([h].[remarks], '''') AS [TicketUpdateRemarks],  
     ISNULL((SELECT [LoginName] FROM [tbl_tp_UserLogin] WHERE Tpuser_id = [h].[AssignedBy]), '''') AS [TicketUpdatedBy],               
     ISNULL((SELECT [TicketStatus] FROM [tbl_tp_TicketStatusMaster] WHERE [TicketStatus_ID] = [h].TicketStatusID), '''') AS [TicketStatus], ISNULL([f].[rating], '''') AS [TicketFeedback],  
     ISNULL((SELECT [LoginName] FROM [tbl_tp_UserLogin] WHERE Tpuser_id = [h].[AssignedBy]), '''') AS [FeedbackForAgent],               
     ISNULL(CAST([f].[submitdate] AS NVARCHAR), '''') AS [FeedbackDate],               
     ISNULL(CAST([f].[comments] AS NVARCHAR), '''') AS [FeedbackComments],  
  isnull(u.ShortUrl,'''') as feedbackurl  
     FROM tbl_tp_ticketmaster_',@parentid,' AS t(NOLOCK) JOIN tbl_tp_TicketStatusMaster(NOLOCK) AS s  
     ON s.TicketStatus_ID = t.TicketStatusID LEFT JOIN tbl_tp_TicketHistory AS h(NOLOCK)              
     ON t.ticketid = h.TicketID and t.parentid=h.parentid LEFT JOIN tbl_tp_TicketType_Master AS m(NOLOCK)  
     ON m.type_id = t.TicketTypeId LEFT JOIN tbl_tp_TicketRatingFeedback(NOLOCK) AS f              
     ON f.TICKETID = t.ticketid left join tbl_tp_TicketSourceMaster(nolock) sm   
     on t.TicketSourceId=sm.TicketSourceId LEFT JOIN tbl_tp_TicketPriorityMaster(NOLOCK) p   
     ON t.TicketPriority = p.Priority_ID LEFT JOIN Serv_Ticket_url_link(nolock) u   
     ON h.TicketHistoryID=u.TicketHistoryID and h.ParentID=u.ParentID
	 left join tbl_tp_UserLogin ttul on ttul.TpUser_Id=[t].[AssignedUser]
	 LEFT JOIN tbl_tp_TicketActivity_',@parentid,' (NOLOCK) AS ta              
     ON ta.TICKETID = t.ticketid
     WHERE 1 = CASE WHEN @reftables1 = ''tbl_tp_ticketmaster_',@parentid,''' AND CAST([h].[TicketHistoryID] AS NVARCHAR) = (SELECT MAX([tickethistoryid]) FROM [tbl_tp_TicketHistory] WHERE CAST([ticketid] AS NVARCHAR) = @refids1)              
        THEN 1              
       WHEN @reftables1 = ''tbl_tp_ticketmaster_',@parentid,'''              
        AND [h].[tickethistoryid] IS NULL              
        THEN 1              
       WHEN @reftables1 = ''tbl_tp_TicketRatingFeedback''              
        AND CAST([f].[TicketHistoryID] AS NVARCHAR) = @refids1              
        THEN 1              
       WHEN @reftables1 = ''tbl_tp_TicketHistory''              
        AND CAST([h].[TicketHistoryID] AS NVARCHAR) = @refids1              
        THEN 1              
       WHEN @reftables1 = ''tbl_tp_TicketRatingFeedback''              
        AND CAST([f].[RatingId] AS NVARCHAR) = @refids1              
        THEN 1              
	   	WHEN @reftables1 = ''tbl_tp_TicketActivity_',@parentid,'''                
        AND CAST([ta].[activityId] AS NVARCHAR) = @refids1              
        THEN 1  
       ELSE 0              
       END
	   order by case when  @reftables1 = ''tbl_tp_TicketActivity_',@parentid,'''   then ta.activityid else 0 end desc) AS a FOR JSON AUTO, INCLUDE_NULL_VALUES);')      
	   print concat('@reftables1: ',@reftables,', @refids1: ',@refids)
	   print concat('strquery: ', @strquery)
    --select cast (@strQuery as nvarchar(max)) 
    Exec sp_executesql @strQuery,N'@reftables1 NVARCHAR(MAX), @refids1 NVARCHAR(MAX), @jsonactivity1 nvarchar(max) out',@reftables1=@reftables,@refids1=@refids,@jsonactivity1=@jsonactivity out  
    print @jsonactivity  
   END     


  IF @eventtype = 'call'              
   BEGIN    
    DROP TABLE IF EXISTS #activitydetails;              
    SET @jsonactivity = (SELECT     *              
          FROM       (SELECT top 1 [k].[call_start_time] AS [ActivityObjectStartTime], [k].[callerid], [k].[dnid], [k].              
          [context], [k].[recordurl], [d].[dialstatus], ISNULL([a].[AppName], 'none') AS [AppNAme], [c].              
          [CampaignName], [dbo].[fn_getcallstatus](ISNULL([k].[uniqueid], 0)) AS [CallStatus], [dbo].              
          [lastagentattended](ISNULL([k].[uniqueid], 0)) AS [LastAgentDialed],isnull(k.call_last_dtmf,'') LastDTMFInput,    
k.[call_start_time] Activityobjectcreatedon,isnull(f.Dialstatus,'') CutomerCallStatus,    
    isnull(dbo.fn_getentityfullname('user',ud.user_id),'') as AgentName,            
        isnull(str(ud.mobile),'') as AgentMobile,isnull(ud.email,'') as AgentEmail              
             --into #activitydetails                                      
             FROM   Kit19Calls AS k(NOLOCK) LEFT JOIN Kit19CallsDialled AS d(NOLOCK)              
             ON k.uniqueid = d.puniqueid LEFT JOIN Kit19Cloudvoicefinaltbl AS f(NOLOCK)              
             ON f.kit19uniqueid = k.uniqueid LEFT JOIN BatchVoiceInfo AS b(NOLOCK)              
             ON b.batchid = f.batchid LEFT JOIN usercampaignmaster AS c(NOLOCK)              
             ON c.id = b.Campaignid LEFT JOIN Cloud_app_master AS a(NOLOCK)              
       ON a.AppId = ISNULL(k.appid, b.Appid)         
        
    left join User_Detail ud (nolock) on  dbo.fn_trim0prefix(d.agentnumber)=            
    case when d.agenttype='mobile' then str(ud.mobile) else cast(ud.user_id as nvarchar(50)) end                  
             WHERE  @refids = CASE              
                  WHEN @reftables = 'Kit19callsdialled'              
                   THEN [d].[id]              
                  WHEN @reftables = 'Kit19calls'              
                   THEN [k].[id]              
         WHEN @reftables = 'Batchvoiceinfo'              
                   THEN [b].[BatchID]              
                  END    
      order by case when f.dialstatus='ANSWER' then 0 else 1 end    
      ) AS a FOR JSON AUTO, INCLUDE_NULL_VALUES);     
          
   END;              
    
   if(@eventtype = 'AI Bot')
   begin
            
        IF(@reftables='tbl_ai_VisitorsLastResponse')
        Begin
            SET @jsonactivity = (Select * From (SELECT VLR.entityName, VLR.entityId, VLR.lastmessage_at, VLR.createdon, VLR.mode, VLR.direction, VLR.lastmessage, VLR.last_status_date, VLR.is_junk, VLR.IsOpen, VLR.IsGoalFulfilled, VLR.IsMilestoneAchieved, VLR.goalSlotJson, VLR.mileStoreJson as  MileStonejson, UL.PersonName, UL.CompanyName, UL.MobileNo, UL.MobileNo1, UL.MobileNo2, UL.EmailID, UL.EmailID1, UL.EmailID2,  UL.CountryCode, UL.CountryCode1, UL.CountryCode2, UL.InitialRemarks,  AG.Name as AgentName, AG.Email, AG.Role, AG.DetailsJson, AG.IsBot, isnull(dbo.fn_getentityfullname('user', ud.User_ID),'') as ActivityOwner, isnull(str(ud.mobile),'') as ActivityOwnerMobile,isnull(ud.email,'') as ActivityOwnerEmail
            FROM    tbl_ai_VisitorsLastResponse AS VLR WITH (nolock) LEFT OUTER JOIN UserEnquiry AS UL WITH (NOLOCK) 
            ON  VLR.entityName = 'Enquiry' AND VLR.entityId = UL.EnquiryId LEFT OUTER JOIN tbl_ai_Agents AS AG WITH (nolock) 
            ON  VLR.agentId = AG.AgentId  left join User_Detail(nolock) ud 
            on  UL.CreatedBy = ud.User_ID
            Where VLR.id=@refids) AS a FOR JSON AUTO, INCLUDE_NULL_VALUES);
        End
            
        IF(@reftables='tbl_ai_Conversations')
        Begin
            SET @jsonactivity = (Select * From (SELECT  CONV.Channel, CONV.Type, CONV.Direction, CONV.DetailsJson as ConvDetailsJson, CONV.CreatedOn, CONV.StartedAt, CONV.LastMessageAt, CONV.Metadata, CONV.EntityName, CONV.EntityId, UL.PersonName, UL.CompanyName, UL.MobileNo, UL.MobileNo1, UL.MobileNo2, UL.EmailID, UL.EmailID1, UL.EmailID2,  UL.CountryCode, UL.CountryCode1, UL.CountryCode2, UL.InitialRemarks, AG.Name as AgentName, AG.Email, AG.Role, AG.DetailsJson, AG.IsBot,  isnull(dbo.fn_getentityfullname('user', ud.User_ID),'') as ActivityOwner, isnull(str(ud.mobile),'') as ActivityOwnerMobile,isnull(ud.email,'') as ActivityOwnerEmail
            FROM    tbl_ai_Conversations AS CONV WITH (nolock) LEFT OUTER JOIN UserEnquiry AS UL WITH (NOLOCK) 
            ON      CONV.EntityName = 'Enquiry' AND CONV.EntityId = UL.EnquiryID LEFT OUTER JOIN tbl_ai_Agents AS AG WITH (nolock) 
            ON      CONV.AgentId = AG.AgentId LEFT OUTER JOIN User_Detail AS ud WITH (nolock) 
            ON      UL.CreatedBy = ud.User_ID
            WHERE   CONV.ConversationId = @refids) AS a FOR JSON AUTO, INCLUDE_NULL_VALUES);
        End

   end
  
             
    IF @eventtype = 'chat'              
       AND @eventid IN(131)              
    BEGIN              
    /* SET @jsonactivity = (SELECT     *              
           FROM       (SELECT [h].[Channelname], [v].[channelprofileid]              
              --into #activitydetails                                      
              FROM   mysmsconversations.dbo.convusers AS v(NOLOCK) JOIN mysmsconversations.dbo.channels              
              AS h(NOLOCK)              
              ON h.id = v.Channelid              
              WHERE  [v].[id] = @refids) AS a FOR JSON AUTO, INCLUDE_NULL_VALUES);      */ 
			  SET @query = '
 (SELECT *              
           FROM       (SELECT [h].[Channelname], [v].[channelprofileid]              
              --into #activitydetails                                      
              FROM   convusers AS v(NOLOCK) 
              JOIN channels AS h(NOLOCK)              
              ON h.id = v.Channelid              
              WHERE  [v].[id] = ' + CAST(@refids AS NVARCHAR) + ') AS a 
FOR JSON AUTO, INCLUDE_NULL_VALUES);';
EXEC usp_clr_GetRemoteStringValue @query, @retval=@jsonactivity out;

    END;              
    IF @eventtype = 'chat'              
       AND @eventid IN(103, 105)              
    BEGIN              
     /*SET @jsonactivity = (SELECT *              
           FROM   (SELECT [h].[Channelname],              
       CASE              
               WHEN [c].[messagetype] = 'text'              
                THEN [c].[bodytext]              
               WHEN [c].[messagetype] = 'template'              
                THEN [t].[templatebody]              
               ELSE [c].[messagetype]              
               END AS [bodytext],              
                   CASE              
                   WHEN [c].[messagetype] = 'text'              
                    THEN LEFT([c].[bodytext], 15)              
                   WHEN [c].[messagetype] = 'template'              
                    THEN LEFT([t].[templatebody], 15)           
                   ELSE [c].[messagetype]              
                   END AS [subbodytext], [c].[templateid], [t].[templatename], [p].              
                   [conversationtype], [c].[messagetype], [p].[createdon] AS       
                   [ActivityObjectCreatedOn]              
             --into #activitydetails                             
             FROM   mysmsconversations.dbo.conversations(NOLOCK) AS c JOIN mysmsconversations.dbo.              
             convparentid(NOLOCK) AS p              
             ON p.id = c.parentconvid JOIN mysmsconversations.dbo.convusers AS v(NOLOCK)              
             ON v.id = c.id JOIN mysmsconversations.dbo.channels AS h(NOLOCK)              
             ON h.id = v.Channelid              
             --left join mysmsconversations.dbo.webhooks w (nolock) on w.id=c.webhookid                                       
             LEFT JOIN MySMSConversations.dbo.convtemplates(NOLOCK) AS t              
             ON t.id = c.templateid              
             WHERE              
   --c.id=(select min(id) from mysmsconversations.dbo.conversations(nolock) where parentconvid=c.parentconvid)                                      
             --and                                       
             @refids = CASE              
                 WHEN @reftables LIKE '%convuser%'              
                  THEN [p].[id]              
                 ELSE [c].[id]              
                 END) AS a FOR JSON AUTO, INCLUDE_NULL_VALUES);   */  
				 SET @query = concat('(
SELECT 
    [h].[Channelname],              
    CASE              
        WHEN [c].[messagetype] = ''text''              
            THEN [c].[bodytext]              
        WHEN [c].[messagetype] = ''template''              
            THEN [t].[templatebody]              
        ELSE [c].[messagetype]              
    END AS [bodytext],              
    CASE              
        WHEN [c].[messagetype] = ''text''              
            THEN LEFT([c].[bodytext], 15)              
        WHEN [c].[messagetype] = ''template''              
            THEN LEFT([t].[templatebody], 15)           
        ELSE [c].[messagetype]              
    END AS [subbodytext], 
    [c].[templateid], 
    [t].[templatename], 
    [p].[conversationtype], 
    [c].[messagetype], 
    [p].[createdon] AS [ActivityObjectCreatedOn]              
FROM   
    conversations (NOLOCK) AS c 
    JOIN convparentid (NOLOCK) AS p ON p.id = c.parentconvid 
    JOIN convusers (NOLOCK) AS v ON v.id = c.id 
    JOIN channels (NOLOCK) AS h ON h.id = v.Channelid              
    LEFT JOIN convtemplates (NOLOCK) AS t ON t.id = c.templateid              
WHERE ',
    @refids,' = CASE              
        WHEN ',@reftables,' LIKE ''%convuser%''              
            THEN [p].[id]              
        ELSE [c].[id]              
    END
FOR JSON AUTO, INCLUDE_NULL_VALUES);');

EXEC usp_clr_GetRemoteStringValue @query, @retval=@jsonactivity out;
    END;              
    IF @eventtype = 'chat'              
       AND @eventid IN(106)              
    BEGIN              
    /* SET @jsonactivity = (SELECT     *              
           FROM       (SELECT TOP 1 CASE              
                  WHEN [c].[messagetype] = 'text'              
                   THEN [c].[bodytext]              
                  ELSE [c].[messagetype]              
                  END AS [bodytext],              
                   CASE              
                   WHEN [c].[messagetype] = 'text'              
                    THEN LEFT([c].[bodytext], 15)              
                   ELSE [c].[messagetype]              
                   END AS [subbodytext], [c].[messagetype], [p].[createdon] AS              
                   [ActivityObjectCreatedOn]              
              FROM         mysmsconversations.dbo.conversations(NOLOCK) AS c JOIN mysmsconversations.dbo              
              .conversationstatus(NOLOCK) AS p              
              ON p.messageid = c.messageid              
              WHERE        [p].[id] = @refids) AS a FOR JSON AUTO, INCLUDE_NULL_VALUES);    */    
			  SET @query = '
(
    SELECT *              
    FROM (
        SELECT TOP 1 
            CASE              
                WHEN [c].[messagetype] = ''text''              
                    THEN [c].[bodytext]              
                ELSE [c].[messagetype]              
            END AS [bodytext],              
            CASE              
                WHEN [c].[messagetype] = ''text''              
                    THEN LEFT([c].[bodytext], 15)              
                ELSE [c].[messagetype]              
            END AS [subbodytext], 
            [c].[messagetype], 
            [p].[createdon] AS [ActivityObjectCreatedOn]              
        FROM conversations (NOLOCK) AS c 
        JOIN conversationstatus (NOLOCK) AS p
            ON p.messageid = c.messageid              
        WHERE [p].[id] = ' + CAST(@refids AS NVARCHAR) + ' 
    ) AS a 
    FOR JSON AUTO, INCLUDE_NULL_VALUES
);';

EXEC usp_clr_GetRemoteStringValue @query, @retval=@jsonactivity out;


    END;              
    IF @eventtype = 'sms'              
    BEGIN              
     IF @reftables = 'batchinfo'              
     BEGIN              
      SET @jsonactivity = (SELECT     *              
            FROM       (SELECT [b].[BatchInsertTime] AS [ActivityObjectCreatedOn], [b].[bmessage] AS              
            [MessageText], SUBSTRING([b].[bmessage], 1, 30) + '...' AS [MessageSubText], [u].[CampaignName],              
            [u].[eventid], [u].[IsEventBased]              
               --into #activitydetails                                      
               FROM   batchinfo(NOLOCK) AS b LEFT JOIN UserCampaignExecutionHistory(NOLOCK) AS c              
               ON c.BatchID = b.BatchID LEFT JOIN usercampaignmaster(NOLOCK) AS u              
               ON u.id = c.CampaignID              
               WHERE  [b].[batchid] = @refids) AS a FOR JSON AUTO, INCLUDE_NULL_VALUES);             
     END;              
     IF @reftables = 'link_smstrack'              
     BEGIN              
      SET @jsonactivity = (SELECT     *              
            FROM       (SELECT [l].[ipAddress], [l].[Long_Url], [l].[VisitDate] AS [ActivityObjectCreatedOn],              
            [b].[bmessage] AS [MessageText], [u].[CampaignName], [u].[eventid], [u].[IsEventBased]              
              --into #activitydetails                                      
               FROM   link_smstrack(NOLOCK) AS l JOIN Link_smsMobile(NOLOCK) AS m              
               ON l.link_id = m.mobile_url_id JOIN batchinfo(NOLOCK) AS b              
               ON b.BatchID = m.batchid LEFT JOIN UserCampaignExecutionHistory(NOLOCK) AS c              
               ON c.BatchID = b.BatchID LEFT JOIN usercampaignmaster(NOLOCK) AS u              
               ON u.id = c.CampaignID              
      WHERE  [l].[trackid] = @refids) AS a FOR JSON AUTO, INCLUDE_NULL_VALUES);              
     END;              
    END;              
    IF @eventtype = 'webform'              
    BEGIN              
     SET @jsonactivity = (SELECT     *              
           FROM       (SELECT [w].[formname], replace([dynimicattr], ';', ',') AS [WebFormData], [w].[EntryDate]              
           AS [ActivityObjectCreatedOn]              
              --into #activitydetails                                      
              FROM   WebEntryTbl(NOLOCK) AS w              
              WHERE  [w].[EntryId] = @refids) AS a FOR JSON AUTO, INCLUDE_NULL_VALUES);              
    END;              
    IF @eventtype = 'landingPage'              
    BEGIN              
     SET @jsonactivity = (SELECT     *              
           FROM       (SELECT 'kit19.com/' + [w].[cname] AS [PageName], [w].[FirstName], [w].[LastName], [w].              
           [Address], [w].[City], CAST([w].[CountryCode] AS NVARCHAR) + [w].[Mobile] AS [MobileProvided], [w].              
           [Email] AS [EmailProvided], [w].[DateCreated] AS [ActivityObjectCreatedOn]              
              --into #activitydetails                                      
              FROM   clientleaddetails(NOLOCK) AS w              
              WHERE  [w].[Id] = @refids) AS a FOR JSON AUTO, INCLUDE_NULL_VALUES);              
    END;              
    IF @eventtype = 'email'              
    BEGIN      
	IF @eventid = 115              
           AND @reftables = 'EngagementEventOpenClick'              
        BEGIN              
         --SET @jsonactivity = (SELECT     *              
         --      FROM  (SELECT [destination_url] AS [MailLinkVisited], [CreatedOn] AS              
         --      [ActivityObjectCreatedOn], [b].[Email_Subject] AS [MailSubject], LEFT([b].              
         --      [email_subject], 15) AS [SubMailSubject]              
         --         --into #activitydetails                                      
         --         FROM   EngagementEventOpenClick(NOLOCK) AS e JOIN BatchEmail_Infos AS b(              
         --         NOLOCK)              
         --         ON e.BatchID = b.BatchID              
         --         WHERE  [e].[ID] = @refids) AS a FOR JSON AUTO, INCLUDE_NULL_VALUES); 
		 		 SET @jsonactivity = (
    SELECT 
        '[{' + STRING_AGG(
            '"MailLinkVisited": ' + ISNULL('"' + destination_url + '"', 'null') + ',' +
            '"ActivityObjectCreatedOn": ' + ISNULL('"' + CONVERT(VARCHAR, CreatedOn, 126) + '"', 'null') + ',' +
            '"MailSubject": ' + ISNULL('"' + Email_Subject + '"', 'null') + ',' +
            '"SubMailSubject": ' + ISNULL('"' + LEFT(email_subject, 15) + '"', 'null'),
            '}'
        ) + '}]'
    FROM (
        SELECT 
            [destination_url], 
            [CreatedOn], 
            [b].[Email_Subject]
        FROM EngagementEventOpenClick AS e
        JOIN BatchEmail_Infos AS b
            ON e.BatchID = b.BatchID
        WHERE [e].[ID] = @refids
    ) AS a
);
        END;              

   ELSE  IF @eventid IN(57, 58)              
     BEGIN              
      SET @jsonactivity = (SELECT     *              
            FROM       (SELECT [MailSubject], [FromAddr], [createdtime] AS [Activityobjectcreatedon], LEFT(              
            [mailsubject], 15) AS [SubMailSubject]              
               --into #activitydetails                                      
               FROM   Mysmst.dbo.tbl_email(NOLOCK)              
               WHERE  [id] = @refids) AS a FOR JSON AUTO, INCLUDE_NULL_VALUES);              
     END;              
     ELSE              
     BEGIN              
      IF @eventid = 4              
      BEGIN              
       SET @jsonactivity = (SELECT     *              
             FROM       (SELECT [OpenCount], [FirstOpened], [LastOpened], [CreatedOn] AS              
             [ActivityObjectCreatedOn]              
                --into #activitydetails                                      
                FROM   Mysmst.dbo.Tbl_EmailTracking(NOLOCK)              
                WHERE  [id] = @refids) AS a FOR JSON AUTO, INCLUDE_NULL_VALUES);              
      END;              
      ELSE              
      BEGIN              
       IF @eventid = 40              
       BEGIN              
        SET @jsonactivity = (SELECT     *              
              FROM       (SELECT [Emails] AS [ActivityThroughEmail], [createdon] AS              
              [ActivityObjectCreatedOn], [email_subject] AS [MailSubject], LEFT([email_subject], 15) AS              
              [SubMailSubject]              
                 --into #activitydetails                                      
                 FROM   tbl_subscription(NOLOCK) AS t LEFT JOIN BatchEmail_Infos(NOLOCK) AS b              
                 ON b.batchid = t.batchid              
                 WHERE  [t].[id] = @refids) AS a FOR JSON AUTO, INCLUDE_NULL_VALUES);              
       END;              
       ELSE              
       BEGIN              
        IF @eventid = 3              
        BEGIN              
         IF @reftables = 'Batchemail_infos'              
         BEGIN              
          SET @jsonactivity = (SELECT     *              
                FROM       (SELECT [email_subject] AS [MailSubject], [SenderName] AS [FromAddr],              
                [batchinsertTime] AS [Activityobjectcreatedon], LEFT([email_subject], 15) AS              
                [SubMailSubject]              
                   --into #activitydetails                                      
                   FROM   Batchemail_infos(NOLOCK)              
                   WHERE  [BatchID] = @refids) AS a FOR JSON AUTO, INCLUDE_NULL_VALUES);              
         END;              
         
          ELSE              
          BEGIN              
           IF @reftables = 'MySMST.dbo.Tbl_Email'              
           BEGIN              
            SET @jsonactivity = (SELECT     *              
                  FROM       (SELECT [MailSubject], [FromAddr], [CreatedTime] AS              
                  [Activityobjectcreatedon], LEFT([mailsubject], 15) AS [SubMailSubject]              
                     --into #activitydetails                                      
                     FROM   MySMST.dbo.Tbl_Email(NOLOCK)              
                     WHERE  [ID] = @refids) AS a FOR JSON AUTO, INCLUDE_NULL_VALUES)              
            ;              
         
          END;              
         END;              
        END;              
       END;              
      END;              
     END;              
    END;              
   END;              
  END;    
  ELSE    
  BEGIN    
 IF @context = 'user'              
 BEGIN    
  INSERT INTO #entitydetails([Entityid], [leadno], [personname], [MobileNo], [MobileNo1], [MobileNo2], [EmailID], [EmailID1], [EmailID2], [FollowupStatus], [Source], [Medium], [Campaign], [EntityCreatedOn])     
    SELECT [u].[User_ID] AS [Entityid], NULL, u.User_Login as [personname], u.Mobile as [MobileNo], null as [MobileNo1], null as [MobileNo2], u.Email as [EmailID], null as [EmailID1], null as [EmailID2], NULL, u.[Source], u.[Medium], u.[Campaign], 
	[u].[DateCreated] AS [EntityCreatedOn]              
     --into #entitydetails    
  FROM   user_detail(NOLOCK) AS u               
  WHERE  [u].[User_ID] = @entityid;    
   
     if (@eventby='system')
  begin
  if @eventtype='Subscription'
  begin
  SET @jsonactivity = (SELECT     *              
    FROM (SELECT top 1 PlanStartDate as SubscriptionStartDate,PlanEndDate SubscriptionExpiryDate,IsTrailPlan,dbo.fn_getgraceexpiry(userid) SubscriptionExpiryGraceDate,
	'CRM' as SubscribedService,concat('Allowed Users: ', dbo.fn_getallowedusers(UserId)) as SubscriptionDetails
     FROM Price_UserSubscriptionDetails(nolock)  AS P
     WHERE  P.UserId = @entityid) AS a FOR JSON AUTO, INCLUDE_NULL_VALUES);    
   
  end
else if @eventtype='Credit and Usage'
begin
if @reftables='credit_details'
begin
SET @jsonactivity = (SELECT     *              
    FROM (SELECT [dbo].[fn_GetSMSBalance](user_id) as SMSBalance,[dbo].[fn_GetMailBalance](user_id) as MailBalance,[dbo].[fn_GetMoneyBalance](user_id) as MoneyBalance
	, dbo.fn_getlastdaymoneyconsumption(user_id) as YesterdayMoneyConsumption, dbo.fn_getlastdaymailconsumption(user_id) as YesterdayMailConsumption, dbo.fn_getlastdaysmsconsumption(user_id) as YesterdaySMSConsumption, debits as CreditsDebited,credits as CreditsAdded, dbo.fn_getuserlogins(fromuser_id) as FromUser,'SMS' as CreditService
     FROM credit_details(nolock)  AS P
	 WHERE  P.User_Id = @entityid and credit_id=@refids
		 ) AS a FOR JSON AUTO, INCLUDE_NULL_VALUES);    
end
else if @reftables='mailcreditdetails'
begin
SET @jsonactivity = (SELECT     *              
    FROM (SELECT [dbo].[fn_GetSMSBalance](user_id) as SMSBalance,[dbo].[fn_GetMailBalance](user_id) as MailBalance,[dbo].[fn_GetMoneyBalance](user_id) as MoneyBalance
	, dbo.fn_getlastdaymoneyconsumption(user_id) as YesterdayMoneyConsumption, dbo.fn_getlastdaymailconsumption(user_id) as YesterdayMailConsumption, dbo.fn_getlastdaysmsconsumption(user_id) as YesterdaySMSConsumption, debits as CreditsDebited,credits as CreditsAdded, dbo.fn_getuserlogins(fromuser_id) as FromUser,'Mail' as CreditService
     FROM mailcreditdetails(nolock)  AS P
	 WHERE  P.User_Id = @entityid and credit_id=@refids
		 ) AS a FOR JSON AUTO, INCLUDE_NULL_VALUES);    
end
else  if @reftables='intcredit_details'
begin
SET @jsonactivity = (SELECT     *              
    FROM (SELECT [dbo].[fn_GetSMSBalance](user_id) as SMSBalance,[dbo].[fn_GetMailBalance](user_id) as MailBalance,[dbo].[fn_GetMoneyBalance](user_id) as MoneyBalance
	, dbo.fn_getlastdaymoneyconsumption(user_id) as YesterdayMoneyConsumption, dbo.fn_getlastdaymailconsumption(user_id) as YesterdayMailConsumption, dbo.fn_getlastdaysmsconsumption(user_id) as YesterdaySMSConsumption, debits as CreditsDebited,credits as CreditsAdded, dbo.fn_getuserlogins(fromuser_id) as FromUser,'Money' as CreditService
     FROM intcredit_details(nolock)  AS P
	 WHERE  P.User_Id = @entityid and credit_id=@refids
		 ) AS a FOR JSON AUTO, INCLUDE_NULL_VALUES);    
end
else
begin
SET @jsonactivity = (SELECT     *              
    FROM (SELECT [dbo].[fn_GetSMSBalance](user_id) as SMSBalance,[dbo].[fn_GetMailBalance](user_id) as MailBalance,[dbo].[fn_GetMoneyBalance](user_id) as MoneyBalance
	, dbo.fn_getlastdaymoneyconsumption(user_id) as YesterdayMoneyConsumption, dbo.fn_getlastdaymailconsumption(user_id) as YesterdayMailConsumption, dbo.fn_getlastdaysmsconsumption(user_id) as YesterdaySMSConsumption, 0 as CreditsDebited,0 as CreditsAdded, dbo.fn_getuserlogins(user_id) as FromUser,'SMS/Mail/Money' as CreditService
     FROM user_detail(nolock)  AS P
	 WHERE  P.User_Id = @entityid
	 
	 ) AS a FOR JSON AUTO, INCLUDE_NULL_VALUES);    
end
end
else if @eventtype='TimeTracking'
begin
if @eventid=135
begin
SET @jsonactivity = (SELECT     *              
    FROM (SELECT Mysmstimetrack.dbo.fn_getstarttimetoday(user_id) as RequiredStartTimeToday,Mysmstimetrack.dbo.fn_getuserstodaybreaktime(user_id) as TodayBreakTime,Mysmstimetrack.dbo.fn_getuserstodayWorktime(user_id) as TodayWorkTime,Mysmstimetrack.dbo.fn_getuserstodaystarttime(user_id) as TodayStartTime
     FROM user_detail(nolock)  AS P
     WHERE  P.User_Id = @entityid) AS a FOR JSON AUTO, INCLUDE_NULL_VALUES);    
end
end

  end

  If exists(Select * from #entitydetails)    
  Begin    
     IF @eventtype = 'Ticket Portal'              
   BEGIN               print @eventtype  
    set @strQuery = Concat(' SET @jsonactivity1 = (SELECT * FROM               
 ( SELECT top 1 [t].[Ticketno], [t].[Subject] AS [SupportTitle], [m].[Type_Desc] AS [TicketType], [p].[PriorityName] AS [TicketPriority], [t].[CreatedOn] AS [ActivityObjectCreatedOn], [t].[ModifiedOn] AS [TicketLastUpdated], ISNULL((SELECT [LoginName] FROM [tbl_tp_UserLogin] AS [d](NOLOCK) 
	WHERE [d].TpUser_id = [t].[Createdby]), '''') AS [TicketCreatedBy],               
     CASE WHEN [t].[AssignedUser] = 0 AND [t].[AssignedGroup] > 0 THEN ''Group'' WHEN [t].[AssignedUser] > 0 THEN ''Individual'' ELSE '''' END AS [TicketAssignType], 
	 isnull(ttul.loginname,'''') AS [TicketAssignedToIndividual],
	 isnull(ttul.Country_Code,'''') AS [TicketAssignedToIndividual_Countrycode],
	 isnull(ttul.Mobile,'''') AS [TicketAssignedToIndividual_Mobile],
	 isnull(ttul.Email,'''') AS [TicketAssignedToIndividual_Email],
	 isnull(ttul.Name,'''') AS [TicketAssignedToIndividual_Name],
	 --ISNULL((SELECT [LoginName] FROM [tbl_tp_UserLogin] AS [d](NOLOCK) WHERE [d].TpUser_id = [t].[AssignedUser]), '''') AS [TicketAssignedToIndividual],               
     ISNULL((SELECT [GroupName] FROM [tbl_tp_GroupMaster] AS [d](NOLOCK) WHERE [d]. [groupid] = [t].[AssignedGroup]), '''') AS [TicketAssignedToGroup],               
     [h].[ActionDateTime] AS [TicketAssignedOn], [sm].TicketSourceName AS [TicketSource], [s].[TicketStatus] AS [TicketLatestStatus],    
  ISNULL( [t].[note], '''') AS [TicketLatestNote], ISNULL([h].[note], '''') AS [TicketNote], ISNULL([t].[remarks],'''') AS [TicketLatestUpdateRemarks], ISNULL([h].[remarks], '''') AS [TicketUpdateRemarks],  
     ISNULL((SELECT [LoginName] FROM [tbl_tp_UserLogin] WHERE Tpuser_id = [h].[AssignedBy]), '''') AS [TicketUpdatedBy],               
     ISNULL((SELECT [TicketStatus] FROM [tbl_tp_TicketStatusMaster] WHERE [TicketStatus_ID] = [h].TicketStatusID), '''') AS [TicketStatus], ISNULL([f].[rating], '''') AS [TicketFeedback],  
     ISNULL((SELECT [LoginName] FROM [tbl_tp_UserLogin] WHERE Tpuser_id = [h].[AssignedBy]), '''') AS [FeedbackForAgent],               
     ISNULL(CAST([f].[submitdate] AS NVARCHAR), '''') AS [FeedbackDate],               
     ISNULL(CAST([f].[comments] AS NVARCHAR), '''') AS [FeedbackComments],  
  isnull(u.ShortUrl,'''') as feedbackurl  
     FROM tbl_tp_ticketmaster_',@parentid,' AS t(NOLOCK) JOIN tbl_tp_TicketStatusMaster(NOLOCK) AS s  
     ON s.TicketStatus_ID = t.TicketStatusID LEFT JOIN tbl_tp_TicketHistory AS h(NOLOCK)              
     ON t.ticketid = h.TicketID and t.parentid=h.parentid LEFT JOIN tbl_tp_TicketType_Master AS m(NOLOCK)  
     ON m.type_id = t.TicketTypeId LEFT JOIN tbl_tp_TicketRatingFeedback(NOLOCK) AS f              
     ON f.TICKETID = t.ticketid left join tbl_tp_TicketSourceMaster(nolock) sm   
     on t.TicketSourceId=sm.TicketSourceId LEFT JOIN tbl_tp_TicketPriorityMaster(NOLOCK) p   
     ON t.TicketPriority = p.Priority_ID LEFT JOIN Serv_Ticket_url_link(nolock) u   
     ON h.TicketHistoryID=u.TicketHistoryID and h.ParentID=u.ParentID
	 left join tbl_tp_UserLogin ttul on ttul.TpUser_Id=[t].[AssignedUser]
	 LEFT JOIN tbl_tp_TicketActivity_',@parentid,' (NOLOCK) AS ta              
     ON ta.TICKETID = t.ticketid
     WHERE 1 = CASE WHEN @reftables1 = ''tbl_tp_ticketmaster_',@parentid,''' AND CAST([h].[TicketHistoryID] AS NVARCHAR) = (SELECT MAX([tickethistoryid]) FROM [tbl_tp_TicketHistory] WHERE CAST([ticketid] AS NVARCHAR) = @refids1)              
        THEN 1              
       WHEN @reftables1 = ''tbl_tp_ticketmaster_',@parentid,'''              
        AND [h].[tickethistoryid] IS NULL              
        THEN 1              
       WHEN @reftables1 = ''tbl_tp_TicketRatingFeedback''              
        AND CAST([f].[TicketHistoryID] AS NVARCHAR) = @refids1              
        THEN 1              
       WHEN @reftables1 = ''tbl_tp_TicketHistory''              
        AND CAST([h].[TicketHistoryID] AS NVARCHAR) = @refids1              
        THEN 1              
       WHEN @reftables1 = ''tbl_tp_TicketRatingFeedback''              
        AND CAST([f].[RatingId] AS NVARCHAR) = @refids1              
        THEN 1              
	   	WHEN @reftables1 = ''tbl_tp_TicketActivity_',@parentid,'''                
        AND CAST([ta].[activityId] AS NVARCHAR) = @refids1              
        THEN 1  
       ELSE 0              
       END
	   order by case when  @reftables1 = ''tbl_tp_TicketActivity_',@parentid,'''   then ta.activityid else 0 end desc) AS a FOR JSON AUTO, INCLUDE_NULL_VALUES);')      
    --select cast (@strQuery as nvarchar(max)) 
    Exec sp_executesql @strQuery,N'@reftables1 NVARCHAR(MAX), @refids1 NVARCHAR(MAX), @jsonactivity1 nvarchar(max) out',@reftables1=@reftables,@refids1=@refids,@jsonactivity1=@jsonactivity out  
    print @jsonactivity  
   END     


   If(@reftables='TBL_ET_Attendance')    
   Begin    
    SET @jsonactivity = (SELECT     *              
    FROM (SELECT ATT.AttendanceIn, ATT.AttendanceOut, ATT.LatitudeIn, ATT.LongitudeIn, ATT.LatitudeOut, ATT.LongitudeOut, ATT.DeviceId, ATT.RemarksIn, ATT.RemarksOut, ATT.CreatedDate, ATT.CreatedBy, ud.User_Login, AG.AttendanceGroupName, AG.GroupType, AG.
DefaultGeoRestrictionIn, AG.DefaultGeoRestrictionOut, AG.DefaultAuthTypeIn, AG.DefaultAuthTypeOut, AG.SignInType, AG.SignOutType, AG.SignInPromptType, AG.SignOutPromptType, AG.DefaultAttendanceCalcType, AG.CalculateTimeSpentIn, 
AG.CalculateScheduleVisitCount, AG.AllowedAttendanceOverride, AG.LeaveRequestIn, AG.AttendanceApproverType, AG.AttendaceApprover, AG.ApplyLeaveBeforeLimit, AG.SignInRange, AG.SignOutRange, AG.SignInTimeLater, AG.SignInTimeLaterType, AG.SignIndisallowedMessage,
AG.SignOutdisallowedMessage, AG.DefaultRosterId, AG.RosterId, AG.FixedNoMeeting, AG.LocationRange, SM.ShiftName, SM.StartTime, SM.EndTime    
     FROM TBL_ET_Attendance AS ATT WITH (NOLOCK) INNER JOIN User_Detail AS ud WITH (nolock)     
     ON ud.User_ID = ATT.UserId INNER JOIN TBL_ET_AttendanceGroup AS AG WITH (nolock)     
     ON ATT.AttendanceGroupId = AG.AttendanceGroupId INNER JOIN TBL_ET_ShiftMaster(nolock) AS SM    
     ON ATT.ShiftId = SM.ShiftId    
     WHERE  ATT.AttendanceId = @refids) AS a FOR JSON AUTO, INCLUDE_NULL_VALUES);    
   End   
     
   if(@reftables = 'TBL_ET_UserLocationGpsHistory')  
 begin  
	declare @temUserLocationId bigint
		select @temUserLocationId = h.UserLocationTrackingId from TBL_ET_UserLocationGpsHistory(nolock) h
					where h.id = @refids
	if(exists(select 1 from TBL_ET_UserLocationTracking(nolock) l where l.UserLocationTrackingId = @temUserLocationId))
	begin
		 SET @jsonactivity = (SELECT     *              
			  FROM (select t.MovementCode, t.CreatedDate, t.Remarks, t.LocationDateTime, t.Latitude, t.Longitude, t.Address,  
			   t.BatteryPerc, t.NetworkPerc, t.Speed, t.Distance  from  
			  TBL_ET_UserLocationTracking(nolock) t  
		where t.UserLocationTrackingId = @refids) AS a FOR JSON AUTO, INCLUDE_NULL_VALUES);  
	end
	else		
	begin
		SET @jsonactivity = (SELECT     *              
			  FROM (select t.MovementCode, t.CreatedDate, t.Remarks, t.LocationDateTime, t.Latitude, t.Longitude, t.Address,  
			   t.BatteryPerc, t.NetworkPerc, t.Speed, t.Distance  from  
			  TBL_ET_UserLocationTracking_Archived(nolock) t  
		where t.UserLocationTrackingId = @refids) AS a FOR JSON AUTO, INCLUDE_NULL_VALUES);  
	end


 
 end  
  End    
 END    
  END    
 END;              
              
  SELECT [s].[Rolename], [rolename] + '.' + [user_login] AS [user_login], [rolename] + '.' + ISNULL([fname], '') AS [fname], [rolename] + '.' + ISNULL([lname], '') AS [lname], [rolename] + '.' + ISNULL([email], '') AS [email], [rolename] + '.' + 
  ISNULL(STR([u].[mobile], 10), '') AS [Mobile], [rolename] + '.' + ISNULL([City], '') AS [City], [rolename] + '.' + ISNULL(State, '') AS State, [rolename] + '.' + ISNULL([Country], '') AS [Country], [rolename] + '.' + ISNULL([Address], '') AS [Address], [rolename] 
+ '.' + ISNULL([CompnayName], '') AS [Company], [rolename] + '.' + ISNULL(CAST([lastlogin1] AS NVARCHAR), '') AS [LastLogin], [rolename] + '.' + ISNULL(CAST([onduty] AS NVARCHAR), '') AS [OnDuty], [rolename] + '.' + ISNULL(CAST([onfield] AS NVARCHAR), '')
 AS [OnField]              
  INTO [#userdetails]              
  FROM user_detail(NOLOCK) AS u JOIN(SELECT [rolename], value AS [Userid]              
       FROM   systemroles AS s CROSS APPLY dbo.fn_split(dbo.              
       fn_GetUseridFromRole(@entityname, @activityid, s.rolename), ',')              
       WHERE  value <> 0 ) AS s              
 ON s.userid = u.User_ID where u.User_ID = @user    
              
 SET @jsonusers = (SELECT * FROM #userdetails FOR json AUTO, INCLUDE_NULL_VALUES);              
              
 SET @jsonentity = (SELECT * FROM #entitydetails FOR json AUTO, INCLUDE_NULL_VALUES);              
   
--select @jsonentity = entitydetails from entity_details_transition where entityid = @entityid and entity = @entityname
    
 IF EXISTS(SELECT 1 FROM #entitydetails)              
 BEGIN              
  SELECT @jsonentity AS [EntityDetails], @jsonactivity AS [ActivityDetails], @jsonusers AS [UserDetails];    
 END;              
 ELSE              
 BEGIN              
  SELECT NULL AS [EntityDetails], NULL AS [ActivityDetails], NULL AS [UserDetails];              
 END;              
                                  
end                                      



GO

