CREATE   PROCEDURE dbo.Usp_GetMetadataForWebForm    
(    
   @FormName nvarchar(max),  
   @ParentID bigint    
)    
as    
Begin    
        
 Declare @FormID bigint = 0;    
     
 select @FormID = FormId from WebFormTbl where FormName = @FormName and ParentId = @ParentID    
     
