/* ============================================================
   Procedure: [dbo].[usp_GetMicrositeDetailsLanding]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_GetMicrositeDetailsLanding] --335, 'Landing'                   
	@UserID BIGINT
	,@Lead_Unsubscribe NVARCHAR(100)
AS
BEGIN
	DECLARE @ParentId BIGINT = 0;
	DECLARE @IsAdmin BIT = 0;
	DECLARE @RoleType VARCHAR(10);
	DECLARE @TeamCode VARCHAR(20)

	IF object_id('tempdb..#tblUserIds') IS NOT NULL
	BEGIN
		DROP TABLE #tblUserIds
	END

	CREATE TABLE #tblUserIds (UserId BIGINT NOT NULL)

	SELECT @TeamCode = tum.TeamCode
	FROM TBL_UA_TeamUserMappingMaster tum
	INNER JOIN TBL_UA_TeamMaster tm ON tm.TeamCode = tum.TeamCode
	WHERE tum.UserId = @UserId

	IF (
			(@TeamCode IS NULL)
			AND (
				@ParentId = @UserId
				OR @IsAdmin = 1
				)
			)
	BEGIN
		--set @RoleType = 'Global'
		INSERT INTO #tblUserIds (UserId)
		SELECT User_Id UserId
		FROM User_Detail(NOLOCK)
		WHERE ParentId = @ParentId
	END
	ELSE IF (@TeamCode != NULL)
	BEGIN
		---set @RoleType = 'Team'
		INSERT INTO #tblUserIds (UserId)
		SELECT UserId
		FROM TBL_UA_TeamUserMappingMaster
		WHERE TeamCode = @TeamCode
	END
	ELSE
	BEGIN
		--set @RoleType = 'User'
		INSERT INTO #tblUserIds (UserId)
		SELECT @UserId
	END

	IF (@Lead_Unsubscribe = 'Landing')
	BEGIN
		SELECT Id
			,PageName
			,CPD.Lead_Unsubscribe AS Type
			,isnull(isprofile, 0) AS isprofile
			,(
				'<p><b> Type:</b> ' + CASE 
					WHEN isnull(cpd.SmsAccountName, '') <> ''
						THEN '<p><b>AccountName:</b> ' + cpd.SmsAccountName + '</p>'
					ELSE ''
					END + CASE 
					WHEN isnull(cpd.SmsSenderName, '') <> ''
						THEN '<p><b>SmsSenderName:</b> ' + cpd.SmsSenderName + '</p>'
					ELSE ''
					END + CASE 
					WHEN isnull(CPD.SmsMessage, '') <> ''
						THEN '<p><b>SmsMessage:</b> ' + cpd.SmsMessage + '</p>'
					ELSE ''
					END + CASE 
					WHEN isnull(CAST(cpd.SmsTemplateId AS VARCHAR(50)), '') <> ''
						THEN '<p><b>SmsTemplateId:</b> ' + (CAST(cpd.SmsTemplateId AS VARCHAR(50))) + '</p>'
					ELSE ''
					END
				) AS SMS
			,(
				CASE 
					WHEN isnull(cpd.EmailAccountName, '') <> ''
						THEN '<p><b>EmailAccountName:</b> ' + cpd.EmailAccountName + '</p>'
					ELSE ''
					END + CASE 
					WHEN isnull(cpd.EmailReplyTo, '') <> ''
						THEN '<p><b>EmailReplyTo:</b> ' + cpd.EmailReplyTo + '</p>'
					ELSE ''
					END + CASE 
					WHEN isnull(cpd.EmailSubject, '') <> ''
						THEN '<p><b>EmailSubject:</b> ' + cpd.EmailSubject + '</p>'
					ELSE ''
					END + CASE 
					WHEN isnull(cpd.EmailMessgae, '') <> ''
						THEN '<p><b>EmailMessgae:</b> ' + cpd.EmailMessgae + '</p>'
					ELSE ''
					END + CASE 
					WHEN isnull(cast(cpd.EmailTemplateId AS VARCHAR(50)), '') <> ''
						THEN '<p><b>EmailTemplateId:</b> ' + (CAST(cpd.EmailTemplateId AS VARCHAR(50))) + '</p>'
					ELSE ''
					END
				) AS Email
			,(
				CASE 
					WHEN isnull(WebHook, '') <> ''
						THEN '<p><b>WebHook:</b> ' + cpd.WebHook + '</p>'
					ELSE ''
					END
				) AS WebHook
		     --, 'False' as IsNewMailBuilder
			, CPD.IsNewMailBuilder
		FROM ClientPageDetail CPD
		WHERE User_ID IN (
				SELECT UserId
				FROM #tblUserIds
				)
		ORDER BY DateCreated DESC
	END

	EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @UserID
		,@Activity_type = 'View_landpg'
		,@ActionType = 'S'
		,@RowJson = ''
		,@Table_name = 'ClientPageDetail'
END



GO

/* ============================================================
   Procedure: [dbo].[usp_GetMicrositeDetailsLanding_Updated]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.usp_GetMicrositeDetailsLanding_Updated --335, 'Landing'             
@UserID bigint,              
@Lead_Unsubscribe nvarchar(100)                 
as                  
begin               
 if(@Lead_Unsubscribe = 'Landing')               
begin                 
select Id,PageName, CPD.Lead_Unsubscribe as Type,    
 (    
'<p><b> Type:</b> ' +    
case    
 when isnull(cpd.SmsAccountName,'') <> '' then     
  '<p><b>AccountName:</b> '  +cpd.SmsAccountName +'</p>' else '' end +     
      
 case    
 when    
 isnull(cpd.SmsSenderName,'') <> '' then  '<p><b>SmsSenderName:</b> '  +cpd.SmsSenderName +'</p>' else '' end +     
 case    
 when isnull(CPD.SmsMessage,'') <> '' then  '<p><b>SmsMessage:</b> '  +cpd.SmsMessage +'</p>' else '' end +     
 case    
 when    
 isnull(CAST(cpd.SmsTemplateId as varchar(50)),'') <> '' then  '<p><b>SmsTemplateId:</b> '  +(CAST(cpd.SmsTemplateId as varchar(50))) +'</p>'     
 ELSE '' END ) AS SMS,    
      
  (    
  case    
  when    
   isnull(cpd.EmailAccountName,'')  <> '' then  '<p><b>EmailAccountName:</b> '  +cpd.EmailAccountName +'</p>' else '' end +    
  case    
  when isnull(cpd.EmailReplyTo,'')<> '' then  '<p><b>EmailReplyTo:</b> '  +cpd.EmailReplyTo +'</p>' else '' end +     
  case    
  when isnull(cpd.EmailSubject,'')<> '' then  '<p><b>EmailSubject:</b> '  +cpd.EmailSubject +'</p>' else '' end +     
 case    
 when isnull(cpd.EmailMessgae,'')<> '' then  '<p><b>EmailMessgae:</b> '  +cpd.EmailMessgae +'</p>' else '' end +     
 case    
 when isnull(cast(cpd.EmailTemplateId as varchar(50)),'')<> '' then  '<p><b>EmailTemplateId:</b> '  +(CAST(cpd.EmailTemplateId as varchar(50))) +'</p>'    
ELSE '' END ) AS Email,    
(    
 case    
 when isnull(WebHook,'')<> '' then  '<p><b>WebHook:</b> '  +cpd.WebHook +'</p>'    
 ELSE '' END) AS WebHook     
 from ClientPageDetail CPD      
 where User_ID=@UserID  order by DateCreated desc                
end              
END      
      
      
--select * from ClientPageDetail


GO

/* ============================================================
   Procedure: [dbo].[usp_GetMicrositeDetailsLandingFilter]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


  
CREATE   PROCEDURE [dbo].[usp_GetMicrositeDetailsLandingFilter] --335, 'Landing'                       
 @UserID BIGINT  
 ,@Lead_Unsubscribe NVARCHAR(100)  
 ,@MrcName nvarchar(max) = null  
AS  
BEGIN  
 DECLARE @ParentId BIGINT = 0;  
 DECLARE @IsAdmin BIT = 0;  
 DECLARE @RoleType VARCHAR(10);  
 DECLARE @TeamCode VARCHAR(20)  
  
 IF object_id('tempdb..#tblUserIds') IS NOT NULL  
 BEGIN  
  DROP TABLE #tblUserIds  
 END  
  
 CREATE TABLE #tblUserIds (UserId BIGINT NOT NULL)  
  
 SELECT @TeamCode = tum.TeamCode  
 FROM TBL_UA_TeamUserMappingMaster tum  
 INNER JOIN TBL_UA_TeamMaster tm ON tm.TeamCode = tum.TeamCode  
 WHERE tum.UserId = @UserId  
  
 IF (  
   (@TeamCode IS NULL)  
   AND (  
    @ParentId = @UserId  
    OR @IsAdmin = 1  
    )  
   )  
 BEGIN  
  --set @RoleType = 'Global'    
  INSERT INTO #tblUserIds (UserId)  
  SELECT User_Id UserId  
  FROM User_Detail(NOLOCK)  
  WHERE ParentId = @ParentId  
 END  
 ELSE IF (@TeamCode != NULL)  
 BEGIN  
  ---set @RoleType = 'Team'    
  INSERT INTO #tblUserIds (UserId)  
  SELECT UserId  
  FROM TBL_UA_TeamUserMappingMaster  
  WHERE TeamCode = @TeamCode  
 END  
 ELSE  
 BEGIN  
  --set @RoleType = 'User'    
  INSERT INTO #tblUserIds (UserId)  
  SELECT @UserId  
 END  
  
 IF (@Lead_Unsubscribe = 'Landing')  
 BEGIN  
  SELECT Id  
   ,PageName  
   ,CPD.Lead_Unsubscribe AS Type  
   ,isnull(isprofile, 0) AS isprofile  
   ,(  
    '<p><b> Type:</b> ' + CASE   
     WHEN isnull(cpd.SmsAccountName, '') <> ''  
      THEN '<p><b>AccountName:</b> ' + cpd.SmsAccountName + '</p>'  
     ELSE ''  
     END + CASE   
     WHEN isnull(cpd.SmsSenderName, '') <> ''  
      THEN '<p><b>SmsSenderName:</b> ' + cpd.SmsSenderName + '</p>'  
     ELSE ''  
     END + CASE   
     WHEN isnull(CPD.SmsMessage, '') <> ''  
      THEN '<p><b>SmsMessage:</b> ' + cpd.SmsMessage + '</p>'  
     ELSE ''  
     END + CASE   
     WHEN isnull(CAST(cpd.SmsTemplateId AS VARCHAR(50)), '') <> ''  
      THEN '<p><b>SmsTemplateId:</b> ' + (CAST(cpd.SmsTemplateId AS VARCHAR(50))) + '</p>'  
     ELSE ''  
     END  
    ) AS SMS  
   ,(  
    CASE   
     WHEN isnull(cpd.EmailAccountName, '') <> ''  
      THEN '<p><b>EmailAccountName:</b> ' + cpd.EmailAccountName + '</p>'  
     ELSE ''  
     END + CASE   
     WHEN isnull(cpd.EmailReplyTo, '') <> ''  
      THEN '<p><b>EmailReplyTo:</b> ' + cpd.EmailReplyTo + '</p>'  
     ELSE ''  
     END + CASE   
     WHEN isnull(cpd.EmailSubject, '') <> ''  
      THEN '<p><b>EmailSubject:</b> ' + cpd.EmailSubject + '</p>'  
     ELSE ''  
     END + CASE   
     WHEN isnull(cpd.EmailMessgae, '') <> ''  
      THEN '<p><b>EmailMessgae:</b> ' + cpd.EmailMessgae + '</p>'  
     ELSE ''  
     END + CASE   
     WHEN isnull(cast(cpd.EmailTemplateId AS VARCHAR(50)), '') <> ''  
      THEN '<p><b>EmailTemplateId:</b> ' + (CAST(cpd.EmailTemplateId AS VARCHAR(50))) + '</p>'  
     ELSE ''  
     END  
    ) AS Email  
   ,(  
    CASE   
     WHEN isnull(WebHook, '') <> ''  
      THEN '<p><b>WebHook:</b> ' + cpd.WebHook + '</p>'  
     ELSE ''  
     END  
    ) AS WebHook
   
  --, 'False' as IsNewMailBuilder
 , CPD.IsNewMailBuilder
  FROM ClientPageDetail CPD  
  WHERE User_ID IN (  
    SELECT UserId  
    FROM #tblUserIds  
    )  
    AND (@MrcName IS NULL OR Cpd.PageName LIKE '%'+@MrcName+'%')  
  ORDER BY DateCreated DESC  
 END  
END  


GO

